def _get_noise_texture_rollback_threshold(material_key: str) -> float:
    """Return material-adaptive noise texture rollback threshold (§8.5A)."""
    _k = str(material_key or "unknown").strip().lower()
    return float(_MATERIAL_NOISE_TEXTURE_ROLLBACK_THRESHOLD.get(_k, 10.0))


def _resolve_noise_texture_rollback_threshold(material_key: str, transfer_chain: list[str] | None = None) -> float:
    """Return the most permissive NTX rollback threshold across material and chain."""
    thresholds = [_get_noise_texture_rollback_threshold(material_key)]
    for stage in transfer_chain or []:
        thresholds.append(_get_noise_texture_rollback_threshold(str(stage).lower()))
    return float(max(thresholds))


def _stereo_to_samples_channels(audio: np.ndarray) -> np.ndarray | None:
    """Return stereo audio in (samples, 2) orientation or None for non-stereo."""
    if not isinstance(audio, np.ndarray) or audio.ndim != 2:
        return None
    if audio.shape[1] == 2:
        return audio
    if audio.shape[0] == 2:
        return audio.T
    return None


def _estimate_interchannel_delay_ms(stereo_sc: np.ndarray, sr: int) -> float:
    """Estimate absolute L/R delay in ms using multi-window median cross-correlation.

    Uses three analysis windows (beginning, middle, end) of 16 384 samples each and
    returns the **median** delay across windows that meet the correlation-confidence
    threshold.  A single short window (the previous 8192-sample approach) is susceptible
    to false positives when a musical passage with dominant panned content occupies the
    analysis segment — resulting in erroneous 0.5–1 ms readings even after STCG
    correction (actual STCG-measured delay: ~0.021 ms / 1 sample).

    §2.51a: Only the *median* estimate is compared to the hard-fail / warning thresholds.
    Windows where both channels are near-silent or the inter-channel correlation is too
    weak to be meaningful are excluded from the median.
    """
    from scipy.signal import correlate as _sps_correlate  # lazy — avoids module-level import for a single function

    if stereo_sc.ndim != 2 or stereo_sc.shape[1] != 2:
        return 0.0
    if sr <= 0:
        return 0.0

    left = np.asarray(stereo_sc[:, 0], dtype=np.float64)
    right = np.asarray(stereo_sc[:, 1], dtype=np.float64)
    n = min(left.size, right.size)
    if n < 512:
        return 0.0

    win_size = min(n, 16_384)
    max_lag = max(1, int(round(sr * 0.002)))  # ±2 ms search window

    # Three anchor positions: 25 %, 50 %, 75 % of the signal
    anchors = [int(n * frac) for frac in (0.25, 0.50, 0.75)]
    delay_estimates: list[float] = []

    for anchor in anchors:
        start = max(0, min(anchor - win_size // 2, n - win_size))
        stop = start + win_size
        l_seg = left[start:stop]
        r_seg = right[start:stop]
        if len(l_seg) < 256:
            continue

        l_seg = l_seg - float(np.mean(l_seg))
        r_seg = r_seg - float(np.mean(r_seg))
        l_std = float(np.std(l_seg))
        r_std = float(np.std(r_seg))
        if l_std < 1e-10 or r_std < 1e-10:
            continue

        corr = _sps_correlate(l_seg / (l_std * len(l_seg)), r_seg / r_std, method="fft")
        center = int(l_seg.size - 1)
        lo = max(0, center - max_lag)
        hi = min(corr.size, center + max_lag + 1)
        if hi <= lo:
            continue

        local_idx = int(np.argmax(np.abs(corr[lo:hi])))
        peak_val = float(np.abs(corr[lo + local_idx]))
        # Skip window if correlation confidence is too low (uncorrelated channels → not a real delay)
        if peak_val < 0.04:
            continue

        best_lag = int((lo + local_idx) - center)
        delay_estimates.append(float(abs(best_lag) * 1000.0 / float(sr)))

    if not delay_estimates:
        return 0.0
    return float(np.median(delay_estimates))


def _compute_stereo_safety_metrics(audio: np.ndarray, sr: int) -> dict[str, float | bool]:
    """Compute core stereo safety metrics for no-surprises export checks."""
    stereo_sc = _stereo_to_samples_channels(np.asarray(audio, dtype=np.float32))
    if stereo_sc is None:
        return {
            "is_stereo": False,
            "delay_ms": 0.0,
            "imbalance_db": 0.0,
            "mono_compat": 1.0,
            "true_peak_dbtp": -120.0,
            "peak_p999": 0.0,
        }

    left = np.asarray(stereo_sc[:, 0], dtype=np.float64)
    right = np.asarray(stereo_sc[:, 1], dtype=np.float64)
    l_rms = float(np.sqrt(np.mean(left * left)) + 1e-12)
    r_rms = float(np.sqrt(np.mean(right * right)) + 1e-12)
    imbalance_db = float(abs(20.0 * np.log10((l_rms + 1e-12) / (r_rms + 1e-12))))
    _corr_num = float(np.dot(left, right))
    _corr_den = float(np.linalg.norm(left) * np.linalg.norm(right) + 1e-12)
    interchannel_corr = float(np.clip(_corr_num / _corr_den, -1.0, 1.0))

    mid = 0.5 * (left + right)
    lr_energy = float(np.sqrt(np.mean(0.5 * (left * left + right * right))) + 1e-12)
    mono_compat = float(np.clip((np.sqrt(np.mean(mid * mid)) + 1e-12) / lr_energy, 0.0, 1.0))

    peak_p999 = float(np.percentile(np.abs(stereo_sc), 99.9))
    true_peak_dbtp = float(20.0 * np.log10(max(peak_p999, 1e-12)))

    return {
        "is_stereo": True,
        "delay_ms": _estimate_interchannel_delay_ms(stereo_sc, int(sr)),
        "imbalance_db": imbalance_db,
        "interchannel_corr": interchannel_corr,
        "mono_compat": mono_compat,
        "true_peak_dbtp": true_peak_dbtp,
        "peak_p999": peak_p999,
    }


def _evaluate_stereo_safety_guard(
    original_audio: np.ndarray,
    restored_audio: np.ndarray,
    sample_rate: int,
    material_key: "str | None" = None,
    source_phase_cancellation_ratio: float = 0.0,
) -> dict[str, Any]:
    """Evaluate §2.51a stereo no-surprises guard (hard-fail + warning).

    §2.51a: material-/kontextadaptive Delta-Bewertung.
    Analog carriers (vinyl, tape, reel_tape, shellac, cassette, wax_cylinder)
    have pre-existing L/R timing misalignments from carrier encoding.
    Restoration phases (phase_12 wow/flutter, phase_14 phase_correction) intentionally
    modify inter-channel timing — the mono_drop threshold must reflect this.
    """
    m_in = _compute_stereo_safety_metrics(original_audio, sample_rate)
    m_out = _compute_stereo_safety_metrics(restored_audio, sample_rate)

    if not bool(m_out.get("is_stereo", False)):
        return {
            "enabled": False,
            "hard_fail": False,
            "warning": False,
            "reason": "non_stereo_output",
            "input": m_in,
            "output": m_out,
            "hard_fail_reasons": [],
            "warning_reasons": [],
        }

    delay_out = float(m_out.get("delay_ms", 0.0))
    imb_in = float(m_in.get("imbalance_db", 0.0))
    imb_out = float(m_out.get("imbalance_db", 0.0))
    mono_in = float(m_in.get("mono_compat", 1.0))
    mono_out = float(m_out.get("mono_compat", 1.0))
    mono_drop = float(mono_out - mono_in)
    corr_in = float(m_in.get("interchannel_corr", 1.0))
    corr_out = float(m_out.get("interchannel_corr", 1.0))
    corr_drop = float(corr_out - corr_in)
    tp_out = float(m_out.get("true_peak_dbtp", -120.0))

    # §2.51a material-adaptive mono_drop threshold.
    # Analog carriers have pre-existing timing issues; restoration phases intentionally
    # correct inter-channel alignment (phase_12, phase_14) → more relaxed threshold.
    _ANALOG_CARRIER_KEYS = frozenset(
        {
            "vinyl",
            "tape",
            "reel_tape",
            "shellac",
            "cassette",
            "wax_cylinder",
            "wire_recording",
            "lacquer_disc",
        }
    )
    _mat = str(material_key or "").lower()
    if _mat in _ANALOG_CARRIER_KEYS or source_phase_cancellation_ratio > 0.20:
        # Analog/multi-chain: phase_12 wow-correction, phase_14 correction can cause ±0.20 delta
        _mono_drop_hard_threshold = -0.22
        _mono_drop_warn_threshold = -0.15
    elif source_phase_cancellation_ratio > 0.10:
        # Moderate pre-existing stereo phase issues (e.g. minidisc, dat)
        _mono_drop_hard_threshold = -0.17
        _mono_drop_warn_threshold = -0.12
    else:
        # Digital sources (cd_digital, mp3, aac, streaming): spec default
        _mono_drop_hard_threshold = -0.12
        _mono_drop_warn_threshold = -0.06

    hard_fail_reasons: list[str] = []
    warning_reasons: list[str] = []

    delay_in = float(m_in.get("delay_ms", 0.0))

    # Hard-fail thresholds (§2.51a)
    # Delta-guard: STCG corrects inter-channel lags to sub-sample precision.
    # A residual 0.5–2 ms reading in the output is almost always a panning
    # artifact from cross-correlated musical content, NOT a real alignment
    # error introduced by restoration.  Only fail/warn when the output delay
    # is WORSE than the input delay (i.e., restoration degraded alignment).
    # Tolerance: 0.10 ms — accounts for multi-window median variance.
    _delay_delta_threshold = 0.10  # ms
    if delay_out > 1.0 and delay_out > delay_in + _delay_delta_threshold:
        hard_fail_reasons.append("interchannel_delay_gt_1ms")
    if imb_out > 6.0 and imb_in < 3.0:
        hard_fail_reasons.append("lr_imbalance_gt_6db_with_balanced_input")
    if mono_drop < _mono_drop_hard_threshold:
        hard_fail_reasons.append("mono_compatibility_drop_significant")
    if corr_out < 0.10 and corr_drop < -0.35 and corr_in > 0.30:
        hard_fail_reasons.append("interchannel_correlation_collapse")
    if tp_out > -1.0:
        hard_fail_reasons.append("true_peak_gt_minus_1dbtp")

    # Warning thresholds (§2.51a)
    if 0.5 < delay_out <= 1.0 and delay_out > delay_in + _delay_delta_threshold:
        warning_reasons.append("interchannel_delay_0p5_to_1ms")
    if 3.0 < imb_out <= 6.0:
        warning_reasons.append("lr_imbalance_3_to_6db")
    if _mono_drop_warn_threshold <= mono_drop < (_mono_drop_warn_threshold + 0.06):
        warning_reasons.append("mono_compatibility_drop_moderate")
    if corr_out < 0.25 and corr_drop < -0.20 and corr_in > 0.25:
        warning_reasons.append("interchannel_correlation_drop")

    return {
        "enabled": True,
        "hard_fail": bool(hard_fail_reasons),
        "warning": bool(warning_reasons),
        "reason": "hard_fail" if hard_fail_reasons else ("warning" if warning_reasons else "ok"),
        "input": m_in,
        "output": m_out,
        "delta": {
            "mono_compat": mono_drop,
            "imbalance_db": float(imb_out - imb_in),
            "delay_ms": float(delay_out - float(m_in.get("delay_ms", 0.0))),
            "interchannel_corr": corr_drop,
        },
        "hard_fail_reasons": hard_fail_reasons,
        "warning_reasons": warning_reasons,
    }


def _canonicalize_quality_mode(raw: "str | None") -> str:
    """Bridge ProcessingMode strings to internal QualityMode strings.

    Magic-Button uses ProcessingMode ('restoration', 'studio_2026').
    Phases that accept a quality_mode kwarg expect QualityMode values
    ('quality', 'maximum', 'balanced', 'fast').
    This function normalises both vocabularies into the phase-internal form.
    (§Mode-Alias copilot-instructions §0b)
    """
    s = str(raw or "").strip().lower().replace("-", "_")
    _MAP: dict[str, str] = {
        "restoration": "quality",
        "studio_2026": "maximum",
        "studio2026": "maximum",
        "studio": "maximum",
        "quality": "quality",
        "maximum": "maximum",
        "balanced": "balanced",
        "fast": "fast",
    }
    return _MAP.get(s, "quality")


def _pick_more_conservative_material(a: "MaterialType", b: "MaterialType") -> "MaterialType":
    """Return the material type with higher conservativeness rank (§Spec Konfliktregel Fallback)."""
    rank_a = _MATERIAL_CONSERVATIVENESS_RANK.get(getattr(a, "value", str(a)), 0)
    rank_b = _MATERIAL_CONSERVATIVENESS_RANK.get(getattr(b, "value", str(b)), 0)
    return a if rank_a >= rank_b else b


def _fc_compute_target_score(
    mode_value: str,
    cal_profile: "dict | None",
) -> float:
    """Compute FeedbackChain target_score adjusted by song calibration restorability.

    §2.31a: Base target 0.78 (studio) / 0.72 (restoration) is fine-tuned
    by restorability_score from the song calibration profile.

    - Poor material (restorability=30): target −0.035 → avoid artefact accumulation
    - Average material (restorability=65): no change
    - Excellent material (restorability=95): target +0.030 → exploit quality headroom

    Range bounded to [0.60, 0.85] to stay within FeedbackChain's convergence zone.
    """
    _mode_norm = str(mode_value or "").strip().lower().replace("_", "").replace(" ", "")
    _is_studio = _mode_norm in {"studio2026", "studio", "maximum"}
    _base = 0.78 if _is_studio else 0.72
    if not isinstance(cal_profile, dict):
        return _base
    _rest = float(cal_profile.get("restorability_score", 65.0))
    _adj = (_rest - 65.0) / 1000.0  # ±0.035 for score range 30–100
    return max(0.60, min(0.85, _base + _adj))


def _compute_weighted_goal_gap(
    scores: dict[str, float],
    thresholds: dict[str, float],
    applicable_goals: set[str],
    goal_weights: dict[str, float] | None = None,
) -> tuple[float, int]:
    """Return weighted threshold gap and number of violated goals.

    Gap = sum(max(0, thr - score) * weight) over applicable goals.
    Lower is better; 0 means all applicable goals pass.
    """
    _weights = goal_weights if isinstance(goal_weights, dict) else {}
    _gap = 0.0
    _violations = 0
    for _g in applicable_goals:
        _thr = float(thresholds.get(_g, 0.85))
        _sc = float(scores.get(_g, 0.0))
        _d = _thr - _sc
        if _d > 0.0:
            _violations += 1
            _w = float(_weights.get(_g, 1.0))
            _gap += _d * float(np.clip(_w, 0.3, 2.0))
    return float(_gap), int(_violations)


class UnifiedRestorerV3:
    """
    Unified Restorer V3 - Defect-First Audio Restoration Engine.

    Usage:
        restorer = UnifiedRestorerV3()  # default QUALITY mode
        # or with explicit config:
        restorer = UnifiedRestorerV3(RestorationConfig(mode=QualityMode.FAST))
        result = restorer.restore(audio, sample_rate=44100)
        restored_audio = result.audio
    """

    @staticmethod
    def _resolve_pmgg_restorability_score(
        cached_result: Any,
        analysis_audio: np.ndarray,
        analysis_sample_rate: int,
        material_key: str,
        fallback_score: float,
        estimator_fn: Any,
    ) -> tuple[float, str, Any | None]:
        """Resolve a stable PMGG restorability score from cache, estimator, or fallback.

        Precedence:
        1) cached_result.restorability_score (if finite)
        2) estimator_fn(...).restorability_score (if finite)
        3) fallback_score
        """
        try:
            _cached_score = getattr(cached_result, "restorability_score", None)
            if _cached_score is not None and np.isfinite(float(_cached_score)):
                return float(_cached_score), "cached", cached_result
        except Exception:
            pass

        try:
            _estimated_result = estimator_fn(
                analysis_audio,
                analysis_sample_rate,
                material=material_key,
                quality_mode="restoration",
            )
            _estimated_score = getattr(_estimated_result, "restorability_score", None)
            if _estimated_score is not None and np.isfinite(float(_estimated_score)):
                return float(_estimated_score), "estimated", _estimated_result
        except Exception:
            return float(fallback_score), "fallback", None

        return float(fallback_score), "fallback", None

    def __init__(
        self,
        config: RestorationConfig | None = None,
        quality_mode: str | None = None,
        monitor_phases: bool | None = None,
        **kwargs,
    ):
        """
        Initialisiert UnifiedRestorerV3 mit Lazy Loading und asynchroner Vorbereitung.
        """
        if config is None:
            config = RestorationConfig()
        if quality_mode is not None:
            _raw_qm_str = str(quality_mode).strip().lower()
            _qm_norm = _canonicalize_quality_mode(_raw_qm_str)
            _QM_MAP = {
                "fast": QualityMode.FAST,
                "balanced": QualityMode.BALANCED,
                "quality": QualityMode.QUALITY,
                "maximum": QualityMode.MAXIMUM,
            }
            config.mode = _QM_MAP.get(_qm_norm, config.mode)
            # §0a: Explicitly propagate studio_2026 flag when quality_mode string
            # contains 'studio' — prevents MAXIMUM mode being misread as studio_2026
            # by callers that pass quality_mode='maximum' for restoration (§Crossfire).
            if "studio" in _raw_qm_str:
                config.studio_2026 = True
        self.config = config
        self._monitor_phases = bool(monitor_phases) if monitor_phases is not None else False
        self._compat_init_kwargs = dict(kwargs) if kwargs else {}
        self.defect_scanner = DefectScanner()
        self.scheduler = AdaptiveCoreScheduler(num_cores=self.config.num_cores)

        # Only create PerformanceGuard if enabled
        if self.config.enable_performance_guard:
            self.performance_guard = PerformanceGuard(
                mode=self.config.mode,
                enforce_limit=self.config.enforce_3x_rt,
                enable_adaptive_skipping=self.config.enable_adaptive_skipping,
            )
        else:
            self.performance_guard = None  # type: ignore[assignment]
            logger.info("Performance Guard disabled via config")
            # Studio 2026 without a PerformanceGuard must still use MAXIMUM quality,
            # not BALANCED. BALANCED (3× RT) would silently downgrade the pipeline.
            if self.is_studio_mode():
                self.config.mode = QualityMode.MAXIMUM
                self.config.enable_phase_skipping = False
        # Lazy Phase Registry: Nur Metadaten, keine Instanzen
        self.phase_metadata: dict[str, dict] = self._discover_phase_metadata()
        self._phase_cache: dict[str, PhaseInterface] = {}
        self._phase_cache_lock = threading.Lock()  # §3.2 Thread-Safety für Lazy-Phase-Cache
        self._warnings: list[str] = []  # §M-2 Schritte_zur_Musikalischen_Exzellenz
        self._quality_estimate_used_fallback: bool = False
        self._quality_estimate_source: str = "unknown"
        self._blocked_experimental_features: set[str] = set()
        self._phase_goal_conflict_runtime: dict[str, Any] = {}
        self._strict_autosetup_policy: dict[str, Any] = {}
        self._global_conservative_scalar: float = 1.0
        self._recovery_certainty_profile: dict[str, Any] = {}
        # §0/§2.46 HF-Hallucination-Guard: per-phase metadata (initialized in _execute_pipeline reset).
        self._phase_metadata_accumulator: dict[str, Any] = {}
        # §2.64/§2.65 MAS convergence state (reset per restore() call)
        self._phase_pre_snapshot: dict[str, float] = {}
        self._phase_deltas: dict[str, dict] = {}
        self._phase_budget_gain_history: dict[str, dict[str, dict[str, float]]] = {}
        self._mas_fully_achieved: bool = False
        # §2.46b Spectral Tilt Drift Guard: era-level spectral tilt stored per song.
        # Set in restore() from era_classifier result; used in _profiled_phase_call post-phase
        # to cap additive phases that over-brighten/darken beyond era character.
        self._era_spectral_tilt: float | None = None
        # Team-Koordination zwischen Folgephasen: prior_phase_context wird pro erfolgreicher
        # Phase fortgeschrieben und an nachfolgende Phasen injiziert.
        self._phase_team_context: dict[str, Any] = {}

        # §0c Graceful-Stop — Watchdog signalisiert dieses Event statt harten Pipeline-Abbruch.
        # Die Phase-Loop in _execute_pipeline prüft das Event nach jeder Phase und exportiert
        # das bisher beste Checkpoint-Ergebnis (kein Datenverlust, kein Kill).
        self._graceful_stop_event = threading.Event()

        # §DEBUG: Pipeline-Trace
        self._debug_trace_enabled: bool = False

        # Per-restore() state (initialized on each restore() call, declared here for Pyright)
        self._song_calibration_profile: dict = {}
        self._active_global_plan: object = None
        self._active_chain_info: object = None
        self._active_defekt_hint: object = None
        self._restoration_context: dict = {}
        self._material_defect_consistency_warnings: list = []
        self._last_restorability_score: float = 50.0
        self._song_goal_importance: object = None
        self._song_goal_weights: dict = {}
        self._song_goal_targets: dict | None = None  # annotated dict[str,float]|None at first use
        self._pmgg_ceiling_capped_targets: dict[str, float] | None = None
        self._last_material_priority_phases: tuple = ()
        self._source_material_baseline: object = None
        self._vintage_phase_strength_caps: dict = {}
        self._material_phase_initial_strengths: dict = {}
        self._recovery_ctx: dict[str, Any] = {}
        self._iad_artifact_fraction_penalty: float = 1.0
        self._artifact_freedom_score: float = 1.0
        self._ssa_segments: list | None = None  # §2.52b SongStructureAnalyzer result
        self._cstc_noise_profile: object = None  # §CSTC pre-pipeline noise profile
        # Additional per-restore() attrs (avoid Pyright 'defined outside __init__')
        self._detected_vocal_gender: str | None = None
        self._phase_plan_intelligence: object = None
        self._phase_regression_log: dict[str, float] = {}
        self._active_intervention_log: list[dict[str, Any]] = []
        self._pmgg_log_entries: list = []
        self._active_pipeline_cb_for_sub: object = None
        self._active_phase_pct_for_sub: tuple[float, float] | None = None
        self._conductor_strength_hints: dict = {}
        self._team_coordination_events: list = []
        self._pipeline_ml_guard_events: list = []
        self._ml_fallbacks_used: dict = {}
        self._interaction_guard_metadata: dict = {}
        self._artifact_freedom_detail: dict = {}
        self._hpi_best_rollback_audio: object = None
        self._carrier_chain_recovery_ratio: float = 0.0
        self._best_carrier_checkpoint: object = None
        self._last_carrier_phase_id: str | None = None
        self._panns_singing: float = 0.0  # §0p: vocal_presence — updated per-restore()

        # PhaseSkipper (optional, beschleunigt Pipeline um 20–40 %)
        if self.config.enable_phase_skipping:
            try:
                self.phase_skipper = PhaseSkipper()
            except Exception as e:
                logger.debug("PhaseSkipper nicht verfügbar: %s — Phase-Skipping deaktiviert", e)
                self.phase_skipper = None
        else:
            self.phase_skipper = None

    def is_studio_mode(self) -> bool:
        """Return True if running in Studio 2026 mode.

        Single source of truth — resolves dual-flag ambiguity between
        ``config.studio_2026`` (bool) and ``config.mode`` (QualityMode).

        NOTE: QualityMode.MAXIMUM alone does NOT imply studio_2026.
        MAXIMUM is a performance/compute budget — it can be used in both
        restoration and studio_2026. Only config.studio_2026=True or a
        mode string containing "studio" indicates studio_2026 mode (§0a).
        """
        if getattr(self.config, "studio_2026", False):
            return True
        _mode = getattr(self.config, "mode", None)
        if _mode is not None:
            _val = getattr(_mode, "value", str(_mode)).lower()
            if "studio" in _val:
                return True
        return False

    @staticmethod
    def _apply_bronze_restoration_minimal_pipeline(
        selected_phases: list[str],
        _runtime_never_skip_phases: list[str],
        _material_key: str,
    ) -> tuple[list[str], list[str]]:
        """Temporarily constrain restoration to a defensive core phase set.

        This helper is intentionally conservative and is only meant for a
        stabilization workflow where catastrophic regressions must be blocked
        before quality-building phases are reintroduced step by step.
        """

        _base_keep = {
            # Emergency no-harm fallback: keep only output-safe phases.
            "phase_30_dc_offset_removal",
            "phase_47_truepeak_limiter",
            "phase_41_output_format_optimization",
        }
        _keep = set(_base_keep)
        _removed = [phase_id for phase_id in selected_phases if phase_id not in _keep]
        if not _removed:
            return list(selected_phases), []
        _kept = [phase_id for phase_id in selected_phases if phase_id in _keep]
        return _kept, _removed

    def _is_research_mode(self) -> bool:
        """Returns True only for explicit RESEARCH deployment mode."""
        return getattr(self.config, "deployment_mode", DeploymentMode.PRODUCT) == DeploymentMode.RESEARCH

    def request_graceful_stop(self) -> None:
        """§0c: Signal the active phase pipeline to stop after the current phase.

        Thread-safe. The pipeline exports the best checkpoint achieved so far
        and returns a RestorationResult with status='recovered' — no data loss,
        no force-kill. Call this from the UI watchdog instead of terminate().
        """
        self._graceful_stop_event.set()
        logger.warning("UV3: §0c graceful stop requested — pipeline will export best checkpoint after current phase")

    @staticmethod
    def _musical_gain_envelope(
        audio: np.ndarray,
        gain: float,
        gate_dbfs: float = -36.0,
        crossfade_ms: float = 10.0,
        sr: int = 48000,
        reference_for_gate: np.ndarray | None = None,
        material_key: str | None = None,
    ) -> np.ndarray:
        """Delegates to backend.core.audio_utils.apply_musical_gain_envelope — single canonical impl.

        §2.45a-II §2.30b: envelope-aware gain, adaptive noise-floor gate, per-sample quiet-zone
        hard clamp (Stufe 5).  No duplicate logic — changes to audio_utils automatically apply here.

        reference_for_gate: pre-phase audio for noise-floor gate estimation (v9.12.2).
        material_key: optional material type for floor guarantee (v9.12.2).
        """
        from backend.core.audio_utils import apply_musical_gain_envelope as _amge

        return _amge(
            audio,
            gain,
            gate_dbfs=gate_dbfs,
            crossfade_ms=crossfade_ms,
            sr=sr,
            reference_for_gate=reference_for_gate,
            material_key=material_key,
        )

    @staticmethod
    def _quiet_edge_rescue_ok(
        reference_audio: np.ndarray,
        candidate_audio: np.ndarray,
        sr: int,
        *,
        material_key: str | None = None,
        max_edge_boost_db: float = 2.0,
    ) -> bool:
        """Reject late gain rescue when it inflates quiet intro/outro zones."""
        try:
            from backend.core.audio_utils import quiet_edge_boost_ok

            return bool(
                quiet_edge_boost_ok(
                    reference_audio,
                    candidate_audio,
                    sr,
                    material_key=material_key,
                    max_edge_boost_db=max_edge_boost_db,
                )
            )
        except Exception:
            return True

    @staticmethod
    def _apply_final_quiet_edge_clamp(
        reference_audio: np.ndarray | None,
        candidate_audio: np.ndarray,
        sr: int,
        *,
        material_key: str | None = None,
        max_edge_boost_db: float = 2.0,
    ) -> np.ndarray:
        """Last-resort quiet-edge clamp after all late rescues and rollbacks."""
        if reference_audio is None:
            return np.asarray(candidate_audio, dtype=np.float32)
        try:
            from backend.core.audio_utils import limit_quiet_edge_boost

            return np.asarray(
                limit_quiet_edge_boost(
                    reference_audio,
                    candidate_audio,
                    sr,
                    material_key=material_key,
                    max_edge_boost_db=max_edge_boost_db,
                ),
                dtype=np.float32,
            )
        except Exception:
            return np.asarray(candidate_audio, dtype=np.float32)

    @staticmethod
    def _update_positive_makeup_authority(phase_id: str, current_allowed: bool) -> tuple[bool, str | None]:
        """Update policy that controls positive cumulative makeup gain.

        §2.45a-VI: HPF/Notch energy removal is intentional and must not be
        compensated by later cumulative loudness guards. A subsequent broadband
        subtractive phase can re-enable positive makeup authority.
        """
        if phase_id in {"phase_02_hum_removal", "phase_05_rumble_filter"}:
            return False, "locked_after_hpf_notch"

        phase_prefix = "_".join(str(phase_id).split("_")[:2])
        if phase_prefix in {"phase_03", "phase_18", "phase_20", "phase_28", "phase_29", "phase_49"}:
            return True, f"unlocked_after_{phase_prefix}"

        return current_allowed, None

    def _allow_experimental_feature(self, feature_name: str) -> bool:
        """Blocks experimental features in PRODUCT mode and records the decision."""
        if self._is_research_mode():
            return True
        if feature_name not in self._blocked_experimental_features:
            self._blocked_experimental_features.add(feature_name)
            _msg = f"Experimenteller Pfad '{feature_name}' im Produktmodus blockiert (deployment_mode=product)."
            self._warnings.append(_msg)
            logger.info(_msg)
        return False

    @staticmethod
    def _fc_defect_severity_mean(defect_result: object | None) -> float:
        """Extract mean defect severity for §2.54 FeedbackChain adaptive thresholds."""
        if defect_result is None:
            return 0.0
        try:
            scores = getattr(defect_result, "scores", None)
            if scores and hasattr(scores, "values"):
                vals = [s.severity for s in scores.values() if hasattr(s, "severity") and s.severity > 0]
                if vals:
                    return float(np.mean(vals))
        except Exception:
            pass
        return 0.0

    @staticmethod
    def _resolve_studio_pqs_improvement(
        pqs_result: Any | None,
        fail_reasons: list[dict[str, Any]],
    ) -> float:
        """Resolve studio pqs_improvement with fail-fast semantics.

        Normierung: (pqs_mos - 0.5) / 5.0 → [0.0, 1.0]
          MOS=0.5 → 0.0
          MOS=2.5 → 0.400
          MOS=3.5 → 0.600
          MOS=4.5 → 0.800
          MOS=5.0 → 0.900

        PQS unavailable/invalid → -1.0 (fail-fast Marker für Studio-Gate).
        """
        if pqs_result is not None:
            try:
                _mos = float(pqs_result.pqs_mos)
                if math.isfinite(_mos):
                    # Normierung: (mos - 0.5) / 5.0 → [0.0, 1.0]
                    return float(np.clip((_mos - 0.5) / 5.0, 0.0, 1.0))
            except Exception:
                pass

            if not any(r.get("error_code") == "PQS_INVALID_STUDIO" for r in fail_reasons):
                fail_reasons.append(
                    {
                        "component": "PerceptualQualityScorer",
                        "error_code": "PQS_INVALID_STUDIO",
                        "severity": "degraded",
                        "detail": "pqs_result present but pqs_mos missing/invalid — fail-fast sentinel -1.0",
                    }
                )
            logger.warning(
                "Studio-2026: PQS-Result ungültig — fail-fast sentinel -1.0 (Audit-Eintrag PQS_INVALID_STUDIO)"
            )
            return -1.0

        if not any(r.get("error_code") == "PQS_UNAVAILABLE_STUDIO" for r in fail_reasons):
            fail_reasons.append(
                {
                    "component": "PerceptualQualityScorer",
                    "error_code": "PQS_UNAVAILABLE_STUDIO",
                    "severity": "degraded",
                    "detail": "PQS plugin not available in studio2026 final gate — fail-fast sentinel -1.0",
                }
            )
        logger.info(
            "Studio-2026: PQS nicht verfügbar (optionales Plugin) — fail-fast sentinel -1.0 "
            "(Audit-Eintrag PQS_UNAVAILABLE_STUDIO)"
        )
        return -1.0

    @staticmethod
    def _evaluate_fallback_quality_floor(
        ml_fallbacks_used: list[dict[str, Any]] | None,
        hpi_result: Any | None,
        artifact_freedom: float,
    ) -> dict[str, Any]:
        """Evaluate the global fallback-quality floor for ML->DSP fallback runs.

        The floor is only active when at least one ML fallback was used.
        Pass condition follows existing hard export gates:
          - artifact_freedom >= 0.95
          - HPI gate passed
        """
        _fallback_count = len(ml_fallbacks_used or [])
        _triggered = _fallback_count > 0
        _artifact_score = float(np.clip(float(artifact_freedom), 0.0, 1.0))

        _hpi_passed = bool(getattr(hpi_result, "passed", False)) if hpi_result is not None else False
        _hpi_value = None
        if hpi_result is not None:
            try:
                _hpi_raw = float(getattr(hpi_result, "hpi", float("nan")))
                if math.isfinite(_hpi_raw):
                    _hpi_value = _hpi_raw
            except Exception:
                _hpi_value = None

        _artifact_ok = _artifact_score >= 0.95
        _passed = bool((not _triggered) or (_artifact_ok and _hpi_passed))
        _status = "passed" if _passed else "degraded"
        _reason = "ok" if _passed else "hpi_or_artifact_floor_failed"

        return {
            "triggered": bool(_triggered),
            "passed": bool(_passed),
            "status": _status,
            "reason": _reason,
            "fallback_count": int(_fallback_count),
            "artifact_freedom": _artifact_score,
            "hpi_passed": bool(_hpi_passed),
            "hpi": _hpi_value,
            "attempts": 0,
            "recovered": False,
            "best_candidate": None,
            "recovery_trace": [],
        }

    @staticmethod
    def _is_benign_digital_source(
        audio: np.ndarray,
        sample_rate: int,
        material_type: MaterialType | None,
    ) -> tuple[bool, dict[str, float | str]]:
        """Detects clean codec/digital sources that should stay near pass-through."""
        material = material_type or MaterialType.UNKNOWN
        digital_materials = {
            MaterialType.CD_DIGITAL,
            MaterialType.DAT,
            MaterialType.MP3_LOW,
            MaterialType.MP3_HIGH,
            MaterialType.AAC,
            MaterialType.MINIDISC,
            MaterialType.STREAMING,
        }
        if material not in digital_materials:
            return False, {"material": material.value}

        # Robust mono downmix: handles both (2, N) channel-first and (N, 2) column-major
        if audio.ndim == 2:
            mono = audio.mean(axis=0) if audio.shape[0] <= audio.shape[1] else audio.mean(axis=1)
        else:
            mono = audio
        mono = np.nan_to_num(np.asarray(mono, dtype=np.float32), nan=0.0, posinf=0.0, neginf=0.0)
        if mono.size < 4096 or sample_rate <= 0:
            return False, {"material": material.value, "reason": "input_too_short"}

        abs_mono = np.abs(mono)
        dc_offset = float(abs(np.mean(mono)))
        hard_clip_ratio = float(np.mean(abs_mono >= 0.999))
        near_clip_ratio = float(np.mean(abs_mono >= 0.98))

        dyn_window = max(1, int(sample_rate * 0.4))
        dyn_frames = mono.size // dyn_window
        if dyn_frames >= 2:
            dyn_blocks = mono[: dyn_frames * dyn_window].reshape(dyn_frames, dyn_window)
            dyn_rms = np.sqrt(np.mean(dyn_blocks**2, axis=1) + 1e-12)
            dyn_std_db = float(np.std(20.0 * np.log10(dyn_rms + 1e-12)))
        else:
            dyn_std_db = 0.0

        n_fft = 4096
        hop = 1024
        window = np.hanning(n_fft).astype(np.float32)
        flatness_values: list[float] = []
        energy = np.zeros(n_fft // 2 + 1, dtype=np.float64)
        frames = 0
        for start in range(0, mono.size - n_fft + 1, hop):
            frame = mono[start : start + n_fft] * window
            mag = np.abs(np.fft.rfft(frame)).astype(np.float64) + 1e-12
            flatness_values.append(float(np.exp(np.mean(np.log(mag))) / np.mean(mag)))
            energy += mag**2
            frames += 1

        if frames == 0:
            return False, {"material": material.value, "reason": "no_frames"}

        freqs = np.fft.rfftfreq(n_fft, d=1.0 / sample_rate)
        flatness_median = float(np.median(flatness_values))
        energy_db = 10.0 * np.log10(np.maximum(energy / frames, 1e-20))
        peak_db = float(np.max(energy_db))
        bandwidth_mask = energy_db >= (peak_db - 55.0)
        effective_bandwidth_hz = float(freqs[bandwidth_mask][-1]) if np.any(bandwidth_mask) else 0.0

        # §Fix8a: MP3_LOW is always a lossy codec with codec artifacts —
        #         never considered benign regardless of signal metrics.
        # §Fix8b: Bandwidth threshold must be relative to Nyquist (78%) to
        #         avoid false "benign" for band-limited material.
        #         44.1 kHz → min 17.2 kHz;  48 kHz → min 18.7 kHz.
        _never_benign_materials = {MaterialType.MP3_LOW}
        _bw_min = max(12_000.0, 0.78 * (sample_rate / 2.0))
        benign = (
            material not in _never_benign_materials
            and dc_offset <= 5e-4
            and hard_clip_ratio <= 5e-6
            and near_clip_ratio <= 5e-5
            and dyn_std_db >= 3.5
            and flatness_median <= 8e-3
            and effective_bandwidth_hz >= _bw_min
        )
        return benign, {
            "material": material.value,
            "dc_offset": dc_offset,
            "hard_clip_ratio": hard_clip_ratio,
            "near_clip_ratio": near_clip_ratio,
            "dyn_std_db": dyn_std_db,
            "flatness_median": flatness_median,
            "effective_bandwidth_hz": effective_bandwidth_hz,
        }

    @staticmethod
    def _has_localized_critical_defects(top_defects: list[Any]) -> tuple[bool, dict[str, float | int]]:
        """Detects short/localized defect patterns that should disable pass-through."""
        localized_tokens = (
            "click",
            "pop",
            "crackle",
            "dropout",
            "glitch",
            "impulse",
            "burst",
            "thump",
        )
        threshold = 0.08
        localized_count = 0
        max_localized_severity = 0.0

        for score in top_defects:
            defect_type_obj = getattr(score, "defect_type", "")
            defect_name = str(getattr(defect_type_obj, "value", defect_type_obj)).strip().lower()
            severity = float(getattr(score, "severity", 0.0) or 0.0)
            if any(token in defect_name for token in localized_tokens):
                max_localized_severity = max(max_localized_severity, severity)
                if severity >= threshold:
                    localized_count += 1

        has_localized_critical = localized_count > 0
        return has_localized_critical, {
            "localized_count": localized_count,
            "max_localized_severity": float(max_localized_severity),
            "threshold": float(threshold),
        }

    @staticmethod
    def _is_mp3_material(material_type: MaterialType | None) -> bool:
        """Returns True when source material is an MP3 variant."""
        return material_type in {MaterialType.MP3_LOW, MaterialType.MP3_HIGH}

    @staticmethod
    def _is_lossy_codec_material(material_type: MaterialType | None) -> bool:
        """Returns True for lossy/consumer codec-style digital materials."""
        return material_type in {
            MaterialType.MP3_LOW,
            MaterialType.MP3_HIGH,
            MaterialType.AAC,
            MaterialType.MINIDISC,
            MaterialType.STREAMING,
        }

    @staticmethod
    def _should_force_mp3_maximum_guard(
        mode: QualityMode,
        material_type: MaterialType | None,
        input_snr_db: float,
        max_defect_severity: float,
        clean_digital_mode: bool,
    ) -> bool:
        """Decides whether MAXIMUM mode should be softened for lossy codec material."""
        if mode != QualityMode.MAXIMUM:
            return False
        if not UnifiedRestorerV3._is_lossy_codec_material(material_type):
            return False
        if clean_digital_mode:
            return True
        # Conservative fallback heuristic for benign MP3s where clean-digital classifier is close to threshold.
        return input_snr_db >= 34.0 and max_defect_severity <= 0.20

    @staticmethod
    def _build_song_calibration_profile(
        *,
        material_type: MaterialType | None,
        mode: QualityMode,
        restorability_score: float,
        input_snr_db: float,
        max_defect_severity: float,
        pipeline_confidence: float,
        era_decade: int | None = None,
        defect_scores: dict[str, float] | None = None,
        panns_tags: dict[str, float] | None = None,
        spectral_fingerprint: dict[str, float] | None = None,
        transfer_chain: list[str] | None = None,
        is_schlager: bool = False,
        genre_label: str = "",
    ) -> dict[str, Any]:
        """Build a song-level calibration profile for phase-family adaptation.

        The profile is intentionally conservative and bounded to avoid overfitting
        to a single title while still allowing track-specific adaptation.

        Args:
            era_decade: Recording decade (e.g. 1940, 1960, 1980). Used for
                era-GP-warmstart scaling per §2.14. None → neutral era factor.
            genre_label: Detected genre label (e.g. 'Rock', 'Jazz', 'Klassik',
                'Oper', 'Schlager'). Used for genre-adaptive family scalar overrides.
                Empty string → no genre-based adjustment.
        """
        _rest = float(np.clip(restorability_score / 100.0, 0.0, 1.0))
        _snr = float(np.clip((input_snr_db - 10.0) / 40.0, 0.0, 1.0))
        _def = float(np.clip(max_defect_severity, 0.0, 1.0))
        _conf = float(np.clip(pipeline_confidence, 0.0, 1.0))

        # §2.14 Era-GP-warmstart: denoise scaling by recording decade.
        # pre-war (≤1940) → heavy noise → higher denoise family scalar.
        # post-1970 → cleaner recordings → lower denoise family scalar.
        _era_denoise_scale = 1.0
        if era_decade is not None:
            if era_decade <= 1940:
                _era_denoise_scale = 1.10  # ~N(0.90,0.05) prior maps to +10% relative
            elif era_decade <= 1960:
                _era_denoise_scale = 1.00  # ~N(0.75,0.08) prior → neutral
            else:
                _era_denoise_scale = 0.88  # ≥1970 → N(0.50,0.10) → gentler denoise

        # Material-type base multipliers (psychoacoustic + restoration constraints).
        # Overrides are narrow (±0.10 max) to stay conservative and not over-ride
        # per-phase material_initial_strengths (from defect_phase_mapper).
        from backend.core.material_canonical import canonical_material_key

        _mat_val = canonical_material_key(material_type)
        _mat_denoise = 1.00
        _mat_reverb = 1.00
        _mat_reconstruct = 1.00
        _mat_vocal = 1.00
        _mat_dynamics = 1.00
        if _mat_val in ("shellac",):
            _mat_denoise = 1.08  # broad-band shellac noise → slightly more aggressive denoise
            _mat_reverb = 0.90  # shellac has no room reverb character worth removing
            _mat_reconstruct = 1.05  # wide BW loss → more reconstruction
        elif _mat_val in ("vinyl",):
            _mat_denoise = 1.00
            _mat_reverb = 0.95
        elif _mat_val in ("tape", "reel_tape"):
            _mat_denoise = 1.03  # tape hiss layer → slightly higher denoise
            _mat_reverb = 1.05  # tape reverb / room often worth reducing
        elif _mat_val in ("cd_digital", "dat"):
            _mat_denoise = 0.85  # clean digital → gentle denoise family
            _mat_reverb = 0.92
            _mat_reconstruct = 0.88
        elif _mat_val in ("mp3_low", "mp3_high"):
            _mat_reconstruct = 1.08  # codec artefacts → more reconstruction
            _mat_dynamics = 1.05  # lossy compression → restore dynamics
        elif _mat_val in ("aac", "minidisc", "streaming"):
            _mat_reconstruct = 1.05

        # §Per-defect calibration: boost the relevant family if a specific defect
        # dominates this song. Uses weighted severity (0=none, 1=heavy).
        # Boost is conservative (+12% max) to avoid over-riding per-phase strengths.
        _dsev_transient_boost = 1.0
        if isinstance(defect_scores, dict) and defect_scores:

            def _dsev(k: str) -> float:
                return float(np.clip(defect_scores.get(k, 0.0), 0.0, 1.0))

            _dsev_denoise = max(
                _dsev("noise"),
                _dsev("high_freq_noise"),
                _dsev("hum"),
                _dsev("quantization_noise"),
                _dsev("aliasing"),
                _dsev("bias_error"),
            )
            _dsev_transient = max(_dsev("clicks"), _dsev("crackle"), _dsev("transient_smearing"))
            _dsev_reconstruct = max(
                _dsev("dropouts"),
                _dsev("bandwidth_loss"),
                _dsev("digital_artifacts"),
                _dsev("compression_artifacts"),
                _dsev("head_wear"),
                _dsev("pre_echo"),
                _dsev("jitter_artifacts"),
                _dsev("azimuth_error"),
            )
            _dsev_reverb_def = max(_dsev("reverb_excess"), _dsev("print_through"))
            _dsev_dynq = max(
                _dsev("wow"),
                _dsev("flutter"),
                _dsev("pitch_drift"),
                _dsev("dynamic_compression_excess"),
                _dsev("low_freq_rumble"),
                _dsev("riaa_curve_error"),
            )
            _dsev_vocal_sib = _dsev("sibilance_excess")

            _mat_denoise = float(np.clip(_mat_denoise * (1.0 + 0.12 * _dsev_denoise), 0.85, 1.20))
            _mat_reverb = float(np.clip(_mat_reverb * (1.0 + 0.12 * _dsev_reverb_def), 0.80, 1.15))
            _mat_reconstruct = float(np.clip(_mat_reconstruct * (1.0 + 0.12 * _dsev_reconstruct), 0.80, 1.20))
            _mat_dynamics = float(np.clip(_mat_dynamics * (1.0 + 0.08 * _dsev_dynq), 0.80, 1.15))
            _mat_vocal = float(np.clip(_mat_vocal * (1.0 + 0.10 * _dsev_vocal_sib), 0.80, 1.15))
            _dsev_transient_boost = float(1.0 + 0.12 * _dsev_transient)

        # §PANNs: scale vocal/instrument families by actual detected presence.
        # Near-zero vocal prob → spare the vocal processing budget.
        # Strong vocal → push vocal family harder.
        _panns_vocal_boost = 1.0
        _panns_instrument_boost = 1.0
        _vocal_prob = 0.0
        _inst_prob = 0.0
        if isinstance(panns_tags, dict) and panns_tags:
            _vocal_prob = max(
                float(panns_tags.get("Singing voice", 0.0) or 0),
                float(panns_tags.get("Speech", 0.0) or 0),
                float(panns_tags.get("Vocals", 0.0) or 0),
                float(panns_tags.get("Male singing", 0.0) or 0),
                float(panns_tags.get("Female singing", 0.0) or 0),
            )
            _inst_prob = max(
                float(panns_tags.get("Guitar", 0.0) or 0),
                float(panns_tags.get("Electric guitar", 0.0) or 0),
                float(panns_tags.get("Brass instrument", 0.0) or 0),
                float(panns_tags.get("Drum", 0.0) or 0),
                float(panns_tags.get("Piano", 0.0) or 0),
                float(panns_tags.get("Keyboard (musical)", 0.0) or 0),
            )
            if _vocal_prob < 0.10:  # clearly instrumental
                _panns_vocal_boost = 0.80
            elif _vocal_prob >= 0.35:  # vocal-dominant
                _panns_vocal_boost = float(np.clip(0.90 + 0.22 * _vocal_prob, 0.90, 1.10))
            if _inst_prob >= 0.35:
                _panns_instrument_boost = float(np.clip(0.90 + 0.22 * _inst_prob, 0.90, 1.10))

        _genre_norm = str(genre_label or "").strip().lower()
        _frisson_sensitivity = 0.0
        if _genre_norm in {"oper", "opera", "klassik", "classical", "choral", "soundtrack", "ambient"}:
            _frisson_sensitivity += 0.45
        elif _genre_norm in {"jazz", "blues", "soul", "schlager"}:
            _frisson_sensitivity += 0.22
        if bool(is_schlager):
            _frisson_sensitivity += 0.10
        if _vocal_prob >= 0.35:
            _frisson_sensitivity += float(np.clip((_vocal_prob - 0.35) / 0.65, 0.0, 1.0)) * 0.28
        _frisson_sensitivity = float(np.clip(_frisson_sensitivity, 0.0, 1.0))

        # §Spectral-Fingerprint-Kalibrierung: direkte Messgrößen aus DefectScanner nutzen.
        # rolloff_95_hz < 8 kHz → Bandbreitenverlust → reconstruction-Familie hochskalieren.
        # noise_floor_p5_db    → präzisere denoise-Kalibrierung als globale SNR-Heuristik.
        # wow_flutter_index    → Tonhalteschwankung → dynamics_eq-Familie.
        _sf_reconstruct_boost = 1.0
        _sf_denoise_boost = 1.0
        _sf_dynq_boost = 1.0
        if isinstance(spectral_fingerprint, dict) and spectral_fingerprint:
            _rolloff = float(spectral_fingerprint.get("rolloff_95_hz", 20000.0))
            _eff_bw = float(spectral_fingerprint.get("effective_bandwidth_hz", 20000.0))
            _nf_db = float(spectral_fingerprint.get("noise_floor_p5_db", -72.0))
            _wfi = float(spectral_fingerprint.get("wow_flutter_index", 0.0))
            # Bandwidth loss: rolloff below 8 kHz = clear HF truncation.
            # Linear scale: 8000 Hz → +0%, 4000 Hz → +10%, 2000 Hz → +15%.
            _bw_use = min(_rolloff, _eff_bw)  # take the more conservative estimate
            _sf_reconstruct_boost = float(np.clip(1.0 + 0.15 * max(0.0, (8000.0 - _bw_use) / 8000.0), 1.00, 1.15))
            # Noise floor: −40 dBFS = very noisy (+10%), −72 dBFS = clean (no boost).
            _nf_noise_frac = float(np.clip((_nf_db + 72.0) / 32.0, 0.0, 1.0))  # 0.0@−72, 1.0@−40
            _sf_denoise_boost = float(np.clip(1.0 + 0.10 * _nf_noise_frac, 1.00, 1.10))
            # Wow/Flutter Index: > 1.5 typical for cassette / damaged tape.
            _sf_dynq_boost = float(np.clip(1.0 + 0.08 * min(_wfi / 2.0, 1.0), 1.00, 1.08))

        # §Vintage-Charakter-Schutz: SOFT_SATURATION (Röhren-/Tape-Charakter) darf
        # NICHT als Defekt behandelt werden (§5 Vintage Aesthetics — bindend).
        # Hohe SOFT_SATURATION-Severity → denoise + transient-Familie dämpfen,
        # damit H2/H4-Obertöne und der Sättigungs-Charakter erhalten bleiben.
        _soft_sat_guard = 1.0
        _soft_sat_transient_guard = 1.0
        if isinstance(defect_scores, dict):
            _sat_sev = float(np.clip(defect_scores.get("soft_saturation", 0.0), 0.0, 1.0))
            if _sat_sev >= 0.25:
                # Reduce denoise aggressiveness proportionally — preserve harmonic overtones.
                _soft_sat_guard = float(np.clip(1.0 - 0.12 * _sat_sev, 0.88, 1.00))
                # Reduce transient processing slightly — soft clipping rounds transients by design.
                _soft_sat_transient_guard = float(np.clip(1.0 - 0.07 * _sat_sev, 0.93, 1.00))

        # §Defekt-Diversitäts-Dämpfung: wenn ≥8 unterschiedliche Defektarten gleichzeitig
        # aktiv sind (severity ≥ 0.18), leichte globale Reduzierung um max. 6%.
        # Verhindert kompounding Restorer-Interaktionen bei sehr stark geschädigtem Material.
        _diversity_penalty = 1.0
        if isinstance(defect_scores, dict) and defect_scores:
            _n_active = sum(1 for v in defect_scores.values() if float(v) >= 0.18)
            if _n_active >= 8:
                _diversity_penalty = float(np.clip(1.0 - 0.01 * min(_n_active - 7, 6), 0.94, 1.00))

        # §German-Schlager-Profil: Vokal-Intimität und Rhythmus-Klarheit priorisieren.
        # Vocal +10%, Transient +5% (Schlagzeug-Punch), Dynamics +5% (Accordion-Schwung).
        # Reconstruction leicht reduziert (Schlager-Aufnahmen sind meist gut erhalten).
        _schlager_vocal_boost = 1.0
        _schlager_transient = 1.0
        _schlager_dynamics = 1.0
        _schlager_recon_factor = 1.0
        if is_schlager:
            _schlager_vocal_boost = 1.10
            _schlager_transient = 1.05
            _schlager_dynamics = 1.05
            _schlager_recon_factor = 0.95  # less aggressive reconstruction on intact vocal recordings

        # §Genre-Profil: Jazz/Klassik/Oper/Rock-spezifische family_scalars (±15% max).
        # Korrekturen sind konservativ und ergänzen die Schlager-Faktoren statt sie zu ersetzen.
        _genre_reverb_factor = 1.0
        _genre_dynamics_factor = 1.0
        _genre_transient_factor = 1.0
        _genre_vocal_factor = 1.0
        _genre_denoise_factor = 1.0
        _genre_label_l = genre_label.strip().lower() if genre_label else ""
        if _genre_label_l in ("klassik", "oper"):
            # Klassik/Oper: Raumklang ist Teil der Authentizität → Dereverb-Druck dämpfen.
            _genre_reverb_factor = 0.80
            # Orchesterdynamik bewahren → Kompression/EQ minimal.
            _genre_dynamics_factor = 0.85
            # Pizzicato-, Forte-Anschläge: Transient-Integrität wichtig.
            _genre_transient_factor = 1.05
            # Gemäßigte Rauschreduzierung (Rauschanteile tragen Raumgefühl).
            _genre_denoise_factor = 0.92
            if _genre_label_l == "oper":
                # Oper: Vokalprominenz zusätzlich stärken (Formanten, Vibrato, Singformant).
                _genre_vocal_factor = 1.08
        elif _genre_label_l == "jazz":
            # Jazz: Club-Raumatmosphäre + Swing-Dynamik bewahren.
            _genre_reverb_factor = 0.85
            _genre_dynamics_factor = 0.88
            # Bass/Bläser/Schlagzeug-Transienten stärken.
            _genre_transient_factor = 1.02
        elif _genre_label_l == "rock":
            # Rock: Schlagzeug-Punch + Power-Chord-Transienten.
            _genre_transient_factor = 1.05
            # Rock hat oft gewollte Sättigung → denoise konservativer.
            _genre_denoise_factor = 0.95
        elif _genre_label_l in ("metal",):
            # Metal: Extremtransienten (Double-Bass, Gitarren-Attack) bewahren.
            _genre_transient_factor = 1.08
            # Gewollte Gainstruktur → kein aggressives Dereverb.
            _genre_reverb_factor = 0.90
            _genre_denoise_factor = 0.95
        elif _genre_label_l in ("electronic", "hip-hop"):
            # Electronic / Hip-Hop: absichtlich komprimiert und begrenzt produziert.
            # Dynamik-Prozesse interpretieren legitime Limitierung als Defekt → dämpfen.
            _genre_dynamics_factor = 0.80
            # Sub-Bass-Transienten (808, Kick) sind genre-definierend → schonen.
            _genre_transient_factor = 1.03
            # Digitale Quellen: denoise eher konservativ (oft sauber produziert).
            _genre_denoise_factor = 0.92
            # Dereverb: Producer-Raum ist Intention, nicht Defekt → stark dämpfen.
            _genre_reverb_factor = 0.75
        elif _genre_label_l == "pop":
            # Pop: Modernes Studio-Finish, oft bereits sauber produziert.
            # Artifizielle Komprimierung respektieren → Dynamik-Phasen gedämpft.
            _genre_dynamics_factor = 0.90
            # Pop-Mix-Reverb ist Produktion, kein Raumakustikartefakt → konservativ.
            _genre_reverb_factor = 0.90
            # Denoise nur wo nötig (Pop oft digitaler Ursprung).
            _genre_denoise_factor = 0.93
        elif _genre_label_l in ("soul/r&b", "soul", "r&b"):
            # Soul/R&B: Warmer, intimer Raumklang durch Studiomischregel — bewahren.
            _genre_reverb_factor = 0.85
            # Dynamische Ausdruckskraft schützen (Vocal-Swells, Fade-Ins).
            _genre_dynamics_factor = 0.92
            # Vokalprominenz leicht steigern — Vokallinien sind Genre-definierend.
            _genre_vocal_factor = 1.05
        elif _genre_label_l in ("blues",):
            # Blues: Röhrenverstärker-Sättigung + Slide-Transienten sind Klangidentität.
            _genre_denoise_factor = 0.92
            _genre_transient_factor = 1.03
            # Club-Raumatmosphäre bewahren.
            _genre_reverb_factor = 0.88
        elif _genre_label_l in ("country",):
            # Country: Nashville-Raumklang + akustische Transienten (Banjo, Flat-Pick).
            _genre_reverb_factor = 0.85
            _genre_transient_factor = 1.04
        elif _genre_label_l in ("folk",):
            # Folk: Minimale Produktion, natürlicher Raumklang eines kleinen Raums.
            _genre_reverb_factor = 0.83
            # Sehr natürlich → denoise sehr konservativ (Atemgeräusche, Saiten = Textur).
            _genre_denoise_factor = 0.90
        elif _genre_label_l in ("reggae",):
            # Reggae: Hall + Echo sind ABSICHTLICHE ikonische Stilmittel (Dub, One-Drop).
            # Aggressives Dereverb würde den Klang zerstören → sehr stark dämpfen.
            _genre_reverb_factor = 0.55
            # Laid-back One-Drop-Groove nicht verschärfen.
            _genre_transient_factor = 0.97
        elif _genre_label_l in ("latin",):
            # Latin (Salsa, Bossa Nova, Cumbia): Rhythmische Transienten (Conga, Bongo, Claves).
            _genre_transient_factor = 1.05
            _genre_reverb_factor = 0.88
        elif _genre_label_l in ("funk",):
            # Funk: Groove-Präzision, Brass-Attacken, Slap-Bass-Transienten.
            _genre_transient_factor = 1.06
            _genre_dynamics_factor = 0.93
        elif _genre_label_l in ("gospel",):
            # Gospel: Kirchenhall ist Teil der Authentizität → Dereverb stark dämpfen.
            _genre_reverb_factor = 0.65
            # Chor-Vokalprominenz schützen.
            _genre_vocal_factor = 1.05
        _global = 1.0
        _global *= 0.90 + 0.20 * _def
        _global *= 0.88 + 0.24 * _rest
        _global *= 0.90 + 0.10 * (1.0 - _snr)
        _global *= 0.92 + 0.16 * _conf
        _global *= _diversity_penalty
        # [RELEASE_MUST] Lücke-G-Fix v9.10.100: global_scalar ∈ [0.50, 1.50]
        # Unteres Limit 0.50 verhindert Neutralisierung aller Phasen.
        # Oberes Limit 1.50 verhindert Umgehung des Soft-Saturation-Guards.
        _global = float(np.clip(_global, 0.50, 1.50))

        _global = UnifiedRestorerV3._pullback_from_bounds(_global, 0.50, 1.50, margin_frac=0.03)

        # [RELEASE_MUST] Lücke-G-Fix v9.10.100: family_scalars[*] ∈ [0.30, 1.80]
        # Untergrenze 0.30 schützt vor Komplettunterdrückung einer Familie.
        # Obergrenze 1.80 verhindert Überamplitude in einzelnen Verarbeitungsstufen.
        _family = {
            "denoise": float(
                np.clip(
                    _global
                    * _mat_denoise
                    * _era_denoise_scale
                    * (0.92 + 0.10 * (1.0 - _snr))
                    * _sf_denoise_boost
                    * _soft_sat_guard
                    * _genre_denoise_factor,
                    0.30,
                    1.80,
                )
            ),
            "reverb": float(np.clip(_global * _mat_reverb * (0.90 + 0.14 * _def) * _genre_reverb_factor, 0.30, 1.80)),
            "reconstruction": float(
                np.clip(
                    _global
                    * _mat_reconstruct
                    * (0.88 + 0.16 * (1.0 - _conf))
                    * _sf_reconstruct_boost
                    * _schlager_recon_factor,
                    0.30,
                    1.80,
                )
            ),
            "dynamics_eq": float(
                np.clip(
                    _global
                    * _mat_dynamics
                    * (0.92 + 0.10 * _rest)
                    * _sf_dynq_boost
                    * _schlager_dynamics
                    * _genre_dynamics_factor,
                    0.30,
                    1.80,
                )
            ),
            "transient": float(
                np.clip(
                    _global
                    * (0.95 + 0.06 * _conf)
                    * _dsev_transient_boost
                    * _soft_sat_transient_guard
                    * _schlager_transient
                    * _genre_transient_factor,
                    0.30,
                    1.80,
                )
            ),
            "vocal": float(
                np.clip(
                    _global
                    * _mat_vocal
                    * (0.92 + 0.08 * _rest)
                    * _panns_vocal_boost
                    * _schlager_vocal_boost
                    * _genre_vocal_factor,
                    0.30,
                    1.80,
                )
            ),
            "instrument": float(np.clip(_global * (0.90 + 0.10 * _rest) * _panns_instrument_boost, 0.30, 1.80)),
            "general": _global,
        }

        # Sanfter Stabilitäts-Pullback auch für Familien-Skalare (keine harte Kantenfahrt).
        for _k, _v in list(_family.items()):
            _family[_k] = UnifiedRestorerV3._pullback_from_bounds(float(_v), 0.30, 1.80, margin_frac=0.03)

        # §Mode differentiation: Studio 2026 permits more aggressive reconstruction,
        # transient shaping and vocal enhancement (higher quality budget).
        _mode_str = getattr(mode, "value", str(mode)).lower()
        if "studio" in _mode_str or "maximum" in _mode_str:
            _family["reconstruction"] = float(np.clip(_family["reconstruction"] * 1.08, 0.30, 1.80))
            _family["transient"] = float(np.clip(_family["transient"] * 1.05, 0.30, 1.80))
            _family["vocal"] = float(np.clip(_family["vocal"] * 1.05, 0.30, 1.80))
            _family["instrument"] = float(np.clip(_family["instrument"] * 1.05, 0.30, 1.80))

        if restorability_score < 40.0:
            _tier = "poor"
        elif restorability_score < 70.0:
            _tier = "fair"
        else:
            _tier = "good"

        # §2.41 SourceFidelityReconstructor — Klangtreue zum Aufnahmetag (v9.10.115)
        # Schätzt die Signallücke zwischen aktuellem Träger und dem Original am
        # Aufnahmetag. Modelliert äraspezifische Original-Bandbreite + akkumulierte
        # Überspielgenerations-Verluste. Ergebnis: reconstruction-Familie gezielt
        # boosten, Zielbandbreite für Phase 06 bereistellen.
        _sfr_bw_target = 20000.0
        _sfr_recon_strength = 0.0
        _sfr_confidence = 0.5
        _sfr_gen_count = 1
        _sfr_hf_loss = 0.0
        _sfr_harm_density = 1.0
        _sfr_era_mic_type = "condenser_modern"
        _sfr_presence_lower = 4000.0
        _sfr_presence_upper = 6500.0
        try:
            from backend.core.source_fidelity_reconstructor import get_source_fidelity_reconstructor

            _sfr = get_source_fidelity_reconstructor()
            _sfr_target = _sfr.estimate(
                era_decade=era_decade,
                material_key=_mat_val,
                spectral_fingerprint=spectral_fingerprint,
                transfer_chain=transfer_chain,
                mode=_mode_str,
            )
            _sfr_bw_target = _sfr_target.bandwidth_extension_target_hz
            _sfr_recon_strength = _sfr_target.reconstruction_strength
            _sfr_confidence = _sfr_target.confidence
            _sfr_gen_count = _sfr_target.transfer_generation_count
            _sfr_hf_loss = _sfr_target.cumulative_hf_loss_db
            _sfr_harm_density = _sfr_target.era_harmonic_density
            _sfr_era_mic_type = _sfr_target.era_mic_type
            _sfr_presence_lower = _sfr_target.presence_center_hz_lower
            _sfr_presence_upper = _sfr_target.presence_center_hz_upper
            # Reconstruction-Familie boosten: confidence-gewichteter Boost [0.0%, +20%].
            # Digitale Quellen (confidence<0.4, gen_count=1) → nahezu kein Boost.
            # Altes Shellac/Vinyl mit vielen Generationen → signifikanter Boost.
            _sfr_recon_boost = float(np.clip(_sfr_recon_strength * _sfr_confidence * 0.20, 0.0, 0.20))
            if _sfr_recon_boost >= 0.01:
                _family["reconstruction"] = float(
                    np.clip(_family["reconstruction"] * (1.0 + _sfr_recon_boost), 0.30, 1.80)
                )
            logger.debug(
                "SourceFidelity: recon_boost=+%.2f bw_gap=%.0fHz gen=%d hf_loss=%.1fdB conf=%.2f mic=%s",
                _sfr_recon_boost,
                _sfr_target.bandwidth_gap_hz,
                _sfr_gen_count,
                _sfr_hf_loss,
                _sfr_confidence,
                _sfr_era_mic_type,
            )
        except Exception as _sfr_exc:
            logger.debug("SourceFidelityReconstructor nicht verfügbar: %s", _sfr_exc)

        _cluster_policy = UnifiedRestorerV3._derive_song_cluster_policy(
            material=_mat_val,
            era_decade=era_decade,
            genre_label=genre_label,
            restorability_tier=_tier,
            is_schlager=bool(is_schlager),
        )

        return {
            "material": _mat_val,
            "mode": getattr(mode, "value", str(mode)),
            "restorability_score": float(restorability_score),
            "restorability_tier": _tier,
            "input_snr_db": float(input_snr_db),
            "max_defect_severity": float(max_defect_severity),
            "pipeline_confidence": _conf,
            "era_decade": era_decade,
            "is_schlager": is_schlager,
            "genre_label": genre_label,
            "global_scalar": _global,
            "family_scalars": _family,
            "vocal_presence": float(np.clip(_vocal_prob, 0.0, 1.0)),
            "instrument_presence": float(np.clip(_inst_prob, 0.0, 1.0)),
            "frisson_sensitivity": _frisson_sensitivity,
            "cluster_policy": _cluster_policy,
            "cluster_key": _cluster_policy.get("cluster_key", "unknown:unknown:general:fair"),
            # §2.41 Source-Fidelity-Felder für Phase 06 und ExcellenceOptimizer:
            "source_fidelity_bandwidth_target_hz": _sfr_bw_target,
            "source_fidelity_reconstruction_strength": _sfr_recon_strength,
            "source_fidelity_confidence": _sfr_confidence,
            "source_fidelity_generation_count": _sfr_gen_count,
            "source_fidelity_hf_loss_db": _sfr_hf_loss,
            "source_fidelity_harmonic_density": _sfr_harm_density,
            "source_fidelity_transfer_chain": list(transfer_chain) if transfer_chain else [],
            # §2.41 (v9.10.116) SOTA: Ära-Mikrofon-Typ + Presence-Center für Phase 38:
            "source_fidelity_era_mic_type": _sfr_era_mic_type,
            "source_fidelity_presence_hz_lower": _sfr_presence_lower,
            "source_fidelity_presence_hz_upper": _sfr_presence_upper,
        }

    @staticmethod
    def _extract_transfer_chain_from_forensics(raw_chain: Any) -> list[str] | None:
        """Extract normalized transfer chain from forensic/raw chain containers."""
        if raw_chain is None:
            return None

        chain_src: Any = None
        if isinstance(raw_chain, str | list | tuple):
            chain_src = raw_chain
        elif isinstance(raw_chain, dict):
            chain_src = raw_chain.get("transfer_chain") or raw_chain.get("chain")
        else:
            chain_src = getattr(raw_chain, "transfer_chain", None) or getattr(raw_chain, "chain", None)

        if chain_src is None:
            return None

        if isinstance(chain_src, str):
            _norm = chain_src.replace("->", ">").replace("→", ">")
            _tokens = [p.strip().lower() for p in _norm.split(">") if p.strip()]
            return _tokens or None

        if isinstance(chain_src, (list, tuple)):
            _out = [str(v).strip().lower() for v in chain_src if str(v).strip()]
            return _out or None

        return None

    @staticmethod
    def _infer_tape_speed_ips(
        material_type: Any,
        era_decade: int | None,
        transfer_chain: list[str] | None = None,
    ) -> float | None:
        """Infer tape speed in IPS from material type, era, and transfer chain.

        Used to inject ``tape_speed_ips`` into ``_restoration_context`` so that
        phase_04 head-bump compensation fires automatically for tape material
        (§copilot-instructions HEAD_BUMP_PROFILES invariant).

        Also searches the full transfer_chain for tape intermediate stages so that
        multi-generation chains such as vinyl → tape → mp3_low correctly trigger
        head-bump compensation even when the primary material is vinyl/shellac.

        Returns None for non-tape materials (no head-bump compensation needed).
        """

        def _ips_for_mat(mat_str: str) -> float | None:
            if "cassette" in mat_str:
                return 1.875  # IEC standard compact cassette speed
            if "reel_tape" in mat_str:
                # Professional reel-to-reel: 15 ips dominant from 1960s onward; earlier 7.5 ips
                return 15.0 if (era_decade is not None and era_decade >= 1960) else 7.5
            if "tape" in mat_str:
                return 7.5  # Generic tape: conservative default
            return None

        mat_str = (material_type.value if hasattr(material_type, "value") else str(material_type)).lower()
        _primary_result = _ips_for_mat(mat_str)
        if _primary_result is not None:
            return _primary_result

        # §2.46a: For multi-generation chains (e.g. vinyl → tape → mp3_low) the
        # primary material is not tape, but a tape intermediate stage still imprints
        # a head-bump LF boost that must be compensated.  Scan transfer_chain for
        # the first tape-family stage and return its speed.
        if transfer_chain:
            for stage in transfer_chain:
                stage_lower = str(stage).lower()
                _chain_result = _ips_for_mat(stage_lower)
                if _chain_result is not None:
                    return _chain_result

        return None  # vinyl, shellac, digital, etc. — head-bump not applicable

    @staticmethod
    def _phase_family_from_phase_id(phase_id: str) -> str:
        """Map phase id to calibration family used by song-level adaptation."""
        try:
            _parts = phase_id.split("_", 2)
            _phase_num = int(_parts[1]) if len(_parts) > 1 else -1
        except Exception:
            _phase_num = -1

        if _phase_num in {2, 3, 18, 29, 37}:
            return "denoise"
        if _phase_num in {20, 49}:
            return "reverb"
        if _phase_num in {6, 7, 9, 23, 24, 55, 56, 57, 58}:
            return "reconstruction"
        if _phase_num in {4, 10, 17, 26, 31, 36, 40, 47}:
            return "dynamics_eq"
        if _phase_num in {8, 11, 50, 12}:
            return "transient"
        if _phase_num in {19, 42, 43}:
            return "vocal"
        if _phase_num in {44, 45, 46, 51, 52}:
            return "instrument"
        return "general"

    @staticmethod
    def _phase_budget_prefix(phase_id: str) -> str | None:
        """Return stable prefix like phase_42 for budget heuristics."""
        parts = str(phase_id).split("_", 2)
        if len(parts) >= 2 and parts[0] == "phase" and parts[1].isdigit():
            return f"phase_{parts[1]}"
        return None

    @classmethod
    def _phase_has_musical_budget_priority(cls, phase_id: str) -> bool:
        """Return True for phases that should be protected under budget pressure."""
        _prefix = cls._phase_budget_prefix(phase_id)
        if _prefix is None:
            return False
        _priority_prefixes = frozenset(
            {
                "phase_19",
                "phase_20",
                "phase_24",
                "phase_29",
                "phase_42",
                "phase_43",
                "phase_49",
                "phase_55",
                "phase_58",
            }
        )
        return _prefix in _priority_prefixes

    def _record_phase_budget_gain(self, phase_id: str, material_key: str, net_gain: float) -> None:
        """Track accepted per-phase net gain for later budget-pressure deprioritisation."""
        _prefix = self._phase_budget_prefix(phase_id)
        if _prefix is None:
            return
        _mat_key = str(material_key or "unknown").lower()
        _mat_hist = self._phase_budget_gain_history.setdefault(_mat_key, {})
        _entry = _mat_hist.setdefault(_prefix, {"samples": 0.0, "mean_net_gain": 0.0})
        _samples = float(_entry.get("samples", 0.0))
        _mean = float(_entry.get("mean_net_gain", 0.0))
        _gain = float(np.clip(net_gain, -0.25, 0.25))
        _new_samples = _samples + 1.0
        _entry["samples"] = _new_samples
        _entry["mean_net_gain"] = (_mean * _samples + _gain) / _new_samples

    def _accepted_phase_net_gain(
        self,
        before_audio: np.ndarray,
        after_audio: np.ndarray,
        _sample_rate: int,
    ) -> float:
        """Estimate the accepted musical net gain after all post-phase guards finished."""
        if np.array_equal(before_audio, after_audio):
            return 0.0
        try:
            _before = np.asarray(before_audio, dtype=np.float32)
            _after = np.asarray(after_audio, dtype=np.float32)
            if _before.ndim > 1:
                _before = np.mean(_before, axis=-1)
            if _after.ndim > 1:
                _after = np.mean(_after, axis=-1)
            _n = min(len(_before), len(_after))
            if _n < 16:
                return 0.0
            _before = _before[:_n]
            _after = _after[:_n]
            _rms_before = float(np.sqrt(np.mean(_before**2) + 1e-12))
            _rms_after = float(np.sqrt(np.mean(_after**2) + 1e-12))
            _edge_before = float(np.mean(np.abs(np.diff(_before))))
            _edge_after = float(np.mean(np.abs(np.diff(_after))))
            _rms_delta = _rms_after - _rms_before
            _edge_delta = _edge_after - _edge_before
            return float(0.7 * _rms_delta + 0.3 * _edge_delta)
        except Exception:
            return 0.0

    def _budget_pressure_skip_reason(
        self,
        phase_id: str,
        *,
        material_key: str,
        remaining_budget_s: float,
        estimated_time_s: float,
        future_phases: list[str],
    ) -> dict[str, Any] | None:
        """Return a skip reason when budget should be reserved for higher-yield phases."""
        _prefix = self._phase_budget_prefix(phase_id)
        if _prefix is None or self._phase_has_musical_budget_priority(phase_id):
            return None

        _reserve_threshold_s = max(estimated_time_s * 1.25, 15.0)
        if remaining_budget_s > _reserve_threshold_s:
            return None

        _future_priority = next(
            (p for p in future_phases if self._phase_has_musical_budget_priority(p)),
            None,
        )
        _late_cosmetic_prefixes = frozenset(
            {
                "phase_16",
                "phase_17",
                "phase_39",
                "phase_40",
                "phase_41",
                "phase_46",
                "phase_48",
                "phase_53",
            }
        )
        if _future_priority is not None and _prefix in _late_cosmetic_prefixes:
            return {
                "reason": "reserve_for_priority_followup",
                "future_priority_phase": _future_priority,
                "remaining_budget_s": round(float(remaining_budget_s), 3),
                "estimated_time_s": round(float(estimated_time_s), 3),
            }

        _hist = self._phase_budget_gain_history.get(str(material_key).lower(), {}).get(_prefix)
        if _hist is None:
            return None
        _samples = int(round(float(_hist.get("samples", 0.0))))
        _mean_gain = float(_hist.get("mean_net_gain", 0.0))
        if _samples >= 2 and _mean_gain < 0.004:
            return {
                "reason": "historically_weak_delta",
                "history_samples": _samples,
                "history_mean_net_gain": round(_mean_gain, 5),
                "remaining_budget_s": round(float(remaining_budget_s), 3),
                "estimated_time_s": round(float(estimated_time_s), 3),
            }

        return None

    @staticmethod
    def _compute_quiet_edge_prevention_profile(
        audio: np.ndarray,
        sr: int,
        *,
        material_key: str | None = None,
    ) -> dict[str, Any]:
        """Detect quiet song edges so risky positive-gain phases can be capped early."""
        try:
            from backend.core.audio_utils import compute_gated_rms_dbfs, compute_signal_relative_gate_dbfs, safe_to_mono

            mono = safe_to_mono(np.asarray(audio, dtype=np.float32))
            n = len(mono)
            if n < max(int(sr * 2.0), 4_800):
                return {"has_quiet_edges": False}

            edge_len = min(int(sr * 4.0), max(int(sr * 1.0), int(n * 0.10)))
            centre_len = min(int(sr * 4.0), max(int(sr * 1.0), int(n * 0.20)))
            centre_start = max(0, (n - centre_len) // 2)
            gate_dbfs = compute_signal_relative_gate_dbfs(
                mono,
                fallback_gate_dbfs=-36.0,
                material_key=material_key,
            )
            centre_db = compute_gated_rms_dbfs(mono[centre_start : centre_start + centre_len], gate_dbfs=gate_dbfs)
            intro_db = compute_gated_rms_dbfs(mono[:edge_len], gate_dbfs=gate_dbfs)
            outro_db = compute_gated_rms_dbfs(mono[-edge_len:], gate_dbfs=gate_dbfs)

            intro_quiet = bool((intro_db <= gate_dbfs + 3.0) or (intro_db <= centre_db - 6.0))
            outro_quiet = bool((outro_db <= gate_dbfs + 3.0) or (outro_db <= centre_db - 6.0))
            intro_depth_db = float(max(0.0, centre_db - intro_db))
            outro_depth_db = float(max(0.0, centre_db - outro_db))
            edge_count = int(intro_quiet) + int(outro_quiet)

            return {
                "has_quiet_edges": bool(edge_count > 0),
                "intro_quiet": intro_quiet,
                "outro_quiet": outro_quiet,
                "edge_count": edge_count,
                "gate_dbfs": float(gate_dbfs),
                "centre_dbfs": float(centre_db),
                "intro_dbfs": float(intro_db),
                "outro_dbfs": float(outro_db),
                "intro_depth_db": intro_depth_db,
                "outro_depth_db": outro_depth_db,
            }
        except Exception:
            return {"has_quiet_edges": False}

    @staticmethod
    def _apply_prevent_first_policy(
        family_scalars: dict[str, float],
        phase_caps: dict[str, float],
        *,
        quiet_edge_profile: dict[str, Any] | None,
        vocal_presence: float,
        frisson_sensitivity: float,
    ) -> tuple[dict[str, float], dict[str, float], dict[str, Any]]:
        """Apply early preventive caps for positive-gain risk classes.

        This helper centralizes bounded preventive policy shaping for quiet song
        edges, vocal-dominant material and frisson-sensitive material.
        """
        _family = {str(k): float(v) for k, v in family_scalars.items()}
        _phase_caps = {str(k): float(v) for k, v in phase_caps.items()}
        _quiet_profile = quiet_edge_profile if isinstance(quiet_edge_profile, dict) else {}
        _vocal_presence = float(np.clip(vocal_presence, 0.0, 1.0))
        _frisson_sensitivity = float(np.clip(frisson_sensitivity, 0.0, 1.0))

        if bool(_quiet_profile.get("has_quiet_edges", False)):
            _edge_count = int(np.clip(_quiet_profile.get("edge_count", 0), 0, 2))
            _max_depth_db = float(
                np.clip(
                    max(
                        float(_quiet_profile.get("intro_depth_db", 0.0)),
                        float(_quiet_profile.get("outro_depth_db", 0.0)),
                    ),
                    0.0,
                    24.0,
                )
            )
            _edge_severity = float(np.clip(0.85 + 0.07 * _edge_count + 0.01 * _max_depth_db, 0.88, 1.10))
            _family["dynamics_eq"] = float(
                np.clip(_family.get("dynamics_eq", 1.0) * (1.0 - 0.10 * _edge_severity), 0.30, 1.80)
            )
            _family["vocal"] = float(np.clip(_family.get("vocal", 1.0) * (1.0 - 0.05 * _edge_severity), 0.30, 1.80))

            for _pid, _cap in {
                "phase_10_compression": float(np.clip(0.42 - 0.03 * (_edge_count - 1), 0.34, 0.42)),
                "phase_17_mastering_polish": float(np.clip(0.38 - 0.03 * (_edge_count - 1), 0.30, 0.38)),
                "phase_26_dynamic_range_expansion": float(np.clip(0.40 - 0.03 * (_edge_count - 1), 0.32, 0.40)),
                "phase_40_loudness_normalization": float(np.clip(0.34 - 0.04 * (_edge_count - 1), 0.26, 0.34)),
                "phase_41_output_format_optimization": float(np.clip(0.38 - 0.04 * (_edge_count - 1), 0.30, 0.38)),
            }.items():
                _phase_caps[_pid] = min(float(_phase_caps.get(_pid, 1.0)), float(_cap))

        if _vocal_presence >= 0.35:
            _vocal_severity = float(np.clip((_vocal_presence - 0.35) / 0.65, 0.0, 1.0))
            _family["vocal"] = float(np.clip(_family.get("vocal", 1.0) * (1.0 - 0.08 * _vocal_severity), 0.30, 1.80))
            _family["dynamics_eq"] = float(
                np.clip(_family.get("dynamics_eq", 1.0) * (1.0 - 0.04 * _vocal_severity), 0.30, 1.80)
            )

            for _pid, _cap in {
                "phase_10_compression": float(np.clip(0.42 - 0.02 * _vocal_severity, 0.36, 0.42)),
                "phase_17_mastering_polish": float(np.clip(0.37 - 0.03 * _vocal_severity, 0.31, 0.37)),
                "phase_42_vocal_enhancement": float(np.clip(0.34 - 0.05 * _vocal_severity, 0.28, 0.34)),
                "phase_43_ml_deesser": float(np.clip(0.38 - 0.04 * _vocal_severity, 0.31, 0.38)),
            }.items():
                _phase_caps[_pid] = min(float(_phase_caps.get(_pid, 1.0)), float(_cap))

        if _frisson_sensitivity >= 0.25:
            _family["dynamics_eq"] = float(
                np.clip(_family.get("dynamics_eq", 1.0) * (1.0 - 0.06 * _frisson_sensitivity), 0.30, 1.80)
            )
            _family["reverb"] = float(
                np.clip(_family.get("reverb", 1.0) * (1.0 - 0.04 * _frisson_sensitivity), 0.30, 1.80)
            )

            for _pid, _cap in {
                "phase_10_compression": float(np.clip(0.40 - 0.04 * _frisson_sensitivity, 0.34, 0.40)),
                "phase_17_mastering_polish": float(np.clip(0.35 - 0.05 * _frisson_sensitivity, 0.29, 0.35)),
                "phase_20_reverb_reduction": float(np.clip(0.26 - 0.04 * _frisson_sensitivity, 0.20, 0.26)),
                "phase_26_dynamic_range_expansion": float(np.clip(0.38 - 0.04 * _frisson_sensitivity, 0.31, 0.38)),
                "phase_49_advanced_dereverb": float(np.clip(0.24 - 0.04 * _frisson_sensitivity, 0.18, 0.24)),
            }.items():
                _phase_caps[_pid] = min(float(_phase_caps.get(_pid, 1.0)), float(_cap))

        return (
            _family,
            _phase_caps,
            {
                "quiet_edge_prevention": dict(_quiet_profile) if _quiet_profile else {"has_quiet_edges": False},
                "vocal_prevention": {
                    "active": bool(_vocal_presence >= 0.35),
                    "vocal_presence": float(_vocal_presence),
                },
                "frisson_prevention": {
                    "active": bool(_frisson_sensitivity >= 0.25),
                    "frisson_sensitivity": float(_frisson_sensitivity),
                },
            },
        )

    @staticmethod
    def _apply_song_autosetup_policy(
        profile: dict[str, Any],
        *,
        defect_scores: dict[str, float] | None,
        transfer_chain: list[str] | None,
        max_defect_severity: float,
        quiet_edge_profile: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        """Apply strict per-song autosetup policy for fidelity/defect/carrier restoration.

        This policy is deterministic and bounded. It tunes family scalars from
        transfer-chain depth and dominant defect topology and installs strict
        phase caps for conflict-prone phases.
        """
        if not isinstance(profile, dict) or not profile:
            return profile

        _out = dict(profile)
        _family = dict(_out.get("family_scalars", {})) if isinstance(_out.get("family_scalars"), dict) else {}
        if not _family:
            return _out

        _chain = (
            UnifiedRestorerV3._extract_transfer_chain_from_forensics(
                transfer_chain or _out.get("source_fidelity_transfer_chain")
            )
            or []
        )
        _chain_depth = len(_chain)
        _max_def = float(np.clip(max_defect_severity, 0.0, 1.0))
        _mat = str(_out.get("material", "unknown") or "unknown").lower()
        _tier = str(_out.get("restorability_tier", "fair") or "fair").lower()
        _quiet_profile = quiet_edge_profile if isinstance(quiet_edge_profile, dict) else {}

        # Carrier-chain awareness: deeper transfer chains need stronger subtractive +
        # reconstruction handling while keeping transients protected.
        if _chain_depth >= 3:
            _family["reconstruction"] = float(np.clip(_family.get("reconstruction", 1.0) * 1.08, 0.30, 1.80))
            _family["denoise"] = float(np.clip(_family.get("denoise", 1.0) * 1.05, 0.30, 1.80))
            _family["transient"] = float(np.clip(_family.get("transient", 1.0) * 0.96, 0.30, 1.80))
        if _chain_depth >= 4:
            _family["reconstruction"] = float(np.clip(_family.get("reconstruction", 1.0) * 1.05, 0.30, 1.80))
            _family["dynamics_eq"] = float(np.clip(_family.get("dynamics_eq", 1.0) * 0.96, 0.30, 1.80))

        # Defect-topology aware balancing: high temporal defects demand safer timing/transient path.
        _d = defect_scores or {}
        _wow = float(np.clip(_d.get("wow", 0.0), 0.0, 1.0))
        _flutter = float(np.clip(_d.get("flutter", 0.0), 0.0, 1.0))
        _drop = float(np.clip(_d.get("dropouts", 0.0), 0.0, 1.0))
        _jitter = float(np.clip(_d.get("jitter_artifacts", 0.0), 0.0, 1.0))
        _temporal = max(_wow, _flutter, _drop, _jitter)
        if _temporal >= 0.35:
            _family["transient"] = float(np.clip(_family.get("transient", 1.0) * (0.98 - 0.10 * _temporal), 0.30, 1.80))
            _family["reconstruction"] = float(
                np.clip(_family.get("reconstruction", 1.0) * (1.00 + 0.10 * _temporal), 0.30, 1.80)
            )

        for _k, _v in list(_family.items()):
            _family[_k] = UnifiedRestorerV3._pullback_from_bounds(float(_v), 0.30, 1.80, margin_frac=0.03)

        # Strict phase caps (phase conflict-safe defaults), material/tier-aware.
        _caps_12 = {
            "vinyl": 0.62,
            "tape": 0.70,
            "reel_tape": 0.66,
            "shellac": 0.56,
            "wax_cylinder": 0.52,
            "wire_recording": 0.52,
            "unknown": 0.60,
        }
        _caps_24 = {
            "vinyl": 0.58,
            "tape": 0.62,
            "reel_tape": 0.60,
            "shellac": 0.54,
            "wax_cylinder": 0.52,
            "wire_recording": 0.52,
            "unknown": 0.60,
        }
        _caps_55 = {
            "vinyl": 0.46,
            "tape": 0.50,
            "reel_tape": 0.48,
            "shellac": 0.42,
            "wax_cylinder": 0.40,
            "wire_recording": 0.40,
            "unknown": 0.48,
        }
        _tier_mul = 1.0
        if _tier == "poor":
            _tier_mul = 0.94
        elif _tier == "good":
            _tier_mul = 1.03
        _severity_mul = float(np.clip(1.0 - 0.06 * _max_def, 0.90, 1.02))

        _phase_caps = {
            "phase_02_hum_removal": float(np.clip(0.36 * _tier_mul * _severity_mul, 0.28, 0.70)),
            "phase_03_denoise": float(np.clip(0.44 * _tier_mul * _severity_mul, 0.30, 0.75)),
            "phase_12_wow_flutter_fix": float(np.clip(_caps_12.get(_mat, _caps_12["unknown"]) * _tier_mul, 0.35, 0.90)),
            "phase_24_dropout_repair": float(
                np.clip(_caps_24.get(_mat, _caps_24["unknown"]) * _tier_mul * _severity_mul, 0.35, 0.90)
            ),
            "phase_29_tape_hiss_reduction": float(np.clip(0.36 * _tier_mul * _severity_mul, 0.28, 0.70)),
            "phase_55_diffusion_inpainting": float(
                np.clip(_caps_55.get(_mat, _caps_55["unknown"]) * _tier_mul * _severity_mul, 0.30, 0.85)
            ),
        }

        _vocal_presence = float(np.clip(_out.get("vocal_presence", 0.0) or 0.0, 0.0, 1.0))
        _frisson_sensitivity = float(np.clip(_out.get("frisson_sensitivity", 0.0) or 0.0, 0.0, 1.0))
        _family, _phase_caps, _prevent_meta = UnifiedRestorerV3._apply_prevent_first_policy(
            _family,
            _phase_caps,
            quiet_edge_profile=_quiet_profile,
            vocal_presence=_vocal_presence,
            frisson_sensitivity=_frisson_sensitivity,
        )

        _strict_policy = {
            "enabled": True,
            "policy_id": "strict_phase_goal_conflict_v1",
            "transfer_chain_depth": int(_chain_depth),
            "phase_strength_caps": _phase_caps,
            **_prevent_meta,
            "rollback_decay_per_family": {
                "denoise": 0.90,
                "transient": 0.92,
                "reconstruction": 0.93,
                "dynamics_eq": 0.95,
                "vocal": 0.95,
                "general": 0.96,
            },
            "rollback_decay_floor": 0.55,
        }

        _out["family_scalars"] = _family
        _out["strict_conflict_policy"] = _strict_policy
        return _out

    def _register_phase_goal_conflict_event(
        self, phase_id: str, reason: str, details: dict[str, Any] | None = None
    ) -> None:
        """Track phase-goal conflicts and adapt family scalars online (non-blocking)."""
        if not isinstance(self._phase_goal_conflict_runtime, dict) or not self._phase_goal_conflict_runtime:
            self._phase_goal_conflict_runtime = {
                "events": [],
                "by_phase": {},
                "by_family": {},
                "total": 0,
            }

        _family = self._phase_family_from_phase_id(phase_id)
        _state = self._phase_goal_conflict_runtime
        _state["total"] = int(_state.get("total", 0)) + 1
        _state["by_phase"][phase_id] = int(_state.get("by_phase", {}).get(phase_id, 0)) + 1
        _state["by_family"][_family] = int(_state.get("by_family", {}).get(_family, 0)) + 1
        _state["events"].append(
            {
                "phase_id": phase_id,
                "family": _family,
                "reason": reason,
                "details": dict(details or {}),
                "index": int(_state.get("total", 0)),
            }
        )

        try:
            _profile = getattr(self, "_song_calibration_profile", None)
            if not isinstance(_profile, dict):
                return
            _family_scalars = _profile.get("family_scalars")
            _policy = _profile.get("strict_conflict_policy")
            if not isinstance(_policy, dict):
                _policy = {}
            if not isinstance(_family_scalars, dict):
                return

            _decays = _policy.get("rollback_decay_per_family", {}) if isinstance(_policy, dict) else {}
            _decay = float(_decays.get(_family, _decays.get("general", 0.96)))
            _floor = float(_policy.get("rollback_decay_floor", 0.55))
            _old = float(_family_scalars.get(_family, 1.0))
            _new = float(np.clip(_old * _decay, _floor, 1.80))
            if _new + 1e-9 < _old:
                _family_scalars[_family] = UnifiedRestorerV3._pullback_from_bounds(_new, 0.30, 1.80, margin_frac=0.03)
                logger.info(
                    "StrictConflictDecay: %s family=%s reason=%s scalar %.3f -> %.3f",
                    phase_id,
                    _family,
                    reason,
                    _old,
                    float(_family_scalars[_family]),
                )

            # If repeated conflict on same phase, tighten phase cap for remaining pipeline.
            _phase_hits = int(_state.get("by_phase", {}).get(phase_id, 0))
            _caps = _policy.get("phase_strength_caps", {}) if isinstance(_policy, dict) else {}
            if isinstance(_caps, dict) and phase_id in _caps and _phase_hits >= 2:
                _old_cap = float(_caps.get(phase_id, 1.0))
                _new_cap = float(np.clip(_old_cap * 0.92, 0.28, 0.95))
                if _new_cap + 1e-9 < _old_cap:
                    _caps[phase_id] = _new_cap
                    logger.info(
                        "StrictConflictCapTighten: %s cap %.3f -> %.3f (hits=%d)",
                        phase_id,
                        _old_cap,
                        _new_cap,
                        _phase_hits,
                    )
        except Exception as _conf_exc:
            logger.debug("Strict conflict tracking failed (non-critical): %s", _conf_exc)

    def _pmgg_retry_budget_hint(
        self,
        phase_id: str,
        *,
        material_key: str,
        remaining_budget_s: float,
        estimated_time_s: float,
        future_phases: list[str],
    ) -> dict[str, Any] | None:
        """Return an advisory PMGG retry-budget hint under wall-budget pressure."""
        _prefix = self._phase_budget_prefix(phase_id)
        if _prefix is None:
            return None

        _phase_priority = self._phase_has_musical_budget_priority(phase_id)
        _future_priority = [p for p in future_phases if self._phase_has_musical_budget_priority(p)]
        _hist = self._phase_budget_gain_history.get(str(material_key).lower(), {}).get(_prefix)
        _samples = int(round(float((_hist or {}).get("samples", 0.0))))
        _mean_gain = float((_hist or {}).get("mean_net_gain", 0.0))
        _weak_history = _samples >= 2 and _mean_gain < 0.004

        _reserve_threshold_s = max(float(estimated_time_s) * 1.35, 18.0)
        if remaining_budget_s > _reserve_threshold_s and not _weak_history:
            return None

        if _future_priority:
            return {
                "reason": "reserve_for_priority_followup",
                "phase_priority": bool(_phase_priority),
                "future_priority_phases": list(_future_priority[:3]),
                "remaining_budget_s": round(float(remaining_budget_s), 3),
                "estimated_time_s": round(float(estimated_time_s), 3),
                "retry_budget_scale": 0.35 if _phase_priority else 0.20,
                "max_retries_cap": 2 if _phase_priority else 1,
            }

        if _weak_history:
            return {
                "reason": "historically_weak_delta",
                "phase_priority": bool(_phase_priority),
                "remaining_budget_s": round(float(remaining_budget_s), 3),
                "estimated_time_s": round(float(estimated_time_s), 3),
                "retry_budget_scale": 0.15,
                "max_retries_cap": 1,
                "history_samples": _samples,
                "history_mean_net_gain": round(_mean_gain, 5),
            }

        return None

    @staticmethod
    def _build_strict_phase_goal_conflict_report(
        *,
        phase_gate_entries: list[Any],
        phase_regression_log: dict[str, float] | None,
        interaction_guard_meta: dict[str, Any] | None,
        runtime_conflict_state: dict[str, Any] | None,
        musical_goals_passed: dict[str, bool] | None,
        song_calibration_profile: dict[str, Any] | None,
    ) -> dict[str, Any]:
        """Build strict conflict verification report between phases and musical goals."""
        _entries = list(phase_gate_entries or [])
        _reg = dict(phase_regression_log or {})
        _ig = dict(interaction_guard_meta or {})
        _rt = dict(runtime_conflict_state or {})
        _passed = dict(musical_goals_passed or {})
        _profile = dict(song_calibration_profile or {})

        _best_effort = [
            getattr(e, "phase_id", "") for e in _entries if str(getattr(e, "action", "")).startswith("best_effort")
        ]
        _best_effort = [p for p in _best_effort if p]
        _regressive = [
            {
                "phase_id": getattr(e, "phase_id", ""),
                "action": str(getattr(e, "action", "")),
                "goal_regressions": dict(getattr(e, "goal_regressions", {}) or {}),
            }
            for e in _entries
            if isinstance(getattr(e, "goal_regressions", None), dict)
            and any(float(v) > 0.05 for v in dict(getattr(e, "goal_regressions", {})).values())
        ]
        _top_drops = sorted(
            [{"phase_id": p, "rms_delta_db": float(d)} for p, d in _reg.items() if float(d) < -0.7],
            key=lambda x: x["rms_delta_db"],
        )[:12]
        _violations = [k for k, ok in _passed.items() if not bool(ok)]

        _rollback_count = 0
        _rbp = {}
        if isinstance(_rt.get("by_phase"), dict):
            _rbp = {str(k): int(v) for k, v in _rt.get("by_phase", {}).items()}
            _rollback_count = int(sum(_rbp.values()))
        elif isinstance(_ig.get("rollbacks_by_phase"), dict):
            _rbp = {str(k): int(v) for k, v in _ig.get("rollbacks_by_phase", {}).items()}
            _rollback_count = int(sum(_rbp.values()))
        elif isinstance(_ig.get("rollback_count"), (int, float)):
            _rollback_count = int(_ig.get("rollback_count", 0))

        _score = float(
            np.clip(
                0.12 * len(set(_best_effort))
                + 0.10 * len(_regressive)
                + 0.12 * _rollback_count
                + 0.05 * len(_top_drops)
                + 0.06 * len(_violations),
                0.0,
                1.0,
            )
        )
        _conflict_present = bool(_score >= 0.35 or _rollback_count >= 2 or len(_best_effort) >= 3)

        _strict_policy = {}
        if isinstance(_profile.get("strict_conflict_policy"), dict):
            _strict_policy = dict(_profile.get("strict_conflict_policy", {}))

        return {
            "enabled": True,
            "conflict_present": _conflict_present,
            "conflict_score": round(_score, 4),
            "rollback_count": int(_rollback_count),
            "rollbacks_by_phase": _rbp,
            "best_effort_phases": sorted(set(_best_effort)),
            "regressive_phase_events": _regressive,
            "top_rms_drops": _top_drops,
            "goal_violations": _violations,
            "runtime_events": list(_rt.get("events", [])) if isinstance(_rt.get("events"), list) else [],
            "autosetup_policy": _strict_policy,
            "family_scalars_final": (
                dict(_profile.get("family_scalars", {})) if isinstance(_profile.get("family_scalars"), dict) else {}
            ),
        }

    @staticmethod
    def _derive_song_cluster_policy(
        *,
        material: str,
        era_decade: int | None,
        genre_label: str,
        restorability_tier: str,
        is_schlager: bool,
    ) -> dict[str, Any]:
        """Derive deterministic cluster policy for closed-loop psychoacoustic control."""
        _mat = str(material or "unknown").lower()
        _genre = str(genre_label or "").strip().lower()
        _tier = str(restorability_tier or "fair").lower()

        if _mat in {"shellac", "vinyl", "tape", "reel_tape", "cassette", "wax_cylinder", "wire_recording"}:
            _mat_bin = "analog"
        elif _mat in {"mp3_low", "mp3_high", "aac", "streaming", "minidisc"}:
            _mat_bin = "lossy"
        else:
            _mat_bin = "digital"

        if era_decade is None:
            _era_bin = "unknown"
        elif int(era_decade) <= 1950:
            _era_bin = "vintage"
        elif int(era_decade) <= 1980:
            _era_bin = "mid"
        else:
            _era_bin = "modern"

        if is_schlager or "schlager" in _genre:
            _genre_bin = "schlager"
        elif _genre in {"klassik", "oper", "classical", "opera"}:
            _genre_bin = "classical"
        elif _genre in {"rock", "metal", "electronic", "edm"}:
            _genre_bin = "rhythmic"
        else:
            _genre_bin = "general"

        _artifact_sens = 1.00
        _fatigue_sens = 1.00
        _recovery_bias = 1.00
        _micro_bias = 1.00

        if _mat_bin == "lossy":
            _artifact_sens *= 1.10
            _fatigue_sens *= 1.06
        elif _mat_bin == "analog":
            _artifact_sens *= 1.04
            _micro_bias *= 0.98

        if _era_bin == "vintage":
            _artifact_sens *= 1.08
            _fatigue_sens *= 1.05
            _recovery_bias *= 0.96
        elif _era_bin == "modern":
            _micro_bias *= 1.03

        if _genre_bin == "classical":
            _artifact_sens *= 1.06
            _fatigue_sens *= 1.06
            _micro_bias *= 0.97
        elif _genre_bin == "rhythmic":
            _micro_bias *= 1.05
            _recovery_bias *= 1.03
        elif _genre_bin == "schlager":
            _recovery_bias *= 1.05

        if _tier in {"poor", "critical"}:
            _artifact_sens *= 1.08
            _recovery_bias *= 0.95
        elif _tier in {"excellent", "good"}:
            _recovery_bias *= 1.04

        _artifact_sens = float(np.clip(_artifact_sens, 0.90, 1.25))
        _fatigue_sens = float(np.clip(_fatigue_sens, 0.90, 1.20))
        _recovery_bias = float(np.clip(_recovery_bias, 0.85, 1.20))
        _micro_bias = float(np.clip(_micro_bias, 0.90, 1.15))

        return {
            "cluster_key": f"{_mat_bin}:{_era_bin}:{_genre_bin}:{_tier}",
            "material_bin": _mat_bin,
            "era_bin": _era_bin,
            "genre_bin": _genre_bin,
            "restorability_tier": _tier,
            "artifact_sensitivity": _artifact_sens,
            "fatigue_sensitivity": _fatigue_sens,
            "recovery_bias": _recovery_bias,
            "microdynamics_bias": _micro_bias,
        }

    @staticmethod
    def _compute_plateau_params(
        material_type: Any,
        restorability_score: float,
    ) -> tuple[float, float]:
        """Return (threshold, dampen) for §9.11.1 PlateauStop, material-adaptive (§2.54).

        VERBOTEN (spec): feste Konstanten 0.005 / 0.40 für alle Materialien.

        Table (spec §2.54):
            shellac / wax_cylinder / wire_recording → 0.002 / 0.55
            reel_tape                                → 0.003 / 0.50
            cassette / tape                          → 0.004 / 0.45
            vinyl                                    → 0.005 / 0.43
            minidisc                                 → 0.006 / 0.42
            mp3_low                                  → 0.008 / 0.40
            mp3_high / aac                           → 0.007 / 0.40
            cd_digital                               → 0.010 / 0.35
            dat                                      → 0.009 / 0.37
            default                                  → 0.005 / 0.40

        restorability < 40 → dampen raised to at least 0.60 (badly damaged material
        must not suppress necessary phases prematurely).
        """
        _mat_val = getattr(material_type, "value", str(material_type)).lower()
        _thr_map: dict[str, tuple[float, float]] = {
            "shellac": (0.002, 0.55),
            "wax_cylinder": (0.002, 0.55),
            "wire_recording": (0.002, 0.55),
            "reel_tape": (0.003, 0.50),
            "cassette": (0.004, 0.45),
            "tape": (0.004, 0.45),
            "vinyl": (0.005, 0.43),
            "minidisc": (0.006, 0.42),
            "mp3_low": (0.008, 0.40),
            "mp3_high": (0.007, 0.40),
            "aac": (0.007, 0.40),
            "cd_digital": (0.010, 0.35),
            "dat": (0.009, 0.37),
        }
        _thr, _dmp = _thr_map.get(_mat_val, (0.005, 0.40))
        # Badly damaged: raise dampen floor — §2.54 restorability < 40 guard.
        if float(restorability_score) < 40.0:
            _dmp = max(_dmp, 0.60)
        return float(_thr), float(_dmp)

    @staticmethod
    def _post_additive_bw_guard(
        audio: np.ndarray,
        sample_rate: int,
        material_type: Any,
        quality_mode: Any = None,
        transfer_chain: list | None = None,
    ) -> tuple[np.ndarray, bool]:
        """§6.2c Post-Additive BW-Hard-Cap — Material-Bandbreiten-Ceiling.

        Butterworth 8th-order LPF nach dem Phase-Loop, um BW-Überschreitungen
        durch additive Phasen (phase_06, phase_07, phase_23, phase_39) zu verhindern.

        Restoration: Hard-Cap aktiv. Studio 2026: kein Enforcement.
        transfer_chain: wenn übergeben, wird das Minimum-Ceiling der gesamten Kette
        verwendet (§6.2c chain-adaptiv via get_chain_bw_ceiling_hz).

        Returns (audio, guard_applied).
        """
        try:
            from backend.core.carrier_transfer_characteristics import (
                get_bw_ceiling_hz,
                get_chain_bw_ceiling_hz,
            )

            _bw_mat_key = material_type.value if hasattr(material_type, "value") else str(material_type)
            _bw_is_studio = quality_mode is not None and "studio" in str(quality_mode).lower()

            if _bw_is_studio:
                return audio, False

            # §6.2c chain-adaptiv: Minimum-BW der gesamten Trägerkette verhindert
            # AudioSR-Halluzination über den schwächsten Kettenstufen-Ceiling.
            if transfer_chain:
                _bw_ceil_hz = get_chain_bw_ceiling_hz(transfer_chain)
            else:
                _bw_ceil_hz = get_bw_ceiling_hz(_bw_mat_key)
            _nyquist = sample_rate / 2.0
            if _bw_ceil_hz >= _nyquist * 0.95:
                return audio, False

            from scipy.signal import butter, sosfiltfilt

            _bw_norm = min(_bw_ceil_hz / _nyquist, 0.99)
            _bw_sos = butter(8, _bw_norm, btype="low", output="sos")
            if audio.ndim == 2:
                for _ch in range(audio.shape[1]):
                    audio[:, _ch] = sosfiltfilt(_bw_sos, audio[:, _ch])
            else:
                audio = sosfiltfilt(_bw_sos, audio)
            audio = np.clip(audio, -1.0, 1.0)
            logger.info(
                "§2.46c BW-Hard-Cap: LPF @%d Hz (material=%s, Butterworth 8th-order)",
                _bw_ceil_hz,
                _bw_mat_key,
            )
            return audio, True
        except Exception as _exc:
            logger.debug("§2.46c BW-Guard failed (non-blocking): %s", _exc)
            return audio, False

    @staticmethod
    def _compute_joy_fatigue_runtime_index(
        musical_goal_scores: dict[str, float] | None,
        fatigue_result: dict[str, Any] | None,
        artifact_freedom: float,
        emotional_arc_score: float,
        audio: np.ndarray | None = None,
        sr: int = 48000,
    ) -> dict[str, Any]:
        """Compute explicit runtime joy/fatigue index (0..1) from available proxies.

        Includes a literature-backed frisson propensity score (Blood & Zatorre
        2001, Grewe 2007, Harrison & Loui 2014) based on:
          - Spectral flux (harmonic surprise / expectation violation)
          - Onset density (rhythmic tension / release)
          - Dynamic range contrast (crescendo/decrescendo patterns)
          - Goal-based proxies (emotional arc, spatial immersion, articulation)
        """
        _scores = musical_goal_scores or {}
        _nat = float(np.clip(float(_scores.get("natuerlichkeit", 0.90)), 0.0, 1.0))
        _warm = float(np.clip(float(_scores.get("waerme", 0.75)), 0.0, 1.0))
        _micro = float(np.clip(float(_scores.get("micro_dynamics", 0.88)), 0.0, 1.0))
        _emo = float(np.clip(float(_scores.get("emotionalitaet", emotional_arc_score)), 0.0, 1.0))
        _bri = float(np.clip(float(_scores.get("brillanz", 0.78)), 0.0, 1.0))
        _art = float(np.clip(float(_scores.get("artikulation", 0.85)), 0.0, 1.0))
        _spa = float(np.clip(float(_scores.get("spatial_depth", 0.70)), 0.0, 1.0))
        _tonal = float(np.clip(float(_scores.get("tonal_center", 0.95)), 0.0, 1.0))
        _trans = float(np.clip(float(_scores.get("transparenz", 0.82)), 0.0, 1.0))
        _artifact = float(np.clip(float(artifact_freedom), 0.0, 1.0))
        _arc = float(np.clip(float(emotional_arc_score), 0.0, 1.0))

        _risk_lookup = {"very_low": 0.08, "low": 0.16, "medium": 0.35, "high": 0.65, "critical": 0.85}
        _fatigue_risk = 0.25
        if isinstance(fatigue_result, dict):
            _risk_level = str(fatigue_result.get("risk_level", "")).lower()
            _fatigue_risk = float(_risk_lookup.get(_risk_level, _fatigue_risk))
            if "risk_score" in fatigue_result:
                try:
                    _fatigue_risk = float(np.clip(float(fatigue_result.get("risk_score")), 0.0, 1.0))
                except Exception:
                    pass

        _fatigue_from_brightness = float(np.clip(max(0.0, _bri - _warm) * 0.8, 0.0, 1.0))
        _fatigue_index = float(np.clip(0.70 * _fatigue_risk + 0.30 * _fatigue_from_brightness, 0.0, 1.0))

        # ── Frisson: real audio analysis (non-blocking) ───────────────────
        # Three acoustic correlates of musical chills (Blood & Zatorre 2001):
        #   1. Spectral flux → harmonic surprise (unexpected chord/timbre changes)
        #   2. Onset density → rhythmic tension/release patterns
        #   3. RMS envelope variance → dynamic crescendo/decrescendo contrast
        _spectral_flux_norm = 0.0
        _onset_density_norm = 0.0
        _dynamic_contrast_norm = 0.0
        _frisson_audio_valid = False

        if audio is not None:
            try:
                _fr_audio = np.asarray(audio, dtype=np.float64)
                _fr_audio = np.nan_to_num(_fr_audio, nan=0.0, posinf=0.0, neginf=0.0)
                if _fr_audio.ndim == 2:
                    _fr_audio = _fr_audio.mean(axis=0) if _fr_audio.shape[0] <= 2 else _fr_audio.mean(axis=1)

                # Cap at 30 seconds for performance
                _max_fr_samples = int(30.0 * sr)
                _fr_audio = _fr_audio[:_max_fr_samples]

                if len(_fr_audio) > int(0.5 * sr):
                    _n_fft_fr = 2048
                    _hop_fr = 512
                    _win_fr = np.hanning(_n_fft_fr).astype(np.float64)

                    # STFT magnitude frames
                    _n_fr_frames = max(1, (len(_fr_audio) - _n_fft_fr) // _hop_fr)
                    _mags: list[np.ndarray] = []
                    _rms_vals: list[float] = []
                    for _ffi in range(_n_fr_frames):
                        _fs = _ffi * _hop_fr
                        _fe = _fs + _n_fft_fr
                        if _fe > len(_fr_audio):
                            break
                        _frame = _fr_audio[_fs:_fe]
                        _mag = np.abs(np.fft.rfft(_frame * _win_fr))
                        _mags.append(_mag)
                        _rms_vals.append(float(np.sqrt(np.mean(_frame**2) + 1e-12)))

                    if len(_mags) >= 3:
                        # 1. Spectral Flux: mean frame-to-frame L2 distance
                        _flux_vals = []
                        for _si in range(1, len(_mags)):
                            _diff = _mags[_si] - _mags[_si - 1]
                            _half_rect = np.maximum(_diff, 0.0)
                            _flux_vals.append(float(np.sqrt(np.sum(_half_rect**2) + 1e-12)))

                        _mean_flux = float(np.mean(_flux_vals))
                        _std_flux = float(np.std(_flux_vals))
                        # Normalise: high flux variance = high harmonic surprise
                        _spectral_flux_norm = float(np.clip(_std_flux / max(_mean_flux, 1e-6), 0.0, 1.0))

                        # 2. Onset density: count significant flux peaks per second
                        _flux_arr = np.array(_flux_vals)
                        _flux_thresh = _mean_flux + 1.5 * _std_flux
                        _onset_count = int(np.sum(_flux_arr > _flux_thresh))
                        _duration_s = len(_fr_audio) / float(sr)
                        _onsets_per_sec = _onset_count / max(_duration_s, 0.1)
                        # Frisson peaks at moderate density (2–6/s), not too sparse not too dense
                        _onset_density_norm = float(np.clip(1.0 - abs(_onsets_per_sec - 4.0) / 4.0, 0.0, 1.0))

                        # 3. Dynamic contrast: RMS envelope variance (crescendo/decrescendo)
                        _rms_arr = np.array(_rms_vals)
                        _rms_db = 20.0 * np.log10(_rms_arr + 1e-12)
                        _dyn_range = float(np.percentile(_rms_db, 95) - np.percentile(_rms_db, 5))
                        # Normalise: 20+ dB dynamic range → high contrast
                        _dynamic_contrast_norm = float(np.clip(_dyn_range / 25.0, 0.0, 1.0))

                        _frisson_audio_valid = True

            except Exception as _fr_exc:
                logger.debug("Frisson audio analysis non-blocking: %s", _fr_exc)

        # Combine audio-based and proxy-based frisson estimation
        if _frisson_audio_valid:
            # Weighted blend: 55% audio-derived, 45% proxy-derived
            _frisson_audio = 0.35 * _spectral_flux_norm + 0.30 * _dynamic_contrast_norm + 0.35 * _onset_density_norm
            _frisson_proxy = 0.30 * _arc + 0.25 * _micro + 0.20 * _emo + 0.15 * _spa + 0.10 * _art
            _frisson_index = float(
                np.clip(
                    0.55 * _frisson_audio + 0.45 * _frisson_proxy - 0.12 * _fatigue_index,
                    0.0,
                    1.0,
                )
            )
        else:
            # Fallback: pure proxy (same as before but with §2.53 literature weights)
            _frisson_index = float(
                np.clip(
                    0.26 * _arc
                    + 0.18 * _micro
                    + 0.14 * _emo
                    + 0.14 * _art
                    + 0.10 * _spa
                    + 0.08 * _trans
                    + 0.10 * _tonal
                    + 0.10 * _artifact
                    - 0.16 * _fatigue_index,
                    0.0,
                    1.0,
                )
            )

        _joy_index = float(
            np.clip(
                0.23 * _nat
                + 0.20 * _emo
                + 0.17 * _micro
                + 0.12 * _warm
                + 0.16 * _artifact
                + 0.12 * _arc
                + 0.08 * _frisson_index
                - 0.20 * _fatigue_index,
                0.0,
                1.0,
            )
        )

        return {
            "joy_index": _joy_index,
            "fatigue_index": _fatigue_index,
            "frisson_index": _frisson_index,
            "components": {
                "natuerlichkeit": _nat,
                "emotionalitaet": _emo,
                "micro_dynamics": _micro,
                "waerme": _warm,
                "artifact_freedom": _artifact,
                "emotional_arc": _arc,
                "brightness": _bri,
                "artikulation": _art,
                "spatial_depth": _spa,
                "tonal_center": _tonal,
                "transparenz": _trans,
                "frisson_propensity": _frisson_index,
                "frisson_spectral_flux": _spectral_flux_norm,
                "frisson_onset_density": _onset_density_norm,
                "frisson_dynamic_contrast": _dynamic_contrast_norm,
                "frisson_audio_analysis_valid": _frisson_audio_valid,
            },
        }

    @staticmethod
    def _derive_auto_improvement_recommendations(
        *,
        musical_goal_scores: dict[str, float] | None,
        musical_goals_passed: dict[str, bool] | None,
        artifact_freedom: float,
        phase_regression_log: dict[str, float] | None,
        top_defects: list[dict[str, Any]] | None,
    ) -> dict[str, Any]:
        """Derive actionable root-cause recommendations from runtime telemetry."""
        _scores = musical_goal_scores or {}
        _passed = musical_goals_passed or {}
        _drops = phase_regression_log or {}
        _defects = top_defects or []

        _recs: list[dict[str, Any]] = []

        if float(artifact_freedom) < 0.97:
            _recs.append(
                {
                    "priority": "high",
                    "focus": "artifact_freedom",
                    "reason": f"artifact_freedom={float(artifact_freedom):.3f} below comfort zone",
                    "action": "tighten reconstruction/transient family scalars and increase artifact sensitivity",
                }
            )

        _nat = float(_scores.get("natuerlichkeit", 1.0))
        if ("natuerlichkeit" in _passed and not bool(_passed.get("natuerlichkeit"))) or _nat < 0.90:
            _recs.append(
                {
                    "priority": "high",
                    "focus": "natuerlichkeit",
                    "reason": f"natuerlichkeit={_nat:.3f}",
                    "action": "deboost dynamics_eq/transient chain and preserve room/studio signature",
                }
            )

        _warm = float(_scores.get("waerme", 1.0))
        _bri = float(_scores.get("brillanz", 0.0))
        if _bri > 0.86 and _warm < 0.74:
            _recs.append(
                {
                    "priority": "medium",
                    "focus": "fatigue",
                    "reason": f"brillanz={_bri:.3f} with waerme={_warm:.3f}",
                    "action": "apply additional anti-harshness damping in dynamics_eq/transient families",
                }
            )

        _micro = float(_scores.get("micro_dynamics", 1.0))
        if _micro < 0.82:
            _recs.append(
                {
                    "priority": "medium",
                    "focus": "micro_dynamics",
                    "reason": f"micro_dynamics={_micro:.3f}",
                    "action": "increase transient family slightly when artifact floor remains stable",
                }
            )

        _top_drop = sorted(
            [(_pid, float(_db)) for _pid, _db in _drops.items() if float(_db) < -1.0], key=lambda x: x[1]
        )
        if _top_drop:
            _pid, _db = _top_drop[0]
            _recs.append(
                {
                    "priority": "medium",
                    "focus": "loudness_drift",
                    "reason": f"largest phase RMS drop at {_pid}: {_db:.2f} dB",
                    "action": "tighten per-phase loudness guard and makeup compensation for this phase family",
                }
            )

        if _defects:
            _top = _defects[0]
            _recs.append(
                {
                    "priority": "info",
                    "focus": "defect_topology",
                    "reason": (
                        f"dominant defect={_top.get('type', 'unknown')} severity={float(_top.get('severity', 0.0)):.3f}"
                    ),
                    "action": "prioritize related material-mandatory phases earlier in future runs",
                }
            )

        return {
            "count": len(_recs),
            "recommendations": _recs,
        }

    @staticmethod
    def _pullback_from_bounds(v: float, lo: float, hi: float, margin_frac: float = 0.03) -> float:
        """Clamp to bounds and gently pull edge-adhering values into the interior."""
        vv = float(np.clip(v, lo, hi))
        span = max(1e-12, hi - lo)
        margin = span * float(np.clip(margin_frac, 0.0, 0.49))
        if margin <= 0.0:
            return vv
        if vv <= lo + 1e-9:
            return float(lo + margin)
        if vv >= hi - 1e-9:
            return float(hi - margin)
        if vv < lo + margin * 0.5:
            return float(lo + margin * 0.5)
        if vv > hi - margin * 0.5:
            return float(hi - margin * 0.5)
        return vv

    @staticmethod
    def _estimate_spectral_tilt_quick(audio: np.ndarray, sr: int) -> float | None:
        """§2.46b: Rapid spectral tilt estimate (dB/oct, 200 Hz–16 kHz) via era_classifier.

        Used post-phase in _profiled_phase_call to detect additive phase over-brightening.
        Returns None on any error (non-blocking).
        """
        try:
            from backend.core.era_classifier import _estimate_spectral_tilt as _est_tilt

            # Channel-format-aware mono extraction:
            # (2, N) channels-first → audio[:, 0] = shape (2,) — WRONG.
            # (N, 2) channels-last  → audio[:, 0] = shape (N,) — correct.
            if audio.ndim == 2:
                if audio.shape[0] == 2 and audio.shape[1] > 2:
                    mono = audio[0]  # channels-first: row 0 = channel 0
                else:
                    mono = audio[:, 0]  # channels-last: column 0 = channel 0
            else:
                mono = audio
            # Limit to 4 s centre excerpt for speed (≤10 ms on typical 48 kHz audio).
            max_n = int(4.0 * sr)
            if len(mono) > max_n:
                start = (len(mono) - max_n) // 2
                mono = mono[start : start + max_n]
            mono = np.nan_to_num(mono, nan=0.0, posinf=0.0, neginf=0.0)
            return float(_est_tilt(mono, sr))
        except Exception:
            return None

    @staticmethod
    def _get_phase_calibration_scalar(phase_id: str, profile: dict[str, Any] | None) -> float:
        """Return phase-family scalar derived from the song calibration profile."""
        if not isinstance(profile, dict):
            return 1.0
        _family_scalars = profile.get("family_scalars")
        if not isinstance(_family_scalars, dict):
            return 1.0

        try:
            _parts = phase_id.split("_", 2)
            _phase_num = int(_parts[1]) if len(_parts) > 1 else -1
        except Exception:
            _phase_num = -1

        # Denoise family: broadband noise / hiss / gate-based processing
        if _phase_num in {2, 3, 18, 29, 37}:
            _family = "denoise"
        # Reverb family: room removal / dereverb
        elif _phase_num in {20, 49}:
            _family = "reverb"
        # Reconstruction family: dropout / spectral gap / diffusion inpainting / SBR / harmonic
        elif _phase_num in {6, 7, 9, 23, 24, 55, 56, 57, 58}:
            _family = "reconstruction"
        # Dynamics / EQ family: EQ correction, dynamics, mastering chain
        elif _phase_num in {4, 10, 17, 26, 31, 36, 40, 47}:
            _family = "dynamics_eq"
        # Transient family: transient preservation / shaping
        elif _phase_num in {8, 11, 50}:
            _family = "transient"
        # Vocal family: de-esser, vocal enhancement, BSRoFormer separation
        elif _phase_num in {19, 42, 43}:
            _family = "vocal"
        # Instrument family: guitar, brass, drums, piano, spatial enhancement
        elif _phase_num in {44, 45, 46, 51, 52}:
            _family = "instrument"
        else:
            _family = "general"

        _raw = _family_scalars.get(_family, profile.get("global_scalar", 1.0))
        try:
            _scalar = float(_raw)
        except Exception:
            _scalar = 1.0
        # [RELEASE_MUST] Lücke-G-Fix v9.10.100: family_scalars ∈ [0.30, 1.80]
        # Plus Stabilitäts-Pullback: avoid persistent edge adhesion in implicit phase scaling.
        _bounded = float(np.clip(_scalar, 0.30, 1.80))
        return UnifiedRestorerV3._pullback_from_bounds(_bounded, 0.30, 1.80, margin_frac=0.03)

    @staticmethod
    def _fast_goal_snapshot(audio: np.ndarray, sr: int, material_type: str = "unknown") -> dict[str, float]:
        """§2.64 DSP-Proxy for per-phase goal measurement (≤200ms, no ML).

        Computes lightweight proxies for all 14 Musical Goals using only
        DSP operations — no ML inference. Used as pre/post snapshot in
        _profiled_phase_call to compute per-phase deltas.
        material_type: §9.12.7 — tape/cassette use lower natuerlichkeit floor
        (hiss spreads spectral energy → lower apparent concentration).

        Returns a dict mapping goal name → proxy score [0, 1].
        Non-blocking: returns empty dict on any error.
        """
        import numpy as _np  # numpy already a hard dependency

        result: dict[str, float] = {}
        try:
            # Mono mix for scalar metrics
            if audio.ndim == 2:
                if audio.shape[0] == 2 and audio.shape[1] > 2:
                    mono = audio[0]  # (2, N) channels-first
                else:
                    mono = audio[:, 0]  # (N, 2) channels-last
            else:
                mono = audio

            N = len(mono)
            if N < 512:
                return {}

            # FFT basis — §2.64 v9.12.2 MULTI-SEGMENT FIX:
            # Single-centre-segment spectral analysis is unreliable for song-level quality:
            # (a) compressed pop/Schlager: centre segment of a dense chord spreads energy
            #     → natuerlichkeit proxy <<< true value for a musical signal.
            # (b) vintage material: a pause segment gives artificially low transparenz/brillanz.
            # Fix: average spectral metrics over 3 representative segments (25 %, 50 %, 75 %).
            fft_n = min(4096, N)
            _win = _np.hanning(fft_n)
            _eps = 1e-12
            _seg_starts = [
                max(0, N // 4 - fft_n // 2),
                max(0, N // 2 - fft_n // 2),
                max(0, 3 * N // 4 - fft_n // 2),
            ]
            _specs: list[_np.ndarray] = []
            for _s0 in _seg_starts:
                _seg = mono[_s0 : _s0 + fft_n]
                if len(_seg) < fft_n:
                    _seg = _np.pad(_seg, (0, fft_n - len(_seg)))
                _specs.append(_np.abs(_np.fft.rfft(_seg * _win)))
            # Averaged spectrum: representative of multiple sections of the song.
            _spec = _np.mean(_np.stack(_specs, axis=0), axis=0)
            _freqs = _np.fft.rfftfreq(fft_n, d=1.0 / float(sr))

            def _band_energy(flo: float, fhi: float) -> float:
                mask = (_freqs >= flo) & (_freqs < fhi)
                return float(_np.sum(_spec[mask] ** 2)) + _eps

            # --- P1: Natuerlichkeit proxy — harmonic energy concentration (multi-segment)
            # §2.64 v9.12.1 (single-segment fix) + §2.64 v9.12.2 (multi-segment stability).
            # Harmonics concentrate energy; Musical Noise / artefacts spread energy uniformly.
            # Average concentration over segments: prevents single-chord passages from
            # artificially lowering the proxy (which would mis-guide PMGG strength).
            _conc_vals: list[float] = []
            for _sp in _specs:
                _sd = _np.sort(_sp)[::-1]
                _tn = max(1, len(_sd) // 8)
                _conc_vals.append(float(_np.sum(_sd[:_tn] ** 2)) / (float(_np.sum(_sd**2)) + _eps))
            _conc = float(_np.mean(_conc_vals))
            # Natural music: top-12.5% bins hold ≥ 40 % energy → conc ≈ 0.50–0.80.
            # Musical Noise / white noise: conc ≈ 0.12–0.25.
            # §9.12.7 Material-adaptive floor: tape hiss spreads energy → lower floor (0.10 vs 0.15).
            _nat_floor = 0.10 if str(material_type or "").lower() in {"tape", "cassette", "reel_tape"} else 0.15
            result["natuerlichkeit"] = float(_np.clip((_conc - _nat_floor) / 0.60, 0.0, 1.0))

            # --- P1: Authentizitaet proxy — HNR via autocorrelation (§2.64 v9.12.2)
            # §2.64 v9.12.2 BUG-FIX: ACF on first-8192-samples is hypersensitive to
            # dropout-repair (phase_24) inpainting at song start → crash from 0.71→0.06.
            # Fix: use centre-third segment (avoids intro/outro + repaired dropout zones)
            # and MAXIMUM over 3 ACF peaks (voiced sections always have high periodicity).
            _acf_start = max(0, N // 3)
            _acf_len = min(8192, N - _acf_start)
            _acf_seg = mono[_acf_start : _acf_start + _acf_len]
            _acf = _np.correlate(_acf_seg, _acf_seg, mode="full")
            _acf = _acf[len(_acf) // 2 :]
            _acf /= _acf[0] + _eps
            _lag_min = int(sr / 1000.0)  # 1 kHz max F0
            _lag_max = int(sr / 50.0)  # 50 Hz min F0
            if _lag_max > len(_acf) - 1:
                _lag_max = len(_acf) - 1
            if _lag_max > _lag_min:
                _peak_acf = float(_np.max(_acf[_lag_min:_lag_max]))
                result["authentizitaet"] = float(_np.clip((_peak_acf + 1.0) / 2.0, 0.0, 1.0))
            else:
                result["authentizitaet"] = 0.5

            # --- P2: Timbral-authentizitaet proxy — spectral centroid stability
            _centroid = float(_np.sum(_freqs * _spec) / (_np.sum(_spec) + _eps))
            # Normalise against Nyquist: 0=bass-heavy, 1=treble-heavy; 0.5=balanced
            _c_norm = float(_np.clip(_centroid / (float(sr) / 2.0), 0.0, 1.0))
            # Balanced centroid (500–5000 Hz) scores highest
            _c_ideal = 2500.0 / (float(sr) / 2.0)
            _timbre = 1.0 - float(_np.clip(abs(_c_norm - _c_ideal) * 3.0, 0.0, 1.0))
            result["timbre_authentizitaet"] = float(_np.clip(_timbre, 0.0, 1.0))

            # --- P2: TonalCenter proxy — low-freq harmonic energy fraction
            _tonal = _band_energy(80.0, 1200.0) / (_band_energy(80.0, 20000.0) + _eps)
            result["tonal_center"] = float(_np.clip(_tonal * 2.0, 0.0, 1.0))  # scale so 0.5 band-frac = 1.0

            # --- P2: Artikulation proxy — transient density (onset energy spikes)
            _rms_frames = []
            _hop = 512
            for _i in range(0, N - _hop, _hop):
                _rms_frames.append(float(_np.sqrt(_np.mean(mono[_i : _i + _hop] ** 2))))
            if len(_rms_frames) >= 4:
                _rms_arr = _np.array(_rms_frames)
                _diff = _np.diff(_rms_arr)
                _onsets = _np.sum(_diff > (_np.std(_diff) * 0.5)) / max(1, len(_diff))
                result["artikulation"] = float(_np.clip(_onsets * 4.0, 0.0, 1.0))
            else:
                result["artikulation"] = 0.5

            # --- P3: MikroDynamik proxy — micro-dynamic range (10th/90th percentile ratio)
            _abs_mono = _np.abs(mono)
            _p10 = float(_np.percentile(_abs_mono, 10)) + _eps
            _p90 = float(_np.percentile(_abs_mono, 90)) + _eps
            _dyn = float(_np.clip((_p90 - _p10) / _p90, 0.0, 1.0))
            result["mikrodynamik"] = _dyn

            # --- P3: Emotionalitaet proxy — low-freq energy ratio (bass drive)
            _emot = _band_energy(60.0, 300.0) / (_band_energy(60.0, 8000.0) + _eps)
            result["emotionalitaet"] = float(_np.clip(_emot * 3.0, 0.0, 1.0))

            # --- P3: Groove proxy — periodicity in onset envelope
            # §2.64 v9.12.1: ACF search window was len//4 — for an 8-frame RMS window
            # that is only 1..2 entries, missing beat periods entirely (BPM ≤ 180 at 512
            # hop / 48 kHz needs ≥ 93 frames for 120 BPM period → extend to len//2).
            if len(_rms_frames) >= 8:
                _rms_arr2 = _np.array(_rms_frames)
                _acf2 = _np.correlate(_rms_arr2, _rms_arr2, mode="full")
                _acf2 = _acf2[len(_acf2) // 2 :]
                _acf2 /= _acf2[0] + _eps
                _groove_peak = float(_np.max(_acf2[1 : max(2, len(_acf2) // 2)]))
                result["groove"] = float(_np.clip((_groove_peak + 1.0) / 2.0, 0.0, 1.0))
            else:
                result["groove"] = 0.5

            # --- P4: Transparenz proxy — wideband SNR proxy (§2.64 v9.12.2 FIX)
            # §2.64 v9.12.2 BUG-FIX: Single-centre-segment 5th/99th percentile SNR is
            # unreliable for compressed pop/Schlager: a loud centre segment has 5th-%ile
            # ≈ 0.1–0.2 → log10(peak/noise) ≈ 0.5–1.2 → SNR-proxy 0.10–0.24 even for
            # clean material. This mis-guides PMGG and gives persistently low scores.
            # Fix: use full-signal percentile (robust over entire track) + spectral
            # flatness as secondary signal-to-noise indicator, averaged over 3 segments.
            _p05_full = float(_np.percentile(_np.abs(mono), 5)) + _eps
            _p95_full = float(_np.percentile(_np.abs(mono), 95)) + _eps
            _snr_full = float(_np.clip(_np.log10(_p95_full / _p05_full) / 4.0, 0.0, 1.0))
            # Spectral flatness (Wiener entropy) averages across 3 segments for stability.
            _sfm_vals: list[float] = []
            for _sp in _specs:
                _sp_pos = _np.maximum(_sp, _eps)
                _sfm = float(_np.exp(_np.mean(_np.log(_sp_pos))) / (_np.mean(_sp_pos) + _eps))
                _sfm_vals.append(float(_np.clip(_sfm, 0.0, 1.0)))
            _sfm_avg = float(_np.mean(_sfm_vals))
            # Low flatness = tonal / harmonic (music) = transparent; high = noisy.
            # Blend: 70 % dynamic-range proxy + 30 % inverted spectral flatness.
            _transp = 0.70 * _snr_full + 0.30 * (1.0 - _sfm_avg)
            result["transparenz"] = float(_np.clip(_transp, 0.0, 1.0))

            # --- P4: Waerme proxy — low-mid energy ratio (200–2000 Hz)
            _waerme = _band_energy(200.0, 2000.0) / (_band_energy(50.0, 20000.0) + _eps)
            result["waerme"] = float(_np.clip(_waerme * 4.0, 0.0, 1.0))

            # --- P4: BassKraft proxy — sub-bass energy fraction
            _bass = _band_energy(30.0, 200.0) / (_band_energy(30.0, 8000.0) + _eps)
            result["basskraft"] = float(_np.clip(_bass * 5.0, 0.0, 1.0))

            # --- P4: SepFidelity proxy — stereo width consistency (or 0.5 for mono)
            if audio.ndim == 2 and audio.shape[0] != 2:
                # (N, 2) format
                if audio.shape[1] == 2:
                    _m = (audio[:, 0] + audio[:, 1]) / 2.0
                    _s = (audio[:, 0] - audio[:, 1]) / 2.0
                    _ms_ratio = float(_np.sqrt(_np.mean(_s**2)) / (_np.sqrt(_np.mean(_m**2)) + _eps))
                    result["sep_fidelity"] = float(_np.clip(1.0 - abs(_ms_ratio - 0.3) * 2.0, 0.0, 1.0))
                else:
                    result["sep_fidelity"] = 0.5
            elif audio.ndim == 2 and audio.shape[0] == 2:
                # (2, N) format
                _m = (audio[0] + audio[1]) / 2.0
                _s = (audio[0] - audio[1]) / 2.0
                _ms_ratio = float(_np.sqrt(_np.mean(_s**2)) / (_np.sqrt(_np.mean(_m**2)) + _eps))
                result["sep_fidelity"] = float(_np.clip(1.0 - abs(_ms_ratio - 0.3) * 2.0, 0.0, 1.0))
            else:
                result["sep_fidelity"] = 0.5

            # --- P5: Brillanz proxy — HF energy ratio (4–16 kHz vs 500 Hz–16 kHz)
            # §2.64 v9.12.1 BUG-FIX: Single-frame crest factor systematically underestimates
            # brillanz (~0.19 cap for typical music). The real BrillanzMetric averages over
            # many STFT frames before computing crest, yielding 6-12× crest. A single-frame
            # crest is 2.5-4×, mapping to brillanz 0.09-0.24 regardless of HF content.
            # Fix: Use band energy ratio (4-16 kHz / total 500 Hz-16 kHz) which directly
            # tracks HF presence and is sensitive to phase_06 (AudioSR) and phase_23 (Apollo).
            # Calibration: ratio 0.02 (no HF) → 0.0; ratio 0.40+ (bright/restored) → 1.0.
            _hf4k_energy = _band_energy(4000.0, 16000.0)
            _mid_energy_bri = _band_energy(500.0, 4000.0) + _eps
            if _hf4k_energy + _mid_energy_bri > _eps:
                _brillanz_ratio = _hf4k_energy / (_hf4k_energy + _mid_energy_bri)
                # Calibration: ratio 0.02 → 0.0; ratio 0.40 → 1.0
                result["brillanz"] = float(_np.clip((_brillanz_ratio - 0.02) / 0.38, 0.0, 1.0))
            else:
                result["brillanz"] = 0.0

            # --- P5: Raumtiefe proxy — late reverb energy in high bins
            _late_energy = _band_energy(4000.0, 16000.0)
            _total_energy = _band_energy(200.0, 16000.0) + _eps
            result["raumtiefe"] = float(_np.clip(_late_energy / _total_energy * 2.5, 0.0, 1.0))
            # §2.64 v9.12.1 BUG-FIX: _P3P5_MAS_GOALS referenced 'spatial_depth' but
            # _fast_goal_snapshot only wrote 'raumtiefe' → MAS-convergence for P3–P5
            # never found the key → _mas_p3p5_achieved stayed False → pipeline ran longer.
            result["spatial_depth"] = result["raumtiefe"]

        except Exception as _fgs_exc:
            logger.debug("§2.64 _fast_goal_snapshot failed (non-blocking): %s", _fgs_exc)

        return result

    # §2.65 P1/P2 goal keys for MAS convergence check
    _P1P2_MAS_GOALS: frozenset[str] = frozenset(
        {
            "natuerlichkeit",
            "authentizitaet",
            "tonal_center",
            "timbre_authentizitaet",
            "artikulation",
        }
    )
    _P3P5_MAS_GOALS: frozenset[str] = frozenset(
        {
            "emotionalitaet",
            "micro_dynamics",
            "groove",
            "transparenz",
            "waerme",
            "bass_kraft",
            "separation_fidelity",
            "brillanz",
            "raumtiefe",
            "spatial_depth",  # §2.64 v9.12.1: alias → _fast_goal_snapshot also writes this key
        }
    )
    _MAS_TOLERANCE: float = 0.02  # §0k: all P1/P2 ≤ MAS+0.02 → convergence
    _MAS_FULL_TOLERANCE: float = 0.05  # §2.65: P3–P5 full convergence marker
    _MAS_OVERSHOOT_TOLERANCE: float = 0.03  # §0k: goal > MAS+0.03 → strength clamp signal

    def _check_mas_convergence(self, post_scores: dict[str, float], mas_gap: dict[str, float], phase_id: str) -> None:
        """Signal early pipeline stop when the song-specific MAS is achieved."""
        if not post_scores or not mas_gap or not phase_id or getattr(self, "_mas_fully_achieved", False):
            return

        _p1p2_gaps = {
            g: float(mas_gap[g])
            for g in self._P1P2_MAS_GOALS
            if g in mas_gap and mas_gap.get(g) is not None and post_scores.get(g) is not None
        }
        if not _p1p2_gaps or not all(gap <= self._MAS_TOLERANCE for gap in _p1p2_gaps.values()):
            return

        _p3p5_gaps = {
            g: float(mas_gap[g])
            for g in self._P3P5_MAS_GOALS
            if g in mas_gap and mas_gap.get(g) is not None and post_scores.get(g) is not None
        }
        _p3p5_achieved = bool(_p3p5_gaps) and all(gap <= self._MAS_FULL_TOLERANCE for gap in _p3p5_gaps.values())

        self._mas_fully_achieved = True
        _mas_meta = getattr(self, "_phase_metadata_accumulator", None)
        if isinstance(_mas_meta, dict):
            _mas_meta["mas_achieved_at_phase"] = phase_id
            _mas_meta["mas_gaps_at_convergence"] = {g: round(v, 4) for g, v in _p1p2_gaps.items()}
            _mas_meta["mas_p3p5_achieved"] = _p3p5_achieved
        logger.info(
            "§2.65 MAS-Convergence REACHED at %s — all P1/P2 goals ≤ MAS+%.2f: %s",
            phase_id,
            self._MAS_TOLERANCE,
            " ".join(f"{g}={_p1p2_gaps[g]:+.3f}" for g in sorted(_p1p2_gaps)),
        )

    @staticmethod
    def _compute_harmonic_adaptation_scalar(
        _phase_id: str,
        phase_family: str | None,
        goal_weights: dict[str, float] | None,
        restorability_score: float | None,
        material_key: str | None = None,
    ) -> float:
        """Compute a bounded cross-phase adaptation scalar for smooth global behaviour.

        This scalar is intentionally lightweight and advisory-only. It harmonizes
        all phases with the per-song context (§2.56 weights + restorability),
        without overriding hard guards or explicit PMGG strengths.
        """

        def _wavg(keys: tuple[str, ...], default: float = 1.0) -> float:
            if not isinstance(goal_weights, dict):
                return float(default)
            vals: list[float] = []
            for k in keys:
                v = goal_weights.get(k)
                if isinstance(v, (int, float)):
                    vals.append(float(v))
            if not vals:
                return float(default)
            return float(np.mean(vals))

        _preserve = _wavg(
            (
                "natuerlichkeit",
                "authentizitaet",
                "tonal_center",
                "timbre_authentizitaet",
                "artikulation",
            )
        )
        _clarity = _wavg(("transparenz", "brillanz", "separation_fidelity"))
        _goal_balance = float(np.clip((_clarity - _preserve) * 0.22, -0.18, 0.18))

        _rest = 70.0 if restorability_score is None else float(restorability_score)
        _rest_norm = float(np.clip((_rest - 50.0) / 50.0, -1.0, 1.0))

        _family = str(phase_family or "general")
        _subtractive_families = {
            "subtractive_cleanup",
            "harmonic_noise_control",
            "spectral_restoration",
            "reconstruction_inpainting",
            "time_pitch_transport",
            "distortion_repair",
        }
        _enhancement_families = {
            "harmonic_reconstruction",
            "harmonic_enhancement",
            "tonal_enhancement",
            "source_enhancement",
            "stereo_enhancement",
            "stereo_generation",
            "semantic_guidance",
        }
        _neutral_families = {
            "stereo_phase_geometry",
            "dynamics_repair",
            "dynamics_control",
            "tonal_restoration",
            "tonal_mastering",
            "finalizer_output",
            "general",
        }

        _scalar = 1.0
        if _family in _subtractive_families:
            # Hard material -> slightly more restorative energy, good material -> gentler.
            _scalar += 0.06 * (-_rest_norm)
            _scalar += 0.5 * _goal_balance
        elif _family in _enhancement_families:
            # Enhancement should be conservative on difficult material.
            _scalar += 0.08 * _rest_norm
            _scalar += 0.9 * _goal_balance
        elif _family in _neutral_families:
            _scalar += 0.03 * _goal_balance
        else:
            _scalar += 0.02 * _goal_balance

        _mat = str(material_key or "").lower()
        if _mat in {"shellac", "wax_cylinder", "wire_recording"} and _family in _enhancement_families:
            _scalar *= 0.95
        elif _mat in {"vinyl", "reel_tape", "tape", "cassette"} and _family in _enhancement_families:
            _scalar *= 0.98

        _bounded = float(np.clip(_scalar, 0.72, 1.18))
        return UnifiedRestorerV3._pullback_from_bounds(_bounded, 0.72, 1.18, margin_frac=0.04)

    @staticmethod
    def _compute_recovery_certainty_profile(
        *,
        restorability_score: float | None,
        source_material_baseline: Any | None,
        transfer_generation_count: int | None,
        material_key: str | None,
    ) -> dict[str, Any]:
        """Estimate recoverability ceiling + uncertainty for advisory conservatism."""
        _rest = 65.0 if restorability_score is None else float(restorability_score)
        _rest_norm = float(np.clip(_rest / 100.0, 0.0, 1.0))

        _gen = int(transfer_generation_count) if isinstance(transfer_generation_count, (int, float)) else 1
        _gen = int(np.clip(_gen, 1, 8))
        _gen_penalty = float(np.clip((_gen - 1) * 0.045, 0.0, 0.28))

        _hf_loss_db = getattr(source_material_baseline, "hf_loss_db", None)
        if isinstance(_hf_loss_db, (int, float)):
            _hf_penalty = float(np.clip(abs(float(_hf_loss_db)) / 90.0, 0.0, 0.18))
        else:
            _hf_penalty = 0.0

        _mat = str(material_key or "").lower()
        _mat_penalty = 0.0
        if _mat in {"shellac", "edison_cylinder", "wax_cylinder", "wire_recording"}:
            _mat_penalty = 0.08
        elif _mat in {"reel_tape", "tape", "cassette", "vinyl"}:
            _mat_penalty = 0.04

        _ceiling = float(np.clip(_rest_norm - _gen_penalty - _hf_penalty - _mat_penalty, 0.12, 0.98))
        _uncertainty = float(np.clip(1.0 - _ceiling, 0.02, 0.88))
        _conservative_scalar = float(np.clip(1.0 - 0.26 * _uncertainty, 0.78, 1.0))

        if _ceiling >= 0.80:
            _band = "high"
        elif _ceiling >= 0.55:
            _band = "medium"
        else:
            _band = "low"

        return {
            "recoverability_ceiling": _ceiling,
            "uncertainty_index": _uncertainty,
            "conservative_audio_scalar": _conservative_scalar,
            "confidence_band": _band,
            "restorability_score": float(_rest),
            "transfer_generation_count": int(_gen),
            "hf_loss_db": float(_hf_loss_db) if isinstance(_hf_loss_db, (int, float)) else None,
        }

    @staticmethod
    def _compute_frisson_audio_impact_scalar(
        *,
        studio_mode: bool,
        phase_family: str | None,
        goal_weights: dict[str, float] | None,
    ) -> float:
        """Compute bounded frisson coupling scalar.

        Mode policy:
        - Restoration: disabled (always 1.0)
        - Studio 2026: enabled, conservative bounded modulation

        This scalar is advisory and intentionally small to avoid over-processing.
        """
        if not bool(studio_mode):
            return 1.0
        if not isinstance(goal_weights, dict) or not goal_weights:
            return 1.0

        def _wavg(keys: tuple[str, ...], default: float = 1.0) -> float:
            vals: list[float] = []
            for k in keys:
                v = goal_weights.get(k)
                if isinstance(v, (int, float)):
                    vals.append(float(v))
            if not vals:
                return float(default)
            return float(np.mean(vals))

        _frisson_weight = _wavg(
            (
                "emotionalitaet",
                "micro_dynamics",
                "artikulation",
                "spatial_depth",
                "transparenz",
                "tonal_center",
            )
        )
        _z = float(np.clip((_frisson_weight - 1.0) / 0.60, -1.0, 1.0))
        _family = str(phase_family or "general")

        _enhancement_families = {
            "harmonic_reconstruction",
            "harmonic_enhancement",
            "tonal_enhancement",
            "source_enhancement",
            "stereo_enhancement",
            "stereo_generation",
            "semantic_guidance",
        }
        _subtractive_families = {
            "subtractive_cleanup",
            "harmonic_noise_control",
            "spectral_restoration",
            "reconstruction_inpainting",
            "time_pitch_transport",
            "distortion_repair",
        }

        _scalar = 1.0
        if _family in _enhancement_families:
            _scalar += 0.045 * _z
        elif _family in _subtractive_families:
            _scalar -= 0.030 * max(0.0, _z)
        else:
            _scalar += 0.015 * _z

        _bounded = float(np.clip(_scalar, 0.94, 1.06))
        return UnifiedRestorerV3._pullback_from_bounds(_bounded, 0.94, 1.06, margin_frac=0.03)

    @staticmethod
    def _mid_pipeline_calibration_step(
        current_scores: "dict[str, float] | None",
        profile: "dict[str, Any] | None",
        checkpoint_label: str,
        completed_count: int,
        total_count: int,
        artifact_floor: float | None = None,
    ) -> "dict[str, Any] | None":
        """Mid-pipeline family-scalar refinement (§2.31a adaptive iteration).

        Uses PMGG-measured Musical Goal scores (zero additional DSP cost) to
        refine family_scalars for pipeline phases not yet executed. Called at
        ~33 % and ~66 % of phase-execution progress inside _execute_pipeline.

        Rules
        -----
        - Adjustments bounded at ±12 % per family per checkpoint call.
        - All scalars clamped to [0.60, 1.10] (matches _get_phase_calibration_scalar).
        - Returns an updated *copy* of the profile (never mutates the original).
        - Returns None when no meaningful adjustment was computed (< 0.5 % delta).

        Uses already-computed PMGG scores — no additional audio processing cost.
        """
        if not isinstance(profile, dict) or not isinstance(current_scores, dict) or not current_scores:
            return None
        _fam = profile.get("family_scalars")
        if not isinstance(_fam, dict):
            return None

        import copy as _copy

        _new_profile: dict[str, Any] = _copy.deepcopy(profile)
        _new_fam: dict[str, float] = _new_profile["family_scalars"]
        _changes: dict[str, float] = {}
        _raw_policy = _new_profile.get("cluster_policy")
        _policy: dict[str, Any] = _raw_policy if isinstance(_raw_policy, dict) else {}
        _artifact_sens = float(np.clip(float(_policy.get("artifact_sensitivity", 1.0)), 0.85, 1.25))
        _fatigue_sens = float(np.clip(float(_policy.get("fatigue_sensitivity", 1.0)), 0.85, 1.20))
        _recovery_bias = float(np.clip(float(_policy.get("recovery_bias", 1.0)), 0.85, 1.20))
        _micro_bias = float(np.clip(float(_policy.get("microdynamics_bias", 1.0)), 0.90, 1.15))

        def _adj(family: str, factor: float) -> None:
            """Apply a bounded multiplicative adjustment, clamped to [0.30, 1.80] (Lücke-G-Fix v9.10.100)."""
            _old = float(np.clip(float(_new_fam.get(family, 1.0)), 0.30, 1.80))
            _new_val = float(np.clip(_old * factor, 0.30, 1.80))
            _new_val = UnifiedRestorerV3._pullback_from_bounds(_new_val, 0.30, 1.80, margin_frac=0.03)
            if abs(_new_val - _old) >= 0.005:  # ignore sub-0.5 % noise
                _new_fam[family] = _new_val
                _changes[family] = round(_new_val - _old, 4)

        # Brillanz (HF crest-factor proxy): low after denoise → SBR / reconstruction needs more
        _brillanz = current_scores.get("brillanz")
        if _brillanz is not None and float(_brillanz) < 0.74:
            _deficit = 0.74 - float(_brillanz)
            _adj("reconstruction", 1.0 + min(0.12, _deficit * 0.5))

        # Micro-dynamics: low → transient shaping + dynamics/EQ need stronger application
        _micro = current_scores.get("micro_dynamics")
        if _micro is not None and float(_micro) < 0.82:
            _deficit = 0.82 - float(_micro)
            _adj("transient", 1.0 + min(0.10, _deficit * 0.4))
            _adj("dynamics_eq", 1.0 + min(0.08, _deficit * 0.3))

        # Tonal center (K-S proxy): regression after denoise/reverb → reconstruction needs care
        _tonal = current_scores.get("tonal_center")
        if _tonal is not None and float(_tonal) < 0.91:
            _deficit = 0.91 - float(_tonal)
            _adj("reconstruction", 1.0 + min(0.08, _deficit * 0.4))
            # Minor de-boost on dynamics_eq to avoid over-EQ causing further key drift
            _adj("dynamics_eq", 1.0 - min(0.05, _deficit * 0.25))

        # Groove: low → rhythm-preserving EQ + transient integrity protection needed
        _groove = current_scores.get("groove")
        if _groove is not None and float(_groove) < 0.78:
            _deficit = 0.78 - float(_groove)
            _adj("dynamics_eq", 1.0 + min(0.08, _deficit * 0.4))
            _adj("transient", 1.0 + min(0.06, _deficit * 0.3))

        # Separation fidelity: low → instrument / stem separation needs more strength
        _sep = current_scores.get("separation_fidelity")
        if _sep is not None and float(_sep) < 0.74:
            _deficit = 0.74 - float(_sep)
            _adj("instrument", 1.0 + min(0.10, _deficit * 0.5))

        # Spatial depth: low → stereo / spatial enhancement needed
        _raum = current_scores.get("spatial_depth") or current_scores.get("raumtiefe")
        if _raum is not None and float(_raum) < 0.65:
            _deficit = 0.65 - float(_raum)
            _adj("instrument", 1.0 + min(0.08, _deficit * 0.4))

        # Artikulation: low → vocal precision / clarity enhancement needed
        _artik = current_scores.get("artikulation")
        if _artik is not None and float(_artik) < 0.80:
            _deficit = 0.80 - float(_artik)
            _adj("vocal", 1.0 + min(0.12, _deficit * 0.5))

        # Bass kraft: low → low-end dynamics EQ boost needed
        _bass = current_scores.get("bass_kraft")
        if _bass is not None and float(_bass) < 0.74:
            _deficit = 0.74 - float(_bass)
            _adj("dynamics_eq", 1.0 + min(0.06, _deficit * 0.3))

        # Produktions-Nachbesserung (psychoakustisch): falls Artefaktfreiheit bereits
        # im laufenden Pipeline-Verlauf sinkt oder Fatigue-/Harshness-Proxys kippen,
        # verbleibende Enhancement-Familien vorsichtig dämpfen statt aggressiv fortzufahren.
        if artifact_floor is not None and float(artifact_floor) < 0.98:
            _af_def = min(0.20, 0.98 - float(artifact_floor))
            _deboost = 1.0 - min(0.12, _af_def * 0.8)
            _adj("reconstruction", _deboost)
            _adj("transient", _deboost)
            _adj("vocal", 1.0 - min(0.10, _af_def * 0.7))
            _adj("instrument", 1.0 - min(0.08, _af_def * 0.6))

        _nat = current_scores.get("natuerlichkeit")
        _warm = current_scores.get("waerme")
        _bri_hi = current_scores.get("brillanz")
        _fatigue_proxy = False
        if _nat is not None and float(_nat) < 0.90:
            _fatigue_proxy = True
        if _bri_hi is not None and _warm is not None and float(_bri_hi) > 0.88 and float(_warm) < 0.74:
            _fatigue_proxy = True
        if _fatigue_proxy:
            _adj("dynamics_eq", 0.94)
            _adj("transient", 0.93)
            _adj("reconstruction", 0.95)

        if not _changes:
            return None  # no meaningful refinement needed

        logger.info(
            "§2.31a MidCalibrate[%s] global=%.3f progress=%d/%d adjustments: %s",
            checkpoint_label,
            float(profile.get("global_scalar", 1.0)),
            completed_count,
            total_count,
            ", ".join(f"{k}:{v:+.4f}" for k, v in sorted(_changes.items())),
        )
        # Persist calibration events for RestorationResult.metadata audit trail
        _events: list[dict[str, Any]] = list(profile.get("_mid_calibration_events", []))
        _events.append(
            {
                "checkpoint": checkpoint_label,
                "progress": f"{completed_count}/{total_count}",
                "adjustments": dict(_changes),
                "artifact_floor": round(float(artifact_floor), 4) if artifact_floor is not None else None,
                "scores_snapshot": {k: round(float(v), 4) for k, v in current_scores.items()},
            }
        )
        _new_profile["_mid_calibration_events"] = _events
        return _new_profile

    @staticmethod
    def _continuous_joy_refinement_step(
        current_scores: "dict[str, float] | None",
        profile: "dict[str, Any] | None",
        trigger_phase_id: str,
        completed_count: int,
        total_count: int,
        artifact_floor: float | None = None,
    ) -> "dict[str, Any] | None":
        """Continuous psychoacoustic refinement after each accepted phase.

        Closed-loop production path: keeps joy/fatigue/artifact trade-offs stable
        throughout the entire phase chain, not only at 33/66% checkpoints.
        """
        if not isinstance(profile, dict) or not isinstance(current_scores, dict) or not current_scores:
            return None
        _fam = profile.get("family_scalars")
        if not isinstance(_fam, dict):
            return None

        import copy as _copy

        _new_profile: dict[str, Any] = _copy.deepcopy(profile)
        _new_fam: dict[str, float] = _new_profile["family_scalars"]
        _changes: dict[str, float] = {}
        _raw_policy = _new_profile.get("cluster_policy")
        _policy: dict[str, Any] = _raw_policy if isinstance(_raw_policy, dict) else {}
        _artifact_sens = float(np.clip(float(_policy.get("artifact_sensitivity", 1.0)), 0.85, 1.25))
        _fatigue_sens = float(np.clip(float(_policy.get("fatigue_sensitivity", 1.0)), 0.85, 1.20))
        _recovery_bias = float(np.clip(float(_policy.get("recovery_bias", 1.0)), 0.85, 1.20))
        _micro_bias = float(np.clip(float(_policy.get("microdynamics_bias", 1.0)), 0.90, 1.15))

        def _adj(family: str, factor: float) -> None:
            _old = float(np.clip(float(_new_fam.get(family, 1.0)), 0.30, 1.80))
            _new_val = float(np.clip(_old * factor, 0.30, 1.80))
            _new_val = UnifiedRestorerV3._pullback_from_bounds(_new_val, 0.30, 1.80, margin_frac=0.03)
            if abs(_new_val - _old) >= 0.003:
                _new_fam[family] = _new_val
                _changes[family] = round(_new_val - _old, 4)

        _nat = current_scores.get("natuerlichkeit")
        _warm = current_scores.get("waerme")
        _bri = current_scores.get("brillanz")
        _artik = current_scores.get("artikulation")
        _micro = current_scores.get("micro_dynamics")

        # Artifact-first damping (very small per-step changes, cumulative closed-loop).
        if artifact_floor is not None and float(artifact_floor) < 0.98:
            _af_def = min(0.20, 0.98 - float(artifact_floor))
            _adj("reconstruction", 1.0 - min(0.06, _af_def * 0.5 * _artifact_sens))
            _adj("transient", 1.0 - min(0.06, _af_def * 0.5 * _artifact_sens))
            _adj("vocal", 1.0 - min(0.05, _af_def * 0.4 * _artifact_sens))
            _adj("instrument", 1.0 - min(0.05, _af_def * 0.4 * _artifact_sens))

        # Fatigue proxy: too bright + too little warmth / naturalness.
        if (_nat is not None and float(_nat) < 0.90) or (
            _bri is not None and _warm is not None and float(_bri) > 0.86 and float(_warm) < 0.74
        ):
            _adj("dynamics_eq", 1.0 - min(0.05, 0.03 * _fatigue_sens))
            _adj("transient", 1.0 - min(0.05, 0.03 * _fatigue_sens))
            _adj("reconstruction", 1.0 - min(0.04, 0.02 * _fatigue_sens))

        # Recovery path when stable and under-articulated.
        if _artik is not None and float(_artik) < 0.80 and (_nat is None or float(_nat) >= 0.90):
            _adj("vocal", 1.0 + min(0.03, 0.02 * _recovery_bias))

        # Preserve musical life if safe: tiny boost only when artifact floor is healthy.
        if _micro is not None and float(_micro) < 0.82 and (artifact_floor is None or float(artifact_floor) >= 0.98):
            _adj("transient", 1.0 + min(0.03, 0.02 * _micro_bias))
            _adj("dynamics_eq", 1.0 + min(0.02, 0.015 * _micro_bias))

        if not _changes:
            return None

        _events: list[dict[str, Any]] = list(profile.get("_joy_closed_loop_events", []))
        _events.append(
            {
                "trigger_phase": trigger_phase_id,
                "progress": f"{completed_count}/{total_count}",
                "adjustments": dict(_changes),
                "artifact_floor": round(float(artifact_floor), 4) if artifact_floor is not None else None,
                "scores_snapshot": {k: round(float(v), 4) for k, v in current_scores.items()},
            }
        )
        _new_profile["_joy_closed_loop_events"] = _events
        logger.debug(
            "JoyLoop[%s] progress=%d/%d adjustments: %s",
            trigger_phase_id,
            completed_count,
            total_count,
            ", ".join(f"{k}:{v:+.4f}" for k, v in sorted(_changes.items())),
        )
        return _new_profile

    def _discover_phase_metadata(self) -> dict[str, dict]:
        """Findet alle Phasenmodule und liest Metadaten (ohne Instanziierung)."""
        phase_dir = os.path.join(os.path.dirname(__file__), "phases")
        phase_files: list[str] = [f for f in os.listdir(phase_dir) if f.startswith("phase_") and f.endswith(".py")]
        metadata = {}
        for fname in phase_files:
            modulename = f"backend.core.phases.{fname[:-3]}"
            try:
                module = importlib.import_module(modulename)
                for _, obj in module.__dict__.items():
                    if (
                        isinstance(obj, type)
                        and issubclass(obj, PhaseInterface)
                        and obj is not PhaseInterface
                        and getattr(obj, "__module__", "") == modulename
                    ):
                        meta = obj().get_metadata()
                        metadata[meta.phase_id] = {
                            "class": obj,
                            "modulename": modulename,
                            "name": meta.name,
                            "category": meta.category.value,
                            "dependencies": meta.dependencies,
                            "estimated_time_factor": meta.estimated_time_factor,
                            "priority": meta.priority,
                        }
                        break  # Only one PhaseInterface subclass per module file
            except Exception as e:
                logger.warning("Phase-Modul %s konnte nicht geladen werden: %s", modulename, e)
        return metadata

    # Phase aliases: maps non-existent phase IDs to their canonical replacements.
    # phase_57_print_through_reduction is not a separate implementation; it routes
    # to phase_29_tape_hiss_reduction (LMS adaptive filter, bidirectional).
    _PHASE_ALIASES: dict[str, str] = {
        "phase_57_print_through_reduction": "phase_29_tape_hiss_reduction",
    }

