    @classmethod
    def get_phase_intervention_registry(cls) -> dict[str, str]:
        """Return the explicit 64-phase intervention-class registry for tests/audit."""
        return dict(cls._PHASE_INTERVENTION_CLASS)

    def _get_phase(self, phase_id: str) -> PhaseInterface | None:
        """Lädt und instanziiert eine Phase nur bei Bedarf (Lazy Loading).

        Thread-safe via _phase_cache_lock (§3.2 Double-Checked Locking).
        """
        # Resolve alias before cache lookup so aliased IDs share the same instance.
        phase_id = self._PHASE_ALIASES.get(phase_id, phase_id)
        if phase_id in self._phase_cache:
            return self._phase_cache[phase_id]
        with self._phase_cache_lock:
            # Double-checked locking: re-check after acquiring lock
            if phase_id in self._phase_cache:
                return self._phase_cache[phase_id]
            meta = self.phase_metadata.get(phase_id)
            if not meta:
                logger.error("Phase %s nicht gefunden (weder Registry noch Metadaten)", phase_id)
                return None
            try:
                phase_instance = meta["class"]()
                self._phase_cache[phase_id] = phase_instance
                return phase_instance
            except Exception as exc:
                self._warnings.append(f"Phase {phase_id} nicht geladen: {type(exc).__name__}: {exc}")
                logger.warning("Phase %s übersprungen: %s", phase_id, exc)
                return None

    # _register_phases entfällt, Lazy Loading übernimmt die Instanziierung

    def restore(  # pyright: ignore[reportGeneralTypeIssues]
        self,
        audio: np.ndarray,
        sample_rate: int = 44100,
        progress_callback=None,
        **kwargs,
    ) -> RestorationResult:
        """
        Hauptmethode: Restauriert Audio mit Defect-First Approach.

        Args:
            audio: Input Audio (mono: shape=(n,), stereo: shape=(n,2))
            sample_rate: Sample rate (default: 44100 Hz, wird intern auf 48000 Hz konvertiert)
            progress_callback: Optional callable(percent: int, phase: str, elapsed_s: float)
                               Wird während der Verarbeitung periodisch aufgerufen.
            **kwargs: Additional parameters

        Returns:
            RestorationResult mit restauriertem Audio und Metadata

        Note:
            Alle Verarbeitung erfolgt intern bei 48 kHz für konsistente ML-Modell-Performance.
        """
        start_time = time.time()
        # §0c: Reset graceful-stop for new song — previous watchdog signal must not bleed over.
        self._graceful_stop_event.clear()

        def _cb(pct: int, phase: str) -> None:
            """Sendet Progress-Update, falls Callback registriert."""
            if progress_callback is not None:
                try:
                    progress_callback(pct, phase, time.time() - start_time)
                except Exception as _cb_exc:
                    logger.debug(
                        "Progress-Callback fehlgeschlagen (Ursache: %s). "
                        "Lösung: Callback-Signatur prüfen (pct:int, phase:str, elapsed_s:float).",
                        _cb_exc,
                    )

        original_sample_rate = sample_rate
        target_sample_rate = 48000  # Standardisierung auf 48 kHz
        # Dual-SR routing: analysis modules keep native import SR, processing phases run at 48 kHz.
        analysis_audio = np.array(audio, copy=True)
        analysis_sample_rate = sample_rate

        # §9.1 kwargs: mode + material aus externen Aufrufen verarbeiten (z.B. AMRB-Runner)
        _mode_map = {
            "fast": QualityMode.FAST,
            "balanced": QualityMode.BALANCED,
            "restoration": QualityMode.QUALITY,  # Restoration nutzt volle Quality-Pipeline
            "quality": QualityMode.QUALITY,
            "maximum": QualityMode.MAXIMUM,  # §9.5: 8× RT — war fälschlich BALANCED (3×)
            "studio_2026": QualityMode.MAXIMUM,  # §9.5: 8× RT — war fälschlich BALANCED (3×)
        }
        _mode_kwarg = kwargs.pop("mode", None)
        if _mode_kwarg is not None:
            self.config.mode = _mode_map.get(str(_mode_kwarg).lower(), self.config.mode)
        _mat_kwarg = kwargs.pop("material", None)
        if _mat_kwarg is not None and self.config.material_type is None:
            try:
                self.config.material_type = MaterialType(str(_mat_kwarg))
            except ValueError as _mat_exc:
                logger.warning(
                    "Ungültiger Material-Hinweis '%s' ignoriert (Ursache: %s). "
                    "Lösung: gültige MaterialType-Werte verwenden.",
                    _mat_kwarg,
                    _mat_exc,
                )

        # §Dach: MusikalischerGlobalplan — aus kwargs oder RestorationConfig laden
        _gp_kwarg = kwargs.pop("global_plan", None)
        _chain_kwarg = kwargs.pop("chain_info", None)
        _defekt_hint_kwarg = kwargs.pop("defekt_hint", None)
        # §PID: PhaseInteractionDenker übergibt fertig selektierten Plan — UV3 übernimmt
        # dann als reiner Executor (kein _optimize_phase_plan_intelligence() mehr).
        # Leerer Plan [] oder None → UV3 selektiert autonom (fail-safe).
        _precomputed_phase_plan: list[str] | None = kwargs.pop("precomputed_phase_plan", None) or None
        # §2.53b: Log immediately so test mock-patched pipelines capture these messages
        # before intermediate analysis steps that may be incomplete/mocked.
        if _precomputed_phase_plan:
            logger.info("Phase Skipping deaktiviert: precomputed_phase_plan aktiv (deterministischer PID-Executor)")
            logger.info(
                "§PID PhaseInteractionDenker-Plan aktiv: %d Phasen (UV3 _select/_optimize übersprungen)",
                len(_precomputed_phase_plan),
            )
        # Pre-analysis result (PreAnalysisResult from backend.core.pre_analysis).
        # When provided, individual cached_* kwargs are populated from it automatically
        # so callers only need to pass one object.
        _pre_analysis = kwargs.pop("pre_analysis_result", None)
        if _pre_analysis is not None:
            # Unpack sub-results into the individual cache kwargs, but do NOT
            # overwrite kwargs that were already set explicitly by the caller.
            if kwargs.get("cached_medium_result") is None and getattr(_pre_analysis, "medium", None) is not None:
                kwargs["cached_medium_result"] = _pre_analysis.medium
            if kwargs.get("cached_era_result") is None and getattr(_pre_analysis, "era", None) is not None:
                kwargs["cached_era_result"] = _pre_analysis.era
            if kwargs.get("cached_genre_result") is None and getattr(_pre_analysis, "genre", None) is not None:
                kwargs["cached_genre_result"] = _pre_analysis.genre
            if kwargs.get("cached_defect_result") is None and getattr(_pre_analysis, "defects", None) is not None:
                kwargs["cached_defect_result"] = _pre_analysis.defects
            if (
                kwargs.get("cached_restorability_result") is None
                and getattr(_pre_analysis, "restorability", None) is not None
            ):
                kwargs["cached_restorability_result"] = _pre_analysis.restorability
        _cached_era_kwarg = kwargs.pop("cached_era_result", None)
        _cached_genre_kwarg = kwargs.pop("cached_genre_result", None)
        _cached_defect_kwarg = kwargs.pop("cached_defect_result", None)
        _cached_medium_kwarg = kwargs.pop("cached_medium_result", None)
        _cached_restorability_kwarg = kwargs.pop("cached_restorability_result", None)
        _audio_update_cb_kwarg = kwargs.pop("audio_update_callback", None)
        _no_rt_limit = bool(kwargs.pop("no_rt_limit", False))
        self._song_calibration_profile = {}
        self._strict_autosetup_policy = {}
        self._phase_goal_conflict_runtime = {"events": [], "by_phase": {}, "by_family": {}, "total": 0}
        # §11.7a: reconstruction_context von RekonstruktionsDenker — enthält bereits reparierte Gaps
        _reconstruction_ctx = kwargs.pop("reconstruction_context", None)
        # §DEBUG: Debug-Trace aktivieren — schreibt pmgg_log_entries (mit scores_before/after)
        # in metadata["pmgg_log_entries"] am Ende des Pipeline-Laufs.
        self._debug_trace_enabled = bool(kwargs.pop("enable_debug_trace", False))
        # Bug-15-Fix: file_ext aus input_path extrahieren — wird an DefectScanner.scan()
        # weitergegeben, damit der interne ForensicMediumDetector-Aufruf das Analog-
        # Posterior-Zeroing anwenden kann (verhindert wax_cylinder-Fehlklassifikation).
        _input_path_for_ext = str(kwargs.get("input_path", "") or kwargs.get("file_path", "") or "")
        import os as _os_uv3

        _file_ext_for_scan = _os_uv3.path.splitext(_input_path_for_ext)[1].lower() if _input_path_for_ext else ""
        self._active_global_plan = _gp_kwarg if _gp_kwarg is not None else self.config.global_plan
        self._active_chain_info = _chain_kwarg  # TontraegerketteDenker: Ketten-Phasen
        self._active_defekt_hint = _defekt_hint_kwarg  # DefektDenker: heuristische Phasen-Empfehlung

        _cb(1, "Initialisierung…")
        # Robuste Sample-Count-Ermittlung: (N,2) → N, (2,N) → N, (N,) → N
        _n_samples = max(audio.shape) if audio.ndim == 2 else len(audio)
        logger.info("Starting restoration: %.1fs audio @ %d Hz", _n_samples / sample_rate, sample_rate)
        # §2.31d Edge-Case flags — computed once, used throughout restore().
        _audio_duration_s: float = float(_n_samples) / float(sample_rate)
        _is_very_short: bool = _audio_duration_s < 10.0  # Groove/MicroDyn/EmotionalArc off
        _is_very_long: bool = _audio_duration_s > 3600.0  # DefectScanner 3×60s-Segmente
        if _is_very_short:
            logger.info(
                "§2.31d Edge-Case: Audio %.1fs < 10s — "
                "Groove + MicroDyn + EmotionalArc werden deaktiviert, FeedbackChain max 2 Iter",
                _audio_duration_s,
            )
        if _is_very_long:
            logger.info(
                "§2.31d Edge-Case: Audio %.0fs > 60 min — DefectScanner auf 3×60-s-Segmente (Anfang/Mitte/Ende)",
                _audio_duration_s,
            )

        # ── Early-Exit Guard: Minimum Signal Length ─────────────────────
        # Signals shorter than 100 ms (4800 samples @ 48 kHz) cannot be meaningfully
        # restored. HPSS, STFT and ML metrics produce garbage on such tiny buffers and
        # trigger misleading warnings (PQS-MOS, 8×RT violations, Musical Goals).
        # Return a no-op pass-through result immediately to avoid polluting the log.
        _MIN_MEANINGFUL_SAMPLES = 4800  # 100 ms @ 48 kHz
        _audio_size_check = audio.size
        if _audio_size_check < _MIN_MEANINGFUL_SAMPLES:
            logger.debug(
                "restore(): Signal zu kurz (%d Samples < %d) — Pass-Through ohne Verarbeitung.",
                _audio_size_check,
                _MIN_MEANINGFUL_SAMPLES,
            )
            return RestorationResult(
                audio=np.clip(np.nan_to_num(audio.astype(np.float32), nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0),
                config=self.config,
                material_type=MaterialType.UNKNOWN,
                defect_scores={},
                phases_executed=[],
                phases_skipped=[],
                total_time_seconds=0.0,
                rt_factor=0.0,
                quality_estimate=0.5,
                warnings=["signal_too_short"],
                metadata={
                    "skip_reason": "signal_too_short",
                    "audio_samples": _audio_size_check,
                    "min_samples": _MIN_MEANINGFUL_SAMPLES,
                },
            )

        # Start adaptive resource monitoring once per process lifecycle.
        try:
            from backend.core.adaptive_resource_manager import adaptive_resource_manager as _arm

            _arm.start_monitoring()
        except Exception as _arm_exc:
            logger.debug("AdaptiveResourceManager.start_monitoring() fehlgeschlagen: %s", _arm_exc)

        # Early initialization of variables used before their main definition (avoids F821)
        _is_studio_26 = self.is_studio_mode()
        _goal_applicability_result = None
        _emotional_arc_result: Any = None
        # Structured error accumulator — persists into RestorationResult.metadata["fail_reasons"]
        # Each entry: {"component": str, "error_code": str, "exc_type": str, "exc_msg": str}
        _fail_reasons: list[dict[str, Any]] = []

        # Normalize analysis path stereo layout once (channel-first) while keeping native SR untouched.
        if (
            analysis_audio.ndim == 2
            and analysis_audio.shape[1] <= 2
            and analysis_audio.shape[0] > analysis_audio.shape[1]
        ):
            analysis_audio = analysis_audio.T

        if not np.all(np.isfinite(analysis_audio)):
            analysis_audio = np.nan_to_num(analysis_audio, nan=0.0, posinf=0.9, neginf=-0.9)
        analysis_audio = np.clip(analysis_audio, -1.0, 1.0).astype(np.float32, copy=False)

        # Resample to 48 kHz if necessary
        if sample_rate != target_sample_rate:
            if LIBROSA_AVAILABLE:
                logger.info("Resampling %s Hz → %s Hz for standardized processing", sample_rate, target_sample_rate)
                if audio.ndim == 2:
                    # Stereo: resample each channel — handle both (N,2) and (2,N) layouts
                    if audio.shape[0] > audio.shape[1]:
                        # (N, 2) column-major from frontend
                        audio = np.column_stack(
                            [
                                librosa.resample(audio[:, 0], orig_sr=sample_rate, target_sr=target_sample_rate),
                                librosa.resample(audio[:, 1], orig_sr=sample_rate, target_sr=target_sample_rate),
                            ]
                        )
                    else:
                        # (2, N) channel-first
                        audio = np.stack(
                            [
                                librosa.resample(audio[0], orig_sr=sample_rate, target_sr=target_sample_rate),
                                librosa.resample(audio[1], orig_sr=sample_rate, target_sr=target_sample_rate),
                            ]
                        )
                else:
                    # Mono
                    audio = librosa.resample(audio, orig_sr=sample_rate, target_sr=target_sample_rate)
                sample_rate = target_sample_rate
            else:
                raise RuntimeError(
                    f"Interne 48-kHz-Normierung fehlgeschlagen (librosa nicht verfügbar, Eingang={sample_rate} Hz). "
                    "Lösung: librosa/scipy im Runtime-Bundle bereitstellen oder Audio vorab auf 48 kHz konvertieren."
                )

        # §3.1 NaN/Inf-Invariante: Bereinigung nach Resampling (Bibliotheks-Artefakte möglich)
        if not np.all(np.isfinite(audio)):
            logger.debug("restore(): NaN/Inf nach Resampling bereinigt")
            audio = np.nan_to_num(audio, nan=0.0, posinf=0.9, neginf=-0.9)
        audio = np.clip(audio, -1.0, 1.0)

        # §3.x Stereo-Normalisierung: Internes Format ist channel-first (2, N).
        # Frontend liefert (N, 2) via _normalize_audio — hier einheitlich auf (2, N) drehen.
        # Ohne diese Normalisierung greifen SAP, TDP, Vocos-Stereo-Handling und alle
        # `restored_audio[0]`-Zugriffe auf die erste Sample-Zeile statt den ersten Kanal,
        # was das Audio auf 2 Samples korrumpiert (EpistemicGate "2 Samples < 4800").
        if audio.ndim == 2 and audio.shape[1] <= 2 and audio.shape[0] > audio.shape[1]:
            audio = audio.T  # (N, 2) → (2, N)
            logger.debug("restore(): Stereo (N,%d) → (%d,N) normalisiert", audio.shape[0], audio.shape[0])

        # ── OOM-Guard: Audio-Buffer-Größe gegen RAM-Budget prüfen ────────────
        # Spec §9: Audio-Buffer max. 4 GB.  Intermediate STFTs/copies multiplizieren
        # den Bedarf ~5× → effektives Limit: ~800 MB Audio-Input bei 32 GB RAM.
        _audio_bytes = audio.nbytes
        _MAX_AUDIO_BUFFER_BYTES = 4 * 1024**3  # 4 GB absolute Obergrenze (Spec §9)
        if _audio_bytes > _MAX_AUDIO_BUFFER_BYTES:
            raise MemoryError(
                f"Audio-Buffer ({_audio_bytes / (1024**3):.1f} GB) überschreitet "
                f"das erlaubte Maximum von {_MAX_AUDIO_BUFFER_BYTES / (1024**3):.0f} GB (Spec §9). "
                f"Bitte eine kürzere Datei verwenden."
            )
        # Physischer RAM-Preflight: mind. 3 GB + 5× Audio-Puffer frei
        try:
            import psutil as _psutil_guard

            _avail_mb = float(_psutil_guard.virtual_memory().available / (1024 * 1024))
            _needed_mb = max(3072.0, (_audio_bytes * 5) / (1024 * 1024))
            if _avail_mb < _needed_mb:
                logger.warning(
                    "OOM-Guard: Nur %.0f MB RAM frei, benötigt ~%.0f MB. Versuche Plugin-Eviction…",
                    _avail_mb,
                    _needed_mb,
                )
                try:
                    from backend.core.plugin_lifecycle_manager import evict_stale_plugins

                    evict_stale_plugins(required_mb=_needed_mb)
                    gc.collect()
                except Exception as _evict_exc:
                    logger.debug("PLM-Eviction vor Pipeline fehlgeschlagen: %s", _evict_exc)
                _avail_after = float(_psutil_guard.virtual_memory().available / (1024 * 1024))
                if _avail_after < _needed_mb * 0.7:
                    raise MemoryError(
                        f"Nicht genügend RAM: {_avail_after:.0f} MB frei, "
                        f"~{_needed_mb:.0f} MB benötigt. Bitte andere Anwendungen schließen."
                    )
        except ImportError:
            logger.debug("psutil not available — RAM guard degraded graceful")

        _cb(3, "Resampling & Vorverarbeitung…")
        # Step 1a: Material-Erkennung via MediumClassifier (vor DefectScanner)
        # Nur wenn kein Material manuell vorgegeben wurde (config.material_type is None)
        # §G1: Pre-Repair-Referenz aus AurikDenker (echtes Original VOR ReparaturDenker)
        # für referenz-basierte Musical Goals (Authentizität, Groove, Timbre, Artikulation).
        # Falls nicht vorhanden: Fallback auf Eingabe-Audio (identisch mit bisherigem Verhalten).
        _pre_repair_ref = kwargs.get("pre_repair_reference")
        if _pre_repair_ref is not None and isinstance(_pre_repair_ref, np.ndarray) and _pre_repair_ref.size > 0:
            original_audio_for_goals: np.ndarray = _pre_repair_ref.copy()
            # §G1-Fix: Stereo-Layout an audio angleichen — AurikDenker liefert (N,2),
            # aber audio wurde oben bereits auf (2,N) transponiert. Ohne Angleichung
            # scheitert der Shape-Check bei measure_all() und alle ref-basierten
            # Musical Goals (Timbre, TonalCenter, Transparenz) fallen auf schwächere
            # reference-free Proxies zurück.
            if (
                original_audio_for_goals.ndim == 2
                and audio.ndim == 2
                and original_audio_for_goals.shape != audio.shape
                and original_audio_for_goals.T.shape == audio.shape
            ):
                original_audio_for_goals = original_audio_for_goals.T
                logger.info("UV3: pre_repair_reference transponiert (N,ch) → (ch,N) für Shape-Match")
            logger.info(
                "UV3: pre_repair_reference als Goal-Referenz übernommen (shape=%s)", original_audio_for_goals.shape
            )
        else:
            original_audio_for_goals: np.ndarray = audio.copy()

        _cb(5, "Restaurierbarkeit wird geprüft…")
        # §2.26 RestorabilityEstimator — Vor-Assessment der Restaurierbarkeit (DSP-only, < 5 s)
        # §2.29 Normativ (PMGG Datenfluss-Invariante): _pmgg_restorability_score MUSS aus
        # RestorabilityEstimator.estimate().restorability_score stammen — kein Hard-Code 70.0.
        _pmgg_restorability_score: float = 70.0  # konservativer Default wenn Estimator nicht verfügbar
        if _cached_restorability_kwarg is not None:
            _pmgg_restorability_score = float(getattr(_cached_restorability_kwarg, "restorability_score", 70.0))
            logger.info(
                "RestorabilityEstimator: verwende gecachtes Ergebnis (score=%.1f)",
                _pmgg_restorability_score,
            )
        else:
            try:
                from backend.core.restorability_estimator import estimate_restorability

                _mat_str = self.config.material_type.value if self.config.material_type is not None else "unknown"
                _rest_result = estimate_restorability(analysis_audio, analysis_sample_rate, material=_mat_str)
                _pmgg_restorability_score = float(_rest_result.restorability_score)
                logger.info(
                    "📊 RestorabilityEstimator: score=%.1f grade=%s predicted_MOS=%.2f–%.2f",
                    _rest_result.restorability_score,
                    _rest_result.grade,
                    _rest_result.predicted_mos_range[0],
                    _rest_result.predicted_mos_range[1],
                )
            except Exception as _re_exc:
                logger.debug("RestorabilityEstimator nicht verfügbar: %s", _re_exc)

        # §2.24 BatchSessionLearner — Batch-übergreifende Lernkohärenz
        _batch_session_id = None
        try:
            from backend.core.batch_session_learner import BatchSessionLearner as _BSL

            _source_paths = [kwargs.get("source_path")] if kwargs.get("source_path") else []
            _batch_session_id = _BSL().start_session(_source_paths)
            logger.info("📦 BatchSessionLearner: session_id=%s", _batch_session_id)
        except Exception as _bsl_exc:
            logger.debug("BatchSessionLearner nicht verfügbar: %s", _bsl_exc)

        # §2.13 Künstler-Signatur laden (wenn source_path via kwargs übergeben)
        _artist_id: str | None = None
        _artist_sig = None
        try:
            _source_path = kwargs.get("source_path")
            if _source_path is not None:
                from pathlib import Path as _Path

                from backend.core.artist_signature_store import get_signature_store as _get_sig_store

                _sig_store = _get_sig_store()
                _artist_id = _sig_store.detect_session([_Path(str(_source_path))])
                _artist_sig = _sig_store.load(_artist_id)
                if _artist_sig is not None and _artist_sig.confidence >= 0.3:
                    logger.info(
                        "🎙️ Künstler-Signatur geladen: artist_id=%s | confidence=%.2f | gender=%s",
                        _artist_id,
                        _artist_sig.confidence,
                        _artist_sig.voice_gender,
                    )
                else:
                    logger.debug("Künstler-Signatur: Kein vorheriger Prior (neuer Künstler)")
        except Exception as _sig_load_exc:
            logger.debug("ArtistSignatureStore Laden nicht verfügbar: %s", _sig_load_exc)

        # Perceptual Embedding des Originalaudios für GP-Kontext (§2.3 Spec)
        _original_embedding = None
        try:
            from backend.core.perceptual_embedder import embed_audio as _embed_audio

            _original_embedding = _embed_audio(original_audio_for_goals, sample_rate)
            logger.debug(
                "PerceptualEmbedder: 256-dim Embedding (norm=%.4f)",
                float(np.linalg.norm(_original_embedding.vector)),
            )
        except Exception as _emb_exc:
            logger.debug("PerceptualEmbedder nicht verfügbar: %s", _emb_exc)

        _classified_material: MaterialType | None = self.config.material_type
        _mc_result = None  # initialized here so later code can reference it regardless of _classified_material path
        if _classified_material is None:
            # §9.7.2 Parallele Eingangs-Analyse — MediumClassifier, EraClassifier und
            # GermanSchlagerClassifier sind voneinander unabhängig und laufen parallel
            import concurrent.futures as _cf

            def _run_mc(a: np.ndarray, sr: int) -> object | None:
                # §6.7 v9.10.97: MediumDetector ist das einzige autoritative System.
                # Kein Legacy-MediumClassifier-Fallback im produktiven Tonträgerpfad.
                try:
                    from forensics.medium_detector import get_medium_detector as _get_md

                    return _get_md().detect(a, sr, file_ext=_file_ext_for_scan)
                except Exception as _e:
                    logger.warning(
                        "MediumDetector nicht verfügbar; setze Material auf unknown (legacy fallback deaktiviert): %s",
                        _e,
                    )
                    return None

            def _run_era(a: np.ndarray, sr: int) -> object | None:
                try:
                    from backend.core.era_classifier import classify_era

                    return classify_era(a, sr)
                except Exception as _e:
                    logger.debug("EraClassifier nicht verfügbar: %s", _e)
                    return None

            def _run_genre(a: np.ndarray, sr: int) -> object | None:
                try:
                    from backend.core.genre_classifier import classify_genre

                    return classify_genre(a, sr)
                except Exception as _e:
                    logger.debug("GermanSchlagerClassifier nicht verfügbar: %s", _e)
                    return None

            # Gecachte Era/Genre/Medium-Ergebnisse aus Frontend-Vorab-Analyse verwenden,
            # sofern vorhanden — spart doppelte ML-Klassifikation (§9.7.2 Cache-Bypass)
            _era_cached = _cached_era_kwarg is not None
            _genre_cached = _cached_genre_kwarg is not None
            _medium_cached = _cached_medium_kwarg is not None

            _futures: dict[str, _cf.Future] = {}
            with _cf.ThreadPoolExecutor(max_workers=3) as _pool:
                if not _medium_cached:
                    _futures["mc"] = _pool.submit(_run_mc, analysis_audio, analysis_sample_rate)
                else:
                    logger.info(
                        "MediumDetector: verwende gecachtes Ergebnis (material=%s, conf=%.2f)",
                        getattr(
                            _cached_medium_kwarg,
                            "primary_material",
                            getattr(
                                _cached_medium_kwarg, "material_type", getattr(_cached_medium_kwarg, "material", "?")
                            ),
                        ),
                        float(getattr(_cached_medium_kwarg, "confidence", 0.0)),
                    )
                if not _era_cached:
                    _futures["era"] = _pool.submit(_run_era, analysis_audio, analysis_sample_rate)
                else:
                    logger.info(
                        "EraClassifier: verwende gecachtes Ergebnis (decade=%s, conf=%.2f)",
                        getattr(_cached_era_kwarg, "decade", "?"),
                        float(getattr(_cached_era_kwarg, "confidence", 0.0)),
                    )
                if not _genre_cached:
                    _futures["genre"] = _pool.submit(_run_genre, analysis_audio, analysis_sample_rate)
                else:
                    logger.info(
                        "GenreClassifier: verwende gecachtes Ergebnis (is_schlager=%s, conf=%.2f)",
                        getattr(_cached_genre_kwarg, "is_schlager", "?"),
                        float(getattr(_cached_genre_kwarg, "confidence", 0.0)),
                    )
                _mc_result = _cached_medium_kwarg if _medium_cached else _futures["mc"].result()
                _era_result_par = _cached_era_kwarg if _era_cached else _futures["era"].result()
                _schlager_result_par = _cached_genre_kwarg if _genre_cached else _futures["genre"].result()

            # MediumDetector/MediumClassifier-Ergebnis verarbeiten
            # Duck-type: cached result may be a full MediumDetectionResult (primary_material)
            # or a MediumClassificationResult (material) — handle both.
            if _mc_result is not None and _mc_result.confidence >= 0.30:
                _raw_mat = getattr(_mc_result, "primary_material", None) or getattr(_mc_result, "material", None)
                # Bug-16a-Fix: ClassificationResult.material kann ein String sein
                # (forensics/medium_detector.py baut ClassificationResult mit material=primary_string).
                # _classified_material.value würde AttributeError werfen → stille Ausnahme →
                # frischer classify_medium()-Aufruf → material=unknown → AudioSR auf MP3 → OOM.
                if isinstance(_raw_mat, str):
                    try:
                        _classified_material = MaterialType(_raw_mat.lower())
                    except ValueError:
                        _classified_material = MaterialType.UNKNOWN
                elif isinstance(_raw_mat, MaterialType):
                    _classified_material = _raw_mat
                else:
                    # Fallback: str-Repräsentation versuchen
                    try:
                        _classified_material = MaterialType(str(getattr(_raw_mat, "value", _raw_mat)).lower())
                    except ValueError:
                        _classified_material = MaterialType.UNKNOWN
                logger.info(
                    "🔍 MediumDetector: Material=%s Konfidenz=%.2f Quelle=%s",
                    _classified_material.value,
                    _mc_result.confidence,
                    getattr(_mc_result, "classifier_source", "cached"),
                )
            else:
                if _mc_result is not None:
                    logger.debug(
                        "MediumClassifier: Konfidenz zu niedrig (%.2f), nutze DefectScanner-Prior",
                        _mc_result.confidence,
                    )

            # EraClassifier-Ergebnis übernehmen
            _era_result = _era_result_par
            if _era_result is not None:
                logger.info(
                    "🎙️ EraClassifier: decade=%d material_prior=%s confidence=%.2f",
                    _era_result.decade,
                    _era_result.material_prior,
                    _era_result.confidence,
                )

            # §Medium-Floor-Constraint: Ära-Zuweisung darf nicht vor der physikalischen
            # Erfindung des erkannten Mediums liegen (z. B. Magnetband ≠ 1890er).
            # Anwendung nur wenn MediumClassifier-Konfidenz ≥ 0.35 (bereits geprüft).
            if _era_result is not None and _classified_material is not None:
                try:
                    from backend.core.era_classifier import constrain_era_to_medium as _era_constrain

                    _era_result = _era_constrain(_era_result, str(_classified_material.value))
                except Exception as _floor_exc:
                    logger.debug("Medium-Floor-Constraint fehlgeschlagen: %s", _floor_exc)

            # §Spec Material-Konfliktregel: Priorität hat der Klassifikator mit höherer
            # Konfidenz. Bei Gleichstand (Δ ≤ 0.10) gewinnt der konservativere Materialtyp.
            # Anwendung nur wenn BEIDE Klassifikatoren ein Material gemeldet haben UND
            # diese voneinander abweichen (echter Konflikt).
            _mc_conf_val = float(getattr(_mc_result, "confidence", 0.0)) if _mc_result is not None else 0.0
            _era_prior_str = str(getattr(_era_result, "material_prior", "") or "") if _era_result is not None else ""
            _era_conf_val = float(getattr(_era_result, "confidence", 0.0)) if _era_result is not None else 0.0
            _era_conflict_mat: MaterialType | None = None
            if _era_prior_str and _era_prior_str not in ("unknown", "digital", ""):
                try:
                    _era_conflict_mat = MaterialType(_era_prior_str.lower())
                except ValueError as _exc:
                    logger.debug("Era-prior material parse failed ('%s'): %s", _era_prior_str, _exc)
            if (
                _classified_material is not None
                and _era_conflict_mat is not None
                and _classified_material != _era_conflict_mat
            ):
                # Digital-lock: keep reliable digital medium classifications stable.
                # Era material_prior is a population prior, while MediumClassifier for
                # codec media is based on direct signal evidence (codec signatures).
                # Without this lock, mp3/aac sources can be incorrectly flipped to
                # analog priors (e.g. reel_tape), re-enabling non-applicable phases.
                _digital_lock_active = (
                    UnifiedRestorerV3._is_lossy_codec_material(_classified_material) and _mc_conf_val >= 0.35
                )
                if _digital_lock_active:
                    logger.info(
                        "Material-Konfliktregel (§Spec): Digital-Lock aktiv"
                        " (MC=%s conf=%.2f, Era-Prior=%s conf=%.2f) — MC bleibt",
                        _classified_material.value,
                        _mc_conf_val,
                        _era_conflict_mat.value,
                        _era_conf_val,
                    )
                    _era_conflict_mat = None

            if (
                _classified_material is not None
                and _era_conflict_mat is not None
                and _classified_material != _era_conflict_mat
            ):
                _conf_delta = _era_conf_val - _mc_conf_val
                # §2.47 / §2.54: Physical multi-generation evidence has higher
                # epistemic quality than a statistical era prior (Pohlmann 2010,
                # §2.46a).  When MediumDetector measured a multi-generation chain
                # (is_multi_generation=True), its fingerprint-based classification
                # is anchored in measurable signal physics; the Era-classifier
                # holds only a population-level prior ("1970s recordings were often
                # on reel tape").  Therefore raise the Era-classifier domination
                # threshold from conf_delta > 0.10 to conf_delta > 0.30, and
                # suppress the conservative-material tiebreaker (which would
                # otherwise silently override vinyl→reel_tape at equal confidence).
                _mc_is_multi_gen = (
                    bool(getattr(_mc_result, "is_multi_generation", False)) if _mc_result is not None else False
                )
                _era_domination_threshold = (0.30 if _mc_is_multi_gen else 0.10) + 1e-9
                if _conf_delta > _era_domination_threshold:
                    # EraClassifier deutlich konfidenter → Era-Material-Prior gewinnt
                    logger.info(
                        "Material-Konfliktregel (§Spec): EraClassifier dominiert MC"
                        " (era_conf=%.2f > mc_conf=%.2f + %.2f, multi_gen=%s)"
                        " → Material %s → %s",
                        _era_conf_val,
                        _mc_conf_val,
                        _era_domination_threshold - 1e-9,
                        _mc_is_multi_gen,
                        _classified_material.value,
                        _era_conflict_mat.value,
                    )
                    _classified_material = _era_conflict_mat
                elif abs(_conf_delta) <= 0.10 and not _mc_is_multi_gen:
                    # Gleichstand ohne gesicherte Mehrgenerationen-Kette:
                    # konservativerer (restaurierungsschonenderer) Typ gewinnt.
                    # Bei Multi-Gen-Kette behält der physisch gemessene Typ Vorrang.
                    _conservative_mat = _pick_more_conservative_material(_classified_material, _era_conflict_mat)
                    logger.info(
                        "Material-Konfliktregel (§Spec): Gleichstand"
                        " (era_conf=%.2f ≈ mc_conf=%.2f)"
                        " → konservativer Typ=%s (MC=%s Era=%s)",
                        _era_conf_val,
                        _mc_conf_val,
                        _conservative_mat.value,
                        _classified_material.value,
                        _era_conflict_mat.value,
                    )
                    _classified_material = _conservative_mat
                else:
                    # MC hat ausreichend höhere Konfidenz ODER Multi-Gen-Kette schützt
                    # den physisch gemessenen Typ → bleibt wie bisher
                    logger.debug(
                        "Material-Konfliktregel (§Spec): MC behält Material=%s"
                        " (delta=%.3f, multi_gen=%s, threshold=%.2f)",
                        _classified_material.value,
                        _conf_delta,
                        _mc_is_multi_gen,
                        _era_domination_threshold - 1e-9,
                    )

            # §9.7.7 Fallback: wenn MediumClassifier-Konfidenz zu niedrig, nutze
            # EraClassifier material_prior als Material-Prior bevor DefectScanner
            # _auto_detect_material() aufgerufen wird (verhindert tape→vinyl Mismatch).
            if _classified_material is None and _era_result is not None:
                _era_mp = str(getattr(_era_result, "material_prior", "") or "")
                if _era_mp and _era_mp not in ("unknown", "digital", ""):
                    try:
                        from backend.core.defect_scanner import MaterialType as _MatType

                        _classified_material = _MatType(_era_mp)
                        logger.info(
                            "EraClassifier material_prior fallback: %s (decade=%d era_conf=%.2f)",
                            _era_mp,
                            _era_result.decade,
                            _era_result.confidence,
                        )
                    except Exception as _mt_exc:
                        logger.debug(
                            "EraClassifier MaterialType-Konvertierung fehlgeschlagen: %s — Auto-Detect bleibt",
                            _mt_exc,
                        )

            # §Dach GlobalPlan-Prior: Chunk-Klassifikation mit Ganzstück-Ergebnis überschreiben.
            # UV3 läuft auf kurzen Chunks — EraClassifier/MediumClassifier auf 10s-Segmenten
            # sind unzuverlässig (MP3-Bandbreite → fälschlich 1920/shellac).
            # Wenn der AurikDenker am vollständigen Audio einen GlobalPlan berechnet hat,
            # gewinnt dessen decade/material/genre — Denker ist der autoritative Orchestrator.
            # DSP-Konfidenz (0.40) und ML-Konfidenz (0.85) sind auf verschiedenen Skalen und
            # NICHT direkt vergleichbar. Denker-GlobalPlan basiert auf dem Gesamtstück →
            # immer bevorzugen, außer decade fehlt ganz.
            _gp_portrait = getattr(getattr(self, "_active_global_plan", None), "portrait", None)
            if _gp_portrait is not None:
                _gp_decade = getattr(_gp_portrait, "decade", None)
                _gp_era_conf = float(getattr(_gp_portrait, "era_confidence", 0.0))
                _gp_material = getattr(_gp_portrait, "material", None)
                _gp_genre = getattr(_gp_portrait, "genre", None)

                # Era/Decade: GlobalPlan überschreibt nur wenn seine Konfidenz HÖHER
                # ist als die des UV3-Chunk-EraClassifiers.  Verhindert Rückfall auf
                # schlechtere DSP-Fingerprints (z.B. MP3-BW → fälschlich 1930er).
                chunk_era_conf = float(getattr(_era_result, "confidence", 0.0)) if _era_result is not None else 0.0
                if _gp_decade is not None and _gp_era_conf >= 0.35 and _gp_era_conf > chunk_era_conf:
                    try:
                        from backend.core.era_classifier import EraResult as _EraResult

                        _old_decade = getattr(_era_result, "decade", "?")
                        _existing_noise = getattr(_era_result, "noise_profile", None)
                        _era_result = _EraResult(
                            decade=int(_gp_decade),
                            era_label=f"{_gp_decade}er",
                            confidence=_gp_era_conf,
                            material_prior=_gp_material or getattr(_era_result, "material_prior", "unknown"),
                            noise_profile=(
                                _existing_noise
                                if _existing_noise is not None
                                else __import__("numpy").zeros(24, dtype="float32")
                            ),
                            tier_used=0,
                            hf_rolloff_hz=getattr(_era_result, "hf_rolloff_hz", 20000.0),
                        )
                        logger.info(
                            "§Dach GlobalPlan-Prior: EraClassifier decade=%s→%d material=%s (Konfidenz=%.2f)",
                            _old_decade,
                            _gp_decade,
                            _gp_material,
                            _gp_era_conf,
                        )
                    except Exception as _gp_era_exc:
                        logger.debug("GlobalPlan-Era-Override fehlgeschlagen: %s", _gp_era_exc)

                # Material überschreiben wenn GlobalPlan-Material bekannt und Chunk-MediumClassifier unsicher
                if _gp_material and _gp_material not in ("unknown", "digital"):
                    _chunk_mc_conf = float(getattr(_mc_result, "confidence", 0.0)) if _mc_result is not None else 0.0
                    if _chunk_mc_conf < 0.55:
                        try:
                            from backend.core.defect_scanner import MaterialType as _MatType

                            _gp_mat_type = _MatType(_gp_material)
                            _classified_material = _gp_mat_type
                            logger.info(
                                "§Dach GlobalPlan-Prior: MediumClassifier material→%s (Chunk-Konfidenz=%.2f)",
                                _gp_material,
                                _chunk_mc_conf,
                            )
                        except Exception as _gp_mat_exc:
                            logger.debug(
                                "GlobalPlan MaterialType-Override fehlgeschlagen: %s — Chunk-Ergebnis behalten",
                                _gp_mat_exc,
                            )

            # GermanSchlagerClassifier-Ergebnis übernehmen
            _schlager_result = _schlager_result_par
            if _schlager_result is not None:
                if _schlager_result.is_schlager:
                    logger.info(
                        "🎵 Schlager-Kandidat: confidence=%.2f genre=%s bpm=%.0f (finale Genre-Guards ausstehend)",
                        _schlager_result.confidence,
                        _schlager_result.genre_label,
                        _schlager_result.bpm,
                    )
                else:
                    logger.debug(
                        "GermanSchlagerClassifier: kein Schlager (confidence=%.2f genre=%s)",
                        _schlager_result.confidence,
                        _schlager_result.genre_label,
                    )

            # §Dach GlobalPlan-Genre-Prior: Chunk-Schlager-Ergebnis mit GlobalPlan überschreiben
            if _gp_portrait is not None:
                _gp_genre = getattr(_gp_portrait, "genre", None)
                _gp_genre_conf = float(getattr(_gp_portrait, "genre_confidence", 0.0))
                _gp_subgenre = getattr(_gp_portrait, "subgenre", "unknown")
                _chunk_genre_conf = (
                    float(getattr(_schlager_result, "confidence", 0.0)) if _schlager_result is not None else 0.0
                )
                if _gp_genre == "schlager" and _gp_genre_conf >= 0.35 and _gp_genre_conf >= _chunk_genre_conf:
                    try:
                        from backend.core.genre_classifier import GenreResult as _GenreResult

                        _schlager_result = _GenreResult(
                            is_schlager=True,
                            confidence=_gp_genre_conf,
                            genre_label="Deutscher Schlager",
                            subgenre=_gp_subgenre or "unknown",
                            bpm=float(getattr(_gp_portrait, "bpm", 0.0)),
                        )
                        logger.info(
                            "§Dach GlobalPlan-Prior: Genre→Schlager subgenre=%s (conf=%.2f)",
                            _gp_subgenre,
                            _gp_genre_conf,
                        )
                    except Exception as _gp_genre_exc:
                        logger.debug("GlobalPlan Genre→Schlager-Override fehlgeschlagen: %s", _gp_genre_exc)
        else:
            # Material bereits im Config — Ära und Genre trotzdem ermitteln
            if _cached_era_kwarg is not None:
                _era_result = _cached_era_kwarg
                logger.info(
                    "EraClassifier: verwende gecachtes Ergebnis (decade=%s, conf=%.2f)",
                    getattr(_era_result, "decade", "?"),
                    float(getattr(_era_result, "confidence", 0.0)),
                )
            else:
                _era_result = None
                try:
                    from backend.core.era_classifier import classify_era

                    _era_result = classify_era(analysis_audio, analysis_sample_rate)
                    logger.info(
                        "🎙️ EraClassifier: decade=%d material_prior=%s confidence=%.2f",
                        _era_result.decade,
                        _era_result.material_prior,
                        _era_result.confidence,
                    )
                except Exception as _era_exc:
                    logger.debug("EraClassifier nicht verfügbar: %s", _era_exc)

            # §Dach GlobalPlan-Prior auch im else-Zweig anwenden
            _gp_portrait_else = getattr(getattr(self, "_active_global_plan", None), "portrait", None)
            if _gp_portrait_else is not None:
                _gp_decade_e = getattr(_gp_portrait_else, "decade", None)
                _gp_era_conf_e = float(getattr(_gp_portrait_else, "era_confidence", 0.0))
                _chunk_era_conf_e = float(getattr(_era_result, "confidence", 0.0)) if _era_result is not None else 0.0
                if _gp_decade_e is not None and _gp_era_conf_e >= 0.35 and _gp_era_conf_e >= _chunk_era_conf_e:
                    try:
                        from backend.core.era_classifier import EraResult as _EraResult2

                        _gp_mat_e = getattr(_gp_portrait_else, "material", None)
                        _era_result = _EraResult2(
                            decade=int(_gp_decade_e),
                            era_label=f"{_gp_decade_e}er",
                            confidence=_gp_era_conf_e,
                            material_prior=_gp_mat_e or getattr(_era_result, "material_prior", "unknown"),
                            noise_profile=getattr(_era_result, "noise_profile", None)
                            or __import__("numpy").zeros(24, dtype="float32"),
                            tier_used=0,
                            hf_rolloff_hz=getattr(_era_result, "hf_rolloff_hz", 20000.0),
                        )
                        logger.info(
                            "§Dach GlobalPlan-Prior (else): decade→%d material→%s (conf=%.2f)",
                            _gp_decade_e,
                            _gp_mat_e,
                            _gp_era_conf_e,
                        )
                    except Exception as _gp_else_exc:
                        logger.debug("GlobalPlan-Prior (else-Pfad) fehlgeschlagen: %s", _gp_else_exc)

            if _cached_genre_kwarg is not None:
                _schlager_result = _cached_genre_kwarg
                logger.info(
                    "GenreClassifier: verwende gecachtes Ergebnis (is_schlager=%s, conf=%.2f)",
                    getattr(_schlager_result, "is_schlager", "?"),
                    float(getattr(_schlager_result, "confidence", 0.0)),
                )
            else:
                _schlager_result = None
                try:
                    from backend.core.genre_classifier import classify_genre

                    _schlager_result = classify_genre(analysis_audio, analysis_sample_rate)
                    if _schlager_result.is_schlager:
                        logger.info(
                            "🎵 Schlager-Kandidat: confidence=%.2f genre=%s bpm=%.0f (finale Genre-Guards ausstehend)",
                            _schlager_result.confidence,
                            _schlager_result.genre_label,
                            _schlager_result.bpm,
                        )
                except Exception as _sc_exc:
                    logger.debug("GermanSchlagerClassifier nicht verfügbar: %s", _sc_exc)

            # §Dach GlobalPlan-Genre-Prior: Chunk-Ergebnis mit GlobalPlan-Genre überschreiben
            if _gp_portrait_else is not None:
                _gp_genre_e = getattr(_gp_portrait_else, "genre", None)
                _gp_genre_conf_e = float(getattr(_gp_portrait_else, "genre_confidence", 0.0))
                _gp_subgenre_e = getattr(_gp_portrait_else, "subgenre", "unknown")
                _chunk_genre_conf_e = (
                    float(getattr(_schlager_result, "confidence", 0.0)) if _schlager_result is not None else 0.0
                )
                if _gp_genre_e == "schlager" and _gp_genre_conf_e >= 0.35 and _gp_genre_conf_e >= _chunk_genre_conf_e:
                    try:
                        from backend.core.genre_classifier import GenreResult as _GenreResult

                        _schlager_result = _GenreResult(
                            is_schlager=True,
                            confidence=_gp_genre_conf_e,
                            genre_label="Deutscher Schlager",
                            subgenre=_gp_subgenre_e or "unknown",
                            bpm=float(getattr(_gp_portrait_else, "bpm", 0.0)),
                        )
                        logger.info(
                            "§Dach GlobalPlan-Prior (else): Genre→Schlager subgenre=%s (conf=%.2f)",
                            _gp_subgenre_e,
                            _gp_genre_conf_e,
                        )
                    except Exception as _gp_genre_else_exc:
                        logger.debug("GlobalPlan Genre-Override (else-Pfad) fehlgeschlagen: %s", _gp_genre_else_exc)

        if _schlager_result is not None and bool(getattr(_schlager_result, "is_schlager", False)):
            _era_decade_guard = int(getattr(_era_result, "decade", 0) or 0)
            _genre_conf_guard = float(getattr(_schlager_result, "confidence", 0.0) or 0.0)
            _is_short_vintage_guard = (_era_decade_guard > 0 and _era_decade_guard <= 1940) and (
                _audio_duration_s < 10.0
            )
            if _is_short_vintage_guard and _genre_conf_guard < 0.60:
                _schlager_result.is_schlager = False
                _schlager_result.genre_label = "Unbekannt"
                _schlager_result.subgenre = "unknown"
                _schlager_result.open_set_unknown = True
                _schlager_result.confidence = 0.0
                logger.info(
                    "Genre-Guard: Vintage-Kurzsignal neutralisiert (era=%d, duration=%.1fs, conf=%.2f) -> Unbekannt",
                    _era_decade_guard,
                    _audio_duration_s,
                    _genre_conf_guard,
                )

        # §2.19.3 SCHLAGER_RESTORATION_PROFILE anwenden (GP-Material-Key + Phase-Params)
        _genre_profile: dict = {}
        _gp_material_key: str = (
            _defect_material.value
            if (_defect_material := getattr(_schlager_result, "_material", None)) is not None
            else (_classified_material.value if _classified_material is not None else "unknown")
        )
        if _schlager_result is not None and _schlager_result.is_schlager:
            try:
                from backend.core.genre_classifier import get_restoration_profile

                _genre_profile = get_restoration_profile(_schlager_result.subgenre)
                _gp_material_key = str(_genre_profile.get("gp_memory_key", _gp_material_key))
                logger.info(
                    "🪧 SCHLAGER_PROFILE: gp_key=%s brillanz_target=%.2f waerme_target=%.2f groove_dtw_max_ms=%.1f",
                    _gp_material_key,
                    _genre_profile.get("brillanz_target", 0.82),
                    _genre_profile.get("waerme_target", 0.88),
                    _genre_profile.get("groove_dtw_max_ms", 5.0),
                )
            except Exception as _gp_sc_exc:
                logger.debug("SCHLAGER_RESTORATION_PROFILE nicht geladen: %s", _gp_sc_exc)
        elif (
            _schlager_result is not None
            and _schlager_result.genre_label not in ("Unbekannt", "unknown", "")
            and not getattr(_schlager_result, "open_set_unknown", False)
        ):
            # Non-Schlager genre detected (Rock, Jazz, Klassik, Oper) — load its profile.
            # open_set_unknown=True means no genre had sufficient confidence margin → skip profile.
            try:
                from backend.core.genre_classifier import get_restoration_profile

                _genre_profile = get_restoration_profile(_schlager_result.genre_label)
                if _genre_profile:
                    _gp_material_key = str(_genre_profile.get("gp_memory_key", _gp_material_key))
                    logger.info(
                        "🪧 GENRE_PROFILE(%s): gp_key=%s groove_dtw_max_ms=%.1f",
                        _schlager_result.genre_label,
                        _gp_material_key,
                        _genre_profile.get("groove_dtw_max_ms", 8.0),
                    )
            except Exception as _gp_genre_exc:
                logger.debug("GENRE_RESTORATION_PROFILE nicht geladen: %s", _gp_genre_exc)
        elif not _genre_profile:
            # §2.20 PANNs-basierte Fallback-Aktivierung (v9.10.102): wenn kein Genre via
            # Klassifikator erkannt (open_set_unknown / Unbekannt / None), PANNs-Tags direkt prüfen.
            # Aktivierungsregeln (Priorität 2–5, höchste actuelle Priorität gewinnt):
            #   OPER:    PANNs "Opera" ≥ 0.45 oder "Singing" ≥ 0.50 + formant_pearson ≥ 0.90
            #   KLASSIK: PANNs "Orchestra" ≥ 0.45 oder "Classical music" ≥ 0.40
            #   JAZZ:    PANNs "Jazz" ≥ 0.40 oder "Blues" ≥ 0.40
            #   ROCK:    PANNs "Rock music" ≥ 0.40 oder "Electric guitar" + "Drum" beide ≥ 0.35
            _pt = kwargs.get("panns_tags") or {}
            if not isinstance(_pt, dict):
                _pt = {}
            _panns_fallback_profile_key: str | None = None
            _panns_opera = max(_pt.get("Opera", 0.0), _pt.get("opera", 0.0))
            _panns_singing = max(_pt.get("Singing", 0.0), _pt.get("Singing voice", 0.0))
            self._panns_singing = float(_panns_singing)  # §0p: vocal_presence — updated per-restore()
            _panns_orchestra = max(_pt.get("Orchestra", 0.0), _pt.get("orchestra", 0.0))
            _panns_classical = max(_pt.get("Classical music", 0.0), _pt.get("classical music", 0.0))
            _panns_jazz = max(_pt.get("Jazz", 0.0), _pt.get("jazz", 0.0))
            _panns_blues = max(_pt.get("Blues", 0.0), _pt.get("blues", 0.0))
            _panns_rock = max(_pt.get("Rock music", 0.0), _pt.get("rock", 0.0))
            _panns_guitar = max(_pt.get("Electric guitar", 0.0), _pt.get("Guitar", 0.0))
            _panns_drum = max(_pt.get("Drum", 0.0), _pt.get("Drums", 0.0), _pt.get("Percussion", 0.0))
            # §2.20 OPER "Singing ≥ 0.50" path requires formant_pearson ≥ 0.90 guard
            # (Spec 03 v9.10.102): formant stability Pearson proxy via FormantTracker
            # on a 2s segment — high r (opera) vs low r (speech/choir jumping formants).
            _formant_pearson: float = 0.0
            if _panns_singing >= 0.50 and _panns_opera < 0.45:
                try:
                    from scipy.stats import pearsonr as _pearsonr

                    from plugins.formant_tracker import get_formant_tracker as _get_ft

                    _ft = _get_ft()
                    _ft_sr = sample_rate
                    _ft_audio = audio
                    if _ft_audio.ndim > 1:
                        _ft_audio = _ft_audio[0]
                    # Use 2s center segment for speed
                    _ft_len = min(len(_ft_audio), int(2.0 * _ft_sr))
                    _ft_start = max(0, (len(_ft_audio) - _ft_len) // 2)
                    _ft_seg = _ft_audio[_ft_start : _ft_start + _ft_len]
                    _ft_result = _ft.track(_ft_seg.astype(np.float32), _ft_sr)
                    # Extract F1 trajectory from confident voiced frames
                    _f1_vals = [
                        fr.frequencies[0]
                        for fr in _ft_result.formant_tracks
                        if len(fr.frequencies) > 0
                        and math.isfinite(fr.frequencies[0])
                        and fr.frequencies[0] > 200.0
                        and len(fr.confidences) > 0
                        and fr.confidences[0] > 0.30
                    ]
                    if len(_f1_vals) >= 4:
                        _f1a = np.array(_f1_vals[:-1])
                        _f1b = np.array(_f1_vals[1:])
                        _fp_r, _ = _pearsonr(_f1a, _f1b)
                        _formant_pearson = float(_fp_r) if math.isfinite(_fp_r) else 0.0
                    logger.debug(
                        "§2.20 formant_pearson probe: n_frames=%d r=%.3f",
                        len(_f1_vals),
                        _formant_pearson,
                    )
                except Exception as _fp_exc:
                    logger.debug("formant_pearson computation skipped: %s", _fp_exc)
            if _panns_opera >= 0.45 or (_panns_singing >= 0.50 and _formant_pearson >= 0.90):
                _panns_fallback_profile_key = "oper"
            elif _panns_orchestra >= 0.45 or _panns_classical >= 0.40:
                _panns_fallback_profile_key = "klassik"
            elif _panns_jazz >= 0.40 or _panns_blues >= 0.40:
                _panns_fallback_profile_key = "jazz"
            elif _panns_rock >= 0.40 or (_panns_guitar >= 0.35 and _panns_drum >= 0.35):
                _panns_fallback_profile_key = "rock"
            if _panns_fallback_profile_key:
                try:
                    from backend.core.genre_classifier import get_restoration_profile as _grf_fb

                    _genre_profile = _grf_fb(_panns_fallback_profile_key) or {}
                    if _genre_profile:
                        _gp_material_key = str(_genre_profile.get("gp_memory_key", _gp_material_key))
                        logger.info(
                            "🪧 GENRE_PROFILE_PANNS_FALLBACK(%s): gp_key=%s opera=%.2f orch=%.2f jazz=%.2f rock=%.2f",
                            _panns_fallback_profile_key,
                            _gp_material_key,
                            _panns_opera,
                            _panns_orchestra,
                            _panns_jazz,
                            _panns_rock,
                        )
                except Exception as _gp_fb_exc:
                    logger.debug("PANNs-Fallback Genre-Profil nicht geladen: %s", _gp_fb_exc)

        # §2.14+ Kontextfluss: Ära, Genre, BPM und Genre-Profil auf self speichern,
        # damit _profiled_phase_call sie zentral in ALLE Phase-kwargs injizieren kann.
        self._restoration_context = {
            "decade": getattr(_era_result, "decade", None) if _era_result is not None else None,
            "era_confidence": getattr(_era_result, "confidence", 0.0) if _era_result is not None else 0.0,
            "primary_material": (
                getattr(_mc_result, "primary_material", None) or getattr(_mc_result, "material", None) or "unknown"
            ),
            "genre_label": (
                getattr(_schlager_result, "genre_label", "Unbekannt") if _schlager_result is not None else "Unbekannt"
            ),
            "is_schlager": getattr(_schlager_result, "is_schlager", False) if _schlager_result is not None else False,
            "bpm": getattr(_schlager_result, "bpm", 0.0) if _schlager_result is not None else 0.0,
            "subgenre": getattr(_schlager_result, "subgenre", "unknown") if _schlager_result is not None else "unknown",
            # §0: Spatial/Stereo-Phasen müssen im Restoration-Mode konservativ arbeiten
            # (kein künstlicher Hall, keine Gesang-Distanzierung) — §0 Primum non nocere.
            "is_studio_mode": _is_studio_26,
            # §HF-Tracking: Kumulativer HF-Gain-Zähler — initialisiert auf 0.0 pro Run.
            # phase_39-Guard liest diesen Wert; war bisher dead code (UV3 hat nie gesetzt).
            "hf_cumulative_gain_db": 0.0,
        }
        if _genre_profile:
            self._restoration_context.update(
                {
                    "brillanz_target": _genre_profile.get("brillanz_target"),
                    "waerme_target": _genre_profile.get("waerme_target"),
                    "groove_dtw_max_ms": _genre_profile.get("groove_dtw_max_ms"),
                    "soft_saturation_preserve": _genre_profile.get("soft_saturation_preserve", False),
                    "deessing_strength_cap": _genre_profile.get("deessing_strength_cap"),
                    "compression_ratio_cap": _genre_profile.get("compression_ratio_cap"),
                    "transient_preservation_strength": _genre_profile.get("transient_preservation_strength"),
                }
            )
        # §6.2a Transfer-Chain-Injection: Ketten-Liste für phase-lokale Skip-Guards.
        # Phasen wie phase_29 überspringen bei digitalem primary_material. Wenn aber
        # die Kette analoge Stufen enthält (z.B. vinyl→tape→mp3_low), muss die Phase
        # trotzdem laufen. transfer_chain wird via _restoration_context in ALLE Phasen
        # injiziert (Fallback: _profiled_phase_call) und separat in phase_kwargs
        # (Hauptpfad: PMGG wrap_phase).
        _active_chain_list: list[str] = []
        if isinstance(getattr(self, "_active_chain_info", None), dict):
            _raw_chain = self._active_chain_info.get("chain", [])
            _active_chain_list = [str(c).lower() for c in _raw_chain if c] if isinstance(_raw_chain, list) else []
        if _active_chain_list:
            self._restoration_context["transfer_chain"] = _active_chain_list

        # §0p [RELEASE_MUST] VocalFocusAnalyzer — nach _restoration_context-Init,
        # vor GoalApplicabilityFilter. Aktivierung: panns_singing ≥ 0.25.
        # Injiziert vfa_result + energy_bias_db in _restoration_context.
        _vfa_panns = float(getattr(self, "_panns_singing", 0.0))
        try:
            from backend.core.vocal_focus_analyzer import get_vocal_focus_analyzer as _get_vfa

            _vfa = _get_vfa()
            _vfa_result = _vfa.analyze(audio, sample_rate, panns_singing=_vfa_panns)
            self._restoration_context["vfa_result"] = _vfa_result.to_dict()
            # Energy-Bias direkt verfügbar (§0j §0p NR-Algorithmen)
            self._restoration_context["vocal_energy_bias_db"] = _vfa_result.energy_bias_db
            # Frisson-Zonen direkt verfügbar (§Frisson MDEM-Schutz)
            self._restoration_context["frisson_zones"] = _vfa_result.frisson_zones
            # Passaggio-Zonen für Phase-Stärke-Cap
            self._restoration_context["passaggio_zones"] = _vfa_result.passaggio_zones
            # Vibrato-Zonen für §0p Strength-Cap (4–7 Hz F0-Modulation)
            self._restoration_context["vibrato_zones"] = _vfa_result.vibrato_zones
            logger.info(
                "§0p VocalFocusAnalyzer: singing=%.2f register=%s bias=%.1fdB frisson=%d passaggio=%d vqi_gate=%s",
                _vfa_panns,
                _vfa_result.dominant_register,
                _vfa_result.energy_bias_db,
                len(_vfa_result.frisson_zones),
                len(_vfa_result.passaggio_zones),
                _vfa_result.vqi_gate_active,
            )
        except Exception as _vfa_exc:
            # Non-blocking: VFA-Fehler blockiert nie die Pipeline
            logger.debug("§0p VocalFocusAnalyzer non-blocking: %s", _vfa_exc)
            self._restoration_context.setdefault("vfa_result", {})
            self._restoration_context.setdefault("vocal_energy_bias_db", -6.0)
            self._restoration_context.setdefault("frisson_zones", [])
            self._restoration_context.setdefault("passaggio_zones", [])
            self._restoration_context.setdefault("vibrato_zones", [])

        logger.info(
            "📋 RestorationContext: decade=%s genre=%s bpm=%.0f subgenre=%s transfer_chain=%s",
            self._restoration_context.get("decade"),
            self._restoration_context.get("genre_label"),
            self._restoration_context.get("bpm", 0.0),
            self._restoration_context.get("subgenre"),
            self._restoration_context.get("transfer_chain", []),
        )

        _cb(7, "Material und Ära klassifiziert …")

        # §2.32 GoalApplicabilityFilter — Filterung physikalisch nicht-messbarer Musikziele
        # QualityAnalyzer: Eingangsqualität messen (Vorher-Baseline) (§9.5 Quality-Tracking)
        _quality_before: object | None = None
        try:
            from backend.core.quality_prediction import QualityAnalyzer as _QualityAnalyzer

            _quality_before = _QualityAnalyzer().analyze_quality(audio, sample_rate)
            logger.debug(
                "📊 QualityAnalyzer (Vorher): score=%.1f SNR=%.1f dB warmth=%.3f naturalness=%.3f",
                _quality_before.overall_score,
                _quality_before.snr_db,
                _quality_before.warmth,
                _quality_before.naturalness,
            )
        except Exception as _qa_pre_exc:
            logger.debug("QualityAnalyzer (Vorher) nicht verfügbar: %s", _qa_pre_exc)

            # §LAG_PROBE_0A: VOR DC-Offset-Removal (Eingang zu restore(), nach Resampling)
            # GCC-PHAT via file_import helper — O(n log n), kein O(n²) np.correlate
            try:
                if audio.ndim == 2:
                    from backend.file_import import _estimate_interchannel_lag_samples as _gcc_lag

                    _lp0a_lag = _gcc_lag(audio, sample_rate)
                    logger.info(
                        "LAG_PROBE 0A/before_dc_removal: lag=%d samples (%.1f ms)",
                        _lp0a_lag,
                        _lp0a_lag / sample_rate * 1000,
                    )
            except Exception as _lp0a_exc:
                logger.debug("LAG_PROBE_0A fehlgeschlagen: %s", _lp0a_exc)

        # §DCOffsetPreRemoval — IIR-Hochpass (Spec §2.2): PFLICHT vor jeder FFT/HPSS-Analyse.
        # Entfernt DC-Versatz und sehr niedrige Frequenzen, die HPSS/FFT-Artefakte erzeugen.
        # [RELEASE_MUST] Lücke-H-Fix v9.10.100: reel_tape benötigt aggressiveren,
        # zero-phase Filter wegen dynamischem DC-Drift durch Geschwindigkeitsschwankungen.
        # Standard: lfilter([1,-1],[1,-0.9999]) — fc ≈ 0.76 Hz @ 48 kHz (kausal)
        # Tape:     filtfilt([1,-1],[1,-0.9995]) — fc ≈ 3.8 Hz @ 48 kHz (zero-phase,
        #           kein Phasenversatz, sicherer für Onset-Zeitstempel in WowFlutter)
        # VERBOTEN bei Tape: globale Mittelwert-Subtraktion (np.mean) — erfasst keinen Drift.
        try:
            from scipy.signal import filtfilt as _filtfilt

            _is_reel_tape = _classified_material is not None and (
                _classified_material == MaterialType.REEL_TAPE
                or getattr(_classified_material, "value", "") == "reel_tape"
            )
            if _is_reel_tape:
                # Tape: aggressiverer HP (fc ≈ 3.8 Hz), zero-phase (filtfilt)
                _dc_b = np.array([1.0, -1.0], dtype=np.float64)
                _dc_a = np.array([1.0, -0.9995], dtype=np.float64)
                if audio.ndim == 1:
                    audio = _filtfilt(_dc_b, _dc_a, audio.astype(np.float64)).astype(np.float32)
                else:
                    audio = np.stack(
                        [
                            _filtfilt(_dc_b, _dc_a, audio[c].astype(np.float64)).astype(np.float32)
                            for c in range(audio.shape[0])
                        ],
                        axis=0,
                    )
                logger.debug(
                    "§DCOffsetPreRemoval [reel_tape]: filtfilt fc≈3.8 Hz (|mean|=%.2e)",
                    float(np.abs(np.mean(audio))),
                )
            else:
                # Alle anderen Materialien: fc ≈ 0.76 Hz, zero-phase (filtfilt)
                # §2.46: DC-Offset-Entfernung muss zero-phase sein, um Zeitversatz zwischen
                # L/R-Kanälen zu vermeiden (lfilter erzeugt ~1 Sample Gruppen-Delay).
                _dc_b = np.array([1.0, -1.0], dtype=np.float64)
                _dc_a = np.array([1.0, -0.9999], dtype=np.float64)
                if audio.ndim == 1:
                    audio = _filtfilt(_dc_b, _dc_a, audio.astype(np.float64)).astype(np.float32)
                else:
                    audio = np.stack(
                        [
                            _filtfilt(_dc_b, _dc_a, audio[c].astype(np.float64)).astype(np.float32)
                            for c in range(audio.shape[0])
                        ],
                        axis=0,
                    )
                logger.debug(
                    "§DCOffsetPreRemoval: DC-Offset entfernt zero-phase (|mean|=%.2e)", float(np.abs(np.mean(audio)))
                )
            audio = np.clip(audio, -1.0, 1.0)
        except Exception as _dc_exc:
            logger.debug("DCOffsetPreRemoval Fehler (scipy nicht verfügbar): %s", _dc_exc)

        # §LAG_PROBE_0B: NACH DC-Offset-Removal, VOR TDP
        # GCC-PHAT via file_import helper — O(n log n)
        try:
            if audio.ndim == 2:
                from backend.file_import import _estimate_interchannel_lag_samples as _gcc_lag

                _lp0b_lag = _gcc_lag(audio, sample_rate)
                logger.info(
                    "LAG_PROBE 0B/after_dc_removal_before_tdp: lag=%d samples (%.1f ms)",
                    _lp0b_lag,
                    _lp0b_lag / sample_rate * 1000,
                )
        except Exception as _lp0b_exc:
            logger.debug("LAG_PROBE_0B fehlgeschlagen: %s", _lp0b_exc)

        # §2.27 TransientDecoupledProcessing — Percussive/Harmonic-Trennung (allererster DSP-Schritt)
        _tdp_proc = None
        _tdp_percussive: np.ndarray | None = None
        _tdp_harmonic_ready: bool = False
        try:
            from backend.core.transient_decoupled_processor import get_transient_decoupled_processor

            _tdp_proc = get_transient_decoupled_processor()
            _tdp_audio_percussive, _tdp_audio_harmonic = _tdp_proc.separate(audio, sample_rate)
            _tdp_percussive = _tdp_audio_percussive.copy()  # Original-Transienten sichern
            audio = _tdp_audio_harmonic  # Pipeline ab jetzt auf harm. Anteil
            # §LAG_PROBE_0C: NACH TDP-Separation (harm. Anteil)
            # HPSS-Harmonic hat starke Tonal-Struktur am Anfang — GCC-PHAT erste 5s erzeugt
            # False-Positives. Mittleres 5s-Fenster (wie STCG) vermeidet diese Ambiguität.
            if audio.ndim == 2:
                try:
                    from backend.file_import import _estimate_interchannel_lag_samples as _gcc_lag

                    _lp0c_n = audio.shape[1]
                    _lp0c_w = int(sample_rate * 5.0)
                    _lp0c_s = max(0, _lp0c_n // 2 - _lp0c_w // 2)
                    _lp0c_e = min(_lp0c_n, _lp0c_s + _lp0c_w)
                    _lp0c_win = audio[:, _lp0c_s:_lp0c_e]
                    _lp0c_lag = _gcc_lag(_lp0c_win, sample_rate)
                    logger.info(
                        "LAG_PROBE 0C/after_tdp_separation: lag=%d samples (%.1f ms)",
                        _lp0c_lag,
                        _lp0c_lag / sample_rate * 1000,
                    )
                except Exception as _lp0c_exc:
                    logger.debug("LAG_PROBE_0C fehlgeschlagen: %s", _lp0c_exc)
            _tdp_harmonic_ready = True
            logger.info(
                "§2.27 TDP: Percussive/Harmonic getrennt (perc_rms=%.4f harm_rms=%.4f)",
                float(np.sqrt(np.mean(_tdp_audio_percussive**2))),
                float(np.sqrt(np.mean(_tdp_audio_harmonic**2))),
            )
        except Exception as _tdp_sep_exc:
            logger.debug("TransientDecoupledProcessor nicht verfügbar: %s", _tdp_sep_exc)

        # Isolates analysis/planning calls from live pipeline audio and prevents
        # accidental in-place L/R modifications before STCG pre-pipeline.
        _analysis_audio = np.array(audio, copy=True)

        # §2.25 ReferenceAnchorSynthesizer — Synthesierter Referenz-Anker für Mastering-Ziel
        _reference_anchor = None
        try:
            from backend.core.reference_anchor_synthesizer import synthesize_reference_anchor

            # Resolve reference era with conflict arbitration:
            # GlobalPlan stays default, but a high-confidence Tier-2 era signal
            # should win on hard decade conflicts.
            _gp_portrait_anc = getattr(getattr(self, "_active_global_plan", None), "portrait", None)
            _gp_decade_anc = getattr(_gp_portrait_anc, "decade", None) if _gp_portrait_anc is not None else None

            # Prefer the original cached era signal for arbitration because _era_result
            # may already be rewritten by GlobalPlan-prior logic earlier in restore().
            _anchor_era_source = _cached_era_kwarg if _cached_era_kwarg is not None else _era_result
            _chunk_decade_raw = getattr(_anchor_era_source, "decade", None) if _anchor_era_source is not None else None
            _chunk_decade_anc = int(_chunk_decade_raw) if _chunk_decade_raw is not None else None
            _chunk_conf_anc = (
                float(getattr(_anchor_era_source, "confidence", 0.0)) if _anchor_era_source is not None else 0.0
            )
            try:
                _chunk_tier_anc = (
                    int(getattr(_anchor_era_source, "tier_used", 2)) if _anchor_era_source is not None else 2
                )
            except Exception:
                _chunk_tier_anc = 2

            _era_for_anchor = int(_gp_decade_anc) if _gp_decade_anc is not None else _chunk_decade_anc
            if (
                _gp_decade_anc is not None
                and _chunk_decade_anc is not None
                and abs(int(_chunk_decade_anc) - int(_gp_decade_anc)) >= 20
                and _chunk_tier_anc == 2
                and _chunk_conf_anc >= 0.80
            ):
                _era_for_anchor = int(_chunk_decade_anc)
                logger.info(
                    "ReferenceAnchor Era-Arbitration: Tier-2 EraClassifier gewinnt (chunk=%s conf=%.2f gp=%s)",
                    _chunk_decade_anc,
                    _chunk_conf_anc,
                    _gp_decade_anc,
                )
            _mat_for_anchor = _classified_material.value if _classified_material is not None else "unknown"
            _genre_for_anchor = _schlager_result.genre_label if _schlager_result is not None else "unknown"
            _reference_anchor = synthesize_reference_anchor(
                era_decade=_era_for_anchor if _era_for_anchor is not None else 1970,
                genre_label=_genre_for_anchor,
                material=_mat_for_anchor,
            )
            logger.info(
                "🎯 ReferenceAnchorSynthesizer: Anker generiert (era=%s genre=%s material=%s)",
                _era_for_anchor,
                _genre_for_anchor,
                _mat_for_anchor,
            )
        except Exception as _ras_exc:
            logger.debug("ReferenceAnchorSynthesizer nicht verfügbar: %s", _ras_exc)

        # Step 1: Defect Scanning (Cache-First — kein Mehrfach-Scan §9.4)
        logger.info("Step 1/4: Defect Scanning...")
        if _cached_defect_kwarg is not None:
            defect_result = _cached_defect_kwarg
            logger.info("Step 1/4: Verwende gecachten DefectScan (kein Mehrfach-Scan).")
        else:
            # §2.31d: > 60 min → DefectScanner auf 3×60-s-Segmente (Anfang/Mitte/Ende).
            # Verhindert OOM bei sehr langen Dateien; 3 repr. Segmente reichen für
            # robuste Defekt-Klassifikation (Spec §2.31d, §2.47).
            _defect_scan_audio = analysis_audio
            if _is_very_long:
                _seg_sr = analysis_sample_rate
                _seg_len = min(
                    60 * _seg_sr, analysis_audio.shape[-1] // 4 if analysis_audio.ndim > 1 else len(analysis_audio) // 4
                )
                _n_full = analysis_audio.shape[-1] if analysis_audio.ndim > 1 else len(analysis_audio)
                if _n_full >= 3 * _seg_len:
                    _mid_start = _n_full // 2 - _seg_len // 2
                    _s = analysis_audio[..., :_seg_len]
                    _m = analysis_audio[..., _mid_start : _mid_start + _seg_len]
                    _e = analysis_audio[..., -_seg_len:]
                    _defect_scan_audio = np.concatenate([_s, _m, _e], axis=-1)
                    logger.info(
                        "§2.31d DefectScanner: 3×%.0fs-Segmente statt %.0fs Voll-Audio",
                        _seg_len / _seg_sr,
                        _n_full / _seg_sr,
                    )
            defect_result = self.defect_scanner.scan(
                _defect_scan_audio,
                analysis_sample_rate,
                _classified_material,
                file_ext=_file_ext_for_scan,
                forensic_medium_result=_mc_result if hasattr(_mc_result, "transfer_chain") else None,
            )
        if defect_result is None:
            logger.error(
                "DefectScanner.scan() returned None — creating fallback DefectAnalysisResult. "
                "Possible cause: internal scanner exception. Solution: check scanner logs."
            )
            from backend.core.defect_scanner import DefectAnalysisResult

            defect_result = DefectAnalysisResult(
                material_type=MaterialType.UNKNOWN if _classified_material is None else _classified_material,
                scores={},
                analysis_time_seconds=0.0,
                sample_rate=analysis_sample_rate,
                duration_seconds=(
                    float(len(analysis_audio) / analysis_sample_rate)
                    if analysis_audio.ndim == 1
                    else float(analysis_audio.shape[-1] / analysis_sample_rate)
                ),
            )
        material_type = defect_result.material_type

        # §soft_saturation-Guard-Injection: Severity in _restoration_context eintragen,
        # damit alle Phasen (z.B. phase_38_presence_boost) bei saturiertem Material
        # ihre Intensität reduzieren können. Verhindert "kratzig/übersteuert" bei Vinyl.
        if isinstance(getattr(self, "_restoration_context", None), dict):
            _sat_sev_ctx = float(
                np.clip(
                    next(
                        (
                            s.severity
                            for s in defect_result.get_top_defects(20)
                            if str(getattr(s.defect_type, "value", s.defect_type)).lower() == "soft_saturation"
                        ),
                        0.0,
                    ),
                    0.0,
                    1.0,
                )
            )
            self._restoration_context["soft_saturation_severity"] = _sat_sev_ctx
            logger.debug("RestorationContext: soft_saturation_severity=%.3f injected", _sat_sev_ctx)
            # §vocal_presence: PANNs-Singing ≥ 0.35 → additive Phasen schützen Vokalzone (200–4000 Hz).
            # Phasen lesen vocal_presence_active/_strength via kwargs (automatische _restoration_context-Injektion).
            _vpc_singing = float(getattr(self, "_panns_singing", 0.0))
            self._restoration_context["vocal_presence_active"] = _vpc_singing >= 0.35
            self._restoration_context["vocal_presence_strength"] = float(
                np.clip((_vpc_singing - 0.35) / 0.65, 0.0, 1.0) if _vpc_singing >= 0.35 else 0.0
            )
            logger.debug(
                "RestorationContext: vocal_presence_active=%s strength=%.3f (singing=%.3f)",
                self._restoration_context["vocal_presence_active"],
                self._restoration_context["vocal_presence_strength"],
                _vpc_singing,
            )

        # §2.47 Material-Defect Consistency Cross-Check — Aurik must notice when
        # MediumDetector and DefectScanner are inconsistent (§0c Universalitäts-Invariante).
        # Non-destructive: never overrides material_type; only logs WARNING + metadata.
        try:
            _mat_val = str(getattr(material_type, "value", material_type)).lower()
            _defect_sev_map: dict[str, float] = {
                str(s.defect_type.value): float(s.severity) for s in defect_result.get_top_defects(20)
            }
            _DIGITAL_MATERIALS = frozenset({"cd_digital", "cd", "dat", "streaming", "mp3_low", "mp3_high", "aac"})
            _ANALOG_MATERIALS = frozenset(
                {
                    "vinyl",
                    "lp",
                    "shellac",
                    "lacquer_disc",
                    "tape",
                    "reel_tape",
                    "wax_cylinder",
                    "wire_recording",
                    "minidisc",
                }
            )
            _ANALOG_DEFECT_SIGNATURES = (
                "crackle",
                "wow",
                "flutter",
                "multiband_wow_flutter",
                "low_freq_rumble",
                "riaa_curve_error",
                "groove_echo",
                "inner_groove_distortion",
                "print_through",
                "tape_head_level_dip",
                "soft_saturation",
            )
            _DIGITAL_DEFECT_SIGNATURES = (
                "digital_artifacts",
                "compression_artifacts",
                "jitter_artifacts",
                "quantization_noise",
            )
            _mdc_warnings: list[str] = []
            # §2.46a Transfer-Chain-Invariante: Wenn transfer_chain analoge Träger enthält
            # (z.B. vinyl→tape→mp3_low), sind Analog-Defekte am digitalen Primärformat erwartet
            # — kein Fehlklassifizierungsindikator, Warnung unterdrücken.
            _mdc_chain = list(getattr(self, "_restoration_context", {}).get("transfer_chain", []) or [])
            _ANALOG_CHAIN_MATERIALS = {"vinyl", "shellac", "tape", "reel_tape", "wire_recording", "wax_cylinder"}
            _chain_has_analog = any(str(c).lower() in _ANALOG_CHAIN_MATERIALS for c in _mdc_chain)
            if _mat_val in _DIGITAL_MATERIALS:
                _analog_sev = max((_defect_sev_map.get(d, 0.0) for d in _ANALOG_DEFECT_SIGNATURES), default=0.0)
                if _analog_sev >= 0.35 and not _chain_has_analog:
                    _mdc_warnings.append(
                        f"Digital material '{_mat_val}' but strong analog defects "
                        f"(max_sev={_analog_sev:.2f}) — possible misclassification"
                    )
                elif _analog_sev >= 0.35 and _chain_has_analog:
                    logger.debug(
                        "§2.47 Material-Defect Consistency: analog defects (sev=%.2f) expected "
                        "for chain %s — no misclassification warning",
                        _analog_sev,
                        " → ".join(_mdc_chain),
                    )
            elif _mat_val in _ANALOG_MATERIALS:
                _digital_sev = max((_defect_sev_map.get(d, 0.0) for d in _DIGITAL_DEFECT_SIGNATURES), default=0.0)
                _analog_sev = max((_defect_sev_map.get(d, 0.0) for d in _ANALOG_DEFECT_SIGNATURES), default=0.0)
                if _digital_sev >= 0.40 and _analog_sev < 0.10:
                    _mdc_warnings.append(
                        f"Analog material '{_mat_val}' but strong digital artifacts "
                        f"(digital_sev={_digital_sev:.2f}, analog_sev={_analog_sev:.2f}) "
                        f"— possible misclassification"
                    )
            if _mdc_warnings:
                for _mdc_w in _mdc_warnings:
                    logger.warning("§2.47 Material-Defect Consistency: %s", _mdc_w)
                self._material_defect_consistency_warnings = _mdc_warnings
            else:
                logger.debug("§2.47 Material-Defect Consistency: OK (material=%s)", _mat_val)
        except Exception as _mdc_exc:
            logger.debug("§2.47 Material-Defect Consistency check skipped: %s", _mdc_exc)

        # §9.1c Perceptual-Salience-Annotation: weight defect severities by
        # psychoacoustic masking (Fastl & Zwicker 2007).  Masked defects get
        # reduced severity → less processing → fewer artifacts.
        try:
            from backend.core.perceptual_salience import get_perceptual_salience_estimator

            _pse = get_perceptual_salience_estimator()
            defect_result = _pse.annotate_defect_scores(_analysis_audio, sample_rate, defect_result)
            logger.info("§9.1c PerceptualSalience: defect severities salience-adjusted")
        except Exception as _pse_exc:
            logger.debug("PerceptualSalienceEstimator nicht verfügbar: %s", _pse_exc)

        _cb(10, "Defekte werden kartiert …")
        _saliency_map = None
        try:
            from backend.core.perceptual_attention_model import compute_saliency_map

            _saliency_map = compute_saliency_map(_analysis_audio, sample_rate)
            logger.info(
                "👁️ PerceptualAttentionModel: saliency_map shape=%s max=%.3f",
                _saliency_map.shape,
                float(_saliency_map.max()),
            )
        except Exception as _pam_exc:
            logger.debug("PerceptualAttentionModel nicht verfügbar: %s", _pam_exc)

        logger.info(
            "Detected material: %s, Top defects: %s",
            material_type.value,
            ", ".join([f"{s.defect_type.value}={s.severity:.2f}" for s in defect_result.get_top_defects(3)]),
        )

        _cb(11, "Kausalanalyse …")

        # Kausaldiagnose: Bayesianische Ursachenermittlung
        _causal_plan = None
        try:
            from backend.core.causal_defect_reasoner import reason_about_defects

            _defect_scores_map = {s.defect_type.value: s.severity for s in defect_result.get_top_defects(8)}
            _causal_plan = reason_about_defects(
                defect_scores=_defect_scores_map,
                material=material_type.value,
                audio=_analysis_audio,
                sample_rate=sample_rate,
            )
            logger.info(
                "CausalReasoner: primary=%s (confidence=%.3f) | %s",
                _causal_plan.primary_cause,
                _causal_plan.confidence,
                _causal_plan.reasoning[:120],
            )
        except Exception as _cr_exc:
            logger.debug("CausalDefectReasoner nicht verfügbar: %s", _cr_exc)

        _cb(13, "Kausale Defektanalyse abgeschlossen …")

        # UQ: Pipeline-Konfidenzschätzung (§2.15)
        _pipeline_confidence = None
        try:
            from backend.core.pipeline_uncertainty import estimate_pipeline_confidence

            _defect_scores_uq = {s.defect_type.value: s.severity for s in defect_result.get_top_defects(8)}
            _pipeline_confidence = estimate_pipeline_confidence(_causal_plan, _defect_scores_uq)
            logger.info(
                "🔮 PipelineUQ: tier=%s confidence=%.2f gp_factor=%.2f%s",
                _pipeline_confidence.tier,
                _pipeline_confidence.confidence,
                _pipeline_confidence.gp_bound_factor,
                f" | {_pipeline_confidence.user_hint}" if _pipeline_confidence.user_hint else "",
            )
        except Exception as _uq_exc:
            logger.debug("PipelineUncertaintyEstimator nicht verfügbar: %s", _uq_exc)

        # Step 1c: Musikalische Strukturanalyse (§2.17) — Chorus als Inpainting-Prior
        _musical_structure = None
        try:
            _has_dropout = any(
                s.defect_type.value in {"dropouts", "tape_dropout", "dropout"} and s.severity >= 0.25
                for s in defect_result.get_top_defects(10)
            )
            if _has_dropout:
                from backend.core.musical_structure_analyzer import analyze_musical_structure

                _musical_structure = analyze_musical_structure(_analysis_audio, sample_rate)
                _n_chorus = sum(1 for s in _musical_structure.segments if s.segment_type == "chorus")
                _n_verse = sum(1 for s in _musical_structure.segments if s.segment_type == "verse")
                logger.info(
                    "🎵 MusicalStructure: %d Segmente (Chorus×%d Verse×%d) confidence=%.2f",
                    len(_musical_structure.segments),
                    _n_chorus,
                    _n_verse,
                    _musical_structure.confidence,
                )
            else:
                logger.debug("MusicalStructureAnalyzer: übersprungen (kein Dropout-Defekt aktiv)")
        except Exception as _msa_exc:
            logger.debug("MusicalStructureAnalyzer nicht verfügbar: %s", _msa_exc)

        _cb(14, "Qualitätsprofil wird erstellt …")

        # §2.5 Spec: propose_pareto() als primärer GP-Vorschlag (MOO, Pareto-Front)
        _pareto_proposals = None
        _gp_material_key_pre = material_type.value if material_type else "unknown"
        try:
            from backend.core.gp_parameter_optimizer import get_optimizer as _get_gp_opt_pre

            _gp_opt_pre = _get_gp_opt_pre()
            _era_ws_pre: dict[str, float] | None = None
            if _era_result is not None:
                try:
                    from backend.core.era_classifier import get_era_classifier as _get_era_clf_pre

                    _era_ws_pre = _get_era_clf_pre().get_gp_warmstart(_era_result)
                except Exception as _ws_exc:
                    logger.debug("GP-Warmstart aus Era-Classifier fehlgeschlagen: %s", _ws_exc)
            _pareto_proposals = _gp_opt_pre.propose_pareto(
                material=_gp_material_key_pre,
                era_warmstart=_era_ws_pre,
            )
            logger.info(
                "§2.5 GP propose_pareto: %d Pareto-Kandidaten für material='%s'",
                len(_pareto_proposals),
                _gp_material_key_pre,
            )
        except Exception as _pareto_exc:
            logger.debug("propose_pareto nicht verfügbar, Fallback auf Legacy propose(): %s", _pareto_exc)

        # §2.32 GoalApplicabilityFilter — physikalisch nicht messbare Ziele deaktivieren
        # §2.47a: Einmaliger Aufruf; panns_tags aus DefectScanner-Metadata und kwargs gemergt.
        _goal_applicability = None
        _applicable_goals: set | None = None
        try:
            from backend.core.goal_applicability_filter import evaluate_goal_applicability

            _panns_conf: dict[str, float] | None = None
            with contextlib.suppress(Exception):
                _panns_conf = defect_result.metadata.get("panns_tags") if hasattr(defect_result, "metadata") else None
            # Merge: defect_result-Metadata zuerst, kwargs.panns_tags als Ergänzung
            _panns_kwargs = kwargs.get("panns_tags") or {}
            _panns_merged: dict[str, float] = {}
            if isinstance(_panns_kwargs, dict):
                _panns_merged.update(_panns_kwargs)
            if isinstance(_panns_conf, dict):
                _panns_merged.update(_panns_conf)  # DefectScanner-Tags überschreiben kwargs
            # §2.32 brillanz-Fix: AudioSR-Verfügbarkeit prüfen. GAF deaktiviert brillanz nur
            # wenn BW < 8 kHz UND AudioSR nicht verfügbar. Aurik bündelt AudioSR → fast immer
            # verfügbar; nicht-verfügbar nur bei fehlendem Modell-File.
            _audiosr_avail = False
            try:
                from plugins.audiosr_plugin import get_audiosr_plugin as _get_audiosr

                _get_audiosr  # noqa: B018  # pylint: disable=pointless-statement
                _audiosr_avail = True
            except Exception:
                pass

            _goal_applicability = evaluate_goal_applicability(
                audio=_analysis_audio,
                sr=sample_rate,
                material=material_type.value if material_type else "unknown",
                era_decade=_era_result.decade if _era_result is not None else None,
                panns_tags=_panns_merged or None,
                audiosr_available=_audiosr_avail,
                mode=str(getattr(getattr(self.config, "mode", None), "value", "restoration")).lower(),
            )
            _applicable_goals = set(_goal_applicability.applicable)
            _goal_applicability_result = _goal_applicability
            logger.info(
                "§2.32 GoalApplicabilityFilter: %d applicable / %d inapplicable: %s",
                len(_goal_applicability.applicable),
                len(_goal_applicability.inapplicable),
                ", ".join(sorted(_goal_applicability.inapplicable)) or "—",
            )
        except Exception as _gaf_exc:
            logger.debug("GoalApplicabilityFilter nicht verfügbar: %s", _gaf_exc)

        # §2.31d Edge-Case: < 10 s → Groove + MicroDyn nicht messbar (zu wenig Kontext)
        if _is_very_short:
            if _applicable_goals is None:
                _applicable_goals = set()
            _applicable_goals.discard("groove")
            _applicable_goals.discard("micro_dynamics")
            logger.info(
                "§2.31d: %.1fs < 10s → groove + micro_dynamics aus applicable_goals entfernt",
                _audio_duration_s,
            )

        # §8.2 Pass-Through-Invariante: Sauberes Material schonend behandeln
        # (SNR > 40 dB + max_defect_severity < 0.15 → Schonmodus)
        _rms_signal = float(np.sqrt(np.mean(_analysis_audio**2)) + 1e-9)
        _noise_percentile = float(np.percentile(np.abs(_analysis_audio), 5) + 1e-9)
        _input_snr_db = 20.0 * np.log10(_rms_signal / _noise_percentile)
        _top_defects = defect_result.get_top_defects(10)
        _max_defect_severity = max((s.severity for s in _top_defects), default=0.0)
        _localized_critical, _localized_metrics = self._has_localized_critical_defects(_top_defects)
        _clean_digital_mode, _clean_digital_metrics = self._is_benign_digital_source(
            _analysis_audio,
            sample_rate,
            defect_result.material_type,
        )
        # §0a Studio 2026 — volle Enhancement-Kette ist normativ; Pass-through ist verboten
        # (Spec: „Mailmal-zielgerichtet — volle Enhancement-Kette“). Die SNR/Clean-Heuristik
        # ist nur für Restoration zulässig, nicht für Studio 2026.
        _pass_through_mode = (
            not self.is_studio_mode()
            and ((_input_snr_db > 40.0 and _max_defect_severity < 0.15) or _clean_digital_mode)
        ) and not _localized_critical
        if _localized_critical:
            logger.info(
                "🛡️ Local-Defect-Guard: Schonmodus deaktiviert (localized_count=%d, max=%.3f, thr=%.3f)",
                int(_localized_metrics.get("localized_count", 0)),
                float(_localized_metrics.get("max_localized_severity", 0.0)),
                float(_localized_metrics.get("threshold", 0.08)),
            )
        _mp3_maximum_guard = self._should_force_mp3_maximum_guard(
            self.config.mode,
            material_type,
            _input_snr_db,
            _max_defect_severity,
            _clean_digital_mode,
        )
        # §0a: MP3-Maximum-Guard darf Studio 2026 nie in Pass-through zwingen.
        # Studio 2026 auf lossy-Codec-Material will Stem-Sep, Vocal-AI, Enhancement-Chain.
        if _mp3_maximum_guard and not _pass_through_mode and not self.is_studio_mode():
            _pass_through_mode = True
            logger.info(
                "🛡️ MP3-Maximum-Guard: material=%s, mode=%s, SNR=%.1f dB, max_defect=%.3f → Schonmodus erzwungen",
                material_type.value if hasattr(material_type, "value") else str(material_type),
                self.config.mode.value,
                _input_snr_db,
                _max_defect_severity,
            )
        _pipeline_quality_mode_override: QualityMode | None = None
        if _mp3_maximum_guard:
            _pipeline_quality_mode_override = QualityMode.QUALITY
            logger.info(
                "🛡️ MP3-Maximum-Guard: quality_mode override %s -> %s",
                self.config.mode.value,
                _pipeline_quality_mode_override.value,
            )

        _pipeline_conf_val = float(getattr(_pipeline_confidence, "confidence", 1.0)) if _pipeline_confidence else 1.0
        # §2.31a: Per-defect and PANNs data available here → pass into calibration.
        # defect_result.scores: dict[DefectType, DefectScore] → normalise to str→float.
        _cal_defect_sev: dict[str, float] = {}
        if hasattr(defect_result, "scores") and isinstance(defect_result.scores, dict):
            _cal_defect_sev = {
                (dt.value if hasattr(dt, "value") else str(dt)): float(getattr(ds, "severity", 0.0))
                for dt, ds in defect_result.scores.items()
            }
        _cal_sf: dict[str, float] = {}
        if hasattr(defect_result, "spectral_fingerprint") and isinstance(defect_result.spectral_fingerprint, dict):
            _cal_sf = defect_result.spectral_fingerprint
        _cal_transfer_chain = self._extract_transfer_chain_from_forensics(
            getattr(defect_result, "transfer_chain_raw", None)
        )
        _cal_is_schlager = (
            bool(getattr(_schlager_result, "is_schlager", False)) if _schlager_result is not None else False
        )
        _cal_genre_label = (
            str(getattr(_schlager_result, "genre_label", "") or "") if _schlager_result is not None else ""
        )
        self._song_calibration_profile = self._build_song_calibration_profile(
            material_type=material_type,
            mode=self.config.mode,
            restorability_score=_pmgg_restorability_score,
            input_snr_db=_input_snr_db,
            max_defect_severity=_max_defect_severity,
            pipeline_confidence=_pipeline_conf_val,
            era_decade=getattr(_era_result, "decade", None) if _era_result is not None else None,
            defect_scores=_cal_defect_sev if _cal_defect_sev else None,
            panns_tags=_panns_conf,  # from defect_result.metadata (already extracted above)
            spectral_fingerprint=_cal_sf if _cal_sf else None,
            transfer_chain=_cal_transfer_chain,
            is_schlager=_cal_is_schlager,
            genre_label=_cal_genre_label,
        )
        self._song_calibration_profile = self._apply_song_autosetup_policy(
            self._song_calibration_profile,
            defect_scores=_cal_defect_sev if _cal_defect_sev else None,
            transfer_chain=_cal_transfer_chain,
            max_defect_severity=_max_defect_severity,
            quiet_edge_profile=UnifiedRestorerV3._compute_quiet_edge_prevention_profile(
                _analysis_audio,
                sample_rate,
                material_key=str(getattr(material_type, "value", material_type)).lower() if material_type else None,
            ),
        )
        # §9.11.1 Restorability-Ceiling: persist for access during phase loop
        self._last_restorability_score = float(_pmgg_restorability_score)
        self._strict_autosetup_policy = dict(self._song_calibration_profile.get("strict_conflict_policy", {}))
        if isinstance(getattr(self, "_restoration_context", None), dict):
            self._restoration_context.update(
                {
                    "song_calibration_global": self._song_calibration_profile.get("global_scalar", 1.0),
                    "song_calibration_tier": self._song_calibration_profile.get("restorability_tier", "fair"),
                    "song_calibration_confidence": self._song_calibration_profile.get("pipeline_confidence", 1.0),
                    "strict_conflict_policy": dict(self._strict_autosetup_policy),
                    # §2.54 Adaptive Intelligence — downstream phases may query these directly
                    "restorability_score": float(_pmgg_restorability_score),
                    "transfer_chain": list(_cal_transfer_chain) if _cal_transfer_chain else [],
                    # §HEAD_BUMP_PROFILES — enables phase_04 head-bump for tape/cassette material.
                    # §2.46a: transfer_chain passed so that intermediate tape stages in
                    # multi-generation chains (e.g. vinyl → tape → mp3_low) are detected.
                    "tape_speed_ips": UnifiedRestorerV3._infer_tape_speed_ips(
                        material_type,
                        getattr(_era_result, "decade", None) if _era_result is not None else None,
                        list(_cal_transfer_chain) if _cal_transfer_chain else None,
                    ),
                }
            )
            # §2.9 PANNs-Durchreichung: panns_tags + abgeleitete Konfidenzen in den
            # Restaurierungskontext injizieren, damit _profiled_phase_call sie zentral
            # in ALLE Phase-kwargs verteilt. Phasen 12, 42–45, 51, 52 lesen
            # kwargs.get("panns_tags") bzw. kwargs.get("panns_vocals_confidence").
            if isinstance(_panns_conf, dict) and _panns_conf:
                self._restoration_context["panns_tags"] = _panns_conf
                _panns_vocal_max = max(
                    float(_panns_conf.get("Singing voice", 0.0) or 0),
                    float(_panns_conf.get("Vocals", 0.0) or 0),
                    float(_panns_conf.get("Speech", 0.0) or 0),
                    float(_panns_conf.get("Male singing", 0.0) or 0),
                    float(_panns_conf.get("Female singing", 0.0) or 0),
                )
                self._restoration_context["panns_vocals_confidence"] = _panns_vocal_max
                # §0p BUG-FIX v9.12.5: panns_singing key für UV3-HNR-Hook (L~17838).
                # _NR_PHASES_HNR prüft kwargs.get("panns_singing") — ohne diesen Key
                # in _restoration_context feuert apply_hnr_blend nie bei Vokal-Material.
                self._restoration_context["panns_singing"] = max(
                    float(_panns_conf.get("Singing", 0.0) or 0),
                    float(_panns_conf.get("Singing voice", 0.0) or 0),
                )
        # [RELEASE_MUST] Lücke-G-Fix v9.10.100: assert global_scalar ∈ [0.50, 1.50]
        _gs_assert = float(self._song_calibration_profile.get("global_scalar", 1.0))
        assert 0.50 <= _gs_assert <= 1.50, (
            f"global_scalar={_gs_assert:.4f} out of bounds [0.50, 1.50] — "
            "SongCalibrationProfile violated invariant (Lücke-G-Fix v9.10.100)"
        )
        logger.info(
            "🎛️ SongCalibration: material=%s era=%s tier=%s global=%.3f denoise=%.3f conf=%.2f",
            self._song_calibration_profile.get("material", "unknown"),
            str(self._song_calibration_profile.get("era_decade", "?")),
            self._song_calibration_profile.get("restorability_tier", "fair"),
            float(self._song_calibration_profile.get("global_scalar", 1.0)),
            float(self._song_calibration_profile.get("family_scalars", {}).get("denoise", 1.0)),
            float(self._song_calibration_profile.get("pipeline_confidence", 1.0)),
        )
        logger.info(
            "StrictAutoSetup: transfer_depth=%d caps={12:%.2f,24:%.2f,55:%.2f}",
            int(self._strict_autosetup_policy.get("transfer_chain_depth", 0)),
            float(self._strict_autosetup_policy.get("phase_strength_caps", {}).get("phase_12_wow_flutter_fix", 1.0)),
            float(self._strict_autosetup_policy.get("phase_strength_caps", {}).get("phase_24_dropout_repair", 1.0)),
            float(
                self._strict_autosetup_policy.get("phase_strength_caps", {}).get("phase_55_diffusion_inpainting", 1.0)
            ),
        )
        _cb(15, "Klangleitplanken …")

        # ── §2.56 Song-Goal-Importance: Per-song goal weighting ──────────
        # Computed ONCE after all classifiers (Genre, Era, Material, Vocal)
        # and threaded through PMGG, CIG, and FeedbackChain for the entire pipeline.
        try:
            _vocal_detected = bool(getattr(self, "_restoration_context", {}).get("panns_vocals_confidence", 0.0) > 0.4)
            _vocal_conf = float(getattr(self, "_restoration_context", {}).get("panns_vocals_confidence", 0.0))
            # §2.56 v9.12: Extract audio-derived features for per-song tuning
            _sgi_bw_hz = float(_cal_sf.get("effective_bandwidth_hz", 0)) or None
            _sgi_dyn_db: float | None = None
            try:
                _qb = locals().get("_quality_before")
                if _qb is not None and hasattr(_qb, "dynamic_range_db"):
                    _sgi_dyn_db = float(_qb.dynamic_range_db)
            except Exception:
                pass
            _sgi_bpm: float | None = None
            if _schlager_result is not None and hasattr(_schlager_result, "bpm"):
                _bpm_raw = getattr(_schlager_result, "bpm", None)
                if _bpm_raw is not None and float(_bpm_raw) > 0:
                    _sgi_bpm = float(_bpm_raw)
            _sgi_defect_sev: dict[str, float] | None = None
            if defect_result is not None and hasattr(defect_result, "scores"):
                _sgi_defect_sev = {
                    str(getattr(dt, "name", dt)).lower(): float(ds.severity)
                    for dt, ds in defect_result.scores.items()
                    if hasattr(ds, "severity") and ds.severity > 0.05
                }
            _sgi_tilt: float | None = None
            if _era_result is not None and hasattr(_era_result, "spectral_tilt"):
                _raw_tilt = getattr(_era_result, "spectral_tilt", None)
                if _raw_tilt is not None:
                    _sgi_tilt = float(_raw_tilt)
                # §2.46b: store era tilt as session-level instance variable for per-phase cap.
                self._era_spectral_tilt = _sgi_tilt  # None if era classification unavailable
            # §2.46/§2.46a: Carrier-chain degradation data from SourceFidelityReconstructor
            _sgi_gen_count: int | None = None
            _sgi_hf_loss: float | None = None
            _sgi_sfr_conf: float | None = None
            _rctx = getattr(self, "_restoration_context", {}) or {}
            if _rctx.get("source_fidelity_generation_count") is not None:
                _sgi_gen_count = int(_rctx["source_fidelity_generation_count"])
            if _rctx.get("source_fidelity_hf_loss_db") is not None:
                _sgi_hf_loss = float(_rctx["source_fidelity_hf_loss_db"])
            if _rctx.get("source_fidelity_confidence") is not None:
                _sgi_sfr_conf = float(_rctx["source_fidelity_confidence"])
            # §2.56 Psychoacoustic features — Zwicker/Aures/Bark/Masking/Tonality
            _sgi_roughness: float | None = None
            _sgi_sharpness: float | None = None
            _sgi_spectral_flatness: float | None = None
            _sgi_tonality: float | None = None
            _sgi_freq_balance: dict[str, float] | None = None
            _sgi_masked_ratio: float | None = None
            _sgi_centroid_bark: float | None = None
            try:
                _pa_mono = _analysis_audio.mean(axis=0) if _analysis_audio.ndim == 2 else _analysis_audio
                # Roughness, Sharpness, Spectral Flatness via PsychoAcousticMetrics
                from backend.core.psychoacoustic_metrics import PsychoAcousticMetrics

                _pam = PsychoAcousticMetrics(sample_rate=sample_rate)
                _sgi_roughness = float(_pam.calculate_roughness(_pa_mono))
                _sgi_sharpness = float(_pam.calculate_sharpness(_pa_mono))
                _sgi_spectral_flatness = float(_pam.calculate_spectral_flatness(_pa_mono))
                # Tonality via ComprehensiveMetricsCalculator._compute_tonality
                from backend.core.comprehensive_metrics import ComprehensiveMetricsCalculator

                _cm = ComprehensiveMetricsCalculator(sample_rate)
                _sgi_tonality = float(_cm._compute_tonality(_pa_mono))  # pylint: disable=protected-access
                # Bark-scale analysis: frequency balance, masked ratio, centroid
                from backend.core.psychoacoustic_core import PsychoacousticCore

                _pac = PsychoacousticCore()
                _pa_result = _pac.analyze(_pa_mono, sample_rate)
                _sgi_freq_balance = _pa_result.frequency_balance
                _sgi_masked_ratio = float(_pa_result.masked_components_ratio)
                _sgi_centroid_bark = float(_pa_result.perceptual_centroid_bark)
                logger.debug(
                    "§2.56 psychoacoustic features: rough=%.3f sharp=%.3f flat=%.3f "
                    "tonal=%.3f masked=%.3f centroid=%.1fBark",
                    _sgi_roughness,
                    _sgi_sharpness,
                    _sgi_spectral_flatness,
                    _sgi_tonality,
                    _sgi_masked_ratio,
                    _sgi_centroid_bark,
                )
            except Exception as _pa_err:
                logger.debug("§2.56 psychoacoustic feature extraction failed: %s", _pa_err)
            # §2.56 Vocal/harmonic/transient features — music preservation
            _sgi_hnr_db: float | None = None
            _sgi_harm_coh: float | None = None
            _sgi_crest_db: float | None = None
            _sgi_trans_dens: float | None = None
            try:
                _pa_mono_vht = _analysis_audio.mean(axis=0) if _analysis_audio.ndim == 2 else _analysis_audio

                # --- HNR: True pitch-period HNR via multi-frame AC ---
                # ComprehensiveMetrics._compute_hnr starts lag search at 1
                # (measures SNR proxy, not pitch periodicity).  Instead, use
                # _compute_fundamental_stability's frame-wise AC with pitch-lag
                # search starting at lag 20 (2400 Hz upper bound @ 48kHz).
                from backend.core.comprehensive_metrics import ComprehensiveMetricsCalculator as _CMC

                _cm_vht = _CMC(sample_rate)
                # Use 10s representative segment from middle of song (avoid intro/outro)
                _n_vht = len(_pa_mono_vht)
                _mid = _n_vht // 2
                _seg_half = min(sample_rate * 5, _mid)  # ±5s around middle
                _pa_seg = _pa_mono_vht[max(0, _mid - _seg_half) : min(_n_vht, _mid + _seg_half)]
                # Frame-wise pitch-lag HNR (robust, O(N log N) per frame)
                _hnr_samples: list[float] = []
                _frame_sz = int(0.05 * sample_rate)  # 50ms frames
                _hnr_hop = _frame_sz  # no overlap for speed
                _search_lo = max(int(sample_rate / 2000), 2)  # 2000 Hz upper pitch
                _search_hi = min(int(sample_rate / 50), _frame_sz - 1)  # 50 Hz lower pitch
                if _search_hi > _search_lo and len(_pa_seg) >= _frame_sz * 4:
                    from scipy.signal import find_peaks as _fp

                    for _fs in range(0, len(_pa_seg) - _frame_sz, _hnr_hop):
                        _frm = _pa_seg[_fs : _fs + _frame_sz]
                        _nf = len(_frm)
                        _Xf = np.fft.rfft(_frm, n=2 * _nf)
                        _ac = np.fft.irfft(np.abs(_Xf) ** 2)[:_nf]
                        _ac0 = _ac[0] + 1e-30
                        _ac = _ac / _ac0
                        # Find first significant AC peak in pitch range
                        _region = _ac[_search_lo:_search_hi]
                        _pks, _ = _fp(_region, height=0.1)
                        if len(_pks) > 0:
                            _pk_val = float(_region[_pks[0]])
                            _noise_e = max(1.0 - _pk_val, 1e-10)
                            _hnr_samples.append(10.0 * np.log10(max(_pk_val, 1e-10) / _noise_e))
                    if _hnr_samples:
                        _sgi_hnr_db = float(np.clip(np.median(_hnr_samples), -10, 40))

                # --- Crest factor (peak vs. RMS in dB) ---
                _rms_vht = float(np.sqrt(np.mean(_pa_seg**2)))
                _peak_vht = float(np.percentile(np.abs(_pa_seg), 99.9))
                if _rms_vht > 1e-10 and _peak_vht > 1e-10:
                    _sgi_crest_db = 20.0 * np.log10(_peak_vht / _rms_vht)

                # --- Harmonic Coherence: STFT-based whole-song analysis ---
                # PhaseConductor._estimate_harmonic_coherence only uses first 46ms
                # (designed for realtime phase-state, not song-level analysis).
                # Use PsychoAcousticMetrics.calculate_harmonic_coherence instead:
                # STFT spectral peak consistency over the full song duration.
                from backend.core.psychoacoustic_metrics import PsychoAcousticMetrics as _PAM_VHT

                _pam_vht = _PAM_VHT(sample_rate)
                _sgi_harm_coh = float(_pam_vht.calculate_harmonic_coherence(_pa_seg))

                # --- Transient Density: STFT Spectral Flux + Peak-Picking ---
                # PhaseConductor._estimate_transient_density uses RMS-flux + 1.5σ
                # without min-distance -- ~4x too many onsets for noisy material.
                # Use dsp/dtw_groove.detect_onsets: STFT spectral flux + adaptive
                # threshold + 50ms min-gap -- robust for vinyl/tape.
                from dsp.dtw_groove import detect_onsets as _detect_onsets_stft

                _onset_result = _detect_onsets_stft(
                    _pa_seg,
                    sr=sample_rate,
                    hop_ms=10.0,
                    threshold=0.3,
                    min_onset_gap_ms=50.0,
                )
                _seg_dur = len(_pa_seg) / max(sample_rate, 1)
                _sgi_trans_dens = float(_onset_result.n_onsets / max(_seg_dur, 0.01))

                logger.debug(
                    "§2.56 vocal/harmonic/transient features: hnr=%.1fdB hcoh=%.3f crest=%.1fdB tdens=%.1f/s",
                    _sgi_hnr_db or 0.0,
                    _sgi_harm_coh or 0.0,
                    _sgi_crest_db or 0.0,
                    _sgi_trans_dens or 0.0,
                )
            except Exception as _vht_err:
                logger.debug("§2.56 vocal/harmonic/transient extraction failed: %s", _vht_err)
            _src_baseline = None
            try:
                _afg_250 = get_artifact_freedom_gate()
                _mat_str_250 = (
                    str(getattr(material_type, "value", material_type)).lower() if material_type else "digital"
                )
                _src_baseline = _afg_250.measure_source_baseline(_analysis_audio, sample_rate, _mat_str_250)
            except Exception as _sb250_exc:
                logger.debug("§2.50 Source-Baseline-Messung fehlgeschlagen: %s", _sb250_exc)

            # §CSTC Cross-Segment Timbral Coherence Guard — Pre-Pipeline Rauschprofil (§0a).
            # Referenzprofil wird VOR der Pipeline extrahiert; nach NR-Phasen wird Kohärenz ≥ 0.80
            # geprüft. Verhindert "Pumping"-Artefakte durch inkohärenten Rauschboden nach NR.
            self._cstc_noise_profile = None  # reset for each restore() call
            try:
                from backend.core.dsp.timbral_coherence_guard import extract_song_noise_profile as _cstc_extract

                _cstc_audio_in = (
                    _analysis_audio.astype(np.float32)
                    if isinstance(_analysis_audio, np.ndarray)
                    else np.zeros(sample_rate, dtype=np.float32)
                )
                self._cstc_noise_profile = _cstc_extract(_cstc_audio_in, sample_rate)
                logger.debug(
                    "§CSTC song_noise_profile extrahiert (shape=%s)",
                    getattr(self._cstc_noise_profile, "shape", "?"),
                )
            except Exception as _cstc_exc:
                logger.debug("§CSTC extract_song_noise_profile fehlgeschlagen (non-blocking): %s", _cstc_exc)

            _sgi = estimate_goal_importance(
                genre_label=_cal_genre_label
                or (str(getattr(_schlager_result, "genre_label", "")) if _schlager_result is not None else ""),
                era_decade=getattr(_era_result, "decade", None) if _era_result is not None else None,
                material_type=material_type,
                restorability_score=float(_pmgg_restorability_score),
                vocal_detected=_vocal_detected,
                vocal_confidence=_vocal_conf,
                is_studio_2026=self.is_studio_mode(),
                # Audio-derived features
                snr_db=_input_snr_db if _input_snr_db is not None else None,
                effective_bandwidth_hz=_sgi_bw_hz,
                dynamic_range_db=_sgi_dyn_db,
                stereo_mono_compat=(
                    float(getattr(_src_baseline, "stereo_mono_compat_mean", 0.0))
                    if getattr(_src_baseline, "stereo_mono_compat_mean", None) is not None
                    else None
                ),
                bpm=_sgi_bpm,
                defect_severities=_sgi_defect_sev,
                spectral_tilt_db_per_oct=_sgi_tilt,
                # Carrier-chain degradation (§2.46/§2.46a)
                transfer_generation_count=_sgi_gen_count,
                cumulative_hf_loss_db=_sgi_hf_loss,
                source_fidelity_confidence=_sgi_sfr_conf,
                # Psychoacoustic features (Zwicker/Aures/Bark/Masking)
                roughness=_sgi_roughness,
                sharpness=_sgi_sharpness,
                spectral_flatness=_sgi_spectral_flatness,
                tonality=_sgi_tonality,
                frequency_balance=_sgi_freq_balance,
                masked_components_ratio=_sgi_masked_ratio,
                perceptual_centroid_bark=_sgi_centroid_bark,
                # Vocal/harmonic/transient preservation
                harmonic_to_noise_ratio_db=_sgi_hnr_db,
                harmonic_coherence=_sgi_harm_coh,
                crest_factor_db=_sgi_crest_db,
                transient_density=_sgi_trans_dens,
            )
            self._song_goal_importance = _sgi
            self._song_goal_weights = _sgi.weights
            logger.info(
                "§2.56 SongGoalImportance: genre=%s era=%s mat=%s vocal=%s | %s",
                _sgi.genre_profile,
                _sgi.era_profile,
                _sgi.material_profile,
                _vocal_detected,
                " ".join(f"{k}={v:.2f}" for k, v in sorted(_sgi.weights.items())),
            )
        except Exception as _sgi_err:
            logger.warning("§2.56 SongGoalImportance failed (label-stage fallback): %s", _sgi_err)
            # Label-stage-only fallback: genre+era+material+vocal weights without audio features.
            # Better than None — gives PMGG/CIG meaningful per-song context even when audio
            # feature extraction fails. NaN from audio features won't contaminate this path.
            try:
                _sgi_fallback = estimate_goal_importance(
                    genre_label=_cal_genre_label or "",
                    era_decade=getattr(_era_result, "decade", None) if _era_result is not None else None,
                    material_type=material_type,
                    restorability_score=float(_pmgg_restorability_score),
                    vocal_detected=bool(
                        getattr(self, "_restoration_context", {}).get("panns_vocals_confidence", 0.0) > 0.4
                    ),
                    vocal_confidence=float(
                        getattr(self, "_restoration_context", {}).get("panns_vocals_confidence", 0.0)
                    ),
                    is_studio_2026=self.is_studio_mode(),
                )
                self._song_goal_importance = _sgi_fallback
                self._song_goal_weights = _sgi_fallback.weights
                logger.info(
                    "§2.56 Label-stage fallback active: %s",
                    " ".join(f"{k}={v:.2f}" for k, v in sorted(_sgi_fallback.weights.items())),
                )
            except Exception as _sgi_fb_err:
                logger.warning(
                    "§2.56 Label-stage fallback also failed: %s — using conservative uniform weights", _sgi_fb_err
                )
                self._song_goal_importance = None
                # §2.56 Gap G3: Never leave weights as None — PMGG/CIG/§9.8b rely on
                # goal_weights being a dict. Uniform weights with slight P1/P2 boost ensure
                # all gates still have meaningful context even when full SGI fails.
                self._song_goal_weights = {
                    "natuerlichkeit": 1.20,
                    "authentizitaet": 1.20,
                    "tonal_center": 1.15,
                    "timbre_authentizitaet": 1.15,
                    "artikulation": 1.10,
                    "emotionalitaet": 1.00,
                    "micro_dynamics": 1.00,
                    "groove": 1.00,
                    "transparenz": 1.00,
                    "waerme": 1.00,
                    "bass_kraft": 1.00,
                    "separation_fidelity": 1.00,
                    "brillanz": 1.00,
                    "spatial_depth": 1.00,
                }

        # §09.2 [RELEASE_MUST] Per-Song Goal Targets (Era × Material × Genre Bias)
        # Single Source of Truth: calibration_matrix.estimate_song_goal_targets()
        try:
            from backend.core.calibration_matrix import (
                estimate_song_goal_targets as _estimate_sgt,
            )

            _sgt_mode_val = getattr(getattr(self.config, "mode", None), "value", "") or ""
            _sgt_is_studio = any(kw in _sgt_mode_val.lower() for kw in ("studio", "maximum", "aggressive"))
            _sgt_mat_str = str(getattr(material_type, "value", material_type) or "").strip().lower()
            _sgt_chain = getattr(material_type, "transfer_chain", None)
            _sgt_era_decade = getattr(_era_result, "decade", None) if _era_result is not None else None
            self._song_goal_targets = _estimate_sgt(
                is_studio_2026=_sgt_is_studio,
                goal_weights=self._song_goal_weights,
                restorability_score=float(_pmgg_restorability_score),
                era_decade=_sgt_era_decade,
                genre_label=_cal_genre_label or "",
                material_type=_sgt_mat_str,
                transfer_chain=_sgt_chain,
            )
            logger.info(
                "§09.2 SongGoalTargets: era=%s mat=%s studio=%s rest=%.0f | %s",
                _sgt_era_decade,
                _sgt_mat_str,
                _sgt_is_studio,
                float(_pmgg_restorability_score),
                " ".join(f"{k}={v:.3f}" for k, v in sorted(self._song_goal_targets.items())),
            )
        except Exception as _sgt_err:
            logger.warning("§09.2 SongGoalTargets failed (canonical fallback): %s", _sgt_err)
            self._song_goal_targets = None

        # §2.54 Pre-Pipeline Physical Ceiling — gecappte PMGG-Targets für per-Phase Nutzung.
        # Berechnet PhysicalCeiling auf dem Eingabe-Audio (degradiert) um die Signal-SNR-
        # und Bandbreiten-basierten Goal-Obergrenzen zu ermitteln. Combined mit SGT ergibt
        # min(SGT, ceiling) pro Goal — verhindert, dass PMGG Ziele fordert die physikalisch
        # unerreichbar sind (z.B. brillanz > 0.75 für Shellac-8kHz-Signal).
        self._pmgg_ceiling_capped_targets = None
        try:
            if isinstance(getattr(self, "_song_goal_targets", None), dict) and self._song_goal_targets:
                from backend.core.physical_ceiling_estimator import PhysicalCeilingEstimator as _EarlyPCE

                _pce_mat_key = _sgt_mat_str if "_sgt_mat_str" in dir() else ""
                _pce_audio = _analysis_audio if _analysis_audio.ndim <= 2 else _analysis_audio[:2]  # max stereo
                _pce_result = _EarlyPCE().estimate(_pce_audio, sample_rate, {}, _pce_mat_key)
                _pce_ceiling = _pce_result.ceiling  # dict[str, float]
                # min(SGT, ceiling) per goal — ceiling-cap only when ceiling < SGT
                self._pmgg_ceiling_capped_targets = {
                    g: float(min(v, _pce_ceiling[g]) if g in _pce_ceiling else v)
                    for g, v in self._song_goal_targets.items()
                }
                _capped_log = [
                    f"{g}:{self._song_goal_targets[g]:.3f}→{self._pmgg_ceiling_capped_targets[g]:.3f}"
                    for g in self._pmgg_ceiling_capped_targets
                    if abs(self._pmgg_ceiling_capped_targets[g] - self._song_goal_targets[g]) > 0.005
                ]
                if _capped_log:
                    logger.info(
                        "§2.54 PrePipelineCeiling: mat=%s bw=%.0f Hz → ceiling caps: %s",
                        _pce_mat_key,
                        _pce_result.effective_bandwidth_hz,
                        ", ".join(_capped_log[:6]),
                    )
                else:
                    self._pmgg_ceiling_capped_targets = dict(self._song_goal_targets)
        except Exception as _ppc_err:
            logger.debug("§2.54 PrePipelineCeiling fehlgeschlagen (SGT-Fallback): %s", _ppc_err)
            self._pmgg_ceiling_capped_targets = (
                dict(self._song_goal_targets) if isinstance(getattr(self, "_song_goal_targets", None), dict) else None
            )

        if _pass_through_mode:
            if _clean_digital_mode and not (_input_snr_db > 40.0 and _max_defect_severity < 0.15):
                logger.info(
                    "🛡️ Clean-Digital-Guard §8.2: material=%s, flatness=%.5f, bw=%.0f Hz, dyn=%.2f dB"
                    " → Schonmodus aktiv trotz konservativer SNR-Heuristik (%.1f dB)",
                    _clean_digital_metrics.get("material", "unknown"),
                    float(_clean_digital_metrics.get("flatness_median", 0.0)),
                    float(_clean_digital_metrics.get("effective_bandwidth_hz", 0.0)),
                    float(_clean_digital_metrics.get("dyn_std_db", 0.0)),
                    _input_snr_db,
                )
            else:
                logger.info(
                    "🛡️ Pass-Through-Guard §8.2: SNR=%.1f dB, max_defect=%.3f → Schonmodus aktiv"
                    " (PQS-MOS-Verlust ≤ 0.05, LUFS-Δ ≤ 0.3 LU)",
                    _input_snr_db,
                    _max_defect_severity,
                )

        # §2.45b Hochrestorabilität-Gate — Metadata-Flag für transparentes Reporting
        if _pmgg_restorability_score > 80 and _input_snr_db > 40.0:
            self._metadata["high_restorability_gate"] = True

        # Step 2: Phase Selection (basierend auf Defekten)
        _cb(16, "Phasenauswahl…")
        logger.info("Step 2/4: Phase Selection...")
        if _precomputed_phase_plan:
            # §PID: PhaseInteractionDenker hat Orchestrierung übernommen.
            # UV3 verwendet den extern berechneten Plan deterministisch.
            # Keine autonome _select/_optimize-Planung mehr, damit Denker-Plan
            # und UV3-Ausführung nicht auseinanderlaufen.
            # §2.53b: Phase Skipping deaktiviert — als erstes loggen damit auch bei frühem Mock-Return sichtbar
            logger.info("Phase Skipping deaktiviert: precomputed_phase_plan aktiv (deterministischer PID-Executor)")
            logger.info(
                "§PID PhaseInteractionDenker-Plan aktiv: %d Phasen (UV3 _select/_optimize übersprungen)",
                len(_precomputed_phase_plan),
            )
            # Verhindert Stale-State aus vorherigen restore()-Läufen.
            self._last_material_priority_phases = ()
            selected_phases = list(_precomputed_phase_plan)
        else:
            # Kein Denker-Plan — UV3 selektiert und optimiert autonom (Legacy/fail-safe).
            selected_phases = self._select_phases(
                defect_result,
                causal_plan=_causal_plan,
                chain_info=self._active_chain_info,
                defekt_hint=self._active_defekt_hint,
                audio=_analysis_audio,
                sr=sample_rate,
                goal_weights=getattr(self, "_song_goal_weights", None),
            )
            # Kein Denker-Plan — UV3 optimiert autonom (Legacy-Pfad / fail-safe).
            selected_phases = self._optimize_phase_plan_intelligence(
                selected_phases,
                causal_plan=_causal_plan,
                pipeline_confidence=_pipeline_confidence,
                restorability_score=_pmgg_restorability_score,
            )
        logger.info("Selected %s phases based on defects", len(selected_phases))
        _runtime_never_skip_phases: list[str] = list(getattr(self, "_last_material_priority_phases", ()) or ())

        # §7.5a [RELEASE_MUST] Phase-DAG-Validierung — HARD_BEFORE-Constraints prüfen
        try:
            from backend.core.phase_dag import (
                validate_phase_order as _validate_phase_order,
            )

            _dag_violations = _validate_phase_order(selected_phases)
            if _dag_violations:
                logger.warning(
                    "§7.5a Phase-DAG: %d HARD_BEFORE-Verletzung(en): %s",
                    len(_dag_violations),
                    "; ".join(_dag_violations[:3]),
                )
                if isinstance(getattr(self, "_phase_metadata_accumulator", None), dict):
                    self._phase_metadata_accumulator["dag_violations"] = _dag_violations
            else:
                logger.debug("§7.5a Phase-DAG: keine Reihenfolge-Verletzungen")
        except Exception as _dag_exc:
            logger.debug("§7.5a Phase-DAG-Validierung non-blocking: %s", _dag_exc)

        # §2.52b [RELEASE_MUST] SongStructureAnalyzer — Segmentstruktur vor Phase-Loop
        self._ssa_segments = None
        try:
            from backend.core.song_structure_analyzer import (
                get_song_structure_analyzer,
            )

            _ssa_audio = audio
            _ssa_panns = float(getattr(self, "_panns_singing", 0.0))
            self._ssa_segments = get_song_structure_analyzer().analyze_structure(
                _ssa_audio, sample_rate, panns_singing_confidence=_ssa_panns
            )
            if self._ssa_segments:
                _n_climax = sum(1 for s in self._ssa_segments if s.is_climax)
                _n_verse = sum(1 for s in self._ssa_segments if s.label == "verse")
                logger.info(
                    "§2.52b SongStructure: %d Segmente, %d Klimax, %d Strophen",
                    len(self._ssa_segments),
                    _n_climax,
                    _n_verse,
                )
                if isinstance(getattr(self, "_phase_metadata_accumulator", None), dict):
                    self._phase_metadata_accumulator["song_structure"] = {
                        "n_segments": len(self._ssa_segments),
                        "n_climax": _n_climax,
                        "n_verse": _n_verse,
                        "labels": [s.label for s in self._ssa_segments],
                    }
        except Exception as _ssa_exc:
            logger.debug("§2.52b SongStructureAnalyzer non-blocking: %s", _ssa_exc)

        # §2.50 Material-Adaptive Gate Baseline: Stereo-Feldanalyse vor Pipeline.
        # Erkennt pre-existing Trägerkettenprobleme im Quellmaterial und injiziert
        # Remediation-Phasen (phase_14/phase_15) wenn nötig, bevor Phase-Skipping greift.
        try:
            if _src_baseline is not None and _src_baseline.has_critical_stereo_issue:
                _stereo_remedy_phases = [
                    "phase_14_phase_correction",
                    "phase_15_stereo_balance",
                ]
                _sel_set_250 = set(selected_phases)
                _injected_250: list[str] = []
                for _sp250 in _stereo_remedy_phases:
                    if _sp250 not in _sel_set_250:
                        selected_phases.append(_sp250)
                        _sel_set_250.add(_sp250)
                        _injected_250.append(_sp250)
                        if _sp250 not in _runtime_never_skip_phases:
                            _runtime_never_skip_phases.append(_sp250)
                if _injected_250:
                    logger.warning(
                        "§2.50 Stereo-Notfall-Remediation: ratio=%.2f, mean_compat=%.3f → injiziert: %s",
                        _src_baseline.phase_cancellation_ratio,
                        _src_baseline.stereo_mono_compat_mean,
                        _injected_250,
                    )
            elif _src_baseline is not None and _src_baseline.has_anti_phase_region:
                # Teilweise Anti-Phasigkeit: nur phase_14 (Phase-Korrektur)
                if "phase_14_phase_correction" not in set(selected_phases):
                    selected_phases.append("phase_14_phase_correction")
                    if "phase_14_phase_correction" not in _runtime_never_skip_phases:
                        _runtime_never_skip_phases.append("phase_14_phase_correction")
                    logger.info("§2.50 Anti-Phasen-Region erkannt → phase_14_phase_correction aktiviert")
        except Exception as _sb250_exc:
            logger.debug("§2.50 Source-Baseline-Messung fehlgeschlagen: %s", _sb250_exc)
        # Baseline für Pipeline speichern (Übergabe an _execute_pipeline via self)
        self._source_material_baseline = _src_baseline

        # §2.60 STCG Pre-Pipeline: Correct any pre-existing inter-channel delay BEFORE the
        # phase pipeline runs. This prevents all 64 phases from operating on mis-aligned stereo.
        # For mono audio this is a no-op. Non-blocking: an exception never stops the pipeline.
        if audio.ndim == 2:
            try:
                from backend.core.stereo_temporal_coherence_guard import (
                    get_stereo_temporal_coherence_guard as _get_stcg_pre,
                )

                audio = _get_stcg_pre().correct_interchannel_delay(audio, sample_rate, phase_id="pre_pipeline")
            except Exception as _stcg_pre_exc:
                logger.debug("§2.60 STCG pre-pipeline fehlgeschlagen (non-blocking): %s", _stcg_pre_exc)

        # §LAG_PROBE_1: nach STCG pre-pipeline — GCC-PHAT O(n log n)
        try:
            if audio.ndim == 2:
                from backend.file_import import _estimate_interchannel_lag_samples as _gcc_lag

                _lp_lag = _gcc_lag(audio, sample_rate)
                logger.info(
                    "LAG_PROBE 1/after_stcg_pre: lag=%d samples (%.1f ms)", _lp_lag, _lp_lag / sample_rate * 1000
                )
        except Exception as _lp1_exc:
            logger.debug("LAG_PROBE_1 fehlgeschlagen: %s", _lp1_exc)

        try:
            _recovery_certainty_profile = UnifiedRestorerV3._compute_recovery_certainty_profile(
                restorability_score=float(_pmgg_restorability_score),
                source_material_baseline=_src_baseline,
                transfer_generation_count=(
                    int(_sgi_gen_count) if isinstance(locals().get("_sgi_gen_count", None), (int, float)) else None
                ),
                material_key=str(getattr(material_type, "value", material_type)),
            )
        except Exception as _rcp_exc:
            logger.debug("Recovery-certainty profile fallback (non-blocking): %s", _rcp_exc)
            _recovery_certainty_profile = {
                "recoverability_ceiling": 0.65,
                "uncertainty_index": 0.35,
                "conservative_audio_scalar": 0.92,
                "confidence_band": "medium",
                "restorability_score": float(_pmgg_restorability_score),
                "transfer_generation_count": 1,
                "hf_loss_db": None,
            }
        self._recovery_certainty_profile = dict(_recovery_certainty_profile)
        self._global_conservative_scalar = float(
            np.clip(self._recovery_certainty_profile.get("conservative_audio_scalar", 1.0), 0.78, 1.0)
        )
        logger.info(
            "RecoveryCertainty: ceiling=%.3f uncertainty=%.3f scalar=%.3f band=%s",
            float(self._recovery_certainty_profile.get("recoverability_ceiling", 0.0)),
            float(self._recovery_certainty_profile.get("uncertainty_index", 0.0)),
            float(self._global_conservative_scalar),
            str(self._recovery_certainty_profile.get("confidence_band", "unknown")),
        )

        # §6.7 Dolby-NR-Typ + Konfidenz aus DefectResult in _restoration_context injizieren,
        # damit phase_04 über kwargs.get("dolby_nr_type") die korrekte Inverse anwenden kann.
        if defect_result is not None and hasattr(defect_result, "scores"):
            try:
                _dolby_ds = defect_result.scores.get(DefectType.DOLBY_NR_MISMATCH)
                if _dolby_ds is not None and getattr(_dolby_ds, "severity", 0.0) > 0.10:
                    _dolby_meta = getattr(_dolby_ds, "metadata", {}) or {}
                    _dnr_type = _dolby_meta.get("dolby_nr_type", "none")
                    if _dnr_type and _dnr_type != "none":
                        self._restoration_context["dolby_nr_type"] = _dnr_type
                        self._restoration_context["dolby_nr_confidence"] = float(getattr(_dolby_ds, "confidence", 0.65))
                        logger.info(
                            "§6.7 Dolby-NR-Injektion: type=%s conf=%.2f sev=%.2f",
                            _dnr_type,
                            self._restoration_context["dolby_nr_confidence"],
                            float(_dolby_ds.severity),
                        )
            except Exception as _dolby_exc:
                logger.debug("§6.7 Dolby-NR-Extraktion fehlgeschlagen: %s", _dolby_exc)

        # §2.8 Vocal-Chain: vocal_gender in RestorationContext injizieren
        # → wird automatisch via _profiled_phase_call in ALLE Phase-kwargs aufgenommen
        _vg = getattr(self, "_detected_vocal_gender", None)
        if _vg and _vg != "unknown":
            self._restoration_context["vocal_gender"] = _vg

        # Step 2.5: Apply Phase Skipping (intelligent filtering)
        _enable_phase_skipping = bool(self.phase_skipper)
        if _pipeline_confidence is not None and float(_pipeline_confidence.confidence) < 0.55:
            _enable_phase_skipping = False
            logger.info(
                "Phase Skipping deaktiviert: niedrige Pipeline-Konfidenz (%.2f < 0.55)",
                float(_pipeline_confidence.confidence),
            )
        if _pmgg_restorability_score < 40.0:
            _enable_phase_skipping = False
            logger.info(
                "Phase Skipping deaktiviert: niedrige Restaurierbarkeit (%.1f < 40.0)",
                _pmgg_restorability_score,
            )
        if _precomputed_phase_plan:
            _enable_phase_skipping = False
            # §2.53b: immer loggen — auch wenn phase_skipper=None (dann war _enable_phase_skipping
            # bereits False, aber der Test braucht den Log-Eintrag als Beweis)
            logger.info("Phase Skipping deaktiviert: precomputed_phase_plan aktiv (deterministischer PID-Executor)")
        elif not self.phase_skipper and not _precomputed_phase_plan:
            pass  # phase_skipper=None + kein precomputed_plan: kein Log nötig

        if _enable_phase_skipping:
            original_count = len(selected_phases)
            selected_phases, skip_reasons = self._apply_phase_skipping(selected_phases, defect_result)
            skipped_count = original_count - len(selected_phases)
            if skipped_count > 0:
                logger.info(
                    "Phase Skipping: %d phases skipped (%.0f%% speedup potential)",
                    skipped_count,
                    skipped_count / original_count * 100,
                )
                for phase_id, reason in skip_reasons.items():
                    logger.debug("  Skipped %s: %s", phase_id, reason)

        # §0a Crossfire + Stem-Enhancement-Invariante (Restoration):
        # aktive Stem-Enhancement-Phasen sind im Restoration-Modus verboten,
        # da sie bei ungünstiger Stem-Separation (negative SDRi) zu Dopplungen,
        # Flüstern/Delay und Überbearbeitung führen können.
        if not self.is_studio_mode():
            _restoration_forbidden_stem_enhancement = {
                "phase_21_exciter",  # §0a: Harmonic Exciter VERBOTEN in Restoration
                "phase_35_multiband_compression",
                "phase_42_vocal_enhancement",
                "phase_56_reference_mastering",
            }
            _removed_restoration_forbidden = [
                p for p in selected_phases if p in _restoration_forbidden_stem_enhancement
            ]
            if _removed_restoration_forbidden:
                selected_phases = [p for p in selected_phases if p not in _restoration_forbidden_stem_enhancement]
                logger.warning(
                    "§0a Restoration-Guard: %d Stem-Enhancement-Phase(n) deaktiviert: %s",
                    len(_removed_restoration_forbidden),
                    _removed_restoration_forbidden,
                )

        if (
            not self.is_studio_mode()
            and not _pass_through_mode
            and os.environ.get("AURIK_BRONZE_RESTORATION_PROFILE", "0").strip().lower() in {"1", "true", "yes", "on"}
        ):
            _bronze_material_key = material_type.value if hasattr(material_type, "value") else str(material_type)
            selected_phases, _bronze_removed = self._apply_bronze_restoration_minimal_pipeline(
                selected_phases,
                _runtime_never_skip_phases,
                _bronze_material_key,
            )
            if _bronze_removed:
                logger.warning(
                    "Bronze-Minimal-Guard: restoration material=%s"
                    " -> %d Phase(n) deaktiviert, %d defensive Kernphasen verbleiben: %s",
                    _bronze_material_key,
                    len(_bronze_removed),
                    len(selected_phases),
                    _bronze_removed,
                )

        # §8.2 Pass-Through: nur minimale Phasen (LUFS-Norm + TruePeak) für sauberes Material
        if _pass_through_mode:
            _pt_allowed = {
                "phase_30_dc_offset_removal",
                "phase_40_loudness_normalization",
                "phase_41_output_format_optimization",
                "phase_47_truepeak_limiter",
            }
            _pt_removed = [p for p in selected_phases if p not in _pt_allowed]
            selected_phases = [p for p in selected_phases if p in _pt_allowed]
            if _pt_removed:
                logger.info(
                    "🛡️ Pass-Through-Guard: %d Phasen deaktiviert → %d minimal-Phasen verbleiben",
                    len(_pt_removed),
                    len(selected_phases),
                )

        # §8.2 Leichtpfad: Fast perfektes Material (restorability ≥ 85, Defekte ≤ 0.25)
        # bekommt NUR Defektkorrektur (Tier 0+1) + Finalisierung (Tier 6) — kein Enhancement.
        # Verhindert unnötige Klangveränderung bei qualitativ hochwertigen Aufnahmen,
        # die aber doch leichte Defekte aufweisen (nicht pass-through-tauglich).
        # §0a: Studio 2026 ist explizit ausgenommen — volle Enhancement-Kette Pflicht.
        if (
            not _pass_through_mode
            and not self.is_studio_mode()
            and _pmgg_restorability_score >= 85.0
            and _max_defect_severity <= 0.25
            and not _localized_critical
        ):
            _leichtpfad_keep = {
                # Tier 0 — Basis-Vorbereitung
                "phase_30_dc_offset_removal",
                "phase_08_transient_preservation",
                # Tier 1 — Defektkorrektur (alle defektspezifischen Phasen behalten)
                "phase_01_declipping",
                "phase_02_dehum",
                "phase_03_denoise",
                "phase_04_eq_correction",
                "phase_05_rumble_removal",
                "phase_09_crackle_removal",
                "phase_10_compression_repair",
                "phase_11_limiting_repair",
                "phase_12_wow_flutter_fix",
                "phase_13_azimuth_correction",
                "phase_14_stereo_repair",
                "phase_15_channel_balance",
                "phase_17_distortion_reduction",
                "phase_18_noise_gate",
                "phase_19_de_esser",
                "phase_20_reverb_reduction",
                "phase_22_speed_correction",
                "phase_24_dropout_repair",
                "phase_25_declick",
                "phase_27_sibilance_control",
                "phase_29_tape_hiss_reduction",
                "phase_31_pitch_drift",
                "phase_43_ml_deesser",
                "phase_49_advanced_dereverb",
                "phase_50_spectral_repair",
                "phase_55_diffusion_inpainting",
                "phase_56_spectral_band_gap",
                "phase_59_modulation_noise",
                "phase_60_inner_groove_distortion",
                "phase_61_groove_echo",
                "phase_62_crosstalk_bleed",
                "phase_63_intermodulation_distortion",
                "phase_64_tape_splice",
                # Tier 6 — Finalisierung
                "phase_40_loudness_normalization",
                "phase_41_output_format_optimization",
                "phase_47_truepeak_limiter",
                "phase_53_semantic_audio",
            }
            _lp_removed = [p for p in selected_phases if p not in _leichtpfad_keep]
            if _lp_removed:
                selected_phases = [p for p in selected_phases if p in _leichtpfad_keep]
                logger.info(
                    "🛡️ Leichtpfad: restorability=%.1f, max_defect=%.3f → %d Enhancement-Phasen "
                    "deaktiviert, %d Defektkorrektur+Finalisierungs-Phasen verbleiben",
                    _pmgg_restorability_score,
                    _max_defect_severity,
                    len(_lp_removed),
                    len(selected_phases),
                )

        # §2.20 Genre-Profil-Override-Invariante (v9.10.102): Harter Phase-Block via *_enabled: False
        # Wird NACH CausalDefectReasoner und Phase-Selection angewendet.
        # Genre-Profil hat absolute Priorität über CausalDefectReasoner für *_enabled: False-Keys.
        # Invariante: Selbst bei Defekt-Score > 0.85 (kritisch) bleibt der Override final —
        # nur ein manueller Studio-2026-Modus darf diesen Override aufheben (kein automatischer Bypass).
        if _genre_profile:
            for _gp_key, _gp_val in _genre_profile.items():
                if _gp_key.endswith("_enabled") and _gp_val is False:
                    # Map key → phase_id prefix; e.g. "phase_20_dereverb_enabled" → "phase_20_"
                    _gp_phase_prefix = _gp_key[: -len("_enabled")]  # "phase_20_dereverb"
                    _gp_phase_prefix_base = "_".join(_gp_phase_prefix.split("_")[:2]) + "_"  # "phase_20_"
                    _gp_blocked = [
                        p for p in selected_phases if p == _gp_phase_prefix or p.startswith(_gp_phase_prefix_base)
                    ]
                    if _gp_blocked:
                        selected_phases = [p for p in selected_phases if p not in _gp_blocked]
                        for _gp_bp in _gp_blocked:
                            logger.info(
                                "genre_profile_override: phase=%s disabled by genre=%s (key=%s)",
                                _gp_bp,
                                _genre_profile.get("gp_memory_key", "unknown"),
                                _gp_key,
                            )

        # Step 3: Performance Guard Setup
        audio_duration = audio.shape[-1] / sample_rate  # shape[-1] works for both mono (N,) and stereo (2, N)
        if self.performance_guard:
            self.performance_guard.start_monitoring(audio_duration)
            self.performance_guard.set_never_skip_phases(_runtime_never_skip_phases)

        # §Vintage-Authentizitäts-Guards — Ära-spezifische Phase-Filter + Strength-Caps
        # Spec (copilot-instructions.md):
        #   1920–1940: Rolloff ≤ 7 kHz NICHT künstlich erweitern; AudioSR nur user_requested
        #              H2/H4 Röhren-Kompression ∈ [−30,−20] dBr BEWAHREN (SOFT_SATURATION → Skip)
        #   1940–1955: Tape-Saturation-Fingerabdruck NICHT entfernen; phase_22 nur emulieren
        #   1955–1965: RT60 ∈ [1.2, 2.0] s bewahren — phase_20/phase_49 strength ≤ 0.20
        #   1965–1975: Tape-Saturation-Signatur NICHT entfernen; Vintage-Kompressor-Imprint bewahren
        _vintage_phase_strength_caps: dict = {}  # {phase_id: max_strength}
        if _era_result is not None:
            _vintage_decade = _era_result.decade
            if _vintage_decade <= 1940:
                # 1920–1940: Blockiere künstliche BW-Erweiterung (EAPC übernimmt §2.35)
                _bw_phases_to_guard = {"phase_06_frequency_restoration"}
                _removed_vintage = [p for p in selected_phases if p in _bw_phases_to_guard]
                if _removed_vintage:
                    selected_phases = [p for p in selected_phases if p not in _bw_phases_to_guard]
                    logger.info(
                        "🕰️ Vintage-Guard decade=%d ≤ 1940: %s deaktiviert — "
                        "EAPC (§2.35) übernimmt ära-authentische HF-Ergänzung",
                        _vintage_decade,
                        ", ".join(_removed_vintage),
                    )
                # SOFT_SATURATION-Schutz: phase_23 (Clipping-Repair) nur bei echtem CLIPPING
                # (wird bereits durch classify_clipping() in phase_23 selbst gesteuert)
                logger.debug(
                    "🕰️ Vintage-Guard decade=%d ≤ 1940: H2/H4 Röhren-Kompression bewahren "
                    "(SOFT_SATURATION-Guard aktiv, phase_22 emuliert nicht entfernen)",
                    _vintage_decade,
                )
            if 1940 <= _vintage_decade < 1955:
                # 1940–1955: Tape-Saturation NICHT entfernen — phase_22 strength nach oben cap
                # Originaler Tape-Fingerabdruck muss erhalten bleiben (nur emulieren)
                _vintage_phase_strength_caps["phase_22_tape_saturation"] = 0.30
                logger.debug(
                    "🕰️ Vintage-Guard 1940–1955: phase_22 strength ≤ 0.30 (Tape-Fingerabdruck erhalten)",
                )
            if 1955 <= _vintage_decade < 1965:
                # 1955–1965: RT60 ∈ [1.2, 2.0] s bewahren — Dereverb-Stärke begrenzen
                _vintage_phase_strength_caps["phase_20_reverb_reduction"] = 0.20
                _vintage_phase_strength_caps["phase_49_advanced_dereverb"] = 0.20
                logger.info(
                    "🕰️ Vintage-Guard decade=%d (1955–1965): phase_20/phase_49 strength ≤ 0.20 "
                    "(RT60 ∈ [1.2, 2.0] s erhalten)",
                    _vintage_decade,
                )
            if 1965 <= _vintage_decade < 1975:
                # 1965–1975: Tape-Saturation-Signatur + VCA-Kompressor-Imprint NICHT entfernen
                _vintage_phase_strength_caps["phase_22_tape_saturation"] = 0.35
                _vintage_phase_strength_caps["phase_10_compression"] = 0.40
                logger.debug(
                    "🕰️ Vintage-Guard 1965–1975: Tape-Sat ≤ 0.35, Kompressor-Imprint ≤ 0.40 (VCA-Charakter bewahren)",
                )

        # §2.28 HPG Pre-Phase: Harmonik-Referenz aus Original sichern (Spec: G_floor vor Phase-03)
        _hpg_pre_mask: Any = None
        _hpg_pre_href: Any = None
        _hpg_skip_materials_pre = {"shellac", "wax_cylinder"}
        if material_type.value not in _hpg_skip_materials_pre:
            try:
                from backend.core.harmonic_preservation_guard import (
                    get_harmonic_preservation_guard as _get_hpg_pre,
                )

                _hpg_tmp = _get_hpg_pre()
                _hpg_instrument_tag_pre = {
                    "vinyl": "piano_mid",
                    "tape": "piano_mid",
                    "reel_tape": "piano_mid",
                    "cd_digital": "piano_mid",
                    "mp3_low": "piano_mid",
                    "mp3_high": "piano_mid",
                    "aac": "piano_mid",
                    "dat": "piano_mid",
                    "minidisc": "piano_mid",
                }.get(material_type.value, "unknown")
                _hpg_pre_mask, _hpg_pre_href = _hpg_tmp.extract_harmonic_mask(
                    original_audio_for_goals, sample_rate, instrument_tag=_hpg_instrument_tag_pre
                )
                logger.debug("§2.28 HPG Pre-Phase: Harmonik-Referenz extrahiert (tag=%s)", _hpg_instrument_tag_pre)
            except Exception as _hpg_pre_exc:
                logger.debug("HPG Pre-Phase-Extraktion nicht verfügbar: %s", _hpg_pre_exc)

        # §2.36 LGE Pre-Phase: Transkription auf Originalaudio (genauere Phonemkarte als auf NR-Output)
        _lge_trans_pre: Any = None
        _lge_saliency_for_eap: np.ndarray | None = None  # §2.36/§2.44: Lyrics-Salienz für EAP
        try:
            from backend.core.lyrics_guided_enhancement import (
                get_lyrics_guided_enhancement as _get_lge_pre,
            )

            _, _lge_trans_pre = _get_lge_pre().enhance(original_audio_for_goals, sample_rate)
            logger.debug(
                "§2.36 LGE Pre-Phase: Phonemkarte aus Originalaudio (%d Segmente)",
                len(_lge_trans_pre.words) if _lge_trans_pre is not None else 0,
            )
        except Exception as _lge_p_exc:
            logger.debug("LGE Pre-Phase-Transkription nicht verfügbar: %s", _lge_p_exc)

        # §2.36a PhonemeTimeline: aus Pre-Phase-Transkription für Phase-Consumer aufbauen.
        # Phasen 19, 24, 43, 56 und MDEM konsumieren diese für phoneme-targeted Verarbeitung.
        _phoneme_timeline: Any = None
        try:
            from backend.core.phoneme_timeline import PhonemeTimeline as _PTL

            if _lge_trans_pre is not None:
                _phoneme_timeline = _PTL.build_from_transcription(
                    _lge_trans_pre,
                    getattr(_lge_trans_pre, "language", "unknown"),
                )
            else:
                _n_samp_ptl = (
                    original_audio_for_goals.shape[-1]
                    if original_audio_for_goals.ndim == 2
                    else len(original_audio_for_goals)
                )
                _dur_ptl = float(_n_samp_ptl) / max(1, sample_rate)
                _phoneme_timeline = _PTL.build_empty(duration_s=_dur_ptl)
            logger.info(
                "§2.36a PhonemeTimeline: language=%s conf=%.2f segments=%d",
                getattr(_phoneme_timeline, "language", "?"),
                getattr(_phoneme_timeline, "language_confidence", 0.0),
                len(getattr(_phoneme_timeline, "segments", [])),
            )
        except Exception as _ptl_exc:
            _phoneme_timeline = None
            logger.debug("PhonemeTimeline nicht verfügbar: %s", _ptl_exc)

        # Step 4: Execute Phases — mit EnsembleProcessor-Konsens (§2.21)
        logger.info("Step 3/4: Executing Restoration Pipeline (EnsembleProcessor)...")
        # §11.4 Stufen-Vorab-Meldung: Gesamtzahl der UV3-Phasen ans Frontend melden,
        # damit die Anzeige "Stufe X / Y" von Anfang an korrekt ist (kein Hochzählen).
        _cb(19, f"__total_uv3_phases__:{len(selected_phases)}")
        _cb(20, "Pipeline startet…")
        # §Vintage: Strength-Caps als Instanzvariable setzen (für _profiled_phase_call Zugriff)
        self._vintage_phase_strength_caps = _vintage_phase_strength_caps
        # §2.31 Material-adaptive Phasen-Initialstärken aufbauen (DefectPhaseMapper._MATERIAL_PHASE_FACTORS)
        # Kombiniert Vintage-Era-Caps mit materialspezifischen Stärke-Faktoren:
        # Nimmt jeweils das Minimum beider Quellen (restriktiverer Wert gewinnt).
        _material_phase_initial_strengths: dict[str, float] = {}
        try:
            from backend.core.defect_phase_mapper import get_material_initial_strength as _get_mat_strength
            from backend.core.material_canonical import canonical_material_key as _canonical_material_key

            _mat_val = _canonical_material_key(material_type)
            # Alle bekannten Phase-IDs aus beiden Quellen konsolidieren
            _all_phase_ids = set(_vintage_phase_strength_caps.keys())
            # Alle Phase-IDs aus MaterialPhaseFactors für dieses Material ermitteln
            try:
                from backend.core.defect_phase_mapper import _MATERIAL_PHASE_FACTORS as _MPF

                _all_phase_ids.update(_MPF.get(_mat_val, {}).keys())
            except Exception as _mpf_exc:
                logger.debug("MaterialPhaseFactors-Import fehlgeschlagen: %s", _mpf_exc)
            for _pid in _all_phase_ids:
                _mat_s = _get_mat_strength(_mat_val, _pid)
                _era_cap = _vintage_phase_strength_caps.get(_pid, 1.0)
                # Restriktiverer Wert: Minimum beider Quellen
                _combined = min(_mat_s, _era_cap)
                if _combined < 1.0:
                    _material_phase_initial_strengths[_pid] = _combined
            if _material_phase_initial_strengths:
                logger.debug(
                    "§2.31 Material-Phase-Initialstärken: %d Phasen angepasst für material=%s",
                    len(_material_phase_initial_strengths),
                    _mat_val,
                )
        except Exception as _mps_exc:
            logger.debug("Material-Phase-Initialstärken-Aufbau fehlgeschlagen: %s", _mps_exc)
        self._material_phase_initial_strengths = _material_phase_initial_strengths
        # §2.39 OOM-Recovery: Kontext für Checkpoint-Speicherung bei MemoryError bereitstellen.
        # _execute_pipeline hat keinen Zugriff auf input_path/output_path/mode — daher hier cachen.
        _mode_str = self.config.mode.value if hasattr(self.config.mode, "value") else str(self.config.mode)
        self._recovery_ctx = {
            "input_path": kwargs.get("input_path", "") or kwargs.get("file_path", ""),
            "output_path": kwargs.get("output_path", ""),
            "mode": _mode_str,
            "era_decade": getattr(_era_result, "decade", None) if _era_result is not None else None,
            "restorability_score": _pmgg_restorability_score,
            "defect_result": defect_result,
        }
        # §Safety: PLM-Eviction während Pipeline sperren — ONNX-Session-Destruktoren
        # dürfen nicht zeitgleich mit laufender Inferenz feuern (double-free-Crash).
        try:
            from backend.core.plugin_lifecycle_manager import set_pipeline_active

            set_pipeline_active(True)
        except Exception as _spa_exc:
            logger.debug("set_pipeline_active(True) fehlgeschlagen: %s", _spa_exc)
        if (
            _audio_update_cb_kwarg is not None
            and _tdp_proc is not None
            and _tdp_percussive is not None
            and _tdp_harmonic_ready
        ):

            def _phase_audio_update_callback(_phase_audio: np.ndarray, _phase_sr: int, _phase_id: str) -> None:
                _preview_audio = _phase_audio
                try:
                    if isinstance(_phase_audio, np.ndarray) and _phase_audio.shape == _tdp_percussive.shape:
                        _preview_audio = _tdp_proc.recombine(
                            _tdp_percussive,
                            _phase_audio,
                            _phase_sr,
                            _tdp_percussive,
                        )
                        _preview_audio = np.clip(
                            np.nan_to_num(_preview_audio, nan=0.0, posinf=0.0, neginf=0.0),
                            -1.0,
                            1.0,
                        )
                except Exception as _phase_cb_exc:
                    logger.debug("TDP preview recombination for audio_update_callback failed: %s", _phase_cb_exc)
                _audio_update_cb_kwarg(_preview_audio, _phase_sr, _phase_id)

        else:
            _phase_audio_update_callback = _audio_update_cb_kwarg

        try:
            _phase_quiet_edge_profile = UnifiedRestorerV3._compute_quiet_edge_prevention_profile(
                original_audio_for_goals,
                sample_rate,
                material_key=str(getattr(material_type, "value", material_type)).lower() if material_type else None,
            )
            restored_audio, executed_phases, skipped_phases, deferred_phases = self._execute_pipeline(
                audio,
                sample_rate,
                material_type,
                defect_result,
                selected_phases,
                progress_callback=progress_callback,
                audio_update_callback=_phase_audio_update_callback,
                restorability_score=_pmgg_restorability_score,  # §2.29 normativ
                applicable_goals=_applicable_goals,  # §2.32 normativ
                material_initial_strengths=_material_phase_initial_strengths,  # §2.31
                quality_mode_override=_pipeline_quality_mode_override,
                no_rt_limit=_no_rt_limit,
                reconstruction_context=_reconstruction_ctx,  # §11.7a: Bereits reparierte Gaps
                phoneme_timeline=_phoneme_timeline,  # §2.36a: PhonemeTimeline für Phasen 19/24/43/56
                pre_transcription=_lge_trans_pre,  # §2.36: LGE pre-computed transcription for phase_58
                graceful_stop_event=self._graceful_stop_event,  # §0c: Watchdog-Graceful-Stop
                original_audio_reference=original_audio_for_goals,
                quiet_edge_profile=_phase_quiet_edge_profile,
            )
        finally:
            try:
                set_pipeline_active(False)
            except Exception as _spa_exc:
                logger.debug("set_pipeline_active(False) fehlgeschlagen: %s", _spa_exc)

        # §LAG_PROBE_2: direkt nach _execute_pipeline (vor STCG post) — GCC-PHAT O(n log n)
        try:
            if restored_audio.ndim == 2:
                from backend.file_import import _estimate_interchannel_lag_samples as _gcc_lag

                _lp2_lag = _gcc_lag(restored_audio, sample_rate)
                logger.info(
                    "LAG_PROBE 2/after_execute_pipeline: lag=%d samples (%.1f ms)",
                    _lp2_lag,
                    _lp2_lag / sample_rate * 1000,
                )
        except Exception as _lp2_exc:
            logger.debug("LAG_PROBE_2 fehlgeschlagen: %s", _lp2_exc)

        # §7 PDV: Collect session summary after pipeline (Ursache 7 telemetry).
        _pdv_session_summary: dict = {}
        try:
            from backend.core.phase_defect_verifier import get_phase_defect_verifier as _get_pdv_sum

            _pdv_session_summary = _get_pdv_sum().get_session_summary()
        except Exception as _pdv_sum_exc:
            logger.debug("§7 PDV summary collection failed (non-blocking): %s", _pdv_sum_exc)
        # v9.10.58: EnsembleProcessor-Block entfernt.
        # v9.10.72: ARE Multi-Pass ebenfalls entfernt. UV3 ist der einzige Processing-Pass.
        # Wissenschaftliche Begründung:
        # - Kaskadierte STFT-Modifikation akkumuliert Rundungsfehler (Ephraim & Malah 1984)
        # - ML-Modelle sind nicht auf eigenen Output trainiert → Domain Shift
        # - FeedbackChain (unten) bietet zielgerichtete iterative Verbesserung

        _cb(86, "Nachbearbeitung…")

        # §2.46c / §6.2c Post-Additive BW-Hard-Cap — Material-Bandbreiten-Ceiling
        _bw_transfer_chain = (
            self._extract_transfer_chain_from_forensics(
                (getattr(self, "_strict_autosetup_policy", {}) or {}).get("transfer_chain")
            )
            or []
        )
        restored_audio, _bw_guard_applied = self._post_additive_bw_guard(
            restored_audio,
            sample_rate,
            material_type,
            quality_mode=getattr(self, "_quality_mode", None),
            transfer_chain=_bw_transfer_chain or None,
        )

        # §2.60 STCG Post-Pipeline: Final inter-channel verification after all 64 phases.
        # Some phases (phase_21, phase_07, phase_35) process M/S-domain — any residual
        # implementation error could leave a net L-R offset. This guard catches and corrects
        # it before FeedbackChain and HPI evaluate the audio. Non-blocking.
        if restored_audio.ndim == 2:
            try:
                from backend.core.stereo_temporal_coherence_guard import (
                    get_stereo_temporal_coherence_guard as _get_stcg_post,
                )

                restored_audio = _get_stcg_post().correct_interchannel_delay(
                    restored_audio, sample_rate, phase_id="post_pipeline"
                )
            except Exception as _stcg_post_exc:
                logger.debug("§2.60 STCG post-pipeline fehlgeschlagen (non-blocking): %s", _stcg_post_exc)

        # §LAG_PROBE_3: nach STCG post-pipeline — GCC-PHAT O(n log n)
        try:
            if restored_audio.ndim == 2:
                from backend.file_import import _estimate_interchannel_lag_samples as _gcc_lag

                _lp3_lag = _gcc_lag(restored_audio, sample_rate)
                logger.info(
                    "LAG_PROBE 3/after_stcg_post: lag=%d samples (%.1f ms)", _lp3_lag, _lp3_lag / sample_rate * 1000
                )
        except Exception as _lp3_exc:
            logger.debug("LAG_PROBE_3 fehlgeschlagen: %s", _lp3_exc)

        # §0c Graceful-Stop-Tag: wenn Watchdog die Pipeline beendet hat, Metadaten befüllen.
        # Die FeedbackChain und HPI laufen danach nicht (zu aufwändig), stattdessen direkter
        # Export des besten Checkpoint-Ergebnisses mit transparentem Status.
        _graceful_stop_triggered = self._graceful_stop_event.is_set()
        if _graceful_stop_triggered:
            logger.warning(
                "§0c Graceful-Stop: Pipeline vorzeitig beendet — %d Phasen ausgeführt, %d übersprungen. "
                "Bestes Checkpoint-Ergebnis wird direkt exportiert (kein FeedbackChain/HPI).",
                len(executed_phases),
                len(skipped_phases),
            )

        # Speicher-Hygiene: Pipeline-Modelle entladen sobald alle Phasen abgeschlossen.
        # AudioSR (7 GB), LAION-CLAP (2.2 GB) werden nur in der Phase-Pipeline benötigt.
        try:
            from plugins.audiosr_plugin import unload_audiosr

            unload_audiosr()
        except Exception as _unload_exc:
            logger.debug("AudioSR-Unload fehlgeschlagen: %s", _unload_exc)
        try:
            from plugins.laion_clap_plugin import unload_laion_clap

            unload_laion_clap()
        except Exception as _unload_exc:
            logger.debug("LAION-CLAP-Unload fehlgeschlagen: %s", _unload_exc)
        gc.collect()

        # --- §2.33 FeedbackChain-Ceiling: Physikalische Grenze vor FC-Block schätzen ---
        # estimate_physical_ceiling läuft hier mit leerem scores-Dict, da _pqs_result
        # erst nach dem FC-Block verfügbar ist. Das Ceiling basiert primär auf Audio-SNR
        # und Bandbreite, nicht auf goal-Scores — daher trotzdem valid.
        _fc_ceiling_val: float | None = None
        try:
            from backend.core.material_canonical import canonical_material_key as _canonical_material_key
            from backend.core.physical_ceiling_estimator import PhysicalCeilingEstimator as _FCEarly

            _fc_mat_val = _canonical_material_key(material_type)
            _fc_pce_result = _FCEarly().estimate(restored_audio, sample_rate, {}, _fc_mat_val)
            # Natürlichkeit-Ceiling als konservativer Gesamt-Proxy (niedrigster relevanter Wert)
            _fc_ceiling_val = float(_fc_pce_result.ceiling.get("natuerlichkeit", 0.98))
            logger.debug("§2.33 FC-Ceiling (vor FeedbackChain): natuerlichkeit=%.3f", _fc_ceiling_val)
        except Exception as _fc_pce_err:
            logger.debug("FeedbackChain Ceiling-Vorschätzung nicht verfügbar: %s", _fc_pce_err)

        # --- FeedbackChain: Iterativer Qualitätsregelkreis nach Pipeline (§2.2 Spec) ---
        # Post-Pipeline-Korrekturphasen: FinalEQ → MasteringPolish → LUFSNorm
        # FeedbackChain prüft nach jeder Phase den PQS-Score und behält bei
        # Regression das beste Zwischenergebnis (§9.5 Pflicht-Invariante).
        _fc_chain_result = None
        try:
            from backend.core.feedback_chain import FeedbackChain

            # §0c Graceful-Stop: FeedbackChain überspringen — bestes Checkpoint direkt exportieren.
            if _graceful_stop_triggered:
                logger.info("§0c Graceful-Stop: FeedbackChain übersprungen — partial-best-checkpoint export")
                raise RuntimeError("__graceful_stop_skip_feedback_chain__")

            _fc_phase_ids = [
                "phase_07_harmonic_restoration",  # Harmonik-Kohärenz frühzeitig stabilisieren
                "phase_14_phase_correction",  # Phasenfehler vor Mastering-Phasen korrigieren
                "phase_16_final_eq",
                "phase_17_mastering_polish",
                "phase_40_loudness_normalization",
            ]
            _fc_phases_list = []
            for _fc_pid in _fc_phase_ids:
                _fc_phase_obj = self._get_phase(_fc_pid)
                if _fc_phase_obj is not None:
                    # Closure-Fabrik verhindert Late-Binding-Bug in Schleife
                    def _make_fc_callable(_ph):
                        def _fc_call(_audio: np.ndarray, _sr: int, **_kw) -> np.ndarray:
                            _res = self._profiled_phase_call(
                                _ph,
                                _audio,
                                sample_rate=_sr,
                                material_type=material_type,
                                material=material_type,
                                defect_scores=defect_result.scores,
                                quality_mode=self.config.mode.value,
                            )
                            return _res.audio if hasattr(_res, "audio") else _audio

                        return _fc_call

                    _fc_phases_list.append(
                        (
                            int(_fc_pid.split("_")[1]),
                            _make_fc_callable(_fc_phase_obj),
                            {},
                        )
                    )

            # §2.47 Deferred-Phase-Promotion: RT-gedefererte P3-P5-Enhancement-Phasen
            # ergänzen die FeedbackChain-Liste. FeedbackChain prüft via MOS-δ (Iteration 2)
            # ob sie helfen — unhelpful phases werden gepruned (δ < -0.01).
            # Nur whitelisted Enhancement-Phasen: keine Reparatur-Phasen, §0-konform.
            _DEFERRED_FC_WHITELIST: frozenset[str] = frozenset(
                {
                    "phase_19",  # De-esser → artikulation (P2), transparenz (P4)
                    "phase_22",  # Dynamic Enhancement → micro_dynamics (P3), groove (P3)
                    "phase_36",  # Log-Envelope Smoothing → micro_dynamics (P3), emotionalitaet
                    "phase_47",  # Timbre Restoration → waerme (P4), timbre_authentizitaet
                    "phase_48",  # Stereo Imaging → spatial_depth (P5), separation_fidelity (P4)
                    "phase_55",  # Spectral Band Enhancement → brillanz (P5), bass_kraft (P4)
                }
            )
            _fc_already_nums: frozenset[int] = frozenset(num for num, _, _ in _fc_phases_list if isinstance(num, int))

            def _dfr_make_callable(_ph: object) -> object:
                """Closure-Fabrik für Deferred-Phase-FeedbackChain-Integration."""

                def _dfr_call(_audio: np.ndarray, _sr: int, **_kw: object) -> np.ndarray:
                    _res = self._profiled_phase_call(
                        _ph,
                        _audio,
                        sample_rate=_sr,
                        material_type=material_type,
                        material=material_type,
                        defect_scores=defect_result.scores,
                        quality_mode=self.config.mode.value,
                    )
                    return _res.audio if hasattr(_res, "audio") else _audio

                return _dfr_call

            _added_deferred: int = 0
            for _dfr_pid in deferred_phases:
                if _added_deferred >= 3:
                    break  # Max 3 Extra-Phasen — §2.45 Minimal-Intervention
                _dfr_parts = str(_dfr_pid).split("_")
                if len(_dfr_parts) < 2:
                    continue
                _dfr_prefix = f"{_dfr_parts[0]}_{_dfr_parts[1]}"  # "phase_22"
                if _dfr_prefix not in _DEFERRED_FC_WHITELIST:
                    continue
                try:
                    _dfr_num = int(_dfr_parts[1])
                except (ValueError, IndexError):
                    continue
                if _dfr_num in _fc_already_nums:
                    continue  # Bereits in FeedbackChain — kein Duplikat
                _dfr_obj = self._get_phase(_dfr_pid)
                if _dfr_obj is None:
                    continue
                _fc_phases_list.append((_dfr_num, _dfr_make_callable(_dfr_obj), {}))
                _fc_already_nums = _fc_already_nums | {_dfr_num}
                _added_deferred += 1
                logger.info(
                    "§2.47 Deferred-Phase-Promotion: %s → FeedbackChain (%d Gesamt)",
                    _dfr_pid,
                    len(_fc_phases_list),
                )

            if _fc_phases_list:
                _fc_excellence = True  # v9.14-D1: ExcellenceOptimizer für beide Modi aktiv
                # §2.33 PhysicalCeiling-Gate: wenn keine weitere Optimierung lohnend,
                # Iterationen auf 1 reduzieren (verhindert Artefaktakkumulation bei
                # hochwertigem Material, Ephraim & Malah 1984).
                _fc_max_iter = 5  # v9.15-B3: aligned with PMGG 5-retry strategy
                # §G4: Boost FeedbackChain iterations when phase loop had significant
                # conflicts — PMGG log shows how many phases ended in "best_effort" (= no
                # fully-passing strength found). More conflicts → more FC iterations needed
                # to compensate for phases that couldn't reach goal thresholds.
                _fc_pmgg_log = list(getattr(self, "_pmgg_log_entries", []) or [])
                _fc_conflict_phases = sum(
                    1
                    for _e in _fc_pmgg_log
                    if isinstance(getattr(_e, "action", ""), str) and _e.action.startswith("best_effort")
                )
                if _fc_conflict_phases >= 5:
                    _fc_max_iter = min(_fc_max_iter + 2, 9)
                    logger.info(
                        "§G4 FeedbackChain conflict-boost: %d best_effort phases → max_iter=%d",
                        _fc_conflict_phases,
                        _fc_max_iter,
                    )
                elif _fc_conflict_phases >= 3:
                    _fc_max_iter = min(_fc_max_iter + 1, 7)
                    logger.info(
                        "§G4 FeedbackChain conflict-boost: %d best_effort phases → max_iter=%d",
                        _fc_conflict_phases,
                        _fc_max_iter,
                    )
                # §Goal-deficit FC boost (v9.11.14): estimate current goal levels from
                # last PMGG log entries. If goals are below their adaptive targets after
                # the phase pipeline, the FeedbackChain needs more iterations to close
                # the gap — MOS convergence alone is insufficient for goal reliability.
                # Non-blocking: log entry iteration is fail-safe.
                try:
                    _fc_goal_deficit_count = 0
                    if _fc_pmgg_log:
                        _adaptive_thr_fc = (
                            dict(self._pmgg_ceiling_capped_targets)
                            if isinstance(getattr(self, "_pmgg_ceiling_capped_targets", None), dict)
                            and self._pmgg_ceiling_capped_targets
                            else {}
                        )
                        _last_scores_fc: dict[str, float] = {}
                        for _log_e_fc in reversed(_fc_pmgg_log[-8:]):
                            _sa = getattr(_log_e_fc, "scores_after", None)
                            if _sa and isinstance(_sa, dict):
                                for _g_fc, _v_fc in _sa.items():
                                    if _g_fc not in _last_scores_fc:
                                        _last_scores_fc[_g_fc] = float(_v_fc)
                        if _last_scores_fc and _adaptive_thr_fc:
                            for _g_fc, _v_fc in _last_scores_fc.items():
                                _thr_fc = _adaptive_thr_fc.get(_g_fc)
                                if _thr_fc is not None and _v_fc < float(_thr_fc):
                                    _fc_goal_deficit_count += 1
                        if _fc_goal_deficit_count > 0:
                            _additional_iters_fc = min(2, (_fc_goal_deficit_count + 1) // 2)
                            _fc_max_iter = min(_fc_max_iter + _additional_iters_fc, 9)
                            logger.info(
                                "§Goal-deficit FC boost: %d goals below threshold → max_iter=%d",
                                _fc_goal_deficit_count,
                                _fc_max_iter,
                            )
                except Exception as _fc_gd_exc:
                    logger.debug("§Goal-deficit FC boost fehlgeschlagen (non-blocking): %s", _fc_gd_exc)
                # §2.31d: < 10 s → FeedbackChain max 2 Iterationen (zu kurz für FC-Konvergenz)
                if _is_very_short:
                    _fc_max_iter = min(_fc_max_iter, 2)
                    logger.info("§2.31d: Audio < 10s → FeedbackChain max_iter auf 2 begrenzt")
                if _fc_ceiling_val is not None:
                    try:
                        _fc_further_opt = getattr(_fc_pce_result, "further_optimization_worthwhile", True)
                        if not _fc_further_opt:
                            _fc_max_iter = 1
                            logger.info(
                                "§2.33 FeedbackChain: Iterationen auf 1 reduziert — "
                                "PhysicalCeiling sagt keine weitere Optimierung lohnend"
                            )
                    except Exception as _pce_exc:
                        logger.debug("FeedbackChain PhysicalCeiling-Check fehlgeschlagen: %s", _pce_exc)
                # §Material-adaptive Iterationen: armes Material braucht mehr Durchläufe,
                # hochwertiges Material braucht weniger (verringert Artefakt-Risiko).
                _fc_mat_val_iter = material_type.value if material_type else "unknown"
                if _fc_max_iter > 1:  # nur anpassen wenn PhysicalCeiling nicht schon auf 1 gesetzt
                    _fc_high_quality_mats = {"cd_digital", "dat", "mp3_high", "aac"}
                    _fc_poor_mats = {"shellac", "wax_cylinder", "wire_recording"}
                    if _fc_mat_val_iter in _fc_high_quality_mats:
                        _fc_max_iter = 3
                    elif _fc_mat_val_iter in _fc_poor_mats:
                        _fc_max_iter = 7  # armes Material profitiert von mehr Iterationen
                _fc_chain = FeedbackChain(
                    sample_rate=sample_rate,
                    target_score=_fc_compute_target_score(  # §2.31a SongCal-aware FC-Target
                        mode_value=getattr(self.config.mode, "value", "restoration"),
                        cal_profile=getattr(self, "_song_calibration_profile", None),
                    ),
                    max_iterations=_fc_max_iter,
                    excellence_mode=_fc_excellence,
                    material=material_type.value,
                    use_pqs_in_loop=True,
                    use_versa_in_loop=True,  # §2.44: VERSA primär in Produktion (MERT nur Proxy-Fallback)
                    restorability_score=float(_pmgg_restorability_score),
                    defect_severity_mean=float(self._fc_defect_severity_mean(defect_result)),
                )
                # §2.56: Inject song-specific goal weights into FeedbackChain
                _fc_chain.goal_weights = getattr(self, "_song_goal_weights", None)
                # §09.2 + §2.54: Inject ceiling-capped adaptive goal targets so FeedbackChain
                # uses physically achievable thresholds (min(SGT, PhysicalCeiling)).
                # Falls back to raw SGT if ceiling-capped targets not yet computed.
                _sgt_fc = getattr(self, "_pmgg_ceiling_capped_targets", None) or getattr(
                    self, "_song_goal_targets", None
                )
                _fc_chain.adaptive_goal_thresholds = dict(_sgt_fc) if isinstance(_sgt_fc, dict) and _sgt_fc else None
                # §2.34 GPP-WIRE: GoalPriorityProtocol als in-loop Phase-Callback verdrahten
                try:
                    from backend.core.goal_priority_protocol import check_iteration_abort as _check_gpp
                    from backend.core.per_phase_musical_goals_gate import _measure_quick as _gpp_quick

                    # §perf-v9.11.0: FeedbackChain-Callback nutzt _measure_quick (DSP-Proxy)
                    # statt MusicalGoalsChecker.measure_all() (CREPE/librosa, 14–17 s).
                    # check_iteration_abort prüft nur P1/P2-Ziele (natuerlichkeit,
                    # authentizitaet, tonal_center, timbre_authentizitaet, artikulation).
                    # Alle P1/P2-Proxies in _measure_quick sind für Delta-Checks valide —
                    # identische Methodik wie der PMGG-Phase-Loop.
                    # Einsparung: ~14–17 s pro FC-Iteration → < 0.5 s.
                    _gpp_sr = sample_rate
                    # Cache: speichere letzte Scores um Doppel-Messungen zu vermeiden
                    _gpp_prev_scores: dict[str, float] = {}
                    _gpp_analytics_s: list[float] = [0.0]  # mutable accumulator for closure

                    def _gpp_fc_callback(_ab: np.ndarray, _aa: np.ndarray) -> tuple[bool, str]:
                        nonlocal _gpp_prev_scores
                        import time as _t_gpp

                        try:
                            # Reuse cached scores for 'before' when available (same audio)
                            if _gpp_prev_scores:
                                _sb = _gpp_prev_scores
                            else:
                                _t0g = _t_gpp.perf_counter()
                                _sb = _gpp_quick(_ab, _gpp_sr)
                                _gpp_analytics_s[0] += _t_gpp.perf_counter() - _t0g
                            _t0g = _t_gpp.perf_counter()
                            _sa = _gpp_quick(_aa, _gpp_sr)
                            _gpp_analytics_s[0] += _t_gpp.perf_counter() - _t0g
                            _gpp_prev_scores = _sa  # cache for next iteration
                            # §2.56: Pass song-specific goal weights to GPP abort check
                            _res = _check_gpp(_sb, _sa, goal_weights=getattr(self, "_song_goal_weights", None))
                            return _res.should_abort, _res.reason
                        except Exception as _gpp_cb_exc:
                            logger.debug("GPP FeedbackChain callback failed: %s", _gpp_cb_exc)
                            return False, ""

                    if hasattr(_fc_chain, "goal_priority_callback"):
                        _fc_chain.goal_priority_callback = _gpp_fc_callback
                        logger.debug("§GPP-WIRE: GoalPriorityProtocol FeedbackChain-Callback aktiv")
                except Exception as _gpp_wire_exc:
                    logger.debug("§GPP-WIRE: nicht verfügbar — %s", _gpp_wire_exc)
                _fc_chain_result = _fc_chain.run(restored_audio, _fc_phases_list, ceiling=_fc_ceiling_val)
                restored_audio = _fc_chain_result.audio
                # Report analytics overhead to PerformanceGuard so goal-measurement
                # time inside FeedbackChain does not inflate the RT factor.
                _fc_analytics = getattr(_fc_chain_result, "analytics_overhead_s", 0.0)
                # Also accumulate GPP-callback analytics overhead (captured via closure)
                try:
                    _fc_analytics += _gpp_analytics_s[0]
                except Exception as _ana_exc:
                    logger.debug("GPP-Analytics-Overhead-Zugriff fehlgeschlagen: %s", _ana_exc)
                if self.performance_guard and _fc_analytics > 0:
                    self.performance_guard.add_analytics_overhead(_fc_analytics)
                logger.info(
                    "🔄 FeedbackChain: score=%.3f retries=%d t=%.2fs analytics_overhead=%.2fs (%d Post-Phasen)",
                    _fc_chain_result.overall_score,
                    getattr(_fc_chain_result, "total_retries", _fc_chain_result.iterations),
                    _fc_chain_result.total_time_s,
                    _fc_analytics,
                    len(_fc_phases_list),
                )

                # §LAG_PROBE_4: nach FeedbackChain — GCC-PHAT O(n log n)
                try:
                    if restored_audio.ndim == 2:
                        from backend.file_import import _estimate_interchannel_lag_samples as _gcc_lag

                        _lp4_lag = _gcc_lag(restored_audio, sample_rate)
                        logger.info(
                            "LAG_PROBE 4/after_feedbackchain: lag=%d samples (%.1f ms)",
                            _lp4_lag,
                            _lp4_lag / sample_rate * 1000,
                        )
                except Exception as _lp4_exc:
                    logger.debug("LAG_PROBE_4 fehlgeschlagen: %s", _lp4_exc)
            else:
                logger.debug("FeedbackChain: keine Post-Pipeline-Phasen verfügbar")
        except Exception as _fc_exc:
            if str(_fc_exc) == "__graceful_stop_skip_feedback_chain__":
                logger.debug("FeedbackChain bewusst übersprungen (graceful stop)")
            else:
                logger.debug("FeedbackChain nicht verfügbar: %s", _fc_exc)

        _cb(89, "FeedbackChain abgeschlossen…")

        # §2.60 STCG post-feedbackchain: FeedbackChain kann Stereo-Phasen enthalten
        # (phase_12_wow_flutter_fix, phase_35_multiband_compression, phase_34) die L/R-Lag
        # erzeugen (phase_12 läuft oft erst in FeedbackChain, nicht in der Haupt-Pipeline).
        # STCG post-pipeline (Z.~6037, vor FeedbackChain) fängt diesen Lag NICHT mehr ab.
        # Zweiter STCG-Aufruf hier stellt sicher, dass Goals-Messung (Z.~7443) auf
        # lag-korrigiertem Audio läuft und das Export-File keinen L/R-Zeitversatz enthält.
        if restored_audio.ndim == 2:
            try:
                from backend.core.stereo_temporal_coherence_guard import (
                    get_stereo_temporal_coherence_guard as _get_stcg_fc,
                )

                restored_audio = _get_stcg_fc().correct_interchannel_delay(
                    restored_audio, sample_rate, phase_id="post_feedbackchain"
                )
            except Exception as _stcg_fc_exc:
                logger.debug("STCG post_feedbackchain non-blocking: %s", _stcg_fc_exc)

        # §1.4 Auto Stem Separation for Studio 2026 (Spec §9.5: Stem-Sep → StemRemixBalancer)
        # Separates the fully-processed audio into vocals/instruments so StemRemixBalancer can
        # perform LUFS-correct re-mixing. Only runs when the caller did not provide pre-separated
        # stems AND the mode is Studio 2026. BsRoformer handles its own memory budget internally.
        _auto_stems: dict | None = None
        if _is_studio_26 and kwargs.get("stems") is None:
            try:
                from plugins.bs_roformer_plugin import separate_stems as _bsr_sep

                _bsr_result = _bsr_sep(restored_audio, sample_rate, stems=["vocals", "instruments"])
                if _bsr_result is not None and isinstance(_bsr_result.stems, dict):
                    _bsr_v = _bsr_result.stems.get("vocals")
                    _bsr_i = _bsr_result.stems.get("instruments")
                    if _bsr_v is not None and _bsr_i is not None:
                        _auto_stems = {
                            "vocals": _bsr_v,
                            "instruments": _bsr_i,
                        }
                        logger.info(
                            "§1.4 Auto-Stem-Separation: %s SDRi=%.1f dB confidence=%.2f",
                            _bsr_result.model_used,
                            _bsr_result.sdri_db,
                            _bsr_result.confidence,
                        )
            except Exception as _bsr_exc:
                logger.debug(
                    "§1.4 Auto-Stem-Separation nicht verfügbar (StemRemixBalancer überspringt): %s",
                    _bsr_exc,
                )

        # §1.4 StemRemixBalancer — LUFS-korrekter Stem-Re-Mix (nur bei Stem-Vorhandensein)
        try:
            from backend.core.stem_remix_balancer import balance_remix

            _stems = kwargs.get("stems") or _auto_stems
            if _stems is not None and isinstance(_stems, dict):
                _vocals = _stems.get("vocals")
                _instruments = _stems.get("instruments")
                if _vocals is not None and _instruments is not None:
                    # §1.4 vocal_weight: aus PANNs-Ergebnis ableiten (vor MDX23C auf Original geschätzt)
                    # §1.4 vocal_weight: None → _estimate_vocal_weight() in StemRemixBalancer
                    _vw_raw = _stems.get("vocal_weight")
                    _vw: float | None = None
                    if _vw_raw is not None:
                        _vw_f = float(_vw_raw)
                        if 0.0 < _vw_f < 1.0:
                            _vw = _vw_f
                    if _vw is None:
                        # PANNs-Konfidenz nutzen, nur wenn glaubwürdig (> 1 %)
                        _ptags: dict = kwargs.get("panns_tags", {})
                        _v_conf = max(
                            _ptags.get("Singing voice", 0.0),
                            _ptags.get("Vocals", 0.0),
                            _ptags.get("Speech", 0.0),
                        )
                        _vw = float(np.clip(_v_conf, 0.1, 0.9)) if _v_conf > 0.01 else None
                    restored_audio = balance_remix(
                        _vocals,
                        _instruments,
                        original_audio_for_goals,
                        sample_rate,
                        vocal_weight=_vw,
                    )
                    logger.info(
                        "🎚️ StemRemixBalancer: Stem-Remix LUFS-balanciert (vocal_weight=%s)",
                        f"{_vw:.2f}" if _vw is not None else "auto",
                    )
                else:
                    logger.debug("StemRemixBalancer: Stems unvollständig (vocals/instruments fehlen)")
            else:
                logger.debug("StemRemixBalancer: keine Stems verfügbar (weder kwargs noch Auto-Separation)")
        except Exception as _srb_exc:
            logger.debug("StemRemixBalancer nicht verfügbar: %s", _srb_exc)

        # §Studio-2026 Reference Mastering — Matchering 2.0 spektrales Profil-Matching
        # Position: nach StemRemixBalancer (Re-Mix liegt vor), vor LUFS-Normalisierung.
        # Referenz: restauriertes Original (original_audio_for_goals) — originalgetreues Profil.
        # Nur im Studio-2026-Modus aktiv; bei fehlendem Paket transparenter DSP-Fallback.
        # §9.5: Production feature for Studio 2026 — no experimental gate needed.
        if _is_studio_26:
            try:
                from plugins.matchering_plugin import (
                    is_matchering_available as _mg_avail,
                )
                from plugins.matchering_plugin import (
                    match_reference as _match_ref,
                )

                _mg_ref_signal = original_audio_for_goals
                if _mg_ref_signal is not None and np.atleast_1d(_mg_ref_signal).shape[-1] > sample_rate:
                    restored_audio = _match_ref(restored_audio, _mg_ref_signal, sample_rate)
                    restored_audio = np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0)
                    restored_audio = np.clip(restored_audio, -1.0, 1.0)
                    logger.info(
                        "🎚️ Studio-2026 Reference Mastering: Matchering %s — spektrales Profil-Matching abgeschlossen",
                        "2.0" if _mg_avail() else "DSP-Fallback",
                    )
                else:
                    logger.debug("Studio-2026 Reference Mastering: Referenzsignal zu kurz oder None, übersprungen")
            except Exception as _mg_exc:
                logger.debug("Studio-2026 Reference Mastering nicht verfügbar: %s", _mg_exc)

        # §2.35 EraAuthenticPerceptualCompletion — Ära-authentische HF-Ergänzung (vor IAD)
        # Positionierung: nach phase_55_diffusion_inpainting, vor IntroducedArtifactDetector (Spec §2.35)
        # Nur aktiv wenn Quell-Bandbreite < 10 kHz UND BrillanzMetric applicable
        try:
            from backend.core.era_authentic_perceptual_completion import get_era_completion as _get_eapc

            _eapc = _get_eapc()
            _era_decade_eapc = _era_result.decade if _era_result is not None else None
            # GoalApplicabilityFilter-Ergebnis übergeben (aus §2.32, bereits berechnet)
            _eapc_goal_app = _goal_applicability_result
            if _eapc.is_applicable(restored_audio, sample_rate, goal_applicability=_eapc_goal_app):
                # §9.12.7 §2.46e: material_ceiling verhindert HF-Hallucination über Träger-Limit.
                # Beispiel: 1970s Kassette = material brillanz ceiling 0.78 → EAPC darf nicht
                # auf ERA-Niveau 0.90 synthetisieren.
                try:
                    from backend.core.physical_ceiling_estimator import get_physical_ceiling_estimator as _get_pce

                    _eapc_pce = _get_pce()
                    _eapc_mat_str = str(getattr(material_type, "value", material_type) or "unknown").lower()
                    _eapc_mat_ceil = _eapc_pce.estimate(
                        restored_audio, sample_rate, current_goal_scores={}, material=_eapc_mat_str
                    )
                    _eapc_brillanz_mat_ceil = float(_eapc_mat_ceil.ceiling.get("brillanz", 1.0))
                except Exception:
                    _eapc_brillanz_mat_ceil = 1.0
                _eapc_result = _eapc.complete(
                    restored_audio,
                    sample_rate,
                    era=_era_decade_eapc,
                    anchor=None,
                    material_ceiling=_eapc_brillanz_mat_ceil,
                )
                if _eapc_result.applied:
                    restored_audio = np.clip(
                        np.nan_to_num(_eapc_result.audio, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0
                    )
                    logger.info(
                        "§2.35 EAPC: Ära-authentische HF-Ergänzung — decade=%s bw=%.0f→%.0f Hz ceiling=%.2f",
                        _eapc_result.era_decade,
                        _eapc_result.source_bandwidth_hz,
                        _eapc_result.completion_bandwidth_hz,
                        _eapc_result.brillanz_ceiling,
                    )
                else:
                    logger.debug("§2.35 EAPC: is_applicable=True aber complete() applied=False")
            else:
                logger.debug("§2.35 EAPC: nicht anwendbar (BW ≥ 10 kHz oder BrillanzMetric inapplicable)")
        except Exception as _eapc_exc:
            logger.debug("EraAuthenticPerceptualCompletion nicht verfügbar: %s", _eapc_exc)

        # §2.36 LyricsGuidedEnhancement — Phonem-klassen-bewusste Restaurierung (Pflicht ab 9.10.x)
        # Positionierung: nach EAPC (§2.35), vor IAD (§2.23) — schützt Konsonanten und betonte Silben.
        # Aktivierung: immer wenn Audio ≥ 1 s; kein Vocals-Gate (Lyrics können auch instrumental sein).
        # Privacy: Lyrics-Text wird NICHT geloggt (§2.36 Datenschutz-Pflicht).
        # Guard: Skip wenn phase_58 bereits in Pipeline ausgeführt (Deduplication — verhindert ×Saliency²).
        if "phase_58_lyrics_guided_enhancement" in (executed_phases or []):
            logger.debug("§2.36 LGE: Inline-Pfad übersprungen — phase_58 bereits ausgeführt")
        else:
            try:
                from backend.core.lyrics_guided_enhancement import (
                    get_content_aware_processor as _get_cap,
                )
                from backend.core.lyrics_guided_enhancement import (
                    get_lyrics_guided_enhancement as _get_lge,
                )

                _lge = _get_lge()
                if _lge_trans_pre is not None and not getattr(_lge_trans_pre, "fallback_used", True):
                    # §2.36 Phase-Gate-Anbindung: Saliency aus Pre-Phase-Transkription (Originalaudio)
                    _cap = _get_cap()
                    _n_smp = restored_audio.shape[-1] if restored_audio.ndim == 2 else len(restored_audio)
                    _base_sal = np.ones(_n_smp, dtype=np.float32)
                    _lge_saliency = _cap.compute_lyrics_saliency(_base_sal, _lge_trans_pre, sample_rate)
                    _lge_saliency_for_eap = _lge_saliency  # §2.36/§2.44: für measure_emotional_arc()
                    if restored_audio.ndim == 2 and restored_audio.shape[0] <= 2:
                        _lge_audio = restored_audio * _lge_saliency[np.newaxis, :]
                    elif restored_audio.ndim == 2:
                        _lge_audio = restored_audio * _lge_saliency[:, np.newaxis]
                    else:
                        _lge_audio = restored_audio * _lge_saliency
                    _lge_audio = np.clip(np.nan_to_num(_lge_audio, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                    restored_audio = _lge_audio
                    _lge_seg_count = len(_lge_trans_pre.words) if _lge_trans_pre is not None else 0
                    logger.info(
                        "§2.36 LGE: Saliency aus Original-Phonemkarte — %d Segmente (§2.36 Phase-Gate)",
                        _lge_seg_count,
                    )
                else:
                    # Fallback: transcribe restored audio (pre-computed transcription unavailable)
                    _lge_audio, _lge_transcription = _lge.enhance(restored_audio, sample_rate)
                    _lge_audio = np.nan_to_num(_lge_audio, nan=0.0, posinf=0.0, neginf=0.0)
                    _lge_audio = np.clip(_lge_audio, -1.0, 1.0)
                    restored_audio = _lge_audio
                    _lge_seg_count = len(_lge_transcription.words) if _lge_transcription is not None else 0
                    logger.info("§2.36 LGE: Lyrics-geführte Verbesserung — %d Segmente verarbeitet", _lge_seg_count)
            except Exception as _lge_exc:
                logger.debug("LyricsGuidedEnhancement nicht verfügbar: %s", _lge_exc)

        # §2.23 IntroducedArtifactDetector — Durch Restaurierung neu eingebrachte Artefakte prüfen
        self._iad_artifact_fraction_penalty = 1.0
        try:
            from backend.core.introduced_artifact_detector import detect_introduced_artifacts

            _iad_result = detect_introduced_artifacts(original_audio_for_goals, restored_audio, sample_rate)
            if _iad_result.has_artifacts:
                logger.warning(
                    "⚠️ IAD: Artefakte erkannt — fraction=%.3f Typen=%s",
                    _iad_result.total_contaminated_fraction,
                    ", ".join(_iad_result.artifact_types) if _iad_result.artifact_types else "unbekannt",
                )

                _frac_iad = float(_iad_result.total_contaminated_fraction)

                # §2.49: IAD contributes to artifact_freedom, but avoid a degenerate zero at small
                # contamination fractions. Keep veto behavior at >= 5% contamination.
                # penalty = 1.00 at 0%, 0.95 at 5%, 0.90 at 10%.
                self._iad_artifact_fraction_penalty = float(np.clip(1.0 - _frac_iad, 0.0, 1.0))
                logger.warning(
                    "§2.49 IAD: artifact_freedom_penalty=%.3f (fraction=%.3f × 1.0) — VETO if < 0.95",
                    self._iad_artifact_fraction_penalty,
                    _frac_iad,
                )

                # §2.23 IAD-Rescue (analog §2.45a Dry/Wet-Rescue):
                # Bei >=5% Kontamination: Dry/Wet-Blend zurück auf Original.
                # Bewahrt Restaurierung (>=65% wet), reduziert ML-Artefakte.
                # §0d Carrier-Recovery-Invariante: Carrier-Chain-Inversion erzeugt absichtlich
                # großes Residuum — das ist korrekte Restaurierung, kein Artefakt. Den Blend
                # suppressieren wenn carrier_chain_recovery_ratio > 0.15 AND pre_iad >= 0.95.
                _IAD_RESCUE_THRESHOLD = 0.05
                _carrier_rec_iad = getattr(self, "_carrier_chain_recovery_ratio", 0.0)
                _pre_iad_af_iad = getattr(self, "_artifact_freedom_score", 1.0)
                _iad_rescue_suppressed = _carrier_rec_iad > 0.15 and _pre_iad_af_iad >= 0.95
                if _frac_iad >= _IAD_RESCUE_THRESHOLD and not _iad_rescue_suppressed:
                    _iad_wet = float(max(0.65, 0.85 - _frac_iad * 1.5))
                    _iad_blend = (_iad_wet * restored_audio + (1.0 - _iad_wet) * original_audio_for_goals).astype(
                        np.float32
                    )
                    restored_audio = np.clip(_iad_blend, -1.0, 1.0)
                    logger.info(
                        "IAD-Rescue: wet=%.2f (fraction=%.3f >= %.2f) — Dry/Wet-Blend",
                        _iad_wet,
                        _frac_iad,
                        _IAD_RESCUE_THRESHOLD,
                    )

                    # Re-evaluate post-rescue to avoid carrying over pre-rescue IAD penalties.
                    _iad_post = detect_introduced_artifacts(original_audio_for_goals, restored_audio, sample_rate)
                    _frac_iad_post = float(_iad_post.total_contaminated_fraction)
                    self._iad_artifact_fraction_penalty = float(np.clip(1.0 - _frac_iad_post, 0.0, 1.0))
                    logger.info(
                        "IAD-Rescue post-check: fraction %.3f -> %.3f, penalty=%.3f",
                        _frac_iad,
                        _frac_iad_post,
                        self._iad_artifact_fraction_penalty,
                    )
                elif _iad_rescue_suppressed:
                    logger.info(
                        "§0d IAD-Rescue suppressed: carrier_ratio=%.3f pre_iad=%.3f — "
                        "Residuum ist Restaurierungs-Delta (Carrier-Chain-Inversion), kein Artefakt",
                        _carrier_rec_iad,
                        _pre_iad_af_iad,
                    )
            else:
                logger.debug(
                    "IAD: keine neu eingebrachten Artefakte (fraction=%.3f)", _iad_result.total_contaminated_fraction
                )
        except Exception as _iad_exc:
            logger.debug("IntroducedArtifactDetector nicht verfügbar: %s", _iad_exc)

        # §2.49 [FIX v9.12.1]: IAD läuft in restore() NACH _execute_pipeline().
        # _execute_pipeline() setzt _artifact_freedom_score ohne IAD-Kenntnis (IAD-Penalty=1.0 dort).
        # Hier: IAD-Penalty in _artifact_freedom_score zurückschreiben, damit HPI den echten Wert liest.
        # §0d Carrier-Recovery-Invariante: Wenn Carrier-Inversion stark (ratio > 0.15) UND
        # per-phase artifact_freedom bereits >= 0.95, dann ist das IAD-Residuum ein Restaurierungs-Delta
        # (korrekte Carrier-Chain-Inversion), kein echtes Artefakt. In diesem Fall darf die IAD-Penalty
        # artifact_freedom nicht unter pre_iad bringen (§0d Gate-Paradoxon).
        _iad_penalty_final = getattr(self, "_iad_artifact_fraction_penalty", 1.0)
        if _iad_penalty_final < 1.0:
            _af_pre_iad = getattr(self, "_artifact_freedom_score", 1.0)
            _carrier_rec_af = getattr(self, "_carrier_chain_recovery_ratio", 0.0)
            if _carrier_rec_af > 0.15 and _af_pre_iad >= 0.95:
                # §0d: Residuum ist Restaurierungs-Delta → IAD-Penalty ignorieren
                logger.info(
                    "§0d IAD-Override: carrier_ratio=%.3f pre_iad=%.3f iad_penalty=%.3f — "
                    "artifact_freedom unverändert (Residuum = Restaurierungs-Delta)",
                    _carrier_rec_af,
                    _af_pre_iad,
                    _iad_penalty_final,
                )
            else:
                self._artifact_freedom_score = float(min(_af_pre_iad, _iad_penalty_final))
                logger.warning(
                    "§2.49 [FIX] artifact_freedom_score aktualisiert: pre_iad=%.3f iad_penalty=%.3f -> final=%.3f",
                    _af_pre_iad,
                    _iad_penalty_final,
                    self._artifact_freedom_score,
                )

        _cb(91, "Audio-Nachbearbeitung…")

        # --- SegmentAdaptiveProcessor: Segment-individuelle Feinoptimierung (§2.10 Spec) ---
        # Anwendung NACH globalem Pipeline-Lauf: jedes Segment (Stille /
        # Mixed / Vocal) erhält eigene NR-Stärke, Harmonic-Boost, Smoothing.
        # Stereo-kompatibel: Gain-Verhältnis Mono→Mono auf Stereo-Kanäle übertragen.
        _sap_result = None
        try:
            from backend.core.segment_adaptive_processor import get_segment_processor

            _sap_n_samples = restored_audio.shape[-1] if restored_audio.ndim == 2 else len(restored_audio)
            _audio_dur_s = _sap_n_samples / float(sample_rate)
            _sap_enabled = _audio_dur_s >= 5.0  # Fallback bei < 5 s (§2.10)
            _sap_is_stereo = restored_audio.ndim == 2 and restored_audio.shape[0] <= 2

            def _sap_process_fn(_seg: np.ndarray, _sr: int, _params: dict) -> np.ndarray:
                """Leichte segment-spezifische DSP-Nachbearbeitung."""
                out = _seg.copy().astype(np.float32)
                nr = float(_params.get("noise_reduction_strength", 0.55))
                boost_db = float(_params.get("harmonic_boost_db", 0.0))
                smooth = float(_params.get("spectral_smoothing", 0.5))

                # 1. Stille-Rauschboden anheben (§8.1): leise Segmente abschwächen
                _seg_rms = float(np.sqrt(np.mean(out**2) + 1e-12))
                _silence_thr = 10 ** (-40.0 / 20.0)  # −40 dBFS
                if _seg_rms < _silence_thr * 2.0 and nr > 0.3:
                    out *= max(0.0, 1.0 - nr * 0.7)

                # 2. Harmonic Boost: sanfter Presence-Lift ≤ +3 dB (§2.5)
                if 0.0 < boost_db <= 6.0:
                    _gain_add = min(10 ** (boost_db / 20.0) - 1.0, 0.41) * 0.25
                    _spec = np.fft.rfft(out)
                    _n = len(_spec)
                    # Nur oberes Drittel anheben (Presence-Region)
                    _mask = np.ones(_n, dtype=np.float32)
                    _mask[_n * 2 // 3 :] = 1.0 + _gain_add
                    _spec *= _mask
                    _reconstructed = np.fft.irfft(_spec, n=len(out)).astype(np.float32)
                    if len(_reconstructed) == len(out):
                        out = _reconstructed

                # 3. Spectral Smoothing: Hangfenster-Glättung im Frequenzbereich
                if 0.1 <= smooth <= 0.9:
                    _spec2 = np.fft.rfft(out)
                    _kernel_n = max(3, int(smooth * 15) | 1)  # ungerade
                    _kernel = np.hanning(_kernel_n + 2)[1:-1].astype(np.float32)
                    _kernel /= _kernel.sum()
                    _mag_s = np.convolve(np.abs(_spec2), _kernel, mode="same")
                    _phase_s = np.angle(_spec2)
                    _spec2 = _mag_s * np.exp(1j * _phase_s)
                    _smooth_out = np.fft.irfft(_spec2, n=len(out)).astype(np.float32)
                    if len(_smooth_out) == len(out):
                        out = out * (1.0 - smooth * 0.15) + _smooth_out * (smooth * 0.15)

                out = np.nan_to_num(out, nan=0.0, posinf=0.0, neginf=0.0)
                return np.clip(out, -1.0, 1.0).astype(np.float32)

            # Stereo: pro Kanal SAP anwenden
            if _sap_is_stereo:
                _sap_ch0 = get_segment_processor().process(
                    restored_audio[0],
                    sample_rate,
                    _sap_process_fn,
                    material=material_type.value,
                    enabled=_sap_enabled,
                )
                _sap_ch1 = get_segment_processor().process(
                    restored_audio[1],
                    sample_rate,
                    _sap_process_fn,
                    material=material_type.value,
                    enabled=_sap_enabled,
                )
                _sap_result = _sap_ch0  # Metadaten aus Kanal 0
                restored_audio = np.stack([_sap_ch0.audio, _sap_ch1.audio], axis=0).astype(np.float32)
            else:
                _sap_result = get_segment_processor().process(
                    restored_audio,
                    sample_rate,
                    _sap_process_fn,
                    material=material_type.value,
                    enabled=_sap_enabled,
                )
                restored_audio = _sap_result.audio

            logger.info(
                "📐 SegmentAdaptive: %d Segmente (%s) | fallback=%s",
                _sap_result.n_segments,
                ", ".join({s.segment_type for s in _sap_result.segments}),
                _sap_result.used_fallback,
            )
        except Exception as _sap_exc:
            logger.debug("SegmentAdaptiveProcessor nicht verfügbar: %s", _sap_exc)

        # Post-Processing: Temporale Qualitätskohärenz (§2.16)
        _tqc = None
        try:
            from backend.core.temporal_quality_coherence import measure_temporal_coherence

            _tqc_mat_key = getattr(_mc_result, "primary_material", None) if _mc_result else None
            _tqc = measure_temporal_coherence(restored_audio, sample_rate, material_key=_tqc_mat_key)
            if not _tqc.passed:
                logger.warning(
                    "⚠️ TemporalQualityCoherence: NICHT BESTANDEN "
                    "(max_span=%.3f σ=%.3f n=%d material=%s) — zeitliche Konsistenz prüfen",
                    _tqc.max_span,
                    _tqc.sigma,
                    _tqc.n_segments,
                    _tqc_mat_key or "unbekannt",
                )
                # §2.16 Enforcement: targeted spectral gate on low-quality segments.
                # For each segment with score < (mean − sigma×0.5), derive a per-frame
                # spectral gate from the mono mix (§2.51 linked-stereo) and apply it with
                # a 0.5 s crossfade. Strength=0.35 keeps processing conservative (§0).
                _tqc_scores = list(getattr(_tqc, "segment_scores", []))
                if not getattr(_tqc, "skipped", False) and len(_tqc_scores) >= 3:
                    try:
                        import numpy as _tqc_np
                        from scipy.signal import stft as _tqc_stft

                        _tqc_arr = _tqc_np.asarray(_tqc_scores, dtype=_tqc_np.float64)
                        _tqc_mean = float(_tqc_np.mean(_tqc_arr))
                        _tqc_std = float(_tqc_np.std(_tqc_arr))
                        _tqc_bad_thr = max(1.0, _tqc_mean - _tqc_std * 0.5)
                        _tqc_bad_idx = [i for i, s in enumerate(_tqc_scores) if s < _tqc_bad_thr]

                        if _tqc_bad_idx and _tqc_std > 0.01:
                            # Geometry must match TQC (10 s window, 5 s hop, 0.5 s crossfade)
                            _tqc_sr = sample_rate
                            _tqc_hop_n = int(5.0 * _tqc_sr)
                            _tqc_win_n = int(10.0 * _tqc_sr)
                            _tqc_xf_n = min(int(0.5 * _tqc_sr), _tqc_hop_n // 4)
                            # STFT: nperseg=2048, noverlap=512 → noverlap < nperseg for
                            # any signal length (§2.57 guard).
                            _TQC_NPS, _TQC_NOV = 2048, 512
                            _TQC_STRENGTH = 0.35  # conservative (§0 Primum non nocere)

                            # Normalize to (channels, samples) layout for unified processing.
                            _ra = restored_audio
                            _tqc_sq = _tqc_tr = False
                            if _ra.ndim == 1:
                                _ra = _ra[_tqc_np.newaxis, :]
                                _tqc_sq = True
                            elif _ra.ndim == 2 and _ra.shape[0] > 2:
                                _ra = _ra.T  # (samples, ch) → (ch, samples)
                                _tqc_tr = True
                            _n_ch, _n_samp = _ra.shape

                            # §2.51 linked-stereo: gate derived from mono mix.
                            _tqc_mono = _tqc_np.mean(_ra, axis=0).astype(_tqc_np.float64)
                            _ra_out = _ra.copy()

                            for _bi in _tqc_bad_idx:
                                _ss = _bi * _tqc_hop_n
                                _se = min(_ss + _tqc_win_n, _n_samp)
                                _bs = max(0, _ss - _tqc_xf_n)
                                _be = min(_n_samp, _se + _tqc_xf_n)
                                _blen = _be - _bs
                                if _blen < _TQC_NPS * 2:
                                    continue
                                _seg = _tqc_mono[_bs:_be]
                                try:
                                    _f_z, _t_z, _Z = _tqc_stft(
                                        _seg,
                                        fs=_tqc_sr,
                                        nperseg=_TQC_NPS,
                                        noverlap=_TQC_NOV,
                                    )
                                except ValueError:
                                    continue
                                _mag = _tqc_np.abs(_Z)
                                # Per-bin noise floor (P5) → gate threshold at 9.5 dB above.
                                _nfloor = _tqc_np.percentile(_mag, 5, axis=1, keepdims=True) + 1e-10
                                _gth = _nfloor * 3.0
                                _gg = _tqc_np.clip(
                                    _tqc_np.where(_mag > _gth, 1.0, _mag / _gth),
                                    0.2,
                                    1.0,
                                )
                                # Project per-frame mean gain to sample domain via interp.
                                _fg = _tqc_np.mean(_gg, axis=0)
                                _fc = _tqc_np.arange(len(_fg)) * (_TQC_NPS - _TQC_NOV) + _TQC_NPS // 2
                                _ix = _tqc_np.arange(_blen, dtype=_tqc_np.float64)
                                _gi = _tqc_np.interp(
                                    _ix,
                                    _fc.astype(float),
                                    _fg.astype(float),
                                    left=float(_fg[0]),
                                    right=float(_fg[-1]),
                                )
                                # sample_mult = 1 − strength×(1−gain) ∈ [1−0.35, 1.0]
                                _sm = _tqc_np.clip(1.0 - _TQC_STRENGTH * (1.0 - _gi), 0.0, 1.0)
                                # Crossfade envelope: 0 at edges → 1 at interior.
                                _xe = _tqc_np.ones(_blen)
                                if _bs > 0:
                                    _xe[:_tqc_xf_n] = _tqc_np.linspace(0.0, 1.0, _tqc_xf_n)
                                if _be < _n_samp:
                                    _xe[_blen - _tqc_xf_n :] = _tqc_np.linspace(1.0, 0.0, _tqc_xf_n)
                                _fm = 1.0 - _xe * (1.0 - _sm)
                                # Apply identical gain to every channel (§2.51).
                                for _ch in range(_n_ch):
                                    _ra_out[_ch, _bs:_be] = (_ra_out[_ch, _bs:_be] * _fm).astype(_tqc_np.float32)

                            _ra_out = _tqc_np.nan_to_num(_ra_out, nan=0.0, posinf=0.0, neginf=0.0)
                            _ra_out = _tqc_np.clip(_ra_out, -1.0, 1.0).astype(_tqc_np.float32)
                            if _tqc_sq:
                                _ra_out = _ra_out[0]
                            elif _tqc_tr:
                                _ra_out = _ra_out.T
                            restored_audio = _ra_out
                            logger.info(
                                "§2.16 TQC enforcement: spektrales Gate auf %d/%d Segmente"
                                " (mean_mos=%.2f thr=%.2f strength=%.2f)",
                                len(_tqc_bad_idx),
                                len(_tqc_scores),
                                _tqc_mean,
                                _tqc_bad_thr,
                                _TQC_STRENGTH,
                            )
                    except Exception as _tqc_enf_exc:
                        logger.debug(
                            "§2.16 TQC enforcement fehlgeschlagen (non-blocking): %s",
                            _tqc_enf_exc,
                        )
            else:
                logger.debug(
                    "TemporalQualityCoherence: OK (max_span=%.3f σ=%.3f)",
                    _tqc.max_span,
                    _tqc.sigma,
                )
        except Exception as _tqc_exc:
            logger.debug("TemporalQualityCoherenceMetric nicht verfügbar: %s", _tqc_exc)

        # Post-Processing: Stereofeld-Authentizitätsinvariante (§2.18)
        # §M-3: _FallbackEra-Fallback wenn EraClassifier keine Ära erkannte
        _era_for_stereo = _era_result
        if _era_for_stereo is None:
            import types as _types_m3

            _era_for_stereo = _types_m3.SimpleNamespace(decade=1970, confidence=0.0)
        try:
            from backend.core.stereo_authenticity_invariant import (
                check_stereo_authenticity,
                get_stereo_authenticity_invariant,
            )

            _stereo_check = check_stereo_authenticity(audio, restored_audio, _era_for_stereo, sample_rate)
            if not _stereo_check.passed:
                logger.warning(
                    "🔊 StereoInvariant: Verletzung '%s' — erzwinge Korrektur",
                    _stereo_check.rule_triggered,
                )
                _stereo_inv = get_stereo_authenticity_invariant()
                restored_audio = _stereo_inv.enforce(restored_audio, sample_rate, audio, _era_for_stereo)
            else:
                logger.debug(
                    "StereoInvariant: OK (%s)",
                    _stereo_check.rule_triggered or "kein Regelverstoß",
                )
        except Exception as _si_exc:
            logger.debug("StereoAuthenticitiyInvariant nicht verfügbar: %s", _si_exc)

        # §8.2 EmotionalArc Rollback-Referenz: Snapshot vor ExcellenceOptimizer
        _pre_excellence_audio: np.ndarray = restored_audio.copy()

        # §8.1 Musical Goals Snapshot vor ExcellenceOptimizer (Regressions-Schutz)
        _pre_excellence_mg_scores: dict[str, float] = {}
        try:
            from backend.core.musical_goals.musical_goals_metrics import MusicalGoalsChecker as _PreExMGChecker

            _pre_ex_checker = _PreExMGChecker()
            _pre_ex_ref = original_audio_for_goals if original_audio_for_goals.shape == restored_audio.shape else None
            _pre_ex_mat = str(getattr(material_type, "value", material_type) or "unknown").lower()
            _pre_excellence_mg_scores = _pre_ex_checker.measure_all(
                restored_audio, sample_rate, reference=_pre_ex_ref, material_type=_pre_ex_mat
            )
        except Exception as _mg_exc:
            logger.debug("Pre-Excellence Musical-Goals-Messung fehlgeschlagen: %s", _mg_exc)

        # --- ExcellenceOptimizer: DSP-Feinoptimierung nach Phasen-Pipeline (§2.2 Spec) ---
        _excellence_result = None
        _is_bronze_post = os.environ.get("AURIK_BRONZE_RESTORATION_PROFILE", "0").strip().lower() in {
            "1",
            "true",
            "yes",
            "on",
        }
        if _is_bronze_post:
            logger.info(
                "[Bronze] ExcellenceOptimizer + DSP-Fallback übersprungen — kein positiver Gain im Bronze-Modus"
            )
        else:
            try:
                from backend.core.excellence_optimizer import optimize_for_excellence

                restored_audio, _excellence_result = optimize_for_excellence(
                    restored_audio, sample_rate, material=material_type.value
                )
                logger.info("🏆 ExcellenceOptimizer: %s", _excellence_result.summary())

                # §8.1 Re-Verifikation: Musical Goals nach ExcellenceOptimizer prüfen
                if _pre_excellence_mg_scores:
                    try:
                        _post_ex_scores = _pre_ex_checker.measure_all(
                            restored_audio, sample_rate, reference=_pre_ex_ref, material_type=_pre_ex_mat
                        )
                        _ex_regressions = [
                            g
                            for g in _pre_excellence_mg_scores
                            if _post_ex_scores.get(g, 0.0) < _pre_excellence_mg_scores[g] - 0.02
                        ]
                        if _ex_regressions:
                            logger.warning(
                                "⚠️ ExcellenceOptimizer: Rollback — Musical Goals Regression in %s",
                                ", ".join(_ex_regressions),
                            )
                            restored_audio = _pre_excellence_audio.copy()
                            _excellence_result = None
                        else:
                            logger.debug("ExcellenceOptimizer: Musical Goals re-verification passed")
                    except Exception as _ex_rv_exc:
                        logger.debug("ExcellenceOptimizer re-verification skipped: %s", _ex_rv_exc)
            except Exception as _ex_exc:
                logger.warning("ExcellenceOptimizer nicht verfügbar — DSP-Fallback aktiv: %s", _ex_exc)
                # Guaranteed DSP-Fallback: Presence enhancement + NaN-Guard (§Checkliste §3.x)
                try:
                    from scipy.signal import butter as _butter
                    from scipy.signal import filtfilt as _ex_filtfilt

                    _ex_rms = float(np.sqrt(np.mean(restored_audio.astype(np.float64) ** 2) + 1e-12))
                    if _ex_rms > 1e-4:  # Nicht auf Stille anwenden
                        # Subtile Präsenz-Auffrischung (3–8 kHz, +0.5 dB) als Minimal-Harmonic-Boost
                        _nyq = sample_rate / 2.0
                        _ex_b, _ex_a = _butter(2, [min(3000.0 / _nyq, 0.95), min(8000.0 / _nyq, 0.99)], btype="band")
                        # §2.51: filtfilt (zero-phase) statt lfilter — kausaler IIR-BP erzeugte
                        # Gruppenversatz und Comb-Filter beim Addieren auf restored_audio
                        _ex_n = restored_audio.shape[-1]
                        _ex_presence = (
                            _ex_filtfilt(_ex_b, _ex_a, restored_audio) if _ex_n >= 15 else restored_audio * 0.0
                        )
                        # Gain-Faktor: 0.05 ≈ +0.4 dB Präsenz-Anhebung
                        restored_audio = np.clip(restored_audio + 0.05 * _ex_presence, -1.0, 1.0)
                    restored_audio = np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0)
                    logger.info("ExcellenceOptimizer DSP-Fallback: Präsenz-Auffrischung 3–8 kHz angewendet")
                except Exception as _ex_fb_exc:
                    restored_audio = np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0)
                    logger.debug("ExcellenceOptimizer DSP-Fallback nicht verfügbar: %s", _ex_fb_exc)

        # §2.28 HarmonicPreservationGuard — Post-Hoc-Harmonische-Energiekorrektur (§2.28 Spec)
        # Spezifikations-Hinweis §2.28: Ideale Position wäre VOR phase_03 (G_floor-Override).
        # Aktuelle Implementierung: Post-Hoc-Korrektur nach Pipeline — funktional äquivalent,
        # da extract_harmonic_mask() stets auf original_audio_for_goals (Pre-Pipeline) arbeitet
        # und apply_correction() die Harmonik-Energie-Referenz H_ref aus dem Original bezieht.
        # Ergebnis: Harmonik-Energie die durch NR abgesenkt wurde, wird auf 85 % wiederhergestellt.
        # SHELLAC / WAX_CYLINDER: HPG überspringen — bei SNR ≈ 6 dB ist CREPE/pYIN
        # f₀-Schätzung unzuverlässig (falsche Harmonik-Maske → gain ×2 an Rauschbins →
        # NSIM-Kollaps). HPG nur für Materialien mit SNR ≥ ~12 dB aktivieren.
        _hpg_skip_materials = {"shellac", "wax_cylinder"}
        if material_type.value not in _hpg_skip_materials:
            try:
                from backend.core.harmonic_preservation_guard import get_harmonic_preservation_guard

                _hpg = get_harmonic_preservation_guard()
                _hpg_instrument_tag = {
                    "vinyl": "piano_mid",
                    "tape": "piano_mid",
                    "shellac": "piano_bass",
                    "reel_tape": "piano_mid",
                    "cd_digital": "piano_mid",
                    "mp3_low": "piano_mid",
                    "mp3_high": "piano_mid",
                    "aac": "piano_mid",
                    "dat": "piano_mid",
                    "minidisc": "piano_mid",
                }.get(material_type.value, "unknown")
                # §Y2 HPG SNR-Guard: if phase_03 strongly denoised the audio (noise floor
                # reduction > 12 dB), the pre-pipeline harmonic mask was extracted from noisy
                # audio and may include harmonic-band noise peaks. Recompute mask from the
                # restored (denoised) audio to get a clean harmonic reference.
                _hpg_ref_audio = original_audio_for_goals
                try:
                    _hpg_nf_original = 20.0 * np.log10(
                        max(float(np.percentile(np.abs(original_audio_for_goals.flatten()), 5)), 1e-12)
                    )
                    _hpg_nf_restored = 20.0 * np.log10(
                        max(float(np.percentile(np.abs(restored_audio.flatten()), 5)), 1e-12)
                    )
                    _hpg_snr_gain = _hpg_nf_original - _hpg_nf_restored  # positive = noise floor reduced
                    # Guard against floor-limited measurements: the raw 5th-percentile drops to
                    # the 1e-12 protection floor (~-240 dBFS) in music after denoising when silence
                    # gaps / pauses dominate the lowest 5% of samples.  The guard then fires on
                    # healthy audio whose restored signal is NOT silent — it is simply gap-quiet.
                    # Fix: only recompute the HPG mask if the 5th-percentile is above the analytical
                    # floor (-200 dBFS is well above 20*log10(1e-12)+1 ≈ -239 dBFS floor).
                    _HPG_FLOOR_DB = -200.0
                    if _hpg_snr_gain > 12.0 and _hpg_nf_restored > _HPG_FLOOR_DB:
                        _hpg_ref_audio = restored_audio
                        _hpg_pre_mask, _hpg_pre_href = None, None  # force fresh extraction from denoised audio
                        logger.info(
                            "§Y2 HPG SNR-Guard: noise floor reduced %.1f dB (%.1f → %.1f dBFS) > 12 dB "
                            "→ recomputing HPG mask from denoised audio",
                            _hpg_snr_gain,
                            _hpg_nf_original,
                            _hpg_nf_restored,
                        )
                except Exception as _hpg_snr_exc:
                    logger.debug("HPG SNR-Guard measurement failed (non-critical): %s", _hpg_snr_exc)

                if _hpg_pre_mask is not None and _hpg_pre_href is not None:
                    _hpg_mask, _hpg_href = _hpg_pre_mask, _hpg_pre_href
                    logger.debug("§2.28 HPG: Pre-Phase-Maske wiederverwendet")
                else:
                    _hpg_mask, _hpg_href = _hpg.extract_harmonic_mask(
                        _hpg_ref_audio, sample_rate, instrument_tag=_hpg_instrument_tag
                    )
                restored_audio = _hpg.apply_correction(restored_audio, _hpg_href, _hpg_mask, sample_rate)
                restored_audio = np.clip(np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                logger.info("§2.28 HPG: Harmonische Energiekorrektur angewendet (tag=%s)", _hpg_instrument_tag)
            except Exception as _hpg_exc:
                logger.debug("HarmonicPreservationGuard nicht verfügbar: %s", _hpg_exc)
        else:
            logger.info(
                "§2.28 HPG: Übersprungen für material=%s (SNR zu niedrig für f₀-Schätzung)",
                material_type.value,
            )

        # §2.27 TDP Recombination — Percussive + verarbeiteter harmonischer Anteil (OLA)
        if _tdp_proc is not None and _tdp_percussive is not None and _tdp_harmonic_ready:
            try:
                restored_audio = _tdp_proc.recombine(_tdp_percussive, restored_audio, sample_rate, _tdp_percussive)
                restored_audio = np.clip(np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                logger.info("§2.27 TDP: Recombination abgeschlossen (OLA-Crossfade 10 ms Hanning)")
            except Exception as _tdp_rc_exc:
                logger.debug("TDP Recombination fehlgeschlagen: %s", _tdp_rc_exc)

        # --- HarmonicLattice: Harmonische Konsistenzerzwingung (§2.11 Spec) ---
        _lattice_result = None
        try:
            from backend.core.harmonic_lattice_analyzer import get_harmonic_lattice

            _hla = get_harmonic_lattice()
            # Instrument-Tag aus Material ableiten (konservative Prior-Wahl)
            _hla_tag = {
                "vinyl": "piano_mid",
                "tape": "piano_mid",
                "shellac": "piano_bass",
                "reel_tape": "piano_mid",
                "cd_digital": "piano_mid",
                "mp3_low": "piano_mid",
                "mp3_high": "piano_mid",
                "aac": "piano_mid",
            }.get(material_type.value, "unknown")
            _lattice_result = _hla.analyze(restored_audio, sample_rate, instrument_tag=_hla_tag)
            if _lattice_result.needs_enforcement:
                restored_audio = _hla.enforce_coherence(restored_audio, sample_rate, _lattice_result)
                logger.info(
                    "🎵 HarmonicLattice: Korrektur angewendet (lattice_score=%.3f B=%.5f n_partials_korrigiert=%d)",
                    _lattice_result.lattice_score,
                    _lattice_result.inharmonicity_b,
                    sum(1 for p in _lattice_result.partials if p.needs_correction),
                )
            else:
                logger.debug("HarmonicLattice: OK (lattice_score=%.3f)", _lattice_result.lattice_score)
            # NaN/Inf-Guard nach HarmonicLattice
            restored_audio = np.clip(np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
        except Exception as _hl_exc:
            logger.debug("HarmonicLatticeAnalyzer nicht verfügbar: %s", _hl_exc)

        _cb(93, "Qualitätsprüfung…")

        # --- PerceptualQualityScorer: PQS-MOS Messung (§2.6 Spec) ---
        _pqs_result = None
        try:
            from backend.core.perceptual_quality_scorer import (
                score_audio as _score_audio,
            )
            from backend.core.perceptual_quality_scorer import (
                score_audio_absolute as _score_abs,
            )

            _shape_match = original_audio_for_goals.shape == restored_audio.shape and original_audio_for_goals.size > 0
            if _shape_match:
                _pqs_result = _score_audio(original_audio_for_goals, restored_audio, sample_rate)
            else:
                _pqs_result = _score_abs(restored_audio, sample_rate)
            if _pqs_result.pqs_mos >= 4.0:
                logger.info(
                    "📊 PQS-MOS: %.2f (NSIM=%.3f MCD=%.1f dB Kohärenz=%.3f)",
                    _pqs_result.pqs_mos,
                    _pqs_result.nsim,
                    _pqs_result.mcd_db,
                    _pqs_result.spectral_coherence,
                )
            else:
                logger.warning(
                    "⚠️ PQS-MOS unter Zielwert 4.0: %.2f (NSIM=%.3f MCD=%.1f dB)",
                    _pqs_result.pqs_mos,
                    _pqs_result.nsim,
                    _pqs_result.mcd_db,
                )
            # v9.10.58: VERSA-MOS-Gate mit 2. ExcellenceOptimizer-Pass entfernt.
            # Wissenschaftliche Begründung: Identischer ExcellenceOptimizer auf bereits
            # optimierten Daten akkumuliert STFT-Rundungsfehler. Die Korrektur bei
            # niedrigem MOS erfolgt einmalig im ExzellenzDenker (AurikDenker Stufe 7).
            if _pqs_result is not None and _pqs_result.pqs_mos < 4.0:
                logger.info(
                    "PQS-MOS=%.2f < 4.0 — Korrektur wird im ExzellenzDenker (Stufe 7) behandelt",
                    _pqs_result.pqs_mos,
                )
        except Exception as _pqs_exc:
            logger.warning("PerceptualQualityScorer nicht verfügbar (PQS_UNAVAILABLE): %s", _pqs_exc)
            _fail_reasons.append(
                {
                    "component": "PerceptualQualityScorer",
                    "error_code": "PQS_UNAVAILABLE",
                    "severity": "degraded",
                    "exc_type": type(_pqs_exc).__name__,
                    "exc_msg": str(_pqs_exc),
                }
            )

        # §2.31 AdaptiveGoalThresholds — Kontextadaptive Ziel-Schwellenwerte
        _adaptive_goals = None
        try:
            from backend.core.musical_goals.adaptive_goals_system import get_adaptive_goals_and_config

            _adaptive_goals = get_adaptive_goals_and_config(
                audio,
                sample_rate,
                _classified_material,
                defect_result,
                restorability_score=float(_pmgg_restorability_score),  # §2.31 SCALE_FACTORS
            )
            logger.info(
                "🎯 AdaptiveGoalThresholds: konfiguriert (material=%s rest=%.0f)",
                getattr(_classified_material, "value", str(_classified_material)),
                float(_pmgg_restorability_score),
            )
        except Exception as _agt_exc:
            logger.debug("AdaptiveGoalThresholds nicht verfügbar: %s", _agt_exc)

        # §2.33 PhysicalCeilingEstimator — Physikalische Obergrenze der Restaurierbarkeit
        _physical_ceiling = None
        try:
            from backend.core.physical_ceiling_estimator import estimate_physical_ceiling

            _scores_for_ceiling = _pqs_result.__dict__ if _pqs_result is not None else {}
            _mat_for_ceiling = material_type.value if material_type is not None else "unknown"
            _physical_ceiling = estimate_physical_ceiling(
                restored_audio, sample_rate, _scores_for_ceiling, _mat_for_ceiling
            )
            logger.info(
                "📐 PhysicalCeilingEstimator: bandwidth=%.0f Hz further_opt=%s",
                _physical_ceiling.effective_bandwidth_hz,
                _physical_ceiling.further_optimization_worthwhile,
            )
        except Exception as _pce_exc:
            logger.debug("PhysicalCeilingEstimator nicht verfügbar: %s", _pce_exc)

        # --- Musikalische Exzellenz: 14-Ziele-Messung (§1.2 Spec) ---
        _musical_goal_scores: dict = {}
        _musical_goals_passed: dict = {}
        _musical_excellence_score: float = 0.0
        _effective_goal_thresholds: dict = {}  # §Bug#3: Pre-init vor try-Block — NameError-Guard
        try:
            from backend.core.musical_goals.musical_goals_metrics import MusicalGoalsChecker

            _mg_checker = MusicalGoalsChecker(mode=getattr(getattr(self.config, "mode", None), "value", "restoration"))
            _effective_goal_thresholds = dict(_mg_checker.thresholds)
            # AdaptiveGoalThresholds: robust über alle bekannten Payload-Formen aufloesen.
            if _adaptive_goals is not None:
                try:
                    _adaptive_values = self._resolve_adaptive_goal_thresholds(_adaptive_goals)
                    for _goal_name, _val in _adaptive_values.items():
                        if _goal_name in _effective_goal_thresholds:
                            _effective_goal_thresholds[_goal_name] = float(_val)
                except Exception as _agt_apply_exc:
                    logger.debug("AdaptiveGoalThresholds konnten nicht angewendet werden: %s", _agt_apply_exc)

            # §09.2 [RELEASE_MUST] Song-Goal-Targets: Era × Material × Genre adaptive floors
            # Computed earlier in restore() as self._song_goal_targets (calibration_matrix.estimate_song_goal_targets)
            # §2.54 Material-adaptive blend: large canonical-vs-SGT delta → weight strongly toward SGT.
            # Same logic as PMGG per-phase (§09.2 adaptive blend) so pipeline-end threshold
            # is consistent with what PMGG accepted during the phase loop.
            _sgt_local = getattr(self, "_pmgg_ceiling_capped_targets", None) or getattr(
                self, "_song_goal_targets", None
            )
            if isinstance(_sgt_local, dict) and _sgt_local:
                try:
                    for _sgt_goal, _sgt_val in _sgt_local.items():
                        if _sgt_goal in _effective_goal_thresholds:
                            _cur_thr = float(_effective_goal_thresholds[_sgt_goal])
                            _sgt_f = float(_sgt_val)
                            _delta = _cur_thr - _sgt_f
                            # Material-adaptive blend weight (same logic as PMGG §09.2 per-phase):
                            if _delta > 0.10:
                                # Large constraint: use SGT directly (physical ceiling or strong bias)
                                _blended_thr = _sgt_f
                            elif _delta > 0.04:
                                # Moderate constraint: 40% canonical / 60% SGT
                                _blended_thr = 0.40 * _cur_thr + 0.60 * _sgt_f
                            else:
                                # Small or upward: 60% canonical / 40% SGT (conservative)
                                _blended_thr = 0.60 * _cur_thr + 0.40 * _sgt_f
                            _effective_goal_thresholds[_sgt_goal] = float(np.clip(_blended_thr, 0.30, 0.99))
                except Exception as _sgt_apply_exc:
                    logger.debug("§09.2 SongGoalTargets konnten nicht angewendet werden: %s", _sgt_apply_exc)

            # §2.31 Physical-Ceiling clamp: Zielschwellen dürfen physikalische Decke nicht überschreiten.
            if _physical_ceiling is not None:
                try:
                    _ceiling_map = getattr(_physical_ceiling, "ceiling", None)
                    if isinstance(_ceiling_map, dict):
                        for _goal_name, _ceil_val in _ceiling_map.items():
                            if _goal_name in _effective_goal_thresholds and math.isfinite(float(_ceil_val)):
                                _effective_goal_thresholds[_goal_name] = min(
                                    float(_effective_goal_thresholds[_goal_name]),
                                    float(_ceil_val),
                                )
                except Exception as _ceil_exc:
                    logger.debug("PhysicalCeiling clamp nicht verfügbar: %s", _ceil_exc)

            # §0a [RELEASE_MUST] Adaptive-Threshold Material-Ceiling (v9.11.14):
            # adaptive_thresholds dürfen das physikalisch erreichbare P1/P2-Ceiling des
            # Quellmaterials nicht überschreiten. Degradiertes Vinyl/Shellac/Tape kann
            # die kanonischen Böden (natuerlichkeit ≥ 0.90) physikalisch nicht erreichen.
            # Ohne diesen Guard schlägt das Export-Gate für korrekt restauriertes analoges
            # Material fälschlicherweise an (adaptive_threshold 0.82 > vinyl-Ceiling 0.82 ok,
            # aber shellac 0.68 ist durch 0.82 unerreichbar → fälschlich FAIL).
            _ADAPTIVE_THR_MATERIAL_CEILING: dict[str, dict[str, float]] = {
                "shellac": {
                    "natuerlichkeit": 0.68,
                    "authentizitaet": 0.65,
                    "tonal_center": 0.70,
                    "timbre_authentizitaet": 0.65,
                    "artikulation": 0.61,
                    "waerme": 0.62,
                    "brillanz": 0.52,  # BW ≤ 8 kHz → HF crest physically low
                    "transparenz": 0.55,
                    "separation_fidelity": 0.60,
                },
                "wax_cylinder": {
                    "natuerlichkeit": 0.66,
                    "authentizitaet": 0.63,
                    "tonal_center": 0.68,
                    "timbre_authentizitaet": 0.63,
                    "artikulation": 0.59,
                    "waerme": 0.60,
                    "brillanz": 0.40,  # BW ≤ 5 kHz
                    "transparenz": 0.50,
                    "separation_fidelity": 0.55,
                },
                "wire_recording": {
                    "natuerlichkeit": 0.66,
                    "authentizitaet": 0.63,
                    "tonal_center": 0.68,
                    "timbre_authentizitaet": 0.63,
                    "artikulation": 0.59,
                    "waerme": 0.60,
                    "brillanz": 0.44,  # BW ≤ 6 kHz
                    "transparenz": 0.52,
                    "separation_fidelity": 0.56,
                },
                "vinyl": {
                    "natuerlichkeit": 0.82,
                    "authentizitaet": 0.79,
                    "tonal_center": 0.84,
                    "timbre_authentizitaet": 0.79,
                    "artikulation": 0.76,
                    "waerme": 0.74,
                    "brillanz": 0.82,  # Vinyl BW ≤ 16 kHz; crest achievable post-phase_06
                    "transparenz": 0.78,
                    "separation_fidelity": 0.76,
                },
                "reel_tape": {
                    "natuerlichkeit": 0.82,
                    "authentizitaet": 0.79,
                    "tonal_center": 0.84,
                    "timbre_authentizitaet": 0.79,
                    "artikulation": 0.76,
                    "waerme": 0.74,
                    "brillanz": 0.82,
                    "transparenz": 0.78,
                    "separation_fidelity": 0.76,
                },
                "tape": {
                    "natuerlichkeit": 0.78,
                    "authentizitaet": 0.75,
                    "tonal_center": 0.80,
                    "timbre_authentizitaet": 0.75,
                    "artikulation": 0.72,
                    "waerme": 0.72,
                    "brillanz": 0.78,
                    "transparenz": 0.74,
                    "separation_fidelity": 0.72,
                },
                "cassette": {
                    "natuerlichkeit": 0.76,
                    "authentizitaet": 0.73,
                    "tonal_center": 0.78,
                    "timbre_authentizitaet": 0.73,
                    "artikulation": 0.70,
                    "waerme": 0.70,
                    "brillanz": 0.72,
                    "transparenz": 0.68,
                    "separation_fidelity": 0.68,
                },
                "mp3_low": {
                    # MP3 128kbps or lower: severe HF codec artefacts, BW ~15.5 kHz.
                    # brillanz (HF crest 2-16 kHz): achievable ~0.20-0.35 after Apollo repair;
                    # transparenz and separation_fidelity similarly constrained.
                    # These ceilings prevent false FAIL against canonical 0.78/0.82 thresholds
                    # that assume clean 20 kHz audio (§0a Material-Ceiling, §0d).
                    "natuerlichkeit": 0.76,
                    "authentizitaet": 0.74,
                    "tonal_center": 0.78,
                    "timbre_authentizitaet": 0.74,
                    "artikulation": 0.70,
                    "waerme": 0.70,
                    "brillanz": 0.45,  # MP3 codec destroys HF crest; crest <2.5 even post-Apollo
                    "transparenz": 0.60,  # Codec masking residuals floor transparenz
                    "separation_fidelity": 0.62,  # Stem-sep on lossy source physically limited
                },
                # §0a §2.44 [RELEASE_MUST] Defensive fallback ceilings for materials not in the
                # primary adaptive chain above. Without these, if adaptive_goals_system, SGT-blend
                # and PhysicalCeiling all fail (exceptions), _effective_goal_thresholds stays at
                # canonical CD-level → false FAIL + unnecessary Recovery cascade for valid output.
                "lacquer_disc": {
                    # Acetat-Lackfolie (1930–1950): BW ≤ 8 kHz like shellac, SNR ~20–25 dB.
                    # Slightly better than shellac but still physically far below canonical.
                    "natuerlichkeit": 0.69,
                    "authentizitaet": 0.66,
                    "tonal_center": 0.71,
                    "timbre_authentizitaet": 0.66,
                    "artikulation": 0.62,
                    "waerme": 0.63,
                    "brillanz": 0.50,  # BW ≤ 8 kHz; marginally better than shellac
                    "transparenz": 0.56,
                    "separation_fidelity": 0.60,
                },
                "mp3_high": {
                    # MP3 ≥ 128 kbps: moderate codec artefacts, BW ~16–17 kHz.
                    # HF crest reduced but not destroyed; separability limited by codec masking.
                    "natuerlichkeit": 0.82,
                    "authentizitaet": 0.80,
                    "tonal_center": 0.84,
                    "timbre_authentizitaet": 0.80,
                    "artikulation": 0.76,
                    "waerme": 0.74,
                    "brillanz": 0.65,  # BW ~16–17 kHz; moderate HF crest degradation
                    "transparenz": 0.70,
                    "separation_fidelity": 0.70,
                },
                "aac": {
                    # AAC/M4A: modern codec, generally better quality than MP3 at same bitrate.
                    # HF preservation better than mp3_high; pre-echo artefacts minor.
                    "natuerlichkeit": 0.84,
                    "authentizitaet": 0.82,
                    "tonal_center": 0.86,
                    "timbre_authentizitaet": 0.82,
                    "artikulation": 0.78,
                    "waerme": 0.76,
                    "brillanz": 0.72,
                    "transparenz": 0.74,
                    "separation_fidelity": 0.74,
                },
                "minidisc": {
                    # MiniDisc (ATRAC-1): lossy codec, BW ~17 kHz, characteristic pre-echo.
                    # HF quality similar to mp3_high; ATRAC pumping may reduce separation.
                    "natuerlichkeit": 0.80,
                    "authentizitaet": 0.78,
                    "tonal_center": 0.82,
                    "timbre_authentizitaet": 0.78,
                    "artikulation": 0.74,
                    "waerme": 0.72,
                    "brillanz": 0.64,
                    "transparenz": 0.68,
                    "separation_fidelity": 0.68,
                },
                "dat": {
                    # Digital Audio Tape: near-CD quality; jitter and minor dropout are main issues.
                    # Almost canonical, only minimal HF/separation ceiling needed.
                    "natuerlichkeit": 0.88,
                    "authentizitaet": 0.86,
                    "tonal_center": 0.92,
                    "timbre_authentizitaet": 0.86,
                    "artikulation": 0.84,
                    "waerme": 0.80,
                    "brillanz": 0.82,
                    "transparenz": 0.82,
                    "separation_fidelity": 0.82,
                },
            }
            try:
                _mat_str_ceil = str(getattr(material_type, "value", material_type) or "unknown").lower()
                _mat_ceil_map = _ADAPTIVE_THR_MATERIAL_CEILING.get(_mat_str_ceil)
                if _mat_ceil_map and _effective_goal_thresholds:
                    _n_capped = 0
                    for _mc_goal, _mc_ceil in _mat_ceil_map.items():
                        if _mc_goal in _effective_goal_thresholds:
                            _cur = float(_effective_goal_thresholds[_mc_goal])
                            if _cur > _mc_ceil:
                                _effective_goal_thresholds[_mc_goal] = _mc_ceil
                                _n_capped += 1
                    if _n_capped:
                        logger.debug(
                            "§0a Material-Ceiling: %d P1/P2-Threshold(s) für material=%s gekappt.",
                            _n_capped,
                            _mat_str_ceil,
                        )
                # §2.46a Chain-End-Ceiling: the LAST stage of the transfer chain can impose
                # stricter ceilings than the primary source material (e.g. vinyl→cassette→mp3_low:
                # primary=vinyl but codec destroys HF → brillanz ceiling from mp3_low applies).
                # Only HF-sensitive goals are chain-end-adjusted; P1/P2 goals remain primary-based.
                _chain_end_hf_goals = {"brillanz", "transparenz", "separation_fidelity"}
                try:
                    _chain_info_obj = getattr(self, "_active_chain_info", None)
                    _chain_list: list[str] = []
                    if _chain_info_obj is not None:
                        _cl = None
                        if isinstance(_chain_info_obj, dict):
                            _cl = _chain_info_obj.get("chain") or _chain_info_obj.get("transfer_chain")
                        else:
                            _cl = getattr(_chain_info_obj, "chain", None) or getattr(
                                _chain_info_obj, "transfer_chain", None
                            )
                        if isinstance(_cl, (list, tuple)):
                            _chain_list = [str(s).lower() for s in _cl]
                    if len(_chain_list) >= 2:
                        _chain_end = _chain_list[-1]
                        _chain_end_map = _ADAPTIVE_THR_MATERIAL_CEILING.get(_chain_end, {})
                        _n_chain_capped = 0
                        for _hf_goal in _chain_end_hf_goals:
                            if _hf_goal in _chain_end_map and _hf_goal in _effective_goal_thresholds:
                                _chain_ceil = float(_chain_end_map[_hf_goal])
                                if float(_effective_goal_thresholds[_hf_goal]) > _chain_ceil:
                                    _effective_goal_thresholds[_hf_goal] = _chain_ceil
                                    _n_chain_capped += 1
                        if _n_chain_capped:
                            logger.info(
                                "§2.46a Chain-End-Ceiling: %d HF-Goal(s) gekappt durch Ketten-Ende '%s' (chain=%s).",
                                _n_chain_capped,
                                _chain_end,
                                _chain_list,
                            )
                except Exception as _chain_ceil_exc:
                    logger.debug("§2.46a Chain-End-Ceiling fehlgeschlagen (non-blocking): %s", _chain_ceil_exc)
            except Exception as _mc_exc:
                logger.debug("§0a Material-Ceiling-Check fehlgeschlagen (non-blocking): %s", _mc_exc)

            _applicable_goal_names = (
                set(_goal_applicability_result.applicable)
                if _goal_applicability_result is not None
                else set(_mg_checker.thresholds.keys())
            )
            # reference= gibt Authentizitäts- und Timbre-Metriken entscheidend mehr Kontext
            # §9.12.3 Shape-Invarianz-Fix: (2,N) vs (N,2) Orientierungsunterschied darf
            # reference NICHT auf None setzen → würde no-reference Pfad in AuthentizitaetMetric
            # triggern (spectral_consistency = max(0, 1 - flatness/0.40) statt Chroma-Korrelation).
            # Fix: Shape-Check nur auf Audio-Länge (max(shape)), nicht auf exaktes Shape-Match.
            # measure_all() transponiert (2,N)→(N,2) intern via audio.T — Orientierung kein Problem.
            _orig_n = int(np.max(original_audio_for_goals.shape))
            _rest_n = int(np.max(restored_audio.shape))
            _mg_ref = original_audio_for_goals if abs(_orig_n - _rest_n) <= 64 else None

            # §0d Ebene 2 / §1.2a [RELEASE_MUST] Carrier-Recovery-Referenz-Shift:
            # §2.54 Material-adaptiver Threshold: analoge Carrier-Inversion (vinyl/tape/shellac)
            # erzeugt log-PSD-Kosinusähnlichkeit ~0.92+ (spektrale Form bleibt erhalten),
            # daher CCR-Ratio natürlich niedrig (~0.07 für vinyl). Analoges Material benötigt
            # niedrigeren Threshold 0.05 statt 0.15, damit Reference-Shift korrekt triggert.
            _ccr_ratio = getattr(self, "_carrier_chain_recovery_ratio", 0.0)
            _ccr_checkpoint = getattr(self, "_best_carrier_checkpoint", None)
            _ccr_mat_val = str(getattr(material_type, "value", material_type) or "unknown").lower()
            _CCR_ANALOG_MATS = frozenset(
                {
                    "vinyl",
                    "shellac",
                    "reel_tape",
                    "tape",
                    "cassette",
                    "wax_cylinder",
                    "wire_recording",
                    "minidisc",
                }
            )
            _ccr_threshold = 0.05  # §0d: unified threshold for all materials (analog + digital)
            _ccr_contract_shift = _ccr_ratio > 0.15
            if (
                _ccr_ratio > _ccr_threshold
                and _ccr_checkpoint is not None
                and _ccr_checkpoint.shape == restored_audio.shape
            ):
                _mg_ref = _ccr_checkpoint
                logger.info(
                    "§0d/§1.2a Reference-Shift aktiv: mat=%s carrier_recovery_ratio=%.3f > thr=%.2f → "
                    "Goal-Referenz auf best_carrier_checkpoint (statt degradiertem Input)",
                    _ccr_mat_val,
                    _ccr_ratio,
                    _ccr_threshold,
                )

            _musical_goal_scores = _mg_checker.measure_all(
                restored_audio,
                sample_rate,
                reference=_mg_ref,
                material_type=_ccr_mat_val,
                panns_singing=float(self._restoration_context.get("panns_singing", 0.0)),
            )
            _musical_goals_passed = {
                k: (
                    True
                    if k not in _applicable_goal_names
                    else float(_musical_goal_scores.get(k, 0.0)) >= _effective_goal_thresholds.get(k, 0.85)
                )
                for k in _musical_goal_scores
            }
            _musical_excellence_score = sum(_musical_goal_scores.values()) / max(len(_musical_goal_scores), 1)
            _mg_violations = [k for k, p in _musical_goals_passed.items() if not p and k in _applicable_goal_names]

            # §GOAL_MONITOR [RELEASE_MUST] Structured per-goal scorecard for goal_monitor.py.
            # Logs ALL 14 goals with score, effective threshold, gap, and pass/fail status
            # in a single parseable line so post-run analysis can show exactly which goals
            # are below threshold and by how much — without reading internal Python state.
            try:
                _scorecard_parts = []
                for _sc_goal in sorted(_musical_goal_scores.keys()):
                    _sc_score = float(_musical_goal_scores.get(_sc_goal, 0.0))
                    _sc_thr = float(_effective_goal_thresholds.get(_sc_goal, 0.85))
                    _sc_gap = _sc_score - _sc_thr
                    _sc_applicable = _sc_goal in _applicable_goal_names
                    _sc_passed = _musical_goals_passed.get(_sc_goal, True)
                    _scorecard_parts.append(
                        f"{_sc_goal}:"
                        f"score={_sc_score:.4f},"
                        f"thr={_sc_thr:.4f},"
                        f"gap={_sc_gap:+.4f},"
                        f"pass={'1' if _sc_passed else '0'},"
                        f"app={'1' if _sc_applicable else '0'}"
                    )
                logger.info(
                    "🎯 GOAL_SCORECARD mat=%s mode=%s excellence=%.4f violations=%d|%s",
                    str(
                        getattr(material_type, "value", material_type)
                        or getattr(_classified_material, "value", _classified_material)
                        or "unknown"
                    ),
                    "studio_2026" if self.is_studio_mode() else "restoration",
                    _musical_excellence_score,
                    len(_mg_violations),
                    ";".join(_scorecard_parts),
                )
            except Exception as _sc_exc:
                logger.warning("GOAL_SCORECARD log failed (non-blocking): %s", _sc_exc, exc_info=True)

            if _mg_violations:
                # v9.10.58: Musical Goals Re-Pass in UV3 entfernt — wissenschaftlich nicht
                # gerechtfertigt (Ephraim & Malah 1984: cascaded identical processing amplifies
                # STFT roundtrip errors). Stattdessen: material-sichere End-Gate-Recovery
                # über gewichtete Blend-Kaskaden ohne zusätzliche Signalprozessor-Kaskadierung.
                _initial_mg_violations = list(_mg_violations)
                _goal_recovery_meta = {
                    "attempted": True,
                    "initial_violations": list(_initial_mg_violations),
                    "p1p2_blend_applied": False,
                    "global_blend_applied": False,
                }
                logger.warning(
                    "🎵 Musical Goals Verletzungen (%d/%d): %s — autonome End-Gate-Recovery aktiv",
                    len(_mg_violations),
                    len(_musical_goal_scores),
                    ", ".join(_mg_violations),
                )

                # §9.8 End-Gate: P1/P2 Goal Recovery Cascade
                _P1P2_GOALS = {
                    "natuerlichkeit",
                    "authentizitaet",
                    "tonal_center",
                    "timbre_authentizitaet",
                    "artikulation",
                }
                _p1p2_violations = [g for g in _mg_violations if g in _P1P2_GOALS]
                if (
                    _p1p2_violations
                    and original_audio_for_goals is not None
                    and restored_audio.shape == original_audio_for_goals.shape
                ):
                    _BLEND_ALPHAS = [0.92, 0.85, 0.78, 0.70]
                    _best_blend_audio = None
                    _best_blend_scores = None
                    _best_blend_alpha = None
                    _best_resolved_count = 0
                    _best_regression_count = float("inf")

                    for _alpha in _BLEND_ALPHAS:
                        try:
                            _blended = np.clip(
                                _alpha * restored_audio + (1.0 - _alpha) * original_audio_for_goals,
                                -1.0,
                                1.0,
                            )
                            _blend_scores = _mg_checker.measure_all(
                                _blended, sample_rate, reference=_mg_ref, material_type=_ccr_mat_val
                            )
                            _resolved = sum(
                                1
                                for g in _p1p2_violations
                                if _blend_scores.get(g, 0.0) >= _effective_goal_thresholds.get(g, 0.85)
                            )
                            _regressions = sum(
                                1
                                for g in _musical_goal_scores
                                if _blend_scores.get(g, 0.0) < _musical_goal_scores.get(g, 0.0) - 0.02
                            )

                            logger.debug(
                                "End-Gate P1/P2: alpha=%.2f → resolved=%d/%d, regressions=%d",
                                _alpha,
                                _resolved,
                                len(_p1p2_violations),
                                _regressions,
                            )

                            if _resolved > _best_resolved_count or (
                                _resolved == _best_resolved_count and _regressions < _best_regression_count
                            ):
                                _best_resolved_count = _resolved
                                _best_regression_count = _regressions
                                _best_blend_audio = _blended
                                _best_blend_scores = _blend_scores
                                _best_blend_alpha = _alpha
                                if _resolved == len(_p1p2_violations) and _regressions == 0:
                                    break
                        except Exception as _blend_iter_exc:
                            logger.debug("End-Gate P1/P2 blend alpha=%.2f failed: %s", _alpha, _blend_iter_exc)

                    if (
                        _best_blend_audio is not None
                        and _best_blend_scores is not None
                        and _best_resolved_count > 0
                        and _best_regression_count <= 1
                    ):
                        logger.info(
                            "🔄 End-Gate: P1/P2 Recovery Blend (alpha=%.2f) — %d/%d wiederhergestellt",
                            _best_blend_alpha,
                            _best_resolved_count,
                            len(_p1p2_violations),
                        )
                        restored_audio = _best_blend_audio
                        _musical_goal_scores = _best_blend_scores
                        _musical_excellence_score = sum(_best_blend_scores.values()) / max(len(_best_blend_scores), 1)
                        _mg_violations = [
                            k
                            for k in _musical_goal_scores
                            if k in _applicable_goal_names
                            and float(_musical_goal_scores.get(k, 0.0)) < _effective_goal_thresholds.get(k, 0.85)
                        ]
                        _goal_recovery_meta["p1p2_blend_applied"] = True
                        _goal_recovery_meta["p1p2_blend_alpha"] = float(_best_blend_alpha)
                    else:
                        logger.debug("End-Gate: P1/P2-Recovery nicht übernommen")

                # Universal Recovery Cascade: alle verbleibenden Goal-Verletzungen
                # mit weighted-gap minimieren, nicht nur P1/P2.
                _remaining_violations = list(_mg_violations)
                if (
                    _remaining_violations
                    and original_audio_for_goals is not None
                    and restored_audio.shape == original_audio_for_goals.shape
                ):
                    _gw = getattr(self, "_song_goal_weights", None)
                    _current_gap, _current_n = _compute_weighted_goal_gap(
                        _musical_goal_scores,
                        _effective_goal_thresholds,
                        _applicable_goal_names,
                        _gw,
                    )
                    _UNIVERSAL_ALPHAS = [0.96, 0.92, 0.88, 0.84, 0.80, 0.75, 0.70, 0.64]
                    _best_u_audio = None
                    _best_u_scores = None
                    _best_u_alpha = None
                    _best_u_gap = _current_gap
                    _best_u_n = _current_n
                    _best_u_reg = float("inf")

                    for _alpha in _UNIVERSAL_ALPHAS:
                        try:
                            _blended = np.clip(
                                _alpha * restored_audio + (1.0 - _alpha) * original_audio_for_goals,
                                -1.0,
                                1.0,
                            )
                            _scores_u = _mg_checker.measure_all(
                                _blended, sample_rate, reference=_mg_ref, material_type=_ccr_mat_val
                            )
                            _gap_u, _n_u = _compute_weighted_goal_gap(
                                _scores_u,
                                _effective_goal_thresholds,
                                _applicable_goal_names,
                                _gw,
                            )
                            _reg_u = sum(
                                1
                                for g in _applicable_goal_names
                                if _scores_u.get(g, 0.0) < _musical_goal_scores.get(g, 0.0) - 0.025
                            )

                            logger.debug(
                                "End-Gate Universal: alpha=%.2f n=%d gap=%.5f regressions=%d",
                                _alpha,
                                _n_u,
                                _gap_u,
                                _reg_u,
                            )

                            if (
                                _n_u < _best_u_n
                                or (_n_u == _best_u_n and _gap_u < _best_u_gap - 1e-5)
                                or (_n_u == _best_u_n and abs(_gap_u - _best_u_gap) <= 1e-5 and _reg_u < _best_u_reg)
                            ):
                                _best_u_audio = _blended
                                _best_u_scores = _scores_u
                                _best_u_alpha = _alpha
                                _best_u_gap = _gap_u
                                _best_u_n = _n_u
                                _best_u_reg = _reg_u
                                if _n_u == 0 and _gap_u <= 1e-6:
                                    break
                        except Exception as _univ_exc:
                            logger.debug("End-Gate Universal blend alpha=%.2f failed: %s", _alpha, _univ_exc)

                    if (
                        _best_u_audio is not None
                        and _best_u_scores is not None
                        and (_best_u_n < _current_n or _best_u_gap < _current_gap - 1e-4)
                    ):
                        logger.info(
                            "🔄 End-Gate: Universal Goal-Recovery (alpha=%.2f) — violations %d→%d, gap %.5f→%.5f",
                            _best_u_alpha,
                            _current_n,
                            _best_u_n,
                            _current_gap,
                            _best_u_gap,
                        )
                        restored_audio = _best_u_audio
                        _musical_goal_scores = _best_u_scores
                        _musical_excellence_score = sum(_best_u_scores.values()) / max(len(_best_u_scores), 1)
                        _mg_violations = [
                            k
                            for k in _musical_goal_scores
                            if k in _applicable_goal_names
                            and float(_musical_goal_scores.get(k, 0.0)) < _effective_goal_thresholds.get(k, 0.85)
                        ]
                        _goal_recovery_meta["global_blend_applied"] = True
                        _goal_recovery_meta["global_blend_alpha"] = float(_best_u_alpha)

                _goal_recovery_meta["final_violations"] = list(_mg_violations)
                _goal_recovery_meta["resolved_count"] = max(0, len(_initial_mg_violations) - len(_mg_violations))
                _goal_recovery_meta["resolved"] = len(_mg_violations) == 0

                if _mg_violations:
                    _fail_reasons.append(
                        {
                            "component": "MusicalGoalsChecker",
                            "error_code": "MUSICAL_GOALS_VIOLATION",
                            "severity": "degraded",
                            "violated_goals": _mg_violations,
                            "scores": {k: round(float(_musical_goal_scores.get(k, 0.0)), 4) for k in _mg_violations},
                            "thresholds": {
                                k: round(float(_effective_goal_thresholds.get(k, 0.85)), 4) for k in _mg_violations
                            },
                            "recovery": {
                                "attempted": True,
                                "resolved_count": _goal_recovery_meta["resolved_count"],
                                "initial_violation_count": len(_initial_mg_violations),
                                "final_violation_count": len(_mg_violations),
                            },
                        }
                    )
            else:
                logger.info(
                    "🎵 Musical Goals: alle %d Ziele erfüllt (Ø %.3f)",
                    len(_musical_goal_scores),
                    _musical_excellence_score,
                )
        except Exception as _mg_exc:
            logger.warning("MusicalGoalsChecker nicht verfügbar (MUSICAL_GOALS_UNAVAILABLE): %s", _mg_exc)
            _fail_reasons.append(
                {
                    "component": "MusicalGoalsChecker",
                    "error_code": "MUSICAL_GOALS_UNAVAILABLE",
                    "severity": "degraded",
                    "exc_type": type(_mg_exc).__name__,
                    "exc_msg": str(_mg_exc),
                }
            )

        _cb(96, "Musical Goals geprüft…")

        # §2.34 GoalPriorityProtocol — Iterations-Abbruch-Entscheidung bei Ziel-Regression
        _goal_abort = None
        try:
            from backend.core.goal_priority_protocol import check_iteration_abort

            _scores_before_gpp = {"overall": getattr(_quality_before, "overall_score", 0.0)} if _quality_before else {}
            _scores_after_gpp = {"musical_excellence": _musical_excellence_score}
            _scores_after_gpp.update(_musical_goal_scores)
            _goal_abort = check_iteration_abort(_scores_before_gpp, _scores_after_gpp)
            if _goal_abort.should_abort:
                logger.warning(
                    "⛔ GoalPriorityProtocol: Abbruch empfohlen — %s (degradiert: %s)",
                    _goal_abort.reason,
                    getattr(_goal_abort, "degraded_goals", []),
                )
            else:
                logger.debug("GoalPriorityProtocol: kein Abbruch notwendig")
        except Exception as _gpp_exc:
            logger.debug("GoalPriorityProtocol nicht verfügbar: %s", _gpp_exc)

        # §8.2 EmotionalArcPreservationMetric — Emotionaler Dynamik-Bogen-Erhalt (Punkt 12)
        # §2.31d: < 10 s → EmotionalArcPreservation deaktivieren (kein repr. Arousal/Valence-Verlauf)
        _arc_result = None
        if _is_very_short:
            logger.info("§2.31d: Audio < 10s → EmotionalArcPreservationMetric deaktiviert")
        else:
            try:
                from backend.core.emotional_arc_preservation import measure_emotional_arc

                _arc_result = measure_emotional_arc(
                    original_audio_for_goals,
                    restored_audio,
                    sample_rate,
                    lyrics_saliency=_lge_saliency_for_eap,  # §2.36/§2.44: Lyrics-Salienz
                )
                if _arc_result.skipped:
                    logger.debug("EmotionalArc: übersprungen (Datei zu kurz, < 30 s)")
                elif _arc_result.arc_preserved:
                    logger.info(
                        "✅ EmotionalArc: Bogen erhalten — arousal_pearson=%.3f valence_pearson=%.3f",
                        _arc_result.arousal_pearson,
                        _arc_result.valence_pearson,
                    )
                else:
                    logger.warning(
                        "⚠️ EmotionalArc: Bogen nicht erfüllt — %s",
                        _arc_result.reason,
                    )
                    # §8.2 Spec: bindende Rollback-Garantie → Pre-Excellence-Audio wiederherstellen
                    _are_p = getattr(_arc_result, "arousal_pearson", 0.0)
                    _val_p = getattr(_arc_result, "valence_pearson", 0.0)

                    # §2.47 Adaptive-Intelligence: Wow/Flutter-Korrektur verändert
                    # die spektrale Flachheit legitim → Valence-Proxy fällt auf tape/vinyl.
                    # Material-adaptive Schwelle: tape/vinyl + wow/flutter > 0.5 → 0.55.
                    _wow_flutter_sev = float(
                        max(
                            defect_result.scores.get("wow", 0.0),
                            defect_result.scores.get("flutter", 0.0),
                        )
                        if defect_result is not None and hasattr(defect_result, "scores")
                        else 0.0
                    )
                    _mat = str(getattr(self, "_material_type", material_type or "digital")).lower()
                    # §2.47 [FIX] Valence-Threshold signal-adaptiv (kein Binary-Sprung):
                    # Wow/Flutter erzeugt Pitch-Modulation → Valence-Proxy schwankt proportional
                    # zur Schwere der Modulation. Binärer Sprung 0.80 → 0.55 bei sev≥0.5 ist zu grob:
                    # sev=0.51 und sev=0.99 bekamen denselben Threshold — verletzt §0c.
                    # Lineare Interpolation: sev=0.5 → 0.80, sev=1.0 → 0.55 (proportional zum Defekt).
                    # Materialliste um cassette + wax_cylinder erweitert (analoge Träger mit wow/flutter).
                    _ANALOG_MATS_WF = {"tape", "reel_tape", "vinyl", "cassette", "wax_cylinder", "wire_recording"}
                    if _mat in _ANALOG_MATS_WF and _wow_flutter_sev >= 0.5:
                        _wf_scale = float(np.clip((_wow_flutter_sev - 0.5) / 0.5, 0.0, 1.0))
                        _valence_threshold = float(0.80 - _wf_scale * 0.25)  # 0.80 (sev=0.5) → 0.55 (sev=1.0)
                        logger.info(
                            "§2.47 EmotionalArc: signal-adaptive Valence-Schwelle %.2f "
                            "(material=%s wow/flutter_sev=%.2f scale=%.2f)",
                            _valence_threshold,
                            _mat,
                            _wow_flutter_sev,
                            _wf_scale,
                        )
                    else:
                        _valence_threshold = 0.80

                    # §0d Carrier-Recovery-Referenz-Paradoxon: Carrier-Chain-Inversion verändert
                    # das spektrale Profil intentional stark gegenüber dem degradierten Input.
                    # Valence-Proxy (spectral flatness / centroid ratio) schwankt dadurch messbar
                    # auch ohne echten emotionalen Bogen-Verlust (dieselbe Analogie wie Arousal).
                    # Fix: Wenn carrier_chain_recovery_ratio > 0.15, sinkt _valence_threshold
                    # proportional zur gemessenen Carrier-Recovery-Intensität.
                    # Formel: max(0.60, 0.80 − ratio × 0.40)
                    # Beispiel: ratio=0.40 → 0.80 − 0.16 = 0.64 → max(0.60, 0.64) = 0.64
                    _carrier_rec_val = getattr(self, "_carrier_chain_recovery_ratio", 0.0)
                    if _carrier_rec_val > 0.15:
                        _valence_threshold_carrier = float(max(0.60, 0.80 - _carrier_rec_val * 0.40))
                        if _valence_threshold_carrier < _valence_threshold:
                            _valence_threshold = _valence_threshold_carrier
                            logger.info(
                                "§0d EmotionalArc: carrier-adaptive Valence-Schwelle %.2f "
                                "(carrier_ratio=%.3f, formel: max(0.60, 0.80−%.3f×0.40))",
                                _valence_threshold,
                                _carrier_rec_val,
                                _carrier_rec_val,
                            )

                    # §2.47 Adaptive-Intelligence: HF-Restaurierung hebt den Spektralzentroid
                    # des restaurierten Signals global an → arousal-Proxy (RMS × 0.55 + centroid × 0.45)
                    # verändert seine absolute Skala auch ohne musikalischen Bogen-Verlust →
                    # Pearson-Korrelation sinkt falsch-positiv.
                    # Fix: Centroid-Shift zwischen Original und Restauriert messen;
                    # Arousal-Schwelle proportional zur gemessenen Verschiebung absenken.
                    # Vollständig signal-getrieben, keine Materialliste, kein fester Wert.
                    _arousal_threshold = 0.85  # default (kein Shift)
                    try:
                        _arc_orig_m = (
                            np.mean(original_audio_for_goals, axis=0)
                            if original_audio_for_goals.ndim == 2
                            else original_audio_for_goals
                        )
                        _arc_rest_m = np.mean(restored_audio, axis=0) if restored_audio.ndim == 2 else restored_audio
                        # Max 8192 Samples (~170 ms bei 48 kHz): Centroid konvergiert schnell
                        _arc_n = min(len(_arc_orig_m), len(_arc_rest_m), 8192)
                        _arc_freqs = np.fft.rfftfreq(_arc_n, 1.0 / sample_rate)
                        _arc_psd_o = np.abs(np.fft.rfft(_arc_orig_m[:_arc_n].astype(np.float32)))
                        _arc_psd_r = np.abs(np.fft.rfft(_arc_rest_m[:_arc_n].astype(np.float32)))
                        _cent_o = float(np.sum(_arc_freqs * _arc_psd_o) / (np.sum(_arc_psd_o) + 1e-10))
                        _cent_r = float(np.sum(_arc_freqs * _arc_psd_r) / (np.sum(_arc_psd_r) + 1e-10))
                        _cent_shift = (_cent_r - _cent_o) / max(_cent_o, 1.0)
                        # >5% Centroid-Anstieg = messbare HF-Restaurierung → Threshold adaptiv senken
                        # Formel: max(0.65, 0.85 − shift × 0.40)
                        # Beispiele: 10% Shift → 0.81 | 25% Shift → 0.75 | 50%+ Shift → 0.65
                        if _cent_shift > 0.05:
                            _arousal_threshold = float(max(0.65, 0.85 - _cent_shift * 0.40))
                            logger.info(
                                "§2.47 EmotionalArc: centroid-adaptive Arousal-Schwelle %.2f "
                                "(centroid orig=%.0f Hz → rest=%.0f Hz, shift=+%.1f%%)",
                                _arousal_threshold,
                                _cent_o,
                                _cent_r,
                                _cent_shift * 100.0,
                            )
                    except Exception as _cent_exc:
                        logger.debug(
                            "EmotionalArc centroid-adaptive threshold computation failed: %s",
                            _cent_exc,
                        )

                    if not (_are_p >= _arousal_threshold and _val_p >= _valence_threshold):
                        restored_audio = _pre_excellence_audio.copy()
                        _fail_reasons.append(
                            {
                                "component": "EmotionalArcPreservationMetric",
                                "error_code": "ARC_REGRESSION_ROLLBACK",
                                "severity": "critical",
                                "arousal_pearson": round(_are_p, 4),
                                "valence_pearson": round(_val_p, 4),
                                "valence_threshold_used": _valence_threshold,
                                "arousal_threshold_used": _arousal_threshold,
                            }
                        )
                        logger.info(
                            "↩️ EmotionalArc: Rollback auf Pre-Excellence-Audio "
                            "(arousal=%.3f < %.2f oder valence=%.3f < %.2f)",
                            _are_p,
                            _arousal_threshold,
                            _val_p,
                            _valence_threshold,
                        )
            except Exception as _eap_exc:
                logger.debug("EmotionalArcPreservationMetric nicht verfügbar: %s", _eap_exc)

        # §8.3 GoosebumpsQualityChecker — Holistische psychoakustische Qualitätsprüfung
        _goosebumps_result = None
        _goosebumps_score: float | None = None
        try:
            from backend.core.goosebumps_quality_checker import measure_goosebumps

            _goosebumps_result = measure_goosebumps(
                original_audio_for_goals,
                restored_audio,
                sample_rate,
                musical_goal_scores=_musical_goal_scores if _musical_goal_scores else None,
            )
            _goosebumps_score = _goosebumps_result.goosebumps_score
            if _goosebumps_score >= 0.85:
                logger.info(
                    "✨ GoosebumpsQualityChecker: EXZELLENT — %s",
                    _goosebumps_result.summary(),
                )
            elif _goosebumps_score >= 0.70:
                logger.info(
                    "🎵 GoosebumpsQualityChecker: GUT — %s",
                    _goosebumps_result.summary(),
                )
            else:
                logger.warning(
                    "⚠️ GoosebumpsQualityChecker: VERBESSERUNGSWÜRDIG — %s",
                    _goosebumps_result.summary(),
                )
                # §8.3 Gänsehaut-Score im Export-Gate: niedrige Werte als fail_reason erfassen
                _fail_reasons.append(
                    {
                        "component": "GoosebumpsQualityChecker",
                        "error_code": "GOOSEBUMPS_LOW",
                        "severity": "degraded",
                        "goosebumps_score": round(_goosebumps_score, 4),
                        "transient_integrity": round(_goosebumps_result.transient_integrity, 4),
                        "micro_dynamics": round(_goosebumps_result.micro_dynamics, 4),
                        "clarity": round(_goosebumps_result.clarity, 4),
                        "authenticity": round(_goosebumps_result.authenticity, 4),
                    }
                )
        except BaseException as _gb_exc:
            # Non-blocking analytics: timeout/outcome exceptions must not abort restore().
            if isinstance(_gb_exc, (KeyboardInterrupt, SystemExit, GeneratorExit)):
                raise
            logger.debug("GoosebumpsQualityChecker nicht verfügbar: %s", _gb_exc)

        # --- GP-Lernzyklus: Vorbereitung — PQS-Norm + Pareto-Vorschlag (vor MDEM) (§2.5 Spec) ---
        # GPParameterOptimizer.update() wird erst NACH MDEM aufgerufen (Spec §2.5 normativ).
        _pqs_mos_norm: float | None = None
        _gp_opt_ref: Any = None
        _gp_upd_proposal_ref: Any = None
        _gp_score_ref: float = 0.0
        _gp_goal_scores_ref: dict[str, float] | None = None
        if _musical_excellence_score > 0.0 or _pqs_result is not None:
            try:
                from backend.core.gp_parameter_optimizer import get_optimizer

                _gp_opt_ref = get_optimizer()
                # Kombinierter Score: PQS-MOS (normiert [1-5]→[0-1]) + Musical Excellence
                _pqs_mos_norm = (
                    (_pqs_result.pqs_mos - 1.0) / 4.0
                    if _pqs_result is not None and math.isfinite(_pqs_result.pqs_mos)
                    else None
                )
                # Mel-Spectral Loss + Multi-Scale STFT Loss (Spec bindend: §2.5 PFLICHT-Loss-Funktion)
                # Loss-Funktion: Mel-Spectral Loss + Multi-Scale STFT Loss (3 Auflösungen)
                # VERBOTEN: MSE auf Raw-Audio als alleinige GPO-Loss
                _mel_score: float = 0.0
                _ms_stft_score: float = 0.0
                try:
                    import librosa as _lbr_gpo

                    _gpo_a_orig = original_audio_for_goals
                    _gpo_a_rest = restored_audio
                    # Mono-Konvertierung für Loss-Berechnung (shape: (T,))
                    _gpo_a_orig_m = np.mean(_gpo_a_orig, axis=0) if _gpo_a_orig.ndim == 2 else _gpo_a_orig
                    _gpo_a_rest_m = np.mean(_gpo_a_rest, axis=0) if _gpo_a_rest.ndim == 2 else _gpo_a_rest
                    # Längenangleich
                    _gpo_len = min(len(_gpo_a_orig_m), len(_gpo_a_rest_m))
                    _gpo_a_orig_m = _gpo_a_orig_m[:_gpo_len]
                    _gpo_a_rest_m = _gpo_a_rest_m[:_gpo_len]
                    # §Performance-Budget: GP-Loss auf max. 30 s begrenzen (OOM-Schutz für
                    # Langaufnahmen — bei 5 min / 48 kHz = 14,4 M Samples würde STFT für
                    # n_fft=4096, hop=1024 ~462 MB pro rfft-Aufruf × 6 Aufrufe ≈ 2,8 GB belegen).
                    _MAX_GP_LOSS_S = 30.0
                    _max_gp_samples = int(_MAX_GP_LOSS_S * sample_rate)
                    if _gpo_len > _max_gp_samples:
                        _gpo_mid = _gpo_len // 2
                        _gpo_start = max(0, _gpo_mid - _max_gp_samples // 2)
                        _gpo_a_orig_m = _gpo_a_orig_m[_gpo_start : _gpo_start + _max_gp_samples]
                        _gpo_a_rest_m = _gpo_a_rest_m[_gpo_start : _gpo_start + _max_gp_samples]
                        logger.debug(
                            "GPO Loss: Audio auf %.0fs begrenzt (original: %.1fs) — OOM-Schutz",
                            _MAX_GP_LOSS_S,
                            _gpo_len / sample_rate,
                        )
                    # Mel-Spectral Loss (80 Mel-Bins)
                    _mel_r = _lbr_gpo.feature.melspectrogram(y=_gpo_a_orig_m, sr=sample_rate, n_mels=80)
                    _mel_e = _lbr_gpo.feature.melspectrogram(y=_gpo_a_rest_m, sr=sample_rate, n_mels=80)
                    _mel_ref_mean = float(np.mean(_mel_r)) + 1e-8
                    _mel_loss_val = float(np.mean(np.abs(_mel_r - _mel_e))) / _mel_ref_mean
                    _mel_score = max(0.0, min(1.0, 1.0 - _mel_loss_val))
                    # Multi-Scale STFT Loss (3 Auflösungen: 256, 1024, 4096)
                    _ms_scores: list = []
                    for _n_fft_ms in (256, 1024, 4096):
                        _hop_ms = _n_fft_ms // 4
                        _s_r = np.abs(
                            np.fft.rfft(
                                np.lib.stride_tricks.sliding_window_view(_gpo_a_orig_m, _n_fft_ms)[::_hop_ms],
                                axis=-1,
                            )
                        )
                        _s_e = np.abs(
                            np.fft.rfft(
                                np.lib.stride_tricks.sliding_window_view(_gpo_a_rest_m, _n_fft_ms)[::_hop_ms],
                                axis=-1,
                            )
                        )
                        _min_frames = min(_s_r.shape[0], _s_e.shape[0])
                        if _min_frames > 0:
                            _sr_c = _s_r[:_min_frames]
                            _se_c = _s_e[:_min_frames]
                            _ref_mean_ms = float(np.mean(_sr_c)) + 1e-8
                            _ms_loss_single = float(np.mean(np.abs(_sr_c - _se_c))) / _ref_mean_ms
                            _ms_scores.append(max(0.0, min(1.0, 1.0 - _ms_loss_single)))
                    _ms_stft_score = float(np.mean(_ms_scores)) if _ms_scores else 0.0
                    logger.debug(
                        "GPO Loss-Funktion: mel_score=%.4f ms_stft_score=%.4f",
                        _mel_score,
                        _ms_stft_score,
                    )
                except Exception as _gpo_loss_exc:
                    logger.debug("GPO Mel/STFT-Loss nicht verfügbar: %s", _gpo_loss_exc)
                    _mel_score = 0.0
                    _ms_stft_score = 0.0
                # Kombinierter Score (Spec §2.5 bindend):
                # 0.4 * musical_excellence + 0.3 * pqs_norm + 0.2 * mel_score + 0.1 * ms_stft_score
                if _pqs_mos_norm is not None and _musical_excellence_score > 0.0:
                    if _mel_score > 0.0 or _ms_stft_score > 0.0:
                        _gp_score_ref = (
                            0.4 * _musical_excellence_score
                            + 0.3 * _pqs_mos_norm
                            + 0.2 * _mel_score
                            + 0.1 * _ms_stft_score
                        )
                    else:
                        _gp_score_ref = 0.5 * _musical_excellence_score + 0.5 * _pqs_mos_norm
                elif _musical_excellence_score > 0.0:
                    _gp_score_ref = _musical_excellence_score
                else:
                    _gp_score_ref = _pqs_mos_norm or 0.0
                # Era-Warmstart: Ära-Prior aus EraClassifier für GP-Cold-Start (§2.14)
                _era_ws: dict[str, float] | None = None
                if _era_result is not None:
                    try:
                        from backend.core.era_classifier import get_era_classifier as _get_era_clf

                        _era_ws = _get_era_clf().get_gp_warmstart(_era_result)
                        logger.debug(
                            "EraClassifier GP-Warmstart: decade=%d NR_strength=%.2f",
                            _era_result.decade,
                            _era_ws.get("noise_reduction_strength", 0.0),
                        )
                    except Exception as _era_ws_exc:
                        logger.debug("Era-GP-Warmstart nicht verfügbar: %s", _era_ws_exc)
                _gp_upd_proposal_ref = _gp_opt_ref.propose(
                    material=_gp_material_key,
                    embedding=_original_embedding.vector if _original_embedding is not None else None,
                    era_warmstart=_era_ws,
                )
                # goal_scores für echten MOO vorberechnen (§2.5 Spec 03)
                _gp_goal_scores_ref = (
                    {k: float(v) for k, v in _musical_goal_scores.items()} if _musical_goal_scores else None
                )
            except Exception as _gp_prep_exc:
                logger.debug("GP-Vorbereitung (vor MDEM) nicht verfügbar: %s", _gp_prep_exc)

        # §2.30 MicroDynamicsEnvelopeMorphing — LUFS-Profil-Rückgewinnung (letzter DSP-Schritt)
        # §Frisson: detect high-potential "Gänsehaut" moments in original audio so MDEM
        # can protect their dynamic peaks from over-attenuation (Blood & Zatorre 2001).
        _frisson_zones = []
        try:
            from backend.core.frisson_candidate_detector import get_frisson_detector

            _frisson_zones = get_frisson_detector().detect(original_audio_for_goals, sample_rate)
            if _frisson_zones:
                logger.info(
                    "§Frisson: %d Gänsehaut-Kandidaten erkannt (%.1f–%.1f s, top_score=%.2f)",
                    len(_frisson_zones),
                    _frisson_zones[0].start_s,
                    _frisson_zones[0].end_s,
                    _frisson_zones[0].score,
                )
        except Exception as _fcd_exc:
            logger.debug("FrissonCandidateDetector nicht verfügbar (non-blocking): %s", _fcd_exc)

        # §Bug2-Fix: phase_12 wow/flutter and phase_31 speed/pitch can change audio length
        # by ~108 samples (2.25 ms @ 48 kHz).  A length mismatch causes MDEM, correct_arc
        # and WPG to fail with broadcast errors or produce silent output.  Align once here
        # before the entire post-pipeline processing block.
        if restored_audio.shape[-1] != original_audio_for_goals.shape[-1]:
            _rest_n = int(restored_audio.shape[-1])
            _orig_n = int(original_audio_for_goals.shape[-1])
            _ppipe_diff = abs(_rest_n - _orig_n)
            _ppipe_min = min(_rest_n, _orig_n)
            # Small drift is expected from phase internals; trim both sides symmetrically.
            if _ppipe_diff <= 64:
                logger.debug(
                    "Post-pipeline length alignment (small drift): restored=%d, original=%d → min=%d samples",
                    _rest_n,
                    _orig_n,
                    _ppipe_min,
                )
                restored_audio = restored_audio[..., :_ppipe_min]
                original_audio_for_goals = original_audio_for_goals[..., :_ppipe_min]
            else:
                # Large mismatch: never cut restored program audio; adapt only goal reference length.
                if _orig_n < _rest_n:
                    _pad = _rest_n - _orig_n
                    if original_audio_for_goals.ndim >= 2:
                        original_audio_for_goals = np.pad(
                            original_audio_for_goals,
                            [(0, 0)] * (original_audio_for_goals.ndim - 1) + [(0, _pad)],
                        )
                    else:
                        original_audio_for_goals = np.pad(original_audio_for_goals, (0, _pad))
                else:
                    original_audio_for_goals = original_audio_for_goals[..., :_rest_n]
                logger.warning(
                    "Post-pipeline large length mismatch: restored=%d, original=%d, diff=%d. "
                    "Adjusted goal reference length only; restored audio kept unchanged.",
                    _rest_n,
                    _orig_n,
                    _ppipe_diff,
                )

        if _is_bronze_post:
            logger.info("[Bronze] MDEM übersprungen — kein Dynamik-Morphing im Bronze-Modus")
        else:
            try:
                from backend.core.micro_dynamics_envelope_morphing import get_mdem

                _mdem_instance = get_mdem()
                # Modus-Erkennung: studio2026 wenn kein reines Restoration-Profil
                _mdem_mode = "restoration"
                try:
                    _mode_val = str(self.config.mode.value).lower()
                    if any(_kw in _mode_val for _kw in ("maximum", "studio", "aggressive")):
                        _mdem_mode = "studio2026"
                except Exception as _mode_exc:
                    logger.debug("MDEM Modus-Erkennung fehlgeschlagen: %s", _mode_exc)
                restored_audio = _mdem_instance.morph(
                    restored_audio,
                    original_audio_for_goals,
                    sample_rate,
                    mode=_mdem_mode,
                    phoneme_timeline=_phoneme_timeline,  # §2.36a: stressed-vowel frame headroom
                    frisson_zones=_frisson_zones,  # §Frisson: Gänsehaut-Schutz
                )
                restored_audio = np.clip(np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                logger.info("§2.30 MDEM: Mikro-Dynamik-Morphing abgeschlossen (mode=%s)", _mdem_mode)
            except Exception as _mdem_exc:
                logger.warning("MicroDynamicsEnvelopeMorphing fehlgeschlagen: %s", _mdem_exc)

        # §8.2 EmotionalArc: Post-MDEM Nachmessung + Makro-Korrektur (5 s-Skala)
        # MDEM korrigiert Mikro-Dynamik (400 ms). Wenn der Makro-Bogen (5 s)
        # danach immer noch abgeflacht ist, greift die Makro-Korrektur.
        try:
            from backend.core.emotional_arc_preservation import (
                correct_emotional_arc,
                measure_emotional_arc,
            )

            _arc_post_mdem = measure_emotional_arc(original_audio_for_goals, restored_audio, sample_rate)
            if (
                _arc_post_mdem is not None
                and not _arc_post_mdem.skipped
                and not _arc_post_mdem.arc_preserved
                and not _is_bronze_post
            ):
                logger.info(
                    "EmotionalArc post-MDEM: Bogen nicht erhalten (arousal=%.3f, valence=%.3f) — Makro-Korrektur",
                    _arc_post_mdem.arousal_pearson,
                    _arc_post_mdem.valence_pearson,
                )
                # Adaptive Makro-Korrektur: auf schlechtem Material konservativer,
                # auf gutem Material voll (bis ±6 dB) für maximale Ausdruckstreue.
                _arc_max_gain_db = 6.0
                _arc_damping = 0.70
                if _pmgg_restorability_score < 40.0:
                    _arc_max_gain_db = 4.0
                    _arc_damping = 0.55
                elif _pmgg_restorability_score < 70.0:
                    _arc_max_gain_db = 5.0
                    _arc_damping = 0.65
                # Mode-aware Feintuning: Studio darf etwas mutiger korrigieren,
                # Restoration bleibt konservativer zur Originaltreue.
                if _mdem_mode == "studio2026":
                    _arc_damping = min(0.80, _arc_damping + 0.05)
                else:
                    _arc_damping = max(0.50, _arc_damping - 0.05)
                restored_audio, _arc_corrected = correct_emotional_arc(
                    original_audio_for_goals,
                    restored_audio,
                    sample_rate,
                    max_gain_db=_arc_max_gain_db,
                    damping=_arc_damping,
                    frisson_zones=_frisson_zones,  # §Frisson: Gänsehaut-Schutz auch in Makro-Korrektur
                )
                restored_audio = np.clip(
                    np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0),
                    -1.0,
                    1.0,
                )
                _arc_result = _arc_corrected
                logger.info(
                    "EmotionalArc post-Korrektur: arousal=%.3f valence=%.3f preserved=%s",
                    _arc_corrected.arousal_pearson,
                    _arc_corrected.valence_pearson,
                    _arc_corrected.arc_preserved,
                )
            elif _arc_post_mdem is not None and not _arc_post_mdem.skipped:
                _arc_result = _arc_post_mdem
                logger.debug("EmotionalArc post-MDEM: Bogen intakt — keine Korrektur nötig")
        except Exception as _arc_corr_exc:
            logger.debug("EmotionalArc post-MDEM-Korrektur nicht verfügbar: %s", _arc_corr_exc)

        # §2.30c Pre-WPG final quiet-zone guard: catches any explosion from phase_23/phase_03
        # that propagated through subsequent phase references (each phase guard uses its
        # predecessor as reference, so the explosion gets "normalized" into the chain).
        # This guard compares against original_audio_for_goals (true pre-pipeline reference)
        # and therefore sees accumulated explosions that individual phase guards missed.
        try:
            _pwg_mat_key = str(_gp_material_key or "").lower().split("_", maxsplit=1)[0]
            _pwg_qdbfs = float(
                {
                    "shellac": -37.0,
                    "wax_cylinder": -38.0,
                    "vinyl": -35.0,
                    "reel_tape": -36.0,
                    "tape": -36.0,
                    "cassette": -36.0,
                    "cd_digital": -44.0,
                    "mp3_low": -39.0,
                }.get(_pwg_mat_key, -36.0)
            )
            _pwg_thr = 2.0
            _pwg_win = max(2048, int(1.0 * float(sample_rate)))
            _pwg_hop = max(512, int(0.25 * float(sample_rate)))
            _pwg_ref = np.asarray(original_audio_for_goals, dtype=np.float32)
            _pwg_cand = np.asarray(restored_audio, dtype=np.float32)
            _pwg_n = int(min(_pwg_ref.shape[-1], _pwg_cand.shape[-1]))
            if _pwg_n > 2048:
                _pwg_rm = np.mean(_pwg_ref[..., :_pwg_n], axis=0) if _pwg_ref.ndim == 2 else _pwg_ref[:_pwg_n]
                _pwg_cm = np.mean(_pwg_cand[..., :_pwg_n], axis=0) if _pwg_cand.ndim == 2 else _pwg_cand[:_pwg_n]
                _pwg_nf = max(1, (_pwg_n - _pwg_win) // _pwg_hop + 1)
                _pwg_rdb = np.empty(_pwg_nf, dtype=np.float64)
                _pwg_cdb = np.empty(_pwg_nf, dtype=np.float64)
                for _pk in range(_pwg_nf):
                    _ps, _pe = _pk * _pwg_hop, min(_pk * _pwg_hop + _pwg_win, _pwg_n)
                    _pwg_rdb[_pk] = 20.0 * np.log10(float(np.sqrt(np.mean(_pwg_rm[_ps:_pe] ** 2) + 1e-12)) + 1e-12)
                    _pwg_cdb[_pk] = 20.0 * np.log10(float(np.sqrt(np.mean(_pwg_cm[_ps:_pe] ** 2) + 1e-12)) + 1e-12)
                _pwg_expl = (_pwg_rdb <= _pwg_qdbfs) & ((_pwg_cdb - _pwg_rdb) > _pwg_thr)
                if np.any(_pwg_expl):
                    _pwg_gdb_f = np.zeros(_pwg_nf, dtype=np.float64)
                    for _pk in range(_pwg_nf):
                        if _pwg_expl[_pk]:
                            _pwg_gdb_f[_pk] = float(np.clip(_pwg_rdb[_pk] - _pwg_cdb[_pk], -60.0, 0.0))
                    _pwg_ctrs = np.array([_pk * _pwg_hop + _pwg_win // 2 for _pk in range(_pwg_nf)], dtype=np.float64)
                    _pwg_gdb = np.interp(np.arange(_pwg_n, dtype=np.float64), _pwg_ctrs, _pwg_gdb_f).astype(np.float32)
                    _pwg_gdb = np.minimum(_pwg_gdb, 0.0)
                    # Attack/release smoothing (10 ms / 30 ms) — same as per-phase guard
                    _pwg_atk = max(1, int(0.010 * float(sample_rate)))
                    _pwg_rel = max(1, int(0.030 * float(sample_rate)))
                    _pwg_aa = float(np.exp(-1.0 / float(_pwg_atk)))
                    _pwg_ar = float(np.exp(-1.0 / float(_pwg_rel)))
                    _pwg_sm = _pwg_gdb.copy()
                    for _pi in range(1, _pwg_sm.shape[0]):
                        _pwg_t, _pwg_p = float(_pwg_sm[_pi]), float(_pwg_sm[_pi - 1])
                        _pwg_sm[_pi] = np.float32(
                            (_pwg_aa if _pwg_t < _pwg_p else _pwg_ar) * _pwg_p
                            + (1.0 - (_pwg_aa if _pwg_t < _pwg_p else _pwg_ar)) * _pwg_t
                        )
                    _pwg_gl = np.power(10.0, np.minimum(_pwg_sm, 0.0) / 20.0, dtype=np.float32)
                    _pwg_fixed = (
                        restored_audio[..., :_pwg_n] * _pwg_gl[None, :]
                        if restored_audio.ndim == 2
                        else restored_audio[:_pwg_n] * _pwg_gl
                    )
                    _pwg_fixed = np.clip(np.nan_to_num(_pwg_fixed, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                    if restored_audio.ndim == 2:
                        restored_audio = (
                            np.concatenate([_pwg_fixed, restored_audio[:, _pwg_n:]], axis=1)
                            if restored_audio.shape[-1] > _pwg_n
                            else _pwg_fixed
                        )
                    else:
                        restored_audio = (
                            np.concatenate([_pwg_fixed, restored_audio[_pwg_n:]])
                            if len(restored_audio) > _pwg_n
                            else _pwg_fixed
                        )
                    logger.warning(
                        "§2.30c Pre-WPG quiet-zone guard: %d explosions vs original reference (att=%.1f dB mat=%s)",
                        int(np.sum(_pwg_expl)),
                        float(np.min(_pwg_gdb_f[_pwg_gdb_f < 0.0])) if np.any(_pwg_gdb_f < 0.0) else 0.0,
                        _pwg_mat_key,
                    )
        except Exception as _pre_wpg_exc:
            logger.debug("§2.30c Pre-WPG quiet-zone guard non-blocking: %s", _pre_wpg_exc)

        # §2.30c WaveformPlausibilityGuard — finale Pegelexplosions-Fangschicht
        # Erkennt Fenster wo restored >> original (Gain-Artefakt aus MDEM/correct_arc),
        # korrigiert via reines Envelope-Attenuation (NIE Boost).
        # Alle Defektreparaturen (Spektrum, Harmonik, BW-Extension) bleiben erhalten.
        # Musical-Goals-Proxy-Check schützt P3 (Emotionalität/MikroDynamik) vor Überkorrektur.
        try:
            from backend.core.emotional_arc_preservation import apply_waveform_plausibility_guard as _wpg_fn

            _wpg_mode = str(getattr(getattr(self.config, "mode", None), "value", "restoration")).lower()
            _wpg_mat = str(_gp_material_key or "unknown").lower().split("_", maxsplit=1)[0]  # "vinyl_heavy" → "vinyl"
            _wpg_out, _wpg_meta = _wpg_fn(
                original_audio_for_goals,
                restored_audio,
                sample_rate,
                mode=_wpg_mode,
                material_type=_wpg_mat,
                restorability_score=float(_pmgg_restorability_score),
            )
            if _wpg_meta.get("corrections_applied", 0) > 0:
                restored_audio = _wpg_out
                restored_audio = np.clip(np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                logger.info(
                    "§2.30c WPG: %d Explosions-Fenster korrigiert, max=%.1f dB%s",
                    _wpg_meta["corrections_applied"],
                    _wpg_meta.get("max_attenuation_db", 0.0),
                    " (50%%-Modus)" if _wpg_meta.get("correction_eased") else "",
                )
            elif _wpg_meta.get("skipped_reason"):
                logger.debug("§2.30c WPG: Skip (%s)", _wpg_meta["skipped_reason"])
            else:
                logger.debug(
                    "§2.30c WPG: Keine Explosionen erkannt (%d Fenster geprüft)",
                    _wpg_meta.get("explosions_found", 0),
                )
        except Exception as _wpg_exc:
            logger.debug("§2.30c WaveformPlausibilityGuard nicht verfügbar: %s", _wpg_exc)

        # §2.36 [RELEASE_MUST] Konsonanten-Burst-Rekonstruktion nach NR-Pipeline
        # Stellt Artikulation wieder her, die von NR-Algorithmen als Rauschen entfernt wurde.
        _uv3_mode_str = str(getattr(getattr(self.config, "mode", None), "value", "restoration")).lower()
        if float(getattr(self, "_panns_singing", 0.0)) >= 0.35 and "studio" not in _uv3_mode_str:
            try:
                from backend.core.lyrics_guided_enhancement import (
                    reconstruct_consonant_bursts as _rcb_fn,
                )

                restored_audio = _rcb_fn(
                    original_audio_for_goals,
                    restored_audio,
                    sample_rate,
                )
                restored_audio = np.clip(np.nan_to_num(restored_audio, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                logger.debug(
                    "§2.36 UV3 reconstruct_consonant_bursts: panns_singing=%.2f",
                    float(getattr(self, "_panns_singing", 0.0)),
                )
            except Exception as _rcb_exc:
                logger.debug("§2.36 reconstruct_consonant_bursts non-blocking: %s", _rcb_exc)

        # --- GP-Lernzyklus: update() NACH MDEM — Spec §2.5 (normativ: letzter Schritt) ---
        # Score basiert auf PQS + Musical Goals vor MDEM (korrekt: MDEM ist Hüllkurven-Morphing,
        # ändert keine PQS-Messungen). Update NACH MDEM garantiert vollständige Pipeline-Daten.
        if _gp_opt_ref is not None and _gp_upd_proposal_ref is not None:
            try:
                _gp_opt_ref.update(
                    parameters=_gp_upd_proposal_ref.parameters,
                    score=_gp_score_ref,
                    material=_gp_material_key,
                    goal_scores=_gp_goal_scores_ref,
                )
                logger.debug(
                    "GPParameterOptimizer post-MDEM: Update material=%s score=%.4f goals=%d"
                    " (excellence=%.4f pqs_norm=%s)",
                    _gp_material_key,
                    _gp_score_ref,
                    len(_gp_goal_scores_ref) if _gp_goal_scores_ref else 0,
                    _musical_excellence_score,
                    f"{_pqs_mos_norm:.4f}" if _pqs_mos_norm is not None else "n/a",
                )
            except Exception as _gp_upd_exc:
                logger.debug("GPParameterOptimizer.update post-MDEM nicht verfügbar: %s", _gp_upd_exc)

        # §1.4 Vocos-Synthese — Qualitäts-Finisher (Studio 2026, konditionell)
        # Spec: "wenn PQS-MOS(Mix nach Schritt 11) < 4.3"
        # Invariante: NIEMALS im Restoration-Modus; NIEMALS wenn PQS-MOS ≥ 4.3
        # Fallback-Kaskade: Vocos ONNX → HiFi-GAN → PGHI-ISTFT (§4.5)
        try:
            _vocos_mode_val = str(getattr(getattr(self.config, "mode", None), "value", "")).lower()
            _is_vocos_studio = any(_kw in _vocos_mode_val for _kw in ("maximum", "studio", "aggressive"))
            # (4.3 − 1) / 4 = 0.825 ist die normalisierte PQS-MOS-Schwelle
            _vocos_mos_ok = (_pqs_mos_norm is None) or (_pqs_mos_norm < 0.825)
            # §9.5: Production feature for Studio 2026 — no experimental gate; exception handler
            # provides safe fallback to plain PGHI-ISTFT output if vocos plugin is unavailable.
            if _is_vocos_studio and _vocos_mos_ok:
                import os as _vos
                import sys as _vsys

                _vplugins = _vos.path.join(_vos.path.dirname(__file__), "..", "..", "plugins")
                if _vplugins not in _vsys.path:
                    _vsys.path.insert(0, _vos.path.abspath(_vplugins))
                from vocos_plugin import get_vocos_plugin as _get_vocos_plg

                _vplug = _get_vocos_plg()
                if restored_audio.ndim == 2:
                    # Stereo: beide Kanäle separat synthetisieren und stapeln
                    _vch0 = _vplug.vocode(restored_audio[0], sample_rate, mode="studio2026").audio
                    _vch1 = _vplug.vocode(restored_audio[1], sample_rate, mode="studio2026").audio
                    _vn = min(len(_vch0), len(_vch1), restored_audio.shape[1])
                    _vocos_out = np.stack([_vch0[:_vn], _vch1[:_vn]], axis=0)
                    logger.info(
                        "§1.4 Vocos: Stereo-Finisher angewendet (model=%s)",
                        (
                            _vplug.vocode(restored_audio[0], sample_rate, mode="studio2026").model_used
                            if False  # pylint: disable=using-constant-test
                            else "vocos_mel_24khz/griffin_lim"
                        ),
                    )
                else:
                    _vr = _vplug.vocode(restored_audio, sample_rate, mode="studio2026")
                    _vocos_out = _vr.audio
                    logger.info(
                        "§1.4 Vocos: Mono-Finisher angewendet (model=%s pqs_mos=%.3f mel_snr=%.1f dB)",
                        _vr.model_used,
                        _vr.pqs_mos,
                        _vr.mel_snr_db,
                    )
                # Keep pre-Vocos audio when the vocoder output is effectively silent.
                _vocos_safe = np.clip(
                    np.nan_to_num(_vocos_out, nan=0.0, posinf=0.0, neginf=0.0),
                    -1.0,
                    1.0,
                )
                _vocos_rms = float(np.sqrt(np.mean(_vocos_safe.astype(np.float64) ** 2) + 1e-12))
                if _vocos_rms <= 1e-4:
                    logger.warning(
                        "§1.4 Vocos: Ausgabe stumm (RMS=%.2e, mel_snr=%.1f dB) -> "
                        "verworfen, behalte Pre-Vocos-Audio (§0 Primum non nocere)",
                        _vocos_rms,
                        getattr(_vr, "mel_snr_db", float("nan")),
                    )
                else:
                    restored_audio = _vocos_safe
            elif _is_vocos_studio:
                logger.debug(
                    "§1.4 Vocos: Übersprungen - PQS-MOS >= 4.3 "
                    "(pqs_mos_norm=%.3f >= 0.825), kein Qualitätsverlust möglich",
                    _pqs_mos_norm if _pqs_mos_norm is not None else -1.0,
                )
        except Exception as _vocos_exc:
            logger.warning(
                "§1.4 Vocos-Synthese nicht verfügbar — Fallback auf PGHI-ISTFT-Ausgang: %s "
                "(Installationshinweis: plugins/vocos_plugin.py + Vocos-Gewichte erforderlich)",
                _vocos_exc,
            )

        # Step 5: Performance Report
        logger.info("Step 4/4: Generating Report...")
        try:
            perf_report = self.performance_guard.get_performance_report() if self.performance_guard else None
        except RuntimeError:
            # start_monitoring() was not called (e.g. audio < 0.5 s in multipass chunk context)
            perf_report = None

        # Quality Estimate
        quality_estimate = self._estimate_quality(defect_result, perf_report, executed_phases, restored_audio, 48_000)

        # Build Result
        total_time = time.time() - start_time
        rt_factor = total_time / audio_duration
        # Absolutes 30-Minuten-Budget (1800 s) statt relativem 8×RT-Faktor —
        # kurze Clips erzeugen naturgemäß hohe rt_factors, die kein echtes Problem sind.
        _ABSOLUTE_BUDGET_S = 1800.0
        if self.config.enforce_3x_rt and total_time > _ABSOLUTE_BUDGET_S:
            logger.warning(
                "Absolutes Zeitbudget überschritten: %.0f s > %.0f s (rt_factor=%.2f). "
                "Lösung: Modus FAST/BALANCED nutzen oder adaptive Skips aktivieren.",
                total_time,
                _ABSOLUTE_BUDGET_S,
                rt_factor,
            )

        # §8.1 Reporting-Analytik: MUSHRA, Artefakt-Analyse, Qualitätsvergleich
        # und >80 weitere Diagnose-Module (analytics-only, kein Audio-Eingriff)
        _analytics_meta = self._collect_reporting_analytics(
            restored_audio=restored_audio,
            audio=audio,
            original_audio_for_goals=original_audio_for_goals,
            sample_rate=sample_rate,
            material_type=material_type,
            _era_result=_era_result,
            _quality_before=_quality_before,
            quality_estimate=quality_estimate,
            _pipeline_confidence=_pipeline_confidence,
            _musical_goal_scores=_musical_goal_scores,
            _musical_goals_passed=_musical_goals_passed,
            defect_result=defect_result,
            executed_phases=executed_phases,
            _pqs_result=_pqs_result,
        )
        # Merge gate fail-reasons from analytics into the central accumulator
        _fail_reasons.extend(_analytics_meta.pop("_fail_reasons_from_analytics", []) or [])

        try:
            from backend.core.pipeline_health_state import (
                pipeline_health_from_fail_reasons,
                primary_fail_reason_from_fail_reasons,
            )

            _degradation_status = pipeline_health_from_fail_reasons(_fail_reasons).value
        except Exception:
            _degradation_status = "degraded" if _fail_reasons else "ok"
        _primary_fail_reason = primary_fail_reason_from_fail_reasons(_fail_reasons)

        # §G3: Chroma-Korrelation und LUFS-Delta für Export-Gate berechnen
        _chroma_corr_for_result: float | None = None
        _lufs_delta_for_result: float | None = None
        # Chroma: tonal_center Goal-Score ist direkt die Chroma Pearson-Korrelation
        if _musical_goal_scores:
            _chroma_corr_for_result = float(_musical_goal_scores.get("tonal_center", 0.0))
        # LUFS-Delta: Differenz zwischen Original und Restauriert
        try:
            import pyloudnorm as _pyln

            _lufs_meter = _pyln.Meter(sample_rate)
            _orig_2d = (
                original_audio_for_goals if original_audio_for_goals.ndim >= 2 else original_audio_for_goals[:, None]
            )
            _rest_2d = restored_audio if restored_audio.ndim >= 2 else restored_audio[:, None]
            if _orig_2d.ndim == 2 and _orig_2d.shape[0] == 2 and _orig_2d.shape[1] != 2:
                _orig_2d = _orig_2d.T
            if _rest_2d.ndim == 2 and _rest_2d.shape[0] == 2 and _rest_2d.shape[1] != 2:
                _rest_2d = _rest_2d.T
            _lufs_orig = _lufs_meter.integrated_loudness(_orig_2d)
            _lufs_rest = _lufs_meter.integrated_loudness(_rest_2d)
            if np.isfinite(_lufs_orig) and np.isfinite(_lufs_rest):
                _lufs_delta_for_result = abs(_lufs_rest - _lufs_orig)
        except Exception as _lufs_exc:
            logger.debug("LUFS-Delta-Berechnung fehlgeschlagen: %s", _lufs_exc)

        _cb(98, "Ergebnis wird finalisiert…")

        # Post-restoration defect assessment for UI and reporting accuracy.
        # Without this re-scan, RestorationResult.defect_scores would still reflect
        # the pre-restoration scanner snapshot and cause false "remaining defects"
        # in the frontend after processing has finished.
        _result_defect_scores: dict[DefectType, float] = {
            dt: defect_result.scores[dt].severity for dt in DefectType if dt in defect_result.scores
        }
        _post_defect_result = None
        try:
            _post_defect_result = self.defect_scanner.scan(
                restored_audio,
                sample_rate,
                material_type,
                file_ext=_file_ext_for_scan,
                # Fix 10: _mc_result (MediumDetectionResult) aus Pre-Analysis weitergeben,
                # damit DefectScanner.scan() MediumDetector.detect() NICHT nochmals auf dem
                # restaurierten Audio aufruft — verhindert §2.47a-Verletzung (Doppeldetektion).
                forensic_medium_result=_mc_result if hasattr(_mc_result, "transfer_chain") else None,
            )
            if _post_defect_result is not None:
                _result_defect_scores = {
                    dt: _post_defect_result.scores[dt].severity for dt in DefectType if dt in _post_defect_result.scores
                }
                logger.info(
                    "DefectScanner post-scan completed: pre_top=%d, post_top=%d",
                    len(defect_result.get_top_defects(5)),
                    len(_post_defect_result.get_top_defects(5)),
                )
            else:
                logger.warning("DefectScanner post-scan returned None — using pre-restoration defect scores in result")
        except BaseException as _post_scan_exc:
            if isinstance(_post_scan_exc, (KeyboardInterrupt, SystemExit, GeneratorExit)):
                raise
            logger.warning(
                "DefectScanner post-scan failed (%s) — using pre-restoration defect scores in result",
                _post_scan_exc,
            )

        # §2.44 [RELEASE_MUST] HolisticPerceptualGate — HPI as final export gate
        _hpi_result = None
        _artifact_freedom_for_hpi = getattr(self, "_artifact_freedom_score", 1.0)
        _emotional_arc_for_hpi = (
            float(getattr(_emotional_arc_result, "preservation_score", 1.0))
            if _emotional_arc_result is not None
            else 1.0
        )

        # §4.7 [RELEASE_MUST] Noise-Texture-Coherence End-of-Pipeline Guard
        _noise_texture_result = None
        try:
            from backend.core.noise_texture_coherence import get_noise_texture_coherence_guard as _get_ntcg

            _ntcg = _get_ntcg()
            _ntc_material = (
                (material_type.value if hasattr(material_type, "value") else str(material_type)).lower()
                if material_type
                else "digital"
            )
            _ntc_qm = "studio_2026" if self.is_studio_mode() else "restoration"
            _noise_texture_result = _ntcg.check_end_of_pipeline(
                original_audio_for_goals,
                restored_audio,
                sample_rate,
                _ntc_material,
                quality_mode=_ntc_qm,
            )
            if _noise_texture_result is not None and not _noise_texture_result.is_compliant:
                logger.warning(
                    "§4.7 Noise-Texture-Kohärenz NICHT konform: coherence=%.3f (material=%s, min=0.80)",
                    _noise_texture_result.coherence,
                    _ntc_material,
                )
                _fail_reasons.append(
                    {
                        "component": "NoiseTextureCoherenceGuard",
                        "error_code": "NOISE_TEXTURE_INCOHERENT",
                        "severity": "degraded",
                        "coherence": round(_noise_texture_result.coherence, 4),
                        "material": _ntc_material,
                    }
                )
        except Exception as _ntc_exc:
            logger.debug("§4.7 Noise-Texture end-of-pipeline check non-blocking: %s", _ntc_exc)

        # §2.44 Context: pass real restorability + genre/material/era so HPG reference
        # memory is keyed correctly (prevents all songs hitting "DEFAULT/digital/post-1990").
        _hpi_restorability = float(_pmgg_restorability_score)
        _hpi_genre = str(_cal_genre_label or "general").strip().lower() or "general"
        _hpi_material = (
            (material_type.value if hasattr(material_type, "value") else str(material_type)).lower()
            if material_type
            else "digital"
        )
        _hpi_era_decade = getattr(_era_result, "decade", 1990)
        _hpi_era = (
            ("pre-1950" if _hpi_era_decade < 1950 else "pre-1980" if _hpi_era_decade < 1980 else "post-1980")
            if _era_result is not None
            else "post-1980"
        )
        try:
            from backend.core.holistic_perceptual_gate import get_holistic_gate as _get_hg

            _hg = _get_hg()
            if self.is_studio_mode():
                _pqs_impr = self._resolve_studio_pqs_improvement(_pqs_result, _fail_reasons)
                _hpi_result = _hg.evaluate_studio(
                    original_audio_for_goals,
                    restored_audio,
                    sample_rate,
                    pqs_improvement=_pqs_impr,
                    artifact_freedom=_artifact_freedom_for_hpi,
                    emotional_arc_score=_emotional_arc_for_hpi,
                )
            else:
                _hpi_result = _hg.evaluate_restoration(
                    original_audio_for_goals,
                    restored_audio,
                    sample_rate,
                    artifact_freedom=_artifact_freedom_for_hpi,
                    emotional_arc_score=_emotional_arc_for_hpi,
                    restorability_score=_hpi_restorability,
                    genre=_hpi_genre,
                    material=_hpi_material,
                    era_bin=_hpi_era,
                )
            if not _hpi_result.passed:
                _fail_reasons.append(
                    {
                        "component": "HolisticPerceptualGate",
                        "error_code": "HPI_FAIL",
                        "severity": "failed",
                        "hpi": _hpi_result.hpi,
                        "artifact_freedom": _hpi_result.artifact_freedom,
                    }
                )
                # §2.60 [RELEASE_MUST] HPI ≤ 0 → Rollback-Kaskade (5 Stufen):
                #   1. _hpi_best_rollback_audio — letzter artefaktfreier Pipeline-Stand (§2.49)
                #   2. _best_carrier_checkpoint — nach Carrier-Phasen, vor Enhancement (§2.60 Stufe 3)
                #   3. original_audio_for_goals — Eingabe vor Pipeline (Primum non nocere, Stufe 5)
                _rollback_target = getattr(self, "_hpi_best_rollback_audio", None)
                if _rollback_target is None:
                    # Stufe 3: Carrier-Checkpoint
                    _rollback_target = getattr(self, "_best_carrier_checkpoint", None)
                    if _rollback_target is not None:
                        logger.info("§2.60 Rollback-Kaskade Stufe 3: _best_carrier_checkpoint")
                if _rollback_target is None:
                    try:
                        _rollback_target = original_audio_for_goals
                    except NameError:
                        _rollback_target = None
                # Bug C fix: Verify rollback target has healthy stereo balance before using it.
                # If checkpoint has L/R imbalance > 20 dB (channel destroyed by stereo phases)
                # while original was balanced, fall back to original_audio_for_goals instead.
                if _rollback_target is not None and _rollback_target.ndim == 2 and _rollback_target.shape[0] == 2:
                    _rb_l = float(np.sqrt(np.mean(_rollback_target[0] ** 2)) + 1e-12)
                    _rb_r = float(np.sqrt(np.mean(_rollback_target[1] ** 2)) + 1e-12)
                    if _rb_l > 1e-4 and _rb_r < _rb_l * 0.1:  # R > 20 dB below L
                        _imb_db = 20.0 * np.log10(_rb_l / (_rb_r + 1e-12))
                        logger.warning(
                            "§2.44 HPI-Rollback-Checkpoint hat silent R-Kanal (%.1f dB Imbalance) "
                            "— Fallback auf original_audio_for_goals (Primum non nocere)",
                            _imb_db,
                        )
                        try:
                            _rollback_target = original_audio_for_goals
                        except NameError:
                            _rollback_target = None
                if _rollback_target is not None and _rollback_target.shape == restored_audio.shape:
                    logger.warning(
                        "§2.44 HPI-Rollback ausgelöst (HPI=%.4f ≤ 0) — "
                        "restored_audio auf besten Rollback-Checkpoint zurückgesetzt",
                        _hpi_result.hpi,
                    )
                    restored_audio = np.clip(
                        np.nan_to_num(_rollback_target, nan=0.0, posinf=0.0, neginf=0.0),
                        -1.0,
                        1.0,
                    )
                else:
                    logger.warning(
                        "§2.44 HPI-Rollback: kein kompatibler Checkpoint verfügbar "
                        "(HPI=%.4f) — Export mit Pipeline-Ausgang (Fallback)",
                        _hpi_result.hpi,
                    )
            else:
                logger.info(
                    "🎯 HPI_COMP mode=%s hpi=%.4f passed=%s timbral=%.3f mert=%.3f artifact=%.3f emotional=%.3f",
                    "Studio" if self.is_studio_mode() else "Restoration",
                    float(_hpi_result.hpi),
                    "1" if bool(_hpi_result.passed) else "0",
                    float(getattr(_hpi_result, "timbral_fidelity", 1.0)),
                    float(getattr(_hpi_result, "mert_similarity", 1.0)),
                    float(_hpi_result.artifact_freedom),
                    float(_hpi_result.emotional_arc_preservation),
                )
        except Exception as _hpi_exc:
            logger.warning(
                "§2.44 HolisticPerceptualGate-Exception (Gate inaktiv, Export im degrade-Modus): %s",
                _hpi_exc,
                exc_info=True,
            )
        if _hpi_result is None:
            logger.warning(
                "§2.44 HPI(unavailable) — HolisticPerceptualGate lieferte kein Ergebnis; "
                "Export läuft im degrade-Modus mit vorhandenen Sicherheitsgates"
            )

        # §MultiSinger [RELEASE_MUST]: detect multi-singer before singer_identity_cosine gate
        try:
            from backend.core.dsp.vocal_register_detector import detect_multi_singer as _detect_ms

            _ms_panns = float(getattr(self, "_panns_singing", 0.0))
            _is_multi_singer = _detect_ms(restored_audio, sample_rate, _ms_panns)
            if _is_multi_singer:
                self._phase_metadata_accumulator["multi_singer"] = True
                logger.info("§MultiSinger: Duett/Chor erkannt — Resemblyzer-Gate übersprungen")
        except Exception as _ms_exc:
            logger.debug("§MultiSinger detect_multi_singer non-blocking: %s", _ms_exc)

        # §2.35c [RELEASE_MUST] VQI-Gate — Gesangs-Qualitäts-Gate bei Singing >= 0.35
        # Aktivierung: PANNs Singing confidence >= 0.35 (§0k vierte Export-Konvergenzbedingung)
        try:
            _vqi_singing_conf = float(getattr(self, "_panns_singing", 0.0))
            if _vqi_singing_conf >= 0.35:
                from backend.core.musical_goals.vocal_quality_index import compute_vqi as _compute_vqi

                _vqi_orig = original_audio_for_goals if original_audio_for_goals is not None else restored_audio
                _is_multi_singer_gate = bool((self._phase_metadata_accumulator or {}).get("multi_singer", False))
                _vqi_segments = [
                    (float(seg.start_s), float(seg.end_s))
                    for seg in (self._ssa_segments or [])
                    if bool(getattr(seg, "has_vocals", False)) and float(seg.end_s) > float(seg.start_s)
                ]
                _vqi_result = _compute_vqi(
                    audio_orig=_vqi_orig,
                    audio_restored=restored_audio,
                    sr=sample_rate,
                    vocal_segments=_vqi_segments or None,
                    skip_singer_identity=_is_multi_singer_gate,  # §MultiSinger: skip Resemblyzer for choirs/duets
                )
                _vqi_score = float(_vqi_result.get("vqi", 0.85))
                self._phase_metadata_accumulator["vqi"] = _vqi_score
                self._phase_metadata_accumulator["singer_identity_cosine"] = float(
                    _vqi_result.get("singer_identity_cosine", 0.85)
                )
                self._phase_metadata_accumulator["singer_id_dsp_fallback"] = bool(
                    _vqi_result.get("singer_id_dsp_fallback", True)
                )
                self._phase_metadata_accumulator["vqi_tier"] = _vqi_result.get("vqi_tier", "unknown")
                logger.info(
                    "§2.35c VQI=%.3f tier=%s singer_id=%.3f formant=%.3f art=%.3f",
                    _vqi_score,
                    _vqi_result.get("vqi_tier"),
                    _vqi_result.get("singer_identity_cosine", 0.0),
                    _vqi_result.get("formant_stability_score", 0.0),
                    _vqi_result.get("articulation_score", 0.0),
                )
                from backend.core.musical_goals.vocal_quality_index import get_vqi_material_floor as _get_vqi_floor

                _vqi_mat_str = str(getattr(material_type, "value", material_type)).lower()
                _vqi_floor = _get_vqi_floor(_vqi_mat_str, is_studio_2026=self.is_studio_mode())
                if _vqi_score < _vqi_floor:
                    logger.warning(
                        "§2.35c VQI=%.3f < %.2f (material=%s) — Recovery-Kaskade: Rollback auf best_carrier_checkpoint",
                        _vqi_score,
                        _vqi_floor,
                        _vqi_mat_str,
                    )
                    _fail_reasons.append(
                        {
                            "component": "VQI",
                            "error_code": "VQI_BELOW_THRESHOLD",
                            "severity": "warning",
                            "vqi": _vqi_score,
                            "singer_id_dsp_fallback": _vqi_result.get("singer_id_dsp_fallback", True),
                        }
                    )
        except Exception as _vqi_exc:
            logger.debug("§2.35c VQI-Gate nicht verfügbar: %s", _vqi_exc)

        # §2.49 Export-Gate: artifact_freedom < 0.95 → rollback + fail_reason
        # [RELEASE_MUST] "Kein Artefakt-behafteter Export" (§2.49 Invariante).
        # Rollback-Kaskade (identisch §2.44):
        #   1. _hpi_best_rollback_audio — letzter artefaktfreier Pipeline-Stand
        #   2. original_audio_for_goals — Eingabe vor Pipeline (Primum non nocere)
        if _artifact_freedom_for_hpi < 0.95:
            _fail_reasons.append(
                {
                    "component": "ArtifactFreedomGate",
                    "error_code": "ARTIFACT_FREEDOM_VETO",
                    "severity": "failed",
                    "artifact_freedom": _artifact_freedom_for_hpi,
                    "detail": getattr(self, "_artifact_freedom_detail", {}),
                }
            )
            _afg_rollback_target = getattr(self, "_hpi_best_rollback_audio", None)
            if _afg_rollback_target is None:
                # §2.60 Stufe 3: Carrier-Checkpoint
                _afg_rollback_target = getattr(self, "_best_carrier_checkpoint", None)
                if _afg_rollback_target is not None:
                    logger.info("§2.60 AFG-Rollback Stufe 3: _best_carrier_checkpoint")
            if _afg_rollback_target is None:
                try:
                    _afg_rollback_target = original_audio_for_goals
                except NameError:
                    _afg_rollback_target = None
            if _afg_rollback_target is not None and _afg_rollback_target.shape == restored_audio.shape:
                logger.warning(
                    "§2.49 Export-Gate: artifact_freedom=%.3f < 0.95 — "
                    "restored_audio auf besten artefaktfreien Checkpoint zurückgesetzt",
                    _artifact_freedom_for_hpi,
                )
                restored_audio = np.clip(
                    np.nan_to_num(_afg_rollback_target, nan=0.0, posinf=0.0, neginf=0.0),
                    -1.0,
                    1.0,
                )
            else:
                logger.warning(
                    "§2.49 Export-Gate: artifact_freedom=%.3f < 0.95 — "
                    "kein kompatibler Rollback-Checkpoint (Primum non nocere: Export trotzdem)",
                    _artifact_freedom_for_hpi,
                )

        # Fallback Quality Floor: when ML->DSP fallback happened, enforce a final
        # quality floor and attempt checkpoint recovery before export.
        _fallback_quality_floor = self._evaluate_fallback_quality_floor(
            ml_fallbacks_used=list(getattr(self, "_ml_fallbacks_used", [])),
            hpi_result=_hpi_result,
            artifact_freedom=_artifact_freedom_for_hpi,
        )
        if bool(_fallback_quality_floor.get("triggered", False)) and not bool(
            _fallback_quality_floor.get("passed", False)
        ):
            _recovery_trace: list[dict[str, Any]] = []
            _recovery_target = getattr(self, "_hpi_best_rollback_audio", None)
            _recovery_source = "hpi_best_checkpoint"
            if _recovery_target is None:
                _recovery_target = original_audio_for_goals
                _recovery_source = "original_audio"

            # §G2: Try all candidates in priority order until shape-compatible source found
            _fqf_candidates: list[tuple[Any, str]] = []
            if getattr(self, "_hpi_best_rollback_audio", None) is not None:
                _fqf_candidates.append((self._hpi_best_rollback_audio, "hpi_best_checkpoint"))
            if original_audio_for_goals is not None:
                _fqf_candidates.append((original_audio_for_goals, "original_audio"))
            for _fqf_cand, _fqf_src in _fqf_candidates:
                if _fqf_cand is not None and hasattr(_fqf_cand, "shape") and _fqf_cand.shape == restored_audio.shape:
                    _recovery_target = _fqf_cand
                    _recovery_source = _fqf_src
                    break

            _fallback_quality_floor["attempts"] = len(_fqf_candidates)
            _compatible_shape = (
                _recovery_target is not None
                and hasattr(_recovery_target, "shape")
                and _recovery_target.shape == restored_audio.shape
            )
            if _compatible_shape:
                restored_audio = np.clip(
                    np.nan_to_num(_recovery_target, nan=0.0, posinf=0.0, neginf=0.0),
                    -1.0,
                    1.0,
                )
                _fallback_quality_floor["recovered"] = True
                _fallback_quality_floor["status"] = "recovered"
                _fallback_quality_floor["best_candidate"] = _recovery_source
                _fallback_quality_floor["reason"] = "fallback_quality_floor_recovered_with_checkpoint"
                _recovery_trace.append(
                    {
                        "attempt": 1,
                        "candidate": _recovery_source,
                        "action": "rollback",
                        "result": "applied",
                    }
                )
                _fail_reasons.append(
                    {
                        "component": "FallbackQualityFloor",
                        "error_code": "FALLBACK_QUALITY_FLOOR_RECOVERED",
                        "severity": "degraded",
                        "action": "rollback_recovery",
                        "detail": _fallback_quality_floor["reason"],
                    }
                )
            else:
                _fallback_quality_floor["status"] = "degraded"
                _fallback_quality_floor["reason"] = "fallback_quality_floor_failed_no_compatible_checkpoint"
                _recovery_trace.append(
                    {
                        "attempt": 1,
                        "candidate": _recovery_source,
                        "action": "rollback",
                        "result": "failed",
                    }
                )
                _fail_reasons.append(
                    {
                        "component": "FallbackQualityFloor",
                        "error_code": "FALLBACK_QUALITY_FLOOR_FAILED",
                        "severity": "failed",
                        "action": "degraded_export",
                        "detail": _fallback_quality_floor["reason"],
                    }
                )
            _fallback_quality_floor["recovery_trace"] = _recovery_trace

        # §2.51a [RELEASE_MUST] Stereo-Hörsicherheitsprofil (No-Surprises Export Guard)
        # Pass material_key and source baseline for adaptive mono_drop threshold (§2.51a material-adaptiv).
        _stereo_mat_key = str(getattr(material_type, "value", material_type) or "")
        _stereo_src_cancel_ratio = float(
            getattr(_src_baseline, "phase_cancellation_ratio", 0.0) if _src_baseline is not None else 0.0
        )
        _stereo_safety_guard = _evaluate_stereo_safety_guard(
            original_audio=original_audio_for_goals,
            restored_audio=restored_audio,
            sample_rate=sample_rate,
            material_key=_stereo_mat_key,
            source_phase_cancellation_ratio=_stereo_src_cancel_ratio,
        )
        if bool(_stereo_safety_guard.get("warning", False)):
            logger.warning(
                "§2.51a Stereo-Warnstufe: %s",
                ", ".join(list(_stereo_safety_guard.get("warning_reasons", []))),
            )
        if bool(_stereo_safety_guard.get("hard_fail", False)):
            _stereo_fail_idx = len(_fail_reasons)
            _fail_reasons.append(
                {
                    "component": "StereoSafetyGuard",
                    "error_code": "STEREO_SAFETY_HARD_FAIL",
                    "severity": "failed",
                    "detail": _stereo_safety_guard,
                }
            )
            _stereo_rollback_target = getattr(self, "_hpi_best_rollback_audio", None)
            if _stereo_rollback_target is None:
                _stereo_rollback_target = original_audio_for_goals
            _shape_ok = (
                _stereo_rollback_target is not None
                and hasattr(_stereo_rollback_target, "shape")
                and _stereo_rollback_target.shape == restored_audio.shape
            )
            if _shape_ok:
                restored_audio = np.clip(
                    np.nan_to_num(_stereo_rollback_target, nan=0.0, posinf=0.0, neginf=0.0),
                    -1.0,
                    1.0,
                )
                logger.warning(
                    "§2.51a Stereo-Hard-Fail → Rollback auf sicheren Checkpoint (%s)",
                    "hpi_best_checkpoint"
                    if getattr(self, "_hpi_best_rollback_audio", None) is not None
                    else "original",
                )
            else:
                logger.warning("§2.51a Stereo-Hard-Fail, aber kein kompatibler Rollback-Checkpoint verfügbar")
        else:
            _stereo_fail_idx = -1
        # Re-evaluate for telemetry after potential rollback.
        _stereo_safety_guard = _evaluate_stereo_safety_guard(
            original_audio=original_audio_for_goals,
            restored_audio=restored_audio,
            sample_rate=sample_rate,
            material_key=_stereo_mat_key,
            source_phase_cancellation_ratio=_stereo_src_cancel_ratio,
        )
        # §2.51a: After successful rollback, downgrade fail_reason from "failed" → "degraded".
        # If the re-evaluated guard passes, the rollback restored a stereo-safe signal.
        if _stereo_fail_idx >= 0 and not bool(_stereo_safety_guard.get("hard_fail", False)):
            if _stereo_fail_idx < len(_fail_reasons):
                _fail_reasons[_stereo_fail_idx]["severity"] = "degraded"
                _fail_reasons[_stereo_fail_idx]["error_code"] = "STEREO_SAFETY_RECOVERED"
                logger.info("§2.51a Stereo-Hard-Fail nach Rollback behoben → Status: degraded")

        # Recompute degradation status after HPI/artifact gates
        try:
            from backend.core.pipeline_health_state import (
                pipeline_health_from_fail_reasons as _phfr_2,
            )
            from backend.core.pipeline_health_state import (
                primary_fail_reason_from_fail_reasons as _prfr_2,
            )

            _degradation_status = _phfr_2(_fail_reasons).value
            _primary_fail_reason = _prfr_2(_fail_reasons)
        except Exception:
            pass

        _top_defects_pre = [
            {"type": s.defect_type.value, "severity": s.severity} for s in defect_result.get_top_defects(5)
        ]
        _joy_runtime_index = self._compute_joy_fatigue_runtime_index(
            _musical_goal_scores if isinstance(_musical_goal_scores, dict) else None,
            (_analytics_meta.get("listening_fatigue") if isinstance(_analytics_meta, dict) else None),
            _artifact_freedom_for_hpi,
            _emotional_arc_for_hpi,
            audio=restored_audio,
            sr=48000,
        )
        if not isinstance(_joy_runtime_index, dict):
            _joy_runtime_index = {}
        _joy_runtime_index = {
            "joy_index": float(np.clip(float(_joy_runtime_index.get("joy_index", 0.0)), 0.0, 1.0)),
            "fatigue_index": float(np.clip(float(_joy_runtime_index.get("fatigue_index", 0.0)), 0.0, 1.0)),
            "frisson_index": float(np.clip(float(_joy_runtime_index.get("frisson_index", 0.0)), 0.0, 1.0)),
            "components": (
                dict(_joy_runtime_index.get("components", {}))
                if isinstance(_joy_runtime_index.get("components", {}), dict)
                else {}
            ),
        }
        _auto_improvement = self._derive_auto_improvement_recommendations(
            musical_goal_scores=_musical_goal_scores if isinstance(_musical_goal_scores, dict) else None,
            musical_goals_passed=_musical_goals_passed if isinstance(_musical_goals_passed, dict) else None,
            artifact_freedom=_artifact_freedom_for_hpi,
            phase_regression_log=dict(getattr(self, "_phase_regression_log", {})),
            top_defects=_top_defects_pre,
        )
        if not isinstance(_auto_improvement, dict):
            _auto_improvement = {}
        _auto_improvement = {
            "count": (
                int(max(0, _auto_improvement.get("count", 0)))
                if isinstance(_auto_improvement.get("count", 0), (int, float))
                else 0
            ),
            "recommendations": (
                list(_auto_improvement.get("recommendations", []))
                if isinstance(_auto_improvement.get("recommendations", []), list)
                else []
            ),
        }

        _song_calibration_meta = dict(getattr(self, "_song_calibration_profile", {}))
        if not isinstance(_song_calibration_meta.get("cluster_policy"), dict):
            _song_calibration_meta["cluster_policy"] = UnifiedRestorerV3._derive_song_cluster_policy(
                material=str(getattr(material_type, "value", material_type) or "unknown"),
                era_decade=_song_calibration_meta.get("era_decade"),
                genre_label=str(_song_calibration_meta.get("genre_label", "general") or "general"),
                restorability_tier=str(_song_calibration_meta.get("restorability_tier", "fair") or "fair"),
                is_schlager=bool(_song_calibration_meta.get("is_schlager", False)),
            )
        _song_calibration_meta["cluster_key"] = str(
            _song_calibration_meta.get("cluster_key")
            or _song_calibration_meta["cluster_policy"].get("cluster_key", "unknown:unknown:general:fair")
        )
        _strict_conflict_report = self._build_strict_phase_goal_conflict_report(
            phase_gate_entries=list(getattr(self, "_pmgg_log_entries", []) or []),
            phase_regression_log=dict(getattr(self, "_phase_regression_log", {})),
            interaction_guard_meta=dict(getattr(self, "_interaction_guard_metadata", {})),
            runtime_conflict_state=dict(getattr(self, "_phase_goal_conflict_runtime", {})),
            musical_goals_passed=_musical_goals_passed if isinstance(_musical_goals_passed, dict) else None,
            song_calibration_profile=_song_calibration_meta,
        )
        if bool(_strict_conflict_report.get("conflict_present", False)):
            _auto_recos = list(_auto_improvement.get("recommendations", []))
            _auto_recos.insert(
                0,
                {
                    "focus": "phase_goal_conflict",
                    "action": "strict_autosetup_active",
                    "reason": (
                        f"conflict_score={float(_strict_conflict_report.get('conflict_score', 0.0)):.2f}, "
                        f"rollbacks={int(_strict_conflict_report.get('rollback_count', 0))}"
                    ),
                },
            )
            _auto_improvement["recommendations"] = _auto_recos[:8]
            _auto_improvement["count"] = len(_auto_improvement["recommendations"])

        logger.info(
            "§2.53 experience_runtime: joy_runtime_index={joy_index:%.3f,fatigue_index:%.3f,frisson_index:%.3f} "
            "auto_improvement_recommendations={count:%d} song_calibration={cluster_key:%s,cluster_policy:%s}",
            float(_joy_runtime_index.get("joy_index", 0.0)),
            float(_joy_runtime_index.get("fatigue_index", 0.0)),
            float(_joy_runtime_index.get("frisson_index", 0.0)),
            int(_auto_improvement.get("count", 0)),
            str(_song_calibration_meta.get("cluster_key", "")),
            str(_song_calibration_meta.get("cluster_policy", {}).get("cluster_key", "")),
        )
        logger.info(
            "StrictConflictReport: present=%s score=%.3f rollback_count=%d",
            bool(_strict_conflict_report.get("conflict_present", False)),
            float(_strict_conflict_report.get("conflict_score", 0.0)),
            int(_strict_conflict_report.get("rollback_count", 0)),
        )
        if int(_auto_improvement.get("count", 0)) == 0:
            logger.warning(
                "§2.53 degrade-hint: auto_improvement_recommendations leer — "
                "non-blocking, aber Runtime-Empfehlungen sollten verfügbar sein"
            )

        try:
            if not self.is_studio_mode() and os.environ.get(
                "AURIK_BRONZE_RESTORATION_PROFILE", "0"
            ).strip().lower() not in {"1", "true", "yes", "on"}:
                import pyloudnorm as _pyln

                _lufs_meter_final = _pyln.Meter(sample_rate)
                _orig_final = (
                    original_audio_for_goals
                    if original_audio_for_goals.ndim >= 2
                    else original_audio_for_goals[:, None]
                )
                _rest_final = restored_audio if restored_audio.ndim >= 2 else restored_audio[:, None]
                if _orig_final.ndim == 2 and _orig_final.shape[0] == 2 and _orig_final.shape[1] != 2:
                    _orig_final = _orig_final.T
                if _rest_final.ndim == 2 and _rest_final.shape[0] == 2 and _rest_final.shape[1] != 2:
                    _rest_final = _rest_final.T
                _lufs_orig_final = _lufs_meter_final.integrated_loudness(_orig_final)
                _lufs_rest_final = _lufs_meter_final.integrated_loudness(_rest_final)
                if np.isfinite(_lufs_orig_final) and np.isfinite(_lufs_rest_final):

                    def _nf_dbfs(_x: np.ndarray) -> float:
                        _arr = np.asarray(_x, dtype=np.float32)
                        if _arr.ndim == 2:
                            if _arr.shape[0] == 2 and _arr.shape[1] != 2:
                                _arr = _arr.T
                            _arr = np.mean(_arr, axis=1)
                        _p5 = float(np.percentile(np.abs(_arr.astype(np.float64)), 5.0)) + 1e-12
                        return float(20.0 * np.log10(_p5))

                    def _samples_first(_x: np.ndarray) -> np.ndarray:
                        _arr = np.asarray(_x, dtype=np.float32)
                        if _arr.ndim == 2 and _arr.shape[0] == 2 and _arr.shape[1] != 2:
                            return _arr.T
                        return _arr

                    # Match UAT R8 semantics: baseline from original input audio after
                    # length alignment to current restored output.
                    _orig_sf = _samples_first(np.asarray(audio, dtype=np.float32))
                    _rest_sf = _samples_first(np.asarray(restored_audio, dtype=np.float32))
                    _orig_len = _orig_sf.shape[0] if _orig_sf.ndim >= 1 else 0
                    _rest_len = _rest_sf.shape[0] if _rest_sf.ndim >= 1 else 0
                    _n_align = min(_orig_len, _rest_len)
                    _orig_for_nf = _orig_sf[:_n_align] if _n_align > 0 else _orig_sf
                    _noise_before_final = _nf_dbfs(_orig_for_nf)
                    _mat_key_nf = str(getattr(self, "_material_type", material_type or "unknown") or "unknown").lower()
                    _noise_allowance_db = {
                        "vinyl": 2.0,
                        "shellac": 2.0,
                        "reel_tape": 2.0,
                        "tape": 2.0,
                        "cassette": 2.0,
                        "mp3_low": 1.5,
                        "mp3_high": 1.0,
                        "aac": 1.0,
                        "streaming": 1.0,
                        "cd_digital": 0.5,
                        "dat": 0.5,
                    }.get(_mat_key_nf, 1.5)
                    _final_delta = abs(_lufs_rest_final - _lufs_orig_final)
                    if _final_delta > 4.0:
                        # §2.45a-II §0d Adaptive-LUFS-Rescue (v9.11.14):
                        # Problem 1 — Wrong delta: integrated LUFS compares original (WITH carrier
                        # noise at -35 dBFS throughout) vs restored (WITHOUT carrier noise → quiet
                        # sections at -55 dBFS). The 14.75 LU delta is mostly carrier-noise removal,
                        # NOT music signal loss. Applying 12 dB gain over-corrects massively.
                        # Fix: compute music-gated delta — only frames where original is above the
                        # original signal's noise floor + 6 dB (i.e., genuine music frames).
                        #
                        # Problem 2 — Wrong gate: _musical_gain_envelope used fixed -50 dBFS gate.
                        # Residual carrier noise at -35 dBFS passes the gate → gets full LUFS boost →
                        # Pegelexplosion at intro/outro.
                        # Fix: adaptive gate = P5(original) + 6 dB → excludes carrier noise,
                        # only boosts genuine music frames.

                        # Adaptive gate: 5th percentile of original = carrier noise floor
                        _adaptive_gate_dbfs = float(np.clip(float(_noise_before_final) + 6.0, -48.0, -18.0))

                        # Music-gated delta: measure actual signal drop in music frames only
                        # (ignores carrier-noise sections that inflate integrated LUFS delta)
                        _hop_mg = 4800  # 100 ms @ 48 kHz
                        _gate_lin_mg = float(10.0 ** (_adaptive_gate_dbfs / 20.0))
                        _rest_arr_mg = np.asarray(restored_audio, dtype=np.float32)
                        _orig_arr_mg = _orig_for_nf  # already aligned to restored length
                        _orig_1d_mg = np.mean(_orig_arr_mg, axis=-1) if _orig_arr_mg.ndim == 2 else _orig_arr_mg.ravel()
                        _rest_1d_mg = np.mean(_rest_arr_mg, axis=-1) if _rest_arr_mg.ndim == 2 else _rest_arr_mg.ravel()
                        _n_mg = min(len(_orig_1d_mg), len(_rest_1d_mg))
                        _n_frames_mg = _n_mg // _hop_mg
                        _needed_db_music = 0.0
                        if _n_frames_mg >= 3:
                            _of = _orig_1d_mg[: _n_frames_mg * _hop_mg].reshape(_n_frames_mg, _hop_mg)
                            _rf = _rest_1d_mg[: _n_frames_mg * _hop_mg].reshape(_n_frames_mg, _hop_mg)
                            _rms_o = np.sqrt(np.mean(_of**2, axis=1) + 1e-15)
                            _rms_r = np.sqrt(np.mean(_rf**2, axis=1) + 1e-15)
                            # §2.45a-II §0 Vinyl-Noise-Gate-Fix: _gate_lin_mg uses P5 of SAMPLE amplitudes
                            # (~-60 dBFS → clamped to -48 dBFS) — too permissive for vinyl surface
                            # noise at -33 dBFS. Replace with P5 of FRAME RMS from original + 10 dB:
                            # P5(frame_rms=-33 dBFS) + 10 dB → gate=-23 dBFS → noise correctly excluded.
                            _p5_frame_rms_orig = float(np.percentile(_rms_o, 5))
                            _frame_gate_lin = _p5_frame_rms_orig * (10.0 ** (10.0 / 20.0))  # P5 + 10 dB
                            _music_gate_lin_mg = max(_gate_lin_mg, _frame_gate_lin)  # stricter gate
                            _music_mask_mg = _rms_o > _music_gate_lin_mg
                            if np.any(_music_mask_mg):
                                _rms_o_music = float(np.sqrt(np.mean(_rms_o[_music_mask_mg] ** 2)))
                                _rms_r_music = float(np.sqrt(np.mean(_rms_r[_music_mask_mg] ** 2)))
                                _raw_music_delta = 20.0 * np.log10((_rms_o_music + 1e-15) / (_rms_r_music + 1e-15))
                                # Only allow positive correction (restore lost signal, never attenuate)
                                # Cap at 6 dB: genuine denoising rarely drops music by more than 6 dB
                                _needed_db_music = float(np.clip(_raw_music_delta, 0.0, 6.0))
                                logger.info(
                                    "§2.45a music-gated LUFS: integrated_delta=%.2f LU → "
                                    "music_delta=%.2f dB (frame_gate=%.1f dBFS, music_frames=%d/%d)",
                                    _final_delta,
                                    _raw_music_delta,
                                    float(20.0 * np.log10(max(_music_gate_lin_mg, 1e-12))),
                                    int(np.sum(_music_mask_mg)),
                                    _n_frames_mg,
                                )

                        _needed_db_final = _needed_db_music  # Use music-gated delta, not integrated LUFS delta
                        _gain_final = float(10.0 ** (_needed_db_final / 20.0))
                        _rescued_final = UnifiedRestorerV3._musical_gain_envelope(
                            np.asarray(restored_audio, dtype=np.float32),
                            _gain_final,
                            gate_dbfs=_adaptive_gate_dbfs,  # adaptive: P5(orig)+6dB, not fixed -50 dBFS
                            crossfade_ms=10.0,
                            sr=sample_rate,
                            # §2.45a-II §0 reference_for_gate=original: frame-RMS P5 from original
                            # prevents vinyl surface noise (-33 dBFS) being classified as music.
                            # Without this, P5 of restored (denoised, ~-45 dBFS) gives gate=-35 dBFS
                            # → noise at -33 dBFS passes gate → Pegelexplosion in intro/outro.
                            reference_for_gate=_orig_for_nf,
                        )
                        if _gain_final > 1.0005:
                            _p999_final = float(np.percentile(np.abs(_rescued_final), 99.9))
                            if _p999_final > 0.98:
                                _abs_final = np.abs(_rescued_final)
                                _over_final = _abs_final > 0.92
                                if np.any(_over_final):
                                    _sign_final = np.sign(_rescued_final)
                                    _soft_final = 0.92 + 0.08 * np.tanh((_abs_final - 0.92) / 0.08)
                                    _rescued_final = np.where(_over_final, _sign_final * _soft_final, _rescued_final)
                        _rescued_final = np.clip(
                            np.nan_to_num(_rescued_final, nan=0.0, posinf=0.0, neginf=0.0),
                            -1.0,
                            1.0,
                        )
                        _rescued_final_2d = _rescued_final if _rescued_final.ndim >= 2 else _rescued_final[:, None]
                        if (
                            _rescued_final_2d.ndim == 2
                            and _rescued_final_2d.shape[0] == 2
                            and _rescued_final_2d.shape[1] != 2
                        ):
                            _rescued_final_2d = _rescued_final_2d.T
                        _lufs_resc_final = _lufs_meter_final.integrated_loudness(_rescued_final_2d)
                        if np.isfinite(_lufs_resc_final):
                            _resc_delta_final = abs(_lufs_resc_final - _lufs_orig_final)
                            _noise_after_final = _nf_dbfs(_rescued_final)
                            # §0c Maximal-umsetzbare Recovery: when the pipeline dropped the
                            # signal by > 8 LU, leaving it underleveled is worse than a moderate
                            # noise-floor rise. Relax the guard proportionally so LUFS rescue
                            # can succeed. The +12 dB extra allowance absorbs the gain-induced
                            # noise-floor rise (1 dB rescue gain → 1 dB noise-floor rise).
                            _noise_allowance_eff = (
                                _noise_allowance_db + 12.0 if _final_delta > 8.0 else _noise_allowance_db
                            )
                            _noise_ok = _noise_after_final <= (_noise_before_final + _noise_allowance_eff)
                            _edge_ok_final = UnifiedRestorerV3._quiet_edge_rescue_ok(
                                _orig_for_nf,
                                _rescued_final,
                                sample_rate,
                                material_key=_mat_key_nf,
                            )
                            if (_resc_delta_final + 1e-6 < _final_delta) and _noise_ok and _edge_ok_final:
                                restored_audio = _rescued_final.astype(np.float32, copy=False)
                                _lufs_delta_for_result = float(_resc_delta_final)
                                logger.info(
                                    "§2.45a final LUFS alignment: delta %.2f -> %.2f LU (gain_db=%.2f)",
                                    float(_final_delta),
                                    float(_resc_delta_final),
                                    _needed_db_final,
                                )
                            elif (_resc_delta_final + 1e-6 < _final_delta) and (not _edge_ok_final):
                                logger.info(
                                    "§2.45a final LUFS rescue skipped by quiet-edge guard: "
                                    "material=%s delta=%.2f->%.2f LU",
                                    _mat_key_nf,
                                    float(_final_delta),
                                    float(_resc_delta_final),
                                )
                            elif (_resc_delta_final + 1e-6 < _final_delta) and (not _noise_ok):
                                # Try combined rescue: keep LUFS benefit, then attenuate only low-level floor
                                # so both R10 (LUFS drift) and R8 (noise-floor) can pass simultaneously.
                                _noise_limit = float(_noise_before_final + _noise_allowance_eff)
                                _excess_db = float(max(0.0, _noise_after_final - _noise_limit))
                                _reduce_db = float(np.clip(_excess_db + 1.0, 1.5, 12.0))

                                def _attenuate_floor_for_lufs(_x: np.ndarray, _reduce: float) -> np.ndarray:
                                    _arr = np.asarray(_x, dtype=np.float32)
                                    _abs = np.abs(_arr)
                                    _thr = float(np.percentile(_abs, 40.0)) + 1e-9
                                    _gmin = float(10.0 ** (-_reduce / 20.0))
                                    _slope = np.clip(_abs / _thr, 0.0, 1.0)
                                    _gain = _gmin + (1.0 - _gmin) * _slope
                                    return _arr * _gain.astype(np.float32, copy=False)

                                _combo_rescued = _attenuate_floor_for_lufs(_rescued_final, _reduce_db)
                                _combo_rescued = np.clip(
                                    np.nan_to_num(_combo_rescued, nan=0.0, posinf=0.0, neginf=0.0),
                                    -1.0,
                                    1.0,
                                )
                                _combo_2d = _combo_rescued if _combo_rescued.ndim >= 2 else _combo_rescued[:, None]
                                if _combo_2d.ndim == 2 and _combo_2d.shape[0] == 2 and _combo_2d.shape[1] != 2:
                                    _combo_2d = _combo_2d.T
                                _lufs_combo = _lufs_meter_final.integrated_loudness(_combo_2d)
                                _noise_combo = _nf_dbfs(_combo_rescued)
                                if np.isfinite(_lufs_combo):
                                    _combo_delta = abs(float(_lufs_combo) - float(_lufs_orig_final))
                                    _combo_edge_ok = UnifiedRestorerV3._quiet_edge_rescue_ok(
                                        _orig_for_nf,
                                        _combo_rescued,
                                        sample_rate,
                                        material_key=_mat_key_nf,
                                    )
                                    if (
                                        (_combo_delta + 1e-6 < _final_delta)
                                        and (_noise_combo <= float(_noise_before_final + _noise_allowance_eff))
                                        and _combo_edge_ok
                                    ):
                                        restored_audio = _combo_rescued.astype(np.float32, copy=False)
                                        _lufs_delta_for_result = float(_combo_delta)
                                        logger.info(
                                            "§2.45a final LUFS+noise rescue: delta %.2f -> %.2f LU "
                                            "(noise %.2f -> %.2f dBFS, limit %.2f, material=%s)",
                                            float(_final_delta),
                                            float(_combo_delta),
                                            float(_noise_before_final),
                                            float(_noise_combo),
                                            _noise_limit,
                                            _mat_key_nf,
                                        )
                                    elif (_combo_delta + 1e-6 < _final_delta) and (not _combo_edge_ok):
                                        _lufs_delta_for_result = float(_final_delta)
                                        logger.info(
                                            "§2.45a final LUFS+noise rescue skipped by quiet-edge guard: material=%s",
                                            _mat_key_nf,
                                        )
                                    else:
                                        _lufs_delta_for_result = float(_final_delta)
                                        logger.info(
                                            "§2.45a final LUFS rescue skipped due to noise-floor guard: "
                                            "noise %.2f -> %.2f dBFS (limit %.2f, material=%s)",
                                            float(_noise_before_final),
                                            float(_noise_after_final),
                                            _noise_limit,
                                            _mat_key_nf,
                                        )
                                else:
                                    _lufs_delta_for_result = float(_final_delta)
                            else:
                                _lufs_delta_for_result = float(_final_delta)
                    else:
                        _lufs_delta_for_result = float(_final_delta)

                    # Final noise-floor rescue (R8): if restoration raised floor above the
                    # material-adaptive allowance, apply low-level downward expansion while
                    # leaving musical peaks untouched.
                    _noise_current_final = _nf_dbfs(restored_audio)
                    # Use the same relaxed allowance as the main LUFS rescue above so that
                    # the noise-floor guard here doesn't undo a successful LUFS rescue.
                    _noise_limit_final = _noise_before_final + (
                        _noise_allowance_db + 12.0 if _final_delta > 8.0 else _noise_allowance_db
                    )
                    if _noise_current_final > _noise_limit_final:
                        _excess_db = float(_noise_current_final - _noise_limit_final)
                        _reduce_db = float(np.clip(_excess_db + 1.0, 1.5, 12.0))

                        def _attenuate_floor(_x: np.ndarray, _reduce: float) -> np.ndarray:
                            _arr = np.asarray(_x, dtype=np.float32)
                            _abs = np.abs(_arr)
                            _thr = float(np.percentile(_abs, 40.0)) + 1e-9
                            _gmin = float(10.0 ** (-_reduce / 20.0))
                            _slope = np.clip(_abs / _thr, 0.0, 1.0)
                            _gain = _gmin + (1.0 - _gmin) * _slope
                            return _arr * _gain.astype(np.float32, copy=False)

                        _noise_rescued = _attenuate_floor(restored_audio, _reduce_db)
                        _noise_rescued = np.clip(
                            np.nan_to_num(_noise_rescued, nan=0.0, posinf=0.0, neginf=0.0),
                            -1.0,
                            1.0,
                        )
                        _noise_resc_2d = _noise_rescued if _noise_rescued.ndim >= 2 else _noise_rescued[:, None]
                        if _noise_resc_2d.ndim == 2 and _noise_resc_2d.shape[0] == 2 and _noise_resc_2d.shape[1] != 2:
                            _noise_resc_2d = _noise_resc_2d.T
                        _lufs_noise_resc = _lufs_meter_final.integrated_loudness(_noise_resc_2d)
                        _noise_after_resc = _nf_dbfs(_noise_rescued)
                        _noise_resc_delta = abs(float(_lufs_noise_resc) - float(_lufs_orig_final))
                        if np.isfinite(_lufs_noise_resc) and (_noise_after_resc <= _noise_limit_final):
                            restored_audio = _noise_rescued.astype(np.float32, copy=False)
                            _lufs_delta_for_result = float(_noise_resc_delta)
                            logger.info(
                                "§2.45a final noise-floor rescue: noise %.2f -> %.2f dBFS (limit %.2f), "
                                "LUFS delta=%.2f",
                                float(_noise_current_final),
                                float(_noise_after_resc),
                                float(_noise_limit_final),
                                float(_noise_resc_delta),
                            )

                    # Joint end-guard (R8+R10): choose a music-only gain candidate that
                    # satisfies both LUFS drift <= 4.0 and noise-floor increase <= 3 dBFS.
                    _joint_2d = restored_audio if restored_audio.ndim >= 2 else restored_audio[:, None]
                    if _joint_2d.ndim == 2 and _joint_2d.shape[0] == 2 and _joint_2d.shape[1] != 2:
                        _joint_2d = _joint_2d.T
                    _joint_lufs_current = _lufs_meter_final.integrated_loudness(_joint_2d)
                    _joint_delta_current = (
                        abs(float(_joint_lufs_current) - float(_lufs_orig_final))
                        if np.isfinite(_joint_lufs_current)
                        else 99.0
                    )
                    _joint_noise_current = _nf_dbfs(restored_audio)
                    if (_joint_delta_current > 4.0) or (_joint_noise_current > _noise_limit_final):
                        _joint_base = np.asarray(restored_audio, dtype=np.float32)
                        _best_joint_audio = None
                        _best_joint_delta = None

                        def _attenuate_floor_joint(_x: np.ndarray, _reduce: float) -> np.ndarray:
                            _arr = np.asarray(_x, dtype=np.float32)
                            _abs = np.abs(_arr)
                            _thr = float(np.percentile(_abs, 40.0)) + 1e-9
                            _gmin = float(10.0 ** (-_reduce / 20.0))
                            _slope = np.clip(_abs / _thr, 0.0, 1.0)
                            _gain = _gmin + (1.0 - _gmin) * _slope
                            return _arr * _gain.astype(np.float32, copy=False)

                        _joint_needed_db = float(np.clip(float(_lufs_orig_final - _joint_lufs_current), -12.0, 12.0))
                        for _scale in (1.00, 0.85, 0.70, 0.55, 0.40, 0.28):
                            _cand_gain = float(10.0 ** ((_joint_needed_db * _scale) / 20.0))
                            # §0a §2.45a-II: use adaptive gate (P5(orig)+6 dB, e.g. -27 dBFS for vinyl)
                            # instead of fixed -36.0 dBFS. Fixed gate allowed vinyl surface noise at
                            # -33 dBFS (-33 > -36) into the gain envelope → Pegelexplosion in intro/outro.
                            _cand = UnifiedRestorerV3._musical_gain_envelope(
                                _joint_base,
                                _cand_gain,
                                gate_dbfs=_adaptive_gate_dbfs,  # adaptive: P5(orig)+6dB, not -36 fixed
                                crossfade_ms=10.0,
                                sr=sample_rate,
                                reference_for_gate=_orig_for_nf,  # §2.45a-II: frame-P5 from original
                            )
                            _cand_noise = _nf_dbfs(_cand)
                            if _cand_noise > _noise_limit_final:
                                _cand_reduce_db = float(np.clip((_cand_noise - _noise_limit_final) + 1.0, 1.5, 12.0))
                                _cand = _attenuate_floor_joint(_cand, _cand_reduce_db)
                            _cand = np.clip(np.nan_to_num(_cand, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                            _cand_2d = _cand if _cand.ndim >= 2 else _cand[:, None]
                            if _cand_2d.ndim == 2 and _cand_2d.shape[0] == 2 and _cand_2d.shape[1] != 2:
                                _cand_2d = _cand_2d.T
                            _cand_lufs = _lufs_meter_final.integrated_loudness(_cand_2d)
                            if not np.isfinite(_cand_lufs):
                                continue
                            _cand_delta = abs(float(_cand_lufs) - float(_lufs_orig_final))
                            _cand_noise = _nf_dbfs(_cand)
                            _cand_edge_ok = UnifiedRestorerV3._quiet_edge_rescue_ok(
                                _orig_for_nf,
                                _cand,
                                sample_rate,
                                material_key=_mat_key_nf,
                            )
                            _cand_ok = (
                                (_cand_delta <= 4.0 + 1e-6)
                                and (_cand_noise <= _noise_limit_final + 1e-6)
                                and _cand_edge_ok
                            )
                            if _cand_ok:
                                if (
                                    _best_joint_audio is None
                                    or _best_joint_delta is None
                                    or _cand_delta < _best_joint_delta
                                ):
                                    _best_joint_audio = _cand.astype(np.float32, copy=False)
                                    _best_joint_delta = float(_cand_delta)

                        if _best_joint_audio is not None and _best_joint_delta is not None:
                            restored_audio = _best_joint_audio
                            _lufs_delta_for_result = float(_best_joint_delta)
                            logger.info(
                                "§2.45a joint end-guard selected candidate: LUFS delta=%.2f, noise_limit=%.2f dBFS",
                                float(_best_joint_delta),
                                float(_noise_limit_final),
                            )

        except Exception as _lufs_final_exc:
            logger.debug("Finale LUFS-Ausrichtung übersprungen: %s", _lufs_final_exc)

        # §2.30c-II [RELEASE_MUST] WaveformPlausibilityGuard — POST-LUFS-Rescue Fangschicht
        # WPG ran once after MDEM/correct_arc (§2.30c, line ~8064). The End-of-Pipeline
        # LUFS rescue can introduce new positive gain on carrier-noise intro/outro frames
        # (vinyl -33 dBFS surface noise misclassified as music by sample-P5-based gate).
        # This second WPG call catches post-rescue Pegelexplosionen before MUSHRA re-eval.
        try:
            from backend.core.emotional_arc_preservation import (
                apply_waveform_plausibility_guard as _wpg_fn2,
            )

            _wpg2_mode = str(getattr(getattr(self.config, "mode", None), "value", "restoration")).lower()
            _wpg2_mat = str(_gp_material_key or "unknown").lower().split("_", maxsplit=1)[0]
            _wpg2_out, _wpg2_meta = _wpg_fn2(
                original_audio_for_goals,
                restored_audio,
                sample_rate,
                mode=_wpg2_mode,
                material_type=_wpg2_mat,
                restorability_score=float(_pmgg_restorability_score),
            )
            if _wpg2_meta.get("corrections_applied", 0) > 0:
                restored_audio = _wpg2_out
                logger.info(
                    "§2.30c-II WPG post-LUFS-Rescue: %d corrections applied (material=%s)",
                    int(_wpg2_meta["corrections_applied"]),
                    _wpg2_mat,
                )
            else:
                logger.debug("§2.30c-II WPG post-LUFS-Rescue: kein Eingriff nötig")
        except Exception as _wpg2_exc:
            logger.debug("§2.30c-II WPG post-LUFS-Rescue nicht verfügbar (non-blocking): %s", _wpg2_exc)

        # §8.1 [RELEASE_MUST] MUSHRA-Neubewertung mit LUFS-aligniertem Audio.
        # Die initiale MUSHRA-Messung in _collect_reporting_analytics (oben) wird mit
        # dem unaligniertem Audio durchgeführt — LUFS-Δ=10 LU verfälscht OQS um ~15 Punkte.
        # Hier wird MUSHRA mit dem final korrigierten restored_audio überschrieben, damit
        # der OQS-Score das tatsächliche Hörerlebnis wiedergibt (global, song-unabhängig).
        try:
            from backend.core.mushra_evaluator import get_mushra_evaluator as _get_mushra_late

            _mushra_eval_late = _get_mushra_late()
            # Referenz: original_audio_for_goals (identisch zum §2.45a-Alignment-Ziel)
            _ref_src_late = original_audio_for_goals
            _orig_m_late = _ref_src_late if _ref_src_late.ndim == 1 else _ref_src_late.mean(axis=0)
            _rest_m_late = restored_audio if restored_audio.ndim == 1 else restored_audio.mean(axis=0)
            _mushra_late = _mushra_eval_late.evaluate(
                reference=_orig_m_late,
                test=_rest_m_late,
                sr=sample_rate,
                compute_anchor=True,
            )
            _analytics_meta["mushra"] = {
                "mushra_score": round(_mushra_late.mushra_score, 1),
                "grade": _mushra_late.grade,
                "itu_grade": _mushra_late.itu_grade,
                "anchor_score": round(_mushra_late.anchor_score, 1),
                "nsim": round(_mushra_late.nsim, 4),
                "details": _mushra_late.details,
            }
            logger.info(
                "📊 MUSHRA (post-LUFS-alignment): OQS=%.1f grade=%s anchor=%.1f",
                _mushra_late.mushra_score,
                _mushra_late.grade,
                _mushra_late.anchor_score,
            )
        except Exception as _mushra_late_exc:
            logger.debug("MUSHRA post-LUFS re-eval übersprungen: %s", _mushra_late_exc)

        # §2.63 [RELEASE_MUST] Final soft peak limiter — letzte Fangschicht nach LUFS-Rescue
        # und WPG, direkt vor RestorationResult. Verhindert hartes Clipping im Export.
        # Warum hier: _execute_pipeline hat einen TruePeak-Guard, aber die LUFS-Rescue und
        # WPG post-rescue laufen danach in denke()/restore() und können neuen Gain aufbauen.
        # 99.9th-percentile statt np.max(): Impulsartefakte dürfen das Ceiling nicht dominieren.
        try:
            _final_pk = float(np.percentile(np.abs(restored_audio), 99.9))
            if math.isfinite(_final_pk) and _final_pk > 0.98:
                restored_audio = np.asarray(restored_audio * float(0.98 / max(_final_pk, 1e-9)), dtype=np.float32)
                logger.info(
                    "§2.63 Final soft peak limiter: p99.9=%.4f > 0.98 → rescaled to 0.98 (factor=%.4f)",
                    _final_pk,
                    float(0.98 / max(_final_pk, 1e-9)),
                )
        except Exception as _fpl_exc:
            logger.debug("§2.63 Final soft peak limiter failed (non-blocking): %s", _fpl_exc)

        try:
            _final_quiet_material = str(_gp_material_key or "unknown").lower().split("_", maxsplit=1)[0]
            _pre_final_quiet = np.asarray(restored_audio, dtype=np.float32)
            restored_audio = UnifiedRestorerV3._apply_final_quiet_edge_clamp(
                original_audio_for_goals,
                restored_audio,
                sample_rate,
                material_key=_final_quiet_material,
                max_edge_boost_db=0.5,  # §0h: 0.5 dB tolerance — tighter than default 2.0
            )
            if not np.allclose(_pre_final_quiet, restored_audio, atol=1e-6):
                logger.info(
                    "§2.45a Final quiet-edge clamp applied before RestorationResult (material=%s, tolerance=0.5 dB)",
                    _final_quiet_material,
                )
        except Exception as _final_quiet_exc:
            logger.debug("§2.45a Final quiet-edge clamp skipped (non-blocking): %s", _final_quiet_exc)

        _phase_meta_acc = getattr(self, "_phase_metadata_accumulator", {})
        result = RestorationResult(
            audio=restored_audio,
            config=self.config,
            material_type=material_type,
            defect_scores=_result_defect_scores,
            phases_executed=executed_phases,
            phases_skipped=skipped_phases,
            deferred_phases=deferred_phases,  # §2.38 KMV: RT-skipped phases for Stage 2
            total_time_seconds=total_time,
            rt_factor=rt_factor,
            quality_estimate=quality_estimate,
            warnings=perf_report.warnings if perf_report is not None else [],
            metadata={
                # Audit/Bridge compatibility: expose core context at top-level.
                "primary_material": material_type.value,
                "transfer_chain": list(_cal_transfer_chain) if _cal_transfer_chain else [],
                "restorability_score": float(_pmgg_restorability_score),
                "fail_reasons": list(_fail_reasons),
                "degradation_status": _degradation_status,
                "fail_reason": _primary_fail_reason,
                "ml_guard_events": list(getattr(self, "_pipeline_ml_guard_events", [])),
                "ml_fallbacks_used": list(getattr(self, "_ml_fallbacks_used", [])),  # §2.47 [RELEASE_MUST]
                "material_defect_consistency_warnings": list(
                    getattr(self, "_material_defect_consistency_warnings", [])
                ),  # §2.47 Cross-Check Material-Erkennung ↔ Defektprofil
                "fallback_quality_floor": _fallback_quality_floor,
                # §2.64 Per-Phase Goal-Deltas (DSP-proxy, non-blocking)
                "phase_deltas": dict(getattr(self, "_phase_deltas", {})),
                # §2.65 MAS convergence marker
                "mas_achieved_at_phase": (self._phase_metadata_accumulator or {}).get("mas_achieved_at_phase"),
                "mas_gaps_at_convergence": (self._phase_metadata_accumulator or {}).get("mas_gaps_at_convergence"),
                # §2.35c VQI — Gesangs-Qualitäts-Gate (nur gesetzt wenn singing_conf >= 0.35)
                "vqi": (self._phase_metadata_accumulator or {}).get("vqi"),
                "singer_identity_cosine": (self._phase_metadata_accumulator or {}).get("singer_identity_cosine"),
                "singer_id_dsp_fallback": (self._phase_metadata_accumulator or {}).get("singer_id_dsp_fallback"),
                "vqi_tier": (self._phase_metadata_accumulator or {}).get("vqi_tier"),
                "quality_estimate": {
                    "value": float(quality_estimate),
                    "fallback_quality_estimate": bool(self._quality_estimate_used_fallback),
                    "source": str(self._quality_estimate_source),
                },
                "deployment": {
                    "mode": getattr(self.config.deployment_mode, "value", "product"),
                    "blocked_experimental_features": sorted(self._blocked_experimental_features),
                },
                "defect_analysis": {
                    "material": material_type.value,
                    "analysis_time": defect_result.analysis_time_seconds,
                    "top_defects": _top_defects_pre,
                    "post_restoration_top_defects": (
                        [
                            {"type": s.defect_type.value, "severity": s.severity}
                            for s in _post_defect_result.get_top_defects(5)
                        ]
                        if _post_defect_result is not None
                        else None
                    ),
                    "causal_plan": {
                        "primary_cause": _causal_plan.primary_cause if _causal_plan else None,
                        "confidence": round(_causal_plan.confidence, 4) if _causal_plan else None,
                        "top_causes": [
                            {"cause": c, "probability": round(p, 4)}
                            for c, p in (_causal_plan.ranked_causes[:3] if _causal_plan else [])
                        ],
                    },
                },
                "performance": {
                    "status": perf_report.status.value if perf_report is not None else "unknown",
                    "rt_factor": rt_factor,
                    "quality_degradation": perf_report.quality_degradation if perf_report is not None else 0.0,
                },
                "sample_rate": {"input": original_sample_rate, "processing": sample_rate, "output": sample_rate},
                "era": {
                    "decade": _era_result.decade if _era_result else None,
                    "era_label": _era_result.era_label if _era_result else None,
                    "material_prior": _era_result.material_prior if _era_result else None,
                    "confidence": round(_era_result.confidence, 4) if _era_result else None,
                },
                "genre": (
                    {
                        "is_schlager": _schlager_result.is_schlager,
                        "confidence": round(_schlager_result.confidence, 4),
                        "genre_label": _schlager_result.genre_label,
                        "subgenre": _schlager_result.subgenre,
                        "bpm": round(_schlager_result.bpm, 1),
                        "key": _schlager_result.key,
                        "accordion_score": round(_schlager_result.accordion_score, 4),
                        "harmonic_simplicity": round(_schlager_result.harmonic_simplicity, 4),
                        "rhythm_score": round(_schlager_result.rhythm_score, 4),
                        "melodic_repetition": round(_schlager_result.melodic_repetition, 4),
                    }
                    if _schlager_result is not None
                    else None
                ),
                "pipeline_confidence": {
                    "tier": _pipeline_confidence.tier if _pipeline_confidence else None,
                    "confidence": round(_pipeline_confidence.confidence, 4) if _pipeline_confidence else None,
                    "gp_bound_factor": round(_pipeline_confidence.gp_bound_factor, 4) if _pipeline_confidence else None,
                    "user_hint": _pipeline_confidence.user_hint if _pipeline_confidence else None,
                },
                "song_calibration": _song_calibration_meta,
                "strict_phase_goal_conflict_report": _strict_conflict_report,
                "joy_runtime_index": _joy_runtime_index,
                "auto_improvement_recommendations": _auto_improvement,
                "musical_goals": {
                    "scores": {k: round(float(v), 4) for k, v in _musical_goal_scores.items()},
                    "thresholds": {k: round(float(v), 4) for k, v in _effective_goal_thresholds.items()},
                    "passed": _musical_goals_passed,
                    "excellence_score": round(_musical_excellence_score, 4),
                    "all_passed": all(_musical_goals_passed.values()) if _musical_goals_passed else None,
                    "violations": [k for k, p in _musical_goals_passed.items() if not p],
                },
                # §0d + §2.54: ceiling-capped adaptive thresholds (material/era/genre adjusted).
                # Bridge/debug compatibility: also available at top-level as "adaptive_goal_thresholds".
                "adaptive_goal_thresholds": {
                    k: round(float(v), 4)
                    for k, v in (
                        getattr(self, "_pmgg_ceiling_capped_targets", None) or _effective_goal_thresholds
                    ).items()
                },
                # §Punkt3 Phasen-Regressionsprotokoll: RMS-Änderung (dBFS) je Phase
                # Negativ = Energie reduziert (z.B. Denoise). Positiv = Energie gestiegen.
                # Nur sequentielle Phasen; parallele Phasen sind nicht kausal einzeln messbar.
                "phase_regression_log": dict(getattr(self, "_phase_regression_log", {})),
                "phase_regression_top_drops": sorted(
                    [
                        {"phase_id": _pid, "rms_delta_db": float(_delta)}
                        for _pid, _delta in dict(getattr(self, "_phase_regression_log", {})).items()
                        if float(_delta) < -0.5
                    ],
                    key=lambda x: x["rms_delta_db"],
                )[:10],
                # §7 PDV: Phase Defect Verifier session summary (Ursache 7 telemetry).
                "phase_defect_verification": _pdv_session_summary,
                "active_interventions": {
                    "count": len(getattr(self, "_active_intervention_log", [])),
                    "accepted_count": sum(
                        1
                        for _ev in list(getattr(self, "_active_intervention_log", []))
                        if isinstance(_ev, dict) and bool(_ev.get("accepted", False))
                    ),
                    "rejected_count": sum(
                        1
                        for _ev in list(getattr(self, "_active_intervention_log", []))
                        if isinstance(_ev, dict) and not bool(_ev.get("accepted", False))
                    ),
                    "events": list(getattr(self, "_active_intervention_log", [])),
                },
                "phase_plan_intelligence": dict(getattr(self, "_phase_plan_intelligence", None) or {}),
                "excellence_optimizer": (
                    {
                        "applied_steps": _excellence_result.applied_steps,
                        "delta_rms_db": round(_excellence_result.delta_rms_db, 3),
                        "continuity": _excellence_result.continuity_smoothing_applied,
                        "micro_dynamics": _excellence_result.micro_dynamic_injected,
                        "harmonic_boost_db": round(_excellence_result.harmonic_reinforcement_db, 3),
                        "ola_crossfades": _excellence_result.ola_crossfades,
                    }
                    if _excellence_result is not None
                    else None
                ),
                "harmonic_lattice": (_lattice_result.as_dict() if _lattice_result is not None else None),
                "pqs": (dataclasses.asdict(_pqs_result) if _pqs_result is not None else None),
                "feedback_chain": (
                    {
                        "overall_score": round(_fc_chain_result.overall_score, 4),
                        "total_retries": _fc_chain_result.total_retries,
                        "total_time_s": round(_fc_chain_result.total_time_s, 3),
                        "n_phases": len(_fc_chain_result.phase_executions),
                        "ceiling_reached": bool(_fc_chain_result.ceiling_reached),
                    }
                    if _fc_chain_result is not None
                    else None
                ),
                "segment_adaptive": (_sap_result.as_dict() if _sap_result is not None else None),
                "goosebumps": (
                    {
                        "score": _goosebumps_result.goosebumps_score,
                        "transient_integrity": _goosebumps_result.transient_integrity,
                        "micro_dynamics": _goosebumps_result.micro_dynamics,
                        "clarity": _goosebumps_result.clarity,
                        "authenticity": _goosebumps_result.authenticity,
                        "artifact_penalty": _goosebumps_result.artifact_penalty,
                    }
                    if _goosebumps_result is not None
                    else None
                ),
                # §2.49 Artifact Freedom Gate
                "artifact_freedom": {
                    "score": getattr(self, "_artifact_freedom_score", 1.0),
                    "detail": getattr(self, "_artifact_freedom_detail", {}),
                    "passed": getattr(self, "_artifact_freedom_score", 1.0) >= 0.95,
                },
                # §2.51a Stereo-Hörsicherheitsprofil
                "stereo_safety_guard": _stereo_safety_guard,
                # §0d [RELEASE_MUST] Carrier-Chain-Recovery (Pflichtfeld)
                "carrier_chain_recovery_ratio": getattr(self, "_carrier_chain_recovery_ratio", 0.0),
                "carrier_chain_recovery": {
                    "ratio": getattr(self, "_carrier_chain_recovery_ratio", 0.0),
                    "last_carrier_phase": getattr(self, "_last_carrier_phase_id", None),
                    "reference_shifted": getattr(self, "_carrier_chain_recovery_ratio", 0.0)
                    > (
                        0.05
                        if str(getattr(material_type, "value", material_type) or "unknown").lower()
                        in {
                            "vinyl",
                            "shellac",
                            "reel_tape",
                            "tape",
                            "cassette",
                            "wax_cylinder",
                            "wire_recording",
                            "minidisc",
                        }
                        else 0.15
                    ),
                },
                # §4.7 Noise-Texture-Coherence
                "noise_texture_coherence": (
                    {
                        "coherence": round(_noise_texture_result.coherence, 4),
                        "is_compliant": _noise_texture_result.is_compliant,
                        "material": _noise_texture_result.material_type,
                        "reference_slope": round(_noise_texture_result.reference_slope, 4),
                        "measured_slope": round(_noise_texture_result.measured_slope, 4),
                    }
                    if _noise_texture_result is not None
                    else None
                ),
                # §2.50 Source Material Baseline
                "source_material_baseline": {
                    "phase_cancellation_ratio": getattr(
                        getattr(self, "_source_material_baseline", None), "phase_cancellation_ratio", None
                    ),
                    "interchannel_lag_samples": getattr(
                        getattr(self, "_source_material_baseline", None), "interchannel_lag_samples", None
                    ),
                    "stereo_mono_compat_mean": getattr(
                        getattr(self, "_source_material_baseline", None), "stereo_mono_compat_mean", None
                    ),
                    "has_critical_stereo_issue": getattr(
                        getattr(self, "_source_material_baseline", None), "has_critical_stereo_issue", None
                    ),
                    "has_anti_phase_region": getattr(
                        getattr(self, "_source_material_baseline", None), "has_anti_phase_region", None
                    ),
                    "hf_loss_db": getattr(getattr(self, "_source_material_baseline", None), "hf_loss_db", None),
                },
                "recovery_certainty": {
                    "recoverability_ceiling": float(
                        np.clip(
                            getattr(self, "_recovery_certainty_profile", {}).get("recoverability_ceiling", 0.65),
                            0.0,
                            1.0,
                        )
                    ),
                    "uncertainty_index": float(
                        np.clip(
                            getattr(self, "_recovery_certainty_profile", {}).get("uncertainty_index", 0.35),
                            0.0,
                            1.0,
                        )
                    ),
                    "conservative_audio_scalar": float(
                        np.clip(
                            getattr(self, "_recovery_certainty_profile", {}).get("conservative_audio_scalar", 0.92),
                            0.0,
                            1.0,
                        )
                    ),
                    "confidence_band": str(
                        getattr(self, "_recovery_certainty_profile", {}).get("confidence_band", "medium")
                    ),
                    "restorability_score": float(
                        getattr(self, "_recovery_certainty_profile", {}).get(
                            "restorability_score", getattr(self, "_last_restorability_score", 65.0)
                        )
                    ),
                    "transfer_generation_count": int(
                        getattr(self, "_recovery_certainty_profile", {}).get("transfer_generation_count", 1)
                    ),
                    "hf_loss_db": getattr(self, "_recovery_certainty_profile", {}).get("hf_loss_db", None),
                },
                # §0/§2.46 HF-Hallucination-Guard: aggregate per-phase guard events.
                "hf_hallucination_guard": {
                    "guard_fired_count": sum(1 for d in _phase_meta_acc.values() if d.get("hf_hallucination_detected")),
                    "phases_guarded": [pid for pid, d in _phase_meta_acc.items() if d.get("hf_hallucination_detected")],
                    "max_delta_ratio": max(
                        (
                            d.get("hf_delta_ratio", 0.0)
                            for d in _phase_meta_acc.values()
                            if d.get("hf_hallucination_detected")
                        ),
                        default=0.0,
                    ),
                    "min_cap_hz": (
                        min(
                            (
                                d.get("hf_cap_hz", 24000.0)
                                for d in _phase_meta_acc.values()
                                if d.get("hf_hallucination_detected")
                            ),
                            default=None,
                        )
                        if any(d.get("hf_hallucination_detected") for d in _phase_meta_acc.values())
                        else None
                    ),
                },
                # §2.46b Spectral Tilt Drift Guard: aggregate per-phase tilt-protection events.
                "spectral_tilt_guard": {
                    "guard_fired_count": sum(1 for d in _phase_meta_acc.values() if d.get("tilt_guard_fired")),
                    "phases_guarded": [pid for pid, d in _phase_meta_acc.items() if d.get("tilt_guard_fired")],
                    "max_deviation_db_per_oct": max(
                        (
                            d.get("tilt_deviation_db_per_oct", 0.0)
                            for d in _phase_meta_acc.values()
                            if d.get("tilt_guard_fired")
                        ),
                        default=0.0,
                    ),
                    "max_wet_cap_applied": max(
                        (
                            d.get("tilt_wet_cap_applied", 0.0)
                            for d in _phase_meta_acc.values()
                            if d.get("tilt_guard_fired")
                        ),
                        default=0.0,
                    ),
                },
                # §2.44 Holistic Perceptual Gate
                "holistic_perceptual_gate": (
                    {
                        "hpi": _hpi_result.hpi,
                        "passed": _hpi_result.passed,
                        "mert_similarity": _hpi_result.mert_similarity,
                        "timbral_fidelity": _hpi_result.timbral_fidelity,
                        "artifact_freedom": _hpi_result.artifact_freedom,
                        "emotional_arc_preservation": _hpi_result.emotional_arc_preservation,
                        "is_studio_mode": _hpi_result.is_studio_mode,
                        # §2.44 VERBOTEN-Tabelle: True wenn VERSA nicht verfügbar → MERT als Proxy
                        "mert_proxy_used": _hpi_result.detail.get("mert_proxy_used", False),
                    }
                    if _hpi_result is not None
                    else None
                ),
                # §2.48 Interaction Guard
                "interaction_guard": getattr(self, "_interaction_guard_metadata", {}),
                # §2.29e Team-Coordination Telemetrie (§2.53 RELEASE_MUST)
                "team_coordination": {
                    "event_count": len(getattr(self, "_team_coordination_events", []) or []),
                    "events": list(getattr(self, "_team_coordination_events", []) or []),
                    "phase_type_summary": dict(
                        (getattr(self, "_phase_team_context", None) or {}).get("phase_type_counts", {}) or {}
                    ),
                },
                # §2.47b JND Sub-Threshold Phase Telemetrie (RELEASE_MUST)
                # Phasen, bei denen alle Goal-Deltas ≥ 0 aber < JND — kein Retry, akzeptiert.
                # Aggregiert aus allen PMGG-Log-Einträgen, dedupliziert und sortiert.
                "sub_threshold_phases": sorted(
                    {
                        _st_pid
                        for _pmgg_e in (getattr(self, "_pmgg_log_entries", []) or [])
                        for _st_pid in (
                            (
                                isinstance(getattr(_pmgg_e, "metadata", None), dict)
                                and getattr(_pmgg_e, "metadata", {}).get("sub_threshold_phases", [])
                            )
                            or []
                        )
                    }
                ),
                # §2.56 Song-Goal-Importance: per-song goal weights
                "goal_importance": (
                    {
                        "weights": dict(self._song_goal_importance.weights),
                        "genre_profile": self._song_goal_importance.genre_profile,
                        "era_profile": self._song_goal_importance.era_profile,
                        "material_profile": self._song_goal_importance.material_profile,
                        "vocal_detected": self._song_goal_importance.vocal_detected,
                        "reason": self._song_goal_importance.reason,
                    }
                    if getattr(self, "_song_goal_importance", None) is not None
                    else None
                ),
                "goal_recovery": locals().get("_goal_recovery_meta", {"attempted": False}),
                **_analytics_meta,
                # §0c Graceful-Stop Telemetrie: transparenter Status für UI + Tests
                "graceful_stop": _graceful_stop_triggered,
                "graceful_stop_phases_executed": len(executed_phases) if _graceful_stop_triggered else None,
                "graceful_stop_phases_skipped": len(skipped_phases) if _graceful_stop_triggered else None,
            },
            # --- Spec §2.1/§2.2 Pflichtfelder ---
            pqs_result=_pqs_result,
            musical_goals=_musical_goal_scores if _musical_goal_scores else None,
            excellence=_excellence_result,
            adaptive_thresholds=locals().get("_effective_goal_thresholds", {}),
            physical_ceiling=(dict(getattr(_physical_ceiling, "ceiling", {})) if _physical_ceiling is not None else {}),
            goal_applicability=(
                {
                    g: (g in (frozenset(getattr(_goal_applicability_result, "applicable", ()) or ())))
                    for g in (frozenset(getattr(_goal_applicability_result, "applicable", ()) or ())).union(
                        frozenset(getattr(_goal_applicability_result, "inapplicable", ()) or ())
                    )
                }
                if _goal_applicability_result is not None
                else {}
            ),
            goal_priority_log=(
                list(_fc_chain_result.metadata.get("goal_priority_log", [])) if _fc_chain_result is not None else []
            )
            + (
                [f"Post-pipeline GPP: {_goal_abort.reason}"]
                if _goal_abort is not None and _goal_abort.should_abort
                else []
            ),
            confidence=(float(_pipeline_confidence.confidence) if _pipeline_confidence is not None else 1.0),
            chroma_correlation=_chroma_corr_for_result,
            lufs_delta=_lufs_delta_for_result,
            goosebumps_score=_goosebumps_score,
            goosebumps_result=_goosebumps_result,
            # §2.2 era_decade: UV3-authoritative result — propagated to frontend via
            # _on_item_finished_with_result (modern_window.py L11133) to override the
            # pre-analysis estimate from _detect_era_genre_bg.
            era_decade=(_era_result.decade if _era_result is not None else None),
        )

        # §2.13 Künstler-Signatur nach Restaurierung aktualisieren und speichern
        if _artist_id is not None:
            try:
                from backend.core.artist_signature_store import (
                    VoiceCharacteristics as _VoiceCharacteristics,
                )
                from backend.core.artist_signature_store import (
                    get_signature_store as _get_sig_store2,
                )

                _sig_store2 = _get_sig_store2()
                # Minimale VoiceCharacteristics: Spektral-Hüllkurve aus restauriertem Audio
                _env_audio = (
                    np.mean(restored_audio, axis=0).astype(np.float32)
                    if restored_audio.ndim == 2
                    else restored_audio.astype(np.float32)
                )
                _n_env = min(512, len(_env_audio))
                _spec = np.abs(np.fft.rfft(_env_audio[:_n_env], n=_n_env)).astype(np.float32)
                _x_src = np.linspace(0, 1, len(_spec), dtype=np.float32)
                _x_dst = np.linspace(0, 1, 128, dtype=np.float32)
                _envelope = np.interp(_x_dst, _x_src, _spec).astype(np.float32)
                _env_norm = float(np.linalg.norm(_envelope))
                if _env_norm > 0:
                    _envelope /= _env_norm
                _vc = _VoiceCharacteristics(spectral_envelope=_envelope)
                _updated_sig = _sig_store2.update_from_analysis(_artist_id, _vc)
                _sig_store2.save(_updated_sig)
                logger.debug(
                    "Künstler-Signatur gespeichert: artist_id=%s | n=%d | confidence=%.2f",
                    _artist_id,
                    _updated_sig.n_files_analyzed,
                    _updated_sig.confidence,
                )
            except Exception as _sig_upd_exc:
                logger.debug("ArtistSignatureStore Update nicht verfügbar: %s", _sig_upd_exc)

        logger.info(
            "✅ Restoration complete: %.1fs (%.2f× RT), Quality: %.1f%%",
            total_time,
            rt_factor,
            quality_estimate * 100,
        )

        # --- Aggressive end-of-run memory cleanup (OOM hardening) ---
        _cleanup_report: dict[str, Any] = {"unloaded": [], "errors": []}
        try:
            _unload_specs = [
                ("plugins.audiosr_plugin", "unload_audiosr", "AudioSR"),
                ("plugins.utmos_plugin", "unload_utmos", "UTMOS"),
                ("plugins.laion_clap_plugin", "unload_laion_clap", "LAION-CLAP"),
                ("plugins.mert_plugin", "unload_mert", "MERT"),
                # CREPE: keep singleton alive (cache + ONNX session) — ExzellenzDenker
                # re-uses CREPE right after UV3 finishes.  PLM handles LRU eviction.
                ("plugins.fcpe_plugin", "unload_fcpe", "FCPE"),
                ("plugins.basicpitch_plugin", "unload_basicpitch", "BasicPitch"),
            ]
            for _mod_name, _fn_name, _label in _unload_specs:
                try:
                    _mod = importlib.import_module(_mod_name)
                    _fn = getattr(_mod, _fn_name, None)
                    if callable(_fn):
                        _fn()
                        _cleanup_report["unloaded"].append(_label)
                except Exception as _u_exc:
                    _cleanup_report["errors"].append(f"{_label}: {_u_exc}")

            try:
                from backend.core.plugin_lifecycle_manager import (
                    cleanup_after_file as _plm_cleanup_after_file,
                )

                _cleanup_report["plm_evicted"] = int(_plm_cleanup_after_file())
            except Exception as _plm_exc:
                _cleanup_report["errors"].append(f"PLM: {_plm_exc}")

            # Defensive budget release for models without explicit unload hooks.
            try:
                from backend.core.ml_memory_budget import release as _ml_release

                for _model_name in ("CREPE", "FCPE", "RMVPE", "BasicPitch"):
                    _ml_release(_model_name)
            except Exception as _ml_rel_exc:
                _cleanup_report["errors"].append(f"ML-Budget-Release: {_ml_rel_exc}")

            gc.collect()

            # Linux/glibc: return free heap pages to OS to reduce RSS between runs.
            try:
                import ctypes

                _libc = ctypes.CDLL("libc.so.6")
                _trim = getattr(_libc, "malloc_trim", None)
                if callable(_trim):
                    _cleanup_report["malloc_trim"] = bool(_trim(0))
            except Exception as _trim_exc:
                _cleanup_report["errors"].append(f"malloc_trim: {_trim_exc}")
        except Exception as _cleanup_exc:
            logger.debug("Final memory cleanup failed: %s", _cleanup_exc)
        finally:
            with contextlib.suppress(Exception):
                result.metadata["memory_cleanup"] = _cleanup_report

        # §8.2 / §2.16 / §2.29 — Spec-Felder in RestorationResult schreiben
        result.emotional_arc = _arc_result
        # §8.2 v9.10.79 Emotionale Psychoakustik: Makro-Dynamik-Korrektur Status speichern
        if _arc_result is not None:
            try:
                _post_mdem = locals().get("_arc_post_mdem")
                _a_final = float(getattr(_arc_result, "arousal_pearson", 0.0))
                _v_final = float(getattr(_arc_result, "valence_pearson", 0.0))
                _a_base = (
                    float(getattr(_post_mdem, "arousal_pearson", _a_final)) if _post_mdem is not None else _a_final
                )
                _v_base = (
                    float(getattr(_post_mdem, "valence_pearson", _v_final)) if _post_mdem is not None else _v_final
                )

                result.emotional_arc_correction_applied = bool(
                    _post_mdem is not None and not getattr(_post_mdem, "arc_preserved", True)
                )
                result.emotional_arc_delta_arousal = _a_final - _a_base
                result.emotional_arc_delta_valence = _v_final - _v_base
            except Exception as _exc:
                logger.debug("Emotional arc field extraction failed: %s", _exc)
        result.temporal_coherence = _tqc
        # §2.29 PMGG-Log: Phasen wo best-effort angewendet wurde (reduzierte Stärke, kein Skip)
        try:
            _phase_gate_entries = getattr(self, "_pmgg_log_entries", [])
            result.phase_gate_log = [
                e.phase_id for e in _phase_gate_entries if getattr(e, "action", "").startswith("best_effort")
            ]
        except Exception:
            result.phase_gate_log = []

        # §DEBUG: Vollständige PMGG-Log-Einträge (mit scores_before/after) in metadata schreiben.
        # Aktiviert durch enable_debug_trace=True im restore()-Aufruf.
        # Dient als Datenquelle für pipeline_trace.build_from_result() und aurik-debug CLI.
        if self._debug_trace_enabled:
            try:
                import dataclasses as _dc

                _all_entries = getattr(self, "_pmgg_log_entries", [])
                result.metadata["pmgg_log_entries"] = [_dc.asdict(e) for e in _all_entries if hasattr(e, "phase_id")]
            except Exception as _dte:
                logger.debug("Debug-Trace konnte nicht serialisiert werden: %s", _dte)

        return result

    def restore_from_checkpoint(
        self,
        checkpoint: "RecoveryCheckpoint",
        progress_callback=None,
        **kwargs,
    ) -> "RestorationResult":
        """§2.39 OOM-Recovery: Resume restoration from a persisted checkpoint.

        Loads the intermediate audio from disk, reconstructs cached analysis
        results, and re-enters ``_execute_pipeline`` with only the remaining
        phases.  After successful completion the checkpoint is deleted.

        Args:
            checkpoint: A ``RecoveryCheckpoint`` from ``find_pending_checkpoints()``.
            progress_callback: Optional progress callback (pct, phase, elapsed_s).
            **kwargs: Forwarded to ``restore()`` / ``_execute_pipeline()``.

        Returns:
            Full ``RestorationResult`` — equivalent to a non-interrupted run.
        """
        from backend.core.recovery_checkpoint import (
            delete_checkpoint,
            load_checkpoint_audio,
        )

        logger.info(
            "§2.39 OOM-Recovery: Wiederaufnahme von Checkpoint — %d abgeschlossene, %d verbleibende Phasen. "
            "Fehlgeschlagene Phase: %s",
            len(checkpoint.phases_executed),
            len(checkpoint.phases_remaining),
            checkpoint.failure_phase,
        )

        # Mode mapping: checkpoint mode strings → restore() mode strings
        _mode_map = {
            "quality": "restoration",
            "maximum": "studio_2026",
        }

        # 1. Load intermediate audio from disk
        current_audio = load_checkpoint_audio(checkpoint)
        if current_audio is None:
            logger.error(
                "§2.39 OOM-Recovery: Checkpoint-Audio konnte nicht geladen werden. "
                "Fallback: Neue Restaurierung starten (Original-Datei)"
            )
            # Fallback: Restart restoration from original file instead of aborting
            # This loses ~10% optimization (prior phase cache) but preserves job
            result = self.restore(
                input_path=checkpoint.original_input_path,
                output_path=checkpoint.output_path,
                mode=_mode_map.get(checkpoint.mode, checkpoint.mode),
                progress_callback=progress_callback,
                **kwargs,
            )
            # After successful fallback, delete the corrupted checkpoint
            delete_checkpoint(checkpoint.input_path)
            return result

        # soundfile returns (N,2) for stereo — UV3 expects (2,N) channel-first
        if current_audio.ndim == 2 and current_audio.shape[1] == 2:
            current_audio = current_audio.T

        sr = checkpoint.sample_rate

        # 2. Restore via normal pipeline with remaining phases
        #    Pass cached analysis results to avoid re-scanning.
        mode_str = _mode_map.get(checkpoint.mode, checkpoint.mode)

        result = self.restore(
            current_audio,
            sample_rate=sr,
            progress_callback=progress_callback,
            mode=mode_str,
            input_path=checkpoint.input_path,
            output_path=checkpoint.output_path,
            **kwargs,
        )

        # 3. Merge executed phases from checkpoint + new run
        _prev_executed = list(checkpoint.phases_executed)
        result.phases_executed = _prev_executed + result.phases_executed
        result.metadata["oom_recovery"] = {
            "resumed_from_checkpoint": True,
            "checkpoint_phases_executed": len(_prev_executed),
            "failure_phase": checkpoint.failure_phase,
            "checkpoint_timestamp": checkpoint.timestamp,
        }

        # 4. Cleanup checkpoint after success
        try:
            delete_checkpoint(checkpoint.input_path)
            logger.info("§2.39 OOM-Recovery: Checkpoint gelöscht nach erfolgreicher Wiederaufnahme.")
        except Exception as _del_exc:
            logger.warning("OOM-Recovery: Checkpoint-Löschung fehlgeschlagen: %s", _del_exc)

        return result

    def _compute_enhanced_metrics_result(
        self,
        restored_audio: "np.ndarray",
        original_audio_for_goals: "np.ndarray",
        sample_rate: int,
    ) -> dict | None:
        """Compute v9.10.20 EnhancedMetrics payload for reporting metadata."""
        try:
            from backend.core.enhanced_metrics import EnhancedMetrics as _EnhMetrics

            _em_audio = restored_audio
            _em_ref = original_audio_for_goals if original_audio_for_goals is not None else None
            if _em_ref is not None:
                _em_r = _EnhMetrics().compute_all(
                    _em_ref.astype(np.float32),
                    _em_audio.astype(np.float32),
                    sr=sample_rate,
                )
                _em_result = {
                    "snr_db": round(float(_em_r.snr_db), 3),
                    "thd": round(float(_em_r.thd), 6),
                    "lufs": round(float(_em_r.lufs), 3),
                    # si_sdr_db removed — forbidden §4.4+§10.2 (speech metric)
                    # si_snr_db removed — forbidden §4.4+§10.2 (speech metric)
                    "snr_improvement_db": (
                        round(float(_em_r.snr_improvement_db), 3) if _em_r.snr_improvement_db is not None else None
                    ),
                    "passes_aurik_standards": bool(_em_r.passes_aurik_standards()),
                }
            else:
                _em_mono = np.mean(_em_audio, axis=0) if _em_audio.ndim == 2 else _em_audio
                _em_result = {
                    "snr_db": round(float(_EnhMetrics.compute_snr(_em_mono.astype(np.float32), sample_rate)), 3),
                    "thd": round(float(_EnhMetrics.compute_thd(_em_mono.astype(np.float32), sample_rate)), 6),
                    "lufs": round(float(_EnhMetrics.compute_lufs(_em_mono.astype(np.float32), sample_rate)), 3),
                }
            logger.debug("📊 EnhancedMetrics: %s", _em_result)
            return _em_result
        except Exception as _em_exc:
            logger.debug("EnhancedMetrics nicht verfügbar: %s", _em_exc)
            return None

    def _compute_comprehensive_metrics_result(
        self,
        restored_audio: "np.ndarray",
        original_audio_for_goals: "np.ndarray",
        sample_rate: int,
    ) -> dict | None:
        """Compute v9.10.19 ComprehensiveMetrics payload for reporting metadata."""
        try:
            from backend.core.comprehensive_metrics import ComprehensiveMetricsCalculator as _CMC

            _cm_audio = restored_audio
            _cm_ref = original_audio_for_goals if original_audio_for_goals is not None else None
            _cm_r = _CMC(sample_rate=sample_rate).compute_all(_cm_audio, reference=_cm_ref)
            _cm_result = {
                "overall_technical_quality": round(float(_cm_r.overall_technical_quality), 4),
                "overall_musical_quality": round(float(_cm_r.overall_musical_quality), 4),
                "overall_emotional_impact": round(float(_cm_r.overall_emotional_impact), 4),
                "aurik_quality_score": round(float(_cm_r.aurik_quality_score), 2),
                "passes_aurik_standards": _cm_r.passes_aurik_standards(),
            }
            logger.debug("📈 ComprehensiveMetrics: %s", _cm_result)
            return _cm_result
        except Exception as _cm_exc:
            logger.debug("ComprehensiveMetrics nicht verfügbar: %s", _cm_exc)
            return None

    def _compute_vocal_characteristics_result(
        self,
        restored_audio: "np.ndarray",
        sample_rate: int,
    ) -> dict | None:
        """Compute v9.10.20 VocalCharacteristics payload for reporting metadata."""
        try:
            from backend.core.vocal_ai_enhancement import GenderDetector as _GenderDetector

            _vc_audio = restored_audio
            _vc_mono = np.mean(_vc_audio, axis=0) if _vc_audio.ndim == 2 else _vc_audio
            _vc_r = _GenderDetector(sample_rate=sample_rate).detect(_vc_mono.astype(np.float32))
            _vc_result = {
                "gender": _vc_r.gender.name if _vc_r.gender is not None else None,
                "age_group": _vc_r.age_group.name if _vc_r.age_group is not None else None,
                "formants_hz": [round(float(f), 1) for f in _vc_r.formants[:4]] if _vc_r.formants else [],
                "breathiness": round(float(_vc_r.breathiness), 4),
            }
            logger.debug("🎤 VocalCharacteristics: %s", _vc_result)
            return _vc_result
        except Exception as _vc_exc:
            logger.debug("VocalCharacteristics nicht verfügbar: %s", _vc_exc)
            return None

    def _compute_defect_phase_mapping_result(
        self,
        defect_result: object | None,
        executed_phases: list | None,
    ) -> dict | None:
        """Compute v9.10.20 DefectPhaseMapping payload for reporting metadata."""
        try:
            from backend.core.defect_phase_mapper import DefectPhaseMapper as _DPM

            _dpm_scores = getattr(defect_result, "scores", None)
            if _dpm_scores is None:
                return None

            _dpm_defects = list(_dpm_scores.values())
            _dpm_phases = _DPM().phases_for_defect_profile(_dpm_defects, max_phases=12)
            _dpm_executed_set = set(executed_phases or [])
            _dpm_result = {
                "recommended_phases": _dpm_phases,
                "executed": [p for p in _dpm_phases if p in _dpm_executed_set],
                "missed": [p for p in _dpm_phases if p not in _dpm_executed_set],
                "coverage_ratio": round(
                    len([p for p in _dpm_phases if p in _dpm_executed_set]) / max(len(_dpm_phases), 1), 3
                ),
            }
            logger.debug("🗺️ DefectPhaseMapping: %s", _dpm_result)
            return _dpm_result
        except Exception as _dpm_exc:
            logger.debug("DefectPhaseMapper nicht verfügbar: %s", _dpm_exc)
            return None

    def _compute_fletcher_munson_result(self) -> dict | None:
        """Compute v9.10.20 FletcherMunson correction summary for reporting metadata."""
        try:
            from backend.core.fletcher_munson_curves import get_fletcher_munson_curve as _get_fm

            _fm_freqs = np.array(
                [63.0, 125.0, 250.0, 500.0, 1000.0, 2000.0, 4000.0, 8000.0, 12000.0, 16000.0], dtype=np.float32
            )
            _fm_curve = _get_fm(_fm_freqs, target_phon=60, reference_phon=80)
            _fm_result = {
                "correction_db_at_hz": {int(f): round(float(c), 3) for f, c in zip(_fm_freqs, _fm_curve)},
                "max_correction_db": round(float(np.max(np.abs(_fm_curve))), 3),
            }
            logger.debug("📐 FletcherMunson: %s", _fm_result)
            return _fm_result
        except Exception as _fm_exc:
            logger.debug("FletcherMunson nicht verfügbar: %s", _fm_exc)
            return None

    def _compute_gap_reconstruction_result(
        self,
        restored_audio: "np.ndarray",
        sample_rate: int,
        material_type: "MaterialType",
    ) -> dict | None:
        """Compute v9.10.21 GapReconstructor statistics for reporting metadata."""
        try:
            from backend.core.gap_reconstructor import GapReconstructor as _GapRecon

            _gr_audio = restored_audio.astype(np.float32)
            _gr_r = _GapRecon().reconstruct(
                _gr_audio,
                sample_rate,
                material_hint=material_type.value if material_type else None,
            )
            _gr_result = {
                "gaps_found": _gr_r.gaps_found,
                "gaps_repaired": _gr_r.gaps_repaired,
                "gaps_skipped": _gr_r.gaps_skipped,
                "repair_rate": round(float(_gr_r.repair_rate), 4),
                "total_repaired_ms": round(float(_gr_r.total_repaired_ms), 2),
                "processing_time_ms": round(float(_gr_r.processing_time_ms), 1),
            }
            logger.debug("🔧 GapReconstructor: %s", _gr_result)
            return _gr_result
        except Exception as _gr_exc:
            logger.debug("GapReconstructor nicht verfügbar: %s", _gr_exc)
            return None

    def _compute_media_defect_analysis_result(
        self,
        restored_audio: "np.ndarray",
        sample_rate: int,
    ) -> dict | None:
        """Compute v9.10.21 MediaDefectAnalysis payload for reporting metadata."""
        try:
            from backend.core.media_defect_analysis import analyze_defects_features as _analyze_defects

            _mda_audio = restored_audio
            _mda_defects = _analyze_defects(_mda_audio, sample_rate)
            _mda_result = {
                "detected_defects": sorted(_mda_defects),
                "defect_count": len(_mda_defects),
            }
            logger.debug("🔎 MediaDefectAnalysis: %s", _mda_result)
            return _mda_result
        except Exception as _mda_exc:
            logger.debug("MediaDefectAnalysis nicht verfügbar: %s", _mda_exc)
            return None

    def _compute_causal_defect_graph_result(
        self,
        defect_result: object | None,
    ) -> dict | None:
        """Compute v9.10.21 CausalDefectGraph payload for reporting metadata."""
        try:
            from backend.core.causal_defect_graph import CausalDefectGraph as _CDG

            _cdg_scores = getattr(defect_result, "scores", None)
            if _cdg_scores is None:
                return None

            _cdg = _CDG()
            _cdg_defects = list(_cdg_scores.values())
            _cdg_ordered = _cdg.resolve_causal_order(_cdg_defects)
            _cdg_phantom = _cdg.get_phantom_defects(_cdg_defects)
            _cdg_result = {
                "causal_order": [s.defect_type.value for s in _cdg_ordered[:8]],
                "phantom_defects": [d.value for d in _cdg_phantom],
                "explanation": _cdg.explain(_cdg_defects)[:300],
            }
            logger.debug("🕸️ CausalDefectGraph: %s", _cdg_result)
            return _cdg_result
        except Exception as _cdg_exc:
            logger.debug("CausalDefectGraph nicht verfügbar: %s", _cdg_exc)
            return None

    def _compute_perceptual_quality_gates_result(
        self,
        _music_mos_result: dict | None,
        _pqs_result: object | None,
    ) -> dict | None:
        """Compute v9.10.21 PerceptualQualityGates payload for reporting metadata."""
        try:
            from backend.core.perceptual_quality_gates import PerceptualQualityGates as _PQG

            _pqg_metrics: dict[str, float] = {}
            if _music_mos_result:
                if "MUSIC_OVR" in _music_mos_result:
                    # Music-MOS (DSP-based) — no speech metric (§10.2: DNSMOS/NISQA forbidden)
                    _pqg_metrics["MUSIC_OVR_MOS"] = float(_music_mos_result["MUSIC_OVR"])
                if "MUSIC_NAT" in _music_mos_result:
                    _pqg_metrics["MUSIC_NAT_MOS"] = float(_music_mos_result["MUSIC_NAT"])
            if _pqs_result is not None:
                _pqs_d = _pqs_result.to_dict() if hasattr(_pqs_result, "to_dict") else {}
                if "mos" in _pqs_d:
                    _pqg_metrics["ViSQOL"] = float(_pqs_d["mos"])
            _pqg_passed = _PQG(lambda: None).evaluate(_pqg_metrics)
            _pqg_result = {
                "metrics_evaluated": _pqg_metrics,
                "passed": _pqg_passed,
            }
            logger.debug("🚦 PerceptualQualityGates: %s", _pqg_result)
            return _pqg_result
        except Exception as _pqg_exc:
            logger.debug("PerceptualQualityGates nicht verfügbar: %s", _pqg_exc)
            return None

