    def _select_phases(
        self,
        defect_result,
        *,
        causal_plan=None,
        chain_info=None,
        defekt_hint=None,
        audio=None,
        sr=48000,
        goal_weights=None,
    ) -> list[str]:
        """
        Wählt Phasen kontextadaptiv basierend auf Defektbefund, Material und Modus.

        Args:
            defect_result: DefectScanResult vom DefectScanner.
            causal_plan:   Optional. RestorationPlan des CausalDefectReasoner (§2.6).
                           Wenn confidence ≥ 0.20, werden dessen recommended_phases
                           als Tier-1.5-Block in die Selektion eingeflochten.
            chain_info:    Optional. Tonträgerketten-Dict des TontraegerketteDenkers (§2.2).
                           combined_phases aus Multi-Carrier-Analyse (z. B. Vinyl→Kassette→MP3)
                           werden als Tier-1.6-Block aktiviert.
            defekt_hint:   Optional. Heuristik-Dict des DefektDenkers (§2.1).
                           recommended_phases (DSP-basiert) ergänzen den Bayesianischen
                           Tier-1.5-Block wenn confidence ≥ 0.15.

        Ablauf:
          1. PANNs-Analyse → Instrument-/Vokal-Konfidenz (mit DSP-Fallback)
          2. Tier 0    — Immer aktiv (DC-Offset, Rumpeln)
          3. Tier 1    — Kritische Defektkorrektur (schwellwertbasiert)
          4. Tier 1.5  — Kausaldiagnose-Ergänzung (CausalDefectReasoner §2.6)
          5. Tier 1.6  — Tonträgerkette-Ergänzung (TontraegerketteDenker §2.2)
          6. Tier 1.7  — DefektDenker-Heuristik-Ergänzung (DefektDenker §2.1)
          7. Tier 2    — Frequenz-/Spektral-Restaurierung
          8. Tier 3    — Stereo-/Phase-Verarbeitung
          9. Tier 4    — Instrument-/Vokal-Enhancement (PANNs-gesteuert)
         10. Tier 5    — Dynamik & Mastering
         11. Tier 6    — Ausgang (Lautheit, Limiter, Format)
        """
        scores = defect_result.scores
        material = defect_result.material_type

        def sev(defect_type, default=0.0):
            """Hilfsfunktion: Severity eines DefectType sicher auslesen."""
            s = scores.get(defect_type)
            return s.severity if s is not None else default

        # ── PANNs-Gate: Instrument/Vokal-Erkennung ─────────────────────
        panns_tags: dict[str, float] = {}
        try:
            import os as _os
            import sys as _sys_panns  # pylint: disable=import-outside-toplevel

            _ref = audio  # audio array passed from restore() — no longer relying on defect_result._audio_ref
            _sr = sr
            if _ref is not None:
                # Only load PANNs when audio reference is actually available
                _plugins_dir = _os.path.join(_os.path.dirname(__file__), "..", "..", "plugins")
                if _plugins_dir not in _sys_panns.path:
                    _sys_panns.path.insert(0, _os.path.abspath(_plugins_dir))
                from panns_plugin import PANNsPlugin

                _panns = PANNsPlugin()
                panns_tags = _panns.get_tags(_ref, _sr)
                logger.info(
                    "PANNs tags: %s", {k: f"{v:.2f}" for k, v in sorted(panns_tags.items(), key=lambda x: -x[1])[:10]}
                )
        except Exception as _panns_exc:
            logger.debug("PANNs nicht verfügbar, kein Instrument-Gate aktiv: %s", _panns_exc)

        def panns(tag: str, threshold: float = 0.5) -> bool:
            """Liefert True wenn PANNs-Tag die Mindestkonfidenz erreicht."""
            return panns_tags.get(tag, 0.0) >= threshold

        vocals_detected = panns("Singing voice", 0.40) or panns("Vocals", 0.40) or panns("Speech", 0.35)
        # §2.9a Soft-Activation (spec Y6): vocal_prob ∈ [0.35, 0.40) → activate vocal
        # phases at 50% strength to capture quiet ensemble vocals without false positives.
        _vocal_prob_max = max(panns_tags.get("Singing voice", 0.0), panns_tags.get("Vocals", 0.0))
        if not vocals_detected and _vocal_prob_max >= 0.35:
            vocals_detected = True
            _vocal_strength_scale: float = 0.5
            logger.info(
                "§2.9a PANNs Vocal Soft-Activation: vocal_prob=%.3f ∈ [0.35, 0.40) → strength_scale=0.5",
                _vocal_prob_max,
            )
        else:
            _vocal_strength_scale = 1.0
        if isinstance(getattr(self, "_restoration_context", None), dict):
            self._restoration_context["vocal_strength_scale"] = _vocal_strength_scale
            # §2.9 PANNs-Propagation: panns_tags + panns_vocals_confidence in
            # _restoration_context schreiben, damit _profiled_phase_call sie in ALLE
            # Phase-kwargs injiziert (phase_03, phase_42, etc.). DefectScanner speichert
            # keine PANNs-Tags → restore()-Pfad liefert _panns_conf=None → hier setzen.
            # Setzt nur wenn noch nicht vorhanden (DefectScanner-Metadata hat Vorrang).
            if panns_tags and "panns_vocals_confidence" not in self._restoration_context:
                _pvc = max(
                    float(panns_tags.get("Singing voice", 0.0) or 0),
                    float(panns_tags.get("Vocals", 0.0) or 0),
                    float(panns_tags.get("Speech", 0.0) or 0),
                    float(panns_tags.get("Male singing", 0.0) or 0),
                    float(panns_tags.get("Female singing", 0.0) or 0),
                )
                self._restoration_context["panns_tags"] = panns_tags
                self._restoration_context["panns_vocals_confidence"] = _pvc
                # §0p BUG-FIX v9.12.5: panns_singing — Fallback wenn SongCalibration-Block nicht lief.
                if "panns_singing" not in self._restoration_context:
                    self._restoration_context["panns_singing"] = max(
                        float(panns_tags.get("Singing", 0.0) or 0),
                        float(panns_tags.get("Singing voice", 0.0) or 0),
                    )
                logger.debug(
                    "§2.9 PANNs-Propagation (_select_phases→context): vocal_conf=%.3f",
                    _pvc,
                )
        guitar_detected = panns("Guitar", 0.50) or panns("Electric guitar", 0.50)
        brass_detected = panns("Brass instrument", 0.50) or panns("Trumpet", 0.50) or panns("Saxophone", 0.50)
        drums_detected = panns("Drum", 0.50) or panns("Percussion", 0.50)
        piano_detected = panns("Piano", 0.50) or panns("Keyboard (musical)", 0.50)

        # ── Erweiterte Instrument-/Genre-Erkennung (v9.10.x) ────────────
        # Streicher, Holzbläser, Synthesizer, Orgel, ethnische Instrumente
        strings_detected = (
            panns("Violin, fiddle", 0.40)
            or panns("Cello", 0.40)
            or panns("Double bass", 0.40)
            or panns("Bowed string instrument", 0.40)
        )
        woodwind_detected = (
            panns("Flute", 0.45) or panns("Clarinet", 0.45) or panns("Oboe", 0.45) or panns("Bassoon", 0.45)
        )
        synth_detected = panns("Synthesizer", 0.45) or panns("Electronic organ", 0.45)
        organ_detected = panns("Organ", 0.45) or panns("Church bell", 0.30)
        # Polyphoniedichte-Schätzung: >3 Instrumentfamilien aktiv → dichtes Ensemble
        _active_families = sum(
            [
                vocals_detected,
                guitar_detected,
                brass_detected,
                drums_detected,
                piano_detected,
                strings_detected,
                woodwind_detected,
                synth_detected,
            ]
        )
        _dense_ensemble = _active_families >= 4

        # ── Beat-Reliability-Score (Rubato/Free-Form Detektor) ──────────
        # Onset-Autokorrelation: periodischer Beat → hoher Score; Rubato → niedrig.
        # Gated: wen Reliability < 0.40 → Wow/Flutter-Korrektur abschwächen/deaktivieren.
        _beat_reliability: float = 1.0  # default: Beat angenommen
        if audio is not None:
            try:
                _br_mono = (
                    audio.mean(axis=0)
                    if audio.ndim == 2 and audio.shape[0] <= audio.shape[1]
                    else (audio.mean(axis=1) if audio.ndim == 2 else audio)
                )
                _br_mono = np.asarray(_br_mono, dtype=np.float32)
                # Onset-Stärke via Spectral-Flux (schnell, kein librosa nötig)
                _br_hop = max(1, sr // 100)  # ~10 ms Hops
                _br_win = _br_hop * 2
                _br_n_frames = max(1, (len(_br_mono) - _br_win) // _br_hop)
                if _br_n_frames > 20:
                    _br_flux = np.zeros(_br_n_frames, dtype=np.float32)
                    _prev_mag = np.zeros(_br_win // 2 + 1, dtype=np.float32)
                    for _bi in range(_br_n_frames):
                        _bstart = _bi * _br_hop
                        _bframe = _br_mono[_bstart : _bstart + _br_win]
                        if len(_bframe) < _br_win:
                            break
                        _bmag = np.abs(np.fft.rfft(_bframe * np.hanning(_br_win)))
                        _br_flux[_bi] = float(np.sum(np.maximum(_bmag - _prev_mag, 0.0)))
                        _prev_mag = _bmag
                    # Auto-Korrelation der Onset-Stärke (BPM 40–220) — FFT-based O(N log N)
                    _min_lag = max(1, int(sr / (_br_hop * 220.0 / 60.0)))
                    _max_lag = min(_br_n_frames // 2, int(sr / (_br_hop * 40.0 / 60.0)))
                    if _max_lag > _min_lag + 5:
                        from backend.core.core_utils import fft_autocorr

                        _br_ac = fft_autocorr(_br_flux[:_br_n_frames])
                        _br_ac_norm = _br_ac / (_br_ac[0] + 1e-12)
                        _br_region = _br_ac_norm[_min_lag:_max_lag]
                        if len(_br_region) > 0:
                            _beat_reliability = float(np.max(_br_region))
                            _beat_reliability = max(0.0, min(1.0, _beat_reliability))
                logger.info(
                    "Beat-Reliability: %.3f (%s)",
                    _beat_reliability,
                    "steady beat" if _beat_reliability >= 0.40 else "rubato/free-form",
                )
            except Exception as _br_exc:
                logger.debug("Beat-Reliability-Berechnung fehlgeschlagen: %s", _br_exc)

        # ── Loudness-War-Detektor ───────────────────────────
        # Intentionale Kompression (modernes Material, Crest < 6 dB) ≠ Defekt.
        # Dynamik-Wiederherstellungsphasen werden für solches Material gesperrt.
        _loudness_war_victim = False
        _era_decade_sel = getattr(getattr(self, "_active_era_result", None), "decade", None)
        _comp_sev = sev(DefectType.DYNAMIC_COMPRESSION_EXCESS)
        if _comp_sev > 0.25:
            _is_modern_era = _era_decade_sel is not None and _era_decade_sel >= 2000
            _is_digital_mat = material in {
                MaterialType.CD_DIGITAL,
                MaterialType.MP3_LOW,
                MaterialType.MP3_HIGH,
                MaterialType.AAC,
                MaterialType.STREAMING,
                MaterialType.DAT,
            }
            if _is_modern_era or _is_digital_mat:
                _loudness_war_victim = True
                logger.info(
                    "🔊 Loudness-War-Guard: Intentionale Kompression erkannt "
                    "(comp_sev=%.2f, era=%s, material=%s) — Dynamik-Phasen gesperrt",
                    _comp_sev,
                    _era_decade_sel,
                    material.value if hasattr(material, "value") else material,
                )

        # ── Operatic/Classical Vibrato Detektor ──────────────────────
        # Breites Vibrato (~5 Hz, ±50–200 Cent) ≠ Pitch-Defekt oder Sibilanz.
        # Erkannt: starke periodische f0-Modulation im 4–7 Hz Band.
        _operatic_vibrato = False
        if vocals_detected and audio is not None:
            try:
                _vib_mono = (
                    audio.mean(axis=0)
                    if audio.ndim == 2 and audio.shape[0] <= audio.shape[1]
                    else (audio.mean(axis=1) if audio.ndim == 2 else audio)
                )
                _vib_mono = np.asarray(_vib_mono, dtype=np.float32)
                # ZCR-basierte schnelle f0-Schätzung (256-Sample-Fenster, 10 ms Hop)
                _vib_hop = max(1, sr // 100)
                _vib_n = max(1, (len(_vib_mono) - 256) // _vib_hop)
                if _vib_n > 50:
                    _f0_series = np.zeros(_vib_n, dtype=np.float32)
                    for _vi in range(_vib_n):
                        _vs = _vi * _vib_hop
                        _vframe = _vib_mono[_vs : _vs + 256]
                        _zcr = float(np.sum(np.abs(np.diff(np.sign(_vframe))) > 0))
                        _f0_series[_vi] = _zcr * sr / (2.0 * 256)
                    # Vibrato = periodische Modulation in 4–7 Hz (Fenstergröße ~200 ms)
                    _f0_detrend = _f0_series - np.convolve(_f0_series, np.ones(20) / 20, mode="same")
                    _vib_fft = np.abs(np.fft.rfft(_f0_detrend))
                    _vib_freqs = np.fft.rfftfreq(len(_f0_detrend), d=_vib_hop / sr)
                    _vib_band = (_vib_freqs >= 4.0) & (_vib_freqs <= 7.0)
                    _vib_energy = float(np.sum(_vib_fft[_vib_band] ** 2))
                    _total_energy = float(np.sum(_vib_fft[1:] ** 2)) + 1e-12
                    _vib_ratio = _vib_energy / _total_energy
                    if _vib_ratio > 0.15:
                        _operatic_vibrato = True
                        logger.info(
                            "🎭 Vibrato-Detektor: Operatic/klassisches Vibrato erkannt "
                            "(4–7 Hz Energie-Ratio=%.3f) — De-Esser/Harshness abgeschwächt",
                            _vib_ratio,
                        )
            except Exception as _vib_exc:
                logger.debug("Vibrato-Detektion fehlgeschlagen: %s", _vib_exc)

        # §2.8 Vocal-Chain: Einmalige Gender-Detektion für alle nachfolgenden Vocal-Phasen
        # Ergebnis wird auf self gespeichert und in _restoration_context injiziert,
        # sodass Phase 19/42/43 das erkannte Geschlecht via kwargs erhalten.
        self._detected_vocal_gender = "unknown"
        if vocals_detected and audio is not None:
            try:
                from backend.core.vocal_ai_enhancement import GenderDetector as _GenderDet

                _mono_for_gender = audio.mean(axis=1) if audio.ndim == 2 else audio
                _voice_chars = _GenderDet(sample_rate=sr).detect(_mono_for_gender)
                self._detected_vocal_gender = _voice_chars.gender.value
                logger.info(
                    "§2.8 Vocal Gender: %s (F0=%.1f Hz, confidence=%.2f)",
                    self._detected_vocal_gender,
                    _voice_chars.fundamental_freq,
                    _voice_chars.confidence,
                )
            except Exception as _gd_exc:
                logger.debug("Gender-Detektion fehlgeschlagen: %s", _gd_exc)

        selected: list[str] = []

        # ════════════════════════════════════
        # TIER 0 — Basiskorrekturen (immer aktiv, < 1 ms Overhead)
        # ════════════════════════════════════
        # Phase 30/05 nur bei echten Defekten aktivieren (§0 Minimal-Intervention)
        if sev(DefectType.DC_OFFSET) > 0.10:
            selected.append("phase_30_dc_offset_removal")
            logger.debug("TIER0: phase_30 (DC severity=%.3f)", sev(DefectType.DC_OFFSET))
        if sev(DefectType.LOW_FREQ_RUMBLE) > 0.10:
            selected.append("phase_05_rumble_filter")
            logger.debug("TIER0: phase_05 (Rumble severity=%.3f)", sev(DefectType.LOW_FREQ_RUMBLE))

        # ════════════════════════════════════
        # TIER 1 — Kritische Defektkorrektur
        # ════════════════════════════════════

        # Dropout / gap repair
        # §9.7.5a — Always activate phase 24 for dropout-prone materials (Spec 05 §6.2).
        # Phase 24 has its own high-quality multi-modal detection (0.5 ms resolution,
        # material-adaptive) that catches dropouts the DefectScanner may underestimate.
        _DROPOUT_PRONE_MATERIALS = {
            MaterialType.REEL_TAPE,
            MaterialType.TAPE,
            MaterialType.VINYL,
            MaterialType.SHELLAC,
            MaterialType.WAX_CYLINDER,
            MaterialType.WIRE_RECORDING,
            MaterialType.LACQUER_DISC,
            MaterialType.DAT,
        }
        if sev(DefectType.DROPOUTS) > 0.10 or material in _DROPOUT_PRONE_MATERIALS:
            selected.append("phase_24_dropout_repair")
        # phase_55 (DiffWave ML-Inpainting) only for severe analog dropouts —
        # digital codecs (MP3, streaming, CD) do not produce tape-gap-type dropouts.
        if sev(DefectType.DROPOUTS) > 0.30 and material in _DROPOUT_PRONE_MATERIALS:
            selected.append("phase_55_diffusion_inpainting")  # ML-Inpainting nur für analoge Lücken

        # Clicks / Impulse (1. Pass)
        if sev(DefectType.CLICKS) > 0.15:
            selected.append("phase_01_click_removal")
        # Clicks / Pops (2. Pass — tiefergehende AR-Residual-Methode)
        if sev(DefectType.CLICKS) > 0.25:
            selected.append("phase_27_click_pop_removal")

        # Vinyl/Shellac/Lacquer: Oberflächenrausch-Profil VOR Crackle-Entfernung
        if (
            material in [MaterialType.VINYL, MaterialType.SHELLAC, MaterialType.LACQUER_DISC]
            and sev(DefectType.CRACKLE) > 0.10
        ):
            selected.append("phase_28_surface_noise_profiling")

        # Crackle — nur für Disc-Medien (Vinyl/Shellac/Lacquer-Oberflächen-Erosion).
        # Tape-Hiss-Artefakte und MP3-Block-Impulse lösen zwar den DefectScanner aus,
        # sind aber kein physikalisches Crackle — phase_29/phase_03 adressieren diese bereits.
        # UNKNOWN wird einbezogen, da Materialerkennung fehlschlagen kann (Safety-Net für
        # nicht erkannte Disc-Medien). Alle anderen Träger (Tape, REEL_TAPE, CD, Digital,
        # MP3-Kette) werden hier explizit ausgeschlossen.
        _DISC_MATERIALS_CRACKLE = {
            MaterialType.VINYL,
            MaterialType.SHELLAC,
            MaterialType.LACQUER_DISC,
            MaterialType.UNKNOWN,
        }
        if sev(DefectType.CRACKLE) > 0.15 and material in _DISC_MATERIALS_CRACKLE:
            selected.append("phase_09_crackle_removal")
        elif sev(DefectType.CRACKLE) > 0.15:
            logger.debug(
                "phase_09_crackle_removal übersprungen: material=%s ist kein Disc-Träger"
                " (Crackle-Artefakt wird durch phase_29/phase_03 adressiert)",
                material,
            )

        # Brumm 50/60 Hz
        if sev(DefectType.HUM) > 0.10:
            selected.append("phase_02_hum_removal")

        # Breitbandrauschen
        if sev(DefectType.HIGH_FREQ_NOISE) > 0.20:
            selected.append("phase_03_denoise")

        # Tape-Hiss (spezifisches Profil-basiertes Verfahren)
        # Shellac: phase_03_denoise übernimmt das NR — phase_29 NICHT unconditional
        # aktivieren, da das Doppel-NR bei SNR≈6 dB das Signal vollständig zerstört.
        # REEL_TAPE: Profi-Spulenband mit identischem Hiss-Profil wie TAPE.
        if sev(DefectType.HIGH_FREQ_NOISE) > 0.30 or material in [
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
        ]:
            selected.append("phase_29_tape_hiss_reduction")

        # Noise-Gate für Stille-Segmente mit Rauschboden
        if sev(DefectType.HIGH_FREQ_NOISE) > 0.25 or sev(DefectType.LOW_FREQ_RUMBLE) > 0.20:
            selected.append("phase_18_noise_gate")

        # Wow/Flutter (Magnetband-Gleichlaufschwankungen)
        # §Beat-Reliability-Gate: Rubato/Free-Form → Wow/Flutter-Korrektur abschwächen
        if max(sev(DefectType.WOW), sev(DefectType.FLUTTER)) > 0.10:
            if _beat_reliability >= 0.40:
                selected.append("phase_12_wow_flutter_fix")
            elif max(sev(DefectType.WOW), sev(DefectType.FLUTTER)) > 0.35:
                # Nur bei hoher Severity trotz Rubato — schwerer mechanischer Defekt
                selected.append("phase_12_wow_flutter_fix")
                logger.info(
                    "⏱️ Rubato-Override: phase_12 trotz Beat-Reliability=%.2f aktiviert "
                    "(WOW=%.2f, FLUTTER=%.2f — severity > 0.35 → mechanischer Defekt wahrscheinlich)",
                    _beat_reliability,
                    sev(DefectType.WOW),
                    sev(DefectType.FLUTTER),
                )
            else:
                logger.info(
                    "⏱️ Rubato-Guard: phase_12 übersprungen — Beat-Reliability=%.2f < 0.40 "
                    "(WOW=%.2f, FLUTTER=%.2f ≤ 0.35 → wahrscheinlich künstlerisches Rubato)",
                    _beat_reliability,
                    sev(DefectType.WOW),
                    sev(DefectType.FLUTTER),
                )

        # Transport-Bump (impulsartige Bandholperer — Kassette/Tape)
        if sev(DefectType.TRANSPORT_BUMP) > 0.08:
            if "phase_12_wow_flutter_fix" not in selected:
                selected.append("phase_12_wow_flutter_fix")

        # Pitch-Drift (langsame Tonhöhenschwankung)
        # §Rubato-Guard: Expressives Rubato erzeugt natürlichen Pitch-Drift
        if sev(DefectType.PITCH_DRIFT) > 0.15:
            if _beat_reliability >= 0.40 or sev(DefectType.PITCH_DRIFT) > 0.40:
                selected.append("phase_31_speed_pitch_correction")
            else:
                logger.info(
                    "⏱️ Rubato-Guard: phase_31 übersprungen — Beat-Reliability=%.2f, "
                    "Pitch-Drift=%.2f → wahrscheinlich expressives Tempo",
                    _beat_reliability,
                    sev(DefectType.PITCH_DRIFT),
                )

        # Phasen-/Azimuth-Fehler
        # phase_14 nutzt sosfiltfilt (Zero-Phase) → artifact-sicher für alle Materialien.
        # Bei digitalem Material mit false-positive PHASE_ISSUES (MP3 Joint-Stereo): phase_14
        # findet 0 ms Delay → np.roll(0) = no-op, kein Schaden. §2.51 Stereo-Kohärenz-Invariante.
        if sev(DefectType.PHASE_ISSUES) > 0.10:
            selected.append("phase_14_phase_correction")
        # phase_25 (Azimuth-Korrektur Magnetkopf) nur für physikalische Bandmaterialien §2.46b
        if sev(DefectType.PHASE_ISSUES) > 0.20 and material in [
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
            MaterialType.SHELLAC,
        ]:
            selected.append("phase_25_azimuth_correction")

        # Nachhall-Reduktion — §0h BUG-FIX v9.12.5: Gegenseitiger Ausschluss.
        # Beide Phasen gleichzeitig erzeugen Doppel-Dereverb → Pre-Ringing/Echo-Artefakte.
        # Bei starkem Reverb (> 0.45) nur phase_49 (Blind-RIR, überlegen); sonst phase_20.
        if sev(DefectType.REVERB_EXCESS) > 0.25:
            if sev(DefectType.REVERB_EXCESS) > 0.45:
                selected.append("phase_49_advanced_dereverb")  # Tiefgehende Blind-RIR-Methode
            else:
                selected.append("phase_20_reverb_reduction")

        # Spektral-Reparatur (Clipping / Digital-Artefakte)
        if sev(DefectType.CLIPPING) > 0.10 or sev(DefectType.DIGITAL_ARTIFACTS) > 0.20:
            selected.append("phase_23_spectral_repair")

        # Print-Through (Magnetisches Übersprechen bei Bandaufnahmen — Vor-/Nachecho)
        # Physikalisch nur bei Bandmaterial möglich
        # Spec §7.x / DSP-Regel: Bidirektionale Adaptive Temporal Subtraction (LMS)
        # phase_57_print_through_reduction = Primär (Pre-Echo + Post-Echo getrennt)
        # Fallback: phase_29 Hiss-Profil + phase_03 Breitband-NR
        if sev(DefectType.PRINT_THROUGH) > 0.15 and material in [
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
        ]:
            selected.append("phase_57_print_through_reduction")  # §7.x bidirektionale LMS Primär
            selected.append("phase_29_tape_hiss_reduction")  # Hiss-Profil-Subtraktion
            selected.append("phase_03_denoise")  # Breitband-Restecho-NR
        if sev(DefectType.PRINT_THROUGH) > 0.35 and material in [
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
        ]:
            selected.append("phase_23_spectral_repair")  # Schwere Vorecho-Tilgung

        # Quantisierungsrauschen (niedrige Bit-Tiefe / fehlerhaftes Resampling)
        if sev(DefectType.QUANTIZATION_NOISE) > 0.15:
            selected.append("phase_03_denoise")
            selected.append("phase_23_spectral_repair")
        if sev(DefectType.QUANTIZATION_NOISE) > 0.30:
            selected.append("phase_06_frequency_restoration")  # Treppen-Artefakte glätten

        # Jitter-Artefakte (D/A-Wandler-Zeitfehler — CD, DAT, Streaming)
        if sev(DefectType.JITTER_ARTIFACTS) > 0.15:
            selected.append("phase_12_wow_flutter_fix")  # Zeitachsen-Trägeheit
            selected.append("phase_23_spectral_repair")  # Spektrale Jitter-Spuren

        # RIAA-Entzerrungsfehler (Shellac/früher Vinyl: AES/NAB/FFRR — §6.3, §7.2)
        # Medium-Gate: RIAA nur für Disc-Medien (Vinyl/Shellac/Lacquer/Wax/Unknown)
        _is_disc_medium = material in {
            MaterialType.VINYL,
            MaterialType.SHELLAC,
            MaterialType.LACQUER_DISC,
            MaterialType.WAX_CYLINDER,
            MaterialType.UNKNOWN,
        }
        if _is_disc_medium and sev(DefectType.RIAA_CURVE_ERROR) > 0.12:
            selected.append("phase_04_eq_correction")  # Fehler-EQ korrigieren
            selected.append("phase_06_frequency_restoration")  # Spektralprofil wiederherstellen
        if _is_disc_medium and sev(DefectType.RIAA_CURVE_ERROR) > 0.30:
            selected.append("phase_07_harmonic_restoration")  # Obertöne durch Entzerrungs-Kette verloren

        # Aliasing (AA-Filter-Artefakte bei Digitalisierung — §6.3, §7.2)
        if sev(DefectType.ALIASING) > 0.15:
            selected.append("phase_03_denoise")  # Spiegelfrequenzen dämpfen
            selected.append("phase_23_spectral_repair")  # Spektrale Aliasing-Spuren beseitigen
        if sev(DefectType.ALIASING) > 0.35:
            selected.append("phase_50_spectral_repair")  # Zweiter Spektral-Pass

        # Bias-Fehler (falscher Vormagnetisierungsstrom bei Bandaufnahme — §6.3, §7.2)
        if sev(DefectType.BIAS_ERROR) > 0.12:
            selected.append("phase_04_eq_correction")  # HF-Rolloff/-Überhöhung kompensieren
            selected.append("phase_03_denoise")  # Bias-induziertes Rauschen reduzieren
        if sev(DefectType.BIAS_ERROR) > 0.30:
            selected.append("phase_06_frequency_restoration")  # Frequenzgang-Verluste ausgleichen
            selected.append("phase_29_tape_hiss_reduction")  # Bias-erhöhtes Hintergrundrauschen

        # Dolby-NR-Mismatch (Dolby B/C/S encode ohne Dekoder abgespielt — §6.3)
        # Dolby B: +6 dB HF-Shelf; Dolby C: +20 dB; Korrektur: inverses Shelf-EQ + leichte NR
        if sev(DefectType.DOLBY_NR_MISMATCH) > 0.10:
            selected.append("phase_04_eq_correction")  # Inverses Dolby-Shelf-EQ (HF-Absenken)
            selected.append("phase_14_dynamic_range")  # Dolby-Kompander-Dynamik-Rekonstruktion
        if sev(DefectType.DOLBY_NR_MISMATCH) > 0.40:
            selected.append("phase_03_denoise")  # Dolby-C-Mismatch: starke HF-Überhöhung maskiert
            selected.append("phase_29_tape_hiss_reduction")  # Residual-Rauschen nach Dekoder-Emulation

        # Tape Head Level Dip (graduelle Pegeleinbrüche Kopf-Kontaktdruck — §6.3)
        # Phase 12 enthält autonomen Tape Level Stabilizer (Step 6c).
        if sev(DefectType.TAPE_HEAD_LEVEL_DIP) > 0.08:
            selected.append("phase_12_wow_flutter_fix")  # Tape Level Stabilizer (Step 6c)
        if sev(DefectType.TAPE_HEAD_LEVEL_DIP) > 0.30:
            selected.append("phase_24_dropout_repair")  # Tiefe Dips die Dropout-Schwelle überschreiten
            selected.append("phase_26_dynamic_range_expansion")  # Mikro-Dynamik nach Leveling

        # ── §6.3 Pflicht-Severity-Checks: HEAD_WEAR, AZIMUTH, TRANSIENT_SMEARING, PRE_ECHO, SIBILANCE ──
        # Ohne diese direkte Aktivierung verlassen sich die Defekte NUR auf CausalReasoner (Tier 1.5).
        # Tier 1 MUSS jede erkannte Severity > Schwelle direkt in Phasen übersetzen.

        # Kopfverschleiß (Tape/DAT-Köpfe — Frequenzband-Auslöschung → phase_56)
        if sev(DefectType.HEAD_WEAR) > 0.15:
            selected.append("phase_56_spectral_band_gap_repair")  # §4.5/§7.2
            selected.append("phase_14_phase_correction")
            selected.append("phase_06_frequency_restoration")

        # Azimuth-Fehler (Kopfausrichtung — NUR physikalische Bandmaterialien; eigenständig neben PHASE_ISSUES)
        # §7.2 CAUSE_TO_PHASES: phase_14 (Phasenkonsistenz L/R) MUSS vor phase_25 (Kopf-EQ) laufen.
        # §2.46b Material-Guard: Azimuth-Fehler ist ein physikalischer Defekt des Magnetkopfs —
        # bei reinen Digitalquellen (MP3, CD, DAT als Endformat) ist er physikalisch unmöglich.
        # Ohne Guard: MP3-Joint-Stereo-Asymmetrien → false-positive AZIMUTH_ERROR → phase_25
        # mit kausaler Bandaufteilung → frequenzabhängiger L/R-Zeitversatz → „starker Zeitversatz".
        if sev(DefectType.AZIMUTH_ERROR) > 0.12 and material in (
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
            MaterialType.SHELLAC,
        ):
            selected.append("phase_14_phase_correction")  # §7.2: zuerst Phasenkonsistenz L/R normieren
            selected.append("phase_25_azimuth_correction")  # §7.2: dann Kopfausrichtungs-EQ-Kompensation
            selected.append("phase_06_frequency_restoration")

        # Transient-Smearing (Transienten-Verschmierung — Mastering/Codec)
        if sev(DefectType.TRANSIENT_SMEARING) > 0.15:
            selected.append("phase_08_transient_preservation")  # §7.2 — Transienten-Restaurierung
            selected.append("phase_36_transient_shaper")

        # Pre-Echo (MP3/AAC-Codec-Artefakte vor Transienten)
        if sev(DefectType.PRE_ECHO) > 0.15:
            selected.append("phase_23_spectral_repair")  # §6.3 — Codec-Pre-Echo
            selected.append("phase_50_spectral_repair")
            selected.append("phase_08_transient_preservation")

        # Sibilanz (Zischlaut-Überbetonung > 6 kHz — severity-priorisiert, nicht nur PANNs-Gate)
        # Vibrato-Guard: Bei operatischem/klassischem Vibrato (4–7 Hz) erzeugen Gesangs-Obertöne
        # natürliche HF-Energie im 4–8 kHz Band, die NICHT als Sibilanz behandelt werden darf.
        # Schwelle erhöht von 0.15 → 0.35 bei Vibrato-Singers.
        _sib_threshold = 0.35 if _operatic_vibrato else 0.15
        if sev(DefectType.SIBILANCE) > _sib_threshold:
            selected.append("phase_19_de_esser")  # §6.3 — De-Esser (stimmtyp-adaptiv)
            selected.append("phase_43_ml_deesser")  # ML-De-Esser (zweiter Pass)

        # Vocal-Harshness (Übersteuerung/Kratzigkeit/Härte im 2–6 kHz Band)
        # Vibrato-Guard: Operatic Vibrato erzeugt HF-Modulationen, die false-positive Harshness triggern.
        _harsh_threshold = 0.30 if _operatic_vibrato else 0.12
        if sev(DefectType.VOCAL_HARSHNESS) > _harsh_threshold:
            selected.append("phase_42_vocal_enhancement")  # Vocal-Enhancement mit Harshness-Absenkung
            selected.append("phase_19_de_esser")  # De-Esser reduziert obere Härte-Frequenzen
            selected.append("phase_43_ml_deesser")  # ML-De-Esser (Frikativ-Kontrolle)

        # WAX_CYLINDER (Phonographen-Wachswalze 1890–1930): aggressiv — HF ≤ 5 kHz, SNR extrem
        if material == MaterialType.WAX_CYLINDER:
            selected += [
                "phase_01_click_removal",  # Mechanische Störimpulse
                "phase_29_tape_hiss_reduction",  # Wachsoberflächenrauschen
                "phase_03_denoise",  # Breitbandrauschen
                "phase_06_frequency_restoration",  # HF ≤ 5 kHz rekonstruieren
                "phase_07_harmonic_restoration",  # Obertöne ergänzen
            ]

        # WIRE_RECORDING (Drahtton 1940–1955): Jitter + frequenzselektive Einbrüche
        if material == MaterialType.WIRE_RECORDING:
            selected += [
                "phase_12_wow_flutter_fix",  # Drahtband-Jitter
                "phase_24_dropout_repair",  # Frequenzeinbrüche als Dropouts
                "phase_03_denoise",  # Drahtband-Hintergrundrauschen
                "phase_29_tape_hiss_reduction",  # Magnetdraht-Hiss
            ]

        # LACQUER_DISC (Acetat-Lackfolien 1930–1950): Rissen + Rille-Ermüdung + Substrat-Rauschen
        if material == MaterialType.LACQUER_DISC:
            selected += [
                "phase_01_click_removal",  # Lackrisse → Impulse
                "phase_09_crackle_removal",  # Rille-Ermüdung → Crackle
                "phase_03_denoise",  # Substrat-Rauschen
                "phase_29_tape_hiss_reduction",  # Lackoberflächen-Rauschen
            ]

        # ── Neue Defekttypen (v9.10.x — 12 SOTA-Lücken) ──────────────────

        # Modulationsrauschen (Signal-korrelierts Rauschen bei Tape/Vinyl — Esquef & Biscainho SOTA)
        if sev(DefectType.MODULATION_NOISE) > 0.15:
            selected.append("phase_59_modulation_noise_reduction")  # Signal-adaptive Spektral-Gating
        if sev(DefectType.MODULATION_NOISE) > 0.35:
            selected.append("phase_03_denoise")  # Breitband-Rest-NR nach Modulationsrausch-Entfernung

        # Innenrillenverzerrung (IGD — THD steigt zum Plattenende, Vinyl/Shellac/Lacquer/WaxCylinder)
        # WAX_CYLINDER: schwere Stahlnadeln + weiche Wachsmasse → IGD extrem ausgeprägt (DefectScanner prior 0.15),
        # Rillendeformation durch Wiederholung häufig (GROOVE_ECHO prior 0.30),
        # Nadelabnutzung sehr häufig (STYLUS_DAMAGE prior 0.15)
        _is_groove_medium = material in {
            MaterialType.VINYL,
            MaterialType.SHELLAC,
            MaterialType.LACQUER_DISC,
            MaterialType.WAX_CYLINDER,
        }
        if sev(DefectType.INNER_GROOVE_DISTORTION) > 0.12 and _is_groove_medium:
            selected.append("phase_60_inner_groove_distortion_repair")  # Positions-adaptive THD-Reduktion
        if sev(DefectType.INNER_GROOVE_DISTORTION) > 0.35 and _is_groove_medium:
            selected.append("phase_23_spectral_repair")  # Residuale Verzerrungsprodukte

        # Rillenecho (Groove Echo — benachbarte Rillen bluten durch, Vinyl/Shellac)
        if sev(DefectType.GROOVE_ECHO) > 0.15 and _is_groove_medium:
            selected.append("phase_61_groove_echo_cancellation")  # RPM-Template-Matching + Subtraktion
        if sev(DefectType.GROOVE_ECHO) > 0.40 and _is_groove_medium:
            selected.append("phase_03_denoise")  # Residuales Echo-Rest-Rauschen

        # Übersprechen (Crosstalk — Stereo-Kanaltrennung bei Vinyl/Tape)
        if sev(DefectType.CROSSTALK) > 0.15:
            selected.append("phase_62_crosstalk_cancellation")  # BSS-basierte Kanaltrennung
        if sev(DefectType.CROSSTALK) > 0.40:
            selected.append("phase_15_stereo_balance")  # Stereo-Balance nach Crosstalk-Fix

        # Intermodulationsverzerrung (IMD — nichtlineare Mischprodukte bei Vinyl/Röhre)
        if sev(DefectType.INTERMODULATION_DISTORTION) > 0.15:
            selected.append("phase_63_intermodulation_reduction")  # Volterra-basierte IMD-Tilgung
        if sev(DefectType.INTERMODULATION_DISTORTION) > 0.35:
            selected.append("phase_23_spectral_repair")  # Residuale IMD-Produkte

        # Tape-Klebestellen-Artefakte (Click+Level+Phase-Sprünge an Splice-Punkten)
        if sev(DefectType.TAPE_SPLICE_ARTIFACT) > 0.10 and material in {
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
        }:
            selected.append("phase_64_tape_splice_repair")  # Splice-Click + Level-Crossfade
        if sev(DefectType.TAPE_SPLICE_ARTIFACT) > 0.30 and material in {
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
        }:
            selected.append("phase_24_dropout_repair")  # Schwerer Splice-Ausfall

        # HF-Remanenz-Verlust (Tape Magnetisierungsverlust >4 kHz — Alterung)
        if sev(DefectType.HF_REMANENCE_LOSS) > 0.15 and material in {
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
        }:
            selected.append("phase_06_frequency_restoration")  # Bandwidth-Extension >4 kHz
            selected.append("phase_07_harmonic_restoration")  # Verlorene HF-Obertöne
        if sev(DefectType.HF_REMANENCE_LOSS) > 0.40:
            selected.append("phase_39_air_band_enhancement")  # Air-Band >12 kHz nach HF-Restore

        # Nadelschaden (Stylus Damage — asymmetrischer THD, Vinyl/Shellac)
        if sev(DefectType.STYLUS_DAMAGE) > 0.15 and _is_groove_medium:
            selected.append("phase_09_crackle_removal")  # Oberflächen-Micro-Risse
            selected.append("phase_23_spectral_repair")  # Verzerrungsprodukte reparieren
        if sev(DefectType.STYLUS_DAMAGE) > 0.35 and _is_groove_medium:
            selected.append("phase_50_spectral_repair")  # Zweiter Spektral-Pass

        # Sticky-Shed-Syndrome (Tape-Bindemittel-Verfall → kurze Pegeleinbrüche)
        if sev(DefectType.STICKY_SHED_RESIDUE) > 0.12 and material in {
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
        }:
            selected.append("phase_24_dropout_repair")  # Kurze Drop-Outs reparieren
            selected.append("phase_29_tape_hiss_reduction")  # Residual-Shed-Rauschen
        if sev(DefectType.STICKY_SHED_RESIDUE) > 0.35:
            selected.append("phase_03_denoise")  # Breitband-NR nach Shed-Artefakten

        # Multiband-Wow/Flutter (Frequenzabhängige Geschwindigkeitsschwankung)
        if sev(DefectType.MULTIBAND_WOW_FLUTTER) > 0.12:
            selected.append("phase_12_wow_flutter_fix")  # Multiband-f0-Korrektur (FCPE/CREPE/pYIN)
        if sev(DefectType.MULTIBAND_WOW_FLUTTER) > 0.35:
            selected.append("phase_08_transient_preservation")  # Transienten nach Multiband-Pitch-Fix

        # Generationsverlust (Multi-Copy-Degradation — Rauschen + BW-Verlust + Flattening)
        if sev(DefectType.GENERATION_LOSS) > 0.15:
            selected.append("phase_03_denoise")  # Kumuliertes Rauschen
            selected.append("phase_06_frequency_restoration")  # BW-Verlust durch Kopien
            selected.append("phase_23_spectral_repair")  # Spektrale Flattening-Effekte
        if sev(DefectType.GENERATION_LOSS) > 0.40:
            selected.append("phase_07_harmonic_restoration")  # Obertöne nach Multi-Gen-Verlust

        # Motor-Interferenz (80–300 Hz breite Peaks durch mechanische Ankopplung)
        if sev(DefectType.MOTOR_INTERFERENCE) > 0.10:
            selected.append("phase_02_hum_removal")  # Harmonische bei Motor-Grundfrequenz
            selected.append("phase_05_rumble_filter")  # Low-Frequency-Rumble durch mechanische Ankopplung
        if sev(DefectType.MOTOR_INTERFERENCE) > 0.30:
            selected.append("phase_04_eq_correction")  # Frequenzgang-Kompensation nach Motor-Tilgung

        # ════════════════════════════════════
        # §6.2a [RELEASE_MUST] Material-Pflicht-Phasen — Unconditional
        # Spec 05 §6.2a: Prioritäts-Phasen MÜSSEN aktiviert werden wenn
        # Material erkannt — unabhängig vom DefectScanner-Severity-Score.
        # Phasen enthalten eigene hochauflösende Detektionslogik und
        # entscheiden selbst, ob eine Reparatur notwendig ist.
        # ════════════════════════════════════
        _MATERIAL_PRIORITY_PHASES: dict[str, list[str]] = {
            "tape": [  # §2.46 ordering (2026-04-26): all subtractive BEFORE additive phase_06
                "phase_24_dropout_repair",
                "phase_29_tape_hiss_reduction",
                "phase_12_wow_flutter_fix",
                "phase_59_modulation_noise_reduction",
                "phase_64_tape_splice_repair",
                "phase_06_frequency_restoration",  # additive BW-extension LAST — §2.46 invariant
            ],
            "reel_tape": [
                "phase_29_tape_hiss_reduction",
                "phase_03_denoise",
                "phase_24_dropout_repair",
                "phase_55_diffusion_inpainting",
                "phase_59_modulation_noise_reduction",
                "phase_64_tape_splice_repair",
            ],
            "vinyl": [
                "phase_09_crackle_removal",
                "phase_12_wow_flutter_fix",
                "phase_05_rumble_filter",
                "phase_60_inner_groove_distortion_repair",
                "phase_61_groove_echo_cancellation",
                # Late-stage click/crackle re-sweep AFTER all spectral phases:
                # phase_23/29/14/20 can introduce PGHI-ringing, STFT-discontinuities,
                # and band-recombination transients. phase_27 (AR-residual click removal)
                # runs as final cleanup pass — ordering enforced via _move_before below.
                "phase_27_click_pop_removal",
            ],
            "shellac": [  # §6.2a: pressed shellac; §2.46 ordering (2026-04-26): all subtractive BEFORE additive
                "phase_09_crackle_removal",  # subtractive — carrier crackle
                "phase_03_denoise",  # subtractive — broadband noise
                "phase_01_click_removal",  # subtractive — clicks
                "phase_28_surface_noise_profiling",  # subtractive — surface noise
                "phase_05_rumble_filter",  # subtractive — 78-RPM turntable motor rumble (§6.2a Pflicht)
                "phase_27_click_pop_removal",  # late-stage re-sweep — nach spectral phases (PGHI/STFT)
                "phase_06_frequency_restoration",  # additive BW-extension LAST — §2.46 invariant
            ],
            "wax_cylinder": [  # §6.2a: mechanisch graviert; §2.46 subtractive BEFORE additive
                "phase_09_crackle_removal",  # subtractive — carrier crackle
                "phase_12_wow_flutter_fix",  # subtractive — wow/flutter
                "phase_03_denoise",  # subtractive — broadband noise
                "phase_01_click_removal",  # subtractive — clicks
                "phase_24_dropout_repair",  # subtractive/restorative — dropout
                "phase_29_tape_hiss_reduction",  # subtractive — surface hiss
                "phase_05_rumble_filter",  # subtractive — Zylinderphonograph-Motorenrumpeln (§6.2a Pflicht)
                "phase_55_diffusion_inpainting",  # restorative synthesis — before additive; BW-Cap 5 kHz
                "phase_06_frequency_restoration",  # additive BW-extension LAST — §2.46; BW-Cap 5 kHz
            ],
            "wire_recording": [
                "phase_12_wow_flutter_fix",
                "phase_24_dropout_repair",
                "phase_03_denoise",
                "phase_29_tape_hiss_reduction",
            ],
            "lacquer_disc": [
                "phase_01_click_removal",
                "phase_09_crackle_removal",
                "phase_03_denoise",
                "phase_29_tape_hiss_reduction",
                "phase_05_rumble_filter",  # Turntable-Rumpeln — §6.2a Pflicht
            ],
            "dat": [
                "phase_24_dropout_repair",
                "phase_02_hum_removal",
                "phase_23_spectral_repair",
            ],
            "cd_digital": [
                "phase_23_spectral_repair",
                "phase_06_frequency_restoration",
                "phase_40_loudness_normalization",
            ],
            "mp3_low": [
                "phase_23_spectral_repair",
                "phase_03_denoise",
                "phase_38_presence_boost",
                "phase_39_air_band_enhancement",
                "phase_06_frequency_restoration",
                "phase_50_spectral_repair",
            ],
            "mp3_high": [
                "phase_23_spectral_repair",
                "phase_39_air_band_enhancement",
                "phase_06_frequency_restoration",
                "phase_50_spectral_repair",
            ],
            "aac": [
                "phase_23_spectral_repair",
                "phase_38_presence_boost",
                "phase_06_frequency_restoration",
            ],
            "minidisc": [
                "phase_23_spectral_repair",
                "phase_06_frequency_restoration",
                "phase_07_harmonic_restoration",
            ],
            "streaming": [
                "phase_24_dropout_repair",
                "phase_23_spectral_repair",
                "phase_50_spectral_repair",
            ],
            "cassette": [  # §6.2a: IEC compact cassette: wow/flutter + hiss dominant; §2.46 ordering (2026-04-26)
                "phase_12_wow_flutter_fix",  # subtractive — wow/flutter
                "phase_29_tape_hiss_reduction",  # subtractive — tape hiss
                "phase_24_dropout_repair",  # subtractive/restorative — dropout
                "phase_59_modulation_noise_reduction",  # subtractive — modulation noise BEFORE additive
                "phase_06_frequency_restoration",  # additive BW-extension LAST — §2.46 invariant
            ],
        }
        _mat_key = material.value if hasattr(material, "value") else str(material)
        _priority_phases = _MATERIAL_PRIORITY_PHASES.get(_mat_key, [])
        self._last_material_priority_phases = tuple(_priority_phases)
        _selected_set_mat = set(selected)
        _mat_priority_added: list[str] = []
        for _mp in _priority_phases:
            if _mp not in _selected_set_mat:
                selected.append(_mp)
                _selected_set_mat.add(_mp)
                _mat_priority_added.append(_mp)
        # §6.2a [RELEASE_MUST] Carrier-Chain-Invariante: Pflichtphasen auch für Zwischenstufen
        # Wenn Kassette in der Kette steckt (z.B. vinyl→cassette→mp3), aber nicht primary_material ist,
        # müssen trotzdem alle cassette-Pflichtphasen aktiviert werden (§2.46a).
        if chain_info is not None:
            _chain_stages: list[str] = []
            if isinstance(chain_info, dict):
                _raw_stages = chain_info.get("chain", [])
                _chain_stages = [str(s) for s in _raw_stages if s] if isinstance(_raw_stages, list) else []
            for _stage in _chain_stages:
                if _stage == _mat_key:
                    continue  # primary material already handled above
                _stage_priorities = _MATERIAL_PRIORITY_PHASES.get(_stage, [])
                for _sp in _stage_priorities:
                    if _sp not in _selected_set_mat:
                        selected.append(_sp)
                        _selected_set_mat.add(_sp)
                        _mat_priority_added.append(_sp)
        if _mat_priority_added:
            logger.info(
                "📋 §6.2a Material-Pflichtphasen: %d ergänzt für material=%s: %s",
                len(_mat_priority_added),
                _mat_key,
                _mat_priority_added,
            )

        # ════════════════════════════════════
        # TIER 1.5 — Kausaldiagnose-Ergänzung (CausalDefectReasoner §2.6)
        # Bayesianische Ursachenanalyse (CAUSE_TO_PHASES) liefert Phasen,
        # die Severity-Schwellen in Tier 1 ggf. nicht aktiviert haben.
        # Nur aktiv wenn confidence ≥ 0.20 (Rauschunterdrückung bei Unsicherheit).
        # ════════════════════════════════════
        if causal_plan is not None and causal_plan.confidence >= 0.20:
            _selected_set = set(selected)
            _causal_added: list[str] = []
            for _cp_phase in causal_plan.recommended_phases:
                if _cp_phase not in _selected_set:
                    selected.append(_cp_phase)
                    _selected_set.add(_cp_phase)
                    _causal_added.append(_cp_phase)
            if _causal_added:
                logger.info(
                    "🧠 CausalReasoner §2.6 ergänzt %d Phase(n) (cause=%s, conf=%.2f): %s",
                    len(_causal_added),
                    causal_plan.primary_cause,
                    causal_plan.confidence,
                    _causal_added,
                )

        # ════════════════════════════════════
        # TIER 1.6 — Tonträgerkette (TontraegerketteDenker §2.2)
        # Phasen aus Multi-Carrier-Analyse (z. B. Vinyl→Kassette→MP3) werden
        # als Ergänzung zur internen Kausal-Analyse aktiviert.
        # ════════════════════════════════════
        if chain_info is not None:
            _chain_phases = chain_info.get("combined_phases", []) if isinstance(chain_info, dict) else []
            _chain_added: list[str] = []
            _chain_set = set(selected)
            for _chn_phase in _chain_phases:
                if _chn_phase not in _chain_set:
                    selected.append(_chn_phase)
                    _chain_set.add(_chn_phase)
                    _chain_added.append(_chn_phase)
            if _chain_added:
                _complexity = chain_info.get("chain_complexity", 0.0) if isinstance(chain_info, dict) else 0.0
                logger.info(
                    "🔗 TontraegerketteDenker §2.2 ergänzt %d Phase(n) (complexity=%.2f): %s",
                    len(_chain_added),
                    _complexity,
                    _chain_added,
                )

        # ════════════════════════════════════
        # TIER 1.7 — DefektDenker Heuristik-Ergänzung (§2.1)
        # Heuristische Phasen-Empfehlungen (DSP-basiert) ergänzen die
        # Bayesianische CausalPlan-Selektion aus Tier 1.5. Schwelle ≥ 0.15
        # (niedriger als CausalReasoner 0.20 — Heuristiken sind präziser).
        # ════════════════════════════════════
        if defekt_hint is not None:
            _dh_conf = float(defekt_hint.get("confidence", 0.0)) if isinstance(defekt_hint, dict) else 0.0
            if _dh_conf >= 0.15:
                _dh_phases = defekt_hint.get("recommended_phases", []) if isinstance(defekt_hint, dict) else []
                _dh_added: list[str] = []
                _dh_set = set(selected)
                for _dh_phase in _dh_phases:
                    if _dh_phase not in _dh_set:
                        selected.append(_dh_phase)
                        _dh_set.add(_dh_phase)
                        _dh_added.append(_dh_phase)
                if _dh_added:
                    logger.info(
                        "🔍 DefektDenker §2.1 ergänzt %d Phase(n) (confidence=%.2f): %s",
                        len(_dh_added),
                        _dh_conf,
                        _dh_added,
                    )

        # ════════════════════════════════════
        # TIER 1.8 — Goal-Gap Phase Injection (§2.56 Goal-Weight-Driven)
        # Wenn ein musikalisches Ziel hohe song-spezifische Wichtigkeit hat
        # (weight ≥ 1.4), aber keine einzige zugehörige Phase vom DefectScanner
        # oder CausalReasoner ausgewählt wurde, wird die primäre Serving-Phase
        # injiziert. Nur broadly-applicable, leichte Phasen — kein schweres ML,
        # keine material-spezifischen Phasen (die sind schon via TIER 0/1 aktiv).
        # §0 Primum non nocere: Injection ergänzt Coverage, ersetzt nie.
        # ════════════════════════════════════
        if goal_weights:
            # goal → liste primärer Phasen (erste verfügbare wird injiziert)
            _GOAL_GAP_SAFE_PHASES: dict[str, list[str]] = {
                "brillanz": ["phase_06_frequency_restoration"],
                "timbre_authentizitaet": ["phase_07_harmonic_restoration"],
                "artikulation": ["phase_08_transient_preservation"],
                "transparenz": ["phase_23_spectral_repair"],
                "waerme": ["phase_07_harmonic_restoration"],
                "micro_dynamics": ["phase_26_dynamic_range_expansion"],
                "spatial_depth": ["phase_48_stereo_imaging"],
            }
            _GOAL_GAP_THRESHOLD = 1.4
            _selected_set_18 = set(selected)
            _goal_gap_added: list[str] = []
            for _gg_goal, _gg_candidates in _GOAL_GAP_SAFE_PHASES.items():
                _gg_weight = float((goal_weights or {}).get(_gg_goal, 1.0))
                if _gg_weight < _GOAL_GAP_THRESHOLD:
                    continue
                # Prüfe ob bereits eine Phase aus dieser Ziel-Gruppe aktiv ist
                # (startswith "phase_XX_" where XX = phase number)
                _already_covered = any(
                    any(_sel.startswith("phase_" + _ggp.split("_")[1] + "_") for _sel in _selected_set_18)
                    for _ggp in _gg_candidates
                )
                if _already_covered:
                    continue
                # Injiziere primäre Phase für dieses Ziel
                for _ggp in _gg_candidates:
                    if _ggp not in _selected_set_18:
                        selected.append(_ggp)
                        _selected_set_18.add(_ggp)
                        _goal_gap_added.append(_ggp)
                        break
            if _goal_gap_added:
                logger.info(
                    "🎯 Goal-Gap §2.56 Tier-1.8: %d Phase(n) für hohe Ziel-Gewichtung (≥%.1f) injiziert: %s",
                    len(_goal_gap_added),
                    _GOAL_GAP_THRESHOLD,
                    _goal_gap_added,
                )

        # ════════════════════════════════════
        # TIER 2 — Frequenz- / Spektral-Restaurierung
        # ════════════════════════════════════

        # Bandbreitenerweiterung bei Verlusten
        if sev(DefectType.BANDWIDTH_LOSS) > 0.20 or sev(DefectType.COMPRESSION_ARTIFACTS) > 0.30:
            selected.append("phase_06_frequency_restoration")

        # Oberton-Restaurierung (tiefergehend)
        if sev(DefectType.BANDWIDTH_LOSS) > 0.30:
            selected.append("phase_07_harmonic_restoration")

        # Transienten-Schutz bei digitalen Artefakten
        if sev(DefectType.DIGITAL_ARTIFACTS) > 0.25:
            selected.append("phase_08_transient_preservation")

        # EQ-Korrektur für materialspezifische Frequenzgänge
        # Alle analogen Träger und DAT haben charakteristische Frequenzgangkurven
        if material in [
            MaterialType.SHELLAC,
            MaterialType.VINYL,
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
            MaterialType.DAT,
            MaterialType.MINIDISC,
            MaterialType.WAX_CYLINDER,
            MaterialType.WIRE_RECORDING,
            MaterialType.LACQUER_DISC,
        ]:
            selected.append("phase_04_eq_correction")

        # Dynamikbereich-Erweiterung bei über-Kompression
        # Loudness-War-Guard: Intentionale Kompression (era ≥ 2000 + digital) NICHT "reparieren"
        if (
            sev(DefectType.DYNAMIC_COMPRESSION_EXCESS) > 0.30 or sev(DefectType.COMPRESSION_ARTIFACTS) > 0.30
        ) and not _loudness_war_victim:
            selected.append("phase_26_dynamic_range_expansion")

        # Spektrale Gesamt-Reparatur (breiter zweiter Pass)
        if sev(DefectType.DIGITAL_ARTIFACTS) > 0.20 or sev(DefectType.COMPRESSION_ARTIFACTS) > 0.20:
            selected.append("phase_50_spectral_repair")

        # ════════════════════════════════════
        # TIER 3 — Stereo- / Phase-Verarbeitung
        # ════════════════════════════════════

        is_stereo = getattr(defect_result, "is_stereo", True)
        if not is_stereo:
            selected.append("phase_32_mono_to_stereo")  # Mono→Pseudo-Stereo

        # Stereo-Balance bei Imbalance
        if sev(DefectType.STEREO_IMBALANCE) > 0.15:
            selected.append("phase_15_stereo_balance")

        # Stereo-Breiten-Begrenzer bei extremer Imbalance
        if sev(DefectType.STEREO_IMBALANCE) > 0.40:
            selected.append("phase_33_stereo_width_limiter")

        # Mid/Side-Verarbeitung für Stereo-Quellen
        if is_stereo:
            selected.append("phase_34_mid_side_processing")

        # ════════════════════════════════════
        # TIER 4 — Instrument- / Vokal-Enhancement (PANNs-gesteuert, §2.9)
        # ════════════════════════════════════

        if vocals_detected:
            # Vibrato-Guard: Bei operatischem/klassischem Vibrato De-Esser nur bei
            # wirklich exzessiver Sibilanz aktivieren (Threshold ×2.5), da HF-Vibrato-
            # Obertöne sonst fälschlich als Sibilanz unterdrückt werden.
            if _operatic_vibrato:
                selected.append("phase_42_vocal_enhancement")  # Formant, Klarheit, Präsenz (vibrato-safe)
                # De-Esser-Phasen nur bei extremer Sibilance (bereits über Severity-Gate oben)
            else:
                selected += [
                    "phase_19_de_esser",  # Sibilant-Kontrolle (stimmtyp-adaptiv)
                    "phase_42_vocal_enhancement",  # Formant, Klarheit, Präsenz
                    "phase_43_ml_deesser",  # ML-De-Esser (zweiter Pass)
                ]
        if guitar_detected:
            selected.append("phase_44_guitar_enhancement")
        if brass_detected:
            selected.append("phase_45_brass_enhancement")
        if drums_detected:
            selected.append("phase_51_drums_enhancement")
        if piano_detected:
            selected.append("phase_52_piano_restoration")

        # Extended Instrument Routing — zusätzliche Instrumentfamilien (§2.9 Erweiterung)
        # Strings (Violin, Cello, Bowed) → Saiteninstrument-EQ + Transient-Schutz für Bogen-Anstrich
        if strings_detected:
            selected.append("phase_44_guitar_enhancement")  # Saiten-Oberton-Optimierung
            selected.append("phase_08_transient_preservation")  # Bogen-Attack bewahren
        # Woodwind (Flute, Clarinet, Oboe, Bassoon) → Blas-Formant-Enhancement + Air
        if woodwind_detected:
            selected.append("phase_45_brass_enhancement")  # Blas-Instrument-Formant-EQ
            selected.append("phase_39_air_band_enhancement")  # Atem-/Luft-Geräusche bewahren
        # Synth/Electronic → Spektral-Repair (breiter Pass), kein Instrument-spezifischer EQ
        if synth_detected:
            selected.append("phase_50_spectral_repair")  # Breitband-Spektral-Integrität
        # Organ/Church → Räumlichkeit + tiefes Fundament bewahren
        if organ_detected:
            selected.append("phase_37_bass_enhancement")  # Orgel-Pedal 16'/32' bewahren
            selected.append("phase_46_spatial_enhancement")  # Kirchenraum-Akustik

        # Dense-Ensemble-Guard: Bei ≥4 aktiven Instrumentfamilien (Orchester, Big Band etc.)
        # reduziere Instrument-spezifische Enhancement-Phasen — Separation ist bei dicht besetzten
        # Ensembles fehleranfällig und Einzelinstrument-EQs interferieren miteinander.
        # Behalte nur generisches Vocal- & Transient-Enhancement, entferne spezifische Instrument-Phasen.
        if _dense_ensemble:
            _instrument_specific = {
                "phase_44_guitar_enhancement",
                "phase_45_brass_enhancement",
                "phase_51_drums_enhancement",
                "phase_52_piano_restoration",
            }
            selected = [p for p in selected if p not in _instrument_specific]
            logger.info(
                "dense_ensemble_guard: %d instrument families active — "
                "removed specific instrument phases, keeping general approach",
                _active_families,
            )

        # Semantische Audio-Analyse (PANNs-Kontext-Verstehen)
        selected.append("phase_53_semantic_audio")

        # §2.36 LyricsGuidedEnhancement (RELEASE_MUST ab 9.10.x)
        # Phoneme-class saliency boosts (fricative/plosive/vowel) für Vokal-Intimität.
        # Aktivierung nur bei erkannten Vocals — Phase hat zusätzlichen internen
        # vocal_probability-Gate (< 0.30 → passthrough).
        if vocals_detected:
            selected.append("phase_58_lyrics_guided_enhancement")

        # ════════════════════════════════════
        # TIER 5 — Dynamik & Mastering
        # ════════════════════════════════════

        # Bass-Fundament (immer)
        selected.append("phase_37_bass_enhancement")

        # Präsenz (2–6 kHz) — bei Vokalinhalt.
        # §8.5A: Lossy-Codec-Material benötigt Presence-Repair auch ohne sichere Vocal-Detektion.
        _lossy_codec_no_vocal = (material in [MaterialType.MP3_LOW, MaterialType.MP3_HIGH, MaterialType.AAC]) and (
            not vocals_detected
        )
        if vocals_detected or _lossy_codec_no_vocal:
            selected.append("phase_38_presence_boost")

        # Air-Band Anhebung > 12 kHz — bei Bandbegrenzung oder analogem Material
        # WAX_CYLINDER und LACQUER_DISC: HF-Rekonstruktion nach physikalischer Bandbegrenzung
        _needs_airband = sev(DefectType.BANDWIDTH_LOSS) > 0.10 or material in [
            MaterialType.SHELLAC,
            MaterialType.TAPE,
            MaterialType.REEL_TAPE,
            MaterialType.WAX_CYLINDER,
            MaterialType.LACQUER_DISC,
            MaterialType.MP3_LOW,
            MaterialType.MP3_HIGH,
        ]
        if _needs_airband:
            selected.append("phase_39_air_band_enhancement")

        # Tape-Sättigungs-Emulation (Tape/REEL-Material — authentischer Charakter)
        # REEL_TAPE hat identischen Röhrensättigungs-Charakter wie TAPE
        if material in [MaterialType.TAPE, MaterialType.REEL_TAPE, MaterialType.SHELLAC]:
            selected.append("phase_22_tape_saturation")

        # Transparente Dynamik (psychoakustisch, genre-adaptiv)
        # §Loudness-War-Guard: Intentionale Kompression bei modernem Material nicht „reparieren"
        if _loudness_war_victim:
            logger.info(
                "🔊 Loudness-War-Guard: phase_54/phase_26/phase_35/phase_10 Dynamik-Phasen "
                "übersprungen — intentionale Kompression wird bewahrt"
            )
        else:
            if (
                material
                in [
                    MaterialType.CD_DIGITAL,
                    MaterialType.DAT,
                    MaterialType.MP3_LOW,
                    MaterialType.MP3_HIGH,
                    MaterialType.AAC,
                    MaterialType.STREAMING,
                ]
                or sev(DefectType.DYNAMIC_COMPRESSION_EXCESS) > 0.20
            ):
                selected.append("phase_54_transparent_dynamics")

        # Multiband-Kompression (wenn nicht über-komprimiert)
        if sev(DefectType.COMPRESSION_ARTIFACTS) < 0.40 and not _loudness_war_victim:
            selected.append("phase_35_multiband_compression")

        # Transient-Shaper (nach Drums-Enhancement)
        if drums_detected:
            selected.append("phase_36_transient_shaper")

        # Kompression & Limiting (wenn nicht bereits über-komprimiert).
        # §2.48 Dynamik-Interaktions-Guard: wenn phase_26 (Dynamic Range Expansion) aktiv ist,
        # darf phase_10 (Compression) NICHT zusätzlich komprimieren — das würde die Expansion
        # direkt rückgängig machen (expand → compress = Netto-Null, aber doppelte Artefaktlast).
        _dyn_expand_active = "phase_26_dynamic_range_expansion" in selected
        if sev(DefectType.COMPRESSION_ARTIFACTS) < 0.50 and not _loudness_war_victim:
            if not _dyn_expand_active:
                selected.append("phase_10_compression")
            else:
                logger.info(
                    "§2.48 Dynamik-Konflikt-Guard: phase_10 deaktiviert — phase_26 (Expansion) aktiv; "
                    "Komprimieren nach Expansion würde Restaurierung umkehren."
                )
            selected.append("phase_11_limiting")

        # Stereo-Enhancement
        if sev(DefectType.STEREO_IMBALANCE) < 0.40:
            selected.append("phase_13_stereo_enhancement")

        # Stereo-Breiten-Enhancement — inhibiert wenn Breiten-Limiter aktiv (§2.48 Interaktions-Guard).
        # Phase_48 würde die Arbeit von phase_33 (Breiten-Limiting bei STEREO_IMBALANCE > 0.40) direkt
        # rückgängig machen → gegenläufige Phasenwirkung verletzt §0 Primum non nocere und §2.45.
        if "phase_33_stereo_width_limiter" not in selected:
            selected.append("phase_48_stereo_width_enhancer")
        else:
            logger.info(
                "§2.48 Stereo-Konflikt-Guard: phase_48 deaktiviert — phase_33 aktiv "
                "(STEREO_IMBALANCE > 0.40); Breiten-Limiter hat Vorrang."
            )

        # Spatial-Enhancement (Raumklang)
        selected.append("phase_46_spatial_enhancement")

        # ════════════════════════════════════
        # TIER 6 — Finalisierung (immer, kanonische Reihenfolge §1.4)
        # ════════════════════════════════════
        selected += [
            "phase_16_final_eq",  # Finales EQ-Trimming
            "phase_17_mastering_polish",  # Finales Feintuning vor Loudness/TruePeak
            "phase_40_loudness_normalization",  # −14 LUFS (Streaming) / −18 (Archiv) — VOR TruePeak (EBU R128)
            "phase_47_truepeak_limiter",  # True-Peak −1.0 dBTP (EBU R128) — NACH LUFS-Normierung
            "phase_41_output_format_optimization",  # Dithering, Metadaten, Format
        ]

        # Duplikate entfernen, Reihenfolge beibehalten
        seen: set = set()
        unique: list[str] = []
        for p in selected:
            if p not in seen:
                seen.add(p)
                unique.append(p)

        logger.info(
            "🎛️  Phase-Selektion: Modus=%s, Material=%s, "
            "PANNs=[Vocals=%s Guitar=%s Brass=%s Drums=%s Piano=%s], "
            "Kausal=%s (conf=%.2f), "
            "%d Phasen ausgewählt",
            self.config.mode,
            material.value if hasattr(material, "value") else material,
            vocals_detected,
            guitar_detected,
            brass_detected,
            drums_detected,
            piano_detected,
            causal_plan.primary_cause if causal_plan is not None else "—",
            causal_plan.confidence if causal_plan is not None else 0.0,
            len(unique),
        )
        return unique

    def _optimize_phase_plan_intelligence(
        self,
        selected_phases: list[str],
        *,
        causal_plan: Any | None,
        pipeline_confidence: Any | None,
        restorability_score: float,
    ) -> list[str]:
        """Optimize phase plan with lightweight orchestration intelligence.

        Goals:
          1) Keep deterministic and safe phase ordering invariants.
          2) Boost high-confidence causal phases earlier in the chain.
          3) Preserve all selected phases (no phase removal in this step).
          4) (Phase 2) Utility-scored re-ranking when enable_phase_utility_scoring=True.

        Phase-2 Utility formula:
            utility(phase) = defect_severity_weight * expected_goal_impact / budget_cost_weight

        Phases below UTILITY_DROP_THRESHOLD are moved to end of list as low-priority candidates
        for budget-aware skipping by downstream PMGG, but are NOT removed here.
        Phases in _UTILITY_PROTECTED are never re-ranked by utility scoring alone.
        """
        phases = list(selected_phases)
        if not phases:
            self._phase_plan_intelligence = {
                "input_count": 0,
                "output_count": 0,
                "causal_boosted": [],
                "precedence_fixes": [],
                "pipeline_confidence": None,
                "restorability_score": float(restorability_score),
            }
            return phases

        _precedence_fixes: list[str] = []

        def _move_before(a: str, b: str) -> None:
            if a in phases and b in phases:
                ia = phases.index(a)
                ib = phases.index(b)
                if ia > ib:
                    phases.pop(ia)
                    ib = phases.index(b)
                    phases.insert(ib, a)
                    _precedence_fixes.append(f"{a}<{b}")

        # Apply ordering constraints iteratively until convergent (max 5 rounds).
        # Single-pass _move_before can leave transitive violations
        # (e.g. A<B then B<C moves B earlier, undoing A<B).
        for _conv_round in range(5):
            _fixes_before = len(_precedence_fixes)

            # Safety ordering constraints (quality-preserving orchestration invariants)
            _move_before("phase_24_dropout_repair", "phase_55_diffusion_inpainting")
            # Spectral-Band-Gap repair must run AFTER Diffusion-Inpainting:
            # phase_55 fills temporal gaps (dropouts, analog voids) first;
            # phase_56 then patches frequency-domain gaps on the already-repaired
            # signal.  Reversed order would attempt band-gap repair on unfilled holes,
            # producing artefacting around dropout boundaries.
            _move_before("phase_55_diffusion_inpainting", "phase_56_spectral_band_gap_repair")
            _move_before("phase_57_print_through_reduction", "phase_29_tape_hiss_reduction")
            _move_before("phase_20_reverb_reduction", "phase_49_advanced_dereverb")
            _move_before("phase_16_final_eq", "phase_17_mastering_polish")
            _move_before("phase_17_mastering_polish", "phase_40_loudness_normalization")
            # EBU R128 §6.1 + Aurik spec §1.5 #10-#11: LUFS normalization MUST precede TruePeak
            # limiting. LUFS norm is a pure gain shift — applying it after TruePeak limiting
            # would re-scale all peaks, negating the limiter entirely.
            _move_before("phase_40_loudness_normalization", "phase_47_truepeak_limiter")
            _move_before("phase_47_truepeak_limiter", "phase_41_output_format_optimization")
            # Direct rule so phase_40 precedes phase_41 even when phase_47 is absent.
            _move_before("phase_40_loudness_normalization", "phase_41_output_format_optimization")

            # Signal-processing-chain ordering (wissenschaftlich korrekte Reihenfolge)
            # Reverb reduction before noise gate: reverb tails blur gate thresholds;
            # after dereverb true silence/noise floor transitions are cleanly exposed
            # (SGMSE+ 2022, WPE; iZotope RX 11 recommended chain)
            _move_before("phase_20_reverb_reduction", "phase_18_noise_gate")
            # Impulse noise removal before broadband NR (prevents impulse energy smearing)
            _move_before("phase_01_click_removal", "phase_03_denoise")
            _move_before("phase_01_click_removal", "phase_27_click_pop_removal")
            # Surface noise profiling before crackle removal (profile-basierte Methode)
            _move_before("phase_28_surface_noise_profiling", "phase_09_crackle_removal")
            # Narrow-band (hum) before broadband NR
            _move_before("phase_02_hum_removal", "phase_03_denoise")
            # DC/click cleanup before wow/flutter correction.
            # Otherwise timing correction can smear click impulses and violate §7.5a.
            _move_before("phase_01_click_removal", "phase_12_wow_flutter_fix")
            # Denoise before frequency extension (clean before reconstruct)
            _move_before("phase_03_denoise", "phase_06_frequency_restoration")
            # Frequency restoration before harmonic restoration (Grundfrequenz vor Obertöne)
            _move_before("phase_06_frequency_restoration", "phase_07_harmonic_restoration")
            # Wow/flutter pitch correction before speed/pitch correction
            _move_before("phase_12_wow_flutter_fix", "phase_31_speed_pitch_correction")
            # Transient preservation before transient shaping
            _move_before("phase_08_transient_preservation", "phase_36_transient_shaper")
            # First spectral repair pass before second pass
            _move_before("phase_23_spectral_repair", "phase_50_spectral_repair")
            # Late-stage click/crackle re-sweep for disc materials (vinyl, shellac):
            # phase_27 must run AFTER all spectral phases that can introduce impulse
            # artifacts (PGHI ringing in phase_29, STFT discontinuities in phase_23,
            # band-recombination transients in phase_14). Ordering ensures phase_27
            # captures and repairs crackle reintroduced by the spectral processing chain.
            _move_before("phase_50_spectral_repair", "phase_27_click_pop_removal")
            _move_before("phase_29_tape_hiss_reduction", "phase_27_click_pop_removal")
            _move_before("phase_23_spectral_repair", "phase_27_click_pop_removal")
            # Vocal chain guard: classic de-esser before vocal enhancement
            _move_before("phase_19_de_esser", "phase_42_vocal_enhancement")
            # Vocal chain guard: classical de-esser before ML de-esser refinement
            _move_before("phase_19_de_esser", "phase_43_ml_deesser")
            # §2.36 LGE after vocal enhancement chain (de-esser → vocal_enhancement → ML de-esser → LGE)
            _move_before("phase_42_vocal_enhancement", "phase_58_lyrics_guided_enhancement")
            _move_before("phase_43_ml_deesser", "phase_58_lyrics_guided_enhancement")
            # Spatial chain guard: room enhancement before stereo width expansion
            _move_before("phase_46_spatial_enhancement", "phase_48_stereo_width_enhancer")

            # §2.46 [RELEASE_MUST] Carrier-Chain-Inversion ordering (v9.10.123)
            # Tier order (invers zur Aufnahmekette):
            #   Tier 1 ADC (DC, Quantisierung)  →  Tier 2 Playback (RIAA, Azimuth, Wow/Flutter)
            #   →  Tier 3 Aging (Crackle, Dropout)  →  Tier 4 Carrier Encoding (Tape Hiss, Surface Noise)
            #   →  Tier 5 Mixer/Preamp PRESERVE  →  Tier 6 Studio Room PRESERVE
            #
            # Tier 1 → Tier 2: DC-Offset (ADC) vor Azimuth/Wow+Flutter (Playback)
            _move_before("phase_30_dc_offset_removal", "phase_25_azimuth_correction")
            _move_before("phase_30_dc_offset_removal", "phase_12_wow_flutter_fix")
            # Tier 2 → Tier 3: Playback-Verzerrungen vor Alterungsschäden
            _move_before("phase_25_azimuth_correction", "phase_09_crackle_removal")
            _move_before("phase_25_azimuth_correction", "phase_24_dropout_repair")
            _move_before("phase_12_wow_flutter_fix", "phase_09_crackle_removal")
            _move_before("phase_12_wow_flutter_fix", "phase_24_dropout_repair")
            # Tier 3 → Tier 4: Alterungsschäden (Crackle, Dropout) vor Trägermedium-Rauschen
            _move_before("phase_09_crackle_removal", "phase_29_tape_hiss_reduction")
            _move_before("phase_24_dropout_repair", "phase_29_tape_hiss_reduction")
            # §2.46 Subtraktiv-vor-Additiv-Invariante: alle NR/De-Reverb-Phasen (Stufe 4 subtraktiv)
            # müssen vor Harmonik-/Frequenzrekonstruktion (Stufe 5 additiv) laufen.
            # Sonst werden frisch rekonstruierte Obertöne sofort wieder weggefiltert.
            # Ohne diese Regeln kann bei Tape+Vinyl-Material (phase_29 + phase_07 aktiv,
            # aber phase_03 inaktiv) die Reihenfolge unkontrolliert verletzt werden.
            _move_before("phase_29_tape_hiss_reduction", "phase_07_harmonic_restoration")
            _move_before("phase_29_tape_hiss_reduction", "phase_06_frequency_restoration")
            _move_before("phase_49_advanced_dereverb", "phase_07_harmonic_restoration")
            _move_before("phase_20_reverb_reduction", "phase_07_harmonic_restoration")
            # §7.2 CAUSE_TO_PHASES["azimuth_error"]: phase_14 (L/R Phasenkonsistenz) vor
            # phase_25 (Kopfausrichtungs-EQ). Bei Aktivierung über AZIMUTH_ERROR-Defektpfad
            # wurde in _select_phases die Reihenfolge bereits korrekt eingetragen; diese Regel
            # fängt Edge-Cases ab, in denen phase_25 über andere Pfade früher eingetragen
            # wurde (z.B. PHASE_ISSUES-Gate vor AZIMUTH_ERROR-Gate).
            _move_before("phase_14_phase_correction", "phase_25_azimuth_correction")
            # §2.48 Groove-Echo vor Reverb-Reduction: Groove-Echo-Cancellation (RPM-Template)
            # muss auf dem originalen Echo-Signal arbeiten, bevor der allgemeine Dereverber
            # die Echo-Charakteristik zerstört (SGMSE+ kann Groove-Echo als Raumhall
            # fehlidentifizieren und entfernen).
            _move_before("phase_61_groove_echo_cancellation", "phase_20_reverb_reduction")
            _move_before("phase_61_groove_echo_cancellation", "phase_49_advanced_dereverb")

            # §2.46 [RELEASE_MUST] EQ-Korrektur (RIAA/Tape-Entzerrung) = Tier 2 Playback.
            # Muss VOR Tier-3-Alterungsschäden (Clicks, Crackle, Dropout) UND VOR
            # Tier-4-Carrier-NR (Broadband NR, Tape Hiss) stehen.
            # Ohne diese Regeln läuft phase_03/phase_29 auf spectrum-unkorriertem Audio:
            # die NR adaptiert sich an den falschen Equalizer-Stand und schneidet nach
            # der RIAA-Inversion Musik-Energie, die sie für Rauschen hielt. Außerdem
            # arbeiten Crackle/Dropout-Detektoren besser auf dem korrekt entzerrten Signal.
            _move_before("phase_30_dc_offset_removal", "phase_04_eq_correction")
            _move_before("phase_05_rumble_filter", "phase_04_eq_correction")
            _move_before("phase_04_eq_correction", "phase_01_click_removal")
            _move_before("phase_04_eq_correction", "phase_09_crackle_removal")
            _move_before("phase_04_eq_correction", "phase_24_dropout_repair")
            _move_before("phase_04_eq_correction", "phase_03_denoise")
            _move_before("phase_04_eq_correction", "phase_29_tape_hiss_reduction")
            # Surface-Noise-Profiling (phase_28) muss VOR der Verwendung des Profils in
            # phase_29 (Tape Hiss) und phase_09 (Crackle) laufen.
            _move_before("phase_28_surface_noise_profiling", "phase_29_tape_hiss_reduction")
            # Vinyl-spezifische Groove-Defekte (Tier 3 Aging) vor Carrier-NR (Tier 4 subtraktiv):
            # Inner-Groove-Distortion und Groove-Echo sind physikalische Vinyl-Artefakte, die
            # auf dem EQ-korrigierten aber noch nicht NR-bearbeiteten Signal detektiert werden müssen.
            _move_before("phase_60_inner_groove_distortion_repair", "phase_03_denoise")
            _move_before("phase_60_inner_groove_distortion_repair", "phase_29_tape_hiss_reduction")
            _move_before("phase_61_groove_echo_cancellation", "phase_03_denoise")
            _move_before("phase_61_groove_echo_cancellation", "phase_29_tape_hiss_reduction")

            if len(_precedence_fixes) == _fixes_before:
                break  # Converged — no further reordering needed

        # Causal boost: if confidence is high, front-load top causal phases after base cleanup.
        _causal_boosted: list[str] = []
        try:
            _c_conf = float(causal_plan.confidence) if causal_plan is not None else 0.0
        except Exception:
            _c_conf = 0.0
        if causal_plan is not None and _c_conf >= 0.35:
            _base_anchor = 2  # after phase_30 + phase_05 baseline
            _non_boostable = {
                "phase_16_final_eq",
                "phase_17_mastering_polish",
                "phase_47_truepeak_limiter",
                "phase_40_loudness_normalization",
                "phase_41_output_format_optimization",
            }
            for _p in list(getattr(causal_plan, "recommended_phases", []))[:2]:
                if _p in phases and _p not in _non_boostable:
                    _old = phases.index(_p)
                    if _old > _base_anchor:
                        phases.pop(_old)
                        phases.insert(_base_anchor, _p)
                        _causal_boosted.append(_p)
                        _base_anchor += 1

        # -----------------------------------------------------------------------
        # Phase 2: Utility-scored re-ranking (feature-gated)
        # -----------------------------------------------------------------------
        # utility(phase) = defect_severity_weight * expected_goal_impact / budget_cost_weight
        # All weights are calibrated on 500 AMRB test items; update via AMRB regression.
        # Phases below UTILITY_DROP_THRESHOLD are moved toward the end so that the
        # PMGG per-phase gate can evict them first when the RT budget is tight.
        # No phase is ever *removed* here — only re-ordered.
        # -----------------------------------------------------------------------
        _UTILITY_DROP_THRESHOLD: float = 0.12
        # Phases whose position must never be altered by utility scoring alone
        _UTILITY_PROTECTED: frozenset = frozenset(
            {
                "phase_30_dc_offset_removal",
                "phase_05_noise_floor_analysis",
                "phase_16_final_eq",
                "phase_17_mastering_polish",
                "phase_47_truepeak_limiter",
                "phase_40_loudness_normalization",
                "phase_41_output_format_optimization",
            }
        )
        # Per-phase static weights: (defect_severity_weight, expected_goal_impact, budget_cost_weight)
        # Tuned from AMRB benchmarks — higher utility → earlier execution priority.
        _PHASE_WEIGHTS: dict[str, tuple[float, float, float]] = {
            # Core cleanup — high impact, low cost
            "phase_01_noise_reduction": (0.90, 0.95, 0.40),
            "phase_02_click_removal": (0.80, 0.85, 0.30),
            "phase_03_rumble_removal": (0.70, 0.75, 0.25),
            "phase_04_hum_removal": (0.85, 0.88, 0.35),
            "phase_06_vinyl_crackle_removal": (0.85, 0.90, 0.45),
            "phase_09_banquet_vinyl_ml": (0.88, 0.92, 0.50),
            "phase_07_dropout_repair_nmf": (0.75, 0.80, 0.60),
            "phase_08_azimuth_correction": (0.60, 0.70, 0.35),
            "phase_10_riaa_curve_correction": (0.78, 0.85, 0.30),
            "phase_11_transient_restoration": (0.65, 0.78, 0.55),
            "phase_12_harmonic_restoration": (0.70, 0.82, 0.65),
            "phase_13_stereo_restoration": (0.60, 0.72, 0.50),
            "phase_14_dynamic_range_restoration": (0.72, 0.80, 0.60),
            "phase_15_frequency_restoration": (0.68, 0.78, 0.55),
            "phase_18_vocal_enhancement": (0.80, 0.88, 0.70),
            "phase_19_de_essing": (0.55, 0.65, 0.30),
            "phase_20_reverb_reduction": (0.75, 0.82, 0.75),
            "phase_21_pitch_correction": (0.65, 0.75, 0.80),
            "phase_22_tape_saturation_emulation": (0.50, 0.60, 0.35),
            "phase_23_clipping_repair": (0.88, 0.90, 0.60),
            "phase_24_dropout_repair": (0.78, 0.84, 0.70),
            "phase_25_wow_flutter_correction": (0.72, 0.80, 0.65),
            "phase_26_print_through_reduction": (0.60, 0.70, 0.50),
            "phase_27_bias_correction": (0.68, 0.76, 0.45),
            "phase_28_bandwidth_extension": (0.58, 0.72, 0.90),
            "phase_29_tape_hiss_reduction": (0.82, 0.86, 0.45),
            "phase_31_stem_separation": (0.70, 0.85, 0.95),
            "phase_32_vocal_isolation": (0.72, 0.87, 0.95),
            "phase_33_music_enhancement": (0.65, 0.78, 0.85),
            "phase_34_mid_side_processing": (
                0.62,
                0.72,
                0.65,
            ),  # M/S dynamics (stereo-field restoration, moderate impact)
            "phase_35_psychoacoustic_enhancement": (0.55, 0.68, 0.60),
            "phase_36_spatial_enhancement": (0.52, 0.65, 0.70),
            "phase_37_codec_artifact_removal": (0.80, 0.87, 0.55),
            "phase_38_presence_boost": (0.70, 0.80, 0.50),
            "phase_39_air_band_enhancement": (0.45, 0.60, 0.80),
            "phase_42_spectral_coherence": (0.60, 0.72, 0.60),
            "phase_43_ml_de_esser": (0.55, 0.65, 0.45),
            "phase_44_guitar_enhancement": (0.60, 0.70, 0.55),
            "phase_45_brass_enhancement": (0.58, 0.68, 0.65),
            "phase_46_spatial_enhancement": (0.55, 0.65, 0.60),
            "phase_48_stereo_width_enhancer": (0.68, 0.80, 0.80),
            "phase_49_advanced_dereverb": (0.72, 0.80, 0.85),
            "phase_50_spectral_repair": (0.62, 0.74, 0.60),
            "phase_51_harmonic_guard": (0.65, 0.75, 0.55),
            "phase_52_breathiness_guard": (0.50, 0.60, 0.40),
            "phase_53_emotional_arc_preservation": (0.58, 0.70, 0.70),
            "phase_54_artifact_suppression": (0.72, 0.80, 0.55),
            "phase_55_diffusion_inpainting": (0.70, 0.82, 0.90),
            "phase_56_reference_mastering": (0.55, 0.70, 0.85),
            "phase_57_print_through_reduction": (0.65, 0.75, 0.50),
            "phase_58_lyrics_guided_enhancement": (
                0.72,
                0.82,
                0.75,
            ),  # LGE §2.36: phoneme-aligned DSP → high vocal quality impact
            "phase_59_modulation_noise_reduction": (0.68, 0.78, 0.55),
            "phase_60_inner_groove_distortion_repair": (0.65, 0.75, 0.50),
            "phase_61_groove_echo_cancellation": (0.62, 0.72, 0.55),
            "phase_62_crosstalk_cancellation": (0.60, 0.70, 0.60),
            "phase_63_intermodulation_reduction": (0.64, 0.74, 0.55),
            "phase_64_tape_splice_repair": (0.70, 0.76, 0.40),
        }

        def _phase_num_prefix(phase_id: str) -> str | None:
            """Return stable prefix like 'phase_46' for alias matching."""
            parts = phase_id.split("_", 2)
            if len(parts) >= 2 and parts[0] == "phase" and parts[1].isdigit():
                return f"phase_{parts[1]}"
            return None

        # Alias map for legacy/current naming drift: same phase number shares weight/protection.
        _phase_num_to_weight: dict[str, tuple[float, float, float]] = {}
        for _pid, _w in _PHASE_WEIGHTS.items():
            _pref = _phase_num_prefix(_pid)
            if _pref is not None and _pref not in _phase_num_to_weight:
                _phase_num_to_weight[_pref] = _w

        _protected_prefixes: set[str] = {
            _pref for _pref in (_phase_num_prefix(p) for p in _UTILITY_PROTECTED) if _pref is not None
        }

        def _is_utility_protected(phase_id: str) -> bool:
            if phase_id in _UTILITY_PROTECTED:
                return True
            _pref = _phase_num_prefix(phase_id)
            return _pref in _protected_prefixes if _pref is not None else False

        _utility_reranked: list[str] = []
        _use_utility = getattr(self.config, "enable_phase_utility_scoring", False)
        if _use_utility and len(phases) > 4:
            # Scale defect_severity_weight by restorability so that poor material
            # gets aggressively cleaned while good material keeps expensive extras.
            _rscore = max(0.01, min(1.0, restorability_score / 100.0))
            _severity_scale = 1.0 + (1.0 - _rscore) * 0.30  # range 1.0 → 1.30

            def _utility(phase_id: str) -> float:
                _w = _PHASE_WEIGHTS.get(phase_id)
                if _w is None:
                    _pref = _phase_num_prefix(phase_id)
                    if _pref is not None:
                        _w = _phase_num_to_weight.get(_pref)
                if _w is None:
                    return 0.50  # unknown phase → neutral utility
                dsev, goal_imp, cost = _w
                effective_dsev = min(1.0, dsev * _severity_scale)
                return (effective_dsev * goal_imp) / max(0.01, cost)

            # Partition into protected, high-utility, and low-utility groups
            _protected_phases = [p for p in phases if _is_utility_protected(p)]
            _eligible_phases = [p for p in phases if not _is_utility_protected(p)]

            # Score and split
            _scored = [(p, _utility(p)) for p in _eligible_phases]
            _high = [p for p, u in _scored if u >= _UTILITY_DROP_THRESHOLD]
            _low = [p for p, u in _scored if u < _UTILITY_DROP_THRESHOLD]

            # High-utility phases: sorted descending (highest impact first) but capped
            # to preserve relative ordering of phases with very similar scores (±0.05)
            _STABLE_BAND: float = 0.05
            _high_sorted = sorted(_high, key=lambda p: -_utility(p))
            # Stabilisation: don't reorder pairs whose utility difference is within band
            _stabilised: list[str] = []
            _remaining_h = list(_high_sorted)
            while _remaining_h:
                _cur = _remaining_h.pop(0)
                # If next phase is within stable band, preserve original relative order
                if _remaining_h:
                    _nxt = _remaining_h[0]
                    if abs(_utility(_cur) - _utility(_nxt)) <= _STABLE_BAND:
                        # Keep original relative ordering for this pair
                        _orig_cur = phases.index(_cur) if _cur in phases else 999
                        _orig_nxt = phases.index(_nxt) if _nxt in phases else 999
                        if _orig_nxt < _orig_cur:
                            _stabilised.append(_nxt)
                            _remaining_h.pop(0)
                            _stabilised.append(_cur)
                            continue
                _stabilised.append(_cur)

            # Rebuild: protected phases retain their original absolute positions;
            # high-utility fill remaining slots; low-utility go to end.
            _final: list[str] = []
            _high_iter = iter(_stabilised)
            _low_iter = iter(sorted(_low, key=lambda p: phases.index(p) if p in phases else 999))
            _protected_idx = {p: phases.index(p) for p in _protected_phases if p in phases}
            _all_idx = sorted(range(len(phases)), key=lambda i: i)
            _insert_positions = {p: phases.index(p) for p in _protected_phases if p in phases}
            # Reconstruct phase list preserving protected absolute positions
            _slot_phases: list[str | None] = [None] * len(phases)
            for p, idx in _insert_positions.items():
                _slot_phases[idx] = p
            for _j in range(len(_slot_phases)):
                if _slot_phases[_j] is None:
                    try:
                        _slot_phases[_j] = next(_high_iter)
                    except StopIteration:
                        with contextlib.suppress(StopIteration):
                            _slot_phases[_j] = next(_low_iter)
            # Fill any remaining low-utility phases at the end
            _filled = [p for p in _slot_phases if p is not None]
            _placed = set(_filled)
            _remaining_low = [p for p in _low if p not in _placed]
            _remaining_high = [p for p in _stabilised if p not in _placed]
            phases = _filled + _remaining_high + _remaining_low
            _utility_reranked = [
                p
                for p in phases
                if p not in _UTILITY_PROTECTED
                and p in dict(_scored)
                and dict(_scored).get(p, 0.5) >= _UTILITY_DROP_THRESHOLD
            ]
            if _utility_reranked:
                logger.info(
                    "🧮 Phase-Utility-Scoring: %d phases re-ranked (low-utility→end: %d), "
                    "restorability=%.0f, severity_scale=%.2f",
                    len(_utility_reranked),
                    len(_low),
                    restorability_score,
                    _severity_scale,
                )

        self._phase_plan_intelligence = {
            "input_count": len(selected_phases),
            "output_count": len(phases),
            "causal_boosted": _causal_boosted,
            "precedence_fixes": _precedence_fixes,
            "utility_scoring_active": _use_utility,
            "utility_reranked_count": len(_utility_reranked),
            "utility_low_priority_count": len(_low) if _use_utility and len(phases) > 4 else 0,
            "pipeline_confidence": (
                round(float(getattr(pipeline_confidence, "confidence", 0.0)), 4)
                if pipeline_confidence is not None
                else None
            ),
            "restorability_score": round(float(restorability_score), 2),
        }
        if _causal_boosted or _precedence_fixes:
            logger.info(
                "🧠 Phase-Plan-Intelligence: causal_boost=%s precedence_fixes=%d",
                _causal_boosted,
                len(_precedence_fixes),
            )
        return phases

    def _apply_phase_skipping(self, selected_phases: list[str], defect_result) -> tuple[list[str], dict[str, str]]:
        """
        Apply intelligent phase skipping to reduce processing time.

        Uses PhaseSkipper to analyze defect_result and skip phases that
        won't provide meaningful improvement (e.g., denoise when noise_floor < -60dB).

        Args:
            selected_phases: List of phase IDs selected by defect analysis
            defect_result: DefectScanResult from defect scanner

        Returns:
            Tuple of (filtered_phases, skip_reasons)
            - filtered_phases: List of phases after skipping
            - skip_reasons: Dict mapping skipped phase_id to reason
        """
        if not self.phase_skipper:
            return selected_phases, {}

        # Create DefectAnalysis object for PhaseSkipper
        # Note: PhaseSkipper expects a DefectAnalysis object with specific fields
        from backend.core.defect_analysis import DefectAnalysis, SourceMedium

        # Map MaterialType to SourceMedium
        medium_map = {
            MaterialType.VINYL: SourceMedium.VINYL,
            MaterialType.TAPE: SourceMedium.CASSETTE,  # Map tape to cassette (most common)
            MaterialType.REEL_TAPE: SourceMedium.REEL_TAPE,
            MaterialType.SHELLAC: SourceMedium.SHELLAC,
            MaterialType.WAX_CYLINDER: SourceMedium.SHELLAC,  # Closest groove-era profile for skipper heuristics
            MaterialType.LACQUER_DISC: SourceMedium.SHELLAC,  # Disc medium with shellac-like skip behavior
            MaterialType.WIRE_RECORDING: SourceMedium.CASSETTE,  # Tape-like transport/noise profile
            MaterialType.DAT: SourceMedium.DAT,
            MaterialType.CD_DIGITAL: SourceMedium.DIGITAL,
            MaterialType.MP3_LOW: SourceMedium.MP3_LOW,
            MaterialType.MP3_HIGH: SourceMedium.MP3_HIGH,
            MaterialType.AAC: SourceMedium.AAC,
            MaterialType.MINIDISC: SourceMedium.MINIDISC,
            MaterialType.STREAMING: SourceMedium.STREAMING,
            MaterialType.UNKNOWN: SourceMedium.UNKNOWN,
        }

        # §Hebel-1 Psychoacoustic-Salience-aware Skip:
        # PerceptualSalienceEstimator has already adjusted DefectScore.severity
        # (annotate_defect_scores: severity *= (0.3 + 0.7 * mean_salience)).
        # We read severity directly — masked defects already carry reduced severity.
        # Additionally extract n_masked_events from metadata for fully-masked detection.
        def _salience_adjusted_severity(defect_type: DefectType) -> float:
            """Return severity adjusted by psychoacoustic masking AND detection confidence.

            Low-confidence detections (scanner uncertain whether defect is real) are
            dampened proportionally so that ambiguous scans on high-quality material
            do not trigger full-strength processing phases.
            Confidence-factor: max(0.35, sqrt(confidence)) — keeps a floor so even
            low-confidence detections remain plausible (never fully zeroed out).
            """
            _ds = defect_result.scores.get(defect_type)
            if _ds is None:
                return 0.0
            sev = float(_ds.severity)
            # §Confidence-Weighting (v9.11.1): dampen severity proportional to
            # detection confidence.  sqrt() gives a gentler curve than linear:
            # conf=1.00 → factor=1.00 (unchanged)
            # conf=0.50 → factor=0.71 (moderate damping)
            # conf=0.25 → factor=0.50 (strong damping)
            # conf=0.10 → factor=0.35 (floor — defect still considered plausible)
            import math as _math

            _conf = max(0.0, min(1.0, float(_ds.confidence)))
            _conf_factor = max(0.35, _math.sqrt(_conf))
            if _conf_factor < 0.98:  # only log when actually dampening
                logger.debug(
                    "§Confidence-Weighting: %s conf=%.2f → factor=%.3f sev %.3f→%.3f",
                    defect_type.value,
                    _conf,
                    _conf_factor,
                    sev,
                    sev * _conf_factor,
                )
            sev = sev * _conf_factor
            # If PerceptualSalienceEstimator ran, severity is already salience-scaled.
            # Extra guard: if ALL events are psychoacoustically masked → halve severity
            # so clearly inaudible defects don't trigger unnecessary phases.
            n_masked = int(_ds.metadata.get("n_masked_events", 0))
            n_salient = int(_ds.metadata.get("n_salient_events", 0))
            if n_masked > 0 and n_salient == 0 and n_masked >= 3:
                # Fully masked defect: reduce further (never to 0 — §2.45 guard)
                sev = max(sev * 0.5, sev * 0.3)
                logger.debug(
                    "§Hebel-1: %s fully masked (%d events) → severity %.3f",
                    defect_type.value,
                    n_masked,
                    sev,
                )
            return sev

        # Create DefectAnalysis (simplified, PhaseSkipper only needs key fields)
        # Note: Map DefectScanner severity scores to DefectAnalysis fields
        clicks_severity = _salience_adjusted_severity(DefectType.CLICKS)
        hum_severity = _salience_adjusted_severity(DefectType.HUM)
        hiss_severity = _salience_adjusted_severity(DefectType.HIGH_FREQ_NOISE)
        dropouts_severity = _salience_adjusted_severity(DefectType.DROPOUTS)

        noise_floor_db = max(-60.0, min(0.0, -60.0 + hiss_severity * 60.0))

        defect_analysis = DefectAnalysis(
            medium=medium_map.get(defect_result.material_type, SourceMedium.UNKNOWN),
            noise_floor_db=noise_floor_db,  # Convert severity to dB (0.0 → -60dB, 1.0 → 0dB)
            clipping_percentage=0.0,  # Not tracked by DefectScanner, use default
            click_count=int(clicks_severity * 100),  # Estimate: severity 0.5 = 50 clicks
            click_density=clicks_severity * 10.0,  # Estimate: severity 0.1 = 1 click/sec
            has_hum=hum_severity > 0.2,
            has_hiss=hiss_severity > 0.25,
            dropout_count=int(dropouts_severity * 20),  # Estimate: severity 0.05 = 1 dropout
        )

        # Get skip decisions from PhaseSkipper
        # Note: PhaseSkipper uses different phase enum, we need to map
        phase_map = {
            "phase_03_denoise": "phase_2_denoise",
            "phase_29_tape_hiss_reduction": "phase_2_denoise",
            "phase_04_eq_correction": None,  # No direct mapping
            "phase_01_click_removal": "phase_5_click_removal",
            "phase_02_hum_removal": "phase_6_dehum",
            "phase_24_dropout_repair": "phase_7_dropout_repair",
            "phase_23_spectral_repair": "phase_8_spectral_repair",
        }

        filtered_phases = []
        skip_reasons = {}

        for phase_id in selected_phases:
            # Check if phase can be skipped
            should_skip = False
            skip_reason = ""

            # Map to PhaseSkipper's phase enum
            skipper_phase = phase_map.get(phase_id)

            if skipper_phase:
                # Use PhaseSkipper logic
                if skipper_phase == "phase_2_denoise":
                    # Skip denoise if noise floor very low
                    if defect_analysis.noise_floor_db <= -60.0 and not defect_analysis.has_hiss:
                        should_skip = not self.config.phase_skipping_conservative
                        skip_reason = f"Very low noise floor ({defect_analysis.noise_floor_db:.1f} dB)"
                elif skipper_phase == "phase_5_click_removal":
                    # Skip click removal if minimal clicks
                    if defect_analysis.click_count == 0:
                        should_skip = not self.config.phase_skipping_conservative
                        skip_reason = "No significant clicks detected"
                elif skipper_phase == "phase_6_dehum":
                    # Skip dehum if no hum detected
                    if not defect_analysis.has_hum:
                        should_skip = not self.config.phase_skipping_conservative
                        skip_reason = "No hum detected"
                elif skipper_phase == "phase_7_dropout_repair":
                    # Never skip dropout repair if selected (critical)
                    should_skip = False
                elif skipper_phase == "phase_8_spectral_repair":
                    # Skip spectral repair if digital source is clean
                    if defect_analysis.medium == SourceMedium.DIGITAL and defect_analysis.noise_floor_db < -50.0:
                        should_skip = not self.config.phase_skipping_conservative
                        skip_reason = "Clean digital source"

            if should_skip:
                skip_reasons[phase_id] = skip_reason
                logger.debug("Skipping %s: %s", phase_id, skip_reason)
            else:
                filtered_phases.append(phase_id)

        return filtered_phases, skip_reasons

    def _profiled_phase_call(self, phase, audio: np.ndarray, **kwargs):
        """Führt eine Phase mit Zeit- und (optional) Speicherprofiling aus.

        Wenn self._active_global_plan gesetzt ist, werden phasenspezifische
        Parameter aus dem Globalplan in kwargs eingeschleust — sofern die Phase
        sie nicht bereits explizit übergeben hat (explizit gewinnt).
        """
        # Get phase metadata for logging
        phase_metadata = phase.get_metadata()
        phase_name = f"{phase_metadata.name} ({phase_metadata.phase_id})"
        _strength_explicit = "strength" in kwargs
        _team_context_enabled = bool(kwargs.pop("phase_team_context_enabled", False))

        # §Dach: GlobalPlan-Parameter einschleusen (ohne explizite Werte zu überschreiben)
        _gp = getattr(self, "_active_global_plan", None)
        if _gp is not None:
            try:
                _phase_params = _gp.get_phase_params(phase_metadata.phase_id)
                for _pk, _pv in _phase_params.items():
                    if _pk not in kwargs:
                        kwargs[_pk] = _pv
            except Exception as _gp_exc:
                logger.debug("GlobalPlan-Parameter für Phase %s fehlgeschlagen: %s", phase_metadata.phase_id, _gp_exc)

        # §2.14+ Kontextfluss: Ära/Genre/BPM/Profil-Daten aus self._restoration_context
        # in ALLE Phasen injizieren (zentrale Injection statt verteilter kwargs).
        _rctx = getattr(self, "_restoration_context", None)
        if _rctx is not None:
            for _ck, _cv in _rctx.items():
                if _ck not in kwargs and _cv is not None:
                    kwargs[_ck] = _cv

        # Normalisierung: material_type und material immer als MaterialType-Enum übergeben
        # Phasen haben unterschiedliche Signaturen (material vs. material_type), beide abdecken
        for _mk in ("material_type", "material"):
            _mv = kwargs.get(_mk)
            if _mv is not None and isinstance(_mv, str):
                try:
                    from backend.core.defect_scanner import MaterialType as _MT

                    kwargs[_mk] = _MT(_mv)
                except Exception as _mt_exc:
                    logger.debug("MaterialType-Konvertierung für '%s'='%s' fehlgeschlagen: %s", _mk, _mv, _mt_exc)
        # Stelle sicher, dass beide Keys vorhanden sind (falls nur einer übergeben wurde)
        if "material_type" in kwargs and "material" not in kwargs:
            kwargs["material"] = kwargs["material_type"]
        elif "material" in kwargs and "material_type" not in kwargs:
            kwargs["material_type"] = kwargs["material"]

        # §2.47 TDP Stem-aware NR: Automatische Aktivierung für phase_03_denoise
        # wenn quality/maximum Modus und analoges Material — "auto" lässt die Phase
        # selbst entscheiden (qualitätsmodus × material_type). Advisory-only: explicit
        # caller-Werte überschreiben die Injection nicht.
        _qmode_str = str(kwargs.get("quality_mode", getattr(self.config.mode, "value", "quality"))).strip().lower()
        _quality_first_unleashed = bool(
            self.is_studio_mode() or _qmode_str in {"quality", "maximum", "studio", "studio2026"}
        )
        kwargs.setdefault("quality_first_unleashed", _quality_first_unleashed)

        if phase_metadata.phase_id == "phase_03_denoise":
            kwargs.setdefault("tdp_stem_aware_nr", "auto")

        _song_calibration = getattr(self, "_song_calibration_profile", None)
        if isinstance(_song_calibration, dict) and _song_calibration:
            kwargs.setdefault("song_calibration_profile", dict(_song_calibration))

        # §2.56 Song-Goal-Importance context for phase-local adaptive guards
        # (e.g. clarity guards in dereverb phases).
        _sgw = getattr(self, "_song_goal_weights", None)
        if isinstance(_sgw, dict) and _sgw:
            kwargs.setdefault("song_goal_weights", dict(_sgw))

        # Provide restorability as scalar context if available for adaptive limits.
        _rest_ctx = getattr(self, "_last_restorability_score", None)
        if isinstance(_rest_ctx, (int, float)):
            kwargs.setdefault("restorability_score", float(_rest_ctx))

        # Team-Modus: Folgephasen erhalten Kontext über bereits ausgeführte Reparaturen,
        # damit sie diese nicht als neue Defekte interpretieren.
        if _team_context_enabled:
            _ptc = getattr(self, "_phase_team_context", None)
            if isinstance(_ptc, dict) and _ptc:
                kwargs.setdefault("prior_phase_context", dict(_ptc))
                kwargs.setdefault("phase_team_mode", True)

            # §2.29e CONFLICT_REGISTRY: Prüfe ob die aktuelle Phase vorherige Reparaturen
            # rückgängig machen könnte. Falls ja, conflict_with_prior_phases injizieren.
            try:
                from backend.core.phase_ontology import get_conflict_phases as _get_conflict_phases

                _pid_str = str(getattr(phase_metadata, "phase_id", "") or "")
                if _pid_str:
                    _prior_ids = list((_ptc or {}).get("executed_phase_ids", []))
                    _conflict_priors: list[str] = []
                    for _prior_id in _prior_ids:
                        _conflicting = _get_conflict_phases(_prior_id)
                        if any(_pid_str.startswith(_cp) for _cp in _conflicting):
                            _conflict_priors.append(_prior_id)
                    if _conflict_priors:
                        kwargs.setdefault("conflict_with_prior_phases", _conflict_priors)
                        logger.debug(
                            "§2.29e CONFLICT_REGISTRY: %s may conflict with repaired content of %s",
                            _pid_str,
                            _conflict_priors,
                        )
            except Exception as _conf_exc:
                logger.debug("CONFLICT_REGISTRY lookup skipped (non-blocking): %s", _conf_exc)

        # §Hebel-3 PhaseConductor: Strength-Hint injizieren wenn Conductor Empfehlung hat.
        # Nur wenn 'strength' noch nicht explizit gesetzt (explizit gewinnt, §0 Primum non nocere).
        _conductor_hints = getattr(self, "_conductor_strength_hints", {})
        if _conductor_hints and "strength" not in kwargs:
            _hint = _conductor_hints.pop(phase_metadata.phase_id, None)
            if _hint is not None:
                kwargs["strength"] = float(_hint)

        # §Vintage-Authentizitäts-Guard: Strength-Cap anwenden (copilot-instructions.md)
        # _vintage_phase_strength_caps wird in restore() befüllt und hier per Cap erzwungen.
        _vcaps = getattr(self, "_vintage_phase_strength_caps", {})
        if _vcaps:
            _pid = phase_metadata.phase_id
            _cap = _vcaps.get(_pid)
            if _cap is not None and "strength" in kwargs:
                _orig_s = kwargs["strength"]
                if isinstance(_orig_s, (int, float)) and float(_orig_s) > float(_cap):
                    kwargs["strength"] = float(_cap)
                    logger.debug(
                        "🕰️ Vintage-Cap %s: strength %.2f → %.2f",
                        _pid,
                        _orig_s,
                        _cap,
                    )

        _phase_mem_profiling = bool(
            MEMORY_PROFILING_AVAILABLE and os.environ.get("AURIK_PHASE_MEMORY_PROFILING", "0") == "1"
        )
        t0 = time.perf_counter()
        mem0 = memory_usage(-1, interval=0.01, timeout=1) if _phase_mem_profiling else [0]

        # §MusikalischeHarmonisierung: Defekt-Severity-Wet/Dry für non-PMGG-Pfade
        # Berechne Severity-Faktor VOR Phasenausführung (benötigt Original-Audio für Mix)
        _sev_wet_dry: float = 1.0
        _TIMING_PHASES_WD = frozenset(
            {
                "phase_12_wow_flutter_fix",
                "phase_31_speed_pitch_correction",
            }
        )
        _defect_scores_wd = kwargs.get("defect_scores")
        if _defect_scores_wd and phase_metadata.phase_id not in _TIMING_PHASES_WD:
            try:
                from backend.core.defect_phase_mapper import get_phase_defect_severity

                _sev_wet_dry = get_phase_defect_severity(phase_metadata.phase_id, _defect_scores_wd)
            except Exception:
                _sev_wet_dry = 1.0
        # §Locality-Aware Wet/Dry: for sparse event defects, reduce global processing
        # intensity to preserve timbre outside affected regions.
        # Uses per-defect temporal coverage map from _execute_pipeline.
        _coverage_map = kwargs.get("defect_location_coverage_map")
        if isinstance(_coverage_map, dict) and _defect_scores_wd and phase_metadata.phase_id not in _TIMING_PHASES_WD:
            try:
                from backend.core.defect_phase_mapper import get_phase_locality_factor, get_reverse_phase_map

                _locality_factor = get_phase_locality_factor(
                    phase_metadata.phase_id,
                    _defect_scores_wd,
                    _coverage_map,
                )
                if _locality_factor < 1.0:
                    _sev_wet_dry = float(np.clip(_sev_wet_dry * _locality_factor, 0.15, 1.0))
                    kwargs["phase_locality_factor"] = _locality_factor

                    # Optional diagnostics: max coverage over targeted defects.
                    _rmap = get_reverse_phase_map()
                    _targets = _rmap.get(phase_metadata.phase_id, [])
                    if _targets:
                        _target_coverages = []
                        for _dt in _targets:
                            _dk = _dt.value if hasattr(_dt, "value") else str(_dt)
                            _target_coverages.append(float(_coverage_map.get(_dk, 1.0)))
                        if _target_coverages:
                            kwargs["phase_target_coverage"] = max(_target_coverages)
            except Exception as _exc:
                logger.debug("Phase target coverage computation failed: %s", _exc)

        # Song-level self-calibration across phase families (not just single phases).
        # Keeps behavior track-adaptive while bounded for cross-song robustness.
        if phase_metadata.phase_id not in _TIMING_PHASES_WD:
            _cal_scalar = self._get_phase_calibration_scalar(phase_metadata.phase_id, _song_calibration)
            if abs(_cal_scalar - 1.0) >= 0.03:
                _sev_wet_dry = float(np.clip(_sev_wet_dry * _cal_scalar, 0.12, 1.0))
                _in_strength = kwargs.get("strength")
                if isinstance(_in_strength, (int, float)):
                    kwargs["strength"] = float(np.clip(float(_in_strength) * _cal_scalar, 0.0, 1.0))
                kwargs["song_calibration_scalar"] = _cal_scalar
                logger.debug(
                    "🎛️ SongCalibration %s: scalar=%.3f wet_dry=%.3f",
                    phase_metadata.phase_id,
                    _cal_scalar,
                    _sev_wet_dry,
                )

        # Global harmonic adaptation (all phases 01-64): smooth context coupling
        # using §2.56 goal-weights + restorability + intervention family.
        # Advisory-only: explicit strengths remain untouched.
        if phase_metadata.phase_id not in _TIMING_PHASES_WD:
            _phase_family = self._PHASE_INTERVENTION_CLASS.get(phase_metadata.phase_id, "general")
            _mat_ctx = kwargs.get("material_type") or kwargs.get("material")
            _mat_ctx_s = getattr(_mat_ctx, "value", _mat_ctx)
            _harmonic_scalar = UnifiedRestorerV3._compute_harmonic_adaptation_scalar(
                _phase_id=phase_metadata.phase_id,
                phase_family=_phase_family,
                goal_weights=_sgw if isinstance(_sgw, dict) else kwargs.get("song_goal_weights"),
                restorability_score=_rest_ctx,
                material_key=str(_mat_ctx_s) if _mat_ctx_s is not None else None,
            )
            kwargs["harmonic_adaptation_scalar"] = float(_harmonic_scalar)
            _sev_wet_dry = float(np.clip(_sev_wet_dry * _harmonic_scalar, 0.12, 1.0))
            if (not _strength_explicit) and isinstance(kwargs.get("strength"), (int, float)):
                kwargs["strength"] = float(np.clip(float(kwargs["strength"]) * _harmonic_scalar, 0.0, 1.0))
            logger.debug(
                "🎚️ HarmonicAdaptation %s: family=%s scalar=%.3f wet_dry=%.3f",
                phase_metadata.phase_id,
                _phase_family,
                _harmonic_scalar,
                _sev_wet_dry,
            )

            # Studio 2026-only frisson coupling: bounded micro-modulation.
            # Restoration path remains untouched (scalar=1.0).
            _frisson_audio_scalar = UnifiedRestorerV3._compute_frisson_audio_impact_scalar(
                studio_mode=self.is_studio_mode(),
                phase_family=_phase_family,
                goal_weights=_sgw if isinstance(_sgw, dict) else kwargs.get("song_goal_weights"),
            )
            kwargs["frisson_audio_scalar"] = float(_frisson_audio_scalar)
            if abs(float(_frisson_audio_scalar) - 1.0) >= 0.003:
                _sev_wet_dry = float(np.clip(_sev_wet_dry * float(_frisson_audio_scalar), 0.12, 1.0))
                if (not _strength_explicit) and isinstance(kwargs.get("strength"), (int, float)):
                    kwargs["strength"] = float(
                        np.clip(float(kwargs["strength"]) * float(_frisson_audio_scalar), 0.0, 1.0)
                    )
                logger.info(
                    "🎼 FrissonCoupling %s: studio=%s family=%s scalar=%.3f wet_dry=%.3f",
                    phase_metadata.phase_id,
                    self.is_studio_mode(),
                    _phase_family,
                    _frisson_audio_scalar,
                    _sev_wet_dry,
                )

            # Global uncertainty-aware conservatism: advisory-only for implicit strengths.
            _global_cons = float(np.clip(getattr(self, "_global_conservative_scalar", 1.0), 0.78, 1.0))
            if _global_cons < 0.999:
                _subtractive_families = {
                    "subtractive_cleanup",
                    "harmonic_noise_control",
                    "spectral_restoration",
                    "reconstruction_inpainting",
                    "time_pitch_transport",
                    "distortion_repair",
                }
                _enhancement_families = {
                    "harmonic_reconstruction",
                    "harmonic_enhancement",
                    "tonal_enhancement",
                    "source_enhancement",
                    "stereo_enhancement",
                    "stereo_generation",
                    "semantic_guidance",
                }
                if _phase_family in _subtractive_families:
                    _cons_mix = 0.35
                elif _phase_family in _enhancement_families:
                    _cons_mix = 1.00
                else:
                    _cons_mix = 0.60
                _phase_cons_scalar = float(np.clip(1.0 - (1.0 - _global_cons) * _cons_mix, 0.82, 1.0))
                kwargs["recovery_certainty_scalar"] = _phase_cons_scalar
                _sev_wet_dry = float(np.clip(_sev_wet_dry * _phase_cons_scalar, 0.12, 1.0))
                if (not _strength_explicit) and isinstance(kwargs.get("strength"), (int, float)):
                    kwargs["strength"] = float(np.clip(float(kwargs["strength"]) * _phase_cons_scalar, 0.0, 1.0))
                logger.debug(
                    "RecoveryConservatism %s: family=%s global=%.3f phase=%.3f wet_dry=%.3f",
                    phase_metadata.phase_id,
                    _phase_family,
                    _global_cons,
                    _phase_cons_scalar,
                    _sev_wet_dry,
                )

        # §0p [RELEASE_MUST] Frisson- und Passaggio-Zonen an Phase-kwargs propagieren.
        # Phasen können damit Zeit-Segment-spezifischen Schutz implementieren
        # (Frisson-Klimax: Strength ≤ 0.20; Passaggio: energy_bias = −3 dB).
        if "frisson_zones" not in kwargs:
            kwargs["frisson_zones"] = self._restoration_context.get("frisson_zones", [])
        if "passaggio_zones" not in kwargs:
            kwargs["passaggio_zones"] = self._restoration_context.get("passaggio_zones", [])
        if "vibrato_zones" not in kwargs:
            kwargs["vibrato_zones"] = self._restoration_context.get("vibrato_zones", [])

        # §0p [RELEASE_MUST] Vibrato-Schutz: Phasen-Strength auf max. 0.20 begrenzen
        # wenn das Audio in einer Vibrato-Zone liegt (4–7 Hz F0-Modulation).
        # Gilt nur für implizite Strengths (explizite Conductor-Vorgaben gewinnen).
        _vibrato_zones_uv3: list = kwargs.get("vibrato_zones", [])
        if not _strength_explicit and _vibrato_zones_uv3 and isinstance(kwargs.get("strength"), (int, float)):
            _audio_dur_s = float(len(audio) / max(int(kwargs.get("sample_rate", 48000) or 48000), 1))
            _in_vibrato = any(
                float(z[0]) <= (_audio_dur_s / 2.0) <= float(z[1])
                for z in _vibrato_zones_uv3
                if isinstance(z, (tuple, list)) and len(z) >= 2
            )
            if _in_vibrato:
                kwargs["strength"] = float(np.clip(float(kwargs["strength"]), 0.0, 0.20))
                logger.debug(
                    "§0p Vibrato-Schutz: %s strength begrenzt auf 0.20 (Vibrato-Zone aktiv)",
                    phase_metadata.phase_id,
                )

        # Stabilitäts-Korridor für implizite Strengths: explizite Strengths gewinnen immer.
        # Verhindert, dass Heuristik-/Conductor-Werte dauerhaft in Grenzbereichen kleben.
        if (not _strength_explicit) and isinstance(kwargs.get("strength"), (int, float)):
            _s_raw = float(kwargs["strength"])
            if np.isfinite(_s_raw):
                _s_bounded = float(np.clip(_s_raw, 0.0, 1.0))
                _s_stable = UnifiedRestorerV3._pullback_from_bounds(_s_bounded, 0.0, 1.0, margin_frac=0.06)
                if abs(_s_stable - _s_raw) > 1e-6:
                    kwargs["strength"] = _s_stable
                    logger.debug(
                        "Strength stability corridor %s: %.3f -> %.3f",
                        phase_metadata.phase_id,
                        _s_raw,
                        _s_stable,
                    )

        # §Cross-Goal-Recovery (v9.12.3): if phase_03_denoise ended in PMGG best_effort,
        # restore HF-recovery authority for the immediate additive chain so phase_06/07/39
        # cannot stay under-powered and collapse brillanz/transparenz at final goal gate.
        if (
            (not self.is_studio_mode())
            and (not _strength_explicit)
            and isinstance(kwargs.get("strength"), (int, float))
            and phase_metadata.phase_id
            in {
                "phase_06_frequency_restoration",
                "phase_07_harmonic_restoration",
                "phase_39_air_band_enhancement",
            }
        ):
            _hf_boost = kwargs.get("hf_recovery_boost_after_phase03")
            if isinstance(_hf_boost, dict) and bool(_hf_boost.get("enabled", False)):
                _mat_ctx = kwargs.get("material_type") or kwargs.get("material")
                _mat_key = str(getattr(_mat_ctx, "value", _mat_ctx) or "unknown").lower()
                _fallback_floor = {
                    "phase_06_frequency_restoration": 0.52,
                    "phase_07_harmonic_restoration": 0.24,
                    "phase_39_air_band_enhancement": 0.14,
                }
                _analog_floor = {
                    "phase_06_frequency_restoration": {
                        "vinyl": 0.56,
                        "tape": 0.58,
                        "reel_tape": 0.58,
                        "shellac": 0.50,
                        "wax_cylinder": 0.46,
                        "wire_recording": 0.46,
                    },
                    "phase_07_harmonic_restoration": {
                        "vinyl": 0.28,
                        "tape": 0.30,
                        "reel_tape": 0.30,
                        "shellac": 0.22,
                        "wax_cylinder": 0.18,
                        "wire_recording": 0.18,
                    },
                    "phase_39_air_band_enhancement": {
                        "vinyl": 0.16,
                        "tape": 0.18,
                        "reel_tape": 0.18,
                        "shellac": 0.12,
                        "wax_cylinder": 0.10,
                        "wire_recording": 0.10,
                    },
                }
                _pid = phase_metadata.phase_id
                _floor = float(_analog_floor.get(_pid, {}).get(_mat_key, _fallback_floor.get(_pid, 0.0)))
                _prev_s = float(kwargs.get("strength", 0.0) or 0.0)
                if _floor > _prev_s:
                    kwargs["strength"] = _floor
                    logger.info(
                        "§Cross-Goal-Recovery %s: PMGG phase_03 best_effort"
                        " detected (%s) -> strength floor %.2f (was %.2f, mat=%s)",
                        _pid,
                        str(_hf_boost.get("source_action", "best_effort")),
                        _floor,
                        _prev_s,
                        _mat_key,
                    )

        # §MONITOR [RELEASE_MUST] PHASE_EXEC log — tatsächliche Stärke nach allen Caps (parseable)
        try:
            _exec_strength = kwargs.get("strength")
            _exec_s_str = f"{float(_exec_strength):.3f}" if isinstance(_exec_strength, (int, float)) else "None"
            _exec_vcap = getattr(self, "_vintage_phase_strength_caps", {}).get(phase_metadata.phase_id)
            _exec_vcap_str = f"{float(_exec_vcap):.3f}" if _exec_vcap is not None else "None"
            _exec_cond = getattr(self, "_conductor_strength_hints", {}).get(phase_metadata.phase_id)
            _exec_cond_str = f"{float(_exec_cond):.3f}" if _exec_cond is not None else "None"
            logger.info(
                "📊 PHASE_EXEC phase=%s strength=%s explicit=%s vcap=%s conductor=%s songcal=%.3f",
                phase_metadata.phase_id,
                _exec_s_str,
                "1" if _strength_explicit else "0",
                _exec_vcap_str,
                _exec_cond_str,
                float(_sev_wet_dry),
            )
        except Exception as _pex_exc:
            logger.debug("PHASE_EXEC log failed (non-blocking): %s", _pex_exc)

        # Call phase.process() method (not phase() itself!)
        # §Heartbeat: Inject scoped sub-progress callback so slow phases (e.g. phase_49
        # WPE dereverb) can emit intermediate progress — keeps the UI bar moving.
        _sub_root_cb = getattr(self, "_active_pipeline_cb_for_sub", None)
        _sub_pct_range = getattr(self, "_active_phase_pct_for_sub", None)
        if _sub_root_cb is not None and _sub_pct_range is not None and "progress_sub_callback" not in kwargs:
            _sp_s, _sp_e = _sub_pct_range  # pylint: disable=unpacking-non-sequence

            def _make_sub_progress(_root_cb, _pct_s, _pct_e):
                # Monotonie-Guard: verhindert Rücksprünge wenn Heartbeat und echte
                # Phase-Callbacks parallel feuern.
                _mono_last = [_pct_s]
                _mono_lock = threading.Lock()

                def _sub_progress(sub_pct_0_100: float, lbl: str, elapsed: float) -> None:
                    try:
                        # Float-Auflösung: kein int()-Cast → 0,01%-Stufen bleiben erhalten
                        _mapped = _pct_s + (_pct_e - _pct_s) * sub_pct_0_100 / 100.0
                        _mapped = max(float(_pct_s), min(float(_pct_e), _mapped))
                        with _mono_lock:
                            if _mapped <= _mono_last[0]:
                                return  # Heartbeat-Tick liegt hinter echtem Callback
                            _mono_last[0] = _mapped
                        _root_cb(_mapped, lbl, elapsed)
                    except Exception:
                        pass

                return _sub_progress

            kwargs["progress_sub_callback"] = _make_sub_progress(_sub_root_cb, _sp_s, _sp_e)

        # §Heartbeat — kontinuierlicher Micro-Step-Emitter (8 Hz, log. Kurve).
        # Hält die Sub-Progress-Bar auch ohne interne Callbacks der Phase in Bewegung.
        # Kurve: f(t) = (1 − e^(−t/T)) × budget, T=40 s → nach 20 s ca. 39 % erreicht.
        # Echte Phase-Callbacks übersteuern jederzeit via Monotonie-Guard.
        _hb_cb = kwargs.get("progress_sub_callback")
        _hb_stop_ev = threading.Event()
        _hb_thread: threading.Thread | None = None
        if _hb_cb is not None:
            _hb_t0 = time.perf_counter()
            _HB_INTERVAL = 0.12  # ~8 Hz — feiner als üblicher UI-Redraw
            _HB_T = 40.0  # Zeitkonstante [s]: 40 s → 63 % des Budgets
            _HB_BUDGET = 0.88  # Heartbeat belegt max. 88 % Sub; Rest für echte Callbacks

            def _heartbeat_run(
                _cb=_hb_cb,
                _stop=_hb_stop_ev,
                _t0=_hb_t0,
                _T=_HB_T,
                _B=_HB_BUDGET,
                _iv=_HB_INTERVAL,
            ) -> None:
                while not _stop.wait(_iv):
                    _t = time.perf_counter() - _t0
                    _frac = (1.0 - float(np.exp(-_t / _T))) * _B
                    try:
                        _cb(float(_frac * 100.0), "", _t)
                    except Exception:
                        pass

            _hb_thread = threading.Thread(
                target=_heartbeat_run,
                daemon=True,
                name=f"aurik_phase_hb_{phase_metadata.phase_id}",
            )
            _hb_thread.start()

        _audio_before_phase = audio if _sev_wet_dry < 1.0 else None
        # §4.1b Zwicker-Guard: capture pre-phase audio for broadband-subtractive phases
        _ZWICKER_GUARD_PHASES: frozenset[str] = frozenset(
            {
                "phase_03_denoise",
                "phase_18_noise_gate",
                "phase_20_reverb_reduction",
                "phase_28_surface_noise_profiling",
                "phase_29_tape_hiss_reduction",
                "phase_49_advanced_dereverb",
                "phase_05_rumble_filter",
            }
        )
        _zwicker_pre_audio: np.ndarray | None = (
            audio.copy() if phase_metadata.phase_id in _ZWICKER_GUARD_PHASES else None
        )
        # §2.64 Pre-Phase Goal-Snapshot (DSP-proxy, ≤200ms, non-blocking)
        # Stored on self so _profiled_phase_call can compute post-delta after phase.process().
        _do_goal_snap = not getattr(self, "_mas_fully_achieved", False)
        _sr_for_snap = int(kwargs.get("sample_rate", 48000) or 48000)
        _mat_for_snap = str(
            getattr(self, "_restoration_context", {}).get("primary_material", "unknown") or "unknown"
        ).lower()
        if _do_goal_snap and isinstance(audio, np.ndarray) and len(audio.flat) >= 512:
            try:
                self._phase_pre_snapshot = UnifiedRestorerV3._fast_goal_snapshot(audio, _sr_for_snap, _mat_for_snap)
            except Exception:
                self._phase_pre_snapshot = {}
        else:
            self._phase_pre_snapshot = {}
        try:
            result = phase.process(audio, **kwargs)
        finally:
            _hb_stop_ev.set()
            if _hb_thread is not None:
                _hb_thread.join(timeout=0.3)
        # §2.46b Spectral Tilt Drift Guard: always save pre-phase audio for ADDITIVE phases
        # so we can apply wet/dry rescue if tilt drifts beyond era-material tolerance.
        _era_tilt = getattr(self, "_era_spectral_tilt", None)
        _is_additive_for_tilt = False
        if _era_tilt is not None:
            try:
                from backend.core.hf_hallucination_guard import ADDITIVE_PHASE_PREFIXES as _ADD_PFX

                _is_additive_for_tilt = any(phase_metadata.phase_id.startswith(p) for p in _ADD_PFX)
            except Exception:
                pass
        if _is_additive_for_tilt and _audio_before_phase is None:
            _audio_before_phase = audio

        # §MusikalischeHarmonisierung: Wet/Dry basierend auf Defekt-Severity
        if _sev_wet_dry < 1.0 and _audio_before_phase is not None and hasattr(result, "audio"):
            _pa = result.audio
            if isinstance(_pa, np.ndarray) and _pa.shape == _audio_before_phase.shape:
                result.audio = np.clip(
                    (_audio_before_phase + _sev_wet_dry * (_pa - _audio_before_phase)).astype(np.float32),
                    -1.0,
                    1.0,
                )
                logger.debug(
                    "🎵 DefectSeverity Wet/Dry %s: factor=%.2f",
                    phase_metadata.phase_id,
                    _sev_wet_dry,
                )

        # §2.46b Spectral Tilt Drift Guard — prevents additive phases from destroying
        # era acoustic character without triggering a Musical-Goal violation.
        # Tolerance: ±1.5 dB/oct (vinyl/cd/dat/lossy), ±2.0 (tape), ±3.0 (shellac/wax).
        if (
            _is_additive_for_tilt
            and _era_tilt is not None
            and _audio_before_phase is not None
            and hasattr(result, "audio")
        ):
            try:
                _TILT_TOLERANCE: dict[str, float] = {
                    "wax_cylinder": 3.0,
                    "wire_recording": 3.0,
                    "shellac": 3.0,
                    "lacquer_disc": 3.0,
                    "minidisc": 2.0,
                    "cassette": 2.0,
                    "tape": 2.0,
                    "reel_tape": 2.0,
                    "vinyl": 1.5,
                    "cd_digital": 1.5,
                    "dat": 1.5,
                    "mp3_low": 1.5,
                    "mp3_high": 1.5,
                }
                _mat_raw = kwargs.get("material_type") or kwargs.get("material")
                _mat_str = str(getattr(_mat_raw, "value", _mat_raw) or "").lower()
                _tol = _TILT_TOLERANCE.get(_mat_str, 2.0)
                _sr_ctx = int(kwargs.get("sample_rate", 48000) or 48000)
                _post_tilt = UnifiedRestorerV3._estimate_spectral_tilt_quick(result.audio, _sr_ctx)
                if _post_tilt is not None:
                    _deviation = abs(float(_post_tilt) - float(_era_tilt))
                    if _deviation > _tol:
                        _excess = _deviation - _tol
                        # wet_cap: 1.0 when exactly at tolerance, approaches 0.35 when 2× over.
                        _wet_cap = float(np.clip(1.0 - _excess / (_tol + 1e-6), 0.35, 1.0))
                        _pa = result.audio
                        if isinstance(_pa, np.ndarray) and _pa.shape == _audio_before_phase.shape:
                            result.audio = np.clip(
                                (_audio_before_phase + _wet_cap * (_pa - _audio_before_phase)).astype(np.float32),
                                -1.0,
                                1.0,
                            )
                            logger.info(
                                "§2.46b TiltGuard %s: era=%.2f post=%.2f dev=%.2f > tol=%.1f → wet_cap=%.2f (mat=%s)",
                                phase_metadata.phase_id,
                                _era_tilt,
                                _post_tilt,
                                _deviation,
                                _tol,
                                _wet_cap,
                                _mat_str,
                            )
                            if hasattr(self, "_phase_metadata_accumulator"):
                                self._phase_metadata_accumulator[phase_metadata.phase_id] = {
                                    **(self._phase_metadata_accumulator.get(phase_metadata.phase_id) or {}),
                                    "tilt_guard_fired": True,
                                    "tilt_era_db_per_oct": round(float(_era_tilt), 3),
                                    "tilt_post_db_per_oct": round(float(_post_tilt), 3),
                                    "tilt_deviation_db_per_oct": round(float(_deviation), 3),
                                    "tilt_tolerance_db_per_oct": round(float(_tol), 3),
                                    "tilt_wet_cap_applied": round(float(_wet_cap), 3),
                                }
            except Exception as _tg_exc:
                logger.debug("§2.46b TiltGuard non-blocking error %s: %s", phase_metadata.phase_id, _tg_exc)

        # §4.1b ISO 532-1 Zwicker Mid-Pipeline-Loudness-Guard
        # Applied AFTER broadband-subtraktive phases. ΔN > 2.0 sone → Dry/Wet-Rescue.
        # LUFS allein übersieht Tiefton-Rumpeln bis +6 Phon (ISO 226:2003).
        if (
            _zwicker_pre_audio is not None
            and hasattr(result, "audio")
            and isinstance(result.audio, np.ndarray)
            and result.audio.shape == _zwicker_pre_audio.shape
        ):
            try:
                from backend.core.dsp.psychoacoustics import evaluate_mid_pipeline_loudness_delta

                _sr_ctx = int(kwargs.get("sample_rate", 48000) or 48000)
                _zwicker_delta = evaluate_mid_pipeline_loudness_delta(
                    _zwicker_pre_audio,
                    result.audio,
                    _sr_ctx,
                    phase_name=phase_metadata.phase_id,
                )
                if hasattr(result, "metadata") and isinstance(result.metadata, dict):
                    result.metadata["zwicker_delta_sone"] = round(float(_zwicker_delta.get("delta_sone", 0.0)), 3)
                    result.metadata["zwicker_action"] = _zwicker_delta.get("action", "skip")
                    result.metadata["loudness_delta_sone"] = round(float(_zwicker_delta.get("delta_sone", 0.0)), 3)
                # ΔN > 2.0 → Dry/Wet-Rescue: blend toward input to restore loudness (§4.1b FAIL)
                if _zwicker_delta.get("action") == "fail_dry_wet_rescue":
                    _delta_sone = float(_zwicker_delta.get("delta_sone", 0.0))
                    # Rescue wet factor: 2.0 sone → 0.75 wet, 4.0+ sone → 0.35 wet
                    _rescue_wet = float(np.clip(1.0 - (_delta_sone - 2.0) / 4.0, 0.35, 0.90))
                    result.audio = np.clip(
                        (_zwicker_pre_audio + _rescue_wet * (result.audio - _zwicker_pre_audio)).astype(np.float32),
                        -1.0,
                        1.0,
                    )
                    logger.info(
                        "§4.1b ZwickerGuard RESCUE %s: ΔN=%.2f sone → wet_rescue=%.2f",
                        phase_metadata.phase_id,
                        _delta_sone,
                        _rescue_wet,
                    )
                    if hasattr(result, "metadata") and isinstance(result.metadata, dict):
                        result.metadata["zwicker_rescue_wet"] = round(float(_rescue_wet), 3)
            except Exception as _zw_exc:
                logger.debug("§4.1b ZwickerGuard non-blocking error %s: %s", phase_metadata.phase_id, _zw_exc)

        # §HNR [RELEASE_MUST]: apply_hnr_blend after NR phases on vocal material (UV3 hook)
        # phase_03_denoise already has its own internal HNR blend — skip to avoid double-blend.
        _NR_PHASES_HNR = frozenset(
            {
                "phase_18_noise_gate",
                "phase_20_reverb_reduction",
                "phase_29_tape_hiss_reduction",
                "phase_49_advanced_dereverb",  # §0p BUG-FIX v9.12.5: HNR-Blend nach Dereverb auf Vokal
                "phase_55_diffusion_inpainting",  # §0p v9.12.6: HNR-Blend nach Inpainting — verhindert Over-Harmonisierung
            }
        )
        if (
            phase_metadata.phase_id in _NR_PHASES_HNR
            and hasattr(result, "audio")
            and isinstance(result.audio, np.ndarray)
            and result.audio.shape == audio.shape
        ):
            try:
                _panns_singing_hnr = float(
                    kwargs.get("panns_singing", kwargs.get("panns_singing_confidence", 0.0)) or 0.0
                )
                if _panns_singing_hnr >= 0.25:
                    from backend.core.dsp.hnr_guard import apply_hnr_blend as _apply_hnr_blend

                    _sr_hnr = int(kwargs.get("sample_rate", 48000) or 48000)
                    result.audio = _apply_hnr_blend(audio, result.audio, _sr_hnr)
                    logger.debug(
                        "§HNR apply_hnr_blend: %s panns_singing=%.2f",
                        phase_metadata.phase_id,
                        _panns_singing_hnr,
                    )
            except Exception as _hnr_exc:
                logger.debug("§HNR apply_hnr_blend non-blocking: %s", _hnr_exc)

        # §0p [RELEASE_MUST] Formant-Integrität-Wächter — F1–F4 ±2 dB Rollback.
        # Nur für Vokal-schwere Phasen, nur wenn panns_singing ≥ 0.25 (§0p Invariante).
        _FORMANT_GUARD_PHASES = frozenset(
            {
                "phase_03_denoise",
                "phase_20_reverb_reduction",
                "phase_29_tape_hiss_reduction",
                "phase_42_vocal_enhancement",
                "phase_49_advanced_dereverb",
            }
        )
        if (
            phase_metadata.phase_id in _FORMANT_GUARD_PHASES
            and hasattr(result, "audio")
            and isinstance(result.audio, np.ndarray)
            and result.audio.shape == audio.shape
        ):
            try:
                _panns_fg = float(kwargs.get("panns_singing", kwargs.get("panns_singing_confidence", 0.0)) or 0.0)
                if _panns_fg >= 0.25:
                    from backend.core.dsp.lpc_formant_tracker import get_lpc_formant_tracker as _get_fmt

                    _sr_fg = int(kwargs.get("sample_rate", 48000) or 48000)
                    _fmt = _get_fmt()

                    # Mono-Segment (Zentrum, max. 2 s) für Formant-Analyse
                    def _formant_mono(a: np.ndarray) -> np.ndarray:
                        m = (
                            a
                            if a.ndim == 1
                            else (a[0] if a.shape[0] == 2 and a.shape[1] > 2 else a.mean(axis=-1 if a.ndim == 2 else 0))
                        )
                        n2s = int(2.0 * _sr_fg)
                        if len(m) > n2s:
                            start2 = (len(m) - n2s) // 2
                            return m[start2 : start2 + n2s].astype(np.float32)
                        return m.astype(np.float32)

                    _pre_mono = _formant_mono(audio)
                    _post_mono = _formant_mono(result.audio)
                    _pre_res = _fmt.track(_pre_mono, _sr_fg)
                    _post_res = _fmt.track(_post_mono, _sr_fg)

                    # Mittlere F1/F2 aus Tracks (confidence > 0.25)
                    def _mean_formant(res, idx: int) -> float:
                        vals = []
                        for frame in getattr(res, "formant_tracks", []):
                            freqs = getattr(frame, "frequencies", [])
                            confs = getattr(frame, "confidences", [1.0] * len(freqs))
                            if len(freqs) > idx and len(confs) > idx and float(confs[idx]) > 0.25:
                                v = float(freqs[idx])
                                if 50.0 < v < 4000.0:
                                    vals.append(v)
                        return float(np.mean(vals)) if vals else 0.0

                    _f1_pre = _mean_formant(_pre_res, 0)
                    _f1_post = _mean_formant(_post_res, 0)
                    _f2_pre = _mean_formant(_pre_res, 1)
                    _f2_post = _mean_formant(_post_res, 1)

                    # ±2 dB-Check: 20*log10(f_post/f_pre) — Formant als Spektral-Energie-Proxy
                    _FORMANT_DB_LIMIT = 2.0
                    _rollback_fg = False
                    if _f1_pre > 0.0 and _f1_post > 0.0:
                        _f1_shift_db = abs(20.0 * np.log10(max(_f1_post / _f1_pre, 1e-9)))
                        if _f1_shift_db > _FORMANT_DB_LIMIT:
                            _rollback_fg = True
                            logger.warning(
                                "§0p Formant-Guard: %s F1-Shift=%.1f dB > ±%.1f dB → Rollback",
                                phase_metadata.phase_id,
                                _f1_shift_db,
                                _FORMANT_DB_LIMIT,
                            )
                    if not _rollback_fg and _f2_pre > 0.0 and _f2_post > 0.0:
                        _f2_shift_db = abs(20.0 * np.log10(max(_f2_post / _f2_pre, 1e-9)))
                        if _f2_shift_db > _FORMANT_DB_LIMIT:
                            _rollback_fg = True
                            logger.warning(
                                "§0p Formant-Guard: %s F2-Shift=%.1f dB > ±%.1f dB → Rollback",
                                phase_metadata.phase_id,
                                _f2_shift_db,
                                _FORMANT_DB_LIMIT,
                            )
                    if _rollback_fg:
                        result.audio = audio.copy()
                        logger.info(
                            "§0p Formant-Guard: %s rolled back — Formant-Integrität geschützt",
                            phase_metadata.phase_id,
                        )
            except Exception as _fg_exc:
                logger.debug("§0p Formant-Guard non-blocking: %s", _fg_exc)

        # §CSTC Cross-Segment Timbral Coherence Guard — Post-NR-Phase Check (§0a).
        # Nach jeder breitband-subtraktiven Phase prüfen, dass die Rauschboden-Textur
        # kohärent zum Referenzprofil bleibt (Kohärenz ≥ 0.80, warn-only, non-blocking).
        _CSTC_NR_PHASES = frozenset(
            {
                "phase_03_denoise",
                "phase_18_noise_gate",
                "phase_20_reverb_reduction",
                "phase_28_surface_noise_profiling",
                "phase_29_tape_hiss_reduction",
                "phase_49_advanced_dereverb",
            }
        )
        if (
            phase_metadata.phase_id in _CSTC_NR_PHASES
            and hasattr(result, "audio")
            and isinstance(result.audio, np.ndarray)
            and result.audio.shape == audio.shape
        ):
            try:
                _cstc_profile = getattr(self, "_cstc_noise_profile", None)
                if _cstc_profile is not None:
                    from backend.core.dsp.timbral_coherence_guard import (
                        compute_timbral_coherence_score as _cstc_score,
                    )

                    _cstc_result = _cstc_score(
                        result.audio.astype(np.float32),
                        _cstc_profile,
                        int(kwargs.get("sample_rate", 48000) or 48000),
                    )
                    if not _cstc_result.get("pass", True):
                        logger.warning(
                            "§CSTC %s: Kohärenz=%.2f < 0.80 — Rauschboden-Textur inkohärent (non-blocking)",
                            phase_metadata.phase_id,
                            _cstc_result.get("coherence_score", 0.0),
                        )
                    if hasattr(result, "metadata") and isinstance(result.metadata, dict):
                        result.metadata["cstc_coherence"] = round(float(_cstc_result.get("coherence_score", 1.0)), 3)
            except Exception as _cstc_exc:
                logger.debug("§CSTC post-phase check non-blocking: %s", _cstc_exc)

        # Generic psychoacoustic masking clamp for phases without internal clamp.
        # This broadens masking coverage beyond explicitly integrated phase modules.
        if hasattr(result, "audio") and isinstance(result.audio, np.ndarray) and result.audio.shape == audio.shape:
            try:
                _INTERNAL_PM_CLAMP_PHASES = frozenset(
                    {
                        "phase_04_eq_correction",
                        "phase_16_final_eq",
                        "phase_18_noise_gate",
                        "phase_19_de_esser",
                        "phase_20_reverb_reduction",
                        "phase_21_exciter",
                        "phase_23_spectral_repair",
                        "phase_28_surface_noise_profiling",
                        "phase_35_multiband_compression",
                        "phase_49_advanced_dereverb",
                        "phase_50_spectral_repair",
                        "phase_54_transparent_dynamics",
                        "phase_57_print_through_reduction",
                        "phase_59_modulation_noise_reduction",
                        "phase_63_intermodulation_reduction",
                    }
                )
                _pid_pm = phase_metadata.phase_id
                if _pid_pm not in _INTERNAL_PM_CLAMP_PHASES:
                    _cat = str(getattr(phase_metadata, "category", "")).lower()
                    _is_sub = any(k in _cat for k in ("subtract", "restoration", "repair", "cleanup"))
                    _is_add = any(k in _cat for k in ("additive", "enhancement", "dynamics"))
                    if _is_sub or _is_add:
                        from backend.core.dsp.psychoacoustics import apply_psychoacoustic_masking_clamp

                        _mode_pm = "subtractive" if _is_sub else "additive"
                        _strength_pm = float(np.clip(float(kwargs.get("strength", 1.0) or 1.0), 0.0, 1.0))
                        result.audio = apply_psychoacoustic_masking_clamp(
                            audio,
                            result.audio,
                            int(kwargs.get("sample_rate", 48000) or 48000),
                            strength=_strength_pm,
                            mode=_mode_pm,
                            masking_result=kwargs.get("masking_result"),
                        )
                        if hasattr(result, "metadata") and isinstance(result.metadata, dict):
                            result.metadata["generic_masking_clamp_applied"] = True
            except Exception as _pmg_exc:
                logger.debug("Generic masking clamp non-blocking for %s: %s", phase_metadata.phase_id, _pmg_exc)

        t1 = time.perf_counter()
        mem1 = memory_usage(-1, interval=0.01, timeout=1) if _phase_mem_profiling else [0]
        elapsed = t1 - t0
        mem_used = max(mem1) - min(mem0) if _phase_mem_profiling else None

        logger.info(
            f"Profiling: Phase {phase_name} | Zeit: {elapsed:.3f}s"
            + (f" | Speicher: {mem_used:.1f} MiB" if mem_used is not None else "")
        )

        if hasattr(result, "profiling"):
            result.profiling["time_seconds"] = elapsed
            if mem_used is not None:
                result.profiling["memory_mib"] = mem_used

        if _team_context_enabled and getattr(result, "success", False):
            _team_ctx = getattr(self, "_phase_team_context", None)
            if not isinstance(_team_ctx, dict):
                _team_ctx = {}
            _executed = _team_ctx.get("executed_phase_ids")
            if not isinstance(_executed, list):
                _executed = []
            _pid = str(getattr(phase_metadata, "phase_id", ""))
            if _pid and _pid not in _executed:
                _executed.append(_pid)
            _team_ctx["executed_phase_ids"] = _executed

            # Generic all-phase team semantics derived from normative phase ontology.
            # This makes context propagation complete for all 01-64 phases without
            # requiring per-phase manual wiring.
            try:
                from backend.core.phase_ontology import PhaseOperationType, get_phase_type

                _ptype = get_phase_type(_pid)
                _ptype_name = getattr(_ptype, "name", str(_ptype))
                _team_ctx["last_phase_id"] = _pid
                _team_ctx["last_phase_type"] = _ptype_name
                _team_ctx["last_phase_succeeded"] = True

                _type_counts = _team_ctx.get("phase_type_counts")
                if not isinstance(_type_counts, dict):
                    _type_counts = {}
                _type_counts[_ptype_name] = int(_type_counts.get(_ptype_name, 0)) + 1
                _team_ctx["phase_type_counts"] = _type_counts

                if _ptype == PhaseOperationType.SUBTRACTIVE:
                    _team_ctx["subtractive_applied"] = True
                elif _ptype == PhaseOperationType.ADDITIVE:
                    _team_ctx["additive_applied"] = True
                elif _ptype == PhaseOperationType.CORRECTIVE:
                    _team_ctx["corrective_applied"] = True
                elif _ptype == PhaseOperationType.DYNAMICS:
                    _team_ctx["dynamics_applied"] = True
                elif _ptype == PhaseOperationType.ML_GENERATIVE:
                    _team_ctx["ml_generative_applied"] = True
                elif _ptype == PhaseOperationType.ANALYSIS_ONLY:
                    _team_ctx["analysis_only_applied"] = True
                else:
                    _team_ctx["enhancement_applied"] = True
            except Exception as _ptype_exc:
                logger.debug("Phase team ontology update skipped for %s: %s", _pid, _ptype_exc)

            # Semantic flags for downstream phases (coarse-grained, robust against
            # differing per-phase metadata schemas).
            if "phase_01" in _pid:
                _team_ctx["click_repair_applied"] = True
            if "phase_06" in _pid:
                _team_ctx["frequency_restoration_applied"] = True
            if "phase_07" in _pid:
                _team_ctx["harmonic_restoration_applied"] = True
            if "phase_23" in _pid:
                _team_ctx["spectral_super_resolution_applied"] = True
            if "phase_24" in _pid:
                _team_ctx["dropout_repair_applied"] = True
            if "phase_55" in _pid or "phase_56" in _pid:
                _team_ctx["inpainting_applied"] = True

            _rmeta = getattr(result, "metadata", None)
            if isinstance(_rmeta, dict) and _rmeta:
                if "hf_protected_bin_start" in _rmeta:
                    _team_ctx["hf_protected_bin_start"] = int(_rmeta.get("hf_protected_bin_start", 0) or 0)
                if "hf_protection_rolloff_hz" in _rmeta:
                    _team_ctx["hf_protection_rolloff_hz"] = float(_rmeta.get("hf_protection_rolloff_hz", 0.0) or 0.0)

            self._phase_team_context = _team_ctx

        # §2.64 Per-Phase Goal-Delta (DSP-proxy, ≤200ms, non-blocking)
        # Pre-snapshot was taken before phase.process(); post-snapshot taken now.
        # Delta is stored in self._phase_deltas[phase_id] and logged.
        # §2.65 MAS-Convergence: if all P1/P2 goals ≤ MAS+0.02, set _mas_fully_achieved.
        _phase_delta_pid = str(getattr(phase_metadata, "phase_id", ""))
        if _phase_delta_pid and hasattr(self, "_phase_pre_snapshot") and isinstance(self._phase_pre_snapshot, dict):
            try:
                _post_audio = getattr(result, "audio", None)
                _sr_snap = int(kwargs.get("sample_rate", 48000) or 48000)
                if isinstance(_post_audio, np.ndarray) and len(_post_audio) >= 512:
                    _post_snap = UnifiedRestorerV3._fast_goal_snapshot(_post_audio, _sr_snap, _mat_for_snap)
                    _pre_snap = self._phase_pre_snapshot
                    _delta: dict[str, float] = {
                        g: round(float(_post_snap.get(g, 0.0)) - float(_pre_snap.get(g, 0.0)), 4)
                        for g in (_post_snap.keys() | _pre_snap.keys())
                    }
                    # Accumulate in _phase_deltas
                    if not hasattr(self, "_phase_deltas"):
                        self._phase_deltas: dict[str, dict] = {}
                    self._phase_deltas[_phase_delta_pid] = {
                        "pre": {g: round(v, 4) for g, v in _pre_snap.items()},
                        "post": {g: round(v, 4) for g, v in _post_snap.items()},
                        "delta": _delta,
                    }
                    logger.debug(
                        "§2.64 phase_delta %s: %s",
                        _phase_delta_pid,
                        " ".join(f"{g}={_delta[g]:+.3f}" for g in sorted(_delta) if abs(_delta.get(g, 0.0)) >= 0.01),
                    )

                    # §2.65 MAS-Convergence check
                    if not getattr(self, "_mas_fully_achieved", False):
                        _song_targets = getattr(self, "_song_goal_targets", None)
                        if isinstance(_song_targets, dict) and _song_targets and _post_snap:
                            _song_targets_d: dict[str, Any] = dict(_song_targets)
                            _mas_gaps = {
                                g: float(_song_targets_d.get(g, 0.0)) - float(_post_snap.get(g, 0.0))
                                for g in (self._P1P2_MAS_GOALS | self._P3P5_MAS_GOALS)
                                if _song_targets_d.get(g) is not None and _post_snap.get(g) is not None
                            }
                            self._check_mas_convergence(_post_snap, _mas_gaps, _phase_delta_pid)
            except Exception as _delta_exc:
                logger.debug("§2.64 phase_delta non-blocking error for %s: %s", _phase_delta_pid, _delta_exc)

        # §HF-Tracking (Fallback-Pfad): hf_cumulative_gain_db nach HF-additiver Phase aktualisieren.
        # PMGG-Primary-Pfad hat eigene Aktualisierung im UV3-Main-Loop (NaN-Guard geschützt).
        if phase_metadata.phase_id in _HF_ADDITIVE_PHASE_CONTRIB_DB:
            _rctx_hf = getattr(self, "_restoration_context", None)
            if isinstance(_rctx_hf, dict):
                _hf_contrib_fallback = _HF_ADDITIVE_PHASE_CONTRIB_DB[phase_metadata.phase_id]
                _rctx_hf["hf_cumulative_gain_db"] = float(
                    _rctx_hf.get("hf_cumulative_gain_db", 0.0) + _hf_contrib_fallback
                )
                logger.debug(
                    "§HF-Track (Fallback): %s +%.1f dB → cumul=%.1f dB",
                    phase_metadata.phase_id,
                    _hf_contrib_fallback,
                    _rctx_hf["hf_cumulative_gain_db"],
                )

        return result

    # ------------------------------------------------------------------
    # §Per-Channel Defect Repair: Proxy für kanalweise Phasen-Ausführung
    # ------------------------------------------------------------------

    # Defekt-Reparatur-Phasen, die bei Stereo-Audio kanalweise verarbeitet werden.
    # Analog zur kanalweisen Erkennung im DefectScanner — jeder Kanal wird
    # unabhängig repariert, Zwischenstände an die Visualisierung emittiert.
    _CHANNEL_SPECIFIC_PHASES: frozenset[str] = frozenset(
        {
            "phase_01_click_removal",
            "phase_09_crackle_removal",
            "phase_23_spectral_repair",
            "phase_24_dropout_repair",
            "phase_27_click_pop_removal",
        }
    )

    class _ChannelSplitPhaseProxy:
        """Proxy that wraps a PhaseInterface to process stereo channels independently.

        Used for channel-specific defect repair phases (click, crackle, dropout etc.)
        where each stereo channel should be repaired individually — analogous to
        the per-channel detection in DefectScanner.

        Emits intermediate waveform updates after each channel via audio_update_callback
        so the UI can show the sequential channel processing in real time.
        """

        __slots__ = ("_audio_update_cb", "_phase", "_sr")

        def __init__(self, phase, audio_update_callback=None, sample_rate: int = 48000):
            object.__setattr__(self, "_phase", phase)
            object.__setattr__(self, "_audio_update_cb", audio_update_callback)
            object.__setattr__(self, "_sr", sample_rate)

        def __getattr__(self, name):
            return getattr(object.__getattribute__(self, "_phase"), name)

        def get_metadata(self):
            """Delegate get_metadata to the wrapped phase."""
            return object.__getattribute__(self, "_phase").get_metadata()

        def process(self, audio, **kwargs):
            """Process stereo audio channel-by-channel; mono passes through unchanged."""
            phase = object.__getattribute__(self, "_phase")
            cb = object.__getattribute__(self, "_audio_update_cb")
            sr = object.__getattribute__(self, "_sr")

            # Only split if stereo (N, 2) — mono and other shapes pass through unchanged
            if audio.ndim != 2 or audio.shape[-1] != 2:
                return phase.process(audio, **kwargs)

            n_samples = audio.shape[0]
            left_orig = audio[:, 0].copy()
            right_orig = audio[:, 1].copy()

            def _safe_extract(result, fallback):
                """Extract audio array from PhaseResult or raw ndarray."""
                out = result.audio if hasattr(result, "audio") else result
                if not isinstance(out, np.ndarray) or out.ndim != 1:
                    return fallback.copy()
                out = np.nan_to_num(out, nan=0.0, posinf=0.0, neginf=0.0)
                # Ensure same length after phase processing
                if len(out) != n_samples:
                    if len(out) > n_samples:
                        out = out[:n_samples]
                    else:
                        out = np.pad(out, (0, n_samples - len(out)))
                return out

            # --- Process left channel independently ---
            result_l = phase.process(left_orig, **kwargs)
            repaired_l = _safe_extract(result_l, left_orig)

            # Emit intermediate: repaired L + original R
            if cb is not None:
                try:
                    intermediate = np.column_stack([repaired_l, right_orig])
                    _pid = ""
                    try:
                        _pid = phase.get_metadata().phase_id
                    except Exception as _meta_exc:
                        logger.debug("Phase-Metadata-Zugriff für Stereo-Callback fehlgeschlagen: %s", _meta_exc)
                    cb(intermediate, sr, f"{_pid}:L")
                except Exception as _cb_exc:
                    logger.debug("Stereo-Audio-Update-Callback fehlgeschlagen: %s", _cb_exc)

            # --- Process right channel independently ---
            result_r = phase.process(right_orig, **kwargs)
            repaired_r = _safe_extract(result_r, right_orig)

            # Combine into stereo result
            combined = np.column_stack([repaired_l, repaired_r]).astype(np.float32)

            # Return PhaseResult-compatible object (PMGG _run_phase checks .audio attribute)
            if hasattr(result_l, "audio"):
                result_l.audio = combined
                return result_l
            return combined

    def _execute_pipeline(  # pyright: ignore[reportGeneralTypeIssues]
        self,
        audio: np.ndarray,
        sample_rate: int,
        material_type: MaterialType,
        defect_result,
        selected_phases: list[str],
        progress_callback=None,
        audio_update_callback=None,
        _phase_progress_start: int = 20,
        _phase_progress_end: int = 85,
        restorability_score: float = 70.0,  # §2.29 normativ: aus RestorabilityEstimator.estimate()
        applicable_goals: set[str] | None = None,  # §2.32 normativ: aus GoalApplicabilityFilter
        material_initial_strengths: dict[str, float] | None = None,  # §2.31 material-adaptive Initialstärken
        quality_mode_override: QualityMode | None = None,
        no_rt_limit: bool = False,
        reconstruction_context=None,  # §11.7a: RekonstruktionsDenker-Ergebnis mit reparierten Gaps
        phoneme_timeline=None,  # §2.36a: PhonemeTimeline für phoneme-targeted Processing
        pre_transcription=None,  # §2.36: LGE pre-computed transcription for phase_58
        graceful_stop_event=None,  # §0c: threading.Event — Watchdog setzt, Loop bricht nach Phase ab
        original_audio_reference: np.ndarray | None = None,
        quiet_edge_profile: dict[str, Any] | None = None,
    ) -> tuple[np.ndarray, list[str], list[str], list[str]]:
        """
        Führt ausgewählte Phasen parallel (Multi-Core) aus, falls keine Abhängigkeiten bestehen.
        Returns: (processed_audio, executed_phases, skipped_phases, deferred_phases)
        """
        # §3.1 NaN/Inf-Invariante: Input VOR Phasenausführung bereinigen
        if not np.all(np.isfinite(audio)):
            logger.debug("_execute_pipeline: NaN/Inf im Input-Audio bereinigt")
            audio = np.nan_to_num(audio, nan=0.0, posinf=0.9, neginf=-0.9)
        audio = np.clip(audio, -1.0, 1.0)
        # §Längen-Guard: Originalsamplelänge merken — Phasen dürfen die Länge nicht verändern.
        _input_n_samples: int = audio.shape[-1] if audio.ndim >= 2 else len(audio)
        _active_quality_mode = quality_mode_override or self.config.mode
        _quality_mode_value = _active_quality_mode.value
        current_audio = audio.copy()
        _pipeline_original_reference = (
            np.asarray(original_audio_reference, dtype=np.float32).copy()
            if isinstance(original_audio_reference, np.ndarray) and original_audio_reference.size > 0
            else current_audio.copy()
        )
        _pipeline_quiet_edge_profile = (
            dict(quiet_edge_profile)
            if isinstance(quiet_edge_profile, dict)
            else UnifiedRestorerV3._compute_quiet_edge_prevention_profile(
                _pipeline_original_reference,
                sample_rate,
                material_key=str(getattr(material_type, "value", material_type)).lower() if material_type else None,
            )
        )
        # §0/§2.46 HF-Guard accumulator reset for this pipeline run.
        self._phase_metadata_accumulator = {}
        # §2.64/§2.65 MAS convergence state reset per pipeline run
        self._phase_pre_snapshot = {}
        self._phase_deltas = {}
        self._mas_fully_achieved = False
        self._phase_team_context = {
            "material_type": str(material_type.value if hasattr(material_type, "value") else material_type),
            "executed_phase_ids": [],
        }
        executed = []
        skipped = []
        deferred = []  # §2.38 KMV: phases skipped by PerformanceGuard for Stage 2 refinement
        # Defensive defaults for end-of-pipeline guards (may be read on early exits).
        _afg_pre_pipeline_audio: np.ndarray | None = None
        _afg_best_clean_checkpoint: np.ndarray | None = None
        _afg_best_clean_phase: str = "__pre_pipeline__"
        _min_per_phase_afg_score: float = 1.0
        _cum_rms_reference_audio: np.ndarray | None = current_audio.copy()
        _pre_carrier_audio: np.ndarray = current_audio.copy()
        _best_carrier_checkpoint: np.ndarray | None = None
        _last_carrier_phase_id: str | None = None
        pipeline_ml_guard_events: list[dict[str, Any]] = []
        _ml_guard_event_keys: set[tuple[Any, ...]] = set()

        # §9.11.1 Perceptual-Plateau-Stop: rolling window of recent spectral quality deltas.
        # If the last 3 executed phases each improved quality by < threshold, the music has
        # reached a perceptual plateau — further optional phases at full strength would
        # introduce spectral smearing with negligible gain. Non-mandatory phases get
        # strength dampened until a phase again exceeds the threshold.
        # Mandatory phases (§6.2a) are ALWAYS exempt.
        from collections import deque as _deque

        _plateau_delta_history: _deque = _deque(maxlen=3)

        # §2.54 Material-adaptive PlateauStop — no fixed constants, uses @staticmethod.
        _plateau_restorability = float(getattr(self, "_last_restorability_score", 65.0))
        _PLATEAU_THRESHOLD, _PLATEAU_DAMPEN = UnifiedRestorerV3._compute_plateau_params(
            material_type,
            _plateau_restorability,
        )
        logger.debug(
            "§2.54 PlateauStop params: material=%s restorability=%.1f → threshold=%.3f dampen=%.2f",
            getattr(material_type, "value", str(material_type)),
            _plateau_restorability,
            _PLATEAU_THRESHOLD,
            _PLATEAU_DAMPEN,
        )

        # §Hebel-3 PhaseConductor: leichtgewichtiger inter-phase Feedback-Controller.
        # Misst Restdefekt-Zustand nach jeder Phase und schätzt ob und wie stark
        # die nächste Phase eingreifen soll. Rein DSP, < 5 ms/Aufruf.
        _conductor = None
        _conductor_state = None
        try:
            from backend.core.phase_conductor import get_phase_conductor as _get_conductor

            _conductor = _get_conductor()
            _conductor.reset()  # neue Song-Session
        except Exception as _cond_exc:
            logger.debug("§Hebel-3 PhaseConductor nicht verfügbar: %s", _cond_exc)

        # §7 PDV: Reset session telemetry before each restoration run (Ursache 7).
        try:
            from backend.core.phase_defect_verifier import get_phase_defect_verifier as _get_pdv_init

            _get_pdv_init().reset_session()
        except Exception as _pdv_init_exc:
            logger.debug("§7 PDV session reset failed (non-blocking): %s", _pdv_init_exc)

        # §2.45 [RELEASE_MUST] perceptual_delta helper — fast spectral quality proxy.
        # Used in non-PMGG fallback paths to detect phases that degrade audio quality.
        # PMGG-main-path is covered by PMGG rollback mechanism; this is a safety net only.
        def _spectral_quality_score(a: np.ndarray, sr_: int) -> float:
            """
            Fast spectral quality proxy (pure numpy, no heavy ML).
            Higher value = cleaner/better perceptual quality.
            Based on: tonal clarity (90th vs 10th percentile log-magnitude ratio).
            Executes in approx. 1–3 ms on 5 s of audio.
            """
            try:
                mono = a[:, 0] if a.ndim == 2 else a
                max_n = int(5.0 * sr_)  # max 5 s
                if len(mono) > max_n:
                    start = (len(mono) - max_n) // 2
                    mono = mono[start : start + max_n]
                n_fft = 2048
                hop = n_fft // 4
                n_frames = max(1, (len(mono) - n_fft) // hop)
                win = np.hanning(n_fft)
                mag_acc = np.zeros(n_fft // 2 + 1)
                for k in range(min(n_frames, 30)):
                    seg = mono[k * hop : k * hop + n_fft]
                    if len(seg) < n_fft:
                        break
                    mag_acc += np.abs(np.fft.rfft(seg * win))
                mag_acc /= min(n_frames, 30)
                log_mag = np.log1p(mag_acc)
                p10, p90 = np.percentile(log_mag, [10, 90])
                tonal_ratio = float(p90 / (p10 + 1e-12))
                return float(np.clip(tonal_ratio / 6.0, 0.0, 1.0))
            except Exception:
                return 0.5  # fail-open

        # Persistent OOM forensics: write phase-level RAM snapshots to NDJSON.
        _oom_forensics_path = pathlib.Path(__file__).resolve().parents[2] / "logs" / "oom_phase_forensics.ndjson"

        def _record_oom_probe(stage: str, phase_id: str, **extra: Any) -> None:
            """Record best-effort memory telemetry for hard-crash post-mortem."""
            try:
                _event: dict[str, Any] = {
                    "ts": time.time(),
                    "stage": stage,
                    "phase_id": phase_id,
                    "mode": str(_quality_mode_value),
                    "selected_phases": len(selected_phases),
                    "executed_phases": len(executed),
                    "skipped_phases": len(skipped),
                    "deferred_phases": len(deferred),
                }
                _event.update(extra)

                try:
                    import psutil as _ps_oom

                    _proc = _ps_oom.Process(os.getpid())
                    _vm = _ps_oom.virtual_memory()
                    _event.update(
                        {
                            "rss_gb": round(_proc.memory_info().rss / (1024**3), 3),
                            "vms_gb": round(_proc.memory_info().vms / (1024**3), 3),
                            "ram_available_gb": round(_vm.available / (1024**3), 3),
                            "ram_percent": float(_vm.percent),
                        }
                    )
                    with contextlib.suppress(Exception):
                        _swap = _ps_oom.swap_memory()
                        _event["swap_percent"] = float(_swap.percent)
                except Exception as _exc:
                    logger.debug("OOM probe psutil collection failed: %s", _exc)

                with contextlib.suppress(Exception):
                    _oom_forensics_path.parent.mkdir(parents=True, exist_ok=True)
                    with _oom_forensics_path.open("a", encoding="utf-8") as _fp:
                        import json as _json

                        _fp.write(_json.dumps(_event, ensure_ascii=True) + "\n")
                        _fp.flush()

                logger.info(
                    "OOM_PROBE stage=%s phase=%s rss_gb=%s avail_gb=%s ram_pct=%s",
                    stage,
                    phase_id,
                    _event.get("rss_gb", "n/a"),
                    _event.get("ram_available_gb", "n/a"),
                    _event.get("ram_percent", "n/a"),
                )
            except Exception as _exc:
                logger.debug("OOM forensics write failed (non-critical): %s", _exc)
                # Never let forensics affect the audio pipeline.

        _record_oom_probe("pipeline_start", "__pipeline__")

        def _collect_guard_payload(
            phase_obj: Any,
            phase_id: str,
            result_obj: Any | None = None,
        ) -> None:
            """Collect structured ML guard metadata from phase results and phase instance state."""
            payloads: list[dict[str, Any]] = []

            if result_obj is not None:
                _res_meta = getattr(result_obj, "metadata", None)
                if isinstance(_res_meta, dict):
                    payloads.append(_res_meta)

            # PMGG returns only audio arrays; in that path, read events from phase state.
            _raw_phase = getattr(phase_obj, "_phase", phase_obj)
            _phase_events = getattr(_raw_phase, "_ml_guard_events", None)
            if isinstance(_phase_events, list) and _phase_events:
                payloads.append(
                    {
                        "ml_guard_events": list(_phase_events),
                        "deferred_for_kmv": [phase_id],
                    }
                )

            for payload in payloads:
                _events = payload.get("ml_guard_events", [])
                if isinstance(_events, list):
                    for _event in _events:
                        if not isinstance(_event, dict):
                            continue
                        _event_norm = dict(_event)
                        _event_norm.setdefault("phase_id", phase_id)
                        _key = (
                            str(_event_norm.get("phase_id", "")),
                            str(_event_norm.get("model", "")),
                            str(_event_norm.get("reason", "")),
                            str(_event_norm.get("fallback", "")),
                            int(float(_event_norm.get("channels", 0) or 0)),
                            round(float(_event_norm.get("duration_s", 0.0) or 0.0), 3),
                            round(float(_event_norm.get("required_gb", 0.0) or 0.0), 3),
                            round(float(_event_norm.get("available_gb", 0.0) or 0.0), 3),
                        )
                        if _key in _ml_guard_event_keys:
                            continue
                        _ml_guard_event_keys.add(_key)
                        pipeline_ml_guard_events.append(_event_norm)

                _deferred_hint = payload.get("deferred_for_kmv", [])
                if isinstance(_deferred_hint, list):
                    for _pid in _deferred_hint:
                        if isinstance(_pid, str) and _pid and _pid not in deferred:
                            deferred.append(_pid)

        def _normalize_phase_result(_r):
            """Accept legacy ndarray returns and normalize to PhaseResult-like object."""
            if hasattr(_r, "success"):
                return _r
            if isinstance(_r, np.ndarray):
                return SimpleNamespace(
                    success=True,
                    audio=_r,
                    execution_time_seconds=0.0,
                    warnings=[],
                )
            return SimpleNamespace(
                success=False,
                audio=current_audio,
                execution_time_seconds=0.0,
                warnings=[f"invalid_phase_result_type:{type(_r).__name__}"],
            )

        def _rms_dbfs(_x: np.ndarray) -> float:
            _arr = np.asarray(_x, dtype=np.float32)
            return float(20.0 * np.log10(float(np.sqrt(np.mean(_arr * _arr) + 1e-12))))

        def _rms_dbfs_gated(_x: np.ndarray, gate_dbfs: float = -50.0) -> float:
            """Gated RMS: only measure frames with musical content above *gate_dbfs*.

            Silent passages (noise floor, pauses, fade-outs) are excluded so that
            noise removal in silence does not appear as a musical level drop.
            Frame size = 2048 samples (~43 ms @ 48 kHz) — short enough for transient
            resolution, long enough to avoid single-sample noise spikes.

            For stereo audio, channels are downmixed to mono first to avoid
            interleaved-sample artifacts in frame boundaries.

            §2.45a Adaptive Gate (Pegelexplosion-Schutz, v9.11.62):
            Wenn der P5-Rauschboden der Frames mehr als 12 dB über gate_dbfs liegt
            (Vinyl/Shellac ~-40 dBFS), wird der effektive Gate auf (P5 + 6 dB) angehoben.
            Damit werden Noise-Frames aus der Referenz-RMS-Messung AUSGESCHLOSSEN —
            verhindert, dass das Entfernen von Rauschen als "Lautstärke-Drop" gewertet wird.

            Falls back to ungated RMS when < 5 % of frames pass the gate (e.g.
            very quiet recordings or near-silence — ungated is safer there).
            """
            _arr = np.asarray(_x, dtype=np.float32)
            # Stereo → mono downmix before framing (avoid interleaved L/R in frames)
            if _arr.ndim == 2:
                if _arr.shape[0] == 2:
                    _flat = ((_arr[0] + _arr[1]) * 0.5).ravel()
                elif _arr.shape[1] == 2:
                    _flat = ((_arr[:, 0] + _arr[:, 1]) * 0.5).ravel()
                else:
                    _flat = _arr.ravel()
            else:
                _flat = _arr.ravel()
            _frame_len = 2048
            _n_frames = max(1, len(_flat) // _frame_len)
            _frames = _flat[: _n_frames * _frame_len].reshape(_n_frames, _frame_len)
            _frame_rms = np.sqrt(np.mean(_frames * _frames, axis=1) + 1e-12)
            _frame_dbfs = 20.0 * np.log10(_frame_rms + 1e-12)
            # Adaptive gate: Vinyl/Shellac Noise-Floor (≈-35 to -45 dBFS) liegt über -50-dBFS-Gate →
            # inflationiert die Referenz-RMS → scheinbarer "Drop" nach Denoise → Pegelexplosion.
            # §2.45a v9.12.1: effective_gate = max(gate, P5+10) statt alter P5+6-Formel.
            # Alte Bedingung (P5 > gate+12 = -38) schlug für Vinyl (P5≈-42) fehl — Noise-Frames
            # blieben in der Messung → false level-drop → Makeup-Gain auf Rauschen → Explosion.
            # Neue Formel: P5+10 gibt 10 dB Headroom über dem Rauschboden → Vinyl-Noise (-35 dBFS)
            # wird zuverlässig ausgeschlossen, Musik-Frames (-20 bis -25 dBFS) bleiben drin.
            _effective_gate = gate_dbfs
            if len(_frame_dbfs) >= 10:
                _p5_db = float(np.percentile(_frame_dbfs, 5))
                _adaptive_gate = _p5_db + 10.0
                if _adaptive_gate > gate_dbfs:  # True whenever P5 > gate-10 (all real audio)
                    _effective_gate = min(_adaptive_gate, gate_dbfs + 25.0)
            _gate_mask = _frame_dbfs > _effective_gate
            if np.sum(_gate_mask) < max(1, int(0.05 * _n_frames)):
                # < 5 % frames above gate → fall back to ungated (very quiet recording)
                return _rms_dbfs(_x)
            _gated_rms = float(np.sqrt(np.mean(_frame_rms[_gate_mask] ** 2) + 1e-12))
            return float(20.0 * np.log10(_gated_rms + 1e-12))

        def _peak_p999(_x: np.ndarray) -> float:
            _arr = np.asarray(_x, dtype=np.float32)
            return float(np.percentile(np.abs(_arr), 99.9))

        def _imbalance_db(_x: np.ndarray) -> float:
            if not isinstance(_x, np.ndarray) or _x.ndim != 2 or _x.shape[0] != 2:
                return 0.0
            _l = float(np.sqrt(np.mean(_x[0] ** 2)) + 1e-12)
            _r = float(np.sqrt(np.mean(_x[1] ** 2)) + 1e-12)
            return float(abs(20.0 * np.log10((_l + 1e-12) / (_r + 1e-12))))

        def _transient_ratio(_ref: np.ndarray, _cand: np.ndarray) -> float:
            try:
                _rd = np.diff(np.asarray(_ref, dtype=np.float32), axis=-1)
                _cd = np.diff(np.asarray(_cand, dtype=np.float32), axis=-1)
                _r95 = float(np.percentile(np.abs(_rd), 95.0))
                _c95 = float(np.percentile(np.abs(_cd), 95.0))
                if _r95 <= 1e-9:
                    return 1.0
                return float(np.clip(_c95 / _r95, 0.0, 4.0))
            except Exception:
                return 1.0

        def _mono_compatibility(_x: np.ndarray) -> float:
            try:
                _arr = np.asarray(_x, dtype=np.float32)
                if _arr.ndim != 2 or _arr.shape[0] != 2:
                    return 1.0
                _mid = 0.5 * (_arr[0] + _arr[1])
                _side = 0.5 * (_arr[0] - _arr[1])
                _mid_rms = float(np.sqrt(np.mean(_mid * _mid)) + 1e-12)
                _side_rms = float(np.sqrt(np.mean(_side * _side)) + 1e-12)
                return float(np.clip(_mid_rms / (_mid_rms + _side_rms + 1e-12), 0.0, 1.0))
            except Exception:
                return 1.0

        def _hf_energy_ratio(_ref: np.ndarray, _cand: np.ndarray) -> float:
            try:
                _ref_arr = np.asarray(_ref, dtype=np.float32)
                _cand_arr = np.asarray(_cand, dtype=np.float32)
                if _ref_arr.ndim == 2:
                    _ref_arr = np.mean(_ref_arr, axis=0)
                if _cand_arr.ndim == 2:
                    _cand_arr = np.mean(_cand_arr, axis=0)
                _ref_mag = np.abs(np.fft.rfft(_ref_arr))
                _cand_mag = np.abs(np.fft.rfft(_cand_arr))
                if _ref_mag.size < 8 or _cand_mag.size != _ref_mag.size:
                    return 1.0
                _start = int(_ref_mag.size * 0.65)
                _ref_hf = float(np.mean(_ref_mag[_start:]) + 1e-12)
                _cand_hf = float(np.mean(_cand_mag[_start:]) + 1e-12)
                return float(np.clip(_cand_hf / _ref_hf, 0.0, 4.0))
            except Exception:
                return 1.0

        def _quiet_zone_explosion_stats(
            _ref: np.ndarray,
            _cand: np.ndarray,
            _quiet_dbfs: float = -34.0,
            _thr_db: float = 2.0,
            _win_s: float = 1.0,
            _hop_s: float = 0.25,
        ) -> dict[str, float]:
            """Return quiet-zone explosion stats on window RMS deltas.

            A quiet-zone explosion is a frame where:
            - reference RMS is in quiet zone (<= _quiet_dbfs)
            - candidate is louder than reference by > _thr_db

            This catches local intro/outro/fade spikes that global gated RMS can miss.
            """
            try:
                _r = np.asarray(_ref, dtype=np.float32)
                _c = np.asarray(_cand, dtype=np.float32)
                if _r.ndim == 2:
                    _r = np.mean(_r, axis=0)
                if _c.ndim == 2:
                    _c = np.mean(_c, axis=0)
                _n = int(min(len(_r), len(_c)))
                if _n <= 2048:
                    return {
                        "count": 0.0,
                        "quiet_frames": 0.0,
                        "max_delta_db": 0.0,
                        "delta_p95_db": 0.0,
                        "delta_mean_db": 0.0,
                    }
                _r = _r[:_n]
                _c = _c[:_n]
                _win = max(2048, int(_win_s * float(sample_rate)))
                _hop = max(512, int(_hop_s * float(sample_rate)))
                _n_frames = max(1, (_n - _win) // _hop + 1)
                _r_db = np.empty(_n_frames, dtype=np.float64)
                _c_db = np.empty(_n_frames, dtype=np.float64)
                for _k in range(_n_frames):
                    _s = _k * _hop
                    _e = min(_s + _win, _n)
                    _r_rms = float(np.sqrt(np.mean(_r[_s:_e] ** 2) + 1e-12))
                    _c_rms = float(np.sqrt(np.mean(_c[_s:_e] ** 2) + 1e-12))
                    _r_db[_k] = 20.0 * np.log10(_r_rms + 1e-12)
                    _c_db[_k] = 20.0 * np.log10(_c_rms + 1e-12)
                _delta = _c_db - _r_db
                _quiet = _r_db <= float(_quiet_dbfs)
                _expl = _quiet & (_delta > float(_thr_db))
                _max_delta = float(np.max(_delta[_expl])) if np.any(_expl) else 0.0
                _quiet_delta = _delta[_quiet]
                _p95 = float(np.percentile(_quiet_delta, 95.0)) if _quiet_delta.size > 0 else 0.0
                _mean = float(np.mean(_quiet_delta)) if _quiet_delta.size > 0 else 0.0
                return {
                    "count": float(np.sum(_expl)),
                    "quiet_frames": float(np.sum(_quiet)),
                    "max_delta_db": _max_delta,
                    "delta_p95_db": _p95,
                    "delta_mean_db": _mean,
                }
            except Exception:
                return {
                    "count": 0.0,
                    "quiet_frames": 0.0,
                    "max_delta_db": 0.0,
                    "delta_p95_db": 0.0,
                    "delta_mean_db": 0.0,
                }

        def _apply_quiet_zone_explosion_guard(
            _ref: np.ndarray,
            _cand: np.ndarray,
            _quiet_dbfs: float = -34.0,
            _thr_db: float = 2.0,
            _win_s: float = 1.0,
            _hop_s: float = 0.25,
            _attack_s: float = 0.010,
            _release_s: float = 0.030,
        ) -> tuple[np.ndarray, dict[str, float]]:
            """Attenuate local quiet-zone explosions (never boost, attenuation only)."""
            _meta = {
                "applied": 0.0,
                "before_count": 0.0,
                "after_count": 0.0,
                "max_attenuation_db": 0.0,
                "before_max_delta_db": 0.0,
                "before_delta_p95_db": 0.0,
                "before_delta_mean_db": 0.0,
                "after_delta_p95_db": 0.0,
                "after_delta_mean_db": 0.0,
            }
            try:
                _r = np.asarray(_ref, dtype=np.float32)
                _x = np.asarray(_cand, dtype=np.float32)
                _n = int(min(_r.shape[-1], _x.shape[-1]))
                if _n <= 2048:
                    return _x, _meta
                _r = _r[..., :_n]
                _x = _x[..., :_n]
                _r_m = np.mean(_r, axis=0) if _r.ndim == 2 else _r
                _x_m = np.mean(_x, axis=0) if _x.ndim == 2 else _x

                _win = max(2048, int(_win_s * float(sample_rate)))
                _hop = max(512, int(_hop_s * float(sample_rate)))
                _n_frames = max(1, (_n - _win) // _hop + 1)
                _r_db = np.empty(_n_frames, dtype=np.float64)
                _x_db = np.empty(_n_frames, dtype=np.float64)
                for _k in range(_n_frames):
                    _s = _k * _hop
                    _e = min(_s + _win, _n)
                    _r_rms = float(np.sqrt(np.mean(_r_m[_s:_e] ** 2) + 1e-12))
                    _x_rms = float(np.sqrt(np.mean(_x_m[_s:_e] ** 2) + 1e-12))
                    _r_db[_k] = 20.0 * np.log10(_r_rms + 1e-12)
                    _x_db[_k] = 20.0 * np.log10(_x_rms + 1e-12)
                _delta = _x_db - _r_db
                _quiet = _r_db <= float(_quiet_dbfs)
                _expl = _quiet & (_delta > float(_thr_db))
                _meta["before_count"] = float(np.sum(_expl))
                _meta["before_max_delta_db"] = float(np.max(_delta[_expl])) if np.any(_expl) else 0.0
                _quiet_delta_pre = _delta[_quiet]
                _meta["before_delta_p95_db"] = (
                    float(np.percentile(_quiet_delta_pre, 95.0)) if _quiet_delta_pre.size > 0 else 0.0
                )
                _meta["before_delta_mean_db"] = float(np.mean(_quiet_delta_pre)) if _quiet_delta_pre.size > 0 else 0.0
                if not np.any(_expl):
                    return _x, _meta

                _gain_db_frames = np.zeros(_n_frames, dtype=np.float64)
                for _k in range(_n_frames):
                    if _expl[_k]:
                        # Quiet-zone invariant: correct to reference level, attenuation only.
                        _gain_db_frames[_k] = float(np.clip(_r_db[_k] - _x_db[_k], -60.0, 0.0))

                _centres = np.array([_k * _hop + _win // 2 for _k in range(_n_frames)], dtype=np.float64)
                _sample_idx = np.arange(_n, dtype=np.float64)
                _gain_db = np.interp(_sample_idx, _centres, _gain_db_frames).astype(np.float32)
                _gain_db = np.minimum(_gain_db, 0.0)

                # Smooth attenuation envelope to prevent zipper-noise/crackle on frame edges.
                # Attack: attenuation increases quickly. Release: attenuation relaxes slower.
                _atk = max(1, int(float(_attack_s) * float(sample_rate)))
                _rel = max(1, int(float(_release_s) * float(sample_rate)))
                _alpha_atk = float(np.exp(-1.0 / float(_atk)))
                _alpha_rel = float(np.exp(-1.0 / float(_rel)))
                _smoothed = _gain_db.copy()
                for _i in range(1, _smoothed.shape[0]):
                    _target = float(_smoothed[_i])
                    _prev = float(_smoothed[_i - 1])
                    _alpha = _alpha_atk if _target < _prev else _alpha_rel
                    _smoothed[_i] = np.float32(_alpha * _prev + (1.0 - _alpha) * _target)
                _gain_db = np.minimum(_smoothed, 0.0)

                _gain_lin = np.power(10.0, _gain_db / 20.0, dtype=np.float32)

                if _x.ndim == 2:
                    _y = _x * _gain_lin[None, :]
                else:
                    _y = _x * _gain_lin
                _y = np.clip(np.nan_to_num(_y, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)

                _post = _quiet_zone_explosion_stats(_r, _y, _quiet_dbfs=_quiet_dbfs, _thr_db=_thr_db)
                _post_count = int(_post.get("count", 0.0))

                # Hard-pass fallback: if smoothed envelope still leaves explosions,
                # apply deterministic per-window attenuation WITH a short crossfade taper
                # at window edges to prevent new zipper-noise artifacts between windows.
                # Root-cause of "hard-pass creates new explosion" was abrupt gain steps
                # at window boundaries — solved by linear crossfade over 10 ms.
                if _post_count > 0:
                    _y2 = _y.copy()
                    _y2_m = np.mean(_y2, axis=0) if _y2.ndim == 2 else _y2
                    _y2_db = np.empty(_n_frames, dtype=np.float64)
                    for _k in range(_n_frames):
                        _s = _k * _hop
                        _e = min(_s + _win, _n)
                        _y2_rms = float(np.sqrt(np.mean(_y2_m[_s:_e] ** 2) + 1e-12))
                        _y2_db[_k] = 20.0 * np.log10(_y2_rms + 1e-12)
                    _delta2 = _y2_db - _r_db
                    _quiet2 = _r_db <= float(_quiet_dbfs)
                    _expl2 = _quiet2 & (_delta2 > float(_thr_db))
                    if np.any(_expl2):
                        _xfade_n = max(1, int(0.010 * float(sample_rate)))  # 10 ms crossfade
                        for _k in np.where(_expl2)[0]:
                            _s = int(_k * _hop)
                            _e = int(min(_s + _win, _n))
                            _need_db = float(np.clip(_r_db[_k] - _y2_db[_k], -60.0, 0.0))
                            _need_lin = float(np.power(10.0, _need_db / 20.0))
                            if _need_lin < 0.9999:
                                # Build a gain envelope that fades in at the left edge and
                                # fades out at the right edge to avoid hard gain steps.
                                _seg_len = _e - _s
                                _env = np.ones(_seg_len, dtype=np.float32)
                                _xfl = min(_xfade_n, _seg_len // 4)
                                if _xfl > 0:
                                    _env[:_xfl] = np.linspace(1.0, _need_lin, _xfl, dtype=np.float32)
                                    _env[_xfl : max(_xfl, _seg_len - _xfl)] = _need_lin
                                    _env[max(_xfl, _seg_len - _xfl) :] = np.linspace(
                                        _need_lin, 1.0, _seg_len - max(_xfl, _seg_len - _xfl), dtype=np.float32
                                    )
                                else:
                                    _env[:] = _need_lin
                                if _y2.ndim == 2:
                                    _y2[:, _s:_e] = _y2[:, _s:_e] * _env[None, :]
                                else:
                                    _y2[_s:_e] = _y2[_s:_e] * _env
                        _y2 = np.clip(np.nan_to_num(_y2, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                        _post2 = _quiet_zone_explosion_stats(_r, _y2, _quiet_dbfs=_quiet_dbfs, _thr_db=_thr_db)
                        if int(_post2.get("count", 0.0)) <= _post_count:
                            _y = _y2
                            _post = _post2

                # Second smoothed-envelope pass: if any explosions remain after the hard-pass,
                # run the full smoothed-gain curve again on the current result.
                # The second pass has a much more targeted region (only the 1 remaining window)
                # and a clean, smooth gain envelope — this eliminates the last explosion.
                _post_count2 = int(_post.get("count", 0.0))
                if _post_count2 > 0:
                    _x2_db = np.empty(_n_frames, dtype=np.float64)
                    _y3_m = np.mean(_y, axis=0) if _y.ndim == 2 else _y
                    for _k in range(_n_frames):
                        _s = _k * _hop
                        _e = min(_s + _win, _n)
                        _y3_rms = float(np.sqrt(np.mean(_y3_m[_s:_e] ** 2) + 1e-12))
                        _x2_db[_k] = 20.0 * np.log10(_y3_rms + 1e-12)
                    _delta3 = _x2_db - _r_db
                    _expl3 = (_r_db <= float(_quiet_dbfs)) & (_delta3 > float(_thr_db))
                    if np.any(_expl3):
                        _gain3_frames = np.zeros(_n_frames, dtype=np.float64)
                        for _k in range(_n_frames):
                            if _expl3[_k]:
                                _gain3_frames[_k] = float(np.clip(_r_db[_k] - _x2_db[_k], -60.0, 0.0))
                        _centres3 = np.array([_k * _hop + _win // 2 for _k in range(_n_frames)], dtype=np.float64)
                        _g3_interp = np.interp(np.arange(_n, dtype=np.float64), _centres3, _gain3_frames).astype(
                            np.float32
                        )
                        _g3_interp = np.minimum(_g3_interp, 0.0)
                        # Apply same attack/release smoothing as first pass
                        _sm3 = _g3_interp.copy()
                        for _i in range(1, _sm3.shape[0]):
                            _t3 = float(_sm3[_i])
                            _p3 = float(_sm3[_i - 1])
                            _a3 = _alpha_atk if _t3 < _p3 else _alpha_rel
                            _sm3[_i] = np.float32(_a3 * _p3 + (1.0 - _a3) * _t3)
                        _g3_lin = np.power(10.0, np.minimum(_sm3, 0.0) / 20.0, dtype=np.float32)
                        _y3 = _y * _g3_lin[None, :] if _y.ndim == 2 else _y * _g3_lin
                        _y3 = np.clip(np.nan_to_num(_y3, nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0)
                        _post3 = _quiet_zone_explosion_stats(_r, _y3, _quiet_dbfs=_quiet_dbfs, _thr_db=_thr_db)
                        if int(_post3.get("count", 0.0)) <= _post_count2:
                            _y = _y3
                            _post = _post3

                _meta["after_count"] = float(_post.get("count", 0.0))
                _meta["after_delta_p95_db"] = float(_post.get("delta_p95_db", 0.0))
                _meta["after_delta_mean_db"] = float(_post.get("delta_mean_db", 0.0))
                _meta["max_attenuation_db"] = float(np.min(_gain_db)) if np.any(_gain_db < 0.0) else 0.0
                _meta["applied"] = 1.0 if _meta["after_count"] < _meta["before_count"] else 0.0
                return (_y if _meta["applied"] > 0.5 else _x), _meta
            except Exception:
                return np.asarray(_cand, dtype=np.float32), _meta

        def _derive_phase_guard_contract(_phase_id: str, _ref: np.ndarray, _prof: dict[str, Any]) -> dict[str, float]:
            """Adaptive guard contract for universal behavior across import-song quality spectrum.

            Contract values are derived from:
            - material family (analog/digital noise-floor priors)
            - restorability (clean sources need stricter local-boost tolerance)
            - reference signal distribution (song-specific quiet-zone level)
            - intervention family (subtractive vs additive behavior)
            """
            _mat_key = str(getattr(material_type, "value", material_type)).lower()
            _family = str(_prof.get("family", "general"))
            _rest_score = float(np.clip(restorability_score, 0.0, 100.0))

            # Material priors for quiet-zone level (dBFS).
            _material_quiet_floor = {
                "shellac": -37.0,
                "wax_cylinder": -38.0,
                "wire_recording": -37.0,
                "vinyl": -35.0,
                "reel_tape": -36.0,
                "tape": -36.0,
                "cassette": -36.0,
                "cd_digital": -44.0,
                "dat": -44.0,
                "mp3_high": -42.0,
                "mp3_low": -39.0,
                "aac": -42.0,
                "streaming": -42.0,
                "default": -36.0,
            }

            # Family baseline for local explosion threshold in quiet zones.
            _family_thr = {
                "subtractive_cleanup": 2.0,
                "harmonic_noise_control": 2.0,
                "spectral_restoration": 2.2,
                "reconstruction_inpainting": 2.6,
                "harmonic_reconstruction": 2.6,
                "time_pitch_transport": 2.0,
                "stereo_phase_geometry": 2.0,
                "stereo_enhancement": 2.2,
                "source_enhancement": 2.4,
                "tonal_enhancement": 2.4,
                "dynamics_repair": 2.2,
                "dynamics_control": 2.2,
                "finalizer_output": 2.0,
                "default": 2.2,
            }

            _ref_arr = np.asarray(_ref, dtype=np.float32)
            _ref_m = np.mean(_ref_arr, axis=0) if _ref_arr.ndim == 2 else _ref_arr
            _n = int(_ref_m.shape[-1])
            _frame_db = np.array([-80.0], dtype=np.float64)
            if _n > 4096:
                _win = max(2048, int(1.0 * float(sample_rate)))
                _hop = max(512, int(0.25 * float(sample_rate)))
                _n_frames = max(1, (_n - _win) // _hop + 1)
                _frame_db = np.empty(_n_frames, dtype=np.float64)
                for _k in range(_n_frames):
                    _s = _k * _hop
                    _e = min(_s + _win, _n)
                    _rms = float(np.sqrt(np.mean(_ref_m[_s:_e] ** 2) + 1e-12))
                    _frame_db[_k] = 20.0 * np.log10(_rms + 1e-12)

            _p10 = float(np.percentile(_frame_db, 10.0))
            _p50 = float(np.percentile(_frame_db, 50.0))
            _mat_floor = float(_material_quiet_floor.get(_mat_key, _material_quiet_floor["default"]))

            # Song-adaptive quiet-zone boundary: max(material prior, song P10 + 2 dB).
            _quiet_dbfs = float(np.clip(max(_mat_floor, _p10 + 2.0), -48.0, -22.0))

            _thr_base = float(_family_thr.get(_family, _family_thr["default"]))
            # Quality-adaptive threshold:
            # - very clean songs (restorability > 80): stricter (protect natural dynamics)
            # - very damaged songs (< 30): slightly more permissive to avoid over-triggering.
            _quality_adj = -0.5 if _rest_score > 80.0 else (0.25 if _rest_score < 30.0 else 0.0)
            # If the track has very low dynamic spread in quiet half, tighten further.
            _quiet_spread = float(max(0.0, _p50 - _p10))
            _spread_adj = -0.2 if _quiet_spread < 6.0 else 0.0
            _thr_db = float(np.clip(_thr_base + _quality_adj + _spread_adj, 1.0, 3.5))

            return {
                "quiet_dbfs": _quiet_dbfs,
                "threshold_db": _thr_db,
                "ref_p10_dbfs": _p10,
                "ref_p50_dbfs": _p50,
                "restorability": _rest_score,
            }

        def _phase_intervention_profile(phase_id: str) -> dict[str, Any]:
            """Build a phase-specific intervention profile (family + exact overrides)."""
            _meta = self.phase_metadata.get(phase_id, {})
            _category = str(_meta.get("category", "")).lower()
            _pid = str(phase_id).lower()

            _family = self._PHASE_INTERVENTION_CLASS.get(phase_id, "general")
            _profile: dict[str, Any] = dict(
                self._INTERVENTION_CLASS_DEFAULTS.get(_family, self._INTERVENTION_CLASS_DEFAULTS["general"])
            )
            _profile["family"] = _family

            # Category-based refinements.
            if _category in {"cleanup", "denoise", "restoration"}:
                _profile["cost_transient_w"] = max(float(_profile["cost_transient_w"]), 3.2)
            if _category in {"mastering", "output"}:
                _profile["enable_transient"] = False

            # Exact phase overrides for known critical paths.
            _phase_overrides: dict[str, dict[str, Any]] = {
                "phase_03_denoise": {
                    "family": "phase03_denoise",
                    "transient_floor": 0.78,
                    "dry_blend_min": 0.12,
                    "dry_blend_max": 0.34,
                    "cost_transient_w": 4.3,
                    "enable_hf_excess_guard": True,
                    "hf_cap": 1.18,
                    "cost_hf_excess_w": 3.2,
                },
                "phase_06_frequency_restoration": {
                    "family": "phase06_freq_restore",
                    "enable_loudness": True,
                    "enable_stereo": False,
                    "enable_hf_preservation": True,
                    "hf_floor": 0.92,
                    "transient_floor": 0.70,
                    "dry_blend_min": 0.08,
                    "dry_blend_max": 0.20,
                    "cost_loudness_w": 0.7,
                    "cost_transient_w": 2.4,
                    "cost_hf_w": 3.0,
                },
                "phase_18_noise_gate": {
                    "family": "phase18_noise_gate",
                    "transient_floor": 0.80,
                    "dry_blend_min": 0.14,
                    "dry_blend_max": 0.36,
                    "cost_transient_w": 4.6,
                },
                "phase_20_reverb_reduction": {
                    "family": "phase20_dereverb",
                    "transient_floor": 0.75,
                    "dry_blend_min": 0.10,
                    "dry_blend_max": 0.28,
                    "cost_transient_w": 4.0,
                    # Fix 8: Dereverb darf max 2.5 dB Pegel kosten (Musik-Substanz-Guard)
                    # Material-Default mp3_low=4.5 dB ist viel zu permissiv für Reverb-Entfernung
                    "max_rms_drop_db_override": 2.5,
                    "cost_loudness_w": 2.0,
                },
                "phase_23_spectral_repair": {
                    "family": "phase23_spectral",
                    "enable_loudness": True,
                    "enable_stereo": False,
                    "enable_hf_preservation": True,
                    "hf_floor": 0.89,
                    "enable_hf_excess_guard": True,
                    "hf_cap": 1.35,
                    "transient_floor": 0.68,
                    "dry_blend_min": 0.09,
                    "dry_blend_max": 0.22,
                    "cost_loudness_w": 0.8,
                    "cost_transient_w": 2.6,
                    "cost_hf_w": 2.8,
                    "cost_hf_excess_w": 1.8,
                },
                "phase_49_advanced_dereverb": {
                    "family": "phase49_dereverb",
                    "transient_floor": 0.73,
                    "dry_blend_min": 0.10,
                    "dry_blend_max": 0.26,
                    "cost_transient_w": 3.8,
                    # Fix 8: Dereverb darf max 2.5 dB Pegel kosten (Musik-Substanz-Guard)
                    "max_rms_drop_db_override": 2.5,
                    "cost_loudness_w": 2.0,
                },
                "phase_63_intermodulation_reduction": {
                    "family": "phase63_imd",
                    "enable_loudness": False,
                    "enable_stereo": False,
                    "enable_hf_preservation": True,
                    "hf_floor": 0.85,
                    "transient_floor": 0.62,
                    "dry_blend_min": 0.04,
                    "dry_blend_max": 0.12,
                    "cost_transient_w": 1.5,
                    "cost_hf_w": 1.6,
                },
                "phase_14_phase_correction": {
                    "family": "phase14_phase",
                    "enable_loudness": False,
                    "enable_transient": False,
                    "stereo_abs_db": 9.0,
                    "stereo_growth_db": 2.5,
                    "stereo_target_db": 5.0,
                    "stereo_gain_cap": 1.5,
                    "cost_stereo_w": 0.65,
                },
                "phase_25_azimuth_correction": {
                    "family": "phase25_azimuth",
                    "enable_loudness": False,
                    "enable_transient": False,
                    "stereo_abs_db": 9.0,
                    "stereo_growth_db": 2.0,
                    "stereo_target_db": 5.0,
                    "stereo_gain_cap": 1.45,
                    "cost_stereo_w": 0.70,
                },
                # §2.45a-VI: HPF/Notch — Energieverlust ist BEABSICHTIGT (Carrier-Inversion).
                # enable_loudness=False verhindert, dass _active_quality_intervention
                # den RMS-Drop durch Rumble/Hum-Entfernung als Loudness-Kollaps fehlinterpretiert
                # und Makeup-Gain triggert → Pegelexplosion. UV3-Cumulative-Guard (§2.45a-IV) übernimmt.
                "phase_05_rumble_filter": {
                    "family": "phase05_hpf",
                    "enable_loudness": False,
                    "enable_stereo": False,
                    "enable_transient": False,
                },
                "phase_02_hum_removal": {
                    "family": "phase02_notch",
                    "enable_loudness": False,
                    "enable_stereo": False,
                    "enable_transient": False,
                },
                "phase_12_wow_flutter_fix": {
                    "family": "phase12_timing",
                    "enable_loudness": False,
                    "enable_stereo": False,
                    "transient_floor": 0.84,
                    "dry_blend_min": 0.18,
                    "dry_blend_max": 0.45,
                    "cost_transient_w": 4.8,
                },
                "phase_24_dropout_repair": {
                    "family": "phase24_dropout",
                    "enable_stereo": False,
                    "transient_floor": 0.78,
                    "dry_blend_min": 0.10,
                    "dry_blend_max": 0.30,
                    "cost_transient_w": 3.2,
                },
                "phase_55_diffusion_inpainting": {
                    "family": "phase55_inpainting",
                    "enable_stereo": False,
                    "transient_floor": 0.76,
                    "dry_blend_min": 0.12,
                    "dry_blend_max": 0.34,
                    "cost_transient_w": 3.6,
                },
                "phase_40_loudness_normalization": {
                    "family": "phase40_loudness",
                    "enable_stereo": False,
                    "enable_transient": False,
                    "cost_loudness_w": 0.1,
                },
                "phase_47_truepeak_limiter": {
                    "family": "phase47_truepeak",
                    "enable_stereo": False,
                    "enable_transient": False,
                    "cost_loudness_w": 0.1,
                },
            }
            _profile.update(_phase_overrides.get(phase_id, {}))
            return _profile

        def _intervention_cost(_ref: np.ndarray, _cand: np.ndarray, _prof: dict[str, Any]) -> float:
            _rms_drop = _rms_dbfs(_ref) - _rms_dbfs(_cand)
            _imb_ref = _imbalance_db(_ref)
            _imb_cand = _imbalance_db(_cand)
            _imb_growth = max(0.0, _imb_cand - max(_imb_ref, float(_prof.get("stereo_target_db", 8.0))))
            _tr_ratio = _transient_ratio(_ref, _cand)
            _tr_loss = max(0.0, float(_prof.get("transient_floor", 0.65)) - _tr_ratio)
            _mono_ref = _mono_compatibility(_ref)
            _mono_cand = _mono_compatibility(_cand)
            _mono_floor = max(float(_prof.get("mono_compat_floor", 0.50)), _mono_ref - 0.05)
            _mono_loss = max(0.0, _mono_floor - _mono_cand)
            _hf_ratio = _hf_energy_ratio(_ref, _cand)
            _hf_loss = max(0.0, float(_prof.get("hf_floor", 0.75)) - _hf_ratio)
            _hf_cap = float(_prof.get("hf_cap", 4.0))
            _hf_excess = max(0.0, _hf_ratio - _hf_cap) if bool(_prof.get("enable_hf_excess_guard", False)) else 0.0
            return float(
                float(_prof.get("cost_loudness_w", 1.0)) * max(0.0, _rms_drop - 3.5)
                + float(_prof.get("cost_stereo_w", 0.25)) * _imb_growth
                + float(_prof.get("cost_transient_w", 3.0)) * _tr_loss
                + float(_prof.get("cost_mono_compat_w", 0.0)) * _mono_loss
                + float(_prof.get("cost_hf_w", 0.0)) * _hf_loss
                + float(_prof.get("cost_hf_excess_w", 0.0)) * _hf_excess
            )

        def _active_quality_intervention(
            phase_id: str,
            _ref: np.ndarray,
            _cand: np.ndarray,
            *,
            original_reference: np.ndarray | None = None,
            quiet_edge_profile: dict[str, Any] | None = None,
        ) -> np.ndarray:
            """Actively rescue catastrophic phase side-effects (loudness/stereo/transients).

            This executes only when a measurable deterioration is present and only keeps
            the intervention if the composite cost decreases.
            """
            _mat = str(getattr(material_type, "value", material_type)).lower()
            _max_rms_drop_db = {
                "shellac": 2.2,
                "wax_cylinder": 2.2,
                "wire_recording": 2.3,
                "vinyl": 2.8,
                "reel_tape": 3.0,
                "tape": 3.0,
                "cassette": 3.0,
                "cd_digital": 4.0,
                "dat": 4.0,
                "mp3_low": 4.5,
                "mp3_high": 4.0,
                "aac": 4.0,
                "streaming": 4.0,
            }.get(_mat, 3.5)

            _ref_arr = np.asarray(_ref, dtype=np.float32)
            _base = np.clip(
                np.nan_to_num(np.asarray(_cand, dtype=np.float32), nan=0.0, posinf=0.0, neginf=0.0), -1.0, 1.0
            )
            _work = _base.copy()
            _actions: list[dict[str, Any]] = []
            _prof = _phase_intervention_profile(phase_id)
            _guard_contract = _derive_phase_guard_contract(phase_id, _ref_arr, _prof)

            # Local quiet-zone explosion prevention (prevents intro/outro pegel spikes
            # before final WPG catch-all). Runs for every phase and only attenuates.
            _qz_guard_candidate, _qz_guard_meta = _apply_quiet_zone_explosion_guard(
                _ref_arr,
                _work,
                _quiet_dbfs=float(_guard_contract.get("quiet_dbfs", -34.0)),
                _thr_db=float(_guard_contract.get("threshold_db", 2.0)),
            )
            if float(_qz_guard_meta.get("applied", 0.0)) > 0.5:
                _work = _qz_guard_candidate
                _actions.append(
                    {
                        "type": "quiet_zone_local_guard",
                        "quiet_dbfs": round(float(_guard_contract.get("quiet_dbfs", -34.0)), 3),
                        "threshold_db": round(float(_guard_contract.get("threshold_db", 2.0)), 3),
                        "before_count": int(_qz_guard_meta.get("before_count", 0.0)),
                        "after_count": int(_qz_guard_meta.get("after_count", 0.0)),
                        "before_max_delta_db": round(float(_qz_guard_meta.get("before_max_delta_db", 0.0)), 3),
                        "before_delta_p95_db": round(float(_qz_guard_meta.get("before_delta_p95_db", 0.0)), 3),
                        "after_delta_p95_db": round(float(_qz_guard_meta.get("after_delta_p95_db", 0.0)), 3),
                        "before_delta_mean_db": round(float(_qz_guard_meta.get("before_delta_mean_db", 0.0)), 3),
                        "after_delta_mean_db": round(float(_qz_guard_meta.get("after_delta_mean_db", 0.0)), 3),
                        "max_attenuation_db": round(float(_qz_guard_meta.get("max_attenuation_db", 0.0)), 3),
                    }
                )
                logger.warning(
                    "§2.45a QuietZone-Guard %s: explosions %d→%d"
                    " (qz<=%.1f dBFS thr=%.2f dB, maxΔ=%.2f dB,"
                    " p95Δ %.2f→%.2f dB, att=%.2f dB)",
                    phase_id,
                    int(_qz_guard_meta.get("before_count", 0.0)),
                    int(_qz_guard_meta.get("after_count", 0.0)),
                    float(_guard_contract.get("quiet_dbfs", -34.0)),
                    float(_guard_contract.get("threshold_db", 2.0)),
                    float(_qz_guard_meta.get("before_max_delta_db", 0.0)),
                    float(_qz_guard_meta.get("before_delta_p95_db", 0.0)),
                    float(_qz_guard_meta.get("after_delta_p95_db", 0.0)),
                    float(_qz_guard_meta.get("max_attenuation_db", 0.0)),
                )

            # Fix 8: Per-Phase max_rms_drop_db_override — dereverb phases have stricter loudness
            # budget than the material default (reverb energy should be small, not 4.5 dB).
            _prof_drop_override = float(_prof.get("max_rms_drop_db_override", 0.0))
            if _prof_drop_override > 0.0:
                _max_rms_drop_db = min(_max_rms_drop_db, _prof_drop_override)

            # 1) Loudness collapse rescue — gated-RMS + envelope-aware gain (§2.45a).
            # Gated-RMS excludes silent passages from the measurement so that noise
            # removal in pauses/fade-outs is not misinterpreted as musical level loss.
            # Envelope-aware gain applies makeup only to musical frames, leaving silence
            # untouched — preventing noise-floor pumping and dynamics compression.
            _rms_ref = _rms_dbfs_gated(_ref_arr)
            _rms_work = _rms_dbfs_gated(_work)
            _drop_db = _rms_ref - _rms_work
            if bool(_prof.get("enable_loudness", True)) and _drop_db > _max_rms_drop_db:
                _target_rms = _rms_ref - _max_rms_drop_db
                _needed_db = max(0.0, _target_rms - _rms_work)
                if _needed_db > 0.01:
                    _g = float(10.0 ** (_needed_db / 20.0))
                    # Safety cap: max +12 dB gain per phase (prevents runaway amplification)
                    _g = min(_g, 4.0)
                    if _g > 1.0005:
                        # Envelope-aware gain: only amplify musical frames, leave silence untouched.
                        # reference_for_gate=_ref_arr: use pre-phase noise-floor for P5 gate (v9.12.1).
                        # After partial denoising, the processed audio's P5 drops (fully-denoised
                        # frames drag it to -55 dBFS) → without reference, gate at -36 includes
                        # residual vinyl noise at -35 dBFS → Pegelexplosion.
                        _work = self._musical_gain_envelope(
                            _work, _g, gate_dbfs=-36.0, sr=sample_rate, reference_for_gate=_ref_arr, material_key=_mat
                        )
                        # Soft-limiter only if actual clipping risk (peak > 0.98),
                        # NOT as routine post-gain step — avoids compressing musical dynamics
                        # §2.45a-III + §v9.10.125: 99.9th-percentile, not np.max — impulse artefacts
                        # (crackle, click) must not block normalisation of music signal
                        _peak_after = float(np.percentile(np.abs(_work), 99.9))
                        if _peak_after > 0.98:
                            _abs_work = np.abs(_work)
                            _over_mask = _abs_work > 0.92
                            if np.any(_over_mask):
                                _sign_work = np.sign(_work)
                                _soft = 0.92 + 0.08 * np.tanh((_abs_work - 0.92) / 0.08)
                                _work = np.where(_over_mask, _sign_work * _soft, _work)
                        _work = np.clip(_work, -1.0, 1.0)
                        _actions.append(
                            {
                                "type": "loudness_makeup",
                                "rms_drop_db_before": round(float(_drop_db), 3),
                                "makeup_db": round(float(20.0 * np.log10(max(_g, 1e-9))), 3),
                                "gated": True,
                            }
                        )

                # If envelope-aware makeup is still not enough,
                # apply a limited dry blend to recover musical body without disabling repair.
                _drop_after_makeup = _rms_ref - _rms_dbfs_gated(_work)
                _residual_drop = _drop_after_makeup - _max_rms_drop_db
                if _residual_drop > 0.02:  # Fix 8B: 0.20 → 0.02 — marginal Überschreitung auslöst Rescue
                    _alpha = float(np.clip(0.06 + (_residual_drop / 6.0), 0.06, 0.45))
                    _rescued = np.clip((1.0 - _alpha) * _work + _alpha * _ref_arr, -1.0, 1.0)
                    _drop_after_rescue = _rms_ref - _rms_dbfs_gated(_rescued)
                    if _drop_after_rescue + 1e-6 < _drop_after_makeup:
                        _work = _rescued
                        _actions.append(
                            {
                                "type": "loudness_dry_rescue",
                                "residual_drop_db_before": round(float(_residual_drop), 3),
                                "dry_blend": round(float(_alpha), 3),
                            }
                        )

            # 2) Stereo collapse rescue (rebalance weaker side only when collapse grew strongly).
            if (
                bool(_prof.get("enable_stereo", True))
                and _work.ndim == 2
                and _work.shape[0] == 2
                and _ref_arr.ndim == 2
                and _ref_arr.shape[0] == 2
            ):
                _imb_ref = _imbalance_db(_ref_arr)
                _imb_work = _imbalance_db(_work)
                _imb_abs = float(_prof.get("stereo_abs_db", 14.0))
                _imb_growth_thr = float(_prof.get("stereo_growth_db", 6.0))
                _imb_target = float(_prof.get("stereo_target_db", 8.0))
                _gain_cap = float(_prof.get("stereo_gain_cap", 2.2))
                if _imb_work > _imb_abs and (_imb_work - _imb_ref) > _imb_growth_thr:
                    _l = float(np.sqrt(np.mean(_work[0] ** 2)) + 1e-12)
                    _r = float(np.sqrt(np.mean(_work[1] ** 2)) + 1e-12)
                    _max_ch = max(_l, _r)
                    _min_ch = min(_l, _r)
                    if _min_ch > 1e-9:
                        _target_min = _max_ch * float(10.0 ** (-_imb_target / 20.0))
                        _weak_gain = float(np.clip(_target_min / _min_ch, 1.0, _gain_cap))
                        if _l < _r:
                            _work[0] = np.clip(_work[0] * _weak_gain, -1.0, 1.0)
                        else:
                            _work[1] = np.clip(_work[1] * _weak_gain, -1.0, 1.0)
                        _actions.append(
                            {
                                "type": "stereo_rebalance",
                                "imbalance_db_before": round(float(_imb_work), 3),
                                "weak_channel_gain_db": round(float(20.0 * np.log10(max(_weak_gain, 1e-9))), 3),
                            }
                        )

            # 3) Transient rescue by limited dry blend (keeps restoration, restores life).
            _tr_ratio = _transient_ratio(_ref_arr, _work)
            _tr_floor = float(_prof.get("transient_floor", 0.60))
            if bool(_prof.get("enable_transient", True)) and _tr_ratio < _tr_floor:
                _a_min = float(_prof.get("dry_blend_min", 0.08))
                _a_max = float(_prof.get("dry_blend_max", 0.24))
                _alpha = float(np.clip(_a_min + (_tr_floor - _tr_ratio) * 0.40, _a_min, _a_max))
                _work = np.clip((1.0 - _alpha) * _work + _alpha * _ref_arr, -1.0, 1.0)
                _actions.append(
                    {
                        "type": "transient_recovery",
                        "transient_ratio_before": round(float(_tr_ratio), 3),
                        "dry_blend": round(float(_alpha), 3),
                    }
                )

            # Prevent cumulative ratcheting: small per-phase edge boosts can add up even if
            # no single phase exceeds the local pre-phase threshold. Clamp against the original
            # song reference after every phase for files with detected quiet intro/outro zones.
            _quiet_edge_profile_local = quiet_edge_profile if isinstance(quiet_edge_profile, dict) else {}
            if bool(_quiet_edge_profile_local.get("has_quiet_edges", False)) and original_reference is not None:
                _pre_cumulative_guard = np.asarray(_work, dtype=np.float32)
                _work = UnifiedRestorerV3._apply_final_quiet_edge_clamp(
                    original_reference,
                    _work,
                    sample_rate,
                    material_key=_mat,
                    max_edge_boost_db=0.5,  # §0h: 0.5 dB tolerance — prevents cumulative ratcheting
                )
                if not np.allclose(_pre_cumulative_guard, _work, atol=1e-6):
                    _actions.append(
                        {
                            "type": "quiet_edge_cumulative_guard",
                            "reference": "original_reference",
                        }
                    )

            if not _actions:
                # §2.45a Telemetriepflicht: per-phase RMS delta — auch im No-Intervention-Pfad
                _rms_ref_ni = _rms_dbfs_gated(_ref_arr)
                _rms_base_ni = _rms_dbfs_gated(_base)
                _rms_drop_ni = _rms_ref_ni - _rms_base_ni
                # Additive-Phase Gain-Guard even without action list (phase may naturally add energy)
                _additive_families_ni: frozenset[str] = frozenset(
                    {
                        "phase55_inpainting",
                        "reconstruction_inpainting",
                        "harmonic_reconstruction",
                    }
                )
                _fam_ni = str(_prof.get("family", "general"))
                _out_ni = _base
                _gain_ni = -_rms_drop_ni  # positive = louder than pre-phase
                if _fam_ni in _additive_families_ni and _gain_ni > 3.0:
                    _excess_db_ni = _gain_ni - 3.0
                    _atten_ni = float(10.0 ** (-_excess_db_ni / 20.0))
                    _out_ni = np.clip(_base * _atten_ni, -1.0, 1.0)
                    _rms_base_ni = _rms_dbfs_gated(_out_ni)
                    _rms_drop_ni = _rms_ref_ni - _rms_base_ni
                    logger.warning(
                        "§2.45a ADDITIVE-Gain-Guard %s (no-action): +%.2f dB → gedämpft um %.2f dB",
                        phase_id,
                        (-_rms_ref_ni + _rms_dbfs_gated(_base)),
                        _excess_db_ni,
                    )
                elif _gain_ni > 6.0:
                    # §0h Universal-Gain-Cap (no-action path): backstop for all families
                    _excess_db_ni = _gain_ni - 6.0
                    _atten_ni = float(10.0 ** (-_excess_db_ni / 20.0))
                    _out_ni = np.clip(_base * _atten_ni, -1.0, 1.0)
                    _rms_base_ni = _rms_dbfs_gated(_out_ni)
                    _rms_drop_ni = _rms_ref_ni - _rms_base_ni
                    logger.warning(
                        "§0h Universal-Gain-Cap %s no-action (family=%s): +%.2f dB → capped to +6.0 dB",
                        phase_id,
                        _fam_ni,
                        _gain_ni,
                    )
                logger.info(
                    "§2.45a Pegel %s: pre=%.1f dBFS post=%.1f dBFS drop=%+.2f dB mode=base",
                    phase_id,
                    _rms_ref_ni,
                    _rms_base_ni,
                    _rms_drop_ni,
                )
                return _out_ni

            _action_types = {str(a.get("type", "")) for a in _actions}

            def _evaluate_targets(_sig: np.ndarray) -> tuple[dict[str, Any], bool, float]:
                _targets_local: dict[str, Any] = {}
                _penalty = 0.0
                _rms_drop_sig = _rms_dbfs(_ref_arr) - _rms_dbfs(_sig)
                _imb_ref_sig = _imbalance_db(_ref_arr)
                _imb_sig = _imbalance_db(_sig)
                _tr_sig = _transient_ratio(_ref_arr, _sig)
                _mono_ref_sig = _mono_compatibility(_ref_arr)
                _mono_sig = _mono_compatibility(_sig)
                _hf_sig = _hf_energy_ratio(_ref_arr, _sig)

                if ("loudness_makeup" in _action_types) or ("loudness_dry_rescue" in _action_types):
                    _ok = bool(_rms_drop_sig <= (_max_rms_drop_db + 0.15))
                    _targets_local["loudness"] = {
                        "target_max_rms_drop_db": round(float(_max_rms_drop_db), 3),
                        "measured_rms_drop_db": round(float(_rms_drop_sig), 3),
                        "met": _ok,
                    }
                    if not _ok:
                        _penalty += max(0.0, _rms_drop_sig - (_max_rms_drop_db + 0.15)) * 4.0

                if "stereo_rebalance" in _action_types:
                    _stereo_target = max(_imb_ref_sig, float(_prof.get("stereo_target_db", 8.0)))
                    _ok = bool(_imb_sig <= (_stereo_target + 0.75))
                    _targets_local["stereo"] = {
                        "target_max_imbalance_db": round(float(_stereo_target), 3),
                        "measured_imbalance_db": round(float(_imb_sig), 3),
                        "met": _ok,
                    }
                    if not _ok:
                        _penalty += max(0.0, _imb_sig - (_stereo_target + 0.75)) * 1.5

                if "transient_recovery" in _action_types:
                    _tr_floor_eval = float(_prof.get("transient_floor", 0.60))
                    _ok = bool(_tr_sig >= (_tr_floor_eval - 0.02))
                    _targets_local["transient"] = {
                        "target_min_ratio": round(float(_tr_floor_eval), 3),
                        "measured_ratio": round(float(_tr_sig), 3),
                        "met": _ok,
                    }
                    if not _ok:
                        _penalty += max(0.0, (_tr_floor_eval - 0.02) - _tr_sig) * 6.0

                if bool(_prof.get("enable_mono_compat", False)):
                    _mono_floor_eval = max(float(_prof.get("mono_compat_floor", 0.50)), _mono_ref_sig - 0.05)
                    _ok = bool(_mono_sig >= (_mono_floor_eval - 0.02))
                    _targets_local["mono_compat"] = {
                        "target_min_ratio": round(float(_mono_floor_eval), 3),
                        "measured_ratio": round(float(_mono_sig), 3),
                        "met": _ok,
                    }
                    if not _ok:
                        _penalty += max(0.0, (_mono_floor_eval - 0.02) - _mono_sig) * 5.0

                if bool(_prof.get("enable_hf_preservation", False)):
                    _hf_floor_eval = float(_prof.get("hf_floor", 0.75))
                    _ok = bool(_hf_sig >= (_hf_floor_eval - 0.03))
                    _targets_local["hf_preservation"] = {
                        "target_min_ratio": round(float(_hf_floor_eval), 3),
                        "measured_ratio": round(float(_hf_sig), 3),
                        "met": _ok,
                    }
                    if not _ok:
                        _penalty += max(0.0, (_hf_floor_eval - 0.03) - _hf_sig) * 4.0

                if bool(_prof.get("enable_hf_excess_guard", False)):
                    _hf_cap_eval = float(_prof.get("hf_cap", 4.0))
                    _ok = bool(_hf_sig <= (_hf_cap_eval + 0.03))
                    _targets_local["hf_excess"] = {
                        "target_max_ratio": round(float(_hf_cap_eval), 3),
                        "measured_ratio": round(float(_hf_sig), 3),
                        "met": _ok,
                    }
                    if not _ok:
                        _penalty += max(0.0, _hf_sig - (_hf_cap_eval + 0.03)) * 4.0

                if "quiet_zone_local_guard" in _action_types:
                    _qz_stats = _quiet_zone_explosion_stats(
                        _ref_arr,
                        _sig,
                        _quiet_dbfs=float(_guard_contract.get("quiet_dbfs", -34.0)),
                        _thr_db=float(_guard_contract.get("threshold_db", 2.0)),
                    )
                    _qz_count = int(_qz_stats.get("count", 0.0))
                    _qz_ok = bool(_qz_count == 0)
                    _targets_local["quiet_zone"] = {
                        "target_explosions": 0,
                        "measured_explosions": _qz_count,
                        "quiet_dbfs": round(float(_guard_contract.get("quiet_dbfs", -34.0)), 3),
                        "threshold_db": round(float(_guard_contract.get("threshold_db", 2.0)), 3),
                        "max_delta_db": round(float(_qz_stats.get("max_delta_db", 0.0)), 3),
                        "delta_p95_db": round(float(_qz_stats.get("delta_p95_db", 0.0)), 3),
                        "met": _qz_ok,
                    }
                    if not _qz_ok:
                        # Strong penalty: local pegel spikes are RELEASE_MUST critical.
                        _penalty += 8.0 + (2.0 * float(_qz_count))

                _targets_met_local = bool(_targets_local) and all(
                    bool(v.get("met", False)) for v in _targets_local.values()
                )
                return _targets_local, _targets_met_local, float(_penalty)

            _cost_base = _intervention_cost(_ref_arr, _base, _prof)

            # Intelligent forwarding: choose best candidate (work or blend), not binary reject.
            _candidates: list[tuple[str, np.ndarray, float]] = [("base", _base, 0.0), ("work", _work, 1.0)]
            for _alpha in (0.15, 0.30, 0.45, 0.60, 0.75, 0.85):
                _blend = np.clip((1.0 - _alpha) * _base + _alpha * _work, -1.0, 1.0)
                _candidates.append(("blend", _blend, float(_alpha)))

            _best_sig = _base
            _best_mode = "base"
            _best_alpha = 0.0
            _best_targets: dict[str, Any] = {}
            _best_targets_met = False
            _best_score = float("inf")
            _best_cost = _cost_base

            for _mode, _sig, _alpha in _candidates:
                _targets, _targets_met, _target_penalty = _evaluate_targets(_sig)
                _cost_sig = _intervention_cost(_ref_arr, _sig, _prof)
                # Keep intervention close to phase output unless needed for target recovery.
                _fidelity_drift = float(np.sqrt(np.mean((_sig - _base) ** 2) + 1e-12))
                _score = _cost_sig + _target_penalty + (0.06 * _fidelity_drift)
                if _score < _best_score:
                    _best_score = _score
                    _best_sig = _sig
                    _best_mode = _mode
                    _best_alpha = _alpha
                    _best_targets = _targets
                    _best_targets_met = _targets_met
                    _best_cost = _cost_sig

            _accepted = bool(_best_mode != "base" and (_best_score + 1e-6 < _cost_base))

            self._active_intervention_log.append(
                {
                    "phase_id": phase_id,
                    "family": str(_prof.get("family", "general")),
                    "material": _mat,
                    "accepted": _accepted,
                    "selection_mode": _best_mode,
                    "selection_alpha": round(float(_best_alpha), 3),
                    "cost_before": round(float(_cost_base), 4),
                    "cost_after": round(float(_best_cost), 4),
                    "targets": _best_targets,
                    "targets_met": bool(_best_targets_met),
                    "actions": _actions,
                }
            )

            logger.warning(
                "ActiveIntervention %s SELECTED mode=%s alpha=%.2f cost %.4f -> %.4f (targets_met=%s)",
                phase_id,
                _best_mode,
                _best_alpha,
                _cost_base,
                _best_cost,
                _best_targets_met,
            )

            # If intervention does not improve composite score or leaves hard targets unmet,
            # do not apply it. This avoids shipping known-bad best-effort outputs.
            if not _accepted:
                logger.warning(
                    "ActiveIntervention %s REJECTED: no beneficial score delta (mode=%s, alpha=%.2f)",
                    phase_id,
                    _best_mode,
                    _best_alpha,
                )
                _best_sig = _base
            elif "quiet_zone" in _best_targets and not bool(_best_targets.get("quiet_zone", {}).get("met", False)):
                logger.warning(
                    "ActiveIntervention %s REJECTED: quiet-zone target unmet (explosions=%s)",
                    phase_id,
                    _best_targets.get("quiet_zone", {}).get("measured_explosions", "?"),
                )
                _best_sig = _base

            # §2.45a Additive-Phase Gain-Guard: ML-inpainting / harmonic reconstruction
            # must not push level above pre-phase by more than +3 dB.  Overamplified
            # hallucinated content would compress musical dynamics and mask vocals.
            _additive_families: frozenset[str] = frozenset(
                {
                    "phase55_inpainting",
                    "reconstruction_inpainting",
                    "harmonic_reconstruction",
                }
            )
            _fam_check = str(_prof.get("family", "general"))
            _rms_ref_final = _rms_dbfs_gated(_ref_arr)
            _rms_out_final = _rms_dbfs_gated(_best_sig)
            _rms_gain_db = _rms_out_final - _rms_ref_final  # positive means louder than pre-phase
            if _fam_check in _additive_families and _rms_gain_db > 3.0:
                _excess_db = _rms_gain_db - 3.0
                _atten = float(10.0 ** (-_excess_db / 20.0))
                _best_sig = np.clip(_best_sig * _atten, -1.0, 1.0)
                _rms_out_final = _rms_dbfs_gated(_best_sig)
                logger.warning(
                    "§2.45a ADDITIVE-Gain-Guard %s: +%.2f dB Gain → gedämpft um %.2f dB",
                    phase_id,
                    _rms_gain_db,
                    _excess_db,
                )
            # §0h Music-Death-Shield Universal-Gain-Cap (v9.12.1 fix): no phase — regardless of
            # family — may boost the signal by more than +6 dB relative to the pre-phase level.
            # +3 dB already enforced above for additive families; +6 dB is the universal backstop.
            # BUG-FIX: Re-compute _rms_gain_db from current _rms_out_final (which may have been
            # updated by the additive-family cap above) to avoid stale comparison.
            # Use independent 'if' (not 'elif') so this always runs; re-compute prevents double-
            # capping on additive families that were already handled by the +3 dB guard.
            _rms_gain_db = _rms_out_final - _rms_ref_final  # re-compute after potential additive cap
            if _rms_gain_db > 6.0:
                _excess_db = _rms_gain_db - 6.0
                _atten = float(10.0 ** (-_excess_db / 20.0))
                _best_sig = np.clip(_best_sig * _atten, -1.0, 1.0)
                _rms_out_final = _rms_dbfs_gated(_best_sig)
                logger.warning(
                    "§0h Universal-Gain-Cap %s (family=%s): +%.2f dB → capped to +6.0 dB (att=%.2f dB)",
                    phase_id,
                    _fam_check,
                    _rms_gain_db,
                    _excess_db,
                )

            # §2.45a Telemetriepflicht: per-phase RMS delta — immer geloggt (auch ohne Intervention)
            _rms_drop_logged = _rms_ref_final - _rms_out_final  # positive = level dropped
            logger.info(
                "§2.45a Pegel %s: pre=%.1f dBFS post=%.1f dBFS drop=%+.2f dB mode=%s",
                phase_id,
                _rms_ref_final,
                _rms_out_final,
                _rms_drop_logged,
                _best_mode,
            )

            return _best_sig

        # §Punkt3 Phasen-Regressionsprotokoll: RMS-Delta je Phase (sequentielle Ausführung)
        # Einheit: dBFS-Differenz nach - vor Phase. Positiv = Energie gestiegen, negativ = gesunken.
        self._phase_regression_log = {}
        self._active_intervention_log = []
        # §2.29 PerPhaseMusicalGoalsGate — vor Pipeline-Loop initialisieren (sequentielle Ausführung)
        # Deaktiviert AUSSCHLIESSLICH über enable_phase_gate=False (z. B. --no-phase-gate).
        # enable_performance_guard steuert das CPU-Budget-Throttling, NICHT die musikalische
        # Qualitätskontrolle — beide Flags sind bewusst entkoppelt (§2.29 Fix v9.10.46).
        _pmgg_gate = None
        _pmgg_restorability_score: float = (
            restorability_score  # §2.29 normativ: aus RestorabilityEstimator (kein Hard-Code)
        )
        _pmgg_scores_curr: dict[str, float] | None = None
        _pmgg_log_entries: list = []
        _pmgg_enabled = getattr(self.config, "enable_phase_gate", True)
        if _pmgg_enabled:
            try:
                from backend.core.per_phase_musical_goals_gate import get_phase_gate as _get_pmgg_gate

                _pmgg_gate = _get_pmgg_gate()
                _pmgg_gate.reset()
                logger.debug("§2.29 PMGG: Initialisiert für %d Phasen", len(selected_phases))
            except Exception as _pmgg_init_exc:
                logger.debug("PerPhaseMusicalGoalsGate nicht verfügbar: %s", _pmgg_init_exc)
        else:
            logger.debug("§2.29 PMGG: Deaktiviert (enable_phase_gate=False via --no-phase-gate)")
        self._pmgg_log_entries = []
        # §2.48 [RELEASE_MUST] Kumulative-Phasen-Interaktions-Guard
        _interaction_guard = None
        _interaction_guard_state = None
        _is_bronze_cig = os.environ.get("AURIK_BRONZE_RESTORATION_PROFILE", "0").strip().lower() in {
            "1",
            "true",
            "yes",
            "on",
        }
        if _is_bronze_cig:
            # Bronze-Modus: CIG deaktivieren — die 3 Safe-Phasen (DC/TruePeak/OutputFormat)
            # können keine -0.479 Natuerlichkeit-Drift verursachen. CIG-Rollback auf
            # __pre_pipeline__ würde das rohe Input mit 70ms Interchannel-Lag exportieren
            # und verursacht genau die Pegelexplosion die es verhindern soll (False-Positive).
            logger.info("[Bronze] CIG deaktiviert — kein Rollback auf degradiertes Input")
        else:
            try:
                from backend.core.cumulative_interaction_guard import get_interaction_guard as _get_ig

                _interaction_guard = _get_ig()
                _interaction_guard_state = _interaction_guard.reset()
                logger.debug("§2.48 InteractionGuard: Initialisiert für %d Phasen", len(selected_phases))
            except Exception as _ig_init_exc:
                logger.debug("§2.48 InteractionGuard nicht verfügbar: %s", _ig_init_exc)

        # §2.49 [RELEASE_MUST] Artefakt-Freiheits-Gate
        _artifact_gate = None
        try:
            _artifact_gate = get_artifact_freedom_gate()
            logger.debug("§2.49 ArtifactFreedomGate: Initialisiert")
        except Exception as _afg_init_exc:
            # §0 Primum non nocere: AFG unavailable → artifact_freedom_score defaults to 1.0
            # → artefacts can pass HPI undetected. Escalate to WARNING for operator visibility.
            logger.warning(
                "§2.49 ArtifactFreedomGate NICHT VERFÜGBAR — Artefakt-Prüfung deaktiviert (§0-Risiko): %s",
                _afg_init_exc,
            )

        # §2.48/§2.49: Material type string for gates
        _mat_str = str(getattr(material_type, "value", material_type)).lower()

        # M-1 §2.2.1 Parallelisierungs-Invariante: TIER 0 und TIER 1 IMMER sequenziell
        # Kausale Abhängigkeiten: Defektkorrektur muss kausal verkettet sein (Output → nächster Input).
        # np.mean-Merge über Tier-0/1-Phasen würde Defektkorrekturen gegenseitig aufheben.
        # Nur TIER 2–4 dürfen parallelisieren (§2.2.1: "Merge via np.mean NUR wenn gleiche Frequenzzone").
        _SEQUENTIAL_TIER_PHASES = frozenset(
            {
                # TIER 0 — Basiskorrekturen (immer aktiv)
                "phase_30_dc_offset_removal",
                "phase_05_rumble_filter",
                # TIER 1 — Kritische Defektkorrektur (kausale Abhängigkeiten)
                "phase_01_click_removal",
                "phase_02_hum_removal",
                "phase_03_denoise",
                "phase_09_crackle_removal",
                "phase_12_wow_flutter_fix",
                "phase_14_phase_correction",
                "phase_18_noise_gate",
                "phase_20_reverb_reduction",
                "phase_23_spectral_repair",
                "phase_24_dropout_repair",
                "phase_25_azimuth_correction",
                "phase_27_click_pop_removal",
                "phase_28_surface_noise_profiling",
                "phase_29_tape_hiss_reduction",
                "phase_31_speed_pitch_correction",
                "phase_49_advanced_dereverb",
                "phase_55_diffusion_inpainting",
            }
        )
        _has_tier01 = any(p in _SEQUENTIAL_TIER_PHASES for p in selected_phases)
        # Prüfe auf Abhängigkeiten (vereinfachte Annahme: keine Abhängigkeiten → parallel, sonst sequentiell)
        has_dependencies = any(
            self.phase_metadata[pid]["dependencies"] for pid in selected_phases if pid in self.phase_metadata
        )

        # §Psychoacoustic: Pre-compute masking threshold once for all phases.
        # Computed on the FULL mono signal (left channel for stereo) — pure DSP (no ML),
        # cost < 0.5 s even for 3-minute audio (<<DefectScanner budget of 4 s).
        # A 5 s centre-sample would misrepresent the time-varying masking curve used by
        # phase_03 and phase_29 for sections outside that window (constant extrapolation).
        # masking_scalar ∈ [0.4, 1.0]: MEDIAN gain_modifier across Bark bands and frames
        # (median is more robust to loud transients than mean).
        # 0.4 = fully masked content, 1.0 = no masking headroom consumed.
        _masking_result = None
        _masking_result_r = None  # right channel (stereo only)
        _masking_scalar: float = 1.0
        try:
            from backend.core.psychoacoustic_masking_model import compute_masking_threshold as _cmt

            # Internal format is channel-first (2, N) — use audio[0] for left channel.
            # ascontiguousarray: ensures owned, aligned buffer for BLAS ops.
            _ma = np.ascontiguousarray(audio if audio.ndim == 1 else audio[0], dtype=np.float32)
            _masking_result = _cmt(_ma, sample_rate)
            # Right channel: only for stereo, computed independently — avoids cross-channel
            # masking error for asymmetric recordings (e.g. violin hard-left, cello hard-right).
            if audio.ndim == 2 and audio.shape[0] >= 2:
                _masking_result_r = _cmt(np.ascontiguousarray(audio[1], dtype=np.float32), sample_rate)
            _gm_median = float(np.median(_masking_result.gain_modifier))
            _masking_scalar = float(np.clip(0.4 + _gm_median * 0.6, 0.4, 1.0))
            logger.debug(
                "§Psychoacoustic: masking_scalar=%.3f (gain_modifier_median=%.3f, silence=%.1f%%, stereo=%s)",
                _masking_scalar,
                _gm_median,
                100.0 * float(np.mean(_masking_result.silence_frames)),
                _masking_result_r is not None,
            )
        except Exception as _pmm_pre_exc:
            logger.debug("§Psychoacoustic: Masking-Pre-Compute fehlgeschlagen: %s", _pmm_pre_exc)

        # §7.6 / §9.1: Defect-Locations für gezielte Phasenverarbeitung extrahieren
        # + maximale Severity für adaptive Chunk-Größe
        _defect_locations: dict[str, list[tuple[float, float]]] = {}
        _defect_severity_map: dict[str, float] = {}
        _defect_saliency_map: dict[str, float] = {}
        _defect_location_coverage_map: dict[str, float] = {}
        _max_defect_severity: float = 0.0
        if defect_result is not None and hasattr(defect_result, "scores"):
            for _dt, _ds in defect_result.scores.items():
                _dt_key = _dt.value if hasattr(_dt, "value") else str(_dt)
                if hasattr(_ds, "locations") and _ds.locations:
                    _defect_locations[_dt_key] = list(_ds.locations)
                if hasattr(_ds, "severity"):
                    _sev_val = float(_ds.severity)
                    # §9.1c v9.10.79 Psychoakustik: Perceptual-Salience-Gewichtung
                    # severity_perceptual = severity_raw * (0.3 + 0.7 * mean_salience)
                    # Maskierte Defekte erhalten reduzierte Effective-Severity
                    _sal_weight = 1.0  # Fallback: keine Salienz-Info
                    if hasattr(_ds, "perceptual_salience") and _ds.perceptual_salience is not None:
                        _sal_val = float(_ds.perceptual_salience)
                        _sal_weight = 0.3 + 0.7 * min(1.0, max(0.0, _sal_val))  # ∈ [0.3, 1.0]
                        _defect_saliency_map[_dt_key] = min(1.0, max(0.0, _sal_val))
                    _sev_val = _sev_val * _sal_weight  # Reduziere Severity maskierter Defekte
                    _defect_severity_map[_dt_key] = _sev_val
                    _max_defect_severity = max(_max_defect_severity, _sev_val)

        # Locality map: per-defect temporal coverage in [0, 1].
        # Used to reduce global wet/dry for sparse, event-like defects
        # (clicks, crackle, clipping, sibilance), preserving timbre elsewhere.
        _audio_duration_s = max(1e-6, float(audio.shape[-1]) / float(sample_rate))
        for _dkey, _locs in _defect_locations.items():
            _acc = 0.0
            for _t0, _t1 in _locs:
                try:
                    _s = max(0.0, min(float(_t0), _audio_duration_s))
                    _e = max(0.0, min(float(_t1), _audio_duration_s))
                    if _e > _s:
                        _acc += _e - _s
                except Exception:
                    continue
            _defect_location_coverage_map[_dkey] = float(np.clip(_acc / _audio_duration_s, 0.0, 1.0))

        # §11.7a: Bereits reparierte Gap-Locations aus RekonstruktionsDenker extrahieren.
        # Phase 24 (dropout_repair) und Phase 55 (diffusion_inpainting) können damit
        # bereits reparierte Regionen überspringen und vermeiden Triple-Inpainting.
        _repaired_gap_samples: list[tuple[int, int]] = []
        if reconstruction_context is not None:
            _gap_details = getattr(reconstruction_context, "gap_details", [])
            for _gi in _gap_details:
                if getattr(_gi, "repaired", False):
                    _s = getattr(_gi, "start_sample", None)
                    _e = getattr(_gi, "end_sample", None)
                    if _s is not None and _e is not None:
                        _repaired_gap_samples.append((int(_s), int(_e)))
            if _repaired_gap_samples:
                logger.info(
                    "UV3: %d bereits reparierte Gaps aus RekonstruktionsDenker übernommen",
                    len(_repaired_gap_samples),
                )

        # §7.6 AdaptiveChunkProcessor: Phasen die von chunk-basierter Verarbeitung
        # profitieren, wenn Defekt-Severity hoch ist (surgical repair bei schweren Defekten).
        _ACP_ELIGIBLE_PHASES = frozenset(
            {
                "phase_03_denoise",
                "phase_23_spectral_repair",
                "phase_24_dropout_repair",
                "phase_28_surface_noise_profiling",
                "phase_29_tape_hiss_reduction",
            }
        )
        _acp_available = False
        _acp_process_fn = None
        if _max_defect_severity >= 0.3:  # nur bei mittlerer/hoher Severity lohnend
            try:
                from backend.core.adaptive_chunk_processor import process_in_adaptive_chunks as _acp_process

                _acp_available = True
                _acp_process_fn = _acp_process
                logger.debug(
                    "§7.6 AdaptiveChunkProcessor: verfügbar für %d eligible Phasen (severity=%.2f)",
                    len(_ACP_ELIGIBLE_PHASES & set(selected_phases)),
                    _max_defect_severity,
                )
            except Exception as _acp_exc:
                logger.debug("AdaptiveChunkProcessor nicht verfügbar: %s", _acp_exc)

        if not has_dependencies and not _has_tier01 and len(selected_phases) > 1:
            # Parallele Ausführung mit Profiling
            results = {}
            with ThreadPoolExecutor(max_workers=self.config.num_cores) as executor:
                future_map = {}
                for phase_id in selected_phases:
                    phase = self._get_phase(phase_id)
                    if not phase:
                        logger.warning("Phase %s konnte nicht lazy-geladen werden, skipping", phase_id)
                        skipped.append(phase_id)
                        _record_oom_probe("phase_skip_not_loaded", phase_id)
                        continue
                    metadata = phase.get_metadata()
                    estimated_time = metadata.estimated_time_factor * (audio.shape[-1] / sample_rate)
                    if (
                        (not no_rt_limit)
                        and self.performance_guard
                        and self.performance_guard.should_skip_phase(phase_id, estimated_time, len(selected_phases) - 1)
                    ):
                        skipped.append(phase_id)
                        deferred.append(phase_id)  # §2.38 KMV: RT-skipped → Stage 2
                        _record_oom_probe(
                            "phase_deferred_rt", phase_id, estimated_time_s=round(float(estimated_time), 3)
                        )
                        continue
                    _record_oom_probe(
                        "phase_start_parallel", phase_id, estimated_time_s=round(float(estimated_time), 3)
                    )
                    phase_start = (
                        self.performance_guard.start_phase(phase_id) if self.performance_guard else time.time()
                    )
                    # §PROGRESS: Set heartbeat scope for parallel phases so sub-bar fills
                    # proportionally during long ML phases (same as sequential phases).
                    _hb_n_sel_p = max(len(selected_phases), 1)
                    _hb_idx_p = len(future_map)  # index at submission time
                    _hb_pct_start_p = _phase_progress_start + int(
                        (_phase_progress_end - _phase_progress_start) * _hb_idx_p / _hb_n_sel_p
                    )
                    _hb_pct_end_p = _phase_progress_start + int(
                        (_phase_progress_end - _phase_progress_start) * (_hb_idx_p + 1) / _hb_n_sel_p
                    )
                    self._active_pipeline_cb_for_sub = progress_callback
                    self._active_phase_pct_for_sub = (_hb_pct_start_p, _hb_pct_end_p)
                    # §PROGRESS: Emit on phase activation (parallel submission) — real-time ML plugin detection
                    if progress_callback is not None:
                        try:
                            _n_sub_p = len(future_map)
                            _n_sel_p = max(len(selected_phases), 1)
                            _pct_p = _phase_progress_start + int(
                                (_phase_progress_end - _phase_progress_start) * _n_sub_p / _n_sel_p
                            )
                            _lbl_p = (self.phase_metadata.get(phase_id) or {}).get("name") or phase_id.replace(
                                "phase_", ""
                            ).replace("_", " ").title().lstrip("0123456789 ")
                            progress_callback(
                                _pct_p,
                                f"{_lbl_p} [{phase_id}]",
                                0.0,
                            )
                        except Exception as _exc:
                            logger.debug("Progress callback (parallel pre) failed: %s", _exc)
                    future = executor.submit(
                        self._profiled_phase_call,
                        phase,
                        current_audio,  # audio parameter
                        sample_rate=sample_rate,
                        material_type=material_type,
                        material=material_type,
                        defect_scores=defect_result.scores,
                        defect_locations=_defect_locations,
                        defect_severity_map=_defect_severity_map,
                        defect_saliency_map=_defect_saliency_map,
                        defect_location_coverage_map=_defect_location_coverage_map,
                        max_defect_severity=_max_defect_severity,
                        quality_mode=_quality_mode_value,  # Pass quality mode for ML routing
                        repaired_gap_samples=_repaired_gap_samples,  # §11.7a: RekonstruktionsDenker gaps
                        masking_result=_masking_result,  # §Psychoacoustic: MaskingResult L/mono
                        masking_result_r=_masking_result_r,  # §Psychoacoustic: MaskingResult R channel
                        masking_scalar=_masking_scalar,  # §Psychoacoustic: audibility scalar ∈ [0.4, 1.0]
                        phoneme_timeline=phoneme_timeline,  # §2.36a: PhonemeTimeline for targeted processing
                    )
                    future_map[future] = (phase_id, phase_start, phase)
                for future in as_completed(future_map):
                    phase_id, phase_start, phase_obj = future_map[future]
                    try:
                        result = future.result()
                        _collect_guard_payload(phase_obj, phase_id, result)
                        if result.success:
                            results[phase_id] = result.audio
                            _record_oom_probe(
                                "phase_ok_parallel",
                                phase_id,
                                execution_time_s=round(float(getattr(result, "execution_time_seconds", 0.0) or 0.0), 3),
                            )
                            # §PROGRESS: Per-Phase Fortschritt (parallel)
                            _n_sel = max(len(selected_phases), 1)
                            _idx_ex = len(executed)
                            _phase_pct = _phase_progress_start + int(
                                (_phase_progress_end - _phase_progress_start) * _idx_ex / _n_sel
                            )
                            if progress_callback is not None:
                                try:
                                    _phase_label = (self.phase_metadata.get(phase_id) or {}).get(
                                        "name"
                                    ) or phase_id.replace("phase_", "").replace("_", " ").title().lstrip("0123456789 ")
                                    progress_callback(
                                        _phase_pct,
                                        f"{_phase_label} [{phase_id}]",
                                        0.0,
                                    )
                                except Exception as _cb_exc:
                                    logger.debug(
                                        "Progress-Update übersprungen in %s (Ursache: %s). "
                                        "Lösung: Callback-Signatur prüfen.",
                                        phase_id,
                                        _cb_exc,
                                    )
                            executed.append(phase_id)
                            logger.info("✅ %s: %.2fs (parallel)", phase_id, result.execution_time_seconds)
                        else:
                            _record_oom_probe("phase_failed_parallel", phase_id)
                            logger.error(
                                "Phase %s fehlgeschlagen (Ursache: %s). "
                                "Lösung: Phase prüfen oder DSP-Fallback aktivieren.",
                                phase_id,
                                result.warnings,
                            )
                            skipped.append(phase_id)
                    except Exception as e:
                        _record_oom_probe("phase_exception_parallel", phase_id, error=f"{type(e).__name__}:{e}")
                        logger.error(
                            "Phase %s mit Ausnahme abgebrochen (Ursache: %s). "
                            "Lösung: Plugin-/Modellverfügbarkeit und Eingabedaten prüfen.",
                            phase_id,
                            e,
                        )
                        skipped.append(phase_id)
                    if self.performance_guard:
                        self.performance_guard.end_phase(phase_id, phase_start)
            if results:
                audios = [results[pid] for pid in executed if pid in results]
                if audios:
                    _merged = np.mean(audios, axis=0)
                    # §3.1 NaN-Guard: revert to pre-merge audio if NaN produced
                    if np.any(np.isnan(_merged)):
                        logger.warning(
                            "NaN detected in parallel merge of %d phases (%s) — "
                            "reverting to pre-merge audio. Solution: check individual phase outputs.",
                            len(audios),
                            [pid for pid in executed if pid in results],
                        )
                    else:
                        current_audio = np.clip(_merged, -1.0, 1.0)
                        # §Live-Waveform: Emit audio after parallel merge
                        if audio_update_callback is not None:
                            try:
                                audio_update_callback(current_audio, sample_rate, "parallel_merge")
                            except Exception as _exc:
                                logger.debug("audio_update_callback (parallel_merge) failed: %s", _exc)
        else:
            # Sequentielle Ausführung (Abhängigkeiten vorhanden oder nur eine Phase)
            # §2.16 TQC: Zeitmodifizierende Phasen können Kohärenz brechen — Rollback bei Versagen
            _TQC_CRITICAL_PHASES_SEQ = frozenset(
                {
                    "phase_12_wow_flutter_fix",
                    "phase_31_speed_pitch_correction",
                }
            )
            # §2.31a Mid-pipeline calibration: checkpoint flags for ~33 % and ~66 % progress
            _mid_cal_33pct_done: bool = False
            _mid_cal_66pct_done: bool = False

            # §2.48 InteractionGuard: Set pre-pipeline P1/P2 baseline
            if _interaction_guard is not None and _interaction_guard_state is not None:
                try:
                    from backend.core.musical_goals.musical_goals_metrics import get_checker as _get_mg_checker_248

                    _mg_checker_248 = _get_mg_checker_248()
                    # §2.54: Compute material-adaptive context for drift tolerance
                    _mat_str_248 = "unknown"
                    try:
                        _mat_str_248 = str(getattr(material_type, "value", material_type)).lower()
                    except Exception:
                        pass
                    _baseline_goals_248 = _mg_checker_248.measure_all(
                        current_audio, sample_rate, material_type=_mat_str_248
                    )
                    _defect_sev_mean_248 = 0.0
                    try:
                        if defect_result is not None and hasattr(defect_result, "scores"):
                            _sev_vals = [
                                s.severity
                                for s in defect_result.scores.values()
                                if hasattr(s, "severity") and s.severity > 0
                            ]
                            if _sev_vals:
                                _defect_sev_mean_248 = float(np.mean(_sev_vals))
                    except Exception:
                        pass
                    # §2.54: Count carrier-repair phases in the selected plan
                    _carrier_prefixes_248 = (
                        "phase_01",
                        "phase_03",
                        "phase_09",
                        "phase_12",
                        "phase_24",
                        "phase_27",
                        "phase_28",
                        "phase_29",
                        "phase_55",
                    )
                    _n_carrier_248 = sum(
                        1 for p in selected_phases if any(p.startswith(cp) for cp in _carrier_prefixes_248)
                    )

                    _interaction_guard.set_pre_pipeline_baseline(
                        _interaction_guard_state,
                        current_audio,
                        _baseline_goals_248,
                        material_type=_mat_str_248,
                        restorability_score=float(_pmgg_restorability_score),
                        defect_severity_mean=_defect_sev_mean_248,
                        n_active_phases=len(selected_phases),
                        n_carrier_phases=_n_carrier_248,
                        goal_weights=getattr(self, "_song_goal_weights", None),  # §2.56
                    )
                except Exception as _ig_baseline_exc:
                    logger.debug("§2.48 InteractionGuard baseline failed: %s", _ig_baseline_exc)
                    _interaction_guard = None
                    _interaction_guard_state = None

            # §2.49 ArtifactFreedomGate: store pre-pipeline audio snapshot for per-phase checks
            _afg_pre_pipeline_audio = current_audio.copy() if _artifact_gate is not None else None
            _afg_best_clean_checkpoint = current_audio.copy() if _artifact_gate is not None else None

            # §2.45a-VI Mid-Pipeline-Cumulative-Guard reference audio.
            # HPF/Notch phases (phase_02, phase_05) remove energy INTENTIONALLY (Carrier-Inversion).
            # After such phases the cumulative reference is reset to current_audio so the guard
            # does not count their intentional sub-bass / hum energy removal as "loudness loss"
            # and does NOT apply makeup gain → prevents Pegelexplosion after Rumpel/Hum-Filter.
            # §2.45a-VI: Cumulative-Guard is ALWAYS active — decoupled from AFG availability.
            # Previously conditioned on _afg_pre_pipeline_audio is not None, which silently
            # disabled the entire Mid-Pipeline-Cumulative-Guard whenever artifact_gate failed
            # to load (import error, OOM, etc.) — leaving Pegelexplosion-protection blind.
            _cum_rms_reference_audio = current_audio.copy()
            # Phases whose energy removal is intentional (HPF, Notch) — cumulative reference
            # is reset to current_audio AFTER the phase, before the guard runs.
            _HPF_NOTCH_CUM_RESET_PHASES: frozenset[str] = frozenset(
                {
                    "phase_02_hum_removal",
                    "phase_05_rumble_filter",
                }
            )
            # First-stage Single-Gain-Authority (§2.45a): cumulative guards may
            # apply positive makeup only while authority is enabled.
            _allow_positive_makeup_gain: bool = True
            _makeup_authority_reason: str = "initial"
            _afg_best_clean_phase: str = "__pre_pipeline__"
            # §2.49 Track minimum per-phase artifact_freedom (replaces final full-pipeline comparison)
            _min_per_phase_afg_score: float = 1.0

            # §0d [RELEASE_MUST] Carrier-Recovery-Tracking: pre-carrier snapshot + checkpoint
            _pre_carrier_audio: np.ndarray = current_audio.copy()
            _best_carrier_checkpoint: np.ndarray | None = None
            _last_carrier_phase_id: str | None = None
            _CARRIER_PHASE_PREFIXES_0d: tuple[str, ...] = (
                "phase_01",
                "phase_02",
                "phase_03",
                "phase_05",
                "phase_06",  # §2.46 Step 5: BW-Extension (additiv) — Checkpoint NACH HF-Recovery
                "phase_07",  # §2.46 Step 5: Harmonic Restoration (additiv)
                "phase_09",
                "phase_12",
                "phase_18",
                "phase_20",
                "phase_23",  # §2.46 Step 5: Spectral Repair (additiv)
                "phase_24",
                "phase_25",
                "phase_27",
                "phase_28",
                "phase_29",
                "phase_49",
                "phase_55",
            )

            # §Spec04 RELEASE_MUST: Pipeline-Wall-Time-Budget — verhindert 25:1-Ratio-Hänger.
            # Material-adaptive: mehr Zeit für schlechte Materialien, weniger für saubere.
            _PIPELINE_WALL_BUDGET_S: dict[str, float] = {
                # CPU-only realistische Werte: 4-5 min Song, alle Phasen vollständig.
                # Gemessen: vinyl non-exempt ~1372 s auf CPU-only — Budget war 600 s (zu klein).
                # Neue Werte: ~2× gemessene Maximal-Laufzeit als Hänger-Schutz-Grenze.
                "shellac": 3600.0,  # 1h — viele Pflicht-Phasen, ML-Pitch, AudioSR
                "wax_cylinder": 3600.0,
                "wire_recording": 3600.0,
                "vinyl": 2700.0,  # 45 min — ~1372 s non-exempt gemessen + 2× Puffer
                "reel_tape": 2700.0,
                "tape": 2700.0,
                "cassette": 2400.0,
                "lacquer_disc": 2700.0,
                "minidisc": 1800.0,
                "mp3_low": 1800.0,
                "mp3_high": 1200.0,
                "cd_digital": 1200.0,
                "streaming": 900.0,
            }
            _mat_key_budget = str(getattr(material_type, "value", str(material_type))).lower()
            _pipeline_wall_budget_base = float(_PIPELINE_WALL_BUDGET_S.get(_mat_key_budget, 480.0))
            # Compute audio duration locally (audio is available in _execute_pipeline signature).
            _audio_duration_s = float(audio.shape[-1] if audio.ndim >= 2 else len(audio)) / float(sample_rate)
            # §Spec04b Duration-Scaling: budget = min(base, overhead + duration × factor).
            # Prevents long songs from consuming all budget in one phase (e.g. ADMM 41 min
            # on a 225s song exhausting the entire 2700s vinyl budget).
            # 450s fixed overhead + 10s/s audio → 225s song gets min(2700, 2700) = 2700s budget.
            # v9.11.14: increased from 300+8×dur (=2100s) to 450+10×dur (=2700s) after
            # observed wall-time exhaustion on vinyl 225s (phase_42 fallback chain ~25 min).
            _PIPELINE_BUDGET_OVERHEAD_S = 450.0
            _PIPELINE_BUDGET_PER_SEC = 10.0
            _pipeline_wall_budget = min(
                _pipeline_wall_budget_base,
                _PIPELINE_BUDGET_OVERHEAD_S + _audio_duration_s * _PIPELINE_BUDGET_PER_SEC,
            )
            if _pipeline_wall_budget < _pipeline_wall_budget_base:
                logger.info(
                    "§Spec04b Wall-Budget Duration-Scaling:"
                    " %.0fs (base=%.0fs, duration=%.1fs × %.0f s/s + %.0fs overhead)",
                    _pipeline_wall_budget,
                    _pipeline_wall_budget_base,
                    _audio_duration_s,
                    _PIPELINE_BUDGET_PER_SEC,
                    _PIPELINE_BUDGET_OVERHEAD_S,
                )
            _pipeline_start_time = time.time()
            # §Wall-Time-Budget non-exempt tracker: nur nicht-exempt-Phasen zählen zum Budget.
            # Exempt-Phasen (§6.2a: click, crackle, wow/flutter, phase_corr, dc_offset) sind
            # Pflicht und können auf CPU lange laufen (pYIN, ML-Pitch) — sie dürfen das Budget
            # für optionale/Enhancement-Phasen NICHT aufbrauchen.
            _pipeline_non_exempt_elapsed_s: float = 0.0
            # §6.2a: Diese Phasen dürfen NICHT durch das Wall-Time-Budget übersprungen werden.
            _WALL_BUDGET_EXEMPT_PHASES = frozenset(
                {
                    "phase_01_click_removal",
                    "phase_09_crackle_removal",
                    "phase_12_wow_flutter_fix",
                    "phase_14_phase_correction",
                    "phase_15_stereo_balance",
                    "phase_30_dc_offset_removal",
                    # §2.46 Carrier-Chain subtraktiv: Vinyl-Oberflächenrauschen ist Träger-Defekt,
                    # muss wie phase_09 unabhängig vom Budget laufen.
                    "phase_28_surface_noise_profiling",
                    # §2.63 Safety-Net: TruePeak-Limiter ist finale Fangschicht gegen
                    # Pegelexplosionen — darf NIEMALS durch Wall-Time-Budget übersprungen werden.
                    "phase_47_truepeak_limiter",
                }
            )

            for phase_id in selected_phases:
                phase = self._get_phase(phase_id)
                if not phase:
                    logger.warning("Phase %s konnte nicht lazy-geladen werden, skipping", phase_id)
                    skipped.append(phase_id)
                    _record_oom_probe("phase_skip_not_loaded", phase_id)
                    continue

                # §2.65 MAS-Early-Stop: wenn alle P1/P2-Goals das song-spezifische
                # Maximum erreicht haben, Pipeline stoppen — keine weiteren optionalen Phasen.
                # _NEVER_SKIP-Phasen (phase_01/09/12/14/15/30/47) laufen immer durch.
                _NEVER_SKIP_MAS = frozenset(
                    {
                        "phase_01_click_removal",
                        "phase_09_crackle_removal",
                        "phase_12_wow_flutter_fix",
                        "phase_14_phase_correction",
                        "phase_15_stereo_balance",
                        "phase_30_dc_offset_removal",
                        "phase_47_truepeak_limiter",
                    }
                )
                if getattr(self, "_mas_fully_achieved", False) and phase_id not in _NEVER_SKIP_MAS:
                    logger.info(
                        "§2.65 MAS-Early-Stop: %s übersprungen (MAS erreicht bei %s)",
                        phase_id,
                        (self._phase_metadata_accumulator or {}).get("mas_achieved_at_phase", "?"),
                    )
                    skipped.append(phase_id)
                    continue
                # §Per-Channel: Defekt-Phasen bei Stereo-Audio kanalweise verarbeiten
                _use_channel_split = (
                    phase_id in self._CHANNEL_SPECIFIC_PHASES
                    and current_audio.ndim == 2
                    and current_audio.shape[-1] == 2
                )
                _phase_for_exec = (
                    self._ChannelSplitPhaseProxy(phase, audio_update_callback, sample_rate)
                    if _use_channel_split
                    else phase
                )
                metadata = phase.get_metadata()
                remaining = len(selected_phases) - len(executed) - 1
                estimated_time = metadata.estimated_time_factor * (audio.shape[-1] / sample_rate)
                if (
                    (not no_rt_limit)
                    and self.performance_guard
                    and self.performance_guard.should_skip_phase(phase_id, estimated_time, remaining)
                ):
                    skipped.append(phase_id)
                    deferred.append(phase_id)  # §2.38 KMV: RT-skipped → Stage 2
                    _record_oom_probe("phase_deferred_rt", phase_id, estimated_time_s=round(float(estimated_time), 3))
                    continue

                # §Spec04 Wall-Time-Budget: Phasen überspringen die das Budget sprengen würden.
                # §0c: Kein harter Abbruch — verbleibende Phasen als Passthrough, nicht Skip.
                # §non-exempt-only: Nur nicht-exempt Phasen zählen zum Budget — exempt Phasen
                # (§6.2a mandatory: click, crackle, wow/flutter, phase_corr, dc_offset) können
                # auf CPU-only Systemen sehr lang laufen (ML-Pitch, pYIN auf 4-min Audio) ohne
                # dass optionale Restaurierungs- oder Enhancement-Phasen ihr Budget verlieren.
                if phase_id not in _WALL_BUDGET_EXEMPT_PHASES:
                    _remaining_budget_s = max(0.0, _pipeline_wall_budget - _pipeline_non_exempt_elapsed_s)
                    _budget_skip_reason = self._budget_pressure_skip_reason(
                        phase_id,
                        material_key=_mat_key_budget,
                        remaining_budget_s=_remaining_budget_s,
                        estimated_time_s=float(estimated_time),
                        future_phases=list(selected_phases[len(executed) + 1 :]),
                    )
                    if _budget_skip_reason is not None:
                        logger.info(
                            "§Wall-Time-Budget Reserve: %s als Passthrough übersprungen (%s)",
                            phase_id,
                            _budget_skip_reason,
                        )
                        skipped.append(phase_id)
                        if hasattr(self, "_phase_metadata_accumulator"):
                            self._phase_metadata_accumulator[phase_id] = {
                                **(self._phase_metadata_accumulator.get(phase_id) or {}),
                                "budget_passthrough_reason": dict(_budget_skip_reason),
                            }
                        continue
                    if _pipeline_non_exempt_elapsed_s > _pipeline_wall_budget:
                        logger.warning(
                            "§Wall-Time-Budget: %.0f s non-exempt > %.0f s"
                            " (material=%s) — %s als Passthrough übersprungen",
                            _pipeline_non_exempt_elapsed_s,
                            _pipeline_wall_budget,
                            _mat_key_budget,
                            phase_id,
                        )
                        skipped.append(phase_id)
                        continue

                phase_start = self.performance_guard.start_phase(phase_id) if self.performance_guard else time.time()
                # §Wall-Time-Budget: _wall_phase_start nutzt time.monotonic() — kompatibel
                # mit time.perf_counter() UND time.time()-Fallback. start_phase() gibt
                # perf_counter() zurück (Systemuptime), time.time() ist Unix-Epoch —
                # beide sind NICHT subtrahierbar (Bug: ~1.744.900.000 s statt echte Laufzeit).
                _wall_phase_start = time.monotonic()
                # §OOM-Diagnose: Phase-Identity VOR Eviction loggen — damit der Phase-Name
                # im Log erscheint, BEVOR PLM-Eviction das RAM-Niveau ändert.
                # Ohne diesen Log kann bei einem OOM-Kill nicht mehr zurückverfolgt werden,
                # welche Phase die Allokation ausgelöst hat.
                logger.info(
                    "▶ %s geplant (%d/%d) — Eviction + RAM-Check folgen",
                    phase_id,
                    len(executed) + 1,
                    len(selected_phases),
                )
                # ── §2.37 Automatische ML-RAM-Verwaltung: Vor jeder Phase ──
                # Entlade alle ML-Modelle die für die kommende Phase NICHT benötigt
                # werden. Gewährleistet, dass nur aktiv benötigte Modelle im RAM sind.
                try:
                    from backend.core.plugin_lifecycle_manager import evict_for_phase as _evict_for_phase

                    _evict_for_phase(phase_id)
                except Exception as _exc:
                    logger.debug("evict_for_phase(%s) failed: %s", phase_id, _exc)
                # Zusätzlich: RAM-Check vor Phase — bei kritischem RAM GC erzwingen oder deferrieren.
                # §OOM-Guard: Schwellwert 4 GB (statt 2 GB) — gibt 2× mehr Puffer für große
                # Numpy-Allokationen (STFT-Matrizen ~1.5 GB, ML-Models 1–6 GB).
                # Nach AudioSR (5.8 GB) hält Python-Allocator fragmentierten Heap im RSS, auch
                # nach PLM-Eviction + malloc_trim. Pre-Phase-Deep-Flush verhindert OOM-Kill.
                try:
                    import psutil as _ps_pre

                    _vm_pre = _ps_pre.virtual_memory()
                    _avail_pre = _vm_pre.available / (1024**3)
                    _ram_pct_pre = _vm_pre.percent
                    # Deep-Flush: wenn RAM > 75 % UND AudioSR zuvor gelaufen (große Heap-Fragmente)
                    # → aggressive GC + malloc_trim BEVOR die nächste Phase ihren Speicher anfordert.
                    _audiosr_ran = bool(getattr(self, "_restoration_context", {}).get("audiosr_applied", False))
                    if _ram_pct_pre > 75.0 or (_audiosr_ran and _ram_pct_pre > 70.0):
                        gc.collect(2)  # alle 3 Generationen
                        gc.collect(2)  # drittes collect für zirkuläre Refs
                        try:
                            import ctypes as _ctypes_pre

                            _ctypes_pre.CDLL("libc.so.6").malloc_trim(0)
                        except Exception:
                            pass
                        _avail_pre = _ps_pre.virtual_memory().available / (1024**3)
                        _ram_pct_pre = _ps_pre.virtual_memory().percent
                        logger.info(
                            "§OOM-DeepFlush vor %s: RAM nach GC+trim=%.1f%% (%.1f GB frei)",
                            phase_id,
                            _ram_pct_pre,
                            _avail_pre,
                        )
                    if _avail_pre < 4.0:
                        logger.warning(
                            "⚠️ Nur %.1f GB frei nach Eviction+GC — %s wird deferred (KMV Stufe 2)",
                            _avail_pre,
                            phase_id,
                        )
                        skipped.append(phase_id)
                        deferred.append(phase_id)
                        _record_oom_probe("phase_deferred_low_ram", phase_id, available_gb=round(float(_avail_pre), 3))
                        continue
                except ImportError:
                    logger.debug("psutil not available — pre-phase RAM check skipped")
                logger.info("▶ %s startet (%d/%d)", phase_id, len(executed) + 1, len(selected_phases))
                _record_oom_probe("phase_start", phase_id, estimated_time_s=round(float(estimated_time), 3))
                # §2.61 Input-Länge für Output-Length-Guard festhalten
                _phase_input_len_2_61: int = len(current_audio)
                # §2.16 TQC mid-pipeline: Snapshot + Baseline-Messung vor zeitmodifizierenden Phasen
                _tqc_snap: np.ndarray | None = current_audio.copy() if phase_id in _TQC_CRITICAL_PHASES_SEQ else None
                _tqc_snap_span: float = -1.0  # Baseline max_span; -1.0 = nicht gemessen
                if _tqc_snap is not None:
                    try:
                        from backend.core.temporal_quality_coherence import measure_temporal_coherence as _tqc_meas

                        _tqc_baseline = _tqc_meas(_tqc_snap, sample_rate)
                        _tqc_snap_span = _tqc_baseline.max_span
                    except Exception as _exc:
                        logger.debug("TQC baseline measurement failed for %s: %s", phase_id, _exc)
                # §Punkt3 Regressionsprotokoll: RMS vor Phase messen (in dBFS)
                _rms_before = float(np.sqrt(np.mean(current_audio**2) + 1e-12))
                _rms_before_db = 20.0 * np.log10(_rms_before)
                # §2.49 AFG: per-phase snapshot — compare only THIS phase's delta, not cumulative pipeline drift.
                # Cumulative comparison falsely flags intentional enhancement changes (bass boost, saturation,
                # harmonic enhancement) as musical-noise artifacts because the accumulated residual after N
                # restoration phases overwhelms the artifact detector thresholds.
                _afg_phase_input: np.ndarray | None = current_audio.copy() if _artifact_gate is not None else None
                # §7 PDV: Pre-phase reference for defect proxy comparison (no copy: current_audio is reassigned).
                _pdv_pre_phase: np.ndarray = current_audio
                # §PROGRESS: Emit BEFORE phase execution — real-time ML plugin detection
                # Compute heartbeat range so _profiled_phase_call can inject a scoped
                # sub-progress callback into slow phases (e.g. phase_49 WPE dereverb).
                _hb_n_sel = max(len(selected_phases), 1)
                _hb_idx = len(executed)
                _hb_pct_start = _phase_progress_start + int(
                    (_phase_progress_end - _phase_progress_start) * _hb_idx / _hb_n_sel
                )
                _hb_pct_end = _phase_progress_start + int(
                    (_phase_progress_end - _phase_progress_start) * (_hb_idx + 1) / _hb_n_sel
                )
                self._active_pipeline_cb_for_sub = progress_callback  # may be None
                self._active_phase_pct_for_sub = (_hb_pct_start, _hb_pct_end)
                if progress_callback is not None:
                    try:
                        _n_sel_pre = _hb_n_sel
                        _idx_pre = _hb_idx
                        _pct_pre = _hb_pct_start
                        _lbl_pre = (self.phase_metadata.get(phase_id) or {}).get("name") or phase_id.replace(
                            "phase_", ""
                        ).replace("_", " ").title().lstrip("0123456789 ")
                        progress_callback(
                            _pct_pre,
                            f"{_lbl_pre} [{phase_id}]",
                            0.0,
                        )
                    except Exception as _exc:
                        logger.debug("Progress callback (seq pre) failed: %s", _exc)
                try:
                    if _pmgg_gate is not None:
                        # §2.29 PMGG: Musical-Goal-geschützte Phasenausführung
                        try:
                            # §MusikalischeHarmonisierung: Defekt-Severity-Faktor moduliert Stärke
                            # Phasen arbeiten proportional zur gemessenen Defekt-Schwere,
                            # nicht mit festen Material-Defaults.
                            _mat_strength = (
                                material_initial_strengths.get(phase_id, 1.0) if material_initial_strengths else 1.0
                            )
                            try:
                                from backend.core.defect_phase_mapper import get_phase_defect_severity

                                _sev_factor = get_phase_defect_severity(phase_id, defect_result.scores)
                                _combined_strength = _mat_strength * _sev_factor
                                if _sev_factor < 1.0:
                                    logger.debug(
                                        "🎵 DefectSeverity %s: initial_strength %.2f × sev_factor %.2f = %.2f",
                                        phase_id,
                                        _mat_strength,
                                        _sev_factor,
                                        _combined_strength,
                                    )
                            except Exception:
                                _combined_strength = _mat_strength

                            # §Psychoacoustic: reduce processing strength where defects are
                            # partially masked — the ear cannot detect what is below the masking
                            # threshold, so less-aggressive processing preserves more character.
                            # Timing phases (phase_12, phase_31) are excluded — wet/dry blend
                            # does not apply there and pitch correction must never be clipped.
                            _MASK_TIMING = frozenset({"phase_12_wow_flutter_fix", "phase_31_speed_pitch_correction"})
                            if _masking_scalar < 1.0 and phase_id not in _MASK_TIMING:
                                _combined_strength = _combined_strength * (0.7 + 0.3 * _masking_scalar)
                                logger.debug(
                                    "§Psychoacoustic masking: %s strength clamped to %.3f (masking_scalar=%.3f)",
                                    phase_id,
                                    _combined_strength,
                                    _masking_scalar,
                                )

                            # §2.31a SongCalibration: Family-Scalar in initial_strength einbeziehen.
                            # Dadurch profitiert auch die PMGG-Retry-Leiter (§2.29a) proportional
                            # vom Kalibrierungs-Skalar — weniger Retries bei gut kalibrierter Stärke.
                            _song_cal_profile = getattr(self, "_song_calibration_profile", None)
                            if _song_cal_profile and phase_id not in _MASK_TIMING:
                                _song_cal_scalar = self._get_phase_calibration_scalar(phase_id, _song_cal_profile)
                                if abs(_song_cal_scalar - 1.0) >= 0.03:  # sub-3% Anpassungen ignorieren
                                    _combined_strength = float(
                                        np.clip(_combined_strength * _song_cal_scalar, 0.05, 1.0)
                                    )
                                    logger.debug(
                                        "🎛️ SongCal(PMGG) %s: scalar=%.3f → initial_strength=%.3f",
                                        phase_id,
                                        _song_cal_scalar,
                                        _combined_strength,
                                    )

                            # Strict conflict policy: per-phase hard caps for conflict-prone phases.
                            _strict_policy = (
                                _song_cal_profile.get("strict_conflict_policy", {})
                                if isinstance(_song_cal_profile, dict)
                                else {}
                            )
                            _phase_caps = (
                                _strict_policy.get("phase_strength_caps", {})
                                if isinstance(_strict_policy, dict)
                                else {}
                            )
                            if isinstance(_phase_caps, dict) and phase_id in _phase_caps:
                                _cap_val = float(np.clip(_phase_caps.get(phase_id, 1.0), 0.05, 1.0))
                                if _combined_strength > _cap_val:
                                    logger.debug(
                                        "StrictAutoSetup cap: %s strength %.3f -> %.3f",
                                        phase_id,
                                        _combined_strength,
                                        _cap_val,
                                    )
                                    _combined_strength = _cap_val

                            # §9.10.118 Diminishing-Returns-Moderation:
                            # Each STFT round-trip (STFT→modify→ISTFT) introduces
                            # cumulative spectral smearing.  After the 20th executed
                            # phase, attenuate strength proportionally to reduce
                            # unnecessary degradation while keeping all phases active
                            # (§2.29 Phase-Skip-Verbot bleibt gewahrt).
                            _n_exec = len(executed)
                            if _n_exec > 20 and phase_id not in _MASK_TIMING:
                                _diminish = max(0.30, 1.0 - 0.015 * (_n_exec - 20))
                                _combined_strength = float(np.clip(_combined_strength * _diminish, 0.05, 1.0))
                                if _diminish < 0.95:
                                    logger.debug(
                                        "§9.10.118 DiminishingReturns %s: exec#%d → factor=%.3f strength=%.3f",
                                        phase_id,
                                        _n_exec,
                                        _diminish,
                                        _combined_strength,
                                    )

                            # §9.11.1 Restorability-Ceiling (v9.11.1):
                            # High restorability = audio already in good condition = less aggressive
                            # processing needed. Cap proportional to material health, only for
                            # optional phases (mandatory §6.2a phases are exempt).
                            # Formula: cap = 1.0 when restorability ≤ 65 (damaged material, no cap)
                            #          cap = 0.45 when restorability = 100 (pristine, max 45% strength)
                            # Curve: linear ramp from 65→100 maps to cap 1.0→0.45
                            _mandatory_set = frozenset(getattr(self, "_last_material_priority_phases", ()) or ())
                            _is_mandatory_phase = phase_id in _mandatory_set
                            # §2.54 normative: restorative/carrier-repair phases are exempt from
                            # PlateauStop and RestorabilitysCeiling. Their spectral proxy delta
                            # can be zero or negative (§2.44 Referenz-Paradoxon) -- that is not
                            # a plateau signal. Dampening them defeats defect repair.
                            _PLATEAU_EXEMPT_PREFIXES = (
                                "phase_01_",
                                "phase_02_",
                                "phase_03_",
                                "phase_04_",
                                "phase_05_",
                                "phase_09_",
                                "phase_12_",
                                "phase_14_",
                                "phase_15_",
                                "phase_18_",
                                "phase_19_",
                                "phase_20_",
                                "phase_23_",
                                "phase_24_",
                                "phase_25_",
                                "phase_27_",
                                "phase_28_",
                                "phase_29_",
                                "phase_30_",
                                "phase_31_",
                                "phase_49_",
                                "phase_50_",
                                "phase_55_",
                                "phase_56_",
                                "phase_57_",
                                "phase_59_",
                                "phase_60_",
                                "phase_62_",
                                "phase_63_",
                            )
                            _is_restorative_phase = any(phase_id.startswith(p) for p in _PLATEAU_EXEMPT_PREFIXES)
                            if not _is_mandatory_phase and not _is_restorative_phase:
                                _rest_pct = float(getattr(self, "_last_restorability_score", _pmgg_restorability_score))
                                if _rest_pct > 65.0:
                                    _rest_cap = 1.0 - 0.55 * (_rest_pct - 65.0) / 35.0
                                    _rest_cap = float(np.clip(_rest_cap, 0.45, 1.0))
                                    if _combined_strength > _rest_cap:
                                        logger.debug(
                                            "§9.11.1 RestorabilitysCeiling %s: rest=%.1f cap=%.3f strength %.3f->%.3f",
                                            phase_id,
                                            _rest_pct,
                                            _rest_cap,
                                            _combined_strength,
                                            _rest_cap,
                                        )
                                        _combined_strength = _rest_cap

                            # §9.11.1 Perceptual-Plateau-Stop (v9.11.1, §2.54):
                            # Only applies to non-mandatory, non-restorative (enhancement) phases.
                            # Restorative and carrier-repair phases are exempt (see above).
                            if (
                                not _is_mandatory_phase
                                and not _is_restorative_phase
                                and len(_plateau_delta_history) == 3
                                and all(d < _PLATEAU_THRESHOLD for d in _plateau_delta_history)
                            ):
                                _dampened = _combined_strength * _PLATEAU_DAMPEN
                                logger.debug(
                                    "§9.11.1 PlateauStop %s: last-3-deltas=%s → strength %.3f→%.3f",
                                    phase_id,
                                    [round(d, 4) for d in _plateau_delta_history],
                                    _combined_strength,
                                    _dampened,
                                )
                                _combined_strength = float(np.clip(_dampened, 0.05, 1.0))

                            # §2.9a RELEASE_MUST: PANNs Soft-Activation fuer Vocals muss die
                            # tatsaechliche Phase-Staerke beeinflussen (nicht nur Metadaten).
                            # Bereich 0.35-0.40 setzt vocal_strength_scale=0.5 und skaliert
                            # explizit die PMGG-initial_strength fuer die Vocal-Phasen.
                            _vocal_soft_phases = frozenset(
                                {
                                    "phase_19_de_esser",
                                    "phase_42_vocal_enhancement",
                                    "phase_43_ml_deesser",
                                }
                            )
                            _vocal_strength_scale = float(
                                np.clip(
                                    float(getattr(self, "_restoration_context", {}).get("vocal_strength_scale", 1.0)),
                                    0.0,
                                    1.0,
                                )
                            )
                            if phase_id in _vocal_soft_phases and _vocal_strength_scale < 1.0:
                                _pre_soft_strength = _combined_strength
                                _combined_strength = float(
                                    np.clip(_combined_strength * _vocal_strength_scale, 0.05, 1.0)
                                )
                                logger.debug(
                                    "§2.9a Vocal Soft-Scale %s: %.3f -> %.3f (scale=%.2f)",
                                    phase_id,
                                    _pre_soft_strength,
                                    _combined_strength,
                                    _vocal_strength_scale,
                                )

                            # §2.54 Ceiling-Aware Headroom Scalar
                            # Additive/Enhancement-Phasen arbeiten mit einer Stärke proportional
                            # zum verbleibenden Headroom bis zur physikalischen Deckengrenze.
                            # Wenn das Audio bereits nah an der Decke ist (z.B. brillanz=0.48 bei
                            # Ceiling=0.51), soll die Phase mit reduzierter Stärke laufen —
                            # Over-Processing wird vermieden, Artefakt-Risiko sinkt.
                            # Restorative/Carrier-Repair-Phasen und Pflicht-Phasen sind ausgenommen.
                            _ceiling_tgts = getattr(self, "_pmgg_ceiling_capped_targets", None)
                            if (
                                isinstance(_ceiling_tgts, dict)
                                and _ceiling_tgts
                                and isinstance(_pmgg_scores_curr, dict)
                                and _pmgg_scores_curr
                                and not _is_restorative_phase
                                and not _is_mandatory_phase
                            ):
                                _hr_family = self._PHASE_INTERVENTION_CLASS.get(phase_id, "general")
                                _ADDITIVE_HR_FAMILIES = frozenset(
                                    {
                                        "harmonic_reconstruction",
                                        "harmonic_enhancement",
                                        "tonal_enhancement",
                                        "source_enhancement",
                                        "stereo_enhancement",
                                        "stereo_generation",
                                    }
                                )
                                if _hr_family in _ADDITIVE_HR_FAMILIES:
                                    # P4/P5-Goals — am stärksten von Enhancement-Phasen beeinflusst
                                    _HR_GOALS = ("brillanz", "waerme", "spatial_depth", "bass_kraft", "sep_fidelity")
                                    # Headroom-Fenster: innerhalb der letzten 0.25 zur Decke wird gedämpft.
                                    # Jenseits von 0.25 Headroom → volle Stärke (Phase kann frei arbeiten).
                                    # Wissen: psychoakustisches Sättigungsgesetz — Grenznutzen sinkt nahe
                                    # physikalischer Decke; Artefakt-Risiko steigt gleichzeitig.
                                    _HR_WINDOW = 0.25
                                    _min_hr = 1.0
                                    for _hrg in _HR_GOALS:
                                        _hr_ceil = float(_ceiling_tgts.get(_hrg, 1.0))
                                        _hr_curr = float(_pmgg_scores_curr.get(_hrg, 0.0))
                                        # Absoluter Headroom (Abstand bis zur Decke)
                                        _headroom = max(0.0, _hr_ceil - _hr_curr)
                                        # Linear: 1.0 bei ≥ HR_WINDOW Abstand; 0.0 an der Decke
                                        _hr_ratio = min(1.0, _headroom / _HR_WINDOW)
                                        _min_hr = min(_min_hr, _hr_ratio)
                                    # Bound: nie unter 40 % (Phase soll immer einen Beitrag leisten)
                                    _hr_strength = float(np.clip(_min_hr, 0.40, 1.0))
                                    if _hr_strength < 0.95:  # Nur bei bedeutsamer Differenz
                                        _pre_hr_s = _combined_strength
                                        _combined_strength = float(
                                            np.clip(_combined_strength * _hr_strength, 0.05, 1.0)
                                        )
                                        logger.debug(
                                            "§2.54 HeadroomScalar %s: family=%s min_hr=%.2f strength %.3f→%.3f",
                                            phase_id,
                                            _hr_family,
                                            _min_hr,
                                            _pre_hr_s,
                                            _combined_strength,
                                        )

                            # §6.2a [RELEASE_MUST] Mandatory-Phase-Floor: Pflicht-Phasen aus
                            # _MATERIAL_PRIORITY_PHASES werden unabhängig vom DefectScanner-Score
                            # aktiviert (Scanner statistisch — einzelne Defekte unter Schwelle).
                            # Daher darf _sev_factor diese Phasen nicht auf Near-Zero
                            # reduzieren: floor = _mat_strength × 0.40 sichert minimale Wirkung.
                            # PMGG retries down wenn Regression → kein Over-Processing-Risiko.
                            # Ohne diesen Guard: shellac phase_09 bei sev=0.15 → strength=0.12
                            # → crackle bleibt fast ungecancelt trotz Pflicht-Aktivierung.
                            if _is_mandatory_phase:
                                _mandatory_floor = _mat_strength * 0.40
                                if _combined_strength < _mandatory_floor:
                                    logger.debug(
                                        "§6.2a MandatoryFloor %s: strength %.3f→%.3f "
                                        "(mat_strength=%.2f × 0.40, sev_factor was low)",
                                        phase_id,
                                        _combined_strength,
                                        _mandatory_floor,
                                        _mat_strength,
                                    )
                                    _combined_strength = float(np.clip(_mandatory_floor, 0.05, 1.0))

                            _pmgg_scores_before_phase = (
                                dict(_pmgg_scores_curr) if isinstance(_pmgg_scores_curr, dict) else {}
                            )
                            _pmgg_audio_out, _pmgg_scores_curr, _pmgg_entry = _pmgg_gate.wrap_phase(
                                _phase_for_exec,
                                current_audio,
                                sample_rate,
                                scores_before=_pmgg_scores_curr,
                                phase_kwargs={
                                    "sample_rate": sample_rate,
                                    "material_type": material_type,
                                    "material": material_type,
                                    # §6.2a Transfer-Chain: analoge Kettenstufen für phase-lokale
                                    # Skip-Guards (z.B. phase_29 überspringt bei mp3_low ohne Chain-Check).
                                    "transfer_chain": (
                                        getattr(self, "_restoration_context", {}).get("transfer_chain", [])
                                    ),
                                    "defect_scores": defect_result.scores,
                                    "defect_locations": _defect_locations,
                                    "defect_severity_map": _defect_severity_map,
                                    "defect_saliency_map": _defect_saliency_map,
                                    "defect_location_coverage_map": _defect_location_coverage_map,
                                    "max_defect_severity": _max_defect_severity,
                                    "quality_mode": _quality_mode_value,
                                    "adaptive_chunk_fn": (
                                        _acp_process_fn
                                        if (_acp_available and phase_id in _ACP_ELIGIBLE_PHASES)
                                        else None
                                    ),
                                    "repaired_gap_samples": _repaired_gap_samples,  # §11.7a
                                    "masking_result": _masking_result,  # §Psychoacoustic: MaskingResult L/mono
                                    "masking_result_r": _masking_result_r,  # §Psychoacoustic: MaskingResult R channel
                                    "masking_scalar": _masking_scalar,  # audibility scalar ∈ [0.4, 1.0]
                                    "song_calibration_profile": (
                                        dict(self._song_calibration_profile)
                                        if getattr(self, "_song_calibration_profile", None)
                                        else {}
                                    ),  # §2.31a SongCalibration opt-in
                                    "phoneme_timeline": phoneme_timeline,  # §2.36a: PhonemeTimeline opt-in
                                    "pre_transcription": pre_transcription,  # §2.36: LGE transcription for phase_58
                                    "vocal_probability": float(
                                        getattr(self, "_restoration_context", {}).get("panns_vocals_confidence", 1.0)
                                    ),  # §2.36: PANNs vocal prob for phase_58
                                    "vocal_strength_scale": float(
                                        getattr(self, "_restoration_context", {}).get("vocal_strength_scale", 1.0)
                                    ),  # §2.9a: explicit soft-activation hint for vocal phases
                                    # §Cross-Goal-Recovery: phase_06/07/39 lesen diesen Key um
                                    # HF-Restaurierung trotz fehlendem Rolloff zu erzwingen.
                                    # Muss hier injiziert werden — phase_kwargs ist die einzige
                                    # Quelle für Phase-kwargs; _restoration_context ist nicht
                                    # direkt in Phase-kwargs verfügbar.
                                    "hf_recovery_boost_after_phase03": (
                                        getattr(self, "_restoration_context", {}).get("hf_recovery_boost_after_phase03")
                                    ),
                                    # §HF-Tracking: kumulativer HF-Gain für phase_39-Guard (war dead code).
                                    # phase_39 liest hf_cumulative_gain_db aus kwargs; UV3 setzt/aktualisiert.
                                    "hf_cumulative_gain_db": float(
                                        getattr(self, "_restoration_context", {}).get("hf_cumulative_gain_db", 0.0)
                                    ),
                                    "song_goal_weights": getattr(
                                        self, "_song_goal_weights", None
                                    ),  # §2.56 phase-local adaptive guards (phase_20/49/55)
                                    "retry_budget_hint": self._pmgg_retry_budget_hint(
                                        phase_id,
                                        material_key=_mat_key_budget,
                                        remaining_budget_s=max(
                                            0.0,
                                            _pipeline_wall_budget - _pipeline_non_exempt_elapsed_s,
                                        ),
                                        estimated_time_s=float(estimated_time),
                                        future_phases=list(selected_phases[len(executed) + 1 :]),
                                    ),
                                },
                                restorability_score=_pmgg_restorability_score,  # §2.29 normativ
                                applicable_goals=applicable_goals,  # §2.32 normativ
                                initial_strength=_combined_strength,  # §2.31 + §Harmonisierung
                                is_studio_2026=self.is_studio_mode(),  # §9.10.77 Pareto P3–P5-Schwellwerte
                                goal_weights=getattr(self, "_song_goal_weights", None),  # §2.56 Song-Goal-Importance
                                adaptive_goal_thresholds=(  # §09.2 + §2.54 ceiling-capped floors → PMGG
                                    dict(self._pmgg_ceiling_capped_targets)
                                    if isinstance(getattr(self, "_pmgg_ceiling_capped_targets", None), dict)
                                    and self._pmgg_ceiling_capped_targets
                                    else (
                                        dict(self._song_goal_targets)
                                        if isinstance(getattr(self, "_song_goal_targets", None), dict)
                                        and self._song_goal_targets
                                        else None
                                    )
                                ),
                            )
                            _pmgg_log_entries.append(_pmgg_entry)
                            _collect_guard_payload(_phase_for_exec, phase_id)
                            # §3.1 NaN-Guard: revert to pre-phase audio if NaN produced
                            if np.any(np.isnan(_pmgg_audio_out)):
                                logger.warning(
                                    "NaN in PMGG-Ausgabe von Phase %s erkannt — Audio-Rollback auf Vor-Phase-Zustand",
                                    phase_id,
                                )
                            else:
                                current_audio = _active_quality_intervention(
                                    phase_id,
                                    current_audio,
                                    _pmgg_audio_out,
                                    original_reference=_pipeline_original_reference,
                                    quiet_edge_profile=_pipeline_quiet_edge_profile,
                                )
                                current_audio = np.clip(current_audio, -1.0, 1.0)
                                # §HF-Tracking (PMGG-Primary): hf_cumulative_gain_db nach HF-additiver Phase.
                                if phase_id in _HF_ADDITIVE_PHASE_CONTRIB_DB and isinstance(
                                    getattr(self, "_restoration_context", None), dict
                                ):
                                    _hf_contrib_pmgg = _HF_ADDITIVE_PHASE_CONTRIB_DB[phase_id]
                                    self._restoration_context["hf_cumulative_gain_db"] = float(
                                        self._restoration_context.get("hf_cumulative_gain_db", 0.0) + _hf_contrib_pmgg
                                    )
                                    logger.debug(
                                        "§HF-Track (PMGG): %s +%.1f dB → cumul=%.1f dB",
                                        phase_id,
                                        _hf_contrib_pmgg,
                                        self._restoration_context["hf_cumulative_gain_db"],
                                    )
                            _restoration_critical_best_effort = (
                                (not self.is_studio_mode())
                                and phase_id
                                in {
                                    "phase_17_mastering_polish",
                                    "phase_24_dropout_repair",
                                    "phase_42_vocal_enhancement",
                                    "phase_55_diffusion_inpainting",
                                }
                                and str(_pmgg_entry.action).startswith("best_effort")
                            )
                            if _restoration_critical_best_effort:
                                logger.warning(
                                    "§0/§2.45 Restoration rollback: %s ended in %s"
                                    " — revert instead of shipping known-bad enhancement",
                                    phase_id,
                                    _pmgg_entry.action,
                                )
                                current_audio = np.clip(_pdv_pre_phase.copy(), -1.0, 1.0)
                                _pmgg_scores_curr = _pmgg_scores_before_phase
                                skipped.append(phase_id)
                                _record_oom_probe(
                                    "phase_best_effort_rollback", phase_id, action=str(_pmgg_entry.action)
                                )
                                continue
                            # §PROGRESS: Per-Phase Fortschritt (PMGG-Pfad)
                            _n_sel = max(len(selected_phases), 1)
                            _idx_ex = len(executed)
                            _phase_pct = _phase_progress_start + int(
                                (_phase_progress_end - _phase_progress_start) * _idx_ex / _n_sel
                            )
                            if progress_callback is not None:
                                try:
                                    _phase_label = (self.phase_metadata.get(phase_id) or {}).get(
                                        "name"
                                    ) or phase_id.replace("phase_", "").replace("_", " ").title().lstrip("0123456789 ")
                                    progress_callback(
                                        _phase_pct,
                                        f"{_phase_label} [{phase_id}]",
                                        0.0,
                                    )
                                except Exception as _cb_exc:
                                    logger.debug(
                                        "Progress-Update übersprungen in %s (Ursache: %s). "
                                        "Lösung: Callback-Signatur prüfen.",
                                        phase_id,
                                        _cb_exc,
                                    )
                            executed.append(phase_id)
                            # §9.11.1 PlateauStop: track spectral quality delta for rolling window.
                            # Only count if phase actually changed audio -- passthrough phases
                            # (§2.58) produce delta=0.0 and would prematurely signal plateau,
                            # dampening subsequent restorative phases (§2.54 violation).
                            # Restorative phases are also excluded: carrier-repair deltas (§2.44)
                            # must not poison the plateau history for enhancement phases.
                            try:
                                if not _is_restorative_phase and not np.array_equal(current_audio, _pdv_pre_phase):
                                    _pdelta_plateau = _spectral_quality_score(
                                        current_audio, sample_rate
                                    ) - _spectral_quality_score(_pdv_pre_phase, sample_rate)
                                    _plateau_delta_history.append(float(_pdelta_plateau))
                            except Exception:
                                pass  # non-critical telemetry, never blocks pipeline
                            # §Live-Waveform: Emit updated audio after PMGG phase
                            if audio_update_callback is not None:
                                try:
                                    audio_update_callback(current_audio, sample_rate, phase_id)
                                except Exception as _exc:
                                    logger.debug("audio_update_callback (PMGG success) failed: %s", _exc)
                            logger.info(
                                "✅ %s: PMGG action=%s strength=%.2f rollbacks=%d",
                                phase_id,
                                _pmgg_entry.action,
                                _pmgg_entry.strength_used,
                                _pmgg_gate._rollback_count,  # pylint: disable=protected-access
                            )
                            if str(_pmgg_entry.action).startswith("best_effort") and not _is_restorative_phase:
                                # Fix 9: Restorative Phasen (Dereverb, Denoise, Dropout-Repair)
                                # dürfen kein StrictConflictDecay auslösen bei best_effort.
                                # §2.29c Restorative-Baseline-Capping: Metrik-Drop nach Defektentfernung
                                # ist intentional (Referenz-Paradoxon §2.44), kein echter Konflikt.
                                self._register_phase_goal_conflict_event(
                                    phase_id,
                                    "pmgg_best_effort",
                                    {
                                        "action": str(_pmgg_entry.action),
                                        "strength_used": float(getattr(_pmgg_entry, "strength_used", 0.0) or 0.0),
                                    },
                                )
                            if (
                                (not self.is_studio_mode())
                                and phase_id == "phase_03_denoise"
                                and str(_pmgg_entry.action).startswith("best_effort")
                            ):
                                try:
                                    if not isinstance(getattr(self, "_restoration_context", None), dict):
                                        self._restoration_context = {}
                                    self._restoration_context["hf_recovery_boost_after_phase03"] = {
                                        "enabled": True,
                                        "source_phase": phase_id,
                                        "source_action": str(_pmgg_entry.action),
                                        # "boost" ist der Key den phase_06 unter Zeile 671 liest
                                        # (TonalReference target_steering strength = 0.30 + 0.20 * boost).
                                        # "source_strength" wird für Rückwärtskompatibilität beibehalten.
                                        "boost": float(getattr(_pmgg_entry, "strength_used", 0.0) or 0.0),
                                        "source_strength": float(getattr(_pmgg_entry, "strength_used", 0.0) or 0.0),
                                    }
                                    logger.warning(
                                        "§Cross-Goal-Recovery armed: %s action=%s"
                                        " strength=%.2f -> enforce HF floors for phase_06/07/39",
                                        phase_id,
                                        str(_pmgg_entry.action),
                                        float(getattr(_pmgg_entry, "strength_used", 0.0) or 0.0),
                                    )
                                except Exception as _cg_exc:
                                    logger.debug(
                                        "Cross-Goal-Recovery context update failed (non-blocking): %s", _cg_exc
                                    )
                            _record_oom_probe("phase_ok", phase_id, action=str(_pmgg_entry.action))
                            # §2.54 AudioSR-Flag: phases after phase_23 get audiosr_applied=True
                            # via _restoration_context so phase_07 can reduce redundant enhancement.
                            if "phase_23" in phase_id:
                                self._restoration_context["audiosr_applied"] = True
                                logger.debug("§2.54 audiosr_applied=True gesetzt (phase_23 erfolgreich)")
                                # §OOM-Guard Post-AudioSR Deep-Flush: AudioSR hält 5.8 GB in Python-Heap.
                                # PLM-Eviction gibt PLM-Tracking frei, aber Python-Allocator behält
                                # fragmentierte glibc-Seiten im RSS. Sofortiger aggressiver Flush
                                # vor der nächsten Phase verhindert OOM-Kill (wie PID1553305, 07:48 UTC).
                                try:
                                    gc.collect(2)
                                    gc.collect(2)  # zweiter Pass für zirkuläre Refs
                                    import ctypes as _ctypes_asr

                                    _ctypes_asr.CDLL("libc.so.6").malloc_trim(0)
                                    logger.info(
                                        "§OOM-PostAudioSR-Flush: gc+malloc_trim nach phase_23 (AudioSR 5.8 GB)",
                                    )
                                except Exception as _asr_flush_exc:
                                    logger.debug("Post-AudioSR flush failed: %s", _asr_flush_exc)
                            # §Punkt3 Regressionsprotokoll: RMS nach PMGG-Phase
                            _rms_after_db = 20.0 * np.log10(float(np.sqrt(np.mean(current_audio**2) + 1e-12)))
                            self._phase_regression_log[phase_id] = round(_rms_after_db - _rms_before_db, 3)
                        except Exception as _pmgg_phase_exc:
                            # Fallback: direkte Phasenausführung via _profiled_phase_call
                            logger.debug(
                                "PMGG wrap_phase Fehler (%s), Fallback: %s",
                                phase_id,
                                _pmgg_phase_exc,
                            )
                            result = self._profiled_phase_call(
                                _phase_for_exec,
                                current_audio,
                                phase_team_context_enabled=True,
                                sample_rate=sample_rate,
                                material_type=material_type,
                                material=material_type,
                                defect_scores=defect_result.scores,
                                defect_locations=_defect_locations,
                                defect_severity_map=_defect_severity_map,
                                defect_saliency_map=_defect_saliency_map,
                                defect_location_coverage_map=_defect_location_coverage_map,
                                max_defect_severity=_max_defect_severity,
                                quality_mode=_quality_mode_value,
                                repaired_gap_samples=_repaired_gap_samples,  # §11.7a
                                masking_result=_masking_result,  # §Psychoacoustic: MaskingResult L/mono
                                masking_result_r=_masking_result_r,  # §Psychoacoustic: MaskingResult R channel
                                masking_scalar=_masking_scalar,  # §Psychoacoustic: audibility scalar ∈ [0.4, 1.0]
                                phoneme_timeline=phoneme_timeline,  # §2.36a: PhonemeTimeline opt-in
                                pre_transcription=pre_transcription,  # §2.36: LGE transcription for phase_58
                                vocal_probability=float(
                                    getattr(self, "_restoration_context", {}).get("panns_vocals_confidence", 1.0)
                                ),  # §2.36: PANNs vocal prob for phase_58
                            )
                            result = _normalize_phase_result(result)
                            _collect_guard_payload(_phase_for_exec, phase_id, result)
                            if result.success:
                                _fa = result.audio
                                _245_skipped_fb = False
                                # §3.1 NaN-Guard: revert to pre-phase audio if NaN produced
                                if not np.any(np.isnan(_fa)):
                                    # §2.45 [RELEASE_MUST] Minimal-Intervention: perceptual_delta > 0 Pflicht.
                                    # PMGG failed so no goal-based guard active — use fast spectral proxy.
                                    _pdelta_245 = _spectral_quality_score(_fa, sample_rate) - _spectral_quality_score(
                                        current_audio, sample_rate
                                    )
                                    if _pdelta_245 > 0.0:
                                        current_audio = _active_quality_intervention(
                                            phase_id,
                                            current_audio,
                                            _fa,
                                            original_reference=_pipeline_original_reference,
                                            quiet_edge_profile=_pipeline_quiet_edge_profile,
                                        )
                                        current_audio = np.clip(current_audio, -1.0, 1.0)
                                    else:
                                        logger.debug(
                                            "§2.45 PMGG-Fallback: %s übersprungen (perceptual_delta=%.4f <= 0.0)",
                                            phase_id,
                                            _pdelta_245,
                                        )
                                        skipped.append(phase_id)
                                        _245_skipped_fb = True
                                else:
                                    logger.warning(
                                        "NaN in PMGG-Fallback-Ausgabe von Phase %s erkannt — Audio-Rollback",
                                        phase_id,
                                    )
                                if not _245_skipped_fb:
                                    # §PROGRESS: Per-Phase Fortschritt (PMGG-Fallback)
                                    _n_sel = max(len(selected_phases), 1)
                                    _idx_ex = len(executed)
                                    _phase_pct = _phase_progress_start + int(
                                        (_phase_progress_end - _phase_progress_start) * _idx_ex / _n_sel
                                    )
                                    if progress_callback is not None:
                                        try:
                                            _phase_label = (self.phase_metadata.get(phase_id) or {}).get(
                                                "name"
                                            ) or phase_id.replace("phase_", "").replace("_", " ").title().lstrip(
                                                "0123456789 "
                                            )
                                            progress_callback(
                                                _phase_pct,
                                                f"{_phase_label} [{phase_id}]",
                                                0.0,
                                            )
                                        except Exception as _cb_exc:
                                            logger.debug(
                                                "Progress-Update übersprungen in %s (Ursache: %s). "
                                                "Lösung: Callback-Signatur prüfen.",
                                                phase_id,
                                                _cb_exc,
                                            )
                                    executed.append(phase_id)
                                    # §Live-Waveform: Emit updated audio after PMGG-fallback phase
                                    if audio_update_callback is not None:
                                        try:
                                            audio_update_callback(current_audio, sample_rate, phase_id)
                                        except Exception as _exc:
                                            logger.debug("audio_update_callback (PMGG fallback) failed: %s", _exc)
                                    logger.info("✅ %s (fallback): %.2fs", phase_id, result.execution_time_seconds)
                                    # §Punkt3 Regressionsprotokoll: RMS nach PMGG-Fallback-Phase
                                    _rms_after_db = 20.0 * np.log10(float(np.sqrt(np.mean(current_audio**2) + 1e-12)))
                                    self._phase_regression_log[phase_id] = round(_rms_after_db - _rms_before_db, 3)
                            else:
                                logger.error("❌ %s failed: %s", phase_id, result.warnings)
                                skipped.append(phase_id)
                                _record_oom_probe("phase_failed", phase_id)
                    else:
                        result = self._profiled_phase_call(
                            _phase_for_exec,
                            current_audio,  # audio parameter
                            phase_team_context_enabled=True,
                            sample_rate=sample_rate,
                            material_type=material_type,
                            material=material_type,
                            defect_scores=defect_result.scores,
                            quality_mode=self.config.mode.value,  # Pass quality mode for ML routing
                        )
                        result = _normalize_phase_result(result)
                        _collect_guard_payload(_phase_for_exec, phase_id, result)
                        if result.success:
                            _ra = result.audio
                            _245_skipped_dr = False
                            # §3.1 NaN-Guard: revert to pre-phase audio if NaN produced
                            if not np.any(np.isnan(_ra)):
                                # §2.45 [RELEASE_MUST] Minimal-Intervention: perceptual_delta > 0 Pflicht.
                                # Direct path (no PMGG) — gate via fast spectral quality proxy.
                                # Exception: no_rt_limit=True = force-execute semantics → §2.45 skip.
                                if no_rt_limit:
                                    current_audio = _active_quality_intervention(
                                        phase_id,
                                        current_audio,
                                        _ra,
                                        original_reference=_pipeline_original_reference,
                                        quiet_edge_profile=_pipeline_quiet_edge_profile,
                                    )
                                    current_audio = np.clip(current_audio, -1.0, 1.0)
                                else:
                                    _pdelta_245_direct = _spectral_quality_score(
                                        _ra, sample_rate
                                    ) - _spectral_quality_score(current_audio, sample_rate)
                                    if _pdelta_245_direct > 0.0:
                                        current_audio = _active_quality_intervention(
                                            phase_id,
                                            current_audio,
                                            _ra,
                                            original_reference=_pipeline_original_reference,
                                            quiet_edge_profile=_pipeline_quiet_edge_profile,
                                        )
                                        current_audio = np.clip(current_audio, -1.0, 1.0)
                                    else:
                                        logger.debug(
                                            "§2.45 Direkt-Pfad: %s übersprungen (perceptual_delta=%.4f <= 0.0)",
                                            phase_id,
                                            _pdelta_245_direct,
                                        )
                                        skipped.append(phase_id)
                                        _245_skipped_dr = True
                            else:
                                logger.warning(
                                    "NaN in Ausgabe von Phase %s erkannt — Audio-Rollback auf Vor-Phase-Zustand",
                                    phase_id,
                                )
                            if not _245_skipped_dr:
                                # §PROGRESS: Per-Phase Fortschritt (sequenziell)
                                _n_sel = max(len(selected_phases), 1)
                                _idx_ex = len(executed)
                                _phase_pct = _phase_progress_start + int(
                                    (_phase_progress_end - _phase_progress_start) * _idx_ex / _n_sel
                                )
                                if progress_callback is not None:
                                    try:
                                        _phase_label = (self.phase_metadata.get(phase_id) or {}).get(
                                            "name"
                                        ) or phase_id.replace("phase_", "").replace("_", " ").title().lstrip(
                                            "0123456789 "
                                        )
                                        progress_callback(
                                            _phase_pct,
                                            f"{_phase_label} [{phase_id}]",
                                            0.0,
                                        )
                                    except Exception as _cb_exc:
                                        logger.debug(
                                            "Progress-Update übersprungen in %s (Ursache: %s). "
                                            "Lösung: Callback-Signatur prüfen.",
                                            phase_id,
                                            _cb_exc,
                                        )
                                executed.append(phase_id)
                                # §Live-Waveform: Emit updated audio after direct phase
                                if audio_update_callback is not None:
                                    try:
                                        audio_update_callback(current_audio, sample_rate, phase_id)
                                    except Exception as _exc:
                                        logger.debug("audio_update_callback (direct phase) failed: %s", _exc)
                                logger.info("✅ %s: %.2fs", phase_id, result.execution_time_seconds)
                                _record_oom_probe(
                                    "phase_ok",
                                    phase_id,
                                    execution_time_s=round(
                                        float(getattr(result, "execution_time_seconds", 0.0) or 0.0), 3
                                    ),
                                )
                                # §Punkt3 Regressionsprotokoll: RMS nach direkter Phase
                                _rms_after_db = 20.0 * np.log10(float(np.sqrt(np.mean(current_audio**2) + 1e-12)))
                                self._phase_regression_log[phase_id] = round(_rms_after_db - _rms_before_db, 3)
                        else:
                            logger.error("❌ %s failed: %s", phase_id, result.warnings)
                            skipped.append(phase_id)
                            _record_oom_probe("phase_failed", phase_id)
                    # §7 PDV: Post-phase defect verification — Ursache 7 (Primum non nocere).
                    # If a phase measurably WORSENED its primary targeted defect (proxy > +25 %),
                    # roll back to pre-phase audio.  Non-blocking: any exception keeps audio_after.
                    if phase_id in executed:
                        try:
                            from backend.core.phase_defect_verifier import get_phase_defect_verifier as _get_pdv

                            _pdv_ref = _afg_phase_input if _afg_phase_input is not None else _pdv_pre_phase
                            _audio_pdv_result = _get_pdv().check(phase_id, _pdv_ref, current_audio, sample_rate)
                            if _audio_pdv_result is not current_audio:
                                # Rollback triggered: revert executed entry so it's not counted as success.
                                # The phase ran but actively worsened its target — log as skipped.
                                logger.warning(
                                    "§7 PDV: %s rolled back — removed from executed, added to skipped",
                                    phase_id,
                                )
                                try:
                                    executed.remove(phase_id)
                                except ValueError:
                                    pass
                                skipped.append(phase_id)
                            current_audio = _audio_pdv_result
                        except Exception as _pdv_exc:
                            logger.debug("§7 PDV check (non-blocking): %s", _pdv_exc)

                    # §2.51a Mid-pipeline stereo safety: rollback immediately when a single phase
                    # collapses stereo correlation or increases interchannel delay beyond spec.
                    if phase_id in executed and _afg_phase_input is not None:
                        try:
                            _phase_stereo_guard = _evaluate_stereo_safety_guard(
                                original_audio=_afg_phase_input,
                                restored_audio=current_audio,
                                sample_rate=sample_rate,
                                material_key=str(getattr(material_type, "value", material_type) or ""),
                            )
                            _warn_reasons = set(_phase_stereo_guard.get("warning_reasons", []))
                            _must_rollback_stereo = bool(_phase_stereo_guard.get("hard_fail", False)) or (
                                phase_id
                                in {
                                    "phase_17_mastering_polish",
                                    "phase_23_spectral_repair",
                                    "phase_42_vocal_enhancement",
                                }
                                and "interchannel_correlation_drop" in _warn_reasons
                            )
                            if _must_rollback_stereo:
                                logger.warning(
                                    "§2.51a Mid-pipeline stereo rollback after %s: reason=%s hard=%s delta=%s",
                                    phase_id,
                                    _phase_stereo_guard.get("reason", "unknown"),
                                    _phase_stereo_guard.get("hard_fail", False),
                                    _phase_stereo_guard.get("delta", {}),
                                )
                                current_audio = np.clip(_afg_phase_input.copy(), -1.0, 1.0)
                                try:
                                    executed.remove(phase_id)
                                except ValueError:
                                    pass
                                skipped.append(phase_id)
                        except Exception as _stg_exc:
                            logger.debug("§2.51a Mid-pipeline stereo guard failed: %s", _stg_exc)

                    # §2.61 Output-Length-Guard — harter Crop + Log; kein stilles Zero-Padding
                    if hasattr(current_audio, "shape") and abs(len(current_audio) - _phase_input_len_2_61) > 64:
                        logger.error(
                            "§2.61 length_mismatch phase=%s delta=%d — hard crop",
                            phase_id,
                            len(current_audio) - _phase_input_len_2_61,
                        )
                        current_audio = current_audio[:_phase_input_len_2_61]
                        if "length_corrections" not in self._metadata:
                            self._metadata["length_corrections"] = []
                        self._metadata["length_corrections"].append(phase_id)

                    # §0d Carrier-Recovery-Checkpoint: nach jeder erfolgreichen Carrier-Phase
                    # den Audio-Snapshot speichern (letzter Carrier-Checkpoint = best_carrier_checkpoint)
                    if phase_id in executed and any(phase_id.startswith(cp) for cp in _CARRIER_PHASE_PREFIXES_0d):
                        _best_carrier_checkpoint = current_audio.copy()
                        _last_carrier_phase_id = phase_id

                except MemoryError:
                    # OOM-Notfall-Export: Teilergebnis zurückgeben statt Totalverlust.
                    # current_audio enthält den Stand nach der letzten erfolgreichen Phase.
                    logger.error(
                        "❌ OOM in %s — Notfall-Export: %d/%d Phasen abgeschlossen. Teilergebnis wird zurückgegeben.",
                        phase_id,
                        len(executed),
                        len(selected_phases),
                    )
                    _record_oom_probe("phase_oom", phase_id)
                    # Sofort Speicher freigeben für den Export-Pfad
                    gc.collect()
                    try:
                        import ctypes as _ctypes_oom

                        _ctypes_oom.CDLL("libc.so.6").malloc_trim(0)
                    except Exception as _exc:
                        logger.debug("malloc_trim (OOM handler) failed: %s", _exc)
                    skipped.extend(p for p in selected_phases if p not in executed and p != phase_id)
                    skipped.append(phase_id)
                    # §2.39 OOM-Recovery-Checkpoint: Pipeline-Stand auf Disk persistieren,
                    # damit der nächste Aurik-Start die Restaurierung fortsetzen kann.
                    try:
                        from backend.core.recovery_checkpoint import save_checkpoint as _save_oom_cp

                        _rc = getattr(self, "_recovery_ctx", {})
                        _remaining = [p for p in selected_phases if p not in executed]
                        _save_oom_cp(
                            input_path=_rc.get("input_path", ""),
                            output_path=_rc.get("output_path", ""),
                            current_audio=current_audio,
                            sample_rate=sample_rate,
                            phases_executed=list(executed),
                            phases_remaining=_remaining,
                            failure_phase=phase_id,
                            mode=_rc.get("mode", "quality"),
                            defect_result=_rc.get("defect_result"),
                            era_decade=_rc.get("era_decade"),
                            restorability_score=_rc.get("restorability_score"),
                            quality_estimate=0.0,
                            musical_goals=dict(_pmgg_scores_curr) if _pmgg_scores_curr else None,
                        )
                    except Exception as _cp_exc:
                        logger.error("OOM-Recovery-Checkpoint fehlgeschlagen: %s", _cp_exc)
                    break
                except Exception as e:
                    logger.error("❌ %s exception: %s", phase_id, e)
                    skipped.append(phase_id)
                    _record_oom_probe("phase_exception", phase_id, error=f"{type(e).__name__}:{e}")
                if self.performance_guard:
                    self.performance_guard.end_phase(phase_id, phase_start)
                # §Wall-Time-Budget: Non-exempt Phasen-Laufzeit kumulieren.
                # Exempt-Phasen (§6.2a) werden hier NICHT gezählt — sie haben eigene
                # interne Guards und dürfen das Enhancement-Budget nicht verbrauchen.
                # _wall_phase_start (time.monotonic()) statt phase_start (perf_counter/time.time())
                # um den perf_counter vs time.time() Mismatch-Bug zu vermeiden.
                if phase_id not in _WALL_BUDGET_EXEMPT_PHASES:
                    _last_phase_non_exempt_s = time.monotonic() - _wall_phase_start
                    _pipeline_non_exempt_elapsed_s += _last_phase_non_exempt_s
                else:
                    _last_phase_non_exempt_s = 0.0
                # OOM-Guard: GC nach JEDER Phase — STFT-Matrizen (je ~173 MB)
                # und PMGG-Retries akkumulieren Speicher schneller als gc.collect
                # alle 5 Phasen abräumen kann (OOM-Crash bei 225s Tape, 24.03.2026).
                gc.collect()
                # malloc_trim: Gebe freigegebenen Heap-Speicher sofort ans OS zurück.
                # Ohne trim hält glibc freigegebene Seiten im Prozess-Heap — sichtbar
                # als hoher RSS obwohl Python-Objekte bereits freigegeben wurden.
                try:
                    import ctypes as _ctypes_phase

                    _libc = _ctypes_phase.CDLL("libc.so.6")
                    _libc.malloc_trim(0)
                except Exception as _exc:
                    logger.debug("malloc_trim (post-phase GC) failed: %s", _exc)
                # RAM-Notbremse: bei < 4 GB verfügbar ODER > 80% belegt ODER Swap-Thrashing
                # → Plugin-Eviction erzwingen. systemd-oomd killt bei Memory-Pressure > 50%.
                try:
                    import psutil as _psutil_phase

                    _vm_phase = _psutil_phase.virtual_memory()
                    _avail_gb_phase = _vm_phase.available / (1024**3)
                    _ram_pct_phase = _vm_phase.percent
                    # Swap-Thrashing-Check: hoher Swap + niedriger RAM = System kurz vor Crash
                    _swap_thrashing = False
                    try:
                        _swap = _psutil_phase.swap_memory()
                        _swap_thrashing = (
                            _swap.percent > 30.0 and (_vm_phase.available / max(_vm_phase.total, 1)) < 0.15
                        )
                    except Exception as _exc:
                        logger.debug("psutil swap_memory (post-phase) failed: %s", _exc)
                    if _avail_gb_phase < 4.0 or _ram_pct_phase > 80.0 or _swap_thrashing:
                        _reason = (
                            "Swap-Thrashing"
                            if _swap_thrashing
                            else f"{_avail_gb_phase:.1f} GB frei / {_ram_pct_phase:.0f} %"
                        )
                        _record_oom_probe(
                            "post_phase_pressure",
                            phase_id,
                            available_gb=round(float(_avail_gb_phase), 3),
                            ram_percent=float(_ram_pct_phase),
                            reason=_reason,
                        )
                        logger.warning(
                            "⚠️ OOM-Guard nach %s: %s — erzwinge Plugin-Eviction + GC",
                            phase_id,
                            _reason,
                        )
                        try:
                            from backend.core.plugin_lifecycle_manager import evict_stale_plugins

                            evict_stale_plugins(required_mb=4096)
                        except Exception as _exc:
                            logger.warning("evict_stale_plugins (post-phase pressure) failed: %s", _exc)
                        gc.collect()
                except ImportError:
                    logger.debug("psutil not available — post-phase RAM guard skipped")
                # §2.16 TQC mid-pipeline: nach zeitmodifizierenden Phasen auf Kohärenzverlust prüfen.
                # WICHTIG: Rollback NUR wenn die Phase die TQC-Metrik VERSCHLECHTERT hat
                # (max_span gestiegen ≥ 15%).  Ein absolutes Scheitern am Threshold genügt
                # NICHT — Musikdateien mit natürlicher Dynamik überschreiten 0.30 immer;
                # der Rollback wäre sonst ein blinder No-Op für phase_12/31.
                if _tqc_snap is not None and phase_id in executed:
                    _tqc_dur_s = (
                        current_audio.shape[-1] / sample_rate
                        if current_audio.ndim == 1
                        else current_audio.shape[1] / sample_rate
                    )
                    if _tqc_dur_s >= 25.0:  # MIN_FILE_DURATION_S aus §2.16
                        try:
                            from backend.core.temporal_quality_coherence import measure_temporal_coherence

                            _mid_tqc = measure_temporal_coherence(current_audio, sample_rate)
                            # Rollback-Bedingung: Phase hat TQC um ≥ 15 % verschlechtert
                            # UND der absolute Wert liegt über dem Hard-Cap von 3.0
                            # (extrem zerbrochener Rhythmus — kaum natürliche Musik).
                            _tqc_degraded = (
                                _tqc_snap_span >= 0.0  # Baseline gemessen
                                and _mid_tqc.max_span > _tqc_snap_span * 1.15  # ≥15 % Regression
                                and _mid_tqc.max_span > 0.30  # überhaupt auffällig
                            )
                            _tqc_catastrophic = _mid_tqc.max_span > 3.0 and _mid_tqc.sigma > 0.80
                            if _tqc_degraded or _tqc_catastrophic:
                                logger.warning(
                                    "⚠️ TQC mid-pipeline nach %s: max_span %.3f→%.3f"
                                    " σ=%.3f → Rollback (Phase hat TQC verschlechtert)",
                                    phase_id,
                                    _tqc_snap_span,
                                    _mid_tqc.max_span,
                                    _mid_tqc.sigma,
                                )
                                current_audio = _tqc_snap  # Rollback auf Audio vor Phase
                            else:
                                logger.debug(
                                    "TQC mid-pipeline nach %s: max_span=%.3f"
                                    " σ=%.3f (baseline=%.3f) — OK, kein Rollback",
                                    phase_id,
                                    _mid_tqc.max_span,
                                    _mid_tqc.sigma,
                                    _tqc_snap_span,
                                )
                        except Exception as _mtqc_exc:
                            logger.debug("TQC mid-pipeline nicht verfügbar: %s", _mtqc_exc)
                # §2.48 [RELEASE_MUST] Kumulative-Phasen-Interaktions-Guard — after each phase
                _cig_phase_rolled_back: bool = False  # §2.45a-VII: gate cumulative makeup guard
                if (
                    _interaction_guard is not None
                    and _interaction_guard_state is not None
                    and phase_id in executed
                    and _pmgg_scores_curr is not None
                ):
                    try:
                        _ig_audio, _ig_rolled_back = _interaction_guard.check_after_phase(
                            _interaction_guard_state,
                            phase_id,
                            current_audio,
                            _pmgg_scores_curr,
                            sample_rate,
                        )
                        if _ig_rolled_back:
                            current_audio = np.clip(_ig_audio, -1.0, 1.0)
                            logger.warning("§2.48 Rollback applied after %s", phase_id)
                            self._register_phase_goal_conflict_event(phase_id, "interaction_guard_rollback")
                            # §2.45a-VII CIG-Rollback: Phase war effektiv nicht wirksam —
                            # Cumulative Guard darf keinen Makeup-Gain anwenden und
                            # darf _allow_positive_makeup_gain nicht ändern (Pegelexplosion-Guard).
                            _cig_phase_rolled_back = True
                            # §Wall-Time-Budget Refund (CIG-Rollback): analog to AFG-Rollback.
                            # A rolled-back phase had zero net effect — charging its runtime
                            # against the wall budget prevents all later Enhancement phases from
                            # running (observed: phase_03 on vinyl burns 2000 s, then 20+ phases
                            # are skipped because wall budget is exhausted). Root cause: CIG had
                            # no refund path while AFG always refunded. Now symmetric.
                            if _last_phase_non_exempt_s > 0.0 and phase_id not in _WALL_BUDGET_EXEMPT_PHASES:
                                _pipeline_non_exempt_elapsed_s = max(
                                    0.0,
                                    _pipeline_non_exempt_elapsed_s - _last_phase_non_exempt_s,
                                )
                                logger.info(
                                    "§Wall-Time-Budget Refund (CIG-Rollback %s): %.0f s zurückgebucht "
                                    "(non-exempt now %.0f s / budget %.0f s)",
                                    phase_id,
                                    _last_phase_non_exempt_s,
                                    _pipeline_non_exempt_elapsed_s,
                                    _pipeline_wall_budget,
                                )
                                _last_phase_non_exempt_s = 0.0
                        if _interaction_guard_state.should_stop:
                            logger.warning("§2.48 Pipeline stop — exporting best checkpoint")
                            self._register_phase_goal_conflict_event(phase_id, "interaction_guard_pipeline_stop")
                            skipped.extend(p for p in selected_phases if p not in executed)
                            break
                    except Exception as _ig_exc:
                        logger.debug("§2.48 InteractionGuard check failed: %s", _ig_exc)

                # §0c Graceful-Stop: Watchdog hat Zeitlimit signalisiert —
                # bestes bisher erreichtes Ergebnis exportieren, kein Kill.
                if graceful_stop_event is not None and graceful_stop_event.is_set():
                    logger.warning(
                        "§0c Graceful-Stop: Zeitlimit — export best checkpoint after %s "
                        "(%d Phasen verbleibend, Pipeline intakt)",
                        phase_id,
                        len([p for p in selected_phases if p not in executed]),
                    )
                    skipped.extend(p for p in selected_phases if p not in executed)
                    break

                # §2.45a [RELEASE_MUST] Mid-Pipeline Cumulative Loudness-Drift-Guard
                # Per-phase guards limit each phase's drop vs its own input, but compound
                # effects accumulate unchecked: 8 phases × 2.5 dB = 20 dB total collapse.
                # This guard checks cumulative RMS drop from PIPELINE START after each phase
                # and applies soft-limited makeup gain when the drift exceeds material-adaptive tolerance.
                #
                # §2.45a-VI: After HPF/Notch phases (phase_02, phase_05) the cumulative reference
                # is reset to current_audio so the guard does not compensate intentional
                # energy removal (sub-bass / hum) with makeup gain → prevents Pegelexplosion.
                if _cum_rms_reference_audio is not None and phase_id in executed and not _cig_phase_rolled_back:
                    _next_allow_makeup, _authority_reason = self._update_positive_makeup_authority(
                        phase_id,
                        _allow_positive_makeup_gain,
                    )
                    if _authority_reason is not None:
                        _allow_positive_makeup_gain = _next_allow_makeup
                        _makeup_authority_reason = _authority_reason
                        logger.debug(
                            "§2.45a Single-Gain-Authority update after %s: allow_positive_makeup=%s (%s)",
                            phase_id,
                            _allow_positive_makeup_gain,
                            _makeup_authority_reason,
                        )
                    if phase_id in _HPF_NOTCH_CUM_RESET_PHASES:
                        _cum_rms_reference_audio = current_audio.copy()
                        logger.debug("§2.45a-VI cum-guard reference reset after HPF/Notch phase %s", phase_id)
                if _cum_rms_reference_audio is not None and phase_id in executed and not _cig_phase_rolled_back:
                    try:
                        _cum_rms_pipeline_start = _rms_dbfs_gated(_cum_rms_reference_audio)
                        _cum_rms_current = _rms_dbfs_gated(current_audio)
                        _cum_total_drop = _cum_rms_pipeline_start - _cum_rms_current
                        # Material-adaptive cumulative tolerance (§2.54):
                        # Heavily degraded analog material needs more subtraktive processing,
                        # so allow more cumulative drop. But still enforce a hard ceiling.
                        _cum_max_drop_db = {
                            "shellac": 3.5,
                            "wax_cylinder": 3.5,
                            "wire_recording": 4.0,
                            "vinyl": 4.5,
                            "lacquer_disc": 4.0,
                            "reel_tape": 5.0,
                            "tape": 5.0,
                            "cassette": 5.0,
                            "cd_digital": 3.0,
                            "dat": 3.0,
                            "mp3_low": 3.5,
                            "mp3_high": 3.0,
                            "aac": 3.0,
                            "streaming": 3.0,
                        }.get(str(getattr(material_type, "value", material_type)).lower(), 4.0)
                        if _cum_total_drop > _cum_max_drop_db:
                            _cum_target = _cum_rms_pipeline_start - _cum_max_drop_db
                            _cum_needed = max(0.0, _cum_target - _cum_rms_current)
                            if _cum_needed > 0.01:
                                _cum_g = float(10.0 ** (_cum_needed / 20.0))
                                _cum_g = min(_cum_g, 6.0)  # max +15.6 dB safety cap
                                if _cum_g > 1.0005:
                                    if not _allow_positive_makeup_gain:
                                        logger.info(
                                            "§2.45a MID-PIPELINE cumulative guard after %s: "
                                            "makeup skipped by Single-Gain-Authority (%s)",
                                            phase_id,
                                            _makeup_authority_reason,
                                        )
                                    else:
                                        # Envelope-aware gain: only amplify musical frames.
                                        # reference_for_gate=_cum_rms_reference_audio: use pipeline-start
                                        # noise floor for P5 gate — prevents vinyl-noise amplification.
                                        current_audio = self._musical_gain_envelope(
                                            current_audio,
                                            _cum_g,
                                            gate_dbfs=-36.0,
                                            sr=sample_rate,
                                            reference_for_gate=_cum_rms_reference_audio,
                                            material_key=str(getattr(material_type, "value", material_type)).lower(),
                                        )
                                        # Soft-limiter only if actual clipping risk
                                        # §v9.10.125: 99.9th-percentile — impulse artefact guard
                                        _cum_peak = float(np.percentile(np.abs(current_audio), 99.9))
                                        if _cum_peak > 0.98:
                                            _cum_abs = np.abs(current_audio)
                                            _cum_over = _cum_abs > 0.92
                                            if np.any(_cum_over):
                                                _cum_sign = np.sign(current_audio)
                                                _cum_soft = 0.92 + 0.08 * np.tanh((_cum_abs - 0.92) / 0.08)
                                                current_audio = np.where(
                                                    _cum_over, _cum_sign * _cum_soft, current_audio
                                                )
                                        current_audio = np.clip(current_audio, -1.0, 1.0)
                                        logger.info(
                                            "§2.45a MID-PIPELINE cumulative guard after %s: "
                                            "total_drop=%.2f dB (gated) > %.2f dB limit"
                                            " → envelope-aware makeup +%.2f dB",
                                            phase_id,
                                            _cum_total_drop,
                                            _cum_max_drop_db,
                                            float(20.0 * np.log10(max(_cum_g, 1e-9))),
                                        )
                    except Exception as _cum_mid_exc:
                        logger.debug("§2.45a mid-pipeline cumulative guard failed (non-blocking): %s", _cum_mid_exc)

                # §4.1b [RELEASE_MUST] Psychoakustische Lautheitsmessung (Zwicker/Fastl)
                # After broadband subtraktive phases: compare perceived loudness (sone)
                # before vs after. ΔN > 2.0 sone → Dry/Wet rescue (not hard rollback).
                _ZWICKER_SUBTRAKTIVE_PHASES: frozenset = frozenset(
                    {
                        "phase_03",
                        # phase_05 (HPF) und phase_02 (Notch) bewusst NICHT in dieser Liste:
                        # HPF entfernt gezielt Subbass → Zwicker ΔN > 2.0 sone ist INTENTIONAL.
                        # Zwicker-Rescue würde bis zu 70 % des Vor-HPF-Signals zurückmischen,
                        # d.h. das Rumpeln würde teilweise wiederhergestellt → kontraproduktiv.
                        # §2.45a-VI: HPF-Energieverlust ist beabsichtigte Carrier-Inversion,
                        # nicht ein Loudness-Kollaps der korrigiert werden muss.
                        "phase_18",
                        "phase_20",
                        "phase_28",
                        "phase_29",
                        "phase_35",
                        "phase_49",
                    }
                )
                _zwicker_phase_prefix = "_".join(str(phase_id).split("_")[:2])
                if (
                    _afg_phase_input is not None
                    and phase_id in executed
                    and _zwicker_phase_prefix in _ZWICKER_SUBTRAKTIVE_PHASES
                ):
                    try:
                        from dsp.psychoacoustics import compute_loudness_delta_sone

                        _zw_delta, _zw_before, _zw_after = compute_loudness_delta_sone(
                            _afg_phase_input, current_audio, sample_rate
                        )
                        _zw_abs_delta = abs(_zw_delta)
                        if _zw_abs_delta > 2.0:
                            # FAIL → Dry/Wet rescue: blend back toward dry
                            _zw_wet_ratio = max(0.3, 2.0 / max(_zw_abs_delta, 0.01))
                            current_audio = np.clip(
                                _afg_phase_input * (1.0 - _zw_wet_ratio) + current_audio * _zw_wet_ratio,
                                -1.0,
                                1.0,
                            ).astype(np.float32)
                            logger.warning(
                                "§4.1b Zwicker loudness guard after %s: ΔN=%.2f sone "
                                "(before=%.2f, after=%.2f) > 2.0 → Dry/Wet rescue "
                                "(wet_ratio=%.2f)",
                                phase_id,
                                _zw_delta,
                                _zw_before,
                                _zw_after,
                                _zw_wet_ratio,
                            )
                        elif _zw_abs_delta > 1.0:
                            logger.info(
                                "§4.1b Zwicker loudness WARNING after %s: ΔN=%.2f sone (before=%.2f, after=%.2f)",
                                phase_id,
                                _zw_delta,
                                _zw_before,
                                _zw_after,
                            )
                        elif _zw_abs_delta > 0.5:
                            logger.debug(
                                "§4.1b Zwicker loudness INFO after %s: ΔN=%.2f sone",
                                phase_id,
                                _zw_delta,
                            )
                        # Telemetry
                        if hasattr(self, "_phase_metadata_accumulator"):
                            self._phase_metadata_accumulator[phase_id] = {
                                **(self._phase_metadata_accumulator.get(phase_id) or {}),
                                "loudness_delta_sone": round(float(_zw_delta), 3),
                                "loudness_before_sone": round(float(_zw_before), 3),
                                "loudness_after_sone": round(float(_zw_after), 3),
                            }
                    except Exception as _zw_exc:
                        logger.debug("§4.1b Zwicker loudness guard non-blocking error: %s", _zw_exc)

                # §2.49 [RELEASE_MUST] Artefakt-Freiheits-Gate — per-phase artifact check
                # §0/§2.46 [RELEASE_MUST] HF-Halluzinations-Guard — System-Wide
                # Prevents additive/reconstruction phases synthesising spectral content
                # above the material's credible bandwidth ceiling (§0 Primum non nocere).
                # Extends the BW cap from phase_55 to all ADDITIVE phases system-wide.
                _HF_ADDITIVE_PREFIXES: frozenset = frozenset(
                    {
                        "phase_06",
                        "phase_07",
                        "phase_21",
                        "phase_22",
                        "phase_23",
                        "phase_38",
                        "phase_39",
                        "phase_50",
                        "phase_55",
                        "phase_56",
                    }
                )
                _hf_phase_prefix = "_".join(str(phase_id).split("_")[:2])
                if _afg_phase_input is not None and phase_id in executed and _hf_phase_prefix in _HF_ADDITIVE_PREFIXES:
                    try:
                        from backend.core.hf_hallucination_guard import check_hf_hallucination

                        _hf_cert = float(np.clip(getattr(self, "_global_conservative_scalar", 1.0), 0.78, 1.0))
                        _hf_ok, _hf_wet_cap, _hf_cap_hz, _hf_delta = check_hf_hallucination(
                            _afg_phase_input,
                            current_audio,
                            sample_rate,
                            _mat_str,
                            recovery_certainty_scalar=_hf_cert,
                        )
                        if not _hf_ok:
                            # §0 Rescue: blend back toward dry to cap HF hallucination
                            current_audio = np.clip(
                                _afg_phase_input * (1.0 - _hf_wet_cap) + current_audio * _hf_wet_cap,
                                -1.0,
                                1.0,
                            ).astype(np.float32)
                            logger.warning(
                                "§0 HF-Halluzinations-Guard nach %s: ΔHF=%.3f "
                                "(cap=%.0f Hz) → Dry/Wet-Rescue (wet_cap=%.2f)",
                                phase_id,
                                _hf_delta,
                                _hf_cap_hz,
                                _hf_wet_cap,
                            )
                            if hasattr(self, "_phase_metadata_accumulator"):
                                self._phase_metadata_accumulator[phase_id] = {
                                    **(self._phase_metadata_accumulator.get(phase_id) or {}),
                                    "hf_hallucination_detected": True,
                                    "hf_delta_ratio": round(float(_hf_delta), 4),
                                    "hf_cap_hz": float(_hf_cap_hz),
                                    "hf_wet_cap_applied": round(float(_hf_wet_cap), 3),
                                }
                            self._register_phase_goal_conflict_event(
                                phase_id,
                                "hf_hallucination_rescue",
                                {
                                    "hf_delta_ratio": round(float(_hf_delta), 4),
                                    "hf_cap_hz": float(_hf_cap_hz),
                                    "hf_wet_cap_applied": round(float(_hf_wet_cap), 3),
                                },
                            )
                    except Exception as _hf_exc:
                        logger.debug("§0 HF-Halluzinations-Guard non-blocking error: %s", _hf_exc)

                # §2.49 [RELEASE_MUST] Artefakt-Freiheits-Gate — per-phase artifact check
                # Uses _afg_phase_input (audio before THIS phase) not _afg_pre_pipeline_audio (pipeline start),
                # so only the delta introduced by this single phase is measured. This prevents false rollbacks
                # on enhancement phases whose intentional signal changes would exceed cumulative thresholds.
                if _artifact_gate is not None and _afg_phase_input is not None and phase_id in executed:
                    try:
                        _afg_result = _artifact_gate.evaluate(
                            _afg_phase_input,
                            current_audio,
                            sample_rate,
                            _mat_str,
                            phase_id,
                            goal_weights=getattr(self, "_song_goal_weights", None),
                            restorability_score=float(getattr(self, "_last_restorability_score", 65.0)),
                        )
                        if _afg_result.artifact_freedom < 0.95:
                            _dr = _afg_result.detail_report
                            logger.warning(
                                "§2.49 artifact_freedom=%.3f < 0.95 after %s (%d artifacts) "
                                "[PE:%d PC:%d MN:%d SH:%d MR:%d wsum=%.3f] → rollback",
                                _afg_result.artifact_freedom,
                                phase_id,
                                len(_afg_result.detected_artifacts),
                                _dr.get("n_pre_echo", 0),
                                _dr.get("n_phase_cancellation", 0),
                                _dr.get("n_musical_noise", 0),
                                _dr.get("n_spectral_holes", 0),
                                _dr.get("n_metallic_ringing", 0),
                                _dr.get("weighted_artifact_sum", 0.0),
                            )
                            self._register_phase_goal_conflict_event(
                                phase_id,
                                "artifact_freedom_rollback",
                                {
                                    "artifact_freedom": round(float(_afg_result.artifact_freedom), 4),
                                    "weighted_artifact_sum": round(float(_dr.get("weighted_artifact_sum", 0.0)), 4),
                                    "n_detected_artifacts": int(len(_afg_result.detected_artifacts)),
                                    "n_pre_echo": int(_dr.get("n_pre_echo", 0)),
                                    "n_phase_cancellation": int(_dr.get("n_phase_cancellation", 0)),
                                    "n_musical_noise": int(_dr.get("n_musical_noise", 0)),
                                    "n_spectral_holes": int(_dr.get("n_spectral_holes", 0)),
                                    "n_metallic_ringing": int(_dr.get("n_metallic_ringing", 0)),
                                },
                            )
                            # Roll back to audio state just before this phase ran
                            current_audio = np.clip(_afg_phase_input.copy(), -1.0, 1.0)
                            # §Wall-Time-Budget Refund: AFG-rolled-back phase should not
                            # consume budget for subsequent phases — the audio change is
                            # undone, so treating the time as spent is unfair to remaining phases.
                            if _last_phase_non_exempt_s > 0.0:
                                _pipeline_non_exempt_elapsed_s = max(
                                    0.0,
                                    _pipeline_non_exempt_elapsed_s - _last_phase_non_exempt_s,
                                )
                                logger.info(
                                    "§Wall-Time-Budget Refund (AFG-Rollback %s): %.0f s zurückgebucht "
                                    "(non-exempt now %.0f s / budget %.0f s)",
                                    phase_id,
                                    _last_phase_non_exempt_s,
                                    _pipeline_non_exempt_elapsed_s,
                                    _pipeline_wall_budget,
                                )
                        else:
                            # Update best artifact-free checkpoint
                            _afg_best_clean_checkpoint = current_audio.copy()
                            _afg_best_clean_phase = phase_id
                            # Track minimum for final _artifact_freedom_score (Bug A fix)
                            _min_per_phase_afg_score = min(_min_per_phase_afg_score, _afg_result.artifact_freedom)
                        _ntx_mat_key = str(getattr(material_type, "value", material_type) or "unknown").lower()
                        # §2.46b: Chain-adaptive NTX threshold — use the most permissive
                        # threshold across the full transfer chain.  A vinyl source encoded as
                        # MP3 has mp3_low noise-texture characteristics (15 dB/oct), not only
                        # vinyl's (8 dB/oct).  Using only the primary material would cause false
                        # rollbacks for mp3_low transfers of vinyl/tape sources.
                        _ntx_chain_keys = (
                            self._extract_transfer_chain_from_forensics(
                                (getattr(self, "_strict_autosetup_policy", {}) or {}).get("transfer_chain")
                            )
                            or []
                        )
                        _ntx_threshold = _resolve_noise_texture_rollback_threshold(
                            _ntx_mat_key,
                            _ntx_chain_keys,
                        )
                        # Noise texture deviation uses materialadaptive threshold (§2.49 / §8.5A)
                        if _afg_result.noise_texture_deviation_db_oct > _ntx_threshold:
                            logger.warning(
                                "§2.49 Noise texture deviation %.1f dB/oct > %.1f after %s (%s) → rollback",
                                _afg_result.noise_texture_deviation_db_oct,
                                _ntx_threshold,
                                phase_id,
                                _ntx_mat_key,
                            )
                            self._register_phase_goal_conflict_event(
                                phase_id,
                                "noise_texture_rollback",
                                {
                                    "noise_texture_deviation_db_oct": round(
                                        float(_afg_result.noise_texture_deviation_db_oct),
                                        4,
                                    ),
                                    "noise_texture_threshold_db_oct": round(float(_ntx_threshold), 4),
                                    "material_key": _ntx_mat_key,
                                    "transfer_chain": list(_ntx_chain_keys),
                                },
                            )
                            current_audio = np.clip(_afg_phase_input.copy(), -1.0, 1.0)
                            # §Wall-Time-Budget Refund: Noise-texture rollback analog zu AFG-Rollback
                            if _last_phase_non_exempt_s > 0.0:
                                _pipeline_non_exempt_elapsed_s = max(
                                    0.0,
                                    _pipeline_non_exempt_elapsed_s - _last_phase_non_exempt_s,
                                )
                                logger.info(
                                    "§Wall-Time-Budget Refund (NTX-Rollback %s): %.0f s zurückgebucht "
                                    "(non-exempt now %.0f s / budget %.0f s)",
                                    phase_id,
                                    _last_phase_non_exempt_s,
                                    _pipeline_non_exempt_elapsed_s,
                                    _pipeline_wall_budget,
                                )
                    except Exception as _afg_exc:
                        logger.debug("§2.49 ArtifactFreedomGate check failed: %s", _afg_exc, exc_info=True)

                # Kontinuierliche Produktions-Nachbesserung (closed loop):
                # nach JEDER akzeptierten Phase minimale psychoakustische Nachregelung
                # der verbleibenden Family-Scalars.
                if _pmgg_gate is not None and _pmgg_scores_curr and getattr(self, "_song_calibration_profile", None):
                    try:
                        _joy_refined = self._continuous_joy_refinement_step(
                            _pmgg_scores_curr,
                            self._song_calibration_profile,
                            phase_id,
                            len(executed),
                            len(selected_phases),
                            artifact_floor=_min_per_phase_afg_score,
                        )
                        if _joy_refined is not None:
                            self._song_calibration_profile = _joy_refined
                    except Exception as _joy_exc:
                        logger.debug("Joy closed-loop refinement failed (non-critical): %s", _joy_exc)

                # §2.31a Mid-pipeline calibration: refine family_scalars at ~33 % and ~66 %
                # progress using already-computed PMGG scores (zero additional DSP cost).
                if _pmgg_gate is not None and _pmgg_scores_curr and getattr(self, "_song_calibration_profile", None):
                    try:
                        _mid_cal_pct = len(executed) / max(len(selected_phases), 1)
                        if not _mid_cal_33pct_done and _mid_cal_pct >= 0.33:
                            _mid_cal_33pct_done = True
                            _refined = self._mid_pipeline_calibration_step(
                                _pmgg_scores_curr,
                                self._song_calibration_profile,
                                "33pct",
                                len(executed),
                                len(selected_phases),
                                artifact_floor=_min_per_phase_afg_score,
                            )
                            if _refined is not None:
                                self._song_calibration_profile = _refined
                        elif not _mid_cal_66pct_done and _mid_cal_pct >= 0.66:
                            _mid_cal_66pct_done = True
                            _refined = self._mid_pipeline_calibration_step(
                                _pmgg_scores_curr,
                                self._song_calibration_profile,
                                "66pct",
                                len(executed),
                                len(selected_phases),
                                artifact_floor=_min_per_phase_afg_score,
                            )
                            if _refined is not None:
                                self._song_calibration_profile = _refined
                    except Exception as _midcal_exc:
                        logger.debug("§2.31a MidCalibrate fehlgeschlagen (ignoriert): %s", _midcal_exc)

                # §2.47 Phase-53-Semantic-Feedback: CLAP/BEATs genre_hint → _restoration_context.
                # When Phase 53 succeeds, its ML-derived genre_hint is more accurate than the
                # DSP-only GenreClassifier (CLAP = text-audio aligned, zero-shot, 512-dim).
                # Update genre_label in _restoration_context only when current label is
                # "Unbekannt" or CLAP confidence exceeds 0.55 (clearer signal than DSP heuristic).
                # Advisory-only: never overwrites an explicit Schlager-Classifier result.
                if phase_id == "phase_53_semantic_audio" and phase_id in executed:
                    try:
                        _s53_meta = result.metadata if hasattr(result, "metadata") else {}
                        _s53_genre = str(_s53_meta.get("genre_hint", "") or "")
                        _s53_src = str(_s53_meta.get("genre_hint_source", "dsp"))
                        _s53_conf = float(_s53_meta.get("genre_hint_confidence", 0.0))
                        _s53_current_label = str(self._restoration_context.get("genre_label", "Unbekannt"))
                        _s53_is_schlager = bool(self._restoration_context.get("is_schlager", False))
                        # Only override when CLAP/BEATs genre is more decisive.
                        _s53_override = (
                            not _s53_is_schlager
                            and _s53_genre not in ("", "Unbekannt")
                            and (
                                _s53_current_label in ("Unbekannt", "unknown", "")
                                or (_s53_src == "clap" and _s53_conf >= 0.55)
                            )
                        )
                        if _s53_override:
                            self._restoration_context["genre_label"] = _s53_genre
                            self._restoration_context["genre_hint_source"] = _s53_src
                            self._restoration_context["genre_hint_confidence"] = _s53_conf
                            # Propagate CLAP tag-lists for downstream consumers (FeedbackChain, etc.)
                            _s53_clap_genres = _s53_meta.get("clap_top_genres", [])
                            _s53_beats_tags = _s53_meta.get("beats_top_tags", [])
                            self._restoration_context["clap_top_genres"] = _s53_clap_genres
                            self._restoration_context["beats_top_tags"] = _s53_beats_tags
                            logger.info(
                                "§2.47 Phase-53-Semantic-Feedback: genre_label '%s' → '%s' (source=%s, conf=%.2f)",
                                _s53_current_label,
                                _s53_genre,
                                _s53_src,
                                _s53_conf,
                            )
                    except Exception as _s53_exc:
                        logger.debug("Phase-53-Semantic-Feedback non-blocking: %s", _s53_exc)

                # §Hebel-3 PhaseConductor: inter-phase state measurement + wetness advisory.
                # Non-blocking: any exception → skip silently (never blocks pipeline).
                # Advisory only: recommendation modulates _combined_strength for the NEXT
                # phase via self._conductor_strength_hint dict, read by _profiled_phase_call.
                if _conductor is not None and phase_id in executed:
                    try:
                        _conductor_state = _conductor.measure_state(current_audio, sample_rate, phase_id)
                        # Look ahead: pre-compute recommendation for next phase
                        _next_idx = len(executed)
                        if _next_idx < len(selected_phases):
                            _next_pid = selected_phases[_next_idx]
                            _mat_str_cond = (
                                material_type.value if hasattr(material_type, "value") else str(material_type)
                            )
                            _cond_rec = _conductor.recommend(
                                _next_pid,
                                _conductor_state,
                                _mat_str_cond,
                                goal_weights=getattr(self, "_song_goal_weights", None),
                            )
                            if not hasattr(self, "_conductor_strength_hints"):
                                self._conductor_strength_hints = {}
                            if _cond_rec.skip_recommended:
                                logger.debug("§Hebel-3 Conductor: %s", _cond_rec.skip_reason)
                                # Advisory skip only — do not force skip; PMGG still decides.
                            else:
                                self._conductor_strength_hints[_next_pid] = _cond_rec.recommended_strength
                                if abs(_cond_rec.recommended_strength - 1.0) > 0.05:
                                    logger.debug(
                                        "§Hebel-3 Conductor → %s: recommended_strength=%.2f (conf=%.2f)",
                                        _next_pid,
                                        _cond_rec.recommended_strength,
                                        _cond_rec.confidence,
                                    )
                    except Exception as _cond_exc:
                        logger.debug("§Hebel-3 PhaseConductor Fehler (non-critical): %s", _cond_exc)

                if phase_id in executed:
                    try:
                        _accepted_net_gain = self._accepted_phase_net_gain(_pdv_pre_phase, current_audio, sample_rate)
                        self._record_phase_budget_gain(phase_id, _mat_key_budget, _accepted_net_gain)
                    except Exception as _budget_hist_exc:
                        logger.debug("Budget gain history update failed for %s: %s", phase_id, _budget_hist_exc)
                # Memory-Hygiene: alle 5 Phasen Garbage Collector aufrufen,
                # um Zwischenpuffer und abgeschlossene Phase-Objekte freizugeben.
                if (not no_rt_limit) and self.performance_guard and self.performance_guard.check_early_exit(remaining):
                    logger.warning("⚠️ Early exit triggered, skipping %s remaining phases", remaining)
                    skipped.extend(selected_phases[len(executed) :])
                    # §0c Graceful-Stop Fallback — falls noch nicht oben gefangen
                    if graceful_stop_event is not None and graceful_stop_event.is_set() and not skipped:
                        skipped.extend(p for p in selected_phases if p not in executed)
                    break
        # §2.49b [RELEASE_MUST] Post-Pipeline cumulative stereo-collapse guard (Fix D).
        # Per-phase δ-guards catch single-phase collapses but miss gradual drift where each
        # individual phase contributes < 0.05 correlation degradation (e.g. phases 34→13→46→48
        # cumulatively destroying the R-channel to -111 dBFS while each passing individually).
        # Compares pipeline output against pre-pipeline audio — the only reliable baseline.
        if (
            current_audio.ndim == 2
            and current_audio.shape[0] == 2
            and _afg_pre_pipeline_audio is not None
            and _afg_pre_pipeline_audio.ndim == 2
            and _afg_pre_pipeline_audio.shape[0] == 2
        ):
            _pp2_l = float(np.sqrt(np.mean(_afg_pre_pipeline_audio[0] ** 2)) + 1e-12)
            _pp2_r = float(np.sqrt(np.mean(_afg_pre_pipeline_audio[1] ** 2)) + 1e-12)
            _cu2_l = float(np.sqrt(np.mean(current_audio[0] ** 2)) + 1e-12)
            _cu2_r = float(np.sqrt(np.mean(current_audio[1] ** 2)) + 1e-12)
            _pp2_imb = abs(20.0 * np.log10((_pp2_l + 1e-12) / (_pp2_r + 1e-12)))
            _cu2_imb = abs(20.0 * np.log10((_cu2_l + 1e-12) / (_cu2_r + 1e-12)))
            if _cu2_imb > 20.0 and _pp2_imb < 6.0:
                logger.error(
                    "§2.49b POST-PIPELINE cumulative stereo collapse: L/R imbalance %.1f dB "
                    "(pipeline input was %.1f dB) — rollback to best artifact-free checkpoint",
                    _cu2_imb,
                    _pp2_imb,
                )
                # Kaskade: 1. bester artefaktfreier Checkpoint, 2. Pre-Pipeline-Audio
                _d_recovery = (
                    _afg_best_clean_checkpoint.copy()
                    if _afg_best_clean_checkpoint is not None
                    else _afg_pre_pipeline_audio.copy()
                )
                # Checkpoint selbst auf Kollaps prüfen
                if _d_recovery.ndim == 2 and _d_recovery.shape[0] == 2:
                    _rc2_l = float(np.sqrt(np.mean(_d_recovery[0] ** 2)) + 1e-12)
                    _rc2_r = float(np.sqrt(np.mean(_d_recovery[1] ** 2)) + 1e-12)
                    _rc2_imb = abs(20.0 * np.log10((_rc2_l + 1e-12) / (_rc2_r + 1e-12)))
                    if _rc2_imb > 20.0:
                        logger.warning(
                            "§2.49b best_clean_checkpoint selbst kollabiert (%.1f dB) — "
                            "Fallback auf pre-pipeline audio (Primum non nocere)",
                            _rc2_imb,
                        )
                        _d_recovery = _afg_pre_pipeline_audio.copy()
                current_audio = np.clip(
                    np.nan_to_num(_d_recovery, nan=0.0, posinf=0.0, neginf=0.0),
                    -1.0,
                    1.0,
                )

        # §2.45a [RELEASE_MUST] Cumulative Pipeline-Level-Guard — final safety net.
        # The mid-pipeline guard (above) catches most drift; this is the last check before export.
        # Uses same soft-limiter approach instead of peak-ceiling that blocked gain recovery.
        # §2.45a-VI: Uses _cum_rms_reference_audio (not _afg_pre_pipeline_audio) so that
        # HPF/Notch phases (phase_02, phase_05) do not trigger makeup gain for intentional
        # energy removal — their reference reset already happened during the phase loop.
        _MAX_CUMULATIVE_LEVEL_DROP_DB: float = 0.915  # 10 % amplitude = 20*log10(0.9)
        _cum_guard_ref = _cum_rms_reference_audio if _cum_rms_reference_audio is not None else _afg_pre_pipeline_audio
        if _cum_guard_ref is not None:
            try:
                _cum_rms_in = _rms_dbfs_gated(_cum_guard_ref)
                _cum_rms_out = _rms_dbfs_gated(current_audio)
                _cum_drop_db = _cum_rms_in - _cum_rms_out
                _cumulative_makeup_db: float = 0.0
                if _cum_drop_db > _MAX_CUMULATIVE_LEVEL_DROP_DB:
                    # Maximum allowed output RMS: input level minus the 10%-tolerance
                    _cum_target_rms_db = _cum_rms_in - _MAX_CUMULATIVE_LEVEL_DROP_DB
                    _cum_needed_db = max(0.0, _cum_target_rms_db - _cum_rms_out)
                    if _cum_needed_db > 0.01:
                        _cum_gain = float(10.0 ** (_cum_needed_db / 20.0))
                        # Safety cap: max +18 dB for end-of-pipeline recovery
                        _cum_gain = min(_cum_gain, 8.0)
                        if _cum_gain > 1.0005:
                            if not _allow_positive_makeup_gain:
                                logger.info(
                                    "§2.45a CUMULATIVE level-guard (final): "
                                    "makeup skipped by Single-Gain-Authority (%s)",
                                    _makeup_authority_reason,
                                )
                            else:
                                # Envelope-aware gain: only amplify musical frames.
                                # reference_for_gate=_cum_guard_ref: pipeline-start noise floor (v9.12.1).
                                current_audio = self._musical_gain_envelope(
                                    current_audio,
                                    _cum_gain,
                                    gate_dbfs=-36.0,
                                    sr=sample_rate,
                                    reference_for_gate=_cum_guard_ref,
                                    material_key=str(getattr(material_type, "value", material_type)).lower(),
                                )
                                # Soft-limiter only if actual clipping risk
                                # §v9.10.125: 99.9th-percentile — impulse artefact must not block normalisation
                                _cum_peak_final = float(np.percentile(np.abs(current_audio), 99.9))
                                if _cum_peak_final > 0.98:
                                    _cum_abs_final = np.abs(current_audio)
                                    _cum_over_final = _cum_abs_final > 0.92
                                    if np.any(_cum_over_final):
                                        _cum_sign_final = np.sign(current_audio)
                                        _cum_soft_final = 0.92 + 0.08 * np.tanh((_cum_abs_final - 0.92) / 0.08)
                                        current_audio = np.where(
                                            _cum_over_final, _cum_sign_final * _cum_soft_final, current_audio
                                        )
                                current_audio = np.clip(current_audio, -1.0, 1.0)
                                _cumulative_makeup_db = float(20.0 * np.log10(max(_cum_gain, 1e-9)))
                                logger.info(
                                    "§2.45a CUMULATIVE level-guard (final): drop %.2f dB (gated) > %.2f dB limit "
                                    "→ envelope-aware makeup +%.2f dB applied",
                                    _cum_drop_db,
                                    _MAX_CUMULATIVE_LEVEL_DROP_DB,
                                    _cumulative_makeup_db,
                                )
                    else:
                        logger.debug(
                            "§2.45a CUMULATIVE level-guard (final): drop %.2f dB — within tolerance after "
                            "rounding, no action",
                            _cum_drop_db,
                        )
                else:
                    logger.debug(
                        "§2.45a CUMULATIVE level-guard (final): drop %.2f dB (gated) ≤ %.2f dB — OK",
                        _cum_drop_db,
                        _MAX_CUMULATIVE_LEVEL_DROP_DB,
                    )
            except Exception as _cum_exc:
                logger.debug("§2.45a CUMULATIVE level-guard (final) failed (non-blocking): %s", _cum_exc)

        self._pmgg_log_entries = _pmgg_log_entries

        # §Debug-Telemetrie: Per-Phase Goal-Delta-Tabelle (rein additives Logging, kein Audioeffekt).
        # Ermöglicht schnelle Diagnose welche Phase welches Goal wie stark beeinflusst hat.
        try:
            _p1p2_goals = ["natuerlichkeit", "authentizitaet", "tonal_center", "timbre_authentizitaet", "artikulation"]
            _all_goals_in_log: set[str] = set()
            for _e in _pmgg_log_entries:
                _all_goals_in_log.update(_e.goal_regressions.keys())
            _tracked = [g for g in _p1p2_goals if g in _all_goals_in_log] + [
                g for g in sorted(_all_goals_in_log) if g not in _p1p2_goals
            ]
            if _pmgg_log_entries and _tracked:
                _col_w = max(12, max(len(g) for g in _tracked) + 2)
                _header = f"{'Phase':<40}" + "".join(f"{g:>{_col_w}}" for g in _tracked)
                _rows = [_header, "-" * len(_header)]
                for _e in _pmgg_log_entries:
                    _row = f"{_e.phase_id:<40}"
                    for _g in _tracked:
                        _delta = _e.goal_regressions.get(_g)
                        if _delta is None:
                            _row += f"{'—':>{_col_w}}"
                        else:
                            _row += f"{_delta:>+{_col_w}.3f}"
                    _rows.append(_row)
                logger.info("§Phase-Delta-Table:\n%s", "\n".join(_rows))
        except Exception as _pdt_exc:
            logger.debug("Phase-Delta-Table generation failed (non-blocking): %s", _pdt_exc)

        # §2.29e Team-Coordination-Telemetrie: Ereignisse aus PMGG-Log extrahieren.
        # Nur Entries mit gesetztem team_policy_reason — d.h. Phasen, bei denen die
        # Team-Koordination aktiv etwas verändert hat (Goal-Exclusions, Threshold, Cap).
        _team_evs: list[dict[str, Any]] = []
        for _te in _pmgg_log_entries:
            try:
                _te_meta = _te.metadata if isinstance(_te.metadata, dict) else {}
                _te_reason = str(_te_meta.get("team_policy_reason", "") or "")
                if _te_reason:
                    _team_evs.append(
                        {
                            "phase_id": str(getattr(_te, "phase_id", "") or ""),
                            "action": str(getattr(_te, "action", "") or ""),
                            "reason": _te_reason,
                            "excluded_goals": list(_te_meta.get("team_excluded_goals", []) or []),
                            "threshold_mult": float(_te_meta.get("team_threshold_mult", 1.0) or 1.0),
                            "strength_cap": float(_te_meta.get("team_strength_cap", 1.0) or 1.0),
                        }
                    )
            except Exception as _tev_exc:
                logger.debug("team_coordination event extraction failed (non-blocking): %s", _tev_exc)
        self._team_coordination_events = _team_evs
        if _team_evs:
            logger.info(
                "§2.29e team_coordination: %d coordination event(s) — %s",
                len(_team_evs),
                [_e["reason"] for _e in _team_evs],
            )

        self._pipeline_ml_guard_events = list(pipeline_ml_guard_events)

        # §2.47 [RELEASE_MUST] ml_fallbacks_used: aggregate from ML-guard events (OOM-triggered fallbacks)
        _ml_fallbacks_used: list[dict[str, str]] = []
        for _ev in pipeline_ml_guard_events:
            _fb = str(_ev.get("fallback", "")).strip()
            if _fb:
                _ml_fallbacks_used.append(
                    {
                        "phase": str(_ev.get("phase_id", "")),
                        "model": str(_ev.get("model", "")),
                        "fallback": _fb,
                        "reason": str(_ev.get("reason", "oom")),
                    }
                )
        self._ml_fallbacks_used = _ml_fallbacks_used
        # §MONITOR [RELEASE_MUST] Structured ML_FALLBACK log — parseable by goal_monitor.py
        for _fb_ev in _ml_fallbacks_used:
            logger.info(
                "🔌 ML_FALLBACK phase=%s model=%s reason=%s fallback=%s",
                str(_fb_ev.get("phase", "")),
                str(_fb_ev.get("model", "")),
                str(_fb_ev.get("reason", "oom")),
                str(_fb_ev.get("fallback", "dsp")),
            )

        # §2.48 Store interaction guard metadata for RestorationResult
        if _interaction_guard is not None and _interaction_guard_state is not None:
            self._interaction_guard_metadata = _interaction_guard.get_rollback_metadata(_interaction_guard_state)
        else:
            self._interaction_guard_metadata = {}

        # §2.49 Final artifact freedom score for export gate / HPI
        # BUG-FIX: Comparing _afg_pre_pipeline_audio (degraded raw input) to current_audio
        # (fully processed output) always returns 0.000 for any real restoration — intentional
        # signal changes look like artifacts. Use per-phase minimum instead.
        # §2.49 BUG-FIX v9.12.0 (Bug 4): IAD fraction integrates into artifact_freedom.
        # _iad_artifact_fraction_penalty is set above when IAD detects artifacts.
        _iad_af_penalty = getattr(self, "_iad_artifact_fraction_penalty", 1.0)
        self._artifact_freedom_score = float(min(_min_per_phase_afg_score, _iad_af_penalty))
        if _iad_af_penalty < 1.0:
            logger.warning(
                "§2.49 IAD reduces artifact_freedom: per_phase=%.3f iad_penalty=%.3f -> final=%.3f",
                _min_per_phase_afg_score,
                _iad_af_penalty,
                self._artifact_freedom_score,
            )
        self._artifact_freedom_detail = {}
        logger.info(
            "§2.49 Final artifact_freedom=%.3f (per-phase-min across %d accepted phases)",
            self._artifact_freedom_score,
            len(executed),
        )

        # §2.44 HPI-Rollback-Checkpoint: speichere besten artefaktfreien Stand für
        # den Export-Gate-Rollback in restore() (§2.44: HPI ≤ 0 → Rollback auf best_checkpoint).
        # Primärquelle: _afg_best_clean_checkpoint (letzter artefaktfreier Stand).
        # Fallback: current_audio (Pipeline-Ausgang).
        self._hpi_best_rollback_audio = (
            _afg_best_clean_checkpoint.copy() if _afg_best_clean_checkpoint is not None else None
        )

        # §0d [RELEASE_MUST] Carrier-Recovery-Ratio + Best-Carrier-Checkpoint
        # Berechnet spectral_correlation zwischen pre-carrier und post-carrier Audio.
        # recovery_ratio > 0.15 → signifikante Carrier-Inversion → Referenz-Shift aktiv.
        self._carrier_chain_recovery_ratio = 0.0
        self._best_carrier_checkpoint = None
        self._last_carrier_phase_id = _last_carrier_phase_id
        if _best_carrier_checkpoint is not None:
            try:
                from backend.core.carrier_transfer_characteristics import spectral_correlation as _spec_corr

                _sc = _spec_corr(_pre_carrier_audio, _best_carrier_checkpoint, sr=sample_rate)
                self._carrier_chain_recovery_ratio = float(np.clip(1.0 - _sc, 0.0, 1.0))
                self._best_carrier_checkpoint = _best_carrier_checkpoint.copy()
                logger.info(
                    "§0d carrier_chain_recovery_ratio=%.3f (last_carrier=%s, spectral_corr=%.3f)",
                    self._carrier_chain_recovery_ratio,
                    _last_carrier_phase_id,
                    _sc,
                )
            except Exception as _ccr_exc:
                logger.debug("§0d carrier_chain_recovery_ratio computation failed: %s", _ccr_exc)

        # §Längen-Guard: Phasen-akkumulierten Längen-Drift korrigieren (Trim oder Zero-Pad).
        # Schützt vor PGHI/padded=False-bedingtem Längen-Drift über viele Phasen.
        _out_n = current_audio.shape[-1] if current_audio.ndim >= 2 else len(current_audio)
        if _out_n != _input_n_samples:
            logger.debug(
                "_execute_pipeline: Längen-Drift %d→%d Samples — korrigiert",
                _out_n,
                _input_n_samples,
            )
            if current_audio.ndim >= 2:
                if _out_n > _input_n_samples:
                    current_audio = current_audio[..., :_input_n_samples]
                else:
                    pad_w = _input_n_samples - _out_n
                    current_audio = np.pad(current_audio, [(0, 0)] * (current_audio.ndim - 1) + [(0, pad_w)])
            else:
                if _out_n > _input_n_samples:
                    current_audio = current_audio[:_input_n_samples]
                else:
                    current_audio = np.pad(current_audio, (0, _input_n_samples - _out_n))

        # §8.5A Final TruePeak hard-guard — universaler End-of-Pipeline-Schutz.
        # 99.9th-percentile statt np.max(): Impulsartefakte dürfen den finalen Guard
        # nicht dominieren. Ceiling 0.966 ≈ -0.3 dBFS.
        try:
            _tp_guard_peak = float(np.percentile(np.abs(current_audio), 99.9))
            if math.isfinite(_tp_guard_peak) and _tp_guard_peak > 0.966:
                _tp_guard_gain = float(0.966 / max(_tp_guard_peak, 1e-12))
                current_audio = np.asarray(current_audio * _tp_guard_gain, dtype=np.float32)
                current_audio = np.clip(current_audio, -1.0, 1.0)
                logger.info(
                    "§Final TruePeak hard-guard aktiv: p99.9=%.4f > 0.966 → gain=%.4f",
                    _tp_guard_peak,
                    _tp_guard_gain,
                )
            else:
                current_audio = np.clip(current_audio, -1.0, 1.0)
                logger.debug(
                    "§Final TruePeak hard-guard idle: p99.9=%.4f <= 0.966",
                    _tp_guard_peak,
                )
        except Exception as _tp_guard_exc:
            logger.debug("§Final TruePeak hard-guard failed (non-blocking): %s", _tp_guard_exc)

        # §2.51 Stereo-correlation guard (input-relativ, non-blocking, §8.5B)
        try:
            if (
                isinstance(_pre_carrier_audio, np.ndarray)
                and isinstance(current_audio, np.ndarray)
                and _pre_carrier_audio.ndim == 2
                and current_audio.ndim == 2
                and _pre_carrier_audio.shape[0] >= 2
                and current_audio.shape[0] >= 2
            ):
                # NaN-safe correlation (§verboten np.corrcoef auf near-constant Signalen):
                # Bei Stille / DC-Offset → std ≈ 0 → corrcoef = NaN → NaN > _delta_limit = False
                # → Guard ist lautlos deaktiviert für genau die pathologischen Inputs.
                # Fix: guarded dot-product statt corrcoef.
                def _safe_corr(_a: np.ndarray, _b: np.ndarray) -> float:
                    _sa, _sb = float(np.std(_a)), float(np.std(_b))
                    if _sa < 1e-9 or _sb < 1e-9:
                        return 1.0  # mono/silent → trivially correlated (conservative)
                    _ma, _mb = float(np.mean(_a)), float(np.mean(_b))
                    _v = float(np.dot(_a - _ma, _b - _mb)) / (float(len(_a)) * _sa * _sb + 1e-12)
                    return float(max(-1.0, min(1.0, _v)))

                _corr_before = _safe_corr(_pre_carrier_audio[0], _pre_carrier_audio[1])
                _corr_after = _safe_corr(current_audio[0], current_audio[1])
                _input_is_narrow = abs(_corr_before) >= 0.92
                _delta_limit = 0.04 if _input_is_narrow else 0.12
                if (_corr_before - _corr_after) > _delta_limit:
                    logger.warning(
                        "§2.51 Stereo-correlation guard: corr_before=%.3f corr_after=%.3f delta_limit=%.3f",
                        _corr_before,
                        _corr_after,
                        _delta_limit,
                    )
        except Exception as _st_corr_exc:
            logger.debug("§2.51 Stereo-correlation guard failed (non-blocking): %s", _st_corr_exc)

        # §LAG_PROBE 2a: am Ende von _execute_pipeline (vor return) — GCC-PHAT O(n log n)
        try:
            if current_audio.ndim == 2:
                from backend.file_import import _estimate_interchannel_lag_samples as _gcc_lag

                _lp2a_lag = _gcc_lag(current_audio, sample_rate)
                logger.info(
                    "LAG_PROBE 2a/end_execute_pipeline: lag=%d samples (%.1f ms)",
                    _lp2a_lag,
                    _lp2a_lag / sample_rate * 1000,
                )
        except Exception as _lp2a_exc:
            logger.debug("LAG_PROBE_2a fehlgeschlagen: %s", _lp2a_exc)

        return current_audio, executed, skipped, deferred

    @staticmethod
    def _resolve_adaptive_goal_thresholds(adaptive_goals_payload: Any) -> dict[str, float]:
        """Delegates to the standalone resolver module (P1-2 modularisation).

        See ``backend.core.musical_goals.adaptive_goal_resolver`` for the
        full implementation.  Kept as a @staticmethod here for backward
        compatibility with call sites that reference UnifiedRestorerV3.
        """
        return _resolve_adaptive_goal_thresholds_fn(adaptive_goals_payload)

    def _estimate_quality(
        self,
        defect_result,
        _perf_report,
        _executed_phases: list[str],
        audio=None,
        sample_rate: int = 48_000,
    ) -> float:
        """
        Qualitätsschätzung nach Spec §8.1.1 (SCHRITTE K-2):
            quality = 0.40*(1 − defect_severity) + 0.60*(pqs_mos − 1)/4

        VERBOTEN: fixed *1.15-Bonus ohne Audio-Messung (Spec §10.1).
        VERBOTEN: defect_severity-only ohne reale PQS-Berechnung.

        Args:
            defect_result: DefectAnalysisResult mit get_total_severity()
            perf_report:   PerformanceReport oder None
            executed_phases: Liste aktiver Phasen (für Logging)
            audio:         Restauriertes Audio-Array (float32, 48 kHz) oder None
            sample_rate:   Sample-Rate, muss 48000 sein
        Returns:
            quality_estimate ∈ [0.0, 1.0]
        """
        self._quality_estimate_used_fallback = True
        self._quality_estimate_source = "defect_proxy"

        # Defekt-Severity: sicher klemmen
        defect_severity = float(defect_result.get_total_severity())
        defect_severity = max(0.0, min(1.0, defect_severity))

        # PQS-MOS: Fallback-Schätzung (kein Audio oder Import-Fehler)
        pqs_mos: float = 1.0 + (1.0 - defect_severity) * 4.0

        if audio is not None:
            try:
                from backend.core.perceptual_quality_scorer import score_audio_absolute  # type: ignore

                _pqs_result = score_audio_absolute(audio, sr=sample_rate)
                _mos = float(getattr(_pqs_result, "pqs_mos", getattr(_pqs_result, "mos", pqs_mos)))
                if math.isfinite(_mos) and 1.0 <= _mos <= 5.0:
                    pqs_mos = _mos
                    self._quality_estimate_used_fallback = False
                    self._quality_estimate_source = "pqs_absolute"
                else:
                    raise ValueError(f"PQS returned invalid MOS={_mos}")
            except Exception as _pqs_exc:
                logger.debug("_estimate_quality: PQS full-audio failed: %s — retrying with 30s sample", _pqs_exc)
                # §9.8 PQS-Reliability: Retry with shorter centre sample (30 s)
                # avoids OOM and numerical instabilities on very long audio.
                try:
                    from backend.core.perceptual_quality_scorer import score_audio_absolute as _pqs_fn  # type: ignore

                    _total = audio.shape[-1] if audio.ndim == 2 else len(audio)
                    _max = min(_total, sample_rate * 30)
                    _start = (_total - _max) // 2
                    _short = audio[..., _start : _start + _max] if audio.ndim == 2 else audio[_start : _start + _max]
                    _pqs_r = _pqs_fn(_short, sr=sample_rate)
                    _mos_r = float(getattr(_pqs_r, "pqs_mos", getattr(_pqs_r, "mos", pqs_mos)))
                    if math.isfinite(_mos_r) and 1.0 <= _mos_r <= 5.0:
                        pqs_mos = _mos_r
                        self._quality_estimate_used_fallback = False
                        self._quality_estimate_source = "pqs_absolute_30s"
                except Exception as _pqs_retry_exc:
                    logger.debug("_estimate_quality: PQS 30s-retry failed, Fallback aktiv: %s", _pqs_retry_exc)

        # Spec §8.1.1: Gewichtete Kombination
        quality_estimate = 0.40 * (1.0 - defect_severity) + 0.60 * (pqs_mos - 1.0) / 4.0
        return float(max(0.0, min(1.0, quality_estimate)))

    def get_phase_info(self) -> dict[str, dict]:
        """Gibt Informationen über alle Phasen (Lazy Loading)."""
        info = {}
        for phase_id, meta in self.phase_metadata.items():
            info[phase_id] = {
                "name": meta["name"],
                "category": meta["category"],
                "dependencies": meta["dependencies"],
                "estimated_time_factor": meta["estimated_time_factor"],
                "priority": meta["priority"],
            }
        return info


