# ─── Module-level Singleton Factory (§3.2 Singleton-Pattern) ───────────────
import threading as _threading  # pylint: disable=wrong-import-position

_restorer_singleton: Optional["UnifiedRestorerV3"] = None
_restorer_singleton_lock = _threading.Lock()


def get_artifact_freedom_gate():
    """Module-level accessor to keep patch points stable for tests and integrations."""
    from backend.core.artifact_freedom_gate import get_artifact_freedom_gate as _get_afg

    return _get_afg()


def estimate_goal_importance(*args, **kwargs):
    """Module-level accessor to keep song-goal patch points stable for tests."""
    from backend.core.song_goal_importance import estimate_goal_importance as _estimate_goal_importance

    return _estimate_goal_importance(*args, **kwargs)


def get_restorer(mode: str = "quality") -> "UnifiedRestorerV3":
    """Thread-sicherer Singleton-Accessor für UnifiedRestorerV3.

    Wird von scripts/run_amrb_v99.py und anderen externen Callers verwendet.
    Unterstützt mode-Aliases: "restoration" und "quality" → QUALITY (höchste Qualität).

    Args:
        mode: Qualitäts-Modus — "fast" | "balanced" | "restoration" |
              "quality" | "maximum" | "studio_2026"

    Returns:
        Einzel-Instanz von UnifiedRestorerV3 (Thread-safe, Double-Checked Locking)
    """
    global _restorer_singleton  # pylint: disable=global-statement
    if _restorer_singleton is None:
        with _restorer_singleton_lock:
            if _restorer_singleton is None:
                _mode_map = {
                    "fast": QualityMode.FAST,
                    "balanced": QualityMode.BALANCED,
                    "restoration": QualityMode.QUALITY,  # Restoration nutzt volle Quality-Pipeline
                    "quality": QualityMode.QUALITY,
                    "maximum": QualityMode.MAXIMUM,  # §9.5: 8× RT — war fälschlich BALANCED (3×)
                    "studio_2026": QualityMode.MAXIMUM,  # §9.5: 8× RT — war fälschlich BALANCED (3×)
                }
                qmode = _mode_map.get(mode.lower(), QualityMode.QUALITY)
                config = RestorationConfig(mode=qmode)
                _restorer_singleton = UnifiedRestorerV3(config)
                logger.info("🏭 get_restorer(): UnifiedRestorerV3 initialisiert (mode=%s)", qmode.value)
    return _restorer_singleton


if __name__ == "__main__":
    # Test UnifiedRestorerV3 mit Beispiel-Audio.

    # Setup Logging
    logging.basicConfig(level=logging.INFO, format="%(asctime)s - %(name)s - %(levelname)s - %(message)s")

    logger.debug("\n%s", "=" * 70)
    logger.debug("UNIFIED RESTORER V3 TEST - Aurik 9.0")
    logger.debug("%s\n", "=" * 70)

    # Generate test audio (3:45 = 225 seconds)
    _sr = 44100
    duration = 225  # 3:45 minutes
    t = np.linspace(0, duration, int(_sr * duration))

    # Base signal: 440 Hz sine
    _audio = 0.3 * np.sin(2 * np.pi * 440 * t)

    # Add defects
    # 1. Clicks
    for i in range(100):
        pos = int(np.random.rand() * len(_audio))
        _audio[pos : pos + 5] += 0.3 * np.random.randn(5)

    # 2. 60Hz Hum
    _audio += 0.04 * np.sin(2 * np.pi * 60 * t)

    # 3. White Noise (Tape Hiss)
    _audio += 0.02 * np.random.randn(len(_audio))

    logger.debug("Test Audio: %ss @ %s Hz", duration, _sr)
    logger.debug("Defects: ~100 clicks, 60Hz hum, tape hiss\n")

    # Test alle Modi
    for _mode in [QualityMode.FAST, QualityMode.BALANCED]:
        logger.debug("\n%s", "─" * 70)
        logger.debug("Testing %s Mode", _mode.value.upper())
        logger.debug("%s\n", "─" * 70)

        _config = RestorationConfig(mode=_mode, num_cores=4, enforce_3x_rt=True, enable_adaptive_skipping=True)

        restorer = UnifiedRestorerV3(_config)

        # Restore
        _result = restorer.restore(_audio, sample_rate=_sr)

        # Report
        logger.debug("\n%s", "=" * 70)
        logger.debug("RESULT SUMMARY - %s", _mode.value.upper())
        logger.debug("%s", "=" * 70)
        logger.debug("Material: %s", _result.material_type.value)
        logger.debug("Total Time: %.1fs", _result.total_time_seconds)
        _rt_pass = "✅ PASS" if _result.rt_factor <= 3.0 else "❌ FAIL"
        logger.debug("RT Factor: %.2f× (%s)", _result.rt_factor, _rt_pass)
        logger.debug("Quality Estimate: %.1f%%", _result.quality_estimate * 100)
        logger.debug("Phases Executed: %s", len(_result.phases_executed))
        logger.debug("Phases Skipped: %s", len(_result.phases_skipped))
        if _result.warnings:
            logger.debug("Warnings: %s", len(_result.warnings))
            for w in _result.warnings[:3]:
                logger.debug("  - %s", w)
        logger.debug("\nTop Defects (Before):")
        for i, defect in enumerate(_result.metadata["defect_analysis"]["top_defects"][:3], 1):
            logger.debug("  %s. %s: %.2f", i, defect["type"], defect["severity"])
        logger.debug("%s\n", "=" * 70)

    logger.debug("\n✅ UnifiedRestorerV3 Test Complete!")
